func (p PipInstallProcess) Execute(workingDir, packagesLayerPath, cacheLayerPath string) error {
	requirementFile := "requirements.txt"
	vendorDir := "vendor"
	findLinks := os.Getenv("PIP_FIND_LINKS")

	if customReqFile := os.Getenv("BP_PIP_REQUIREMENT"); customReqFile != "" {
		requirementFile = customReqFile
	}

	if customVendorDir := os.Getenv("BP_PIP_DEST_PATH"); customVendorDir != "" {
		vendorDir = customVendorDir
	}

	args := []string{
		"install",
		"--exists-action=w",
		fmt.Sprintf("--cache-dir=%s", cacheLayerPath),
		"--compile",
		"--user",
		"--disable-pip-version-check",
		fmt.Sprintf("--requirement=%s", requirementFile),
	}

	env := []string{
		fmt.Sprintf("PYTHONUSERBASE=%s", packagesLayerPath),
		fmt.Sprintf("PIP_FIND_LINKS=%s", findLinks),
	}

	if _, err := os.Stat(filepath.Join(workingDir, vendorDir)); err == nil {
		args = append(args[:1], append([]string{"--ignore-installed", "--no-index"}, args[1:]...)...)
		env = []string{
			fmt.Sprintf("PYTHONUSERBASE=%s", packagesLayerPath),
			fmt.Sprintf("PIP_FIND_LINKS=%s %s", findLinks, filepath.Join(workingDir, vendorDir)),
		}
	} else if !os.IsNotExist(err) {
		return err
	}

	execution := Execution{
		Args: args,
		Dir:  workingDir,
		Env:  env,
	}

	err := p.executable.Execute(execution)
	if err != nil {
		return err
	}

	p.emitter.Emit("Successfully installed packages from %s\n", requirementFile)
	return nil
