package main

import (
	"fmt"
)

func maximumWealth(accounts [][]int) int {
	return wealth(accounts)
}

func wealth(accounts [][]int) int {
	var accSum []int
	for i := 0; i < len(accounts); i++ {
		sum := 0
		for _, v := range accounts[i] {
			sum += v
		}
		accSum = append(accSum, sum)
	}

	return max(accSum)
}

func max(sums []int) int {
	max := sums[0]
	for i := range sums {
		if sums[i] > max {
			max = sums[i]
		}
	}
	return max
}

func main() {
	// Test cases
	testCases := []struct {
		accounts [][]int
		expected int
	}{
		{[][]int{{1, 2, 3}, {3, 2, 1}}, 6},
		{[][]int{{1, 5}, {7, 3}, {3, 5}}, 10},
		{[][]int{{2, 8, 7}, {7, 1, 3}, {1, 9, 5}}, 17},
	}

	for _, tc := range testCases {
		actual := maximumWealth(tc.accounts)
		if actual != tc.expected {
			fmt.Printf("For accounts %v, expected maximum wealth to be %d, but got %d\n", tc.accounts, tc.expected, actual)
		} else {
			fmt.Printf("For accounts %v, the maximum wealth is correctly calculated as %d\n", tc.accounts, actual)
		}
	}
