package main

import (
	"fmt"
	"reflect"
)

// isEmptyValue checks if the provided value is considered "empty".
// An empty value can be a zero-length string, array, map, slice,
// a boolean `false`, a numeric type with a value of `0`, or a nil pointer or interface.
// It returns a boolean indicating whether the value is empty and an error if the type is not supported.
func isEmptyValue(v reflect.Value) (bool, error) {
	switch v.Kind() {
	case reflect.Array, reflect.Map, reflect.Slice, reflect.String:
		return v.Len() == 0, nil
	case reflect.Bool:
		return !v.Bool(), nil
	case reflect.Int, reflect.Int8, reflect.Int16, reflect.Int32, reflect.Int64:
		return v.Int() == 0, nil
	case reflect.Uint, reflect.Uint8, reflect.Uint16, reflect.Uint32, reflect.Uint64, reflect.Uintptr:
		return v.Uint() == 0, nil
	case reflect.Float32, reflect.Float64:
		return v.Float() == 0, nil
	case reflect.Interface, reflect.Ptr:
		return v.IsNil(), nil
	case reflect.Invalid:
		return true, nil
	}
	return false, fmt.Errorf("isEmptyValue: unknown type %s", v.Kind())
}

func main() {
	// Test cases to verify the solution correctness
	testCases := []interface{}{
		"", // Empty string
		"non-empty", // Non-empty string
		0, // Zero integer
		42, // Non-zero integer
		false, // Boolean false
		true, // Boolean true
		[]int{}, // Empty slice
		[]int{1, 2, 3}, // Non-empty slice
		map[string]int{}, // Empty map
		map[string]int{"a": 1}, // Non-empty map
		(*struct{})(nil), // Nil pointer
		&struct{}{}, // Non-nil pointer
	}

	for _, tc := range testCases {
		v := reflect.ValueOf(tc)
		empty, err := isEmptyValue(v)
		if err != nil {
			fmt.Printf("Error: %s\n", err)
		} else {
			fmt.Printf("Value: %v, IsEmpty: %t\n", tc, empty)
		}
	}
}
