package irc

import (
	"bufio"
	"fmt"
	"log"
	"net"
	"strings"
)

// Client represents an IRC client
type Client struct {
	addr      string
	channels  []string
	conn      net.Conn
	debug     bool
	logger    *log.Logger
	nick      string
	realName  string
	user      string
	version   string
}

// NewClient creates a new IRC client with the given options
func NewClient(options ...Option) *Client {
	client := &Client{}
	for _, option := range options {
		option(client)
	}
	return client
}

// Connect establishes a connection to the IRC server and joins the channels
func (c *Client) Connect() error {
	var err error
	if c.conn == nil {
		c.conn, err = net.Dial("tcp", c.addr)
		if err != nil {
			return err
		}
	}

	// Set up reader and writer
	reader := bufio.NewReader(c.conn)
	writer := bufio.NewWriter(c.conn)

	// Send USER and NICK commands
	userCommand := fmt.Sprintf("USER %s 0 * :%s\r\n", c.user, c.realName)
	nickCommand := fmt.Sprintf("NICK %s\r\n", c.nick)
	writer.WriteString(userCommand)
	writer.WriteString(nickCommand)
	writer.Flush()

	// Join channels
	for _, channel := range c.channels {
		joinCommand := fmt.Sprintf("JOIN %s\r\n", channel)
		writer.WriteString(joinCommand)
		writer.Flush()
	}

	// Handle incoming messages in a separate goroutine
	go c.handleMessages(reader)

	return nil
}

// SendMessage sends a message to the specified channel
func (c *Client) SendMessage(channel, message string) error {
	if !strings.HasPrefix(channel, "#") {
		channel = "#" + channel
	}
	msgCommand := fmt.Sprintf("PRIVMSG %s :%s\r\n", channel, message)
	_, err := c.conn.Write([]byte(msgCommand))
	return err
}

// handleMessages reads messages from the server and logs them if debug is enabled
func (c *Client) handleMessages(reader *bufio.Reader) {
	for {
		line, err := reader.ReadString('\n')
		if err != nil {
			c.log(fmt.Sprintf("Error reading from server: %s", err))
			break
		}
		c.log(line)
	}
}

// log logs a message if a logger is set, otherwise it prints to the standard logger
func (c *Client) log(message string) {
	if c.debug {
		if c.logger != nil {
			c.logger.Println(message)
		} else {
			log.Println(message)
		}
	}
}

// Test cases to verify the solution correctness
func main() {
	// Create a logger
	logger := log.New(log.Writer(), "IRC: ", log.LstdFlags)

	// Create a new IRC client with options
	client := NewClient(
		WithAddr("irc.example.com:6667"),
		WithChannel("#example"),
		WithNick("goBot"),
		WithRealName("Go IRC Bot"),
		WithUser("goBot"),
		WithVersion("goBot 1.0"),
		WithDebug(),
		WithLogger(logger),
	)

	// Connect to the IRC server
	err := client.Connect()
	if err != nil {
		log.Fatalf("Error connecting to IRC server: %s", err)
	}

	// Send a message to the channel
	err = client.SendMessage("#example", "Hello, IRC!")
	if err != nil {
		log.Fatalf("Error sending message: %s", err)
	}
}
