package merkle

import (
	"encoding/json"
	"math"
	"sort"
	"strconv"

	"github.com/nathanjisaac/actual-server-go/internal/core/crdt"
)

type Merkle struct {
	Hash     uint32
	Children map[string]*Merkle
}

func NewMerkle(hash uint32) *Merkle {
	return &Merkle{Hash: hash, Children: map[string]*Merkle{}}
}

func (trie *Merkle) toMapInterface() map[string]interface{} {
	merkleMap := map[string]interface{}{}
	if trie.Hash != 0 {
		merkleMap["hash"] = int32(trie.Hash)
	}

	for key, merkle := range trie.Children {
		if key != "hash" {
			merkleMap[key] = merkle.toMapInterface()
		}
	}

	return merkleMap
}

func (trie *Merkle) ToJSONString() (string, error) {
	merkleMap := trie.toMapInterface()

	jsonString, err := json.Marshal(merkleMap)
	if err != nil {
		return "", err
	}

	return string(jsonString), nil
}

func (trie *Merkle) getKeys() []string {
	j := 0
	keys := make([]string, len(trie.Children))
	for k := range trie.Children {
		keys[j] = k
		j++
	}
	return keys
}

func (trie *Merkle) insertKey(key string, hash uint32) *Merkle {
	if len(key) == 0 {
		return nil
	}

	c := string(key[0])

	cNode := NewMerkle(0)
	n := trie.Children[c]
	nHash := -1
	var nInserted *Merkle

	if n != nil {
		nHash = int(n.Hash)

		cNode.Hash = n.Hash
		for k := range n.Children {
			if n.Children[k] != nil {
				cNode.Children[k] = n.Children[k]
			}
		}
	} else {
		n = NewMerkle(0)
	}

	if len(key) > 1 {
		nInserted = n.insertKey(key[1:], hash)
	}
	if nInserted != nil {
		if nInserted.Hash != 0 {
			cNode.Hash = nInserted.Hash
		}
		for k := range nInserted.Children {
			if nInserted.Children[k] != nil {
				cNode.Children[k] = nInserted.Children[k]
			}
		}
	}

	if trie.Children == nil {
		trie.Children = map[string]*Merkle{}
	}
	if nHash != -1 {
		cNode.Hash = uint32(nHash) ^ hash
	} else {
		cNode.Hash = hash
	}
	trie.Children[c] = cNode
	return trie
}

func (trie *Merkle) Insert(timestamp crdt.Timestamp) {
	hash := timestamp.Hash()
	key := strconv.FormatInt((timestamp.GetMillis() / (1000 * 60)), 10)

	trie.Hash ^= hash
	trie.insertKey(key, hash)
}

func (trie *Merkle) Prune() *Merkle {
	n := 2

	if trie == nil {
		return nil
	}
	if trie.Children == nil {
		trie.Children = map[string]*Merkle{}
	}

	// Checking if empty
	if len(trie.Children) == 0 && trie.Hash == 0 {
		return trie
	}

	keys := trie.getKeys()
	sort.Strings(keys)

	sliceRange := len(keys) - n
	newTrie := NewMerkle(trie.Hash)
	for _, k := range keys[int(math.Max(0, float64(sliceRange))):] {
		node := trie.Children[k].Prune()
		if node != nil {
			newTrie.Children[k] = node
		}
	}
	return newTrie
}

// Test cases to verify the solution correctness
func main() {
	// Assuming crdt.Timestamp interface and its methods are implemented
	var timestamp1, timestamp2 crdt.Timestamp // These would be actual timestamp objects with implemented methods

	merkleTrie := NewMerkle(0)

	// Insert timestamps
	merkleTrie.Insert(timestamp1)
	merkleTrie.Insert(timestamp2)

	// Prune the trie
	prunedTrie := merkleTrie.Prune()

	// Convert to JSON string
	jsonString, err := prunedTrie.ToJSONString()
	if err != nil {
		panic(err)
	}

	// Output the JSON string
	println(jsonString)
}
