package main

import (
	"errors"
	"fmt"
	"math/rand"
	"strings"
	"time"
)

// LoadBalanceConf is an interface for load balancer configuration.
type LoadBalanceConf interface {
	GetConf() []string
}

// LoadBalanceCheckConf is a struct that implements LoadBalanceConf.
type LoadBalanceCheckConf struct {
	conf []string
}

func (l *LoadBalanceCheckConf) GetConf() []string {
	return l.conf
}

// RandomBalance is a load balancer that selects a server randomly.
type RandomBalance struct {
	currentIndex int
	addresses    []string
	conf         LoadBalanceConf
}

func (r *RandomBalance) Add(params ...string) error {
	if len(params) == 0 {
		return errors.New("param len 1 at least")
	}
	addr := params[0]
	r.addresses = append(r.addresses, addr)
	return nil
}

func (r *RandomBalance) Next() string {
	if len(r.addresses) == 0 {
		return ""
	}
	r.currentIndex = rand.Intn(len(r.addresses))
	return r.addresses[r.currentIndex]
}

func (r *RandomBalance) Get(_ string) (string, error) {
	return r.Next(), nil
}

func (r *RandomBalance) SetConf(conf LoadBalanceConf) {
	r.conf = conf
}

func (r *RandomBalance) Update() {
	if conf, ok := r.conf.(*LoadBalanceCheckConf); ok {
		r.addresses = nil
		for _, ip := range conf.GetConf() {
			_ = r.Add(strings.Split(ip, ",")...)
		}
	}
}

func main() {
	rand.Seed(time.Now().UnixNano())

	// Test cases
	balancer := RandomBalance{}
	conf := LoadBalanceCheckConf{
		conf: []string{"192.168.0.1", "192.168.0.2", "192.168.0.3"},
	}

	// Set configuration and update balancer
	balancer.SetConf(&conf)
	balancer.Update()

	// Add a new server address
	err := balancer.Add("192.168.0.4")
	if err != nil {
		fmt.Println("Error adding address:", err)
	}

	// Retrieve server addresses
	for i := 0; i < 5; i++ {
		server, err := balancer.Get("")
		if err != nil {
			fmt.Println("Error retrieving server:", err)
		} else {
			fmt.Println("Selected server:", server)
		}
	}

	// Update configuration
	newConf := LoadBalanceCheckConf{
		conf: []string{"192.168.0.5", "192.168.0.6"},
	}
	balancer.SetConf(&newConf)
	balancer.Update()

	// Retrieve server addresses after update
	for i := 0; i < 5; i++ {
		server, err := balancer.Get("")
		if err != nil {
			fmt.Println("Error retrieving server:", err)
		} else {
			fmt.Println("Selected server after update:", server)
		}
	}
}
