// InitConfig initializes the configuration by reading from the specified JSON file path.
// It uses a singleton pattern to ensure that the configuration is only set once.
func InitConfig(path string) error {
	once.Do(func() {
		var data []byte
		data, initError = ioutil.ReadFile(path)
		if initError != nil {
			return
		}
		initError = json.Unmarshal(data, &conf)
	})
	return initError
}

// GetConfig returns the current configuration.
// If the configuration has not been initialized, it returns an error.
func GetConfig() (Config, error) {
	if initError != nil {
		return Config{}, errors.New("configuration not initialized")
	}
	return conf, nil
}

