func main() {
	// Resolve the IP address of the endpoint.
	hostIPs, err := net.LookupIP("host.docker.internal")
	if err != nil {
		log.Panic(err)
	}
	hostIP := hostIPs[0].String()

	// Create a virtual network interface.
	tun, tnet, err := netstack.CreateNetTUN(
		[]netip.Addr{netip.MustParseAddr("192.168.4.28")},
		[]netip.Addr{},
		device.DefaultMTU,
	)
	if err != nil {
		log.Panic(err)
	}

	// Initialize a new WireGuard device with verbose logging.
	dev := device.NewDevice(tun, conn.NewDefaultBind(), device.NewLogger(device.LogLevelVerbose, ""))

	// Read the local private key and the remote public key from files.
	cwd, err := os.Getwd()
	if err != nil {
		log.Panic(err)
	}
	localPrivateKeyBase64, err := os.ReadFile(filepath.Join(cwd, ".wg/iad"))
	if err != nil {
		log.Panic(err)
	}
	localPrivateKey, err := base64.StdEncoding.DecodeString(string(localPrivateKeyBase64))
	if err != nil {
		log.Panic(err)
	}
	remotePublicKeyBase64, err := os.ReadFile(filepath.Join(cwd, ".wg/sin.pub"))
	if err != nil {
		log.Panic(err)
	}
	remotePublicKey, err := base64.StdEncoding.DecodeString(string(remotePublicKeyBase64))
	if err != nil {
		log.Panic(err)
	}

	// Configure the WireGuard device.
	wgConf := bytes.NewBuffer(nil)
	fmt.Fprintf(wgConf, "private_key=%s\n", hex.EncodeToString(localPrivateKey))
	fmt.Fprintf(wgConf, "public_key=%s\n", hex.EncodeToString(remotePublicKey))
	fmt.Fprintf(wgConf, "endpoint=%s\n", hostIP+":58120")
	fmt.Fprintf(wgConf, "allowed_ip=%s\n", "0.0.0.0/0")
	fmt.Fprintf(wgConf, "persistent_keepalive_interval=25\n")
	if err := dev.IpcSetOperation(bufio.NewReader(wgConf)); err != nil {
		log.Panic(err)
	}

	// Bring up the WireGuard interface.
	dev.Up()

	// Use the virtual network to send an HTTP GET request.
	client := http.Client{
		Transport: &http.Transport{
			DialContext: tnet.DialContext,
		},
	}
