// ProductImageCore represents the core data of a product image.
type ProductImageCore struct {
	ID        int
	ProductID int
	URL       string
	Alt       string
}

// ProductImage is the GORM model for the product image table.
type ProductImage struct {
	gorm.Model
	ProductID int
	URL       string
	Alt       string
}

// RepositoryInterface defines the methods that our repository should implement.
type RepositoryInterface interface {
	Create(data ProductImageCore) (rows int, err error)
	GetAll() (data []ProductImageCore, err error)
	GetByID(id int) (data ProductImageCore, err error)
}

// productImageRepository implements RepositoryInterface using a GORM database connection.
type productImageRepository struct {
	db *gorm.DB
}

// New creates a new instance of productImageRepository with the given GORM database connection.
func New(db *gorm.DB) RepositoryInterface {
	return &productImageRepository{
		db: db,
	}
}

// Create inserts a new product image into the database.
func (repo *productImageRepository) Create(data ProductImageCore) (rows int, err error) {
	imageProductGorm := fromCore(data)
	tx := repo.db.Create(&imageProductGorm)
	if tx.Error != nil {
		return -1, tx.Error
	}

	if tx.RowsAffected == 0 {
		return 0, errors.New("no rows affected")
	}

	return int(tx.RowsAffected), nil
}

// GetAll retrieves all product images from the database.
func (repo *productImageRepository) GetAll() (data []ProductImageCore, err error) {
	var productImages []ProductImage
	tx := repo.db.Find(&productImages)
	if tx.Error != nil {
		return nil, tx.Error
	}

	dataCore := toCoreList(productImages)

	return dataCore, nil
}

// GetByID retrieves a product image by its ID from the database.
func (repo *productImageRepository) GetByID(id int) (data ProductImageCore, err error) {
	var productImage ProductImage
	tx := repo.db.First(&productImage, id)
	if tx.Error != nil {
		return data, tx.Error
	}

	dataCore := productImage.toCore()

	return dataCore, nil
}

// fromCore converts a ProductImageCore to a ProductImage (GORM model).
func fromCore(data ProductImageCore) ProductImage {
	return ProductImage{
		ProductID: data.ProductID,
		URL:       data.URL,
		Alt:       data.Alt,
	}
}

// toCoreList converts a slice of ProductImage (GORM model) to a slice of ProductImageCore.
func toCoreList(productImages []ProductImage) []ProductImageCore {
	var dataCore []ProductImageCore
	for _, img := range productImages {
		dataCore = append(dataCore, img.toCore())
	}
	return dataCore
}

// toCore converts a ProductImage (GORM model) to a ProductImageCore.
func (p ProductImage) toCore() ProductImageCore {
	return ProductImageCore{
		ID:        int(p.ID),
		ProductID: p.ProductID,
		URL:       p.URL,
		Alt:       p.Alt,
	}
}

func main() {
	// Initialize the database connection (for demonstration purposes, using SQLite in-memory database).
	db, err := gorm.Open(sqlite.Open("file::memory:?cache=shared"), &gorm.Config{})
	if err != nil {
		panic("failed to connect database")
	}

	// Migrate the schema
	db.AutoMigrate(&ProductImage{})

	// Create a new repository instance
	repo := New(db)

	// Test cases
	// Create a new product image
	rowsAffected, err := repo.Create(ProductImageCore{ProductID: 1, URL: "http://example.com/image1.jpg", Alt: "Image 1"})
	if err != nil {
		fmt.Printf("Error creating product image: %s\n", err)
	} else {
		fmt.Printf("Product image created, rows affected: %d\n", rowsAffected)
	}

	// Get all product images
	productImages, err := repo.GetAll()
	if err != nil {
		fmt.Printf("Error retrieving product images: %s\n", err)
	} else {
		fmt.Printf("Retrieved product images: %+v\n", productImages)
	}

