	var err error
	db, err = gorm.Open(sqlite.Open("test.db"), &gorm.Config{})
	if err != nil {
		panic("failed to connect database")
	}

	// Migrate the schema
	db.AutoMigrate(&Album{}, &Track{})
}

func main() {
	router := gin.Default()

	router.GET("/album", getAlbums)
	router.GET("/album/:id", getAlbumByID)
	router.GET("/album/search", searchAlbums)

	router.Run(":8080")
}

func getAlbums(c *gin.Context) {
	offsetQuery := c.Query("offset")
	limitQuery := c.Query("limit")

	if offsetQuery == "" || limitQuery == "" {
		c.JSON(http.StatusBadRequest, gin.H{"message": "bad request"})
		return
	}

	offset, err := strconv.Atoi(offsetQuery)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"message": "invalid offset"})
		return
	}

	limit, err := strconv.Atoi(limitQuery)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"message": "invalid limit"})
		return
	}

	var albums []Album
	db.Preload("Tracks").Offset(offset).Limit(limit).Find(&albums)
	c.JSON(http.StatusOK, albums)
}

