	id := c.Param("id")
	var album Album
	if err := db.Preload("Tracks").First(&album, id).Error; err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"message": "bad request"})
		return
	}
	c.JSON(http.StatusOK, album)
