// structsEqual checks if two struct types can be safely converted between each other using unsafe.Pointer.
func structsEqual(a, b interface{}) bool {
	aType := reflect.TypeOf(a).Elem()
	bType := reflect.TypeOf(b).Elem()

	if aType.NumField() != bType.NumField() {
		return false
	}

	for i := 0; i < aType.NumField(); i++ {
		aField := aType.Field(i)
		bField := bType.Field(i)

		if aField.Type != bField.Type || aField.Offset != bField.Offset {
			return false
		}
	}

	return true
}

// toTLSClientHelloInfo converts a qtls.ClientHelloInfo to a tls.ClientHelloInfo using unsafe.Pointer.
func toTLSClientHelloInfo(chi *qtls.ClientHelloInfo) *tls.ClientHelloInfo {
	return (*tls.ClientHelloInfo)(unsafe.Pointer(chi))
}

// Test cases
