	println(structsEqual(&target{}, &renamedField{})) // Expected: false
	println(structsEqual(&target{}, &renamedPrivateField{})) // Expected: false
	println(structsEqual(&target{}, &additionalField{})) // Expected: false
	println(structsEqual(&target{}, &interchangedFields{})) // Expected: false
