	"os"
)

// CAConfig is a section used in the requests initializing a new CA.
type CAConfig struct {
	PathLength  int    `json:"pathlen" yaml:"pathlen"`
	PathLenZero bool   `json:"pathlenzero" yaml:"pathlenzero"`
	Expiry      string `json:"expiry" yaml:"expiry"`
	Backdate    string `json:"backdate" yaml:"backdate"`
}

// BasicConstraints CSR information RFC 5280, 4.2.1.9
type BasicConstraints struct {
	IsCA       bool `asn1:"optional"`
	MaxPathLen int  `asn1:"optional,default:-1"`
}

// appendCAInfoToCSR appends CAConfig BasicConstraint extension to a CSR
func appendCAInfoToCSR(reqConf *CAConfig, csr *x509.CertificateRequest) error {
	pathlen := reqConf.PathLength
	if pathlen == 0 && !reqConf.PathLenZero {
		pathlen = -1
	}
	val, err := asn1.Marshal(BasicConstraints{true, pathlen})
	if err != nil {
		return err
	}

	csr.ExtraExtensions = append(csr.ExtraExtensions, pkix.Extension{
		Id:       asn1.ObjectIdentifier{2, 5, 29, 19},
		Value:    val,
		Critical: true,
	})

	return nil
}

// createCSR creates a new CSR with the given CAConfig
func createCSR(reqConf *CAConfig) (*x509.CertificateRequest, error) {
	template := x509.CertificateRequest{
		Subject: pkix.Name{
			CommonName: "example.com",
		},
	}

	err := appendCAInfoToCSR(reqConf, &template)
	if err != nil {
		return nil, err
	}

	csrBytes, err := x509.CreateCertificateRequest(rand.Reader, &template, nil)
	if err != nil {
		return nil, err
	}

	csr, err := x509.ParseCertificateRequest(csrBytes)
	if err != nil {
		return nil, err
	}

	return csr, nil
}

// main is the entry point of the program
func main() {
	// Example CA configuration
	caConfig := CAConfig{
		PathLength:  1,
		PathLenZero: false,
		Expiry:      "8760h",
		Backdate:    "1h",
	}

	csr, err := createCSR(&caConfig)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to create CSR: %v\n", err)
		os.Exit(1)
	}

	// Encode and print the CSR in PEM format
	pemBlock := &pem.Block{Type: "CERTIFICATE REQUEST", Bytes: csr.Raw}
	pemBytes := pem.EncodeToMemory(pemBlock)
	fmt.Printf("%s", pemBytes)
}
