package main

import (
	"bufio"
	"fmt"
	"net"
)

func main() {
	// Start a TCP server listening on port 8081.
	listener, err := net.Listen("tcp", ":8081")
	if err != nil {
		fmt.Println("Error setting up listener:", err)
		return
	}
	defer listener.Close()
	fmt.Println("Server is listening on port 8081...")

	// Accept a new connection.
	conn, err := listener.Accept()
	if err != nil {
		fmt.Println("Error accepting connection:", err)
		return
	}
	defer conn.Close()
	fmt.Println("Connected to client.")

	// Create a reader to read messages from the connection.
	reader := bufio.NewReader(conn)

	for {
		// Read a message from the client until a newline character is encountered.
		message, err := reader.ReadString('\n')
		if err != nil {
			fmt.Println("Error reading message:", err)
			break
		}

		// Check if the message is the termination command "end\n".
		if message == "end\n" {
			fmt.Println("Received end command, closing connection.")
			break
		}

		// Print the received message and send a confirmation response.
		fmt.Printf("Received message: %s", message)
		response := fmt.Sprintf("Received: %s", message)
		_, err = conn.Write([]byte(response))
		if err != nil {
			fmt.Println("Error sending response:", err)
			break
		}
	}

	// Close the connection and stop the server.
	fmt.Println("Closing the server.")
}

