package main

import (
	"context"
	"fmt"
	"strings"
	"time"

	krakendv1 "github.com/nais/krakend/api/v1"
	"github.com/nais/krakend/internal/controller"
	networkingv1 "k8s.io/api/networking/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/types"
	"sigs.k8s.io/controller-runtime/pkg/client"
)

// Assume that the client and context are properly initialized and available
var k8sClient client.Client
var ctx context.Context

func main() {
	// Example usage
	apiEndpoint := createApiEndpoint("my-application", []string{
		"http://service1",
		"http://service2.ns1.svc.cluster.local",
		"http://service3.ns2.svc.cluster.local",
		"http://service4.ns1",
	})

	err := createNetworkPoliciesForApiEndpoint(apiEndpoint)
	if err != nil {
		fmt.Printf("Error creating network policies: %v\n", err)
	} else {
		fmt.Println("Network policies created successfully")
	}
}

func createNetworkPoliciesForApiEndpoint(apiEndpoint *krakendv1.ApiEndpoints) error {
	namespace := apiEndpoint.Namespace
	appName := apiEndpoint.Name

	for _, endpoint := range apiEndpoint.Spec.Endpoints {
		serviceURL := endpoint.BackendHost
		serviceName, serviceNamespace := parseServiceNameAndNamespace(serviceURL)

		// Only create a NetworkPolicy if the service is in the same namespace
		if serviceNamespace == "" || serviceNamespace == namespace {
			networkPolicy := &networkingv1.NetworkPolicy{
				ObjectMeta: metav1.ObjectMeta{
					Name:      fmt.Sprintf("%s-%s", appName, serviceName),
					Namespace: namespace,
				},
				Spec: networkingv1.NetworkPolicySpec{
					PodSelector: metav1.LabelSelector{
						MatchLabels: map[string]string{
							"app": serviceName,
						},
					},
					Ingress: []networkingv1.NetworkPolicyIngressRule{
						{
							From: []networkingv1.NetworkPolicyPeer{
								{
									PodSelector: &metav1.LabelSelector{
										MatchLabels: map[string]string{
											"app": appName,
										},
									},
								},
							},
							Ports: []networkingv1.NetworkPolicyPort{
								{
									Protocol: func() *networkingv1.Protocol {
										proto := networkingv1.ProtocolTCP
										return &proto
									}(),
									Port: func() *intstr.IntOrString {
										port := intstr.FromInt(80)
										return &port
									}(),
								},
							},
						},
					},
				},
			}

			// Create the NetworkPolicy
			if err := k8sClient.Create(ctx, networkPolicy); err != nil {
				return fmt.Errorf("failed to create NetworkPolicy for service %s: %w", serviceName, err)
			}
		}
	}

	return nil
}

func parseServiceNameAndNamespace(serviceURL string) (serviceName, serviceNamespace string) {
	// Assume serviceURL is in the format "http://service.namespace" or "http://service.namespace.svc.cluster.local"
	parts := strings.Split(serviceURL, ".")
	if len(parts) >= 2 {
		serviceName = strings.TrimPrefix(parts[0], "http://")
		serviceNamespace = parts[1]
	} else {
		serviceName = strings.TrimPrefix(serviceURL, "http://")
	}
	return
}

func createApiEndpoint(name string, backends []string) *krakendv1.ApiEndpoints {
	endpoints := make([]krakendv1.Endpoint, len(backends))
	for i, backend := range backends {
		endpoints[i] = krakendv1.Endpoint{
			Path:        fmt.Sprintf("/path%d", i),
			BackendHost: backend,
		}
	}

	return &krakendv1.ApiEndpoints{
		ObjectMeta: metav1.ObjectMeta{
			Name:      name,
			Namespace: "ns1",
		},
		Spec: krakendv1.ApiEndpointsSpec{
			Auth: krakendv1.Auth{
				Name: "auth-provider",
			},
			Endpoints: endpoints,
		},
	}
}
