// IsSoftKeyword checks if the given token is a soft keyword.
func IsSoftKeyword(t Token) bool {
	return t >= ASSERT && t <= CHAR_X
}

// IsKeyword checks if the given token is a keyword.
func IsKeyword(t Token) bool {
	return t >= AS && t <= TRUE
