type LevelTypeRecord struct {
	Name      string
	Id        int
	Files     [32]string
	Beta      bool
	Act       int
	Expansion bool
}

var LevelTypes []LevelTypeRecord

func LoadLevelTypes(fileContent string) {
	data := strings.Split(fileContent, "\r\n")[1:]
	LevelTypes = make([]LevelTypeRecord, 0, len(data))
	for _, line := range data {
		if len(line) == 0 || strings.HasPrefix(line, "Expansion") {
			continue
		}
		parts := strings.Split(line, "\t")
		record := LevelTypeRecord{}
		record.Name = parts[0]
		record.Id, _ = strconv.Atoi(parts[1])
		for i := 0; i < 32; i++ {
			fileEntry := ""
			if i < len(parts)-4 {
				fileEntry = parts[i+2]
				if fileEntry == "0" {
					fileEntry = ""
				}
			}
			record.Files[i] = fileEntry
		}
		record.Beta = parts[len(parts)-3] != "1"
		record.Act, _ = strconv.Atoi(parts[len(parts)-2])
		record.Expansion = parts[len(parts)-1] != "1"
		LevelTypes = append(LevelTypes, record)
	}
	log.Printf("Loaded %d LevelType records", len(LevelTypes))
}

func main() {
	// Example file content
	fileContent := `Name	Id	File1	File2	File3	Beta	Act	Expansion
LevelOne	1	Level1.ds1	Level1.pal	0	0	1	0
LevelTwo	2	Level2.ds1	0	0	1	2	1
Expansion	3	ExpLevel1.ds1	ExpLevel1.pal	0	0	1	1
LevelThree	3	Level3.ds1	Level3.pal	Level3.dcc	1	3	0`

	LoadLevelTypes(fileContent)

	// Test cases to verify the solution correctness
	fmt.Println("Level Types Loaded:")
