package main

import (
	"fmt"
	"path"
)

// LengthMin is the shortest string length that will be considered a
// potential secret by the environment redactor.
const LengthMin = 6

var redacted = []byte("[REDACTED]")

// Logger interface for logging messages.
type Logger interface {
	Warningf(format string, args ...interface{})
}

// SimpleLogger is a simple implementation of the Logger interface.
type SimpleLogger struct{}

// Warningf logs a formatted warning message.
func (l SimpleLogger) Warningf(format string, args ...interface{}) {
	fmt.Printf("WARNING: "+format+"\n", args...)
}

// Redact ignores its input and returns "[REDACTED]".
func Redact([]byte) []byte {
	return redacted
}

// Values returns the variable values to be redacted.
func Values(logger Logger, patterns []string, environment map[string]string) []string {
	vars := Vars(logger, patterns, environment)
	if len(vars) == 0 {
		return nil
	}

	vals := make([]string, 0, len(vars))
	for _, val := range vars {
		vals = append(vals, val)
	}

	return vals
}

// Vars returns the variable names and values to be redacted.
func Vars(logger Logger, patterns []string, environment map[string]string) map[string]string {
	vars := make(map[string]string)

	for name, val := range environment {
		for _, pattern := range patterns {
			matched, err := path.Match(pattern, name)
			if err != nil {
				logger.Warningf("Bad redacted vars pattern: %s", pattern)
				continue
			}

			if !matched {
				continue
			}
			if len(val) < LengthMin {
				if len(val) > 0 {
					logger.Warningf("Value of %s below minimum length (%d bytes) and will not be redacted", name, LengthMin)
				}
				continue
			}

			vars[name] = val
			break
		}
	}

	return vars
}

func main() {
	logger := SimpleLogger{}
	patterns := []string{"*SECRET", "*PASSWORD", "*TOKEN"}
	environment := map[string]string{
		"API_TOKEN":        "123456789",
		"DB_PASSWORD":      "password123",
		"NON_SENSITIVE":    "visible",
		"SHORT_SECRET":     "short",
		"INVALID_PATTERN*": "should not crash",
	}

	fmt.Println("Original environment:")
	for k, v := range environment {
		fmt.Printf("%s: %s\n", k, v)
	}

	redactedVars := Vars(logger, patterns, environment)
	redactedEnvironment := make(map[string]string)
	for k, v := range environment {
		if _, ok := redactedVars[k]; ok {
			redactedEnvironment[k] = string(Redact([]byte(v)))
		} else {
			redactedEnvironment[k] = v
		}
	}

	fmt.Println("\nRedacted environment:")
	for k, v := range redactedEnvironment {
		fmt.Printf("%s: %s\n", k, v)
	}
}
