)

// MagicNumber represents the sequence of bytes that a valid ROM should start with.
var MagicNumber = []byte{0x7f, 0x45, 0x4c, 0x46}

// isValidROM checks if the given ROM starts with the Magic Number.
func isValidROM(rom []byte) bool {
	if len(rom) < len(MagicNumber) {
		return false
	}
	for i, b := range MagicNumber {
		if rom[i] != b {
			return false
		}
	}
	return true
}

// TestIsValidROM tests the isValidROM function with various test cases.
func TestIsValidROM(t *testing.T) {
	assert := assert.New(t)

	tests := []struct {
		Input    []byte
		Expected bool
	}{
		{
			Input:    append(MagicNumber, 0x00, 0x01, 0x02), // Valid ROM with additional bytes
			Expected: true,
		},
		{
			Input:    MagicNumber, // Valid ROM with only Magic Number
			Expected: true,
		},
		{
			Input:    []byte{}, // Empty ROM
			Expected: false,
		},
		{
			Input:    []byte{0xde, 0xad, 0xbe, 0xef}, // Invalid ROM with incorrect Magic Number
			Expected: false,
		},
		{
			Input:    []byte{0x7f, 0x45, 0x4c}, // Incomplete Magic Number
			Expected: false,
		},
	}

	for _, test := range tests {
		assert.Equal(test.Expected, isValidROM(test.Input), "ROM validation failed for input: %v", test.Input)
	}
}
