// replaceVersions replaces placeholders in the template with the provided version strings.
func replaceVersions(template string, versions ...interface{}) (string, error) {
	for _, version := range versions {
		if placeholder, ok := version.(string); ok {
			beforeCount := strings.Count(template, placeholder)
			if beforeCount < 1 {
				return "", fmt.Errorf("placeholder %s not found in template", placeholder)
			}
			template = strings.Replace(template, placeholder, "%s", 1)

			afterCount := strings.Count(template, placeholder)
			if beforeCount-1 != afterCount {
				return "", fmt.Errorf("failed to replace placeholder %s", placeholder)
			}
		}
	}
	return template, nil
}

// validateConfigExpectation compares the expected and actual configuration strings after replacing placeholders.
func validateConfigExpectation(t *testing.T, ID, expected, actual string, versions ...interface{}) {
