package main

import (
	"net/http"
	"sync"

	"github.com/gin-gonic/gin"
)

// InMemoryStore holds the in-memory key-value pairs.
type InMemoryStore struct {
	sync.RWMutex
	store map[string]string
}

// NewInMemoryStore creates a new InMemoryStore.
func NewInMemoryStore() *InMemoryStore {
	return &InMemoryStore{
		store: make(map[string]string),
	}
}

// Set sets a key-value pair in the store.
func (s *InMemoryStore) Set(key, value string) {
	s.Lock()
	defer s.Unlock()
	s.store[key] = value
}

// Get retrieves the value for a given key from the store.
func (s *InMemoryStore) Get(key string) (string, bool) {
	s.RLock()
	defer s.RUnlock()
	value, exists := s.store[key]
	return value, exists
}

// Delete removes a key-value pair from the store.
func (s *InMemoryStore) Delete(key string) {
	s.Lock()
	defer s.Unlock()
	delete(s.store, key)
}

// Keys lists all the keys in the store.
func (s *InMemoryStore) Keys() []string {
	s.RLock()
	defer s.RUnlock()
	keys := make([]string, 0, len(s.store))
	for key := range s.store {
		keys = append(keys, key)
	}
	return keys
}

func main() {
	gin.SetMode(gin.ReleaseMode)
	store := NewInMemoryStore()
	r := gin.Default()

	r.POST("/set", func(c *gin.Context) {
		var payload struct {
			Key   string `json:"key"`
			Value string `json:"value"`
		}
		if err := c.BindJSON(&payload); err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid request payload"})
			return
		}
		store.Set(payload.Key, payload.Value)
		c.JSON(http.StatusOK, gin.H{"status": "success"})
	})

	r.GET("/get/:key", func(c *gin.Context) {
		key := c.Param("key")
		value, exists := store.Get(key)
		if !exists {
			c.JSON(http.StatusNotFound, gin.H{"error": "Key not found"})
			return
		}
		c.JSON(http.StatusOK, gin.H{"value": value})
	})

	r.DELETE("/delete/:key", func(c *gin.Context) {
		key := c.Param("key")
		store.Delete(key)
		c.JSON(http.StatusOK, gin.H{"status": "success"})
	})

	r.GET("/keys", func(c *gin.Context) {
		keys := store.Keys()
		c.JSON(http.StatusOK, gin.H{"keys": keys})
	})

	r.Run("0.0.0.0:3000")
}
