// Codec interface for encoding and decoding messages.
type Codec interface {
	Encode(interface{}) ([]byte, error)
	Decode([]byte, interface{}) error
	ContentFormat() string
}

// GeneralMessageCodec for encoding and decoding JSON messages.
type GeneralMessageCodec struct{}

func (c GeneralMessageCodec) Encode(v interface{}) ([]byte, error) {
	return json.Marshal(v)
}

func (c GeneralMessageCodec) Decode(data []byte, v interface{}) error {
	return json.Unmarshal(data, v)
}

func (c GeneralMessageCodec) ContentFormat() string {
	return "application/json"
}

// CreateOption functional option for CreateResource.
type CreateOption func(*createOptions)

type createOptions struct {
	codec Codec
}

func WithCodec(codec Codec) CreateOption {
	return func(o *createOptions) {
		o.codec = codec
	}
}

// Client for interacting with the cloud-based IoT device management service.
type Client struct {
	gateway pb.GrpcGatewayClient
}

// CreateResource requests creation of a new resource on a device.
func (c *Client) CreateResource(
	ctx context.Context,
	deviceID string,
	href string,
	request interface{},
	response interface{},
	opts ...CreateOption,
) error {
	cfg := createOptions{
		codec: GeneralMessageCodec{},
	}
	for _, o := range opts {
		o(&cfg)
	}

	data, err := cfg.codec.Encode(request)
	if err != nil {
		return err
	}
	r := pb.CreateResourceRequest{
		ResourceId: commands.NewResourceID(deviceID, href),
		Content: &pb.Content{
			Data:        data,
			ContentType: cfg.codec.ContentFormat(),
		},
	}

	resp, err := c.gateway.CreateResource(ctx, &r)
	if err != nil {
		return fmt.Errorf("cannot create resource /%v/%v: %w", deviceID, href, err)
	}

	return cfg.codec.Decode(resp.GetContent().GetData(), response)
}

