	"math"
)

// maxNumberOfBalloons calculates the maximum number of times the word "balloon"
// can be formed from the letters in the input string `text`.
func maxNumberOfBalloons(text string) int {
	// Initialize an array to keep count of each letter's frequency.
	l := [26]int{}
	for _, b := range text {
		l[b-'a']++
	}
	// Since 'l' and 'o' are needed twice, halve their counts.
	l['l'-'a'] = l['l'-'a'] / 2
	l['o'-'a'] = l['o'-'a'] / 2

	// Find the minimum count among the letters 'b', 'a', 'l', 'o', 'n'.
	min := math.MaxInt16
	for _, b := range "balon" {
		v := l[b-'a']
		if v == 0 {
			return 0
		}
		if v < min {
			min = v
		}
	}
	return min
}

func main() {
	// Test cases to verify the solution correctness.
	fmt.Println(maxNumberOfBalloons("leetcode"))          // Output: 0
	fmt.Println(maxNumberOfBalloons("balloon"))           // Output: 1
	fmt.Println(maxNumberOfBalloons("balloonballoonx"))   // Output: 2
	fmt.Println(maxNumberOfBalloons("lloo"))              // Output: 0
	fmt.Println(maxNumberOfBalloons("balonbalonbalon"))   // Output: 3
}
