// ParkingRate represents individual parking rate information.
type ParkingRate struct {
	// Hourly rate for parking
	HourlyRate string `json:"hourly_rate,omitempty"`
	// Duration for which the hourly rate applies
	DurationHours int `json:"duration_hours,omitempty"`
}

// Validate validates this parking rate
func (m *ParkingRate) Validate(formats strfmt.Registry) error {
	if err := m.validateHourlyRate(); err != nil {
		return err
	}
	return nil
}

func (m *ParkingRate) validateHourlyRate() error {
	if swag.IsZero(m.HourlyRate) { // not required
		return nil
	}

	// Assuming the hourly rate should be a valid monetary amount
	matched, _ := regexp.MatchString(`^\d+(\.\d{1,2})?$`, m.HourlyRate)
	if !matched {
		return errors.New(400, "invalid hourly rate: %s", m.HourlyRate)
	}

	return nil
}

// ParkingCreateBody represents the parking creation parameters in the message body.
type ParkingCreateBody struct {
	// Additional parking information
	AdditionalParkingInformation string `json:"additional_parking_information,omitempty"`
	// Centre identifier
	CentreID string `json:"centre_id,omitempty"`
	// Credit card surcharge amount
	CreditCardSurchargeAmount string `json:"credit_card_surcharge_amount,omitempty"`
	// Fee when parking is not hourly
	FlatRate string `json:"flat_rate,omitempty"`
	// Maximum daily rate on weekdays
	MaximumDailyRateWeekday string `json:"maximum_daily_rate_weekday,omitempty"`
	// Maximum daily rate on weekends
	MaximumDailyRateWeekend string `json:"maximum_daily_rate_weekend,omitempty"`
	// Overnight fee on weekdays
	OvernightFeeWeekday string `json:"overnight_fee_weekday,omitempty"`
	// Overnight fee on weekends
	OvernightFeeWeekend string `json:"overnight_fee_weekend,omitempty"`
	// Parking rates
	ParkingRates []*ParkingRate `json:"parking_rates,omitempty"`
	// PDF filename for terms and conditions
	PdfRef string `json:"pdf_ref,omitempty"`
	// Fee (true) or complimentary (false) parking
	RatesApply bool `json:"rates_apply,omitempty"`
	// Type of rate
	TypeOfRate string `json:"type_of_rate,omitempty"`
	// Valet parking instructions
	ValetParkingInstructions string `json:"valet_parking_instructions,omitempty"`
}

// Validate validates this parking create body
func (m *ParkingCreateBody) Validate(formats strfmt.Registry) error {
	var res []error

	if err := m.validateParkingRates(formats); err != nil {
		res = append(res, err)
	}

	if len(res) > 0 {
		return errors.CompositeValidationError(res...)
	}
	return nil
}

func (m *ParkingCreateBody) validateParkingRates(formats strfmt.Registry) error {
	if swag.IsZero(m.ParkingRates) { // not required
		return nil
	}

	for i := 0; i < len(m.ParkingRates); i++ {
		if swag.IsZero(m.ParkingRates[i]) { // not required
			continue
		}

		if m.ParkingRates[i] != nil {
			if err := m.ParkingRates[i].Validate(formats); err != nil {
				return err
			}
		}
	}

	return nil
}

func main() {
	// Example test case
	parkingBody := ParkingCreateBody{
		CentreID: "123ABC",
		TypeOfRate: "Hourly",
		RatesApply: true,
		ParkingRates: []*ParkingRate{
			{
				HourlyRate: "5.00",
				DurationHours: 2,
			},
			{
				HourlyRate: "invalid_rate",
				DurationHours: 4,
			},
		},
	}

	err := parkingBody.Validate(strfmt.NewFormats())
	if err != nil {
		fmt.Println("Validation failed:", err)
	} else {
		fmt.Println("Validation passed!")
	}
}
