package main

import "fmt"

// TreeNode represents a node in a binary tree.
type TreeNode struct {
	Val   int
	Left  *TreeNode
	Right *TreeNode
}

// isSymNode checks if two nodes are symmetric.
func isSymNode(left *TreeNode, right *TreeNode) bool {
	if left == nil || right == nil {
		return left == right
	}

	if left.Val != right.Val {
		return false
	}

	return isSymNode(left.Left, right.Right) && isSymNode(left.Right, right.Left)
}

// isSymmetric checks if a binary tree is symmetric around its center.
func isSymmetric(root *TreeNode) bool {
	if root == nil {
		return true
	}

	return isSymNode(root.Left, root.Right)
}

func main() {
	// Test cases to verify the solution correctness.
	testCases := []struct {
		root     *TreeNode
		expected bool
	}{
		{
			root: &TreeNode{
				Val: 1,
				Left: &TreeNode{
					Val: 2,
					Left: &TreeNode{
						Val: 3,
					},
					Right: nil,
				},
				Right: &TreeNode{
					Val: 2,
					Left: &TreeNode{
						Val: 3,
					},
					Right: nil,
				},
			},
			expected: true,
		},
		{
			root: &TreeNode{
				Val: 1,
				Left: &TreeNode{
					Val: 2,
					Right: &TreeNode{
						Val: 3,
					},
				},
				Right: &TreeNode{
					Val: 2,
					Right: &TreeNode{
						Val: 3,
					},
				},
			},
			expected: false,
		},
	}

	for i, tc := range testCases {
		result := isSymmetric(tc.root)
		if result != tc.expected {
			fmt.Printf("Test case %d failed: expected %v, got %v\n", i+1, tc.expected, result)
		} else {
			fmt.Printf("Test case %d passed.\n", i+1)
		}
	}
}
