// Below is the test file for the log package.

package log

import (
	"bytes"
	"fmt"
	"os"
	"testing"
)

// captureOutput is a helper function to capture the output of a function call.
func captureOutput(f func()) string {
	var buf bytes.Buffer
	stdout := os.Stdout
	defer func() { os.Stdout = stdout }()
	os.Stdout = &buf
	f()
	return buf.String()
}

// TestPrintLogConst tests the PrintLogConst function.
func TestPrintLogConst(t *testing.T) {
	expected := "Log: Information\n"
	output := captureOutput(PrintLogConst)
	if output != expected {
		t.Errorf("PrintLogConst() = %q, want %q", output, expected)
	}
}

// TestFatal tests the Fatal function.
// Since Fatal exits the program, we need to recover from the panic caused by os.Exit.
func TestFatal(t *testing.T) {
	if os.Getenv("BE_CRASHER") == "1" {
		Fatal()
		return
	}

	cmd := fmt.Sprintf("BE_CRASHER=1 go test -run ^%s$", t.Name())
	expected := "Fatal Error: Exiting program\nexit status 1"
	output, err := captureOutput(func() { os.Exit(1) })
	if e, ok := err.(*exec.ExitError); ok && !e.Success() {
		output = fmt.Sprintf("%sexit status %d", output, e.ExitCode())
	}

	if output != expected {
		t.Fatalf("Fatal() = %q, want %q", output, expected)
	}
}
