package kvstore

import (
	"errors"
	"sync"
)

// KeyValueStore is a simple in-memory key-value store.
type KeyValueStore struct {
	store map[string]string
	mu    sync.RWMutex
}

// NewKeyValueStore creates a new KeyValueStore.
func NewKeyValueStore() *KeyValueStore {
	return &KeyValueStore{
		store: make(map[string]string),
	}
}

// Set sets a key-value pair in the store.
func (kvs *KeyValueStore) Set(key, value string) {
	kvs.mu.Lock()
	defer kvs.mu.Unlock()
	kvs.store[key] = value
}

// Get retrieves the value for a key from the store.
// It returns an error if the key does not exist.
func (kvs *KeyValueStore) Get(key string) (string, error) {
	kvs.mu.RLock()
	defer kvs.mu.RUnlock()
	value, exists := kvs.store[key]
	if !exists {
		return "", errors.New("key not found")
	}
	return value, nil
}

// Keeper implements the QueryServer interface and provides methods for setting and getting key-value pairs.
type Keeper struct {
	store *KeyValueStore
}

// NewKeeper creates a new Keeper with an in-memory key-value store.
func NewKeeper() *Keeper {
	return &Keeper{
		store: NewKeyValueStore(),
	}
}

// SetKeyValue handles the SetKeyValue functionality.
func (k *Keeper) SetKeyValue(key, value string) {
	k.store.Set(key, value)
}

// GetKeyValue handles the GetKeyValue functionality.
func (k *Keeper) GetKeyValue(key string) (string, error) {
	return k.store.Get(key)
}

// Example usage and test cases
func main() {
	keeper := NewKeeper()

	// Test SetKeyValue
	keeper.SetKeyValue("user1", "Alice")
	keeper.SetKeyValue("user2", "Bob")

	// Test GetKeyValue
	value, err := keeper.GetKeyValue("user1")
	if err != nil {
		panic(err)
	}
	println("user1:", value) // Expected output: user1: Alice

	value, err = keeper.GetKeyValue("user3")
	if err != nil {
		println(err.Error()) // Expected output: key not found
	} else {
		println("user3:", value)
	}
}
