package main

import (
	"errors"
	"fmt"
	"time"
)

type Area struct {
	Id        int       `gorm:"primary_key"`
	Name      string    `gorm:"primary_key"`
	ParentId  int
	Level     string
	CreatedAt time.Time
	UpdatedAt time.Time
}

type AreaManager struct {
	areas map[int]Area
}

func NewAreaManager() *AreaManager {
	return &AreaManager{
		areas: make(map[int]Area),
	}
}

func (m *AreaManager) AddArea(area Area) error {
	if _, exists := m.areas[area.Id]; exists {
		return errors.New("area with the given ID already exists")
	}
	area.CreatedAt = time.Now()
	area.UpdatedAt = area.CreatedAt
	m.areas[area.Id] = area
	return nil
}

func (m *AreaManager) UpdateArea(id int, updated Area) error {
	area, exists := m.areas[id]
	if !exists {
		return errors.New("area not found")
	}
	updated.CreatedAt = area.CreatedAt
	updated.UpdatedAt = time.Now()
	m.areas[id] = updated
	return nil
}

func (m *AreaManager) DeleteArea(id int) error {
	for _, area := range m.areas {
		if area.ParentId == id {
			return errors.New("cannot delete area with child areas")
		}
	}
	if _, exists := m.areas[id]; !exists {
		return errors.New("area not found")
	}
	delete(m.areas, id)
	return nil
}

func (m *AreaManager) GetArea(id int) (Area, error) {
	area, exists := m.areas[id]
	if !exists {
		return Area{}, errors.New("area not found")
	}
	return area, nil
}

func (m *AreaManager) ListAreasByParentId(parentId int) []Area {
	var childAreas []Area
	for _, area := range m.areas {
		if area.ParentId == parentId {
			childAreas = append(childAreas, area)
		}
	}
	return childAreas
}

func main() {
	manager := NewAreaManager()

	// Test cases
	country := Area{Id: 1, Name: "Country", Level: "country"}
	state := Area{Id: 2, Name: "State", ParentId: 1, Level: "state"}
	city := Area{Id: 3, Name: "City", ParentId: 2, Level: "city"}

	// Adding areas
	fmt.Println(manager.AddArea(country)) // Should print nil
	fmt.Println(manager.AddArea(state))   // Should print nil
	fmt.Println(manager.AddArea(city))    // Should print nil

	// Updating an area
	cityUpdated := Area{Id: 3, Name: "Updated City", ParentId: 2, Level: "city"}
	fmt.Println(manager.UpdateArea(3, cityUpdated)) // Should print nil

	// Deleting an area
	fmt.Println(manager.DeleteArea(2)) // Should print "cannot delete area with child areas"
	fmt.Println(manager.DeleteArea(3)) // Should print nil

	// Retrieving an area
	area, err := manager.GetArea(1)
	fmt.Println(area, err) // Should print the country area and nil

	// Listing areas by parent ID
	children := manager.ListAreasByParentId(1)
	fmt.Println(children) // Should print a list containing the state area
}
