// TreasuryDebitReversalNetwork represents the rails used to reverse the funds.
type TreasuryDebitReversalNetwork string

// Constants for TreasuryDebitReversalNetwork
const (
	TreasuryDebitReversalNetworkAch  TreasuryDebitReversalNetwork = "ach"
	TreasuryDebitReversalNetworkCard TreasuryDebitReversalNetwork = "card"
)

// TreasuryDebitReversalStatus represents the status of the DebitReversal.
type TreasuryDebitReversalStatus string

// Constants for TreasuryDebitReversalStatus
const (
	TreasuryDebitReversalStatusFailed     TreasuryDebitReversalStatus = "failed"
	TreasuryDebitReversalStatusProcessing TreasuryDebitReversalStatus = "processing"
	TreasuryDebitReversalStatusSucceeded  TreasuryDebitReversalStatus = "succeeded"
)

// TreasuryDebitReversalParams represents the parameters to reverse a ReceivedDebit.
type TreasuryDebitReversalParams struct {
	Amount          int64
	Currency        string
	FinancialAccount string
	Network         TreasuryDebitReversalNetwork
	ReceivedDebit   string
}

// TreasuryDebitReversal represents a debit reversal.
type TreasuryDebitReversal struct {
	ID               string
	Amount           int64
	Currency         string
	FinancialAccount string
	Network          TreasuryDebitReversalNetwork
	Status           TreasuryDebitReversalStatus
	ReceivedDebit    string
	StatusTransitions struct {
		CompletedAt int64
	}
}

// ReverseDebit simulates the reversal of a debit transaction.
func ReverseDebit(params TreasuryDebitReversalParams) TreasuryDebitReversal {
	return TreasuryDebitReversal{
		ID:               generateUniqueID(),
		Amount:           params.Amount,
		Currency:         params.Currency,
		FinancialAccount: params.FinancialAccount,
		Network:          params.Network,
		Status:           TreasuryDebitReversalStatusProcessing,
		ReceivedDebit:    params.ReceivedDebit,
	}
}

// UpdateDebitReversalStatus updates the status of a given TreasuryDebitReversal.
func UpdateDebitReversalStatus(debitReversal *TreasuryDebitReversal, newStatus TreasuryDebitReversalStatus) {
	debitReversal.Status = newStatus
	if newStatus == TreasuryDebitReversalStatusSucceeded {
		debitReversal.StatusTransitions.CompletedAt = time.Now().Unix()
	}
}

// generateUniqueID simulates the generation of a unique identifier.
func generateUniqueID() string {
	return fmt.Sprintf("dr_%d", time.Now().UnixNano())
}

func main() {
	// Test case 1: Reverse a debit transaction
	params := TreasuryDebitReversalParams{
		Amount:          10000,
		Currency:        "usd",
		FinancialAccount: "fa_123",
		Network:         TreasuryDebitReversalNetworkAch,
		ReceivedDebit:   "rd_456",
	}
	debitReversal := ReverseDebit(params)
	fmt.Printf("Debit Reversal Created: %+v\n", debitReversal)

	// Test case 2: Update the status of the debit reversal to succeeded
	UpdateDebitReversalStatus(&debitReversal, TreasuryDebitReversalStatusSucceeded)
