package profileawards

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"net/http"
	"time"
)

// Award represents a professional award in a user's profile.
type Award struct {
	ID                string    `json:"id"`
	Title             string    `json:"title"`
	IssuedDate        time.Time `json:"issuedDate"`
	IssuingOrganization string  `json:"issuingOrganization"`
	Description       string    `json:"description"`
}

// AwardsService provides operations to manage awards in a user's profile.
type AwardsService struct {
	client *http.Client
	baseURL string
}

// NewAwardsService creates a new instance of AwardsService.
func NewAwardsService(client *http.Client, baseURL string) *AwardsService {
	return &AwardsService{
		client:  client,
		baseURL: baseURL,
	}
}

// ListAwardsOptions specifies the optional parameters to the ListAwards method.
type ListAwardsOptions struct {
	Top    int
	Skip   int
	Filter string
	Order  string
}

// ListAwards retrieves a list of awards from a user's profile.
func (s *AwardsService) ListAwards(ctx context.Context, opts *ListAwardsOptions) ([]Award, error) {
	url := fmt.Sprintf("%s/me/profile/awards", s.baseURL)
	req, err := http.NewRequestWithContext(ctx, "GET", url, nil)
	if err != nil {
		return nil, err
	}

	// Add query parameters to the request URL.
	q := req.URL.Query()
	if opts != nil {
		if opts.Top > 0 {
			q.Add("$top", fmt.Sprintf("%d", opts.Top))
		}
		if opts.Skip > 0 {
			q.Add("$skip", fmt.Sprintf("%d", opts.Skip))
		}
		if opts.Filter != "" {
			q.Add("$filter", opts.Filter)
		}
		if opts.Order != "" {
			q.Add("$orderby", opts.Order)
		}
	}
	req.URL.RawQuery = q.Encode()

	resp, err := s.client.Do(req)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return nil, errors.New("failed to retrieve awards")
	}

	var awards []Award
	if err := json.NewDecoder(resp.Body).Decode(&awards); err != nil {
		return nil, err
	}

	return awards, nil
}

// CreateAward creates a new award in a user's profile.
func (s *AwardsService) CreateAward(ctx context.Context, award Award) (*Award, error) {
	url := fmt.Sprintf("%s/me/profile/awards", s.baseURL)
	payload, err := json.Marshal(award)
	if err != nil {
		return nil, err
	}

	req, err := http.NewRequestWithContext(ctx, "POST", url, bytes.NewBuffer(payload))
	if err != nil {
		return nil, err
	}
	req.Header.Set("Content-Type", "application/json")

	resp, err := s.client.Do(req)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusCreated {
		return nil, errors.New("failed to create award")
	}

	var newAward Award
	if err := json.NewDecoder(resp.Body).Decode(&newAward); err != nil {
		return nil, err
	}

	return &newAward, nil
}

// Example test cases to verify the solution correctness.
func main() {
	client := &http.Client{}
	service := NewAwardsService(client, "https://graph.microsoft.com/v1.0")

	// List awards with pagination.
	awards, err := service.ListAwards(context.Background(), &ListAwardsOptions{Top: 10, Skip: 0})
	if err != nil {
		fmt.Println("Error listing awards:", err)
		return
	}
	fmt.Println("Awards:", awards)

	// Create a new award.
	newAward, err := service.CreateAward(context.Background(), Award{
		Title:             "Best Innovator",
		IssuedDate:        time.Now(),
		IssuingOrganization: "Innovation Committee",
		Description:       "Awarded for outstanding innovation in technology.",
	})
	if err != nil {
		fmt.Println("Error creating award:", err)
		return
	}
	fmt.Println("New Award:", newAward)
}
