package main

import (
	"flag"
	"fmt"
	"sort"
	"sync"
)

type Task struct {
	ID          int
	Description string
	Priority    int
	Completed   bool
}

type TaskManager struct {
	sync.Mutex
	tasks []Task
	nextID int
}

func (tm *TaskManager) AddTask(description string, priority int) {
	tm.Lock()
	defer tm.Unlock()
	tm.nextID++
	task := Task{
		ID:          tm.nextID,
		Description: description,
		Priority:    priority,
		Completed:   false,
	}
	tm.tasks = append(tm.tasks, task)
}

func (tm *TaskManager) ListTasks() {
	tm.Lock()
	defer tm.Unlock()
	sort.Slice(tm.tasks, func(i, j int) bool {
		if tm.tasks[i].Priority == tm.tasks[j].Priority {
			return tm.tasks[i].ID < tm.tasks[j].ID
		}
		return tm.tasks[i].Priority < tm.tasks[j].Priority
	})
	for _, task := range tm.tasks {
		status := "Pending"
		if task.Completed {
			status = "Completed"
		}
		fmt.Printf("ID: %d, Description: %s, Priority: %d, Status: %s\n", task.ID, task.Description, task.Priority, status)
	}
}

func (tm *TaskManager) CompleteTask(id int) {
	tm.Lock()
	defer tm.Unlock()
	for i, task := range tm.tasks {
		if task.ID == id {
			tm.tasks[i].Completed = true
			return
		}
	}
	fmt.Printf("Task with ID %d not found.\n", id)
}

var (
	addFlag      string
	priorityFlag int
	listFlag     bool
	completeFlag int
)

func init() {
	flag.StringVar(&addFlag, "add", "", "Add a new task with a description")
	flag.IntVar(&priorityFlag, "priority", 3, "Priority of the task (1-5)")
	flag.BoolVar(&listFlag, "list", false, "List all tasks")
	flag.IntVar(&completeFlag, "complete", 0, "Mark a task as completed by its ID")
}

func main() {
	flag.Parse()

	taskManager := TaskManager{}

	if addFlag != "" {
		taskManager.AddTask(addFlag, priorityFlag)
	}

	if listFlag {
		taskManager.ListTasks()
	}

	if completeFlag > 0 {
		taskManager.CompleteTask(completeFlag)
	}
}

// Test cases to verify the solution correctness
func main() {
	taskManager := TaskManager{}

	// Adding tasks
	taskManager.AddTask("Buy milk", 2)
	taskManager.AddTask("Send email", 1)
	taskManager.AddTask("Walk the dog", 3)

	// Listing tasks
	taskManager.ListTasks()

	// Completing a task
	taskManager.CompleteTask(1)

	// Listing tasks again to see the changes
	taskManager.ListTasks()
}
