// encodeOne encodes a single value into a string representation.
func encodeOne(rv *reflect.Value) (string, error) {
	switch rv.Kind() {
	case reflect.Int, reflect.Int8, reflect.Int16, reflect.Int32, reflect.Int64:
		return fmt.Sprintf("%d", rv.Int()), nil
	case reflect.Uint, reflect.Uint8, reflect.Uint16, reflect.Uint32, reflect.Uint64:
		return fmt.Sprintf("%d", rv.Uint()), nil
	case reflect.Float32, reflect.Float64:
		return fmt.Sprintf("%v", rv.Float()), nil
	case reflect.Bool:
		return fmt.Sprintf("%t", rv.Bool()), nil
	case reflect.String:
		return rv.String(), nil
	case reflect.Ptr:
		if rv.IsNil() {
			return "", errors.New("nil pointer cannot be encoded")
		}
		elem := rv.Elem()
		return encodeOne(&elem)
	default:
		return "", fmt.Errorf("unsupported type: %s", rv.Type())
	}
}

// ToQueryMap converts a request object into a query map.
func ToQueryMap(req Common) (map[string]string, error) {
	queryMap := make(map[string]string)
	rv := reflect.ValueOf(req).Elem()
	rt := rv.Type()

	for i := 0; i < rv.NumField(); i++ {
		field := rv.Field(i)
		if !field.CanInterface() {
			continue // Skip unexported fields
		}

		fieldName := rt.Field(i).Name
		if field.Kind() == reflect.Struct {
			// Recursively encode nested structs
			nestedMap, err := ToQueryMap(field.Addr().Interface().(Common))
			if err != nil {
				return nil, err
			}
			for k, v := range nestedMap {
				queryMap[fmt.Sprintf("%s.%s", fieldName, k)] = v
			}
		} else {
			encodedValue, err := encodeOne(&field)
			if err != nil {
				return nil, err
			}
			queryMap[fieldName] = encodedValue
		}
	}

	return queryMap, nil
}

