)

type CallState int

const (
	INCOMING_CALLSTATE CallState = iota
	ESTABLISHING_CALLSTATE
	ESTABLISHED_CALLSTATE
	HOLD_CALLSTATE
	TRANSFERRING_CALLSTATE
	TRANSFERACCEPTED_CALLSTATE
	REDIRECTING_CALLSTATE
	TERMINATING_CALLSTATE
	TERMINATED_CALLSTATE
	UNKNOWNFUTUREVALUE_CALLSTATE
)

func (i CallState) String() string {
	return []string{"INCOMING", "ESTABLISHING", "ESTABLISHED", "HOLD", "TRANSFERRING", "TRANSFERACCEPTED", "REDIRECTING", "TERMINATING", "TERMINATED", "UNKNOWNFUTUREVALUE"}[i]
}

func ParseCallState(v string) (CallState, error) {
	switch strings.ToUpper(v) {
	case "INCOMING":
		return INCOMING_CALLSTATE, nil
	case "ESTABLISHING":
		return ESTABLISHING_CALLSTATE, nil
	case "ESTABLISHED":
		return ESTABLISHED_CALLSTATE, nil
	case "HOLD":
		return HOLD_CALLSTATE, nil
	case "TRANSFERRING":
		return TRANSFERRING_CALLSTATE, nil
	case "TRANSFERACCEPTED":
		return TRANSFERACCEPTED_CALLSTATE, nil
	case "REDIRECTING":
		return REDIRECTING_CALLSTATE, nil
	case "TERMINATING":
		return TERMINATING_CALLSTATE, nil
	case "TERMINATED":
		return TERMINATED_CALLSTATE, nil
	case "UNKNOWNFUTUREVALUE":
		return UNKNOWNFUTUREVALUE_CALLSTATE, nil
	}
	return 0, errors.New("Unknown CallState value: " + v)
}

func SerializeCallState(values []CallState) []string {
	result := make([]string, len(values))
	for i, v := range values {
		result[i] = v.String()
	}
	return result
}

func IsValidTransition(from, to CallState) bool {
	validTransitions := map[CallState][]CallState{
		INCOMING_CALLSTATE:        {ESTABLISHING_CALLSTATE, TERMINATED_CALLSTATE},
		ESTABLISHING_CALLSTATE:    {ESTABLISHED_CALLSTATE, TERMINATED_CALLSTATE},
		ESTABLISHED_CALLSTATE:     {HOLD_CALLSTATE, TRANSFERRING_CALLSTATE, TERMINATING_CALLSTATE},
		HOLD_CALLSTATE:            {ESTABLISHED_CALLSTATE, TERMINATING_CALLSTATE},
		TRANSFERRING_CALLSTATE:    {TRANSFERACCEPTED_CALLSTATE, TERMINATING_CALLSTATE},
		TRANSFERACCEPTED_CALLSTATE: {ESTABLISHED_CALLSTATE, TERMINATING_CALLSTATE},
		REDIRECTING_CALLSTATE:     {ESTABLISHING_CALLSTATE, TERMINATED_CALLSTATE},
		TERMINATING_CALLSTATE:     {TERMINATED_CALLSTATE},
		TERMINATED_CALLSTATE:      {},
		UNKNOWNFUTUREVALUE_CALLSTATE: {},
	}

	for _, validTo := range validTransitions[from] {
		if to == validTo {
			return true
		}
	}
	return false
}

// Test cases to verify the solution correctness
func main() {
	// Test ParseCallState
	incoming, err := ParseCallState("INCOMING")
	if err != nil || incoming != INCOMING_CALLSTATE {
		panic("ParseCallState failed for INCOMING")
	}

	// Test SerializeCallState
	states := []CallState{INCOMING_CALLSTATE, ESTABLISHED_CALLSTATE, TERMINATED_CALLSTATE}
	serializedStates := SerializeCallState(states)
	expectedSerializedStates := []string{"INCOMING", "ESTABLISHED", "TERMINATED"}
	for i, state := range serializedStates {
		if state != expectedSerializedStates[i] {
			panic("SerializeCallState failed")
		}
	}

	// Test IsValidTransition
	if !IsValidTransition(INCOMING_CALLSTATE, ESTABLISHING_CALLSTATE) {
		panic("IsValidTransition failed for valid transition INCOMING -> ESTABLISHING")
	}
	if IsValidTransition(ESTABLISHED_CALLSTATE, INCOMING_CALLSTATE) {
		panic("IsValidTransition failed for invalid transition ESTABLISHED -> INCOMING")
	}
}
