package main

import (
	"net/http"
	"os"
	"path/filepath"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/spf13/afero"
)

// FileInfo represents the details of a file or directory.
type FileInfo struct {
	Name     string      `json:"name"`    // base name of the file
	Fullname string      `json:"fullname"`
	Ext      string      `json:"ext"`
	Size     int64       `json:"size"`     // length in bytes for regular files; system-dependent for others
	Mode     os.FileMode `json:"mode"`     // file mode bits
	ModTime  time.Time   `json:"mod_time"` // modification time
	IsDir    bool        `json:"is_dir"`   // abbreviation for Mode().IsDir()
}

// ListFilesHandler creates a handler function that lists the contents of a directory.
func ListFilesHandler(fs afero.Fs) gin.HandlerFunc {
	return func(c *gin.Context) {
		var request struct {
			Path     string `form:"path" binding:"required"`
			ShowHide bool   `form:"show_hide"`
		}
		if err := c.ShouldBindQuery(&request); err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
			return
		}

		info, err := fs.Stat(request.Path)
		if err != nil {
			c.JSON(http.StatusNotFound, gin.H{"error": err.Error()})
			return
		}

		if !info.IsDir() {
			c.FileFromFS(request.Path, afero.NewHttpFs(fs))
			return
		}

		infos, err := afero.ReadDir(fs, request.Path)
		if err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
			return
		}

		result := make([]*FileInfo, 0, len(infos))
		for _, fi := range infos {
			if fi.Name()[0] == '.' && !request.ShowHide {
				continue
			}
			fullname := filepath.Join(request.Path, fi.Name())
			result = append(result, &FileInfo{
				Name:     fi.Name(),
				Fullname: fullname,
				Ext:      filepath.Ext(fi.Name()),
				Size:     fi.Size(),
				Mode:     fi.Mode(),
				ModTime:  fi.ModTime(),
				IsDir:    fi.IsDir(),
			})
		}

		c.JSON(http.StatusOK, result)
	}
}

func main() {
	fs := afero.NewMemMapFs() // Using an in-memory filesystem for demonstration purposes.
	router := gin.Default()
	router.GET("/list", ListFilesHandler(fs))
	router.Run(":8080")
}

