}

// FollowAction allows a user to follow another user.
func FollowAction(ctx context.Context, userID, targetUserID int64) error {
	req := &rpcSocialNetwork.FollowActionRequest{
		UserId:       userID,
		TargetUserId: targetUserID,
	}
	resp, err := socialNetworkClient.FollowAction(ctx, req)
	if err != nil {
		return err
	}
	if resp.BaseResp.StatusCode != 0 {
		return errno.NewErrNo(resp.BaseResp.StatusCode, resp.BaseResp.StatusMsg)
