package sessionstore

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"os"
	"time"

	_ "github.com/mattn/go-sqlite3"
)

// Store represents the session storage system.
type Store struct {
	db                 *sql.DB
	sessionTableName   string
	automigrateEnabled bool
	debugEnabled       bool
}

// NewStoreOptions contains options for creating a new Store.
type NewStoreOptions struct {
	DB                 *sql.DB
	SessionTableName   string
	AutomigrateEnabled bool
	DebugEnabled       bool
}

// NewStore creates a new instance of Store with the given options.
func NewStore(opts NewStoreOptions) (*Store, error) {
	store := &Store{
		db:                 opts.DB,
		sessionTableName:   opts.SessionTableName,
		automigrateEnabled: opts.AutomigrateEnabled,
		debugEnabled:       opts.DebugEnabled,
	}

	if store.automigrateEnabled {
		if err := store.AutoMigrate(); err != nil {
			return nil, err
		}
	}

	return store, nil
}

// AutoMigrate automatically creates the session table if it does not exist.
func (s *Store) AutoMigrate() error {
	query := fmt.Sprintf(`CREATE TABLE IF NOT EXISTS %s (
		key TEXT PRIMARY KEY,
		value TEXT NOT NULL,
		expiration INTEGER NOT NULL
	)`, s.sessionTableName)

	_, err := s.db.Exec(query)
	if err != nil {
		return err
	}

	if s.debugEnabled {
		fmt.Println("Automigration completed.")
	}

	return nil
}

// Set creates or updates a session with the given key, value, and expiration time in seconds.
func (s *Store) Set(key, value string, expiration int64) error {
	expirationTime := time.Now().Add(time.Duration(expiration) * time.Second).Unix()
	query := fmt.Sprintf(`INSERT INTO %s (key, value, expiration) VALUES (?, ?, ?)
		ON CONFLICT(key) DO UPDATE SET value=excluded.value, expiration=excluded.expiration`, s.sessionTableName)

	_, err := s.db.Exec(query, key, value, expirationTime)
	if err != nil {
		return err
	}

	if s.debugEnabled {
		fmt.Printf("Session set: key=%s, value=%s, expiration=%d\n", key, value, expiration)
	}

	return nil
}

// Get retrieves the value of a session by its key.
func (s *Store) Get(key string) (string, error) {
	var value string
	var expiration int64

	query := fmt.Sprintf(`SELECT value, expiration FROM %s WHERE key = ?`, s.sessionTableName)
	row := s.db.QueryRow(query, key)
	err := row.Scan(&value, &expiration)
	if err != nil {
		if err == sql.ErrNoRows {
			return "", nil // No session found
		}
		return "", err
	}

	if time.Now().Unix() > expiration {
		return "", nil // Session expired
	}

	return value, nil
}

// Delete removes a session by its key.
func (s *Store) Delete(key string) (bool, error) {
	query := fmt.Sprintf(`DELETE FROM %s WHERE key = ?`, s.sessionTableName)
	result, err := s.db.Exec(query, key)
	if err != nil {
		return false, err
	}

	rowsAffected, err := result.RowsAffected()
	if err != nil {
		return false, err
	}

	if s.debugEnabled {
		fmt.Printf("Session deleted: key=%s\n", key)
	}

	return rowsAffected > 0, nil
}

// Has checks if a session exists by its key.
func (s *Store) Has(key string) (bool, error) {
	var exists bool
	query := fmt.Sprintf(`SELECT EXISTS(SELECT 1 FROM %s WHERE key = ?)`, s.sessionTableName)
	err := s.db.QueryRow(query, key).Scan(&exists)
	if err != nil {
		return false, err
	}

	return exists, nil
}

// SetJSON stores a session with JSON data.
func (s *Store) SetJSON(key string, value interface{}, expiration int64) error {
	jsonValue, err := json.Marshal(value)
	if err != nil {
		return err
	}

	return s.Set(key, string(jsonValue), expiration)
}

// GetJSON retrieves a session with JSON data.
func (s *Store) GetJSON(key string, target interface{}) error {
	value, err := s.Get(key)
	if err != nil {
		return err
	}

	if value == "" {
		return nil // No session found or expired
	}

	return json.Unmarshal([]byte(value), target)
}

// EnableDebug enables or disables debug mode.
func (s *Store) EnableDebug(enabled bool) {
	s.debugEnabled = enabled
}

// InitDB initializes the database connection and removes any existing database file.
func InitDB(filepath string) *sql.DB {
	os.Remove(filepath) // remove database file if it exists
	dsn := filepath + "?parseTime=true"
	db, err := sql.Open("sqlite3", dsn)
	if err != nil {
		panic(err)
	}
	return db
}

