package main

import (
	"fmt"
	lls "github.com/alexandrestein/gods/stacks/linkedliststack"
)

// ReverseStack reverses the elements of a stack using only stack operations.
func ReverseStack(stack *lls.Stack) {
	if stack.Empty() {
		return
	}

	// Pop elements from the stack and push them into a temporary stack
	tempStack := lls.New()
	for !stack.Empty() {
		value, _ := stack.Pop()
		tempStack.Push(value)
	}

	// Pop elements from the temporary stack and push them back into the original stack
	for !tempStack.Empty() {
		value, _ := tempStack.Pop()
		stack.Push(value)
	}
}

func main() {
	stack := lls.New()
	stack.Push(1)
	stack.Push(2)
	stack.Push(3)
	fmt.Println("Original stack:", stack.Values())

	ReverseStack(stack)
	fmt.Println("Reversed stack:", stack.Values())
}
