// ListResourceGroups is a mock implementation that returns a fixed list of resource groups or an error.
func (c *MockResourceGroupsClient) ListResourceGroups(ctx context.Context) ([]string, error) {
	if ctx.Value("error") != nil {
		return nil, ctx.Value("error").(error)
	}
	return []string{"Group1", "Group2"}, nil
}

// Router is a struct that holds methods for handling HTTP requests.
type Router struct{}

// getInstance is a mock implementation that returns a mock resource groups client or nil based on the instance name.
func (router *Router) getInstance(name string) *MockResourceGroupsClient {
	if name == "valid-instance" {
		return &MockResourceGroupsClient{}
	}
	return nil
}

// getResourceGroups is the HTTP handler for retrieving resource groups from an Azure instance.
func (router *Router) getResourceGroups(w http.ResponseWriter, r *http.Request) {
	name := chi.URLParam(r, "name")

	zap.S().Debug("Get resource groups parameters.", zap.String("name", name))

	i := router.getInstance(name)
	if i == nil {
		zap.S().Error("Could not find instance name.", zap.String("name", name))
		http.Error(w, "Could not find instance name", http.StatusBadRequest)
		return
	}

	resourceGroups, err := i.ListResourceGroups(r.Context())
	if err != nil {
		zap.S().Error("Could not list resource groups.", zap.Error(err))
		http.Error(w, "Could not list resource groups", http.StatusInternalServerError)
		return
	}

	json.NewEncoder(w).Encode(resourceGroups)
}

// Test cases to verify the correctness of the getResourceGroups function.
func TestGetResourceGroups(t *testing.T) {
	r := chi.NewRouter()
	router := &Router{}
	r.Get("/resourcegroups/{name}", router.getResourceGroups)

	// Test case when the instance is valid and there is no error listing resource groups.
	req := httptest.NewRequest(http.MethodGet, "/resourcegroups/valid-instance", nil)
	w := httptest.NewRecorder()
	r.ServeHTTP(w, req)
	assert.Equal(t, http.StatusOK, w.Code)
	assert.JSONEq(t, `["Group1", "Group2"]`, w.Body.String())

	// Test case when the instance name is invalid.
	req = httptest.NewRequest(http.MethodGet, "/resourcegroups/invalid-instance", nil)
	w = httptest.NewRecorder()
	r.ServeHTTP(w, req)
	assert.Equal(t, http.StatusBadRequest, w.Code)
	assert.Equal(t, "Could not find instance name\n", w.Body.String())

	// Test case when there is an error listing resource groups.
	req = httptest.NewRequest(http.MethodGet, "/resourcegroups/valid-instance", nil)
	req = req.WithContext(context.WithValue(req.Context(), "error", context.Canceled))
	w = httptest.NewRecorder()
	r.ServeHTTP(w, req)
	assert.Equal(t, http.StatusInternalServerError, w.Code)
	assert.Equal(t, "Could not list resource groups\n", w.Body.String())
}
