	flag.Parse()

	log.Printf("Starting greeting service for %s", *name)

	// Setup signal catching
	sigs := make(chan os.Signal, 1)

	// Catch all signals since not explicitly listing
	signal.Notify(sigs)

	// Method invoked upon seeing signal
	go func() {
		for sig := range sigs {
			log.Printf("RECEIVED SIGNAL: %s", sig)

			switch sig {
			case syscall.SIGINT, syscall.SIGTERM:
				AppCleanup()
				os.Exit(1)
			case syscall.SIGURG:
				// Ignoring SIGURG used for preemption in Go runtime since 1.14
				log.Printf("Ignoring SIGURG")
			default:
				// Handle other signals if necessary
			}
		}
	}()

	// Infinite print loop
	for {
		log.Printf("hello %s", *name)

		// Wait random number of milliseconds
		nSecs := rand.Intn(3000)
		log.Printf("About to sleep %dms before looping again", nSecs)
		time.Sleep(time.Millisecond * time.Duration(nSecs))
	}
}

func AppCleanup() {
