// HTTPError represents an error with an associated HTTP status code and message.
type HTTPError struct {
	Code    int
	Message string
}

// Error returns the string representation of the HTTPError.
func (e *HTTPError) Error() string {
	return fmt.Sprintf("HTTP %d: %s", e.Code, e.Message)
}

// KubernetesErrorToHTTPError converts a Kubernetes API error to an HTTPError.
// If the error is not a Kubernetes API error, the original error is returned.
func KubernetesErrorToHTTPError(err error) error {
	if kubernetesError, ok := err.(*kerrors.StatusError); ok {
		httpCode := int(kubernetesError.Status().Code)
		httpMessage := kubernetesError.Status().Message
		return &HTTPError{Code: httpCode, Message: httpMessage}
	}
	return err
}

func main() {
	// Test cases
	testCases := []struct {
		name string
		err  error
	}{
		{
			name: "Kubernetes StatusError",
			err: &kerrors.StatusError{
				ErrStatus: metav1.Status{
					Code:    http.StatusNotFound,
					Message: "Resource not found",
				},
			},
		},
		{
			name: "Generic error",
			err:  fmt.Errorf("generic error"),
		},
	}

	for _, tc := range testCases {
		fmt.Printf("Test case: %s\n", tc.name)
		result := KubernetesErrorToHTTPError(tc.err)
		switch result.(type) {
		case *HTTPError:
			httpErr := result.(*HTTPError)
			fmt.Printf("Converted to HTTPError: Code=%d, Message=%s\n", httpErr.Code, httpErr.Message)
		default:
			fmt.Printf("Original error: %s\n", result.Error())
		}
	}
}
