// initEnv loads the .env file
func initEnv() {
	if _, err := os.Stat(".env"); errors.Is(err, os.ErrNotExist) {
		fmt.Println("skip load .env file")
		return
	}
	err := godotenv.Load()
	if err != nil {
		fmt.Printf("init env has failed with error: %v\n", err)
		os.Exit(1)
	}
}

// initLogger creates a new zap.Logger
func initLogger() *zap.Logger {
	return logger.NewLogger()
}

// initConfig initializes the config.
func initConfig() *config.Configurations {
	viper.SetConfigType("yaml")

	// Expand environment variables inside the config file
	b, err := os.ReadFile(configFile)
	if err != nil {
		fmt.Printf("read config has failed with error: %v\n", err)
		os.Exit(1)
	}

	expand := os.ExpandEnv(string(b))
	configReader := strings.NewReader(expand)

	viper.AutomaticEnv()

	if err := viper.ReadConfig(configReader); err != nil {
		fmt.Printf("read config has failed with error: %v\n", err)
		os.Exit(1)
	}

	configs := config.Configurations{}
	if err := viper.Unmarshal(&configs); err != nil {
		fmt.Printf("unmarshal config has failed with error: %v\n", err)
		os.Exit(1)
	}

	return &configs
}

func main() {
	initEnv()
	log := initLogger()
	configs := initConfig()

	// Connect to PostgreSQL database
	client, err := ent.Open("postgres", configs.Postgres.ConnectionString)
	if err != nil {
		log.Error("Error connecting to PostgreSQL database", zap.Error(err))
		os.Exit(1)
	}
	defer client.Close()

	// Run the auto migration tool
	if err := client.Schema.Create(context.Background()); err != nil {
		log.Error("Failed to create db schema from the automation migration tool", zap.Error(err))
		os.Exit(1)
	}

	// Create a Gin router instance
	r := gin.Default()

	// Use middlewares
	r.Use(
		middleware.AuthMiddleware(),
		middleware.CorsMiddleware(),
		middleware.RequestCtxMiddleware(),
		ginzap.Ginzap(log, time.RFC3339, true),
		ginzap.RecoveryWithZap(log, true),
	)

	srv := handler.NewDefaultServer(resolver.NewSchema(client))

