// HexCipher provides methods to encrypt and decrypt messages using hexadecimal encoding.
type HexCipher struct{}

// Encrypt takes a plaintext byte slice and returns a hexadecimal encoded byte slice.
func (c HexCipher) Encrypt(ptxt []byte) []byte {
	return []byte(hex.EncodeToString(ptxt))
}

// Decrypt takes a hexadecimal encoded byte slice and returns the original plaintext byte slice.
// If the input is not a valid hexadecimal string, it returns an empty byte slice.
func (c HexCipher) Decrypt(ctxt []byte) []byte {
	ptxt, err := hex.DecodeString(string(ctxt))
	if err != nil {
		return []byte{}
	}
	return ptxt
}

