package main

import (
	"encoding/json"
	"net/http"

	"github.com/go-chi/chi"
	"github.com/google/uuid"
)

type CSPReport struct {
	ID             uuid.UUID `json:"id"`
	ViolatedDirective string `json:"violated-directive"`
	BlockedURI        string `json:"blocked-uri"`
	DocumentURI       string `json:"document-uri"`
	UserAgent         string `json:"user-agent"`
}

type ReportService interface {
	Create(CSPReport) (CSPReport, error)
	GetByID(uuid.UUID) (CSPReport, error)
	ListReports() ([]CSPReport, error)
}

type inMemoryReportService struct {
	reports map[uuid.UUID]CSPReport
}

func NewInMemoryReportService() ReportService {
	return &inMemoryReportService{
		reports: make(map[uuid.UUID]CSPReport),
	}
}

func (s *inMemoryReportService) Create(report CSPReport) (CSPReport, error) {
	report.ID = uuid.New()
	s.reports[report.ID] = report
	return report, nil
}

func (s *inMemoryReportService) GetByID(id uuid.UUID) (CSPReport, error) {
	report, exists := s.reports[id]
	if !exists {
		return CSPReport{}, http.ErrMissingFile
	}
	return report, nil
}

func (s *inMemoryReportService) ListReports() ([]CSPReport, error) {
	reports := make([]CSPReport, 0, len(s.reports))
	for _, report := range s.reports {
		reports = append(reports, report)
	}
	return reports, nil
}

func main() {
	r := chi.NewRouter()
	rs := NewInMemoryReportService()
	h := newReportHandler(rs)

	r.Route("/reports", func(r chi.Router) {
		r.Post("/", h.postReport)
		r.Get("/{id}", h.getReport)
		r.Get("/", h.listReports)
	})

	http.ListenAndServe(":8080", r)
}

type reportHandler struct {
	rs ReportService
}

func newReportHandler(rs ReportService) *reportHandler {
	return &reportHandler{
		rs: rs,
	}
}

func (h *reportHandler) postReport(writer http.ResponseWriter, request *http.Request) {
	var report CSPReport
	if err := json.NewDecoder(request.Body).Decode(&report); err != nil {
		http.Error(writer, err.Error(), http.StatusBadRequest)
		return
	}

	report.UserAgent = request.Header.Get("User-Agent")
	createdReport, err := h.rs.Create(report)
	if err != nil {
		http.Error(writer, err.Error(), http.StatusInternalServerError)
		return
	}

	writer.Header().Set("Content-Type", "application/json")
	writer.WriteHeader(http.StatusCreated)
	json.NewEncoder(writer).Encode(createdReport)
}

func (h *reportHandler) getReport(writer http.ResponseWriter, request *http.Request) {
	rawID := chi.URLParam(request, "id")
	id, err := uuid.Parse(rawID)
	if err != nil {
		http.Error(writer, err.Error(), http.StatusBadRequest)
		return
	}

	report, err := h.rs.GetByID(id)
	if err != nil {
		http.Error(writer, err.Error(), http.StatusNotFound)
		return
	}

	writer.Header().Set("Content-Type", "application/json")
	json.NewEncoder(writer).Encode(report)
}

func (h *reportHandler) listReports(writer http.ResponseWriter, request *http.Request) {
	reports, err := h.rs.ListReports()
	if err != nil {
		http.Error(writer, err.Error(), http.StatusInternalServerError)
		return
	}

	writer.Header().Set("Content-Type", "application/json")
	json.NewEncoder(writer).Encode(reports)
}
