package main

import (
	"bufio"
	"context"
	"fmt"
	"net"
	"os"
	"strings"
	"time"

	opentracing "github.com/opentracing/opentracing-go"
	"github.com/opentracing/opentracing-go/log"
	"github.com/wubbalubbaaa/easyRpc"
	"github.com/wubbalubbaaa/easyRpc/extension/middleware/coder/tracing"
)

func main() {
	// Initialize the client with a connection to the server.
	client, err := easyRpc.NewClient(func() (net.Conn, error) {
		return net.DialTimeout("tcp", "localhost:8888", time.Second*3)
	})
	if err != nil {
		panic(err)
	}
	defer client.Stop()

	// Initialize the tracer and set it as the global tracer.
	tracer := tracing.NewTracer(nil)
	opentracing.InitGlobalTracer(tracer)

	// Use the tracer as the coder for the client handler.
	client.Handler.UseCoder(tracer)

	// Create a buffered reader for standard input.
	reader := bufio.NewReader(os.Stdin)

	// Continuously read input from the user.
	for {
		// Start a new span for getting user input.
		span := opentracing.StartSpan("getInput")
		span.SetTag("component", "client")
		ctx := opentracing.ContextWithSpan(context.Background(), span)
		// Set a baggage item to demonstrate global baggage propagation.
		span.SetBaggageItem("user", "echo")
		span.LogFields(log.Object("ctx", ctx))

		// Prompt the user for input.
		fmt.Print("\n\nEnter text (empty string to exit): ")
		text, _ := reader.ReadString('\n')
		text = strings.TrimSpace(text)
		if len(text) == 0 {
			fmt.Println("Exiting.")
			os.Exit(0)
		}

		// Log the user input.
		span.LogFields(log.String("user text", text))

		// Prepare the request and response variables.
		req := text
		rsp := ""

		// Make the RPC call to the server with tracing information.
		err = client.Call("/echo", &req, &rsp, time.Second*5, tracing.Values(span.Context()))
		if err != nil {
			// Log any errors that occur during the call.
			span.LogFields(log.Error(err))
		} else {
			// Log the server response.
			span.LogFields(log.String("rsp", rsp))
			fmt.Println("Server response:", rsp)
		}

		// Finish the span.
		span.Finish()
	}
}
