	}
	defer r.Body.Close()

	log.Printf("Received payload: %v\n", payload)
	w.WriteHeader(http.StatusOK)
}

func dispatchPayloads() {
	ticker := time.NewTicker(10 * time.Second)
	defer ticker.Stop()

	for {
		select {
		case <-ticker.C:
			webhooksLock.RLock()
			currentWebhooks := make([]Webhook, len(webhooks))
			copy(currentWebhooks, webhooks)
			webhooksLock.RUnlock()

			payload := Payload{Data: randStringBytes(10)}
			jsonPayload, _ := json.Marshal(payload)

			for _, webhook := range currentWebhooks {
				go func(webhook Webhook) {
					http.Post(webhook.URL, "application/json", bytes.NewBuffer(jsonPayload))
				}(webhook)
			}
		}
	}
}

func randStringBytes(n int) string {
	const letterBytes = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ"
	b := make([]byte, n)
	for i := range b {
		b[i] = letterBytes[rand.Intn(len(letterBytes))]
	}
	return string(b)
}

func main() {
	r := mux.NewRouter()
	r.HandleFunc("/register", registerWebhookHandler).Methods("POST")
	r.HandleFunc("/status", statusHandler).Methods("GET")
	r.HandleFunc("/payload", payloadHandler).Methods("POST")

	srv := &http.Server{
		Addr:    "127.0.0.1:8080",
		Handler: r,
	}

	go func() {
		if err := srv.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			log.Fatalf("ListenAndServe error: %v", err)
		}
	}()

	go dispatchPayloads()

	stopChan := make(chan os.Signal, 1)
	signal.Notify(stopChan, os.Interrupt)
	<-stopChan

	ctx, cancel := context.WithTimeout(context.Background(), 15*time.Second)
	defer cancel()
	if err := srv.Shutdown(ctx); err != nil {
		log.Fatalf("Server Shutdown Failed:%+v", err)
	}
	log.Println("Service stopped")
}
