func main() {
	scanner := bufio.NewScanner(os.Stdin)

	tc := readNum(scanner)
	for tc > 0 {
		tc--
		n, m := readTwoNums(scanner)
		L := make([]int, n)
		R := make([]int, n)
		for i := 0; i < n; i++ {
			L[i], R[i] = readTwoNums(scanner)
		}
		P := make([]int, m)
		for i := 0; i < m; i++ {
			P[i] = readNum(scanner)
		}
		res := solve(n, L, R, m, P)
		for _, num := range res {
			fmt.Println(num)
		}
	}
}

func solve(n int, L []int, R []int, m int, P []int) []int {
	ps := make(PS, n)
	for i := 0; i < n; i++ {
		ps[i] = Pair{L[i], R[i]}
	}
	sort.Sort(ps)

	res := make([]int, m)
	for i := 0; i < m; i++ {
		j := sort.Search(n, func(j int) bool {
			return ps[j].second >= P[i]
		})

		if j == n {
			res[i] = -1
		} else if ps[j].first <= P[i] {
			res[i] = 0
		} else {
			res[i] = ps[j].first - P[i]
		}
	}

	return res
}

// The Pair, PS, and related methods are included here as part of the solution.

