	var err error
	DB, err = gorm.Open(sqlite.Open("test.db"), &gorm.Config{})
	if err != nil {
		log.Fatalf("failed to connect database: %v", err)
	}
	// Migrate the schema
	DB.AutoMigrate(&Video{})
}

// CreateVideo creates a new video record in the database.
func CreateVideo(ctx context.Context, video *Video) error {
	return DB.WithContext(ctx).Create(video).Error
}

// QueryVideoByID retrieves a video record by its ID.
func QueryVideoByID(ctx context.Context, videoID uint) (*Video, error) {
	var video Video
	if err := DB.WithContext(ctx).First(&video, videoID).Error; err != nil {
		return nil, err
	}
	return &video, nil
}

// QueryVideoByAuthorID retrieves all video records for a given author by the author's ID.
func QueryVideoByAuthorID(ctx context.Context, authorID int64) ([]*Video, error) {
	var videos []*Video
	if err := DB.WithContext(ctx).Where("author_id = ?", authorID).Find(&videos).Error; err != nil {
		return nil, err
	}
	return videos, nil
}

// QueryVideoBeforeTime retrieves all video records published before a certain timestamp.
func QueryVideoBeforeTime(ctx context.Context, time int64) ([]*Video, error) {
	var videos []*Video
	if err := DB.WithContext(ctx).Where("publish_at < ?", time).Find(&videos).Error; err != nil {
		return nil, err
	}
	return videos, nil
}

// UpdateVideo updates the title and URLs of an existing video record by its ID.
func UpdateVideo(ctx context.Context, videoID uint, title, playURL, coverURL string) error {
	return DB.WithContext(ctx).Model(&Video{}).Where("id = ?", videoID).Updates(Video{Title: title, PlayURL: playURL, CoverURL: coverURL}).Error
}

// DeleteVideo deletes a video record by its ID.
