	Event_Line_Spectrum
	Event_Line_LevelMeter
	Event_Line_Input
	Event_SRV_Exited
	Event_MAX
)

type broadcastEvent struct {
	evt uint8
	sub uint8
	arg int
}

type broadcastMap map[uint8][]broadcastEvent

var subscriptions broadcastMap = make(broadcastMap)

func Subscribe(cmd uint8, evt uint8, sub uint8) error {
	if cmd <= Command_MIN || cmd >= Command_MAX {
		return errors.New("invalid command")
	}
	if evt <= Event_MIN || evt >= Event_MAX {
		return errors.New("invalid event")
	}
	subscriptions[cmd] = append(subscriptions[cmd], broadcastEvent{evt: evt, sub: sub})
	return nil
}

func Unsubscribe(cmd uint8, evt uint8, sub uint8) error {
	if cmd <= Command_MIN || cmd >= Command_MAX {
		return errors.New("invalid command")
	}
	if evt <= Event_MIN || evt >= Event_MAX {
		return errors.New("invalid event")
	}
	events, ok := subscriptions[cmd]
	if !ok {
		return errors.New("command not subscribed")
	}
	for i, e := range events {
		if e.evt == evt && e.sub == sub {
			subscriptions[cmd] = append(events[:i], events[i+1:]...)
			return nil
		}
	}
	return errors.New("subscription not found")
}

func Broadcast(evt broadcastEvent) {
	for cmd, events := range subscriptions {
		for _, e := range events {
			if e.evt == evt.evt && e.sub == evt.sub {
				fmt.Printf("Broadcasting event %d to subscriber %d on command %d with arg %d\n", evt.evt, evt.sub, cmd, evt.arg)
			}
		}
	}
}

func ProcessEvent(cmd uint8, evt uint8) error {
	if cmd <= Command_MIN || cmd >= Command_MAX {
		return errors.New("invalid command")
	}
	if evt <= Event_MIN || evt >= Event_MAX {
		return errors.New("invalid event")
	}
	events, ok := subscriptions[cmd]
	if !ok {
		return errors.New("command not subscribed")
	}
	for _, e := range events {
		if e.evt == evt {
			fmt.Printf("Processing event %d on command %d\n", evt, cmd)
			return nil
		}
	}
	return errors.New("event not subscribed for command")
}

func main() {
	// Test cases
	err := Subscribe(Command_SPEAKER, Event_SP_Online, 1)
	if err != nil {
		fmt.Println("Subscribe error:", err)
	}

	err = ProcessEvent(Command_SPEAKER, Event_SP_Online)
	if err != nil {
		fmt.Println("ProcessEvent error:", err)
	}

	Broadcast(broadcastEvent{evt: Event_SP_Online, sub: 1, arg: 42})

	err = Unsubscribe(Command_SPEAKER, Event_SP_Online, 1)
	if err != nil {
		fmt.Println("Unsubscribe error:", err)
	}

	err = ProcessEvent(Command_SPEAKER, Event_SP_Online)
	if err != nil {
		fmt.Println("ProcessEvent error:", err)
	}
}
