// Terminal represents a simulated command-line interface.
type Terminal struct {
	prompt          string
	systemCommands  []string
	history         []string
	echo            bool
	historyEnabled  bool
	historyPosition int
}

// NewTerminal creates a new Terminal with the given prompt.
func NewTerminal(prompt string) *Terminal {
	return &Terminal{
		prompt: prompt,
	}
}

// SetSystemCommand sets the list of system commands for autocomplete.
func (t *Terminal) SetSystemCommand(cmdList []string) {
	t.systemCommands = cmdList
}

// History enables or disables the history feature.
func (t *Terminal) History(enabled bool) {
	t.historyEnabled = enabled
}

// Echo enables or disables the echo feature.
func (t *Terminal) Echo(enabled bool) {
	t.echo = enabled
}

// getInput reads a line of input from the user and provides autocomplete suggestions.
func (t *Terminal) getInput() string {
	reader := bufio.NewReader(os.Stdin)
	var input string
	for {
		fmt.Print(t.prompt)
		line, _, err := reader.ReadLine()
		if err != nil {
			fmt.Fprintln(os.Stderr, "Error reading input:", err)
			continue
		}
		input = string(line)

		// Check for Tab key (autocomplete)
		if strings.HasSuffix(input, "\t") {
			input = input[:len(input)-1] // Remove the Tab character
			input = t.autocomplete(input)
			continue
		}

		// Add to history if enabled
		if t.historyEnabled {
			t.history = append(t.history, input)
			t.historyPosition = len(t.history) // Reset history position
		}

		break
	}

	if t.echo {
		fmt.Println(input)
	}

	return input
}

// autocomplete provides suggestions based on the current input.
func (t *Terminal) autocomplete(input string) string {
	for _, cmd := range t.systemCommands {
		if strings.HasPrefix(cmd, input) {
			fmt.Println(cmd)
			return cmd
		}
	}
	return input
}

func main() {
	cmdList := []string{"hosts", "services", "connect", "connects", "release", "log", "start", "stop", "restart", "delete", "exit", "test2", "test1", "test3", "tes41", "test5", "test6", "tes71", "test8", "test9", "test10", "test11", "test12", "test13", "test14", "test15"}
	term := NewTerminal("> ")
	term.SetSystemCommand(cmdList)
	term.History(true)
	term.Echo(true)
	for {
		cmd := term.getInput()
		if cmd == "exit" {
			break
		}
	}
}
