func main() {
	// Initialize a Kafka producer with the specified configurations.
	producer, err := ck.NewProducer(&ck.ConfigMap{
		"bootstrap.servers":                     "localhost:9092",
		"acks":                                  "all",
		"max.in.flight.requests.per.connection": 5,
		"compression.type":                      "gzip",
		"reconnect.backoff.max.ms":              10000,
		"reconnect.backoff.ms":                  100,
		"log.connection.close":                  false,
	})
	if err != nil {
		fmt.Printf("Failed to create producer: %v\n", err)
		return
	}
	defer producer.Close()

	// Delivery report handler for produced messages
	go func() {
		for e := range producer.Events() {
			switch ev := e.(type) {
			case *ck.Message:
				if ev.TopicPartition.Error != nil {
					fmt.Printf("Delivery failed: %v\n", ev.TopicPartition.Error)
				} else {
					fmt.Printf("Delivered message to %v\n", ev.TopicPartition)
				}
			}
		}
	}()

	// Produce 100,000 messages to the "test_topic" topic.
	topic := "test_topic"
	for i := 0; i < 100000; i++ {
		value := fmt.Sprintf("value %d", i)
		producer.Produce(&ck.Message{
			TopicPartition: ck.TopicPartition{Topic: &topic, Partition: ck.PartitionAny},
			Value:          []byte(value),
			Key:            []byte(fmt.Sprintf("key-%d", i)),
		}, nil)
	}

	// Wait for all messages to be delivered
	producer.Flush(15 * 1000)

	fmt.Println("All messages sent")
}

// Test cases are not provided as Kafka integration requires a running Kafka instance.
// However, you can verify the correctness by running a Kafka broker and checking the "test_topic" for the produced messages.
