func BTreeApplyInorder(root *TreeNode, f func(string)) {
	if root != nil {
		BTreeApplyInorder(root.Left, f)
		f(root.Data)
		BTreeApplyInorder(root.Right, f)
	}
}

func main() {
	// Create a binary tree for demonstration
	root := &TreeNode{Data: "4"}
	root.Left = &TreeNode{Data: "2", Parent: root}
	root.Right = &TreeNode{Data: "6", Parent: root}
	root.Left.Left = &TreeNode{Data: "1", Parent: root.Left}
	root.Left.Right = &TreeNode{Data: "3", Parent: root.Left}
	root.Right.Left = &TreeNode{Data: "5", Parent: root.Right}
	root.Right.Right = &TreeNode{Data: "7", Parent: root.Right}

	// Define a function to be applied to each node's data
	printNodeData := func(data string) {
		fmt.Println(data)
	}

	// Apply the function to each node in the tree using inorder traversal
	BTreeApplyInorder(root, printNodeData)
}

