// EnrichRamSpecs enriches the RAM specifications based on the provided parameters.
func EnrichRamSpecs(ctx context.Context, typ memory.MemoryDeviceType, busTransferRateMHz uint, busWidthBits uint) map[string]string {
	enrichedSpecs := make(map[string]string)

	// Calculate the bus speed, which is half the bus transfer rate for DDR types.
	busSpeedMHz := busTransferRateMHz / 2
	enrichedSpecs["Bus Speed"] = fmt.Sprintf("%d", busSpeedMHz)

	// Determine the standard and module strings based on the memory type.
	switch typ {
	case memory.MemoryDeviceTypeDDR:
		enrichedSpecs["Standard"] = fmt.Sprintf("DDR-%d", busTransferRateMHz)
		enrichedSpecs["Module"] = fmt.Sprintf("PC-%d", busSpeedMHz*8)
	case memory.MemoryDeviceTypeDDR4:
		enrichedSpecs["Standard"] = fmt.Sprintf("DDR4-%d", busTransferRateMHz)
		enrichedSpecs["Module"] = fmt.Sprintf("PC4-%d", busSpeedMHz*8)
	// Add additional cases for other memory types as needed.
	default:
		enrichedSpecs["Standard"] = "Unknown"
		enrichedSpecs["Module"] = "Unknown"
	}

	return enrichedSpecs
}

