// TickTime represents the time interval between each signal check.
const TickTime = 100 * time.Millisecond

// Signal represents a signal from the circuit network.
type Signal struct {
	Value int64
}

// LogicalOperation defines a function type for logical operations.
type LogicalOperation func(signalValue, switchValue int64) bool

// LaserTurret represents a defense structure.
type LaserTurret struct{}

// EnableOrDisable powers the turret on or off.
func (lt *LaserTurret) EnableOrDisable(on bool) {
	fmt.Printf("Laser Turret is now %v\n", on)
}

// Accumulator represents an energy storage device.
type Accumulator struct{}

// Work enables or disables the accumulator.
func (acc *Accumulator) Work(on bool) {
	fmt.Printf("Accumulator is now %v\n", on)
}

// PowerSwitch controls the power supply to various structures.
type PowerSwitch struct {
	sync.Mutex
	SwitchValue      int64
	In               chan Signal
	LogicalOperation LogicalOperation
	IsOn             bool
	Connections      []interface{}
}

// NewPowerSwitch creates a new PowerSwitch with the given parameters.
func NewPowerSwitch(in chan Signal, logicalOperation LogicalOperation, connections []interface{}) *PowerSwitch {
	return &PowerSwitch{
		SwitchValue:      0,
		In:               in,
		LogicalOperation: logicalOperation,
		IsOn:             false,
		Connections:      connections,
	}
}

// Work starts the PowerSwitch logic.
func (ps *PowerSwitch) Work() {
	for {
		ps.switchLogic()
		time.Sleep(TickTime)
	}
}

// switchLogic processes the incoming signal and controls the power supply.
func (ps *PowerSwitch) switchLogic() {
	ps.Lock()
	defer ps.Unlock()
	in := <-ps.In
	isOn := ps.LogicalOperation(in.Value, ps.SwitchValue)
	ps.IsOn = isOn
	for _, connection := range ps.Connections {
		powerSwitchForConnections(connection, isOn)
	}
}

// powerSwitchForConnections applies the power switch state to the connected structures.
func powerSwitchForConnections(connection interface{}, isOn bool) {
	switch connect := connection.(type) {
	case *LaserTurret:
		connect.EnableOrDisable(isOn)
	case *Accumulator:
		connect.Work(isOn)
	default:
		log.Fatalf("powerSwitchForConnections unsupported type %T", connect)
	}
}

// Example usage of PowerSwitch.
func main() {
	// Define a logical operation for the PowerSwitch.
	greaterThan := func(signalValue, switchValue int64) bool {
		return signalValue > switchValue
	}

	// Create a channel for signals.
	signalChan := make(chan Signal, 1)

	// Create a PowerSwitch with a logical operation and some connections.
	ps := NewPowerSwitch(signalChan, greaterThan, []interface{}{
		&LaserTurret{},
		&Accumulator{},
	})

	// Start the PowerSwitch logic in a separate goroutine.
	go ps.Work()

	// Send some test signals to the PowerSwitch.
	signalChan <- Signal{Value: 5}
	time.Sleep(200 * time.Millisecond)
	signalChan <- Signal{Value: 0}
	time.Sleep(200 * time.Millisecond)

	// Close the signal channel and wait for a moment before exiting.
	close(signalChan)
	time.Sleep(200 * time.Millisecond)
}
