// Expression represents a generic expression in the AST.
type Expression struct {
	Value string
}

// NewExpression creates a new Expression instance.
func NewExpression(value string) *Expression {
	return &Expression{Value: value}
}

// ConstExpr is an alias for Expression, representing a constant expression.
type ConstExpr = Expression

// ConstantDecl represents a single constant declaration.
type ConstantDecl struct {
	Ident                 string
	Type                  string
	ConstExpr             *ConstExpr
	PortabilityDirective  string
}

// ConstSection represents a section of constant declarations.
type ConstSection []*ConstantDecl

// AddConstantDecl adds a new constant declaration to the ConstSection.
func (cs *ConstSection) AddConstantDecl(ident, typ, value, directive string) {
	constDecl := &ConstantDecl{
		Ident:                ident,
		Type:                 typ,
		ConstExpr:            NewExpression(value),
		PortabilityDirective: directive,
	}
	*cs = append(*cs, constDecl)
}

// Children retrieves all child nodes of a ConstSection.
func (cs ConstSection) Children() []*ConstExpr {
	children := make([]*ConstExpr, len(cs))
	for i, decl := range cs {
		children[i] = decl.ConstExpr
	}
	return children
}

// ToDeclaration converts a ConstantDecl to a generic declaration.
func (cd *ConstantDecl) ToDeclaration() string {
	if cd.Type != "" {
		return fmt.Sprintf("%s: %s = %s", cd.Ident, cd.Type, cd.ConstExpr.Value)
	}
	return fmt.Sprintf("%s = %s", cd.Ident, cd.ConstExpr.Value)
}

// Test cases to verify the solution correctness.
func main() {
	constSection := ConstSection{}

	// Test adding constant declarations
	constSection.AddConstantDecl("Pi", "float64", "3.14159", "")
	constSection.AddConstantDecl("AppName", "", `"MyApp"`, "cross-platform")

	// Test retrieving children
	children := constSection.Children()
	for _, child := range children {
		fmt.Println(child.Value)
	}

	// Test converting to generic declaration
	for _, decl := range constSection {
		fmt.Println(decl.ToDeclaration())
	}
}
