package hic

import (
	"bufio"
	"os"
	"strconv"
	"strings"
)

type Straw struct {
	Bin1Start    int
	Bin2Start    int
	ContactScore int
}

func Read(filename string) []Straw {
	file, err := os.Open(filename)
	if err != nil {
		panic(err)
	}
	defer file.Close()

	var straws []Straw
	scanner := bufio.NewScanner(file)
	for scanner.Scan() {
		fields := strings.Fields(scanner.Text())
		bin1Start, _ := strconv.Atoi(fields[0])
		bin2Start, _ := strconv.Atoi(fields[1])
		contactScore, _ := strconv.Atoi(fields[2])
		straws = append(straws, Straw{Bin1Start: bin1Start, Bin2Start: bin2Start, ContactScore: contactScore})
	}
	if err := scanner.Err(); err != nil {
		panic(err)
	}
	return straws
}

func GoReadToChan(filename string) <-chan Straw {
	ch := make(chan Straw)
	go func() {
		file, err := os.Open(filename)
		if err != nil {
			close(ch)
			panic(err)
		}
		defer file.Close()

		scanner := bufio.NewScanner(file)
		for scanner.Scan() {
			fields := strings.Fields(scanner.Text())
			bin1Start, _ := strconv.Atoi(fields[0])
			bin2Start, _ := strconv.Atoi(fields[1])
			contactScore, _ := strconv.Atoi(fields[2])
			ch <- Straw{Bin1Start: bin1Start, Bin2Start: bin2Start, ContactScore: contactScore}
		}
		if err := scanner.Err(); err != nil {
			panic(err)
		}
		close(ch)
	}()
	return ch
}

func Equal(a, b Straw) bool {
	return a.Bin1Start == b.Bin1Start && a.Bin2Start == b.Bin2Start && a.ContactScore == b.ContactScore
}

func AllAreEqual(a, b []Straw) bool {
	if len(a) != len(b) {
		return false
	}
	for i := range a {
		if !Equal(a[i], b[i]) {
			return false
		}
	}
	return true
}
