package main

import (
	"encoding"
	"fmt"
	"reflect"
	"strconv"
)

type FloatFormatConfig struct {
	ThousandsSep  string
	DecimalSep    string
	Precision     int
	PadPrecision  bool
}

type FormatConfig struct {
	Nil            string
	True           string
	False          string
	Float          FloatFormatConfig
	TypeFormatters map[reflect.Type]Formatter
}

type Formatter interface {
	FormatValue(reflect.Value, *FormatConfig) string
}

func FormatValue(val reflect.Value, config *FormatConfig) string {
	derefVal, derefType := reflection.DerefValueAndType(val)
	if f, ok := config.TypeFormatters[derefType]; ok && derefVal.IsValid() {
		return f.FormatValue(derefVal, config)
	}

	if nullable.ReflectIsNull(val) {
		return config.Nil
	}

	textMarshaller, _ := val.Interface().(encoding.TextMarshaler)
	if textMarshaller == nil && val.CanAddr() {
		textMarshaller, _ = val.Addr().Interface().(encoding.TextMarshaler)
	}
	if textMarshaller == nil {
		textMarshaller, _ = derefVal.Interface().(encoding.TextMarshaler)
	}
	if textMarshaller != nil {
		text, err := textMarshaller.MarshalText()
		if err == nil {
			return string(text)
		}
	}

	switch derefType.Kind() {
	case reflect.Bool:
		if derefVal.Bool() {
			return config.True
		}
		return config.False

	case reflect.String:
		return derefVal.String()

	case reflect.Float32, reflect.Float64:
		return float.Format(
			derefVal.Float(),
			config.Float.ThousandsSep,
			config.Float.DecimalSep,
			config.Float.Precision,
			config.Float.PadPrecision,
		)

	case reflect.Int, reflect.Int8, reflect.Int16, reflect.Int32, reflect.Int64:
		return strconv.FormatInt(derefVal.Int(), 10)

	case reflect.Uint, reflect.Uint8, reflect.Uint16, reflect.Uint32, reflect.Uint64:
		return strconv.FormatUint(derefVal.Uint(), 10)
	}

	if s, ok := val.Interface().(fmt.Stringer); ok {
		return s.String()
	}
	if val.CanAddr() {
		if s, ok := val.Addr().Interface().(fmt.Stringer); ok {
			return s.String()
		}
	}
	if s, ok := derefVal.Interface().(fmt.Stringer); ok {
		return s.String()
	}

	switch x := derefVal.Interface().(type) {
	case []byte:
		return string(x)
	default:
		return fmt.Sprint(val.Interface())
	}
}

// Test cases to verify the solution correctness
func main() {
	config := &FormatConfig{
		Nil:   "NULL",
		True:  "YES",
		False: "NO",
		Float: FloatFormatConfig{
			ThousandsSep: ",",
			DecimalSep:   ".",
			Precision:    2,
			PadPrecision: true,
		},
		TypeFormatters: make(map[reflect.Type]Formatter),
	}

	// Test cases
	values := []interface{}{
		nil,
		true,
		false,
		"hello",
		123.456,
		789,
		uint(123),
		[]byte("byte slice"),
	}

	for _, v := range values {
		val := reflect.ValueOf(v)
		fmt.Println(FormatValue(val, config))
	}
}
