package main

import (
	"bufio"
	"encoding/hex"
	"errors"
	"fmt"
	"github.com/google/gopacket"
	"github.com/google/gopacket/layers"
	"github.com/google/gopacket/pcapgo"
	"log"
	"net"
	"os"
	"strings"
	"time"
)

// utils package would contain the following functions:
// utils.PrintableDate - returns a string representation of the current date and time suitable for use in a filename.
// utils.MakeCaptureInfo - takes a slice of strings representing the timestamp, source IP, source port, and destination port, and returns a gopacket.CaptureInfo struct.

func HandleClient(conn net.Conn) error {
	a := conn.RemoteAddr().String()
	addr := strings.Split(a, ":")[0]
	fname := addr + "__" + utils.PrintableDate(time.Now()) + ".pcap"
	f, err := os.Create(fname)
	if err != nil {
		return err
	}
	defer f.Close()

	bufrdr := bufio.NewReader(conn)
	w := pcapgo.NewWriter(f)
	if err := w.WriteFileHeader(uint32(65535), layers.LinkTypeEthernet); err != nil {
		return err
	}

	for {
		p, err := bufrdr.ReadString('\n')
		if err != nil {
			return err
		}
		pb, err := hex.DecodeString(strings.TrimSuffix(p, "\n"))
		if err != nil {
			return err
		}
		if len(pb) > 0 {
			fields := strings.Split(string(pb), ",")
			if len(fields) < 5 {
				return errors.New("too few fields received")
			}
			pkt := gopacket.NewPacket([]byte(fields[4]), layers.LayerTypeEthernet, gopacket.Default)
			info := utils.MakeCaptureInfo(fields[:4])
			if err := w.WritePacket(info, pkt.Data()); err != nil {
				return err
			}
		}
	}
}

func main() {
	fmt.Println("Starting packet capture server...")
	listener, err := net.Listen("tcp", "0.0.0.0:8000")
	if err != nil {
		log.Fatal(err)
	}
	defer listener.Close()

	for {
		conn, err := listener.Accept()
		if err != nil {
			log.Printf("Error accepting connection: %v", err)
			continue
		}
		fmt.Println("Receiving data from client...")
		go func() {
			if err := HandleClient(conn); err != nil {
				log.Printf("Error handling client: %v", err)
			}
			conn.Close()
		}()
	}
}
