// LoggingMiddleware logs the details of incoming requests and the time taken to process them.
func LoggingMiddleware(inner http.Handler, name string) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()

		inner.ServeHTTP(w, r)

		log.Printf(
			"%s %s %s %s",
			r.Method,
			r.RequestURI,
			name,
			time.Since(start),
		)
	})
}

// HelloHandler is a simple HTTP handler that responds with "Hello, World!".
func HelloHandler(w http.ResponseWriter, r *http.Request) {
	fmt.Fprintln(w, "Hello, World!")
}

func main() {
	// Create a new HTTP server mux
	mux := http.NewServeMux()

	// Wrap the HelloHandler with the LoggingMiddleware
	loggedHelloHandler := LoggingMiddleware(http.HandlerFunc(HelloHandler), "HelloHandler")

	// Register the wrapped handler with the server mux
	mux.Handle("/", loggedHelloHandler)

	// Start the HTTP server
	log.Fatal(http.ListenAndServe(":8080", mux))
}

