package main

import (
	"errors"
	"fmt"
	"strings"
	"testing"

	. "github.com/smartystreets/goconvey/convey"
)

// StringMapFlag is a custom flag that parses a map of string key-value pairs.
type StringMapFlag struct {
	m map[string]string
}

// Set parses a key-value pair and adds it to the map.
func (f *StringMapFlag) Set(value string) error {
	parts := strings.SplitN(value, ":", 2)
	if len(parts) != 2 {
		return errors.New("invalid format, expected key:value")
	}
	key, val := parts[0], parts[1]
	if _, exists := f.m[key]; exists {
		return fmt.Errorf(`key "%s" is already specified`, key)
	}
	f.m[key] = val
	return nil
}

// String returns the string representation of the map.
func (f *StringMapFlag) String() string {
	pairs := make([]string, 0, len(f.m))
	for k, v := range f.m {
		pairs = append(pairs, fmt.Sprintf("%s:%s", k, v))
	}
	return strings.Join(pairs, " ")
}

// Get returns the underlying map.
func (f *StringMapFlag) Get() interface{} {
	return f.m
}

// NewStringMapFlag creates a new StringMapFlag.
func NewStringMapFlag() *StringMapFlag {
	return &StringMapFlag{m: make(map[string]string)}
}

// TestStringMapFlag verifies the correctness of the StringMapFlag implementation.
func TestStringMapFlag(t *testing.T) {
	Convey("Given a StringMapFlag", t, func() {
		f := NewStringMapFlag()

		Convey("When setting a new key-value pair", func() {
			err := f.Set("a:1")
			Convey("It should add the pair to the map without error", func() {
				So(err, ShouldBeNil)
				So(f.m, ShouldResemble, map[string]string{"a": "1"})
			})
		})

		Convey("When setting a key-value pair with a key that already exists", func() {
			_ = f.Set("b:2")
			err := f.Set("b:3")
			Convey("It should return an error indicating the key is already specified", func() {
				So(err, ShouldNotBeNil)
				So(err.Error(), ShouldContainSubstring, `key "b" is already specified`)
			})
		})

		Convey("When setting a key-value pair with a value containing colons", func() {
			err := f.Set("c:something:with:colon")
			Convey("It should add the pair to the map without error", func() {
				So(err, ShouldBeNil)
				So(f.m, ShouldResemble, map[string]string{"c": "something:with:colon"})
			})
		})

		Convey("When retrieving the string representation of the map", func() {
			_ = f.Set("a:1")
			_ = f.Set("d:4")
			str := f.String()
			Convey("It should return a string with each key-value pair separated by a space", func() {
				So(str, ShouldContainSubstring, "a:1")
				So(str, ShouldContainSubstring, "d:4")
				So(strings.Count(str, " "), ShouldEqual, 1) // One space, meaning two pairs.
			})
		})

		Convey("When retrieving the underlying map", func() {
			_ = f.Set("a:1")
			_ = f.Set("e:5")
			m := f.Get()
			Convey("It should return the map with all key-value pairs", func() {
				So(m, ShouldResemble, map[string]string{"a": "1", "e": "5"})
			})
		})
	})
}
