package main

import "fmt"

// RemoveDuplicates takes a sorted array of integers and removes all duplicates.
// It modifies the array in-place and returns the new length of the array.
// The function ensures that the order of the unique elements is maintained.
func RemoveDuplicates(nums []int) int {
	if len(nums) == 0 {
		return 0
	}
	// Initialize the nextNonDuplicate index to 1 since the first element is always unique.
	nextNonDuplicate := 1

	// Iterate over the array starting from the second element.
	for i := 1; i < len(nums); i++ {
		// If the current element is different from the element before the nextNonDuplicate index,
		// it is a unique element and should be moved to the nextNonDuplicate index.
		if nums[nextNonDuplicate-1] != nums[i] {
			nums[nextNonDuplicate] = nums[i]
			nextNonDuplicate++
		}
	}
	// The nextNonDuplicate index represents the length of the array without duplicates.
	return nextNonDuplicate
}

func main() {
	array1 := []int{1, 1, 2, 2, 3, 3}
	array2 := []int{1, 2, 4, 4, 5, 6, 7, 7, 9}
	newLength1 := RemoveDuplicates(array1)
	newLength2 := RemoveDuplicates(array2)
	fmt.Printf("The length of array %v after removing duplicates is %d\n", array1[:newLength1], newLength1)
	fmt.Printf("The length of array %v after removing duplicates is %d\n", array2[:newLength2], newLength2)
}
