// DesignInfo - Only basic design information.
type DesignInfo struct {
	Name        string `json:"name"`
	Description string `json:"description,omitempty"`
	Id          string `json:"id"`
	UserId      string `json:"userId,omitempty"`
}

// RequiredError represents an error for a missing required field.
type RequiredError struct {
	Field string
}

func (e *RequiredError) Error() string {
	return fmt.Sprintf("required field '%s' is missing", e.Field)
}

// ErrTypeAssertionError represents an error for a failed type assertion.
var ErrTypeAssertionError = errors.New("type assertion failed")

// IsZeroValue checks if the given value is the zero value for its type.
func IsZeroValue(value interface{}) bool {
	return reflect.DeepEqual(value, reflect.Zero(reflect.TypeOf(value)).Interface())
}

// AssertDesignInfoRequired checks if the required fields are not zero-ed.
func AssertDesignInfoRequired(obj DesignInfo) error {
	elements := map[string]interface{}{
		"id": obj.Id,
	}
	for name, el := range elements {
		if isZero := IsZeroValue(el); isZero {
			return &RequiredError{Field: name}
		}
	}
	return nil
}

// AssertRecurseDesignInfoRequired recursively checks if required fields are not zero-ed in a nested slice.
func AssertRecurseDesignInfoRequired(objSlice interface{}) error {
	slice, ok := reflect.ValueOf(objSlice)
	if !ok || slice.Kind() != reflect.Slice {
		return ErrTypeAssertionError
	}

	for i := 0; i < slice.Len(); i++ {
		for j := 0; j < slice.Index(i).Len(); j++ {
			item := slice.Index(i).Index(j).Interface()
			designInfo, ok := item.(DesignInfo)
			if !ok {
				return ErrTypeAssertionError
			}
			if err := AssertDesignInfoRequired(designInfo); err != nil {
				return err
			}
		}
	}
	return nil
}

func main() {
	// Test cases
	designs := [][]DesignInfo{
		{
			{Name: "Design A", Id: "1"},
			{Name: "Design B", Id: "2"},
		},
		{
			{Name: "Design C", Id: "3"},
			{Name: "Design D", Id: ""},
		},
	}

	err := AssertRecurseDesignInfoRequired(designs)
	if err != nil {
		fmt.Println("Validation failed:", err)
	} else {
		fmt.Println("All designs are valid.")
	}
}
