package game

import (
	"math"
)

// Pos represents a position within a world, containing coordinates and look angles.
type Pos struct {
	X     float64
	Y     float64
	Z     float64
	Yaw   float32
	Pitch float32
}

// MoveForward updates the position of the entity when it moves forward by a given distance.
func (p *Pos) MoveForward(distance float64) {
	// Convert degrees to radians for trigonometric functions
	yawRad := float64(p.Yaw) * math.Pi / 180.0
	pitchRad := float64(p.Pitch) * math.Pi / 180.0

	// Calculate the change in each direction
	dx := distance * math.Sin(yawRad) * math.Cos(pitchRad)
	dz := distance * math.Cos(yawRad) * math.Cos(pitchRad)
	dy := distance * math.Sin(pitchRad)

	// Update the position
	p.X += dx
	p.Y -= dy // Assuming Y is up, and moving forward with a positive pitch means moving downwards
	p.Z += dz
}

// Rotate updates the entity's orientation by given delta angles for Yaw and Pitch.
func (p *Pos) Rotate(deltaYaw, deltaPitch float32) {
	// Update Yaw and ensure it wraps around
	p.Yaw += deltaYaw
	for p.Yaw < 0 {
		p.Yaw += 360
	}
	for p.Yaw >= 360 {
		p.Yaw -= 360
	}

	// Update Pitch and clamp it between -90 and 90 degrees
	p.Pitch += deltaPitch
	if p.Pitch > 90 {
		p.Pitch = 90
	} else if p.Pitch < -90 {
		p.Pitch = -90
	}
}

// Test cases to verify the solution correctness
func main() {
	pos := Pos{X: 0, Y: 0, Z: 0, Yaw: 0, Pitch: 0}

	// Test MoveForward
	pos.MoveForward(10)
	// Expected new position: {X: 0, Y: 0, Z: 10, Yaw: 0, Pitch: 0}
	println(pos)

	// Test Rotate
	pos.Rotate(90, 0)
	// Expected new orientation: {X: 0, Y: 0, Z: 10, Yaw: 90, Pitch: 0}
	println(pos)

	pos.Rotate(0, 30)
	// Expected new orientation: {X: 0, Y: 0, Z: 10, Yaw: 90, Pitch: 30}
	println(pos)

	pos.Rotate(300, -120)
	// Expected new orientation: {X: 0, Y: 0, Z: 10, Yaw: 30, Pitch: -90}
	println(pos)
}
