}

// Reconcile performs the reconciliation for a single MeterBase resource.
func (r *MeterBaseReconciler) Reconcile(ctx context.Context, meterbase *marketplacev1alpha1.MeterBase) error {
	logger := logf.Log.WithName("meterbase_reconciler")
	patcher := patch.RHMDefaultPatcher

	// Define the Pod object
	pod := &corev1.Pod{
		ObjectMeta: metav1.ObjectMeta{
			Name:      meterbase.Name,
			Namespace: meterbase.Namespace,
		},
	}

	// Define the namespaced name
	namespacedName := types.NamespacedName{Name: meterbase.Name, Namespace: meterbase.Namespace}

	// Attempt to get the Pod
	err := r.client.Get(ctx, namespacedName, pod)
	if err != nil {
		if errors.IsNotFound(err) {
			// Pod not found, create it
			utils.RhmAnnotator.SetLastAppliedAnnotation(pod)
			if err := r.client.Create(ctx, pod); err != nil {
				return r.handleError(ctx, meterbase, err)
			}
			return r.updateStatusCondition(ctx, meterbase, marketplacev1alpha1.ConditionInstalling, "created")
		}
		// Other error occurred
		return r.handleError(ctx, meterbase, err)
	}

	// Pod found, check if it needs to be updated
	updatedPod := pod.DeepCopy()
	updatedPod.Annotations["foo"] = "bar"
	patchResult, _ := patcher.Calculate(pod, updatedPod)
	if !patchResult.IsEmpty() {
		if err := r.client.Patch(ctx, updatedPod, client.RawPatch(types.MergePatchType, patchResult.Patch)); err != nil {
			return r.handleError(ctx, meterbase, err)
		}
		return r.updateStatusCondition(ctx, meterbase, marketplacev1alpha1.ConditionInstalling, "updated")
	}

	// Check if the Pod should be deleted
	if pod.Annotations["foo"] == "bar" {
		if err := r.client.Delete(ctx, pod); err != nil {
			return r.handleError(ctx, meterbase, err)
		}
	}

	return nil
}

// handleError handles errors by updating the MeterBase status condition to ConditionError.
func (r *MeterBaseReconciler) handleError(ctx context.Context, meterbase *marketplacev1alpha1.MeterBase, err error) error {
	r.updateStatusCondition(ctx, meterbase, marketplacev1alpha1.ConditionError, err.Error())
	return emperrors.Wrap(err, "reconciliation error")
}

// updateStatusCondition updates the status conditions of the MeterBase resource.
func (r *MeterBaseReconciler) updateStatusCondition(ctx context.Context, meterbase *marketplacev1alpha1.MeterBase, conditionType marketplacev1alpha1.ConditionType, message string) error {
	conditions := status.NewConditions(meterbase.Status.Conditions)
	conditions.SetCondition(status.Condition{
		Type:    conditionType,
		Status:  corev1.ConditionTrue,
		Reason:  string(conditionType),
		Message: message,
	})
	meterbase.Status.Conditions = conditions
	return r.client.Status().Update(ctx, meterbase)
}

