package main

import (
	"fmt"
	"strconv"
	"time"
)

type Employee struct {
	ID         string
	Name       string
	Department string
	Position   string
}

var employeeDatabase map[string]Employee

func init() {
	employeeDatabase = make(map[string]Employee)
}

func AddEmployee(employee Employee) bool {
	if _, err := strconv.Atoi(employee.ID); err != nil {
		return false
	}
	if _, exists := employeeDatabase[employee.ID]; exists {
		return false
	}
	employeeDatabase[employee.ID] = employee
	return true
}

func DeleteEmployee(id string) bool {
	if _, ok := employeeDatabase[id]; !ok {
		return false
	}
	delete(employeeDatabase, id)
	return true
}

func GetEmployees() map[string]Employee {
	return employeeDatabase
}

func UpdateEmployee(employee Employee) bool {
	time.Sleep(2 * time.Second)
	if _, exists := employeeDatabase[employee.ID]; !exists {
		return false
	}
	employeeDatabase[employee.ID] = employee
	return true
}

func FlushEmployees() {
	for k := range employeeDatabase {
		delete(employeeDatabase, k)
	}
}

func GetEmployeeDatabase() map[string]Employee {
	return employeeDatabase
}

// Test cases to verify the solution correctness
func main() {
	// Test AddEmployee
	fmt.Println("Add Employee:", AddEmployee(Employee{ID: "123", Name: "John Doe", Department: "Engineering", Position: "Developer"})) // true
