	fmt.Println("Delete Non-existing Employee:", DeleteEmployee("999")) // false

	// Test FlushEmployees
	FlushEmployees()
	fmt.Println("Get Employees after flush:", GetEmployees()) // map[]

	// Test GetEmployeeDatabase
	fmt.Println("Get Employee Database:", GetEmployeeDatabase()) // map[]
}
