// ToString safely converts a byte slice to a string.
// It ensures that the conversion does not cause data loss or corruption.
func ToString(b []byte) string {
	return string(b)
}

// ToBytes safely converts a string to a byte slice.
// It ensures that the conversion does not cause data loss or corruption.
func ToBytes(s string) []byte {
	return []byte(s)
}

// IsPrintableASCII checks if a given byte slice contains only printable ASCII characters.
// It returns true if all bytes are in the range of 32 to 126 inclusive, false otherwise.
func IsPrintableASCII(b []byte) bool {
	for _, c := range b {
		if c < 32 || c > 126 {
			return false
		}
	}
	return true
}

// Test cases to verify the correctness of the functions.
func main() {
	// Test ToString
	byteSlice := []byte{72, 101, 108, 108, 111}
	str := ToString(byteSlice)
	if str != "Hello" {
