// Assuming endpoint and batchpoint are initialized and configured elsewhere
var endpoint client.Client
var batchpoint client.BatchPoints

var deviceCount int64
var userCount int64

func main() {
	CountTimer()
}

// CountTimer starts the periodic counting and saving of device and user counts.
func CountTimer() {
	mustSave()
	t1 := time.NewTimer(10 * time.Second)
	t2 := time.NewTimer(1 * time.Hour)
	for {
		select {
		case <-t1.C:
			saveCount()
			t1.Reset(10 * time.Second)
		case <-t2.C:
			mustSave()
			t2.Reset(1 * time.Hour)
		}
	}
}

// saveCount checks the current device and user counts and saves them if they have changed.
func saveCount() {
	devicen, usern, err := emqtt.CountDevice()
	if err != nil {
		logs.Error("Error counting devices and users:", err)
		return
	}
	if usern != userCount {
		saveData("user", usern)
		userCount = usern
	}

	if deviceCount != devicen {
		saveData("device", devicen)
		deviceCount = devicen
	}
}

// mustSave forcefully saves the current device and user counts to the database.
func mustSave() {
	devicen, usern, err := emqtt.CountDevice()
	if err != nil {
		logs.Error("Error counting devices and users:", err)
		return
	}
	saveData("user", usern)
	saveData("device", devicen)
}

// saveData writes the given data to the InfluxDB database with the specified id.
func saveData(id string, data interface{}) error {
	if endpoint != nil {
		tags := map[string]string{
			"id": id,
		}
		fields := map[string]interface{}{
			"data": data,
		}
		point, err := client.NewPoint("trends", tags, fields, time.Now())
		if err != nil {
			logs.Error("Error creating new point:", err)
			return err
		}
		batchpoint.AddPoint(point)
		err = endpoint.Write(batchpoint)
		if err != nil {
			logs.Error("Error writing to InfluxDB:", err)
			return err
		}
	}
	return nil
}

// Test cases to verify the solution correctness.
func main() {
	// Initialize logging, MQTT client, InfluxDB client, and batch points here.
	// ...

