	go CountTimer()

	// Assume we have a channel to listen for a shutdown signal.
	shutdownChan := make(chan struct{})
	<-shutdownChan // Blocks until a shutdown signal is received.

	// Perform any necessary cleanup before exiting.
	// ...
	log.Println("Shutting down count timer.")
}
