package main

import (
	"fmt"
	"log"

	"golang.org/x/crypto/bcrypt"
	"gorm.io/driver/mysql"
	"gorm.io/gorm"
)

// User represents the user model in the database.
type User struct {
	gorm.Model
	Name     string
	Email    string `gorm:"unique"`
	Password string
}

// Config holds the database configuration parameters.
type Config struct {
	DBUsername string
	DBPassword string
	DBPort     string
	DBHost     string
	DBName     string
}

// Initialize the database connection with the given configuration.
func InitDB(config Config) *gorm.DB {
	connectionString := fmt.Sprintf("%s:%s@tcp(%s:%s)/%s?charset=utf8mb4&parseTime=True&loc=Local",
		config.DBUsername,
		config.DBPassword,
		config.DBHost,
		config.DBPort,
		config.DBName,
	)

	db, err := gorm.Open(mysql.Open(connectionString), &gorm.Config{})
	if err != nil {
		log.Fatalf("Failed to connect to database: %v", err)
	}

	return db
}

// InitialMigration performs the database migration for the User model.
func InitialMigration(db *gorm.DB) {
	db.AutoMigrate(&User{})
}

// CreateUser adds a new user to the database.
func CreateUser(db *gorm.DB, name, email, password string) (*User, error) {
	hashedPassword, err := bcrypt.GenerateFromPassword([]byte(password), bcrypt.DefaultCost)
	if err != nil {
		return nil, err
	}

	user := User{Name: name, Email: email, Password: string(hashedPassword)}
	result := db.Create(&user)
	return &user, result.Error
}

// GetUserByID retrieves a user by their ID.
func GetUserByID(db *gorm.DB, id uint) (*User, error) {
	var user User
	result := db.First(&user, id)
	return &user, result.Error
}

// UpdateUser updates a user's information by their ID.
func UpdateUser(db *gorm.DB, id uint, name, email, password string) (*User, error) {
	user, err := GetUserByID(db, id)
	if err != nil {
		return nil, err
	}

	if name != "" {
		user.Name = name
	}
	if email != "" {
		user.Email = email
	}
	if password != "" {
		hashedPassword, err := bcrypt.GenerateFromPassword([]byte(password), bcrypt.DefaultCost)
		if err != nil {
			return nil, err
		}
		user.Password = string(hashedPassword)
	}

	result := db.Save(user)
	return user, result.Error
}

// DeleteUser removes a user by their ID.
func DeleteUser(db *gorm.DB, id uint) error {
	result := db.Delete(&User{}, id)
	return result.Error
}

// Test cases to verify the correctness of CRUD operations.
func main() {
	config := Config{
		DBUsername: "root",
		DBPassword: "password",
		DBPort:     "3306",
		DBHost:     "localhost",
		DBName:     "crud_go",
	}

	db := InitDB(config)
	InitialMigration(db)

	// Create a new user
	newUser, err := CreateUser(db, "John Doe", "john@example.com", "password123")
	if err != nil {
		log.Fatalf("Failed to create user: %v", err)
	}
	fmt.Printf("New user created: %+v\n", newUser)

	// Retrieve the user by ID
	retrievedUser, err := GetUserByID(db, newUser.ID)
	if err != nil {
		log.Fatalf("Failed to retrieve user: %v", err)
	}
	fmt.Printf("Retrieved user: %+v\n", retrievedUser)

	// Update the user's information
	updatedUser, err := UpdateUser(db, newUser.ID, "Jane Doe", "jane@example.com", "newpassword123")
	if err != nil {
		log.Fatalf("Failed to update user: %v", err)
	}
	fmt.Printf("Updated user: %+v\n", updatedUser)

	// Delete the user
	err = DeleteUser(db, newUser.ID)
	if err != nil {
		log.Fatalf("Failed to delete user: %v", err)
	}
	fmt.Println("User deleted successfully")
}
