package tex

import (
	"errors"
	"fmt"
)

// ErrInvalidSource describes an invalid source directory for templates
type ErrInvalidSource struct {
	Source string
}

func (e *ErrInvalidSource) Error() string {
	return fmt.Sprintf("invalid source: %s", e.Source)
}

func (e *ErrInvalidSource) Is(target error) bool {
	_, ok := target.(*ErrInvalidSource)
	return ok
}

// ErrInvalidDest describes an invalid destination directory
type ErrInvalidDest struct {
	Dest string
}

func (e *ErrInvalidDest) Error() string {
	return fmt.Sprintf("invalid dest: %s", e.Dest)
}

func (e *ErrInvalidDest) Is(target error) bool {
	_, ok := target.(*ErrInvalidDest)
	return ok
}

// ErrNoMatch is returned when there are no files matching source
type ErrNoMatch struct {
	Source string
}

func (e *ErrNoMatch) Error() string {
	return fmt.Sprintf("no match for: %s", e.Source)
}

func (e *ErrNoMatch) Is(target error) bool {
	_, ok := target.(*ErrNoMatch)
	return ok
}

// ErrWithMessage wraps an error with an additional message
type ErrWithMessage struct {
	Cause   error
	Message string
}

func (e *ErrWithMessage) Error() string {
	return fmt.Sprintf("%s: %s", e.Message, e.Cause.Error())
}

func (e *ErrWithMessage) Is(target error) bool {
	_, ok := target.(*ErrWithMessage)
	return ok
}

func (e *ErrWithMessage) Unwrap() error {
	return e.Cause
}

// wrapErr wraps an existing error with an additional message
func wrapErr(err error, message string) error {
	return &ErrWithMessage{
		Cause:   err,
		Message: message,
	}
}

// Test cases to verify the correctness of the solution
func main() {
	// Test ErrInvalidSource
	errInvalidSource := &ErrInvalidSource{Source: "/invalid/source/path"}
	fmt.Println(errInvalidSource.Error()) // Output: invalid source: /invalid/source/path

	// Test ErrInvalidDest
	errInvalidDest := &ErrInvalidDest{Dest: "/invalid/dest/path"}
	fmt.Println(errInvalidDest.Error()) // Output: invalid dest: /invalid/dest/path

	// Test ErrNoMatch
	errNoMatch := &ErrNoMatch{Source: "*.txt"}
	fmt.Println(errNoMatch.Error()) // Output: no match for: *.txt

	// Test ErrWithMessage
	errWithMessage := wrapErr(errInvalidSource, "Failed to load templates")
	fmt.Println(errWithMessage.Error()) // Output: Failed to load templates: invalid source: /invalid/source/path

	// Test unwrapping ErrWithMessage
	unwrappedErr := errors.Unwrap(errWithMessage)
	fmt.Println(unwrappedErr.Error()) // Output: invalid source: /invalid/source/path

	// Test error type checking
	fmt.Println(errors.Is(errWithMessage, &ErrInvalidSource{})) // Output: true
	fmt.Println(errors.Is(errWithMessage, &ErrInvalidDest{}))   // Output: false
}
