// User represents the interface for user operations.
type User interface {
	Select(w http.ResponseWriter, r *http.Request)
	SelectAll(w http.ResponseWriter, r *http.Request)
	Upsert(w http.ResponseWriter, r *http.Request)
	Delete(w http.ResponseWriter, r *http.Request)
}

// user implements the User interface and contains the ORM layer for user operations.
type user struct {
	userOrmer ormer.UserOrmer
}

// NewUserClient creates a new user client with the provided database connection.
func NewUserClient(db *pg.DB) User {
	return &user{
		userOrmer: ormer.NewUserOrmer(db),
	}
}

// Select retrieves a single user by their ID.
func (u *user) Select(w http.ResponseWriter, r *http.Request) {
	params := mux.Vars(r)
	id, err := strconv.Atoi(params["id"])
	if err != nil {
		http.Error(w, "Invalid user ID", http.StatusBadRequest)
		return
	}

	user, err := u.userOrmer.Select(id)
	if err != nil {
		http.Error(w, "User not found", http.StatusNotFound)
		return
	}

	json.NewEncoder(w).Encode(user)
}

// SelectAll retrieves a list of all users.
func (u *user) SelectAll(w http.ResponseWriter, r *http.Request) {
	users, err := u.userOrmer.SelectAll()
	if err != nil {
		http.Error(w, "Error retrieving users", http.StatusInternalServerError)
		return
	}

	json.NewEncoder(w).Encode(users)
}

// Upsert creates a new user or updates an existing user's information.
func (u *user) Upsert(w http.ResponseWriter, r *http.Request) {
	var user ormer.User
	if err := json.NewDecoder(r.Body).Decode(&user); err != nil {
		http.Error(w, "Invalid user data", http.StatusBadRequest)
		return
	}

	err := u.userOrmer.Upsert(&user)
	if err != nil {
		http.Error(w, "Error upserting user", http.StatusInternalServerError)
		return
	}

	json.NewEncoder(w).Encode(user)
}

// Delete removes a user by their ID.
func (u *user) Delete(w http.ResponseWriter, r *http.Request) {
	params := mux.Vars(r)
	id, err := strconv.Atoi(params["id"])
	if err != nil {
		http.Error(w, "Invalid user ID", http.StatusBadRequest)
		return
	}

	err = u.userOrmer.Delete(id)
	if err != nil {
		http.Error(w, "Error deleting user", http.StatusInternalServerError)
		return
	}

	w.WriteHeader(http.StatusNoContent)
}

func main() {
	// Assume db is a *pg.DB instance connected to the PostgreSQL database.
	var db *pg.DB
	userClient := NewUserClient(db)

	r := mux.NewRouter()
	r.HandleFunc("/users/{id}", userClient.Select).Methods("GET")
	r.HandleFunc("/users", userClient.SelectAll).Methods("GET")
	r.HandleFunc("/users", userClient.Upsert).Methods("POST", "PUT")
	r.HandleFunc("/users/{id}", userClient.Delete).Methods("DELETE")

	http.Handle("/", r)
	fmt.Println("Server started at http://localhost:8080")
	http.ListenAndServe(":8080", nil)
}

// Test cases are not provided in this snippet as they would require a mock database setup and HTTP request simulation.
