	"net/http"
	"time"
)

// Middleware is a type that defines a function that takes an http.HandlerFunc and returns a new one.
type Middleware func(http.HandlerFunc) http.HandlerFunc

// LogRequestDuration is a middleware that logs the duration of each HTTP request.
func LogRequestDuration(f http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()
		defer func() {
			end := time.Now()
			duration := end.Sub(start)
			log.Printf("Method: %s, Path: %s, Start: %s, End: %s, Duration: %s\n",
				r.Method, r.URL.Path, start.Format(time.RFC3339), end.Format(time.RFC3339), duration)
		}()
		f(w, r)
	}
}

// HelloHandler is a simple HTTP handler that responds with "Hello, World!".
func HelloHandler(w http.ResponseWriter, r *http.Request) {
	fmt.Fprintln(w, "Hello, World!")
}

func main() {
	http.HandleFunc("/", LogRequestDuration(HelloHandler))
	log.Println("Server starting on port 8080...")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

// To test this solution, you can run the server and make requests to it using a tool like curl or a web browser.
