package main

import (
	"encoding/json"
	"errors"
	"fmt"
	"log"
	"math/rand"
	"net/http"
	"time"
)

const (
	BotAuthor       = "Jane Doe"
	BotDescription  = "Simple HTTP Server"
	BotCommand      = "random"
	Port            = "8080"
)

type Request struct {
	Command string `json:"command"`
}

type Response struct {
	Text string `json:"text"`
}

func (req *Request) ParseData(r *http.Request) error {
	decoder := json.NewDecoder(r.Body)
	err := decoder.Decode(req)
	if err != nil {
		return err
	}
	return nil
}

func (resp *Response) ToJson() ([]byte, error) {
	return json.Marshal(resp)
}

func sendSuccess(w http.ResponseWriter, text []byte) {
	w.Header().Set("Content-Type", "application/json; charset=UTF-8")
	w.WriteHeader(http.StatusCreated)
	fmt.Fprintf(w, "%s", text)
}

func sendError(w http.ResponseWriter, err error) {
	w.Header().Set("Content-Type", "application/json; charset=UTF-8")
	w.WriteHeader(http.StatusBadRequest)
	fmt.Fprintf(w, `{"error": "%s"}`, err.Error())
}

func info(w http.ResponseWriter, r *http.Request) {
	if r.Method != "GET" {
		sendError(w, errors.New("method not allowed"))
		return
	}

	info := fmt.Sprintf(`{"author": "%v", "info": "%v", "commands": "%v"}`, BotAuthor, BotDescription, BotCommand)
	w.Header().Set("Content-Type", "application/json; charset=UTF-8")
	w.WriteHeader(http.StatusOK)
	fmt.Fprintf(w, "%s", info)
}

func randomText() (string, error) {
	rand.Seed(time.Now().UnixNano())
	quotes := []string{
		"Life is about making an impact, not making an income.",
		"Whatever the mind of man can conceive and believe, it can achieve.",
		"Strive not to be a success, but rather to be of value.",
	}
	return quotes[rand.Intn(len(quotes))], nil
}

func handler(w http.ResponseWriter, r *http.Request) {
	if r.Method != "POST" {
		sendError(w, errors.New("method not allowed"))
		return
	}

	req := Request{}
	err := req.ParseData(r)
	if err != nil {
		sendError(w, err)
		return
	}

	var text string
	switch req.Command {
	case "random":
		text, err = randomText()
		if err != nil {
			sendError(w, err)
			return
		}
	default:
		sendError(w, errors.New("unknown command"))
		return
	}

	resp := Response{Text: text}
	resTxt, err := resp.ToJson()
	if err != nil {
		sendError(w, err)
		return
	}

	sendSuccess(w, resTxt)
}

func panicRecover(f func(w http.ResponseWriter, r *http.Request)) func(w http.ResponseWriter, r *http.Request) {
	return func(w http.ResponseWriter, r *http.Request) {
		defer func() {
			if rec := recover(); rec != nil {
				log.Printf("Panic: %v\n", rec)
				sendError(w, errors.New("internal server error"))
			}
		}()
		f(w, r)
	}
}

func main() {
	http.HandleFunc("/info", panicRecover(info))
	http.HandleFunc("/event", panicRecover(handler))

	fmt.Printf("Start listening server on port %v\n", Port)
	log.Fatal(http.ListenAndServe(":"+Port, nil))
}
