// User represents a user resource in the IaC environment.
type User struct {
	ScopeId     string
	AccountIds  []string
	Description string
	Name        string
}

// UserConfig represents the configuration for a user resource.
type UserConfig struct {
	ScopeId     *string
	AccountIds  *[]*string
	Description *string
	Name        *string
}

// UserManager is responsible for managing user resources.
type UserManager struct {
	users map[string]User
}

// NewUserManager creates a new instance of UserManager.
func NewUserManager() *UserManager {
	return &UserManager{
		users: make(map[string]User),
	}
}

// CreateUser creates a new user resource based on the provided UserConfig.
func (m *UserManager) CreateUser(config UserConfig) (User, error) {
	if config.ScopeId == nil || *config.ScopeId == "" {
		return User{}, errors.New("scope ID is required")
	}

	user := User{
		ScopeId: *config.ScopeId,
	}

	if config.AccountIds != nil {
		for _, accountId := range *config.AccountIds {
			if accountId == nil || *accountId == "" {
				return User{}, errors.New("account IDs must be non-empty strings")
			}
			user.AccountIds = append(user.AccountIds, *accountId)
		}
	}

	if config.Description != nil {
		user.Description = *config.Description
	}

	if config.Name != nil {
		user.Name = *config.Name
	} else {
		user.Name = "user-" + user.ScopeId
	}

	m.users[user.ScopeId] = user
	return user, nil
}

// UpdateUser updates an existing user resource with the provided UserConfig.
func (m *UserManager) UpdateUser(scopeId string, config UserConfig) (User, error) {
	user, exists := m.users[scopeId]
	if !exists {
		return User{}, fmt.Errorf("user with scope ID %s does not exist", scopeId)
	}

	if config.AccountIds != nil {
		user.AccountIds = []string{}
		for _, accountId := range *config.AccountIds {
			if accountId == nil || *accountId == "" {
				return User{}, errors.New("account IDs must be non-empty strings")
			}
			user.AccountIds = append(user.AccountIds, *accountId)
		}
	}

	if config.Description != nil {
		user.Description = *config.Description
	}

	if config.Name != nil {
		user.Name = *config.Name
	}

	m.users[scopeId] = user
	return user, nil
}

// DeleteUser deletes a user resource by its scope ID.
func (m *UserManager) DeleteUser(scopeId string) error {
	_, exists := m.users[scopeId]
	if !exists {
		return fmt.Errorf("user with scope ID %s does not exist", scopeId)
	}
	delete(m.users, scopeId)
	return nil
}

