// FetchURLContent sends an HTTP GET request to the specified URL and returns the status code and body of the response.
// It returns an error if the request fails.
func FetchURLContent(url string) (statusCode int, responseBody string, err error) {
	client := gohttp.New()

	response, err := client.Get(url)
	if err != nil {
		return 0, "", err
	}
	defer response.Body.Close()

	body, err := ioutil.ReadAll(response.Body)
	if err != nil {
		return response.StatusCode, "", err
	}

	return response.StatusCode, string(body), nil
}

func main() {
	// Test cases
	urls := []string{
		"https://httpbin.org/get",
		"https://invalid-url",
	}

	for _, url := range urls {
		statusCode, body, err := FetchURLContent(url)
		if err != nil {
			fmt.Printf("Error fetching '%s': %s\n", url, err)
		} else {
			fmt.Printf("Status Code: %d\nResponse Body: %s\n", statusCode, body)
		}
	}
}
