type AuthorPost struct {
	Name      string `json:"name" binding:"required"`
	Email     string `json:"email" binding:"required,email"`
	Biography string `json:"biography"`
}

type AuthorUpdate struct {
	Name      string `json:"name" binding:"required"`
	Email     string `json:"email" binding:"required,email"`
	Biography string `json:"biography"`
}

var (
	authors  = make(map[string]AuthorPost)
	mu       sync.RWMutex
)

func createAuthor(c *gin.Context) {
	var newAuthor AuthorPost
	if err := c.ShouldBindJSON(&newAuthor); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	mu.Lock()
	defer mu.Unlock()

	if _, exists := authors[newAuthor.Email]; exists {
		c.JSON(http.StatusConflict, gin.H{"error": "Author already exists"})
		return
	}

	authors[newAuthor.Email] = newAuthor
	c.JSON(http.StatusCreated, newAuthor)
}

func getAuthor(c *gin.Context) {
	email := c.Param("email")

	mu.RLock()
	defer mu.RUnlock()

	author, exists := authors[email]
	if !exists {
		c.JSON(http.StatusNotFound, gin.H{"error": "Author not found"})
		return
	}

	c.JSON(http.StatusOK, author)
}

func updateAuthor(c *gin.Context) {
	email := c.Param("email")
	var updateData AuthorUpdate
	if err := c.ShouldBindJSON(&updateData); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	mu.Lock()
	defer mu.Unlock()

	if updateData.Email != email {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Email in path and body do not match"})
		return
	}

	author, exists := authors[email]
	if !exists {
		c.JSON(http.StatusNotFound, gin.H{"error": "Author not found"})
		return
	}

	// Update the author's profile
	author.Name = updateData.Name
	author.Biography = updateData.Biography
	authors[email] = author

	c.JSON(http.StatusOK, author)
}

func main() {
	router := gin.Default()

	router.POST("/authors", createAuthor)
	router.GET("/authors/:email", getAuthor)
	router.PUT("/authors/:email", updateAuthor)

	router.Run(":8080")
}

// Test cases to verify the solution correctness
