package random

import (
	"math/rand"
	"time"
)

// RandInt64 returns a non-negative pseudo-random 64-bit integer as an int64 less than max.
func RandInt64(max int64) int64 {
	rand.Seed(time.Now().UnixNano())
	return rand.Int63n(max)
}

// RandInt32 returns a non-negative pseudo-random 32-bit integer as an int32 less than max.
func RandInt32(max int32) int32 {
	rand.Seed(time.Now().UnixNano())
	return rand.Int31n(max)
}

// RandInt returns a non-negative pseudo-random integer as an int less than max.
func RandInt(max int) int {
	rand.Seed(time.Now().UnixNano())
	return rand.Intn(max)
}

// RandSection returns a non-negative pseudo-random 64-bit integer as an int64 in the range [min, max).
func RandSection(min, max int64) int64 {
	rand.Seed(time.Now().UnixNano())
	return min + rand.Int63n(max-min)
}

// RandSectionContain returns a non-negative pseudo-random 64-bit integer as an int64 in the range [min, max].
func RandSectionContain(min, max int64) int64 {
	rand.Seed(time.Now().UnixNano())
	return min + rand.Int63n(max-min+1)
}

// random_test.go
package random

import "testing"

func TestRandMax(t *testing.T) {
	maxValues := []int64{88, 100, 1000}
	for _, max := range maxValues {
		if got := RandInt64(max); got < 0 || got >= max {
			t.Errorf("RandInt64(%d) = %d; want in range [0, %d)", max, got, max)
		}
		if got := RandInt32(int32(max)); got < 0 || got >= int32(max) {
			t.Errorf("RandInt32(%d) = %d; want in range [0, %d)", max, got, max)
		}
		if got := RandInt(int(max)); got < 0 || got >= int(max) {
			t.Errorf("RandInt(%d) = %d; want in range [0, %d)", max, got, max)
		}
	}
}

func TestRandSection(t *testing.T) {
	min := int64(4)
	max := int64(5)
	if got := RandSection(min, max); got < min || got >= max {
		t.Errorf("RandSection(%d, %d) = %d; want in range [%d, %d)", min, max, got, min, max)
	}
	if got := RandSectionContain(min, max); got < min || got > max {
		t.Errorf("RandSectionContain(%d, %d) = %d; want in range [%d, %d]", min, max, got, min, max)
	}
}
