	CodeInvalidOutput     uint32 = 102
	CodeInvalidAddress    uint32 = 103
	CodeUnknownAddress    uint32 = 104
	CodeInsufficientCoins uint32 = 105
	CodeInvalidCoins      uint32 = 106
	CodeUnknownRequest    uint32 = 107
