package library

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"time"
)

// Book represents a book object in the library system
type Book struct {
	ID             int       `json:"id"`
	Title          string    `json:"title"`
	Author         string    `json:"author"`
	PublicationStr string    `json:"publication_date"`
	Publication    time.Time `json:"-"`
}

// BookCreateOptions fields are those accepted by CreateBook
type BookCreateOptions struct {
	Title          string `json:"title"`
	Author         string `json:"author"`
	PublicationStr string `json:"publication_date"`
}

// BookUpdateOptions fields are those accepted by UpdateBook
type BookUpdateOptions struct {
	Title          *string `json:"title,omitempty"`
	Author         *string `json:"author,omitempty"`
	PublicationStr *string `json:"publication_date,omitempty"`
}

// BooksPagedResponse represents a paginated Book API response
type BooksPagedResponse struct {
	PageOptions
	Data []Book `json:"data"`
}

// Client represents the client for the library system
type Client struct {
	BaseURL    string
	HTTPClient *http.Client
}

// NewClient creates a new library system client
func NewClient(baseURL string) *Client {
	return &Client{
		BaseURL:    baseURL,
		HTTPClient: &http.Client{},
	}
}

// ListBooks lists books with pagination support
func (c *Client) ListBooks(ctx context.Context, opts *ListOptions) ([]Book, error) {
	url := fmt.Sprintf("%s/books", c.BaseURL)
	if opts != nil {
		url = fmt.Sprintf("%s?%s", url, opts.Values().Encode())
	}

	req, err := http.NewRequestWithContext(ctx, "GET", url, nil)
	if err != nil {
		return nil, err
	}

	resp, err := c.HTTPClient.Do(req)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	var pagedResponse BooksPagedResponse
	if err := json.NewDecoder(resp.Body).Decode(&pagedResponse); err != nil {
		return nil, err
	}

	for i := range pagedResponse.Data {
		pagedResponse.Data[i].fixDates()
	}

	return pagedResponse.Data, nil
}

// GetBook gets the book with the provided ID
func (c *Client) GetBook(ctx context.Context, id int) (*Book, error) {
	url := fmt.Sprintf("%s/books/%d", c.BaseURL, id)

	req, err := http.NewRequestWithContext(ctx, "GET", url, nil)
	if err != nil {
		return nil, err
	}

	resp, err := c.HTTPClient.Do(req)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	var book Book
	if err := json.NewDecoder(resp.Body).Decode(&book); err != nil {
		return nil, err
	}

	return book.fixDates(), nil
}

// CreateBook creates a new book
func (c *Client) CreateBook(ctx context.Context, createOpts BookCreateOptions) (*Book, error) {
	url := fmt.Sprintf("%s/books", c.BaseURL)

	bodyData, err := json.Marshal(createOpts)
	if err != nil {
		return nil, err
	}

	req, err := http.NewRequestWithContext(ctx, "POST", url, json.RawMessage(bodyData))
	if err != nil {
		return nil, err
	}

	resp, err := c.HTTPClient.Do(req)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	var book Book
	if err := json.NewDecoder(resp.Body).Decode(&book); err != nil {
		return nil, err
	}

	return book.fixDates(), nil
}

// UpdateBook updates the book with the specified ID
func (c *Client) UpdateBook(ctx context.Context, id int, updateOpts BookUpdateOptions) (*Book, error) {
	url := fmt.Sprintf("%s/books/%d", c.BaseURL, id)

	bodyData, err := json.Marshal(updateOpts)
	if err != nil {
		return nil, err
	}

	req, err := http.NewRequestWithContext(ctx, "PUT", url, json.RawMessage(bodyData))
	if err != nil {
		return nil, err
	}

	resp, err := c.HTTPClient.Do(req)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	var book Book
	if err := json.NewDecoder(resp.Body).Decode(&book); err != nil {
		return nil, err
	}

	return book.fixDates(), nil
}

// DeleteBook deletes the book with the specified ID
func (c *Client) DeleteBook(ctx context.Context, id int) error {
	url := fmt.Sprintf("%s/books/%d", c.BaseURL, id)

	req, err := http.NewRequestWithContext(ctx, "DELETE", url, nil)
	if err != nil {
		return err
	}

	resp, err := c.HTTPClient.Do(req)
	if err != nil {
		return err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return fmt.Errorf("error deleting book: status code %d", resp.StatusCode)
	}

	return nil
}

// fixDates converts JSON timestamps to Go time.Time values
func (b *Book) fixDates() *Book {
	if b.PublicationStr != "" {
		b.Publication, _ = time.Parse(time.RFC3339, b.PublicationStr)
	}
	return b
}

// Test cases to verify the solution correctness
func main() {
	client := NewClient("http://localhost:8080")

	// Create a new book
	book, err := client.CreateBook(context.Background(), BookCreateOptions{
		Title:          "The Go Programming Language",
		Author:         "Alan A. A. Donovan, Brian W. Kernighan",
		PublicationStr: "2015-10-26T00:00:00Z",
	})
	if err != nil {
		panic(err)
	}
	fmt.Printf("Created book: %+v\n", book)

	// Get the created book
	fetchedBook, err := client.GetBook(context.Background(), book.ID)
	if err != nil {
		panic(err)
	}
	fmt.Printf("Fetched book: %+v\n", fetchedBook)

	// Update the book
	updatedTitle := "The Go Programming Language (2nd Edition)"
	book, err = client.UpdateBook(context.Background(), book.ID, BookUpdateOptions{
		Title: &updatedTitle,
	})
	if err != nil {
		panic(err)
	}
	fmt.Printf("Updated book: %+v\n", book)

	// List books
	books, err := client.ListBooks(context.Background(), &ListOptions{Page: 1, PageSize: 10})
	if err != nil {
		panic(err)
	}
	fmt.Printf("Listed books: %+v\n", books)

	// Delete the book
	err = client.DeleteBook(context.Background(), book.ID)
	if err != nil {
