package main

import (
	"errors"
	"fmt"
	"net"
	"os"

	"github.com/cqroot/prompt"
	"github.com/cqroot/prompt/input"
)

var ErrInvalidIP = errors.New("invalid IPv4 address")

func validateIPv4(ip string) error {
	parsedIP := net.ParseIP(ip)
	if parsedIP == nil || parsedIP.To4() == nil {
		return fmt.Errorf("%s: %w", ip, ErrInvalidIP)
	}
	return nil
}

func main() {
	p := prompt.New()
	p.SetExitChecker(func(input string) bool {
		return input == "quit"
	})

	for {
		val, err := p.Ask("Please enter a valid IPv4 address (or type 'quit' to exit):").
			Input("192.168.1.1", input.WithValidateFunc(validateIPv4))
		if err != nil {
			if errors.Is(err, prompt.ErrUserQuit) {
				fmt.Fprintln(os.Stderr, "Exiting program. Goodbye!")
				os.Exit(0)
			} else if errors.Is(err, ErrInvalidIP) {
				fmt.Fprintln(os.Stderr, err)
				continue // Prompt again
			} else {
				panic(err) // Unexpected error
			}
		}
		fmt.Printf("You have entered a valid IPv4 address: %s\n", val)
		break
	}
}
