// Import the necessary packages
import (
	"log"
	"os"
	"time"
)

// Define the configuration sections and their fields with default values and environment variable bindings
type LoggerSection struct {
	LogLevel string `default:"debug" env:"LOG_LEVEL"`
}

type ServerSection struct {
	Address string `default:"127.0.0.1:8000" env:"ADDRESS"`
}

type DatabaseSection struct {
	Host              string        `default:"127.0.0.1" env:"HOST"`
	Port              string        `default:"6432" env:"PORT"`
	User              string        `default:"postgres" env:"USER"`
	Password          string        `default:"" env:"PASSWORD"`
	DBName            string        `default:"postgres" env:"DB_NAME"`
	ConnectionTimeout time.Duration `default:"2s" env:"CONNECTION_TIMEOUT"`
	OperationTimeout  time.Duration `default:"2s" env:"OPERATION_TIMEOUT"`
}

type Config struct {
	Logger   LoggerSection
	Server   ServerSection
	Database DatabaseSection
}

// New initializes and returns a configuration object
func New(configPath string) *Config {
	var cfg Config

	// Check if the configuration file exists, log a message if it does not
	if _, err := os.Stat(configPath); err != nil {
		log.Println("fail to get config file, continue without it:", err)
	}

	// Set up the configuration loader with the specified file and environment variable prefix
	loader := aconfig.LoaderFor(&cfg, aconfig.Config{
		SkipFlags: true,

		EnvPrefix: "CURRENCY_API",
		Files:     []string{configPath},
		FileDecoders: map[string]aconfig.FileDecoder{
			".yaml": aconfigyaml.New(),
		},
	})

	// Load the configuration, log a fatal error if it fails
	if loadErr := loader.Load(); loadErr != nil {
		log.Fatal("failed to load configuration", loadErr)
	}

	// Return the configuration object
	return &cfg
}

// Main function to demonstrate the usage of the New function
func main() {
	// Assume the configuration file is named "config.yaml"
	configPath := "config.yaml"

	// Initialize the configuration
	cfg := New(configPath)

	// Print the loaded configuration for demonstration purposes
	fmt.Printf("Logger Level: %s\n", cfg.Logger.LogLevel)
	fmt.Printf("Server Address: %s\n", cfg.Server.Address)
	fmt.Printf("Database Host: %s\n", cfg.Database.Host)
	fmt.Printf("Database Port: %s\n", cfg.Database.Port)
	fmt.Printf("Database User: %s\n", cfg.Database.User)
	fmt.Printf("Database Password: %s\n", cfg.Database.Password)
	fmt.Printf("Database Name: %s\n", cfg.Database.DBName)
	fmt.Printf("Database Connection Timeout: %s\n", cfg.Database.ConnectionTimeout)
	fmt.Printf("Database Operation Timeout: %s\n", cfg.Database.OperationTimeout)
}

