// Qualifications is a slice that holds the list of qualifications.
var Qualifications []Qualification

// AddQualification adds a new qualification to the list.
func AddQualification(qualification Qualification) error {
	for _, q := range Qualifications {
		if q.ID == qualification.ID {
			return fmt.Errorf("qualification with ID %s already exists", qualification.ID)
		}
	}
	Qualifications = append(Qualifications, qualification)
	return nil
}

// RemoveQualification removes a qualification from the list by ID.
func RemoveQualification(id string) error {
	for i, q := range Qualifications {
		if q.ID == id {
			Qualifications = append(Qualifications[:i], Qualifications[i+1:]...)
			return nil
		}
	}
	return fmt.Errorf("qualification with ID %s not found", id)
}

// ListQualifications returns the current list of qualifications.
func ListQualifications() []Qualification {
	return Qualifications
}

// ExtendQualification updates the expiration date of a qualification.
func ExtendQualification(id string, newValidUntil time.Time) error {
	for i, q := range Qualifications {
		if q.ID == id {
			Qualifications[i].ValidUntil = newValidUntil
			return nil
		}
	}
	return fmt.Errorf("qualification with ID %s not found", id)
}

