package githubparser

import (
	"net/url"
	"strings"
)

// GitHubURLParser is a struct that provides methods to parse GitHub URLs.
type GitHubURLParser struct {
	rawURL string
}

// New creates a new instance of GitHubURLParser.
func New() *GitHubURLParser {
	return &GitHubURLParser{}
}

// SetURL sets the URL to be parsed by the GitHubURLParser.
func (p *GitHubURLParser) SetURL(rawURL string) {
	p.rawURL = rawURL
}

// Is checks if the given URL is a valid GitHub URL.
func (p *GitHubURLParser) Is() bool {
	u, err := url.Parse(p.rawURL)
	if err != nil {
		return false
	}
	return strings.Contains(u.Host, "github.com")
}

// GetUserName extracts the username from the GitHub URL.
func (p *GitHubURLParser) GetUserName() string {
	parts := p.getURLParts()
	if len(parts) > 0 {
		return parts[0]
	}
	return ""
}

// GetProjectName extracts the repository name from the GitHub URL.
func (p *GitHubURLParser) GetProjectName() string {
	parts := p.getURLParts()
	if len(parts) > 1 {
		return parts[1]
	}
	return ""
}

// GetProjectPath extracts the subpath within the repository from the GitHub URL.
func (p *GitHubURLParser) GetProjectPath() string {
	parts := p.getURLParts()
	if len(parts) > 2 {
		return "/" + strings.Join(parts[2:], "/")
	}
	return ""
}

// GetProjectURL constructs the base URL of the repository.
func (p *GitHubURLParser) GetProjectURL() string {
	userName := p.GetUserName()
	projectName := p.GetProjectName()
	if userName != "" && projectName != "" {
		return "github.com/" + userName + "/" + projectName
	}
	return ""
}

// GetProviderID identifies the provider from the GitHub URL.
func (p *GitHubURLParser) GetProviderID() string {
	if p.Is() {
		return "github"
	}
	return ""
}

// GetURL returns the full URL if it is a valid GitHub URL.
func (p *GitHubURLParser) GetURL() string {
	if p.Is() {
		return p.rawURL
	}
	return ""
}

// getURLParts splits the URL path into parts, excluding the domain.
func (p *GitHubURLParser) getURLParts() []string {
	u, err := url.Parse(p.rawURL)
	if err != nil {
		return []string{}
	}
	path := strings.Trim(u.Path, "/")
	return strings.Split(path, "/")
}

