package main

import (
	"net/http"
	"sync"

	"github.com/labstack/echo/v4"
	"github.com/labstack/echo/v4/middleware"
)

type KeyValueStore struct {
	store map[string]string
	mu    sync.RWMutex
}

func NewKeyValueStore() *KeyValueStore {
	return &KeyValueStore{
		store: make(map[string]string),
	}
}

func (kvs *KeyValueStore) Set(c echo.Context) error {
	kvs.mu.Lock()
	defer kvs.mu.Unlock()

	type request struct {
		Key   string `json:"key"`
		Value string `json:"value"`
	}

	req := new(request)
	if err := c.Bind(req); err != nil {
		return echo.NewHTTPError(http.StatusBadRequest, err.Error())
	}

	kvs.store[req.Key] = req.Value
	return c.NoContent(http.StatusCreated)
}

func (kvs *KeyValueStore) Get(c echo.Context) error {
	kvs.mu.RLock()
	defer kvs.mu.RUnlock()

	key := c.Param("key")
	value, exists := kvs.store[key]
	if !exists {
		return echo.NewHTTPError(http.StatusNotFound, "Key not found")
	}

	return c.JSON(http.StatusOK, map[string]string{key: value})
}

func (kvs *KeyValueStore) GetAll(c echo.Context) error {
	kvs.mu.RLock()
	defer kvs.mu.RUnlock()

	return c.JSON(http.StatusOK, kvs.store)
}

func (kvs *KeyValueStore) Delete(c echo.Context) error {
	kvs.mu.Lock()
	defer kvs.mu.Unlock()

	key := c.Param("key")
	_, exists := kvs.store[key]
	if !exists {
		return echo.NewHTTPError(http.StatusNotFound, "Key not found")
	}

	delete(kvs.store, key)
	return c.NoContent(http.StatusNoContent)
}

func main() {
	e := echo.New()
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())
	e.Use(middleware.GzipWithConfig(middleware.GzipConfig{
		Level: 5,
	}))
	e.Use(middleware.CORSWithConfig(middleware.CORSConfig{
		AllowOrigins: []string{"*"},
		AllowHeaders: []string{echo.HeaderOrigin, echo.HeaderContentType, echo.HeaderAccept},
	}))

	kvs := NewKeyValueStore()

	e.POST("/api/v1/map", kvs.Set)
	e.GET("/api/v1/map/:key", kvs.Get)
	e.GET("/api/v1/map/all", kvs.GetAll)
	e.DELETE("/api/v1/map/:key", kvs.Delete)

	e.Logger.Fatal(e.Start(":8080"))
}
