package collection

import (
	"testing"
)

// Set represents a collection of distinct objects.
type Set struct {
	items map[string]struct{}
}

// NewSet creates a new Set instance.
func NewSet() *Set {
	return &Set{items: make(map[string]struct{})}
}

// Add inserts a new item into the set.
func (s *Set) Add(item string) {
	s.items[item] = struct{}{}
}

// Remove deletes an item from the set.
func (s *Set) Remove(item string) {
	delete(s.items, item)
}

// Contains checks if an item is in the set.
func (s *Set) Contains(item string) bool {
	_, exists := s.items[item]
	return exists
}

// Size returns the number of items in the set.
func (s *Set) Size() int {
	return len(s.items)
}

// TestSetOperations tests the Set data structure operations.
func TestSetOperations(t *testing.T) {
	set := NewSet()
	set.Add("item 1")
	set.Add("item 2")
	set.Add("item 2") // Adding duplicate item, should not affect the size

	if set.Size() != 2 {
		t.Errorf("Expected set size to be 2, got %d", set.Size())
	}

	if !set.Contains("item 1") {
		t.Error("Expected set to contain 'item 1'")
	}

	set.Remove("item 1")
	if set.Contains("item 1") {
		t.Error("Expected 'item 1' to be removed from the set")
	}

	if set.Size() != 1 {
		t.Errorf("Expected set size to be 1 after removal, got %d", set.Size())
	}

	set.Remove("item 2")
	if set.Contains("item 2") {
		t.Error("Expected 'item 2' to be removed from the set")
	}

	if set.Size() != 0 {
		t.Errorf("Expected set to be empty, got size %d", set.Size())
	}
}
