	"os"
	"strconv"
	"strings"

	"./utils" // Assuming the utils package is in the same directory
)

type Note struct {
	ID      int
	Content string
}

var notes []Note
var nextID int = 1

func main() {
	scanner := bufio.NewScanner(os.Stdin)
	for {
		utils.ClearTerminal()
		fmt.Println("Please choose an option:")
		fmt.Println("1) List all notes")
		fmt.Println("2) Create a new note")
		fmt.Println("3) Update an existing note")
		fmt.Println("4) Delete a note")
		fmt.Println("5) Exit")
		fmt.Print("Enter your choice: ")

		scanner.Scan()
		choice := scanner.Text()

		switch choice {
		case "1":
			listNotes()
		case "2":
			createNote(scanner)
		case "3":
			updateNote(scanner)
		case "4":
			deleteNote(scanner)
		case "5":
			fmt.Println("Exiting application...")
			return
		default:
			fmt.Println("Invalid choice, please try again.")
		}
	}
}

func listNotes() {
	fmt.Println("Listing all notes:")
	for _, note := range notes {
		fmt.Printf("ID: %d, Content: %s\n", note.ID, note.Content)
	}
	fmt.Println("Press Enter to continue...")
	bufio.NewReader(os.Stdin).ReadBytes('\n')
}

func createNote(scanner *bufio.Scanner) {
	fmt.Print("Enter note content: ")
	scanner.Scan()
	content := scanner.Text()
	notes = append(notes, Note{ID: nextID, Content: content})
	nextID++
	fmt.Println("Note created successfully.")
}

func updateNote(scanner *bufio.Scanner) {
	fmt.Print("Enter note ID to update: ")
	scanner.Scan()
	id, err := strconv.Atoi(scanner.Text())
	if err != nil {
		fmt.Println("Invalid ID, please try again.")
		return
	}
	for i, note := range notes {
		if note.ID == id {
			fmt.Print("Enter new content: ")
			scanner.Scan()
			notes[i].Content = scanner.Text()
			fmt.Println("Note updated successfully.")
			return
		}
	}
	fmt.Println("Note not found.")
}

func deleteNote(scanner *bufio.Scanner) {
	fmt.Print("Enter note ID to delete: ")
	scanner.Scan()
	id, err := strconv.Atoi(scanner.Text())
	if err != nil {
		fmt.Println("Invalid ID, please try again.")
		return
	}
	for i, note := range notes {
		if note.ID == id {
			notes = append(notes[:i], notes[i+1:]...)
			fmt.Println("Note deleted successfully.")
			return
		}
	}
	fmt.Println("Note not found.")
}

// Test cases to verify the solution correctness
func main() {
	// Since the application is interactive and relies on user input,
	// automated test cases are not feasible. However, you can manually
	// test the application by running it and following the prompts to
	// create, update, list, and delete notes.
}
