// Define a function to format and output the issues in Checkstyle XML format.
func FormatAndOutputIssues(issues []CheckstyleError, appErr error) {
	files := map[string]*CheckstyleFile{}
	for _, issue := range issues {
		if file, exists := files[issue.Rule]; exists {
			file.Errors = append(file.Errors, &issue)
		} else {
			files[issue.Rule] = &CheckstyleFile{
				Name:   issue.Rule,
				Errors: []*CheckstyleError{&issue},
			}
		}
	}

	checkstyleReport := &Checkstyle{}
	for _, file := range files {
		checkstyleReport.Files = append(checkstyleReport.Files, file)
	}

	out, err := xml.MarshalIndent(checkstyleReport, "", "  ")
	if err != nil {
		fmt.Fprint(os.Stderr, err)
		return
	}
	fmt.Fprint(os.Stdout, xml.Header)
	fmt.Fprint(os.Stdout, string(out))

	if appErr != nil {
		fmt.Fprint(os.Stderr, appErr)
	}
}

// Example usage of the FormatAndOutputIssues function.
func main() {
	issues := []CheckstyleError{
		{
			Rule:     "rule1",
			Line:     10,
			Column:   5,
			Severity: "error",
			Message:  "Example issue 1",
			Link:     "http://example.com/rule1",
		},
		{
			Rule:     "rule2",
			Line:     20,
			Column:   15,
			Severity: "warning",
			Message:  "Example issue 2",
			Link:     "http://example.com/rule2",
		},
	}

	FormatAndOutputIssues(issues, nil)
}
