package main

import (
	"errors"
	"fmt"
	"sync"
	"time"
)

// VerificationCode represents a single verification code with an expiration time.
type VerificationCode interface {
	Valid() bool
	Expire()
	GetCode() string
}

// VerificationStore is responsible for generating and managing verification codes.
type VerificationStore interface {
	Generate() (VerificationCode, error)
	Delete(code string)
	Check(code string) bool
}

// SimpleVerificationCode is a simple implementation of the VerificationCode interface.
type SimpleVerificationCode struct {
	code      string
	expired   bool
	expiresAt time.Time
}

// Valid checks if the verification code is still valid (not expired).
func (vc *SimpleVerificationCode) Valid() bool {
	return !vc.expired && time.Now().Before(vc.expiresAt)
}

// Expire sets the verification code as expired.
func (vc *SimpleVerificationCode) Expire() {
	vc.expired = true
}

// GetCode returns the verification code string.
func (vc *SimpleVerificationCode) GetCode() string {
	return vc.code
}

// InMemoryVerificationStore is an in-memory implementation of the VerificationStore interface.
type InMemoryVerificationStore struct {
	codes map[string]*SimpleVerificationCode
	mu    sync.Mutex
}

// Generate creates a new verification code with a 5-minute expiration time.
func (store *InMemoryVerificationStore) Generate() (VerificationCode, error) {
	store.mu.Lock()
	defer store.mu.Unlock()

	code := fmt.Sprintf("%06d", time.Now().UnixNano()%1000000)
	vc := &SimpleVerificationCode{
		code:      code,
		expired:   false,
		expiresAt: time.Now().Add(5 * time.Minute),
	}
	store.codes[code] = vc
	return vc, nil
}

// Delete removes a verification code from the store.
func (store *InMemoryVerificationStore) Delete(code string) {
	store.mu.Lock()
	defer store.mu.Unlock()

	delete(store.codes, code)
}

// Check verifies if a code is valid and not expired.
func (store *InMemoryVerificationStore) Check(code string) bool {
	store.mu.Lock()
	defer store.mu.Unlock()

	if vc, exists := store.codes[code]; exists {
		return vc.Valid()
	}
	return false
}

// NewInMemoryVerificationStore creates a new instance of InMemoryVerificationStore.
func NewInMemoryVerificationStore() *InMemoryVerificationStore {
	return &InMemoryVerificationStore{
		codes: make(map[string]*SimpleVerificationCode),
	}
}

func main() {
	store := NewInMemoryVerificationStore()

	// Test case 1: Generate a new code and check its validity
	code, err := store.Generate()
	if err != nil {
		fmt.Println("Error generating code:", err)
		return
	}
	fmt.Println("Generated code:", code.GetCode())
	fmt.Println("Is code valid?", store.Check(code.GetCode()))

	// Test case 2: Expire the code and check its validity again
	code.Expire()
	fmt.Println("Is code valid after expiring?", store.Check(code.GetCode()))

	// Test case 3: Wait for 5 minutes and check the code validity
	time.Sleep(5 * time.Minute)
	fmt.Println("Is code valid after 5 minutes?", store.Check(code.GetCode()))

	// Test case 4: Delete the code and check its existence
	store.Delete(code.GetCode())
	fmt.Println("Is code still valid after deletion?", store.Check(code.GetCode()))
}
