    Responses []Response
}

func (out *Output) ClearResponses() *Output {
    out.Responses = []Response{}
    return out
}

func (out *Output) FilterResponses(condition func(Response) bool) *Output {
    filtered := []Response{}
    for _, response := range out.Responses {
        if condition(response) {
            filtered = append(filtered, response)
        }
    }
    out.Responses = filtered
    return out
}

// Example usage and test cases
func main() {
    // Create an Output with some responses
    output := &Output{
        Responses: []Response{
            {ID: "1", Content: "Response 1", Valid: true},
            {ID: "2", Content: "Response 2", Valid: false},
            {ID: "3", Content: "Response 3", Valid: true},
        },
    }

    // Define a condition function to filter valid responses
    validCondition := func(r Response) bool {
        return r.Valid
    }

    // Filter the responses
    output.FilterResponses(validCondition)

    // Print the filtered responses
    for _, response := range output.Responses {
        fmt.Printf("ID: %s, Content: %s, Valid: %t\n", response.ID, response.Content, response.Valid)
    }
    // Expected output:
    // ID: 1, Content: Response 1, Valid: true
    // ID: 3, Content: Response 3, Valid: true
}
