package main

import (
	"errors"
	"fmt"
	"sync"
)

// Call represents a single call in the telecommunication system.
type Call struct {
	ID          string
	Participants []string
	State       string
	Subject     string
}

// CallManager manages the calls within the telecommunication system.
type CallManager struct {
	calls map[string]*Call
	mu    sync.Mutex
}

// NewCallManager creates a new instance of CallManager.
func NewCallManager() *CallManager {
	return &CallManager{
		calls: make(map[string]*Call),
	}
}

// CreateCall creates a new call and adds it to the manager.
func (m *CallManager) CreateCall(subject string, participants []string) *Call {
	m.mu.Lock()
	defer m.mu.Unlock()

	callID := fmt.Sprintf("call-%d", len(m.calls)+1) // Simple ID generation logic
	call := &Call{
		ID:          callID,
		Participants: participants,
		State:       "active",
		Subject:     subject,
	}
	m.calls[call.ID] = call
	return call
}

// EndCall ends the call with the given ID.
func (m *CallManager) EndCall(callID string) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	call, exists := m.calls[callID]
	if !exists {
		return errors.New("call not found")
	}
	call.State = "ended"
	return nil
}

// GetCall retrieves the call with the given ID.
func (m *CallManager) GetCall(callID string) (*Call, error) {
	m.mu.Lock()
	defer m.mu.Unlock()

	call, exists := m.calls[callID]
	if !exists {
		return nil, errors.New("call not found")
	}
	return call, nil
}

// ListCalls returns a slice of all active calls.
func (m *CallManager) ListCalls() []*Call {
	m.mu.Lock()
	defer m.mu.Unlock()

	var activeCalls []*Call
	for _, call := range m.calls {
		if call.State == "active" {
			activeCalls = append(activeCalls, call)
		}
	}
	return activeCalls
}

func main() {
	manager := NewCallManager()

	// Test cases
	call1 := manager.CreateCall("Project Discussion", []string{"Alice", "Bob"})
	fmt.Printf("Created Call: %+v\n", call1)

	call2 := manager.CreateCall("Team Meeting", []string{"Charlie", "Dave", "Eve"})
	fmt.Printf("Created Call: %+v\n", call2)

	err := manager.EndCall(call1.ID)
	if err != nil {
		fmt.Println("Error ending call:", err)
	}

	call, err := manager.GetCall(call1.ID)
	if err != nil {
		fmt.Println("Error getting call:", err)
	} else {
		fmt.Printf("Retrieved Call: %+v\n", call)
	}

	activeCalls := manager.ListCalls()
	fmt.Println("Active Calls:")
	for _, c := range activeCalls {
		fmt.Printf("%+v\n", c)
	}
}
