package auth

import (
	vaultapi "github.com/hashicorp/vault/api"
	"github.com/pkg/errors"
)

// K8sAuthenticatorOptions holds the configuration parameters for Kubernetes authentication.
type K8sAuthenticatorOptions struct {
	Host  string // Kubernetes API server host
	CA    string // Kubernetes CA certificate
	Token string // Token reviewer JWT
}

// Authenticator defines the interface for Vault authentication methods.
type Authenticator interface {
	EnsureAuth() error
	ConfigureAuth() error
}

// KubernetesAuthenticator implements the Authenticator interface for Kubernetes authentication.
type KubernetesAuthenticator struct {
	vc     *vaultapi.Client
	config *K8sAuthenticatorOptions
}

// NewKubernetesAuthenticator creates a new KubernetesAuthenticator with the given Vault client and configuration options.
func NewKubernetesAuthenticator(vc *vaultapi.Client, cf *K8sAuthenticatorOptions) Authenticator {
	return &KubernetesAuthenticator{
		vc:     vc,
		config: cf,
	}
}

// EnsureAuth ensures that the Kubernetes authentication method is enabled in Vault.
func (k *KubernetesAuthenticator) EnsureAuth() error {
	if k.vc == nil {
		return errors.New("vault client is nil")
	}

	authList, err := k.vc.Sys().ListAuth()
	if err != nil {
		return err
	}
	for path, auth := range authList {
		if auth.Type == kubernetesAuthType && path == kubernetesAuthPath {
			// Kubernetes auth already enabled
			return nil
		}
	}

	err = k.vc.Sys().EnableAuthWithOptions(kubernetesAuthPath, &vaultapi.EnableAuthOptions{
		Type: kubernetesAuthType,
	})
	return err
}

// ConfigureAuth configures the Kubernetes authentication method in Vault with the necessary parameters.
func (k *KubernetesAuthenticator) ConfigureAuth() error {
	if k.vc == nil {
		return errors.New("vault client is nil")
	}
	if k.config == nil {
		return errors.New("kubernetes config is nil")
	}

	payload := map[string]interface{}{
		"kubernetes_host":        k.config.Host,
		"kubernetes_ca_cert":     k.config.CA,
		"token_reviewer_jwt":     k.config.Token,
		"disable_iss_validation": true,
		"disable_local_ca_jwt":   true,
	}

	_, err := k.vc.Logical().Write("auth/kubernetes/config", payload)
	return err
}

// Test cases to verify the solution correctness.
func main() {
	// Initialize Vault client (omitted for brevity)
	vaultClient, err := vaultapi.NewClient(vaultapi.DefaultConfig())
	if err != nil {
		panic(err)
	}

	// Define Kubernetes authentication options
	k8sAuthOptions := &K8sAuthenticatorOptions{
		Host:  "https://kubernetes.default.svc",
		CA:    "<kubernetes-ca-cert>",
		Token: "<token-reviewer-jwt>",
	}

	// Create a new Kubernetes authenticator
	authenticator := NewKubernetesAuthenticator(vaultClient, k8sAuthOptions)

	// Ensure Kubernetes authentication is enabled
	if err := authenticator.EnsureAuth(); err != nil {
		panic(err)
	}

	// Configure Kubernetes authentication
	if err := authenticator.ConfigureAuth(); err != nil {
		panic(err)
	}

	// Output success message
	println("Kubernetes authentication is enabled and configured successfully.")
}
