package main

import (
	"encoding/json"
	"errors"
	"fmt"
)

type UserRequest struct {
	Name     string `json:"name"`
	Email    string `json:"email"`
	Phone    string `json:"phone"`
	Address  string `json:"address"`
	Image    string `json:"image"`
	Password string `json:"password"`
}

type UserLoginRequest struct {
	Email    string `json:"email"`
	Password string `json:"password"`
}

type LoginResponse struct {
	ID      string `json:"id"`
	Name    string `json:"name"`
	Email   string `json:"email"`
	Phone   string `json:"phone"`
	Address string `json:"address"`
	Type    string `json:"type"`
}

type UpdateProfileRequest struct {
	Name    string `json:"name"`
	Email   string `json:"email"`
	Phone   string `json:"phone"`
	Address string `json:"address"`
	Image   string `json:"image"`
}

type Profile struct {
	ID      string `json:"id"`
	Name    string `json:"name"`
	Email   string `json:"email"`
	Phone   string `json:"phone"`
	Address string `json:"address"`
	Image   string `json:"image"`
}

var users = make(map[string]UserRequest) // In-memory user storage

// RegisterUser registers a new user if the email is not already used.
func RegisterUser(userReq UserRequest) (Profile, error) {
	for _, user := range users {
		if user.Email == userReq.Email {
			return Profile{}, errors.New("email already in use")
		}
	}

	id := fmt.Sprintf("%d", len(users)+1) // Generate a simple unique ID
	users[id] = userReq

	return Profile{
		ID:      id,
		Name:    userReq.Name,
		Email:   userReq.Email,
		Phone:   userReq.Phone,
		Address: userReq.Address,
		Image:   userReq.Image,
	}, nil
}

// LoginUser authenticates a user and returns a login response without the password.
func LoginUser(loginReq UserLoginRequest) (LoginResponse, error) {
	for id, user := range users {
		if user.Email == loginReq.Email && user.Password == loginReq.Password {
			return LoginResponse{
				ID:      id,
				Name:    user.Name,
				Email:   user.Email,
				Phone:   user.Phone,
				Address: user.Address,
				Type:    "user",
			}, nil
		}
	}
	return LoginResponse{}, errors.New("invalid credentials")
}

// UpdateUserProfile updates a user's profile and returns the updated profile without the password.
func UpdateUserProfile(id string, updateReq UpdateProfileRequest) (Profile, error) {
	user, exists := users[id]
	if !exists {
		return Profile{}, errors.New("user not found")
	}

	user.Name = updateReq.Name
	user.Email = updateReq.Email
	user.Phone = updateReq.Phone
	user.Address = updateReq.Address
	user.Image = updateReq.Image
	users[id] = user

	return Profile{
		ID:      id,
		Name:    user.Name,
		Email:   user.Email,
		Phone:   user.Phone,
		Address: user.Address,
		Image:   user.Image,
	}, nil
}

// GetUserProfile retrieves a user's profile without the password.
func GetUserProfile(id string) (Profile, error) {
	user, exists := users[id]
	if !exists {
		return Profile{}, errors.New("user not found")
	}

	return Profile{
		ID:      id,
		Name:    user.Name,
		Email:   user.Email,
		Phone:   user.Phone,
		Address: user.Address,
		Image:   user.Image,
	}, nil
}

func main() {
	// Test cases
	userReq := UserRequest{
		Name:     "John Doe",
		Email:    "john@example.com",
		Phone:    "1234567890",
		Address:  "123 Main St",
		Image:    "profile.jpg",
		Password: "password123",
	}

	// Register a new user
	profile, err := RegisterUser(userReq)
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Println("Registered User:", profile)
	}

	// Attempt to login
	loginReq := UserLoginRequest{
		Email:    "john@example.com",
		Password: "password123",
	}
	loginResp, err := LoginUser(loginReq)
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Println("Login Successful:", loginResp)
	}

	// Update user profile
	updateReq := UpdateProfileRequest{
		Name:    "John Updated",
		Email:   "john@example.com",
		Phone:   "0987654321",
		Address: "321 Main St",
		Image:   "new_profile.jpg",
	}
	updatedProfile, err := UpdateUserProfile(profile.ID, updateReq)
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Println("Updated Profile:", updatedProfile)
	}

	// Retrieve user profile
	retrievedProfile, err := GetUserProfile(profile.ID)
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Println("Retrieved Profile:", retrievedProfile)
	}
}
