import (
	"fmt"
	"math"
)

// maxSingleSellProfit calculates the maximum profit from a single buy and sell action.
func maxSingleSellProfit(prices []int) int {
	maxProfit := 0
	minPrice := math.MaxInt64

	for _, price := range prices {
		if price < minPrice {
			minPrice = price
		} else if profit := price - minPrice; profit > maxProfit {
			maxProfit = profit
		}
	}

	return maxProfit
}

func main() {
	testCases := [][]int{
		{7, 1, 5, 3, 6, 4},
		{7, 6, 4, 3, 1},
		{1, 2, 3, 4, 5},
	}

	for _, prices := range testCases {
		fmt.Printf("Max profit for prices %v: %d\n", prices, maxSingleSellProfit(prices))
	}
}
