package pocketlog

import (
	"fmt"
	"io"
	"os"
	"time"
)

// LogLevel defines the severity of the log message.
type LogLevel int

const (
	// INFO represents informational messages.
	INFO LogLevel = iota
	// WARN represents warning messages.
	WARN
	// ERROR represents error messages.
	ERROR
)

// Logger represents a simple logger with configurable options.
type Logger struct {
	output      io.Writer
	level       LogLevel
	includeTime bool
}

// NewLogger creates a new Logger with the given options.
func NewLogger(opts ...Option) *Logger {
	lgr := &Logger{
		output:      os.Stdout,
		level:       INFO,
		includeTime: true,
	}
	for _, opt := range opts {
		opt(lgr)
	}
	return lgr
}

// WithOutput sets the output destination for the logger.
func WithOutput(output io.Writer) Option {
	return func(lgr *Logger) {
		lgr.output = output
	}
}

// WithLogLevel sets the log level for the logger.
func WithLogLevel(level LogLevel) Option {
	return func(lgr *Logger) {
		lgr.level = level
	}
}

// WithTimestamp sets the flag to include timestamps in the logs.
func WithTimestamp(include bool) Option {
	return func(lgr *Logger) {
		lgr.includeTime = include
	}
}

// log writes a log entry with the given level and message.
func (l *Logger) log(level LogLevel, msg string) {
	if level < l.level {
		return
	}

	levelStr := ""
	switch level {
	case INFO:
		levelStr = "INFO"
	case WARN:
		levelStr = "WARN"
	case ERROR:
		levelStr = "ERROR"
	}

	timeStr := ""
	if l.includeTime {
		timeStr = fmt.Sprintf("[%s] ", time.Now().Format(time.RFC3339))
	}

	logEntry := fmt.Sprintf("%s[%s] %s\n", timeStr, levelStr, msg)
	l.output.Write([]byte(logEntry))
}

// Info logs an informational message.
func (l *Logger) Info(msg string) {
	l.log(INFO, msg)
}

// Warn logs a warning message.
func (l *Logger) Warn(msg string) {
	l.log(WARN, msg)
}

// Error logs an error message.
func (l *Logger) Error(msg string) {
	l.log(ERROR, msg)
}

// Example usage of the pocketlog package.
func main() {
	// Create a logger with default options.
	logger := NewLogger()

	// Log messages with different levels.
	logger.Info("This is an informational message.")
	logger.Warn("This is a warning message.")
	logger.Error("This is an error message.")

	// Create a logger that writes to a file and only logs WARN and ERROR messages.
	file, _ := os.Create("log.txt")
	defer file.Close()
	fileLogger := NewLogger(WithOutput(file), WithLogLevel(WARN), WithTimestamp(false))

	// Log messages with the file logger.
	fileLogger.Info("This INFO message will not be logged to the file.")
	fileLogger.Warn("This WARN message will be logged to the file.")
	fileLogger.Error("This ERROR message will be logged to the file.")
}
