	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
)

var (
	kubeconfig string
)

func init() {
	kubeconfig = filepath.Join(
		os.Getenv("HOME"), ".kube", "config",
	)
}

func buildConfig() *rest.Config {
	config, err := clientcmd.BuildConfigFromFlags("", kubeconfig)
	if err != nil {
		log.Fatal(err)
	}
	return config
}

func InitClient() (*kubernetes.Clientset, error) {
	config := buildConfig()
	clientset, err := kubernetes.NewForConfig(config)
	if err != nil {
		return nil, err
	}
	return clientset, nil
}

func InitMetricsClient() (*metrics.Clientset, error) {
	config := buildConfig()
	metricsClientset, err := metrics.NewForConfig(config)
	if err != nil {
		return nil, err
	}
	return metricsClientset, nil
}

func ListPods(namespace string) ([]string, error) {
	clientset, err := InitClient()
	if err != nil {
		return nil, err
	}

	pods, err := clientset.CoreV1().Pods(namespace).List(context.TODO(), metav1.ListOptions{})
	if err != nil {
		return nil, err
	}

	var podNames []string
	for _, pod := range pods.Items {
		podNames = append(podNames, pod.Name)
	}

	return podNames, nil
}

func GetPodMetrics(namespace, podName string) (cpuUsage, memoryUsage string, err error) {
	metricsClientset, err := InitMetricsClient()
	if err != nil {
		return "", "", err
	}

	metrics, err := metricsClientset.MetricsV1beta1().PodMetricses(namespace).Get(context.TODO(), podName, metav1.GetOptions{})
	if err != nil {
		return "", "", err
	}

	for _, container := range metrics.Containers {
		cpuUsage = container.Usage.Cpu().String()
		memoryUsage = container.Usage.Memory().String()
		break // Assuming we only need the first container's metrics for this example
	}

	return cpuUsage, memoryUsage, nil
}

func main() {
	// Example usage:
	namespace := "default" // Replace with your namespace

	podNames, err := ListPods(namespace)
	if err != nil {
		log.Fatalf("Error listing pods: %v", err)
	}
	fmt.Println("Pods in namespace:", podNames)

	for _, podName := range podNames {
		cpu, mem, err := GetPodMetrics(namespace, podName)
		if err != nil {
			log.Printf("Error getting metrics for pod %s: %v", podName, err)
			continue
		}
		fmt.Printf("Pod: %s, CPU: %s, Memory: %s\n", podName, cpu, mem)
	}
}

