package main

import (
	"crypto/sha256"
	"encoding/hex"
	"fmt"
	"strconv"
	"time"
)

// Transaction represents a transfer of value from one address to another.
type Transaction struct {
	From   string // Sender's address
	To     string // Receiver's address
	Amount int    // Amount transferred
}

// Block represents a single block in the DAGBlockchain, containing transactions and references to parent blocks.
type Block struct {
	Timestamp    string          // Time at which the block was created
	Transactions []*Transaction  // List of transactions included in the block
	PrevHashes   []string        // Hashes of the block's parent blocks
	Hash         string          // Hash of the block
}

// DAGBlockchain represents a blockchain where each block can reference multiple parent blocks.
type DAGBlockchain struct {
	Blocks []*Block // List of blocks in the blockchain
}

// NewBlock creates a new block with the given transactions and parent block hashes.
func NewBlock(transactions []*Transaction, prevHashes []string) *Block {
	block := &Block{
		Timestamp:    time.Now().String(),
		Transactions: transactions,
		PrevHashes:   prevHashes,
	}
	block.Hash = block.calculateHash()
	return block
}

// calculateHash computes the hash of the block using its contents and parent block hashes.
func (b *Block) calculateHash() string {
	record := b.Timestamp
	for _, tx := range b.Transactions {
		record += tx.From + tx.To + strconv.Itoa(tx.Amount)
	}
	for _, prevHash := range b.PrevHashes {
		record += prevHash
	}
	h := sha256.New()
	h.Write([]byte(record))
	hashed := h.Sum(nil)
	return hex.EncodeToString(hashed)
}

// NewDAGBlockchain initializes a new DAGBlockchain with a genesis block.
func NewDAGBlockchain() *DAGBlockchain {
	genesisBlock := NewBlock(nil, []string{})
	return &DAGBlockchain{
		Blocks: []*Block{genesisBlock},
	}
}

// AddBlock adds a new block to the DAGBlockchain with the specified transactions and parent block hashes.
func (bc *DAGBlockchain) AddBlock(transactions []*Transaction, prevHashes []string) *Block {
	block := NewBlock(transactions, prevHashes)
	bc.Blocks = append(bc.Blocks, block)
	return block
}

// Print the details of all blocks in the blockchain.
func (bc *DAGBlockchain) PrintBlocks() {
	fmt.Println("Blocks:")
	for _, block := range bc.Blocks {
		fmt.Printf("Timestamp: %s\n", block.Timestamp)
		fmt.Println("Transactions:")
		for _, tx := range block.Transactions {
			fmt.Printf("From: %s\n", tx.From)
			fmt.Printf("To: %s\n", tx.To)
			fmt.Printf("Amount: %d\n", tx.Amount)
		}
		fmt.Printf("PrevHashes: %v\n", block.PrevHashes)
		fmt.Printf("Hash: %s\n", block.Hash)
		fmt.Println()
	}
}

func main() {
	bc := NewDAGBlockchain()

	// Test cases: Add some transactions and blocks
	tx1 := &Transaction{From: "Alice", To: "Bob", Amount: 10}
	block1 := bc.AddBlock([]*Transaction{tx1}, []string{bc.Blocks[0].Hash})

	tx2 := &Transaction{From: "Bob", To: "Charlie", Amount: 5}
	block2 := bc.AddBlock([]*Transaction{tx2}, []string{block1.Hash})

	tx3 := &Transaction{From: "Charlie", To: "Dave", Amount: 3}
	block3 := bc.AddBlock([]*Transaction{tx3}, []string{block1.Hash})

	tx4 := &Transaction{From: "Dave", To: "Eve", Amount: 2}
	block4 := bc.AddBlock([]*Transaction{tx4}, []string{block2.Hash, block3.Hash})

	// Print the blocks to verify correctness
	bc.PrintBlocks()
	_ = block4 // To avoid unused variable error
}
