package main

import (
	"encoding/json"
	"fmt"
	"io/ioutil"
	"os"
	"sync"
)

// Mysql struct defining keys for MySQL connection details
type Mysql struct {
	Host string `json:"host"`
	Port string `json:"port"`
	User string `json:"user"`
	Pass string `json:"pass"`
}

// Config struct defining key for a slice of MySQL configurations
type Config struct {
	MySQLPool []Mysql `json:"mysql"`
}

// ConfigConecta struct with server configurations and keys
var ConfigConecta Config
var globalMutex sync.RWMutex

// LerConfig reads and parses the configuration file into ConfigConecta
func LerConfig(ConfigFile string) error {
	globalMutex.Lock()
	defer globalMutex.Unlock()

	jsonFile, err := os.Open(ConfigFile)
	if err != nil {
		return err
	}
	defer jsonFile.Close()

	byteValue, err := ioutil.ReadAll(jsonFile)
	if err != nil {
		return err
	}

	err = json.Unmarshal(byteValue, &ConfigConecta)
	if err != nil {
		return err
	}

	return nil
}

// GetMySQLConnectionStrings returns a slice of MySQL connection strings
func GetMySQLConnectionStrings() ([]string, error) {
	globalMutex.RLock()
	defer globalMutex.RUnlock()

	if ConfigConecta.MySQLPool == nil {
		return nil, fmt.Errorf("configuration is not loaded")
	}

	var connectionStrings []string
	for _, mysql := range ConfigConecta.MySQLPool {
		connectionString := fmt.Sprintf("%s:%s@tcp(%s:%s)", mysql.User, mysql.Pass, mysql.Host, mysql.Port)
		connectionStrings = append(connectionStrings, connectionString)
	}

	return connectionStrings, nil
}

func main() {
	// Example usage
	configFile := "config.json" // Replace with the path to your JSON config file
	err := LerConfig(configFile)
	if err != nil {
		fmt.Printf("Error reading config: %s\n", err)
		return
	}

	connectionStrings, err := GetMySQLConnectionStrings()
	if err != nil {
		fmt.Printf("Error retrieving connection strings: %s\n", err)
		return
	}

	for _, connectionString := range connectionStrings {
		fmt.Println(connectionString)
	}
}
