	lumberJackLogger := &lumberjack.Logger{
		Filename:   "./app.log",
		MaxSize:    10, // megabytes
		MaxBackups: 7,
		MaxAge:     30, // days
		Compress:   true,
	}
	return zapcore.AddSync(lumberJackLogger)
}

func LogSampleMessages() {
