// Capability represents an OpenGL capability requirement.
type Capability struct {
    Name     string
    Check    func(Extensions) bool
}

// CheckCapabilities checks if the current OpenGL context supports the required capabilities.
func CheckCapabilities(b *Binding, requiredCaps []Capability) Errors {
    supportedExts := b.QueryExtensions()
    var errors Errors

    for _, cap := range requiredCaps {
        if !cap.Check(supportedExts) {
            errors.append(Error{
                Field:       "Capability",
                Tag:         cap.Name,
                Requirement: "supported",
                Message:     fmt.Sprintf("OpenGL capability '%s' is not supported", cap.Name),
            })
        }
    }

    return errors
}

