import (
	"errors"
	"fmt"
	"image/color"
	"strconv"
)

// ErrInvalidFormat is a custom error type for invalid color format.
var ErrInvalidFormat = errors.New("invalid color format")

// Parse converts a hexadecimal color string to a color.Color object.
func Parse(hex string) (color.Color, error) {
	if hex == "" || hex[0] != '#' {
		return nil, ErrInvalidFormat
	}

	hex = hex[1:]
	length := len(hex)

	if length != 3 && length != 4 && length != 6 && length != 8 {
		return nil, ErrInvalidFormat
	}

	if length == 3 || length == 4 {
		// Double each character for shorthand notation
		b := make([]byte, length*2)
		for i := 0; i < length; i++ {
			b[i*2], b[i*2+1] = hex[i], hex[i]
		}
		hex = string(b)
	}

	// If alpha channel is not provided, assume it's FF
	if len(hex) == 6 {
		hex += "ff"
	}

	r, err := strconv.ParseUint(hex[0:2], 16, 8)
	if err != nil {
		return nil, ErrInvalidFormat
	}
	g, err := strconv.ParseUint(hex[2:4], 16, 8)
	if err != nil {
		return nil, ErrInvalidFormat
	}
	b, err := strconv.ParseUint(hex[4:6], 16, 8)
	if err != nil {
		return nil, ErrInvalidFormat
	}
	a, err := strconv.ParseUint(hex[6:8], 16, 8)
	if err != nil {
		return nil, ErrInvalidFormat
	}

	return color.RGBA{uint8(r), uint8(g), uint8(b), uint8(a)}, nil
}

func main() {
	// Test cases
	cases := []string{
		"#00000000",
		"#000000ff",
		"#fa0000d7",
		"#f0fffff0",
		"#f0f8ff",
		"#faebd7",
		"#00ffff",
		"#7fffd4",
		"#f0ffff",
		"#f5f5dc",
		"#ffe4c4",
		"#000000",
		"#abcd",
		"#abc",
		"abc",
		"#abx",
		"#abcdef123",
	}

	for _, hex := range cases {
		c, err := Parse(hex)
		if err != nil {
			fmt.Printf("Error parsing '%s': %s\n", hex, err)
		} else {
			fmt.Printf("Parsed '%s' to color: %+v\n", hex, c)
		}
	}
}
