	"errors"
	"github.com/gin-gonic/contrib/sessions"
)

type CartItem struct {
	ID       string  `json:"id"`
	Name     string  `json:"name"`
	Quantity int     `json:"quantity"`
	Price    float64 `json:"price"`
}

type GinGonicSession struct {
	Session sessions.Session
}

func (gcs GinGonicSession) Restore() (map[string]*CartItem, error) {
	var list map[string]*CartItem
	session := gcs.Session
	data := session.Get("__meta_gin_cart")

	if data == nil {
		list = make(map[string]*CartItem)
		return list, nil
	} else {
		encoded := data.(string)
		if err := json.Unmarshal([]byte(encoded), &list); err != nil {
			return list, err
		}
		return list, nil
	}
}

func (gcs GinGonicSession) Save(data map[string]*CartItem) error {
	encoded, err := json.Marshal(data)
	if err != nil {
		return err
	}
	session := gcs.Session
	session.Set("__meta_gin_cart", string(encoded))
	session.Save()
	return nil
}

func (gcs GinGonicSession) AddItem(item *CartItem) error {
	cart, err := gcs.Restore()
	if err != nil {
		return err
	}
	if _, exists := cart[item.ID]; exists {
		return errors.New("item already exists in the cart")
	}
	cart[item.ID] = item
	return gcs.Save(cart)
}

func (gcs GinGonicSession) RemoveItem(itemID string) error {
	cart, err := gcs.Restore()
	if err != nil {
		return err
	}
	if _, exists := cart[itemID]; !exists {
		return errors.New("item does not exist in the cart")
	}
	delete(cart, itemID)
	return gcs.Save(cart)
}

func (gcs GinGonicSession) UpdateItemQuantity(itemID string, quantity int) error {
	cart, err := gcs.Restore()
	if err != nil {
		return err
	}
	if item, exists := cart[itemID]; exists {
		item.Quantity = quantity
		return gcs.Save(cart)
	}
	return errors.New("item does not exist in the cart")
}

func (gcs GinGonicSession) CalculateTotal() (float64, error) {
	cart, err := gcs.Restore()
	if err != nil {
		return 0, err
	}
	var total float64
	for _, item := range cart {
		total += float64(item.Quantity) * item.Price
	}
	return total, nil
}

// Test cases to verify the solution correctness
func main() {
	// Mock session store and session
	store := sessions.NewCookieStore([]byte("secret"))
	session := sessions.Session{Options: &sessions.Options{MaxAge: 0}, Store: store, Name: "session"}

	// Create a GinGonicSession instance
	gcs := GinGonicSession{Session: session}

	// Add items to the cart
	gcs.AddItem(&CartItem{ID: "1", Name: "Apple", Quantity: 2, Price: 0.99})
	gcs.AddItem(&CartItem{ID: "2", Name: "Banana", Quantity: 3, Price: 0.59})

	// Update item quantity
	gcs.UpdateItemQuantity("1", 5)

	// Remove an item from the cart
