// gorm.Model definition
type Model struct {
	ID        uint `gorm:"primaryKey" json:"id"`
	CreatedAt time.Time
	UpdatedAt time.Time
	DeletedAt gorm.DeletedAt `gorm:"index"`
}

type Item struct {
	Model
	Title        string `json:"title"` // product Name
	Price        int    `json:"price"`
	Stock        int    `json:"stock"` // quantity
	ReorderLevel int    `json:"reorder_level"`
	Description  string `json:"description"`
	CoverSrc     string `json:"coverSrc"`
	Rating       []Rating
}

type Rating struct {
	Score int `json:"score"`
}

type Purchase struct {
	ItemID uint `json:"item_id"`
	Amount int  `json:"amount"`
}

// In-memory storage for items
var inventory = make(map[uint]*Item)

// AddItem adds a new item to the inventory.
func AddItem(item *Item) error {
	if item == nil {
		return errors.New("item cannot be nil")
	}
	if _, exists := inventory[item.ID]; exists {
		return errors.New("item already exists")
	}
	inventory[item.ID] = item
	return nil
}

// PurchaseItem updates the stock level of the purchased item.
func PurchaseItem(purchase *Purchase) error {
	if item, exists := inventory[purchase.ItemID]; exists {
		if item.Stock < purchase.Amount {
			return errors.New("not enough stock available")
		}
		item.Stock -= purchase.Amount
		return nil
	}
	return errors.New("item not found")
}

// NeedsReorder checks if the item needs to be reordered.
func NeedsReorder(itemID uint) (bool, error) {
	if item, exists := inventory[itemID]; exists {
		return item.Stock <= item.ReorderLevel, nil
	}
	return false, errors.New("item not found")
}

// GetItemDetails retrieves the details of an item.
func GetItemDetails(itemID uint) (*Item, error) {
	if item, exists := inventory[itemID]; exists {
		return item, nil
	}
	return nil, errors.New("item not found")
}

// ListReorderItems lists all items that need to be reordered.
func ListReorderItems() ([]Item, error) {
	var itemsToReorder []Item
	for _, item := range inventory {
		if item.Stock <= item.ReorderLevel {
			itemsToReorder = append(itemsToReorder, *item)
		}
	}
	return itemsToReorder, nil
}

func main() {
	// Test cases
	item1 := &Item{
		Model:        Model{ID: 1},
		Title:        "Laptop",
		Price:        1000,
		Stock:        5,
		ReorderLevel: 2,
		Description:  "High-performance laptop",
		CoverSrc:     "http://example.com/laptop.jpg",
	}

	item2 := &Item{
		Model:        Model{ID: 2},
		Title:        "Smartphone",
		Price:        500,
		Stock:        10,
		ReorderLevel: 5,
		Description:  "Latest model smartphone",
		CoverSrc:     "http://example.com/smartphone.jpg",
	}

	// Add items to inventory
	err := AddItem(item1)
	if err != nil {
		fmt.Println("Error adding item:", err)
	}
	err = AddItem(item2)
	if err != nil {
		fmt.Println("Error adding item:", err)
	}

	// Make a purchase
	purchase := &Purchase{
		ItemID: 1,
		Amount: 3,
	}
	err = PurchaseItem(purchase)
	if err != nil {
		fmt.Println("Error purchasing item:", err)
	}

	// Check reorder status
	reorder, err := NeedsReorder(1)
	if err != nil {
		fmt.Println("Error checking reorder status:", err)
	} else {
		fmt.Printf("Item 1 needs reorder: %v\n", reorder)
	}

	// Get item details
	details, err := GetItemDetails(1)
	if err != nil {
