package main

import (
	"fmt"
	"sync"
)

// Task represents a unit of work with some data.
type Task struct {
	Data interface{}
}

// TaskManager safely manages tasks.
type TaskManager struct {
	mu   sync.RWMutex
	data map[string]*Task
}

// NewTaskManager creates a new TaskManager.
func NewTaskManager() *TaskManager {
	return &TaskManager{
		data: make(map[string]*Task),
	}
}

// New adds a new task with the specified key.
func (tm *TaskManager) New(k string, task *Task) {
	tm.mu.Lock()
	defer tm.mu.Unlock()
	tm.data[k] = task
}

// Del deletes the task associated with the specified key.
func (tm *TaskManager) Del(k string) {
	tm.mu.Lock()
	defer tm.mu.Unlock()
	delete(tm.data, k)
}

// CopyGet retrieves a copy of the task associated with the specified key.
func (tm *TaskManager) CopyGet(k string) *Task {
	tm.mu.RLock()
	defer tm.mu.RUnlock()
	if task, ok := tm.data[k]; ok {
		copiedTask := *task
		return &copiedTask
	}
	return nil
}

// Get retrieves a pointer to the task associated with the specified key.
func (tm *TaskManager) Get(k string) *Task {
	tm.mu.RLock()
	defer tm.mu.RUnlock()
	return tm.data[k]
}

// List retrieves a map of all tasks.
func (tm *TaskManager) List() map[string]*Task {
	tm.mu.RLock()
	defer tm.mu.RUnlock()
	copy := make(map[string]*Task)
	for k, v := range tm.data {
		copy[k] = v
	}
	return copy
}

// Len returns the number of tasks currently managed.
func (tm *TaskManager) Len() int {
	tm.mu.RLock()
	defer tm.mu.RUnlock()
	return len(tm.data)
}

// Exists checks if a task with the specified key exists.
func (tm *TaskManager) Exists(k string) bool {
	tm.mu.RLock()
	defer tm.mu.RUnlock()
	_, ok := tm.data[k]
	return ok
}

func main() {
	// Create a new TaskManager.
	manager := NewTaskManager()

	// Add some tasks.
	manager.New("task1", &Task{Data: "This is task 1"})
	manager.New("task2", &Task{Data: "This is task 2"})

