package main

import (
	"fmt"
	"testing"
)

type TreeNode struct {
	Val   int
	Left  *TreeNode
	Right *TreeNode
}

func InorderTraversal(root *TreeNode) []int {
	var result []int
	var inorder func(node *TreeNode)
	inorder = func(node *TreeNode) {
		if node == nil {
			return
		}
		inorder(node.Left)
		result = append(result, node.Val)
		inorder(node.Right)
	}
	inorder(root)
	return result
}

func ConstructTree(values []*int) *TreeNode {
	if len(values) == 0 {
		return nil
	}
	var nodes []*TreeNode
	for _, val := range values {
		if val != nil {
			nodes = append(nodes, &TreeNode{Val: *val})
		} else {
			nodes = append(nodes, nil)
		}
	}
	for i, j := 0, 1; j < len(nodes); i++ {
		if nodes[i] != nil {
			if j < len(nodes) {
				nodes[i].Left = nodes[j]
				j++
			}
			if j < len(nodes) {
				nodes[i].Right = nodes[j]
				j++
			}
		}
	}
	return nodes[0]
}

// Helper function to create a pointer to an integer
func Int(val int) *int {
	return &val
}

// Test cases
func TestInorderTraversal(t *testing.T) {
	tests := []struct {
		values []*int
		want   []int
	}{
		{[]*int{Int(1), nil, Int(2), Int(3)}, []int{1, 3, 2}},
		{[]*int{Int(1), Int(2), Int(3), nil, nil, Int(4), Int(5)}, []int{2, 1, 4, 3, 5}},
		{[]*int{}, []int{}},
	}

	for _, test := range tests {
		tree := ConstructTree(test.values)
		got := InorderTraversal(tree)
		if !slicesEqual(got, test.want) {
			t.Errorf("InorderTraversal(%v) = %v, want %v", test.values, got, test.want)
		}
	}
}

// Helper function to compare two slices
func slicesEqual(a, b []int) bool {
	if len(a) != len(b) {
		return false
	}
	for i := range a {
		if a[i] != b[i] {
			return false
		}
	}
	return true
}

func main() {
	// Example usage:
	values := []*int{Int(1), Int(2), Int(3), nil, nil, Int(4), Int(5)}
	tree := ConstructTree(values)
	result := InorderTraversal(tree)
	fmt.Println("Inorder Traversal:", result)
}
