package release

import (
	"fmt"
	sysio "io"
	"text/template"

	"github.com/UiP9AV6Y/changelog-assembler/pkg/io"
)

const (
	DefaultOutputFile      = "CHANGELOG.md"
	StartDelimiterTemplate = `<a name="%s"></a>`
	EndDelimiterTemplate   = `<!-- changelog-assembler: %s -->`
	DefaultTemplate        = `## Version {{.Version}}\n{{range .Entries}}- {{.}}\n{{end}}`
	GroupedTemplate        = `## Version {{.Version}}\n{{range .Groups}}### {{.Component}}\n{{range .Entries}}- {{.}}\n{{end}}{{end}}`
)

type RenderContext struct {
	Version string
	Entries []string
	Groups  []Group
}

type Group struct {
	Component string
	Entries   []string
}

type Renderer struct {
	OutputFile             string
	TemplateFile           string
	GroupComponents        bool
	StartDelimiterTemplate string
	EndDelimiterTemplate   string

	writers io.IOFactory
}

// NewRenderer creates a new Renderer with default settings.
func NewRenderer(writers io.IOFactory) *Renderer {
	renderer := &Renderer{
		StartDelimiterTemplate: StartDelimiterTemplate,
		EndDelimiterTemplate:   EndDelimiterTemplate,
		OutputFile:             DefaultOutputFile,
		writers:                writers,
	}

	return renderer
}

// Write writes the changelog data to the output file.
func (r *Renderer) Write(data *RenderContext) (err error) {
	var tpl *template.Template
	var writer sysio.WriteCloser

	if writer, err = r.writers.Writer(io.ProtoPrepend + r.OutputFile); err != nil {
		return
	}

	defer func() {
		if cErr := writer.Close(); err == nil {
			err = cErr
		}
	}()

	if tpl, err = r.newTemplate(); err != nil {
		return
	}

	err = r.writeData(data, tpl, writer)
	return
}

// newTemplate creates a new template based on the Renderer settings.
func (r *Renderer) newTemplate() (*template.Template, error) {
	tpl := template.New("changelog_entry")

	if len(r.TemplateFile) > 0 {
		return tpl.ParseFiles(r.TemplateFile)
	} else if r.GroupComponents {
		return tpl.Parse(GroupedTemplate)
	}

	return tpl.Parse(DefaultTemplate)
}

// writeData writes the changelog data to the writer using the provided template.
func (r *Renderer) writeData(data *RenderContext, tpl *template.Template, writer sysio.WriteCloser) (err error) {
	startDelimiter := []byte(fmt.Sprintf(r.StartDelimiterTemplate, data.Version))
	endDelimiter := []byte(fmt.Sprintf(r.EndDelimiterTemplate, data.Version))

	if _, err := io.WriteLine(writer, startDelimiter); err != nil {
		return err
	}

	if err := tpl.Execute(writer, data); err != nil {
		return err
	}

	if _, err := io.WriteLine(writer, endDelimiter); err != nil {
		return err
	}

	return nil
}

// Test cases to verify the solution correctness.
func main() {
	// Mock IOFactory that writes to stdout (or any other io.Writer)
	mockWriters := io.NewMockIOFactory()

	renderer := NewRenderer(mockWriters)

	// Example RenderContext with grouped components
	groupedContext := &RenderContext{
		Version: "1.0.0",
		Groups: []Group{
			{
				Component: "API",
				Entries:   []string{"Added new endpoint for retrieving posts."},
			},
			{
				Component: "UI",
				Entries:   []string{"Improved responsiveness on mobile devices."},
			},
		},
	}

	// Example RenderContext without grouped components
	plainContext := &RenderContext{
		Version: "1.0.1",
		Entries: []string{
			"Fixed bug causing crash on startup.",
			"Updated documentation with new API examples.",
		},
	}

	// Set GroupComponents to true to use the grouped template
	renderer.GroupComponents = true
	if err := renderer.Write(groupedContext); err != nil {
		fmt.Println("Error writing grouped changelog:", err)
	}

	// Set GroupComponents to false to use the default template
	renderer.GroupComponents = false
	if err := renderer.Write(plainContext); err != nil {
		fmt.Println("Error writing plain changelog:", err)
	}
}
