import (
	"sync"
)

// Defining the model for an Account
type Account struct {
	ID      int64
	Balance float64
	Name    string
}

// Defining a slice of Account pointers as Accounts
type Accounts []*Account

// Mock implementation of AccountRepository
type MockAccountRepository struct {
	accounts map[int64]*Account
	mu       sync.RWMutex
}

// Create a new account and return its ID
func (r *MockAccountRepository) Create(account *Account) (int64, error) {
	r.mu.Lock()
	defer r.mu.Unlock()
	account.ID = int64(len(r.accounts) + 1)
	r.accounts[account.ID] = account
	return account.ID, nil
}

// Find an account by ID
func (r *MockAccountRepository) FindByID(accountID int64) (*Account, error) {
	r.mu.RLock()
	defer r.mu.RUnlock()
	if account, exists := r.accounts[accountID]; exists {
		return account, nil
	}
	return nil, errors.New("account not found")
}

// Find all accounts
func (r *MockAccountRepository) FindAll() (Accounts, error) {
	r.mu.RLock()
	defer r.mu.RUnlock()
	allAccounts := make(Accounts, 0, len(r.accounts))
	for _, account := range r.accounts {
		allAccounts = append(allAccounts, account)
	}
	return allAccounts, nil
}

// Update an account
func (r *MockAccountRepository) Update(account *Account) error {
	r.mu.Lock()
	defer r.mu.Unlock()
	if _, exists := r.accounts[account.ID]; exists {
		r.accounts[account.ID] = account
		return nil
	}
	return errors.New("account not found")
}

// Transfer funds between two accounts
func TransferFunds(repo AccountRepository, fromID, toID int64, amount float64) error {
	fromAccount, err := repo.FindByID(fromID)
	if err != nil {
		return err
	}
	toAccount, err := repo.FindByID(toID)
	if err != nil {
		return err
	}

	if fromAccount.Balance < amount {
		return errors.New("insufficient funds")
	}

	fromAccount.Balance -= amount
	toAccount.Balance += amount

	if err := repo.Update(fromAccount); err != nil {
		return err
	}
	if err := repo.Update(toAccount); err != nil {
		return err
	}

	return nil
}

// Test cases to verify the solution correctness
func main() {
	repo := &MockAccountRepository{
		accounts: make(map[int64]*Account),
	}

	// Create accounts
	_, _ = repo.Create(&Account{Balance: 1000, Name: "Alice"})
	_, _ = repo.Create(&Account{Balance: 500, Name: "Bob"})

	// Transfer funds
	err := TransferFunds(repo, 1, 2, 300)
	if err != nil {
		fmt.Println("Transfer failed:", err)
	} else {
		fmt.Println("Transfer succeeded")
	}

	// Print account balances after transfer
	accounts, _ := repo.FindAll()
	for _, account := range accounts {
		fmt.Printf("Account ID: %d, Name: %s, Balance: %.2f\n", account.ID, account.Name, account.Balance)
	}
}
