	// if err != nil {
	// 	return nil, err
	// }

	return database, nil
}

type stop struct {
	error
}

func retry(attempts int, sleep time.Duration, fn func() error) error {
	for i := 0; i < attempts; i++ {
		if err := fn(); err != nil {
			if s, ok := err.(stop); ok {
				return s.error
			}
			time.Sleep(sleep)
			sleep = sleep * 2 // Exponential backoff
		} else {
			return nil
		}
	}
	return fmt.Errorf("after %d attempts, last error: %s", attempts, fn())
}

