package main

import (
	"bufio"
	"fmt"
	"os"
	"strconv"
)

func main() {
	defer flush()

	N := readInt() // Number of stations
	M := readInt() // Number of recorded trips
	Q := readInt() // Number of queries

	// Initialize a 2D slice to store the cumulative sum of trips
	t := make([][]int, N+1)
	for i := range t {
		t[i] = make([]int, N+1)
	}

	// Read the trips and increment the count for each trip from L to R
	for i := 0; i < M; i++ {
		L := readInt()
		R := readInt()
		t[L][R]++
	}

	// Calculate the cumulative sum horizontally
	for i := 1; i <= N; i++ {
		for j := 1; j <= N; j++ {
			t[i][j] += t[i][j-1]
		}
	}

	// Calculate the cumulative sum vertically
	for j := 1; j <= N; j++ {
		for i := 1; i <= N; i++ {
			t[i][j] += t[i-1][j]
		}
	}

	// Process the queries
	for i := 0; i < Q; i++ {
		p := readInt()
		q := readInt()
		// Calculate the total number of trips for the query using the cumulative sum
		result := t[q][q] - t[p-1][q] - t[q][p-1] + t[p-1][p-1]
		println(result)
	}
}

const (
	ioBufferSize = 1 * 1024 * 1024 // 1 MB
)

var stdinScanner = func() *bufio.Scanner {
	result := bufio.NewScanner(os.Stdin)
