// Mock database for user credentials.
var mockUsers = map[string]string{
	"admin": "password123",
}

// Token storage to keep track of logged-in users.
var activeTokens = make(map[string]struct{})

type Base struct{}

type LoginRequest struct {
	Username string `json:"username"`
	Password string `json:"password"`
}

type LoginResponse struct {
	Token string `json:"token"`
}

type CaptchaResponse struct {
	Captcha string `json:"captcha"`
}

// AdminLogin handles the login request.
func (b *Base) AdminLogin(c *app.RequestContext) {
	var loginReq LoginRequest
	if err := c.BindAndValidate(&loginReq); err != nil {
		c.JSON(http.StatusBadRequest, err.Error())
		return
	}

	expectedPassword, ok := mockUsers[loginReq.Username]
	if !ok || expectedPassword != loginReq.Password {
		c.JSON(http.StatusUnauthorized, "Invalid credentials")
		return
	}

	// Generate a token for the user.
	token := generateToken()
	activeTokens[token] = struct{}{}

	c.JSON(http.StatusOK, LoginResponse{Token: token})
}

// Captcha generates a simple captcha.
func (b *Base) Captcha(c *app.RequestContext) {
	captcha := generateCaptcha()
	c.JSON(http.StatusOK, CaptchaResponse{Captcha: captcha})
}

// Logout invalidates the user's token.
func (b *Base) Logout(c *app.RequestContext) {
	token := c.Request.Header.Get("Authorization")
	if token == "" || !validateToken(token) {
		c.JSON(http.StatusUnauthorized, "Invalid or missing token")
		return
	}

	delete(activeTokens, token)
	c.JSON(http.StatusOK, "Logged out successfully")
}

func generateToken() string {
	return randomString(30)
}

func generateCaptcha() string {
	return randomString(6)
}

func validateToken(token string) bool {
	_, exists := activeTokens[token]
	return exists
}

func randomString(n int) string {
	const letters = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
	rand.Seed(time.Now().UnixNano())
	s := make([]byte, n)
	for i := range s {
		s[i] = letters[rand.Intn(len(letters))]
	}
	return string(s)
}

func main() {
	h := server.Default(server.WithHostPorts(":8080"))
	r := h.Group("/admin/v1")

	baseApi := new(Base)
	r.POST("/login", baseApi.AdminLogin)
	r.POST("/captcha", baseApi.Captcha)
	r.DELETE("/logout", baseApi.Logout)

	h.Spin()
}

