	"net/http"
	"net/http/httptest"
	"testing"
)

// EnableCorsMiddleware is a middleware that sets the CORS header on the response.
func EnableCorsMiddleware(h http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Access-Control-Allow-Origin", "*")
		h.ServeHTTP(w, r)
	})
}

// helloHandler is a simple HTTP handler that responds with "Hello, World!".
func helloHandler(w http.ResponseWriter, r *http.Request) {
	fmt.Fprint(w, "Hello, World!")
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("/", helloHandler)

	// Wrap the mux with the CORS middleware
	wrappedMux := EnableCorsMiddleware(mux)

	http.ListenAndServe(":8080", wrappedMux)
}

// TestEnableCorsMiddleware tests that the CORS middleware sets the correct header.
func TestEnableCorsMiddleware(t *testing.T) {
	mux := http.NewServeMux()
	mux.HandleFunc("/", helloHandler)

	wrappedMux := EnableCorsMiddleware(mux)

	// Create an HTTP request to pass to our handler.
	req, err := http.NewRequest("GET", "/", nil)
	if err != nil {
		t.Fatal(err)
	}

	// Record the HTTP response using httptest.
	rr := httptest.NewRecorder()
	handler := http.Handler(wrappedMux)

	// Dispatch the HTTP request to the handler.
	handler.ServeHTTP(rr, req)

	// Check the status code is what we expect.
	if status := rr.Code; status != http.StatusOK {
		t.Errorf("handler returned wrong status code: got %v want %v", status, http.StatusOK)
	}

	// Check the response body is what we expect.
	expected := "Hello, World!"
	if rr.Body.String() != expected {
		t.Errorf("handler returned unexpected body: got %v want %v", rr.Body.String(), expected)
	}

	// Check the CORS header is set correctly.
	if cors := rr.Header().Get("Access-Control-Allow-Origin"); cors != "*" {
		t.Errorf("handler did not set CORS header correctly: got %v want %v", cors, "*")
	}
}
