func NewModulesRolesManager() *ModulesRolesManager {
	return &ModulesRolesManager{
		modules: make(map[string]ModulesRoles),
	}
}

// ListModulesRoles lists all modules with their roles
func (m *ModulesRolesManager) ListModulesRoles() ModulesRolesListResponse {
	var list []ModulesRoles
	for _, module := range m.modules {
		list = append(list, module)
	}
	return ModulesRolesListResponse{Data: list}
}

// GetModuleRoles retrieves a specific module's roles by its key
func (m *ModulesRolesManager) GetModuleRoles(key Key) (ModulesRolesResponse, error) {
	module, exists := m.modules[key.ID]
	if !exists {
		return ModulesRolesResponse{}, errors.New("module not found")
	}
	return ModulesRolesResponse{Data: module}, nil
}

// AddModule adds a new module with roles to the system
func (m *ModulesRolesManager) AddModule(module ModulesRoles) {
	m.modules[module.Key.ID] = module
}

// UpdateModuleRoles updates the roles of an existing module
func (m *ModulesRolesManager) UpdateModuleRoles(key Key, roles []string) error {
	module, exists := m.modules[key.ID]
	if !exists {
		return errors.New("module not found")
	}
	module.Attributes.Roles = roles
	m.modules[key.ID] = module
	return nil
}

// DeleteModule deletes a module from the system
func (m *ModulesRolesManager) DeleteModule(key Key) error {
	_, exists := m.modules[key.ID]
	if !exists {
		return errors.New("module not found")
	}
	delete(m.modules, key.ID)
	return nil
}

