)

const TRUE = 1

type ASTree interface {
	Child(i int) ASTree
	NumChildren() int
	String() string
	Eval(env Environment, args... interface{}) interface{}
}

type Environment interface {
	SetVariable(name string, value interface{})
	GetVariable(name string) interface{}
}

type SimpleEnvironment struct {
	variables map[string]interface{}
}

func NewSimpleEnvironment() *SimpleEnvironment {
	return &SimpleEnvironment{variables: make(map[string]interface{})}
}

func (env *SimpleEnvironment) SetVariable(name string, value interface{}) {
	env.variables[name] = value
}

func (env *SimpleEnvironment) GetVariable(name string) interface{} {
	return env.variables[name]
}

type astList struct {
	children []ASTree
}

func (a *astList) Child(i int) ASTree {
	return a.children[i]
}

func (a *astList) NumChildren() int {
	return len(a.children)
}

type IfStmnt struct {
	astList
}

func NewIfStmnt(list []ASTree) *IfStmnt {
	return &IfStmnt{astList{list}}
}

func (self *IfStmnt) Condition() ASTree {
	return self.Child(0)
}

func (self *IfStmnt) ThenBlock() ASTree {
	return self.Child(1)
}

func (self *IfStmnt) ElseBlock() ASTree {
	if self.NumChildren() > 2 {
		return self.Child(2)
	} else {
		return nil
	}
}

func (self *IfStmnt) String() string {
	result := "(if " + self.Condition().String() + " " + self.ThenBlock().String()
	if self.ElseBlock() != nil {
		result += " else " + self.ElseBlock().String()
	}
	return result + ")"
}

func (self *IfStmnt) Eval(env Environment, args... interface{}) interface{} {
	c := self.Condition().Eval(env)
	if reflect.TypeOf(c).Kind() == reflect.Int && c.(int) == TRUE {
		return self.ThenBlock().Eval(env)
	} else {
		e := self.ElseBlock()
		if e == nil {
			return 0
		} else {
			return e.Eval(env)
		}
	}
}

// Example ASTree nodes for testing
type Literal struct {
	value int
}

func (l *Literal) Child(i int) ASTree {
	return nil
}

func (l *Literal) NumChildren() int {
	return 0
}

func (l *Literal) String() string {
	return fmt.Sprintf("%d", l.value)
}

func (l *Literal) Eval(env Environment, args... interface{}) interface{} {
	return l.value
}

type Variable struct {
	name string
}

func (v *Variable) Child(i int) ASTree {
	return nil
}

func (v *Variable) NumChildren() int {
	return 0
}

func (v *Variable) String() string {
	return v.name
}

func (v *Variable) Eval(env Environment, args... interface{}) interface{} {
	return env.GetVariable(v.name)
}

func main() {
	// Test cases
	env := NewSimpleEnvironment()
	env.SetVariable("x", 10)

	condition := &Variable{name: "x"}
	thenBlock := &Literal{value: 1}
	elseBlock := &Literal{value: 0}

	ifStmnt := NewIfStmnt([]ASTree{condition, thenBlock, elseBlock})

	fmt.Println("If Statement:", ifStmnt.String())
	fmt.Println("Evaluation Result:", ifStmnt.Eval(env))
}
