package main

import (
	"context"
	"errors"
	"fmt"
	"sync"
	"time"

	"go.mongodb.org/mongo-driver/mongo"
	"go.mongodb.org/mongo-driver/mongo/options"
	"go.mongodb.org/mongo-driver/mongo/readpref"
)

type DBConfig struct {
	Uri            string
	ConnectTimeout time.Duration
	DBName         string
	PoolSize       uint64
}

type MongoConnection struct {
	mu         sync.Mutex
	pool       chan *mongo.Database
	poolLength int
	Errors     chan error
	config     *DBConfig
}

func NewMongoConnection(dbConfig DBConfig) *MongoConnection {
	return &MongoConnection{
		pool:       make(chan *mongo.Database, dbConfig.PoolSize),
		poolLength: 0,
		Errors:     make(chan error),
		config:     &dbConfig,
	}
}

func (conn *MongoConnection) GetMongoDB() (*mongo.Database, error) {
	conn.mu.Lock()
	defer conn.mu.Unlock()

	if len(conn.pool) == 0 && uint64(conn.poolLength) < conn.config.PoolSize {
		db, err := conn.NewMongoDB()
		if err == nil {
			conn.poolLength++
		}
		return db, err
	}

	select {
	case db := <-conn.pool:
		if err := db.Client().Ping(context.TODO(), readpref.Primary()); err == nil {
			return db, nil
		}
	default:
		return conn.NewMongoDB()
	}
}

func (conn *MongoConnection) PutMongoDB(db *mongo.Database) error {
	if db == nil {
		return errors.New("nil database cannot be put back into the pool")
	}
	if err := db.Client().Ping(context.TODO(), readpref.Primary()); err != nil {
		return err
	}
	conn.pool <- db
	return nil
}

func (conn *MongoConnection) CloseMongoDB() error {
	close(conn.pool)
	for db := range conn.pool {
		if err := db.Client().Disconnect(context.Background()); err != nil {
			return err
		}
	}
	return nil
}

func (conn *MongoConnection) NewMongoDB() (*mongo.Database, error) {
	clientOptions := options.Client().ApplyURI(conn.config.Uri)
	clientOptions = clientOptions.SetConnectTimeout(conn.config.ConnectTimeout)
	clientOptions = clientOptions.SetMaxPoolSize(conn.config.PoolSize)

	client, err := mongo.Connect(context.Background(), clientOptions)
	if err != nil {
		return nil, err
	}

	if err := client.Ping(context.Background(), readpref.Primary()); err != nil {
		return nil, err
	}

	fmt.Println("Connected to MongoDB!")
	return client.Database(conn.config.DBName), nil
}

func (conn *MongoConnection) DBAsync(wg *sync.WaitGroup, f func(db *mongo.Database, errChan chan error) error) error {
	defer wg.Done()

	db, err := conn.GetMongoDB()
	if err != nil {
		conn.Errors <- err
		return err
	}
	if db == nil {
		err = errors.New("cannot get db")
		conn.Errors <- err
		return err
	}

	defer conn.PutMongoDB(db)

	err = f(db, conn.Errors)
	if err != nil {
		conn.Errors <- err
	}
	return err
}

// Example usage
func main() {
	config := DBConfig{
		Uri:            "mongodb://localhost:27017",
		ConnectTimeout: 10 * time.Second,
		DBName:         "exampleDB",
		PoolSize:       5,
	}

	conn := NewMongoConnection(config)
	defer conn.CloseMongoDB()

	var wg sync.WaitGroup
	wg.Add(1)

	go conn.DBAsync(&wg, func(db *mongo.Database, errChan chan error) error {
		// Perform database operations here
		fmt.Println("Performing async DB operation")
		return nil
	})

	wg.Wait()

	select {
	case err := <-conn.Errors:
		fmt.Println("Error occurred:", err)
	default:
		fmt.Println("No errors reported.")
	}
}
