	ID          int
	Description string
	Done        bool
}

var tasks []Task
var nextID int = 1

func main() {
	rootCmd := &cobra.Command{Use: "taskmanager"}
	rootCmd.AddCommand(createCmd())
	rootCmd.AddCommand(listCmd())
	rootCmd.AddCommand(doneCmd())

	if err := rootCmd.Execute(); err != nil {
		fmt.Println(err)
		os.Exit(1)
	}
}

func createCmd() *cobra.Command {
	return &cobra.Command{
		Use:   "create [description]",
		Short: "Create a new task",
		Args:  cobra.MinimumNArgs(1),
		Run: func(cmd *cobra.Command, args []string) {
			description := args[0]
			task := Task{ID: nextID, Description: description, Done: false}
			tasks = append(tasks, task)
			fmt.Printf("Created task #%d\n", task.ID)
			nextID++
		},
	}
}

func listCmd() *cobra.Command {
	return &cobra.Command{
		Use:   "list",
		Short: "List all tasks",
		Run: func(cmd *cobra.Command, args []string) {
			for _, task := range tasks {
				status := "not done"
				if task.Done {
					status = "done"
				}
				fmt.Printf("%d: %s [%s]\n", task.ID, task.Description, status)
			}
		},
	}
}

func doneCmd() *cobra.Command {
	return &cobra.Command{
		Use:   "done [id]",
		Short: "Mark a task as done",
		Args:  cobra.ExactArgs(1),
		Run: func(cmd *cobra.Command, args []string) {
			id, err := strconv.Atoi(args[0])
			if err != nil {
				fmt.Println("Please provide a valid task ID.")
				return
			}
			for i, task := range tasks {
				if task.ID == id {
					tasks[i].Done = true
					fmt.Printf("Task #%d marked as done.\n", id)
					return
				}
			}
			fmt.Printf("Task #%d not found.\n", id)
		},
	}
}
