// InsertEmployeeRepo inserts a new employee record into the database.
func InsertEmployeeRepo(coll *mongo.Collection, ctx context.Context, req models.EmployeeModel) (*primitive.ObjectID, error) {
	mod := mongo.IndexModel{
		Keys: bson.M{
			"empId": 1,
		},
		Options: options.Index().SetUnique(true),
	}

	_, indxErr := coll.Indexes().CreateOne(ctx, mod)
	if indxErr != nil {
		return nil, indxErr
	}

	curDate := primitive.NewDateTimeFromTime(time.Now())
	req.CreatedDate = &curDate
	req.UpdatedDate = &curDate
	result, insertErr := coll.InsertOne(ctx, req)
	if insertErr != nil {
		return nil, insertErr
	}

	var id primitive.ObjectID
	if result != nil {
		id = result.InsertedID.(primitive.ObjectID)
	}

	return &id, nil
}

// UpdateEmployeeRepo updates an existing employee record.
func UpdateEmployeeRepo(coll *mongo.Collection, ctx context.Context, req models.EmployeeModel) (*int64, error) {
	param := bson.M{
		"empName":      req.EmpName,
		"empPosition":  req.EmpPosition,
		"empGender":    req.EmpGender,
		"empEmail":     req.EmpEmail,
		"empCompany":   req.EmpCompany,
		"empStatus":    req.EmpStatus,
		"updatedBy":    req.UpdatedBy,
		"updatedDate":  primitive.NewDateTimeFromTime(time.Now()),
	}
	updateResult, updateErr := coll.UpdateOne(ctx, bson.M{"_id": req.Id}, bson.M{"$set": param})
	if updateErr != nil {
		return nil, updateErr
	}

	var updateCount int64
	if updateResult != nil {
		updateCount = updateResult.ModifiedCount
	}
	return &updateCount, nil
}

// GetEmployeeRepo retrieves a single employee record by its ID or EmpId.
func GetEmployeeRepo(coll *mongo.Collection, ctx context.Context, req st.EmployeeReq) (*models.EmployeeModel, error) {
	param := bson.M{}
	if req.Id != nil {
		objId, _ := primitive.ObjectIDFromHex(*req.Id)
		param["_id"] = objId
	}
	if req.EmpId != nil {
		param["empId"] = *req.EmpId
	}
	if req.EmpStatus != nil {
		param["EmpStatus"] = *req.EmpStatus
	}

	var obj models.EmployeeModel
	if len(param) > 0 {
		resultErr := coll.FindOne(ctx, param).Decode(&obj)
		if resultErr != nil {
			return nil, resultErr
		}
	}

	return &obj, nil
}

// ListEmployeeRepo lists employee records with pagination and optional keyword search and filtering.
func ListEmployeeRepo(coll *mongo.Collection, ctx context.Context, param st.EmployeeReq) ([]models.EmployeeModel, *int64, *int64, error) {
	filter := bson.M{}
	if param.Keyword != nil && *param.Keyword != "" {
		var opts []bson.M
		opts = append(opts, bson.M{"empName": bson.M{"$regex": primitive.Regex{Pattern: *param.Keyword, Options: "i"}}})
		opts = append(opts, bson.M{"empPosition": bson.M{"$regex": primitive.Regex{Pattern: *param.Keyword, Options: "i"}}})
		opts = append(opts, bson.M{"empEmail": bson.M{"$regex": primitive.Regex{Pattern: *param.Keyword, Options: "i"}}})
		opts = append(opts, bson.M{"empCompany": bson.M{"$regex": primitive.Regex{Pattern: *param.Keyword, Options: "i"}}})
		filter["$or"] = opts
	}

	if param.EmpId != nil {
		filter["empId"] = *param.EmpId
	}

	if param.EmpStatus != nil {
		filter["empStatus"] = *param.EmpStatus
	}

	var limit int64 = 30
	var skip int64 = 0

	if param.PerPage != nil {
		limit = *param.PerPage
	}

	if param.Page != nil {
		skip = (*param.Page - 1) * limit
	}

	findOptions := options.Find()
	findOptions.SetSkip(skip)
	findOptions.SetLimit(limit)
	findOptions.SetSort(bson.M{"updatedDate": 1})

	totalResults, _ := coll.CountDocuments(ctx, filter)
	result, findErr := coll.Find(ctx, filter, findOptions)
	if findErr != nil {
		return nil, nil, nil, findErr
	}

	listData := []models.EmployeeModel{}
	if resultErr := result.All(ctx, &listData); resultErr != nil {
		return nil, nil, nil, resultErr
	}

	totalPages := int64(math.Ceil(float64(totalResults) / float64(limit)))

	return listData, &totalResults, &totalPages, nil
}

// DeleteEmployeeRepo deletes an employee record by its ID.
func DeleteEmployeeRepo(coll *mongo.Collection, ctx context.Context, id *string) (*int64, error) {
	objectId, objectErr := primitive.ObjectIDFromHex(*id)
	if objectErr != nil {
		return nil, objectErr
	}

	deleteResult, deleteErr := coll.DeleteOne(ctx, bson.M{"_id": objectId})
	if deleteErr != nil {
		return nil, deleteErr
	}

	var deleteCount int64
	if deleteResult != nil {
		deleteCount = deleteResult.DeletedCount
	}
	return &deleteCount, nil
}

