package main

import (
	"errors"
	"fmt"
)

type JobTrigger struct {
	ID          string
	DisplayName string
	Description string
	Status      string
}

type DLPJobTriggerManager struct {
	triggers map[string]*JobTrigger
}

func NewDLPJobTriggerManager() *DLPJobTriggerManager {
	return &DLPJobTriggerManager{
		triggers: make(map[string]*JobTrigger),
	}
}

func (m *DLPJobTriggerManager) CreateJobTrigger(id, displayName, description, status string) error {
	if displayName == "" || description == "" {
		return errors.New("display name and description must be non-empty")
	}
	if status != "ACTIVE" && status != "INACTIVE" {
		return errors.New("status must be either 'ACTIVE' or 'INACTIVE'")
	}
	if _, exists := m.triggers[id]; exists {
		return fmt.Errorf("job trigger with ID '%s' already exists", id)
	}
	m.triggers[id] = &JobTrigger{
		ID:          id,
		DisplayName: displayName,
		Description: description,
		Status:      status,
	}
	return nil
}

func (m *DLPJobTriggerManager) UpdateJobTrigger(id, displayName, description, status string) error {
	if displayName == "" || description == "" {
		return errors.New("display name and description must be non-empty")
	}
	if status != "ACTIVE" && status != "INACTIVE" {
		return errors.New("status must be either 'ACTIVE' or 'INACTIVE'")
	}
	trigger, exists := m.triggers[id]
	if !exists {
		return fmt.Errorf("job trigger with ID '%s' does not exist", id)
	}
	trigger.DisplayName = displayName
	trigger.Description = description
	trigger.Status = status
	return nil
}

func (m *DLPJobTriggerManager) GetJobTrigger(id string) (*JobTrigger, error) {
	trigger, exists := m.triggers[id]
	if !exists {
		return nil, fmt.Errorf("job trigger with ID '%s' does not exist", id)
	}
	return trigger, nil
}

func main() {
	manager := NewDLPJobTriggerManager()

	// Test case: Create a new job trigger
	err := manager.CreateJobTrigger("trigger1", "Data Scan", "Scans for sensitive data", "ACTIVE")
	if err != nil {
		fmt.Println("Error:", err)
	}

	// Test case: Retrieve the job trigger
	trigger, err := manager.GetJobTrigger("trigger1")
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Printf("Retrieved Job Trigger: %+v\n", trigger)
	}

	// Test case: Update the job trigger
	err = manager.UpdateJobTrigger("trigger1", "Updated Data Scan", "Updated description", "INACTIVE")
	if err != nil {
		fmt.Println("Error:", err)
	}

	// Test case: Retrieve the updated job trigger
	trigger, err = manager.GetJobTrigger("trigger1")
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Printf("Updated Job Trigger: %+v\n", trigger)
	}
}
