func CreateTaskContext(taskID string, retryCount int, maxRetry int, queueName string) context.Context {
	ctx := context.Background()
	ctx = asynqcontext.WithTaskID(ctx, taskID)
	ctx = asynqcontext.WithRetryCount(ctx, retryCount)
	ctx = asynqcontext.WithMaxRetry(ctx, maxRetry)
	ctx = asynqcontext.WithQueueName(ctx, queueName)
	return ctx
}

func ProcessTask(ctx context.Context, taskFunc func(ctx context.Context) error) error {
	if err := taskFunc(ctx); err != nil {
		HandleTaskFailure(ctx, err)
		return err
	}
	return nil
}

func HandleTaskFailure(ctx context.Context, err error) {
	retryCount, _ := asynqcontext.GetRetryCount(ctx)
	maxRetry, _ := asynqcontext.GetMaxRetry(ctx)
	taskID, _ := asynqcontext.GetTaskID(ctx)
	queueName, _ := asynqcontext.GetQueueName(ctx)

	if retryCount < maxRetry {
		fmt.Printf("Task %s from queue %s failed: %s. Retrying %d out of %d times.\n", taskID, queueName, err, retryCount+1, maxRetry)
		newCtx := CreateTaskContext(taskID, retryCount+1, maxRetry, queueName)
		ProcessTask(newCtx, sampleTask)
	} else {
		fmt.Printf("Task %s from queue %s failed: %s. Reached maximum retry count.\n", taskID, queueName, err)
	}
}

func sampleTask(ctx context.Context) error {
	// Simulate a task that has a 50% chance of failing
	if rand.Intn(2) == 0 {
		return errors.New("task failed due to random error")
	}
	fmt.Println("Task completed successfully")
	return nil
}

func main() {
	rand.Seed(time.Now().UnixNano())

	ctx := CreateTaskContext("task123", 0, 3, "default")
	err := ProcessTask(ctx, sampleTask)
	if err != nil {
		fmt.Println("Task processing completed with errors.")
	} else {
		fmt.Println("Task processing completed successfully.")
	}
}
