package main

import (
	"fmt"
	"math"
	"strconv"
	"strings"
)

type Position struct {
	X int
	Y int
}

func ParseInt(s string) int {
	i, err := strconv.Atoi(s)
	if err != nil {
		panic(err)
	}
	return i
}

func Diff(a, b int) int {
	return int(math.Abs(float64(a - b)))
}

func Parse(str string) Position {
	if str[0] == '(' {
		str = str[1:]
	}
	if str[len(str)-1] == ')' {
		str = str[:len(str)-1]
	}

	parts := strings.Split(str, ",")
	return Position{
		X: ParseInt(strings.TrimSpace(parts[0])),
		Y: ParseInt(strings.TrimSpace(parts[1])),
	}
}

func Add(left, right Position) Position {
	return Position{
		X: left.X + right.X,
		Y: left.Y + right.Y,
	}
}

func Sub(left, right Position) Position {
	return Position{
		X: left.X - right.X,
		Y: left.Y - right.Y,
	}
}

func ManhattanDist(left, right Position) int {
	return Diff(left.X, right.X) + Diff(left.Y, right.Y)
}

func DistCeil(left, right Position) int {
	pos := Sub(right, left)
	return int(math.Ceil(math.Sqrt(math.Pow(float64(pos.X), 2) + math.Pow(float64(pos.Y), 2))))
}

func main() {
	// Test cases
	pos1 := Parse("(3, 4)")
	pos2 := Parse(" ( -2 , 10 ) ")
	sum := Add(pos1, pos2)
	diff := Sub(pos1, pos2)
	manhattanDistance := ManhattanDist(pos1, pos2)
	distCeil := DistCeil(pos1, pos2)

	fmt.Printf("Position 1: %+v\n", pos1)
	fmt.Printf("Position 2: %+v\n", pos2)
	fmt.Printf("Sum: %+v\n", sum)
	fmt.Printf("Difference: %+v\n", diff)
	fmt.Printf("Manhattan Distance: %d\n", manhattanDistance)
	fmt.Printf("Ceiling of Euclidean Distance: %d\n", distCeil)
}
