	}
	if review.Rating < 1 || review.Rating > 5 {
		return errors.New("rating must be between 1 and 5")
	}
	rm.reviews[review.MovieID] = review
	return nil
}

func (rm *ReviewManager) GetReview(movieID int) (Review, error) {
	if review, exists := rm.reviews[movieID]; exists {
		return review, nil
	}
	return Review{}, errors.New("no review found for the movie")
}

