package main

import (
	"errors"
	"fmt"
	"strings"
)

func evaluateBooleanExpression(expression string) (bool, error) {
	// Remove all whitespace from the expression
	expression = strings.ReplaceAll(expression, " ", "")

	// Check for invalid characters
	for _, r := range expression {
		if !strings.Contains("truefalse&&||()", string(r)) {
			return false, errors.New("invalid character in expression")
		}
	}

	// Evaluate the expression
	var stack []string
	var current string

	for _, r := range expression {
		switch r {
		case 't', 'r', 'u', 'e', 'f', 'a', 'l', 's':
			current += string(r)
			if current == "true" || current == "false" {
				stack = append(stack, current)
				current = ""
			}
		case '&', '|':
			if len(current) > 0 {
				return false, errors.New("invalid expression")
			}
			current += string(r)
		case '(':
			if len(current) > 0 {
				return false, errors.New("invalid expression")
			}
			stack = append(stack, string(r))
		case ')':
			if len(current) > 0 {
				return false, errors.New("invalid expression")
			}
			if len(stack) == 0 || stack[len(stack)-1] != "(" {
				return false, errors.New("mismatched parentheses")
			}
			stack = stack[:len(stack)-1] // Pop the '('
		default:
			return false, errors.New("invalid character in expression")
		}
	}

	// Simplify the stack
	for len(stack) > 1 {
		var a, b string
		a, stack = stack[len(stack)-1], stack[:len(stack)-1]
		op, stack := stack[len(stack)-1], stack[:len(stack)-1]
		b, stack = stack[len(stack)-1], stack[:len(stack)-1]

		var result string
		if op == "&&" {
			result = fmt.Sprintf("%v", a == "true" && b == "true")
		} else if op == "||" {
			result = fmt.Sprintf("%v", a == "true" || b == "true")
		} else {
			return false, errors.New("invalid operator")
		}
		stack = append(stack, result)
	}

	if len(stack) != 1 {
		return false, errors.New("invalid expression")
	}

	return stack[0] == "true", nil
}

func main() {
	testCases := []string{
		"true || (false && true)",
		"true && (false",
		"false || false && true",
		"(true || false) && (false || true)",
		"true && !(false || true)",
	}

	for _, testCase := range testCases {
		result, err := evaluateBooleanExpression(testCase)
		if err != nil {
			fmt.Printf("Error evaluating expression '%s': %v\n", testCase, err)
		} else {
			fmt.Printf("The result of '%s' is %v\n", testCase, result)
		}
	}
}
