	"fmt"
	"strings"

	strfmt "github.com/go-openapi/strfmt"
	// Assume parser and models packages are available and imported.
)

// BackendConfig represents a backend configuration for a load balancer.
type BackendConfig struct {
	Name             string   // Unique name of the backend.
	Servers          []string // List of unique server names.
	LoadBalancingAlg string   // Load balancing algorithm.
}

// Validate checks if the BackendConfig is valid.
func (b *BackendConfig) Validate() error {
	if b.Name == "" {
		return errors.New("backend name cannot be empty")
	}
	if len(b.Servers) == 0 {
		return errors.New("backend must have at least one server")
	}
	serverSet := make(map[string]struct{})
	for _, server := range b.Servers {
		if _, exists := serverSet[server]; exists {
			return fmt.Errorf("duplicate server name: %s", server)
		}
		serverSet[server] = struct{}{}
	}
	validAlgorithms := []string{"roundrobin", "leastconn"}
	if !contains(validAlgorithms, b.LoadBalancingAlg) {
		return fmt.Errorf("invalid load balancing algorithm: %s", b.LoadBalancingAlg)
	}
	return nil
}

// contains checks if a string is present in a slice.
func contains(slice []string, item string) bool {
	for _, a := range slice {
		if a == item {
			return true
		}
	}
	return false
}

// BackendManager manages backend configurations.
type BackendManager struct {
	backends map[string]*BackendConfig
}

// NewBackendManager creates a new BackendManager.
func NewBackendManager() *BackendManager {
	return &BackendManager{
		backends: make(map[string]*BackendConfig),
	}
}

// CreateBackend creates a new backend configuration.
func (m *BackendManager) CreateBackend(backend *BackendConfig) error {
	if _, exists := m.backends[backend.Name]; exists {
		return fmt.Errorf("backend %s already exists", backend.Name)
	}
	if err := backend.Validate(); err != nil {
		return err
	}
	m.backends[backend.Name] = backend
	return nil
}

// GetBackend retrieves a backend configuration by its name.
func (m *BackendManager) GetBackend(name string) (*BackendConfig, error) {
	backend, exists := m.backends[name]
	if !exists {
		return nil, fmt.Errorf("backend %s does not exist", name)
	}
	return backend, nil
}

// EditBackend updates an existing backend configuration.
func (m *BackendManager) EditBackend(name string, newBackend *BackendConfig) error {
	if _, exists := m.backends[name]; !exists {
		return fmt.Errorf("backend %s does not exist", name)
	}
	if err := newBackend.Validate(); err != nil {
		return err
	}
	m.backends[name] = newBackend
	return nil
}

// DeleteBackend deletes a backend configuration.
func (m *BackendManager) DeleteBackend(name string) error {
	if _, exists := m.backends[name]; !exists {
		return fmt.Errorf("backend %s does not exist", name)
	}
	delete(m.backends, name)
	return nil
}

// ListBackends lists all backend configurations.
func (m *BackendManager) ListBackends() []*BackendConfig {
	backends := make([]*BackendConfig, 0, len(m.backends))
	for _, backend := range m.backends {
		backends = append(backends, backend)
	}
	return backends
}

