package main

import (
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"time"

	"github.com/AlecAivazis/survey/v2"
)

// Assuming utils package and K8sConfig struct are defined as per the given code snippet.
// utils package should contain:
// - ActualConfigPath: the path where the actual configuration is to be stored.
// - SettingsPath: the path where the settings JSON file is to be stored.
// - RemoveFromList: a utility function to remove an item from a slice by index.

type K8sConfig struct {
	Name     string `json:"name"`
	Location string `json:"location"`
}

type IAppSettings interface {
	AddConfig(newConfig K8sConfig) error
	DelConfigs(configsSelected []string) error
	UseConfig(configName string) error
	SaveFile() error
	GetConfigList() []K8sConfig
	GetUpdatedAt() time.Time
	GetCurrentConfig() K8sConfig
}

type AppSettings struct {
	CurrentConfig K8sConfig   `json:"current"`
	UpdatedAt     time.Time   `json:"updatedAt"`
	ConfigList    []K8sConfig `json:"configs"`
}

// NewAppSettings creates a new instance of AppSettings with default values.
func NewAppSettings() *AppSettings {
	return &AppSettings{K8sConfig{}, time.Now(), make([]K8sConfig, 0)}
}

// GetCurrentConfig returns the current Kubernetes configuration.
func (settings *AppSettings) GetCurrentConfig() K8sConfig {
	return settings.CurrentConfig
}

// GetConfigList returns the list of Kubernetes configurations.
func (settings *AppSettings) GetConfigList() []K8sConfig {
	return settings.ConfigList
}

// GetUpdatedAt returns the last updated timestamp of the settings.
func (settings *AppSettings) GetUpdatedAt() time.Time {
	return settings.UpdatedAt
}

// AddConfig adds a new Kubernetes configuration to the manager.
func (settings *AppSettings) AddConfig(newConfig K8sConfig) error {
	for _, config := range settings.ConfigList {
		if config.Name == newConfig.Name {
			return errors.New("config name already used")
		}
	}

	settings.ConfigList = append(settings.ConfigList, newConfig)
	return settings.SaveFile()
}

// DelConfigs deletes the specified configurations from the manager.
func (settings *AppSettings) DelConfigs(configsSelected []string) error {
	newConfigList := make([]K8sConfig, 0)
	for _, config := range settings.ConfigList {
		shouldDelete := false
		for _, selected := range configsSelected {
			if config.Name == selected {
				shouldDelete = true
				break
			}
		}
		if !shouldDelete {
			newConfigList = append(newConfigList, config)
		} else {
			if err := os.Remove(config.Location); err != nil {
				return err
			}
		}
	}
	settings.ConfigList = newConfigList
	return settings.SaveFile()
}

// UseConfig sets the specified configuration as the current configuration.
func (settings *AppSettings) UseConfig(configName string) error {
	for _, config := range settings.ConfigList {
		if config.Name == configName {
			bytesRead, err := os.ReadFile(config.Location)
			if err != nil {
				return err
			}

			if err := os.WriteFile(utils.ActualConfigPath, bytesRead, 0644); err != nil {
				return err
			}

			settings.CurrentConfig = config
			return settings.SaveFile()
		}
	}
	return errors.New("config not found")
}

// SaveFile saves the current state of the manager to a JSON file.
func (settings *AppSettings) SaveFile() error {
	prevSettings, err := GetSettings()
	if err != nil {
		return err
	}

	if prevSettings.GetUpdatedAt() != settings.GetUpdatedAt() {
		override := false
		prompt := &survey.Confirm{
			Message: "Settings file changed in the meantime. Override?",
			Default: true,
		}
		if err := survey.AskOne(prompt, &override); err != nil {
			return err
		}

		if !override {
			return nil
		}
	}

	settings.UpdatedAt = time.Now()
	file, _ := json.Marshal(settings)
	return os.WriteFile(utils.SettingsPath, file, 0644)
}

// GetSettings reads the settings from the JSON file and returns an IAppSettings interface.
func GetSettings() (IAppSettings, error) {
	bytesRead, err := os.ReadFile(utils.SettingsPath)
	if err != nil {
		return nil, errors.New("settings file reading failed")
	}

	var tempSettings AppSettings
	if err := json.Unmarshal(bytesRead, &tempSettings); err != nil {
		return nil, errors.New("settings file decoding failed")
	}

	return &tempSettings, nil
}

// Test cases to verify the solution correctness.
func main() {
	settings := NewAppSettings()

	// Add a new configuration
	err := settings.AddConfig(K8sConfig{Name: "dev", Location: "/path/to/dev/config"})
	if err != nil {
		fmt.Println("Error adding config:", err)
	}

	// Use a configuration
	err = settings.UseConfig("dev")
	if err != nil {
		fmt.Println("Error using config:", err)
	}

	// Delete a configuration
	err = settings.DelConfigs([]string{"dev"})
	if err != nil {
		fmt.Println("Error deleting config:", err)
	}

	// Attempt to use a deleted configuration
	err = settings.UseConfig("dev")
	if err != nil {
		fmt.Println("Expected error:", err)
	}
}
