package main

import (
	"fmt"
	"time"

	"github.com/dgrijalva/jwt-go"
)

const (
	audience = "api-platform-users"
	issuer   = "api-auth-service"
	subject  = "user-authentication"
)

var (
	errInvalidTokenClaims           = fmt.Errorf("invalid token claims")
	errUnexpectedTokenSigningMethod = fmt.Errorf("unexpected token signing method")
)

// TokenManager is a JSON web token manager
type TokenManager struct {
	accessTokenSecretKey  string
	refreshTokenSecretKey string
	accessTokenDuration   time.Duration
	refreshTokenDuration  time.Duration
}

// UserForToken contains user information for token generation
type UserForToken struct {
	Email       string `json:"email"`
	UserID      string `json:"user_id"`
	PhoneNumber string `json:"phone_number"`
}

// CustomClaims is a custom JWT claims that contains some user's information
type CustomClaims struct {
	jwt.StandardClaims
	UserForToken
}

// NewTokenManager returns a new JWT manager
func NewTokenManager(accessTokenSecretKey, refreshTokenSecretKey string, accessTokenDuration, refreshTokenDuration time.Duration) *TokenManager {
	return &TokenManager{
		accessTokenSecretKey:  accessTokenSecretKey,
		refreshTokenSecretKey: refreshTokenSecretKey,
		accessTokenDuration:   accessTokenDuration,
		refreshTokenDuration:  refreshTokenDuration,
	}
}

// GenerateAccessToken generates and signs a new access token for a user
func (manager *TokenManager) GenerateAccessToken(user *UserForToken) (string, error) {
	now := time.Now().UTC()
	claims := CustomClaims{
		StandardClaims: jwt.StandardClaims{
			Subject:   subject,
			Issuer:    issuer,
			Audience:  audience,
			IssuedAt:  now.Unix(),
			ExpiresAt: now.Add(manager.accessTokenDuration).Unix(),
		},
		UserForToken: *user,
	}

	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
	return token.SignedString([]byte(manager.accessTokenSecretKey))
}

// GenerateRefreshToken generates and signs a new refresh token for a user
func (manager *TokenManager) GenerateRefreshToken() (string, error) {
	now := time.Now().UTC()
	claims := jwt.StandardClaims{
		Subject:   subject,
		ExpiresAt: now.Add(manager.refreshTokenDuration).Unix(),
	}

	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
	return token.SignedString([]byte(manager.refreshTokenSecretKey))
}

// VerifyAccessToken verifies the access token string and returns a user claim if the token is valid
func (manager *TokenManager) VerifyAccessToken(accessToken string) (*CustomClaims, error) {
	token, err := jwt.ParseWithClaims(
		accessToken,
		&CustomClaims{},
		func(token *jwt.Token) (interface{}, error) {
			if _, ok := token.Method.(*jwt.SigningMethodHMAC); !ok {
				return nil, errUnexpectedTokenSigningMethod
			}
			return []byte(manager.accessTokenSecretKey), nil
		},
	)

	if err != nil {
		return nil, fmt.Errorf("invalid token: %w", err)
	}

	claims, ok := token.Claims.(*CustomClaims)
	if !ok {
		return nil, errInvalidTokenClaims
	}

	return claims, nil
}

// VerifyRefreshToken verifies the refresh token string and returns a new access token if the token is valid
func (manager *TokenManager) VerifyRefreshToken(refreshToken string) (string, error) {
	token, err := jwt.ParseWithClaims(
		refreshToken,
		&jwt.StandardClaims{},
		func(token *jwt.Token) (interface{}, error) {
			if _, ok := token.Method.(*jwt.SigningMethodHMAC); !ok {
				return nil, errUnexpectedTokenSigningMethod
			}
			return []byte(manager.refreshTokenSecretKey), nil
		},
	)

	if err != nil {
		return "", fmt.Errorf("invalid token: %w", err)
	}

	claims, ok := token.Claims.(*jwt.StandardClaims)
	if !ok || !claims.Valid() {
		return "", errInvalidTokenClaims
	}

	// Assuming the refresh token is valid, generate a new access token
	user := &UserForToken{
		Email:       "user@example.com", // This should be retrieved from a data store
		UserID:      "12345",            // This should be retrieved from a data store
		PhoneNumber: "+1234567890",      // This should be retrieved from a data store
	}
	return manager.GenerateAccessToken(user)
}

func main() {
	// Example usage of the TokenManager
	accessTokenSecretKey := "my_secret_key_for_access_token"
	refreshTokenSecretKey := "my_secret_key_for_refresh_token"
	accessTokenDuration := 15 * time.Minute
	refreshTokenDuration := 7 * 24 * time.Hour

	manager := NewTokenManager(accessTokenSecretKey, refreshTokenSecretKey, accessTokenDuration, refreshTokenDuration)

	user := &UserForToken{
		Email:       "user@example.com",
		UserID:      "12345",
		PhoneNumber: "+1234567890",
	}

	accessToken, err := manager.GenerateAccessToken(user)
	if err != nil {
		fmt.Println("Error generating access token:", err)
		return
	}
	fmt.Println("Access Token:", accessToken)

	refreshToken, err := manager.GenerateRefreshToken()
	if err != nil {
		fmt.Println("Error generating refresh token:", err)
		return
	}
	fmt.Println("Refresh Token:", refreshToken)

	// Verify the access token
	claims, err := manager.VerifyAccessToken(accessToken)
	if err != nil {
		fmt.Println("Error verifying access token:", err)
		return
	}
	fmt.Printf("Access Token Claims: %+v\n", claims)

	// Verify the refresh token and get a new access token
	newAccessToken, err := manager.VerifyRefreshToken(refreshToken)
	if err != nil {
		fmt.Println("Error verifying refresh token:", err)
		return
	}
	fmt.Println("New Access Token:", newAccessToken)
}
