)

// Counter is a Metric that can only go up (or be reset to zero).
type Counter struct {
	value int64
	mu    sync.Mutex
}

func (c *Counter) Add(delta int64) {
	c.mu.Lock()
	defer c.mu.Unlock()
	c.value += delta
}

func (c *Counter) Value() int64 {
	c.mu.Lock()
	defer c.mu.Unlock()
	return c.value
}

// Gauge is a Metric that can go up or down.
type Gauge struct {
	value int64
	mu    sync.Mutex
}

func (g *Gauge) Add(delta int64) {
	g.mu.Lock()
	defer g.mu.Unlock()
	g.value += delta
}

func (g *Gauge) Value() int64 {
	g.mu.Lock()
	defer c.mu.Unlock()
	return g.value
}

// Histogram is a Metric that aggregates values into predefined buckets.
type Histogram struct {
	buckets []float64
	counts  []int64
	mu      sync.Mutex
}

func NewHistogram(buckets []float64) *Histogram {
	return &Histogram{
		buckets: buckets,
		counts:  make([]int64, len(buckets)+1),
	}
}

func (h *Histogram) Add(value int64) {
	h.mu.Lock()
	defer h.mu.Unlock()
	for i, b := range h.buckets {
		if float64(value) <= b {
			h.counts[i]++
			return
		}
	}
	h.counts[len(h.counts)-1]++
}

func (h *Histogram) Value() int64 {
	h.mu.Lock()
	defer h.mu.Unlock()
	sum := int64(0)
	for _, count := range h.counts {
		sum += count
	}
	return sum
}

func (h *Histogram) Min() float64 {
	h.mu.Lock()
	defer h.mu.Unlock()
	for i, count := range h.counts {
		if count > 0 {
			if i == 0 {
				return 0
			}
			return h.buckets[i-1]
		}
	}
	return math.NaN()
}

func (h *Histogram) Max() float64 {
	h.mu.Lock()
	defer h.mu.Unlock()
	for i := len(h.counts) - 1; i >= 0; i-- {
		if h.counts[i] > 0 {
			if i == len(h.buckets) {
				return math.Inf(1)
			}
			return h.buckets[i]
		}
	}
	return math.NaN()
}

func (h *Histogram) Avg() float64 {
	h.mu.Lock()
	defer h.mu.Unlock()
	sum := float64(0)
	totalCount := int64(0)
	for i, count := range h.counts {
		totalCount += count
		bucketValue := float64(0)
		if i < len(h.buckets) {
			bucketValue = h.buckets[i]
		} else {
			bucketValue = h.buckets[i-1]
		}
		sum += bucketValue * float64(count)
	}
	if totalCount == 0 {
		return 0
	}
	return sum / float64(totalCount)
}

func (h *Histogram) Sum() float64 {
	h.mu.Lock()
	defer h.mu.Unlock()
	sum := float64(0)
	for i, count := range h.counts {
		bucketValue := float64(0)
		if i < len(h.buckets) {
			bucketValue = h.buckets[i]
		} else {
			bucketValue = h.buckets[i-1]
		}
		sum += bucketValue * float64(count)
	}
	return sum
}

