package main

import (
	"sync"
	"time"
)

type CacheItem struct {
	Value      string
	Expiration int64
}

type Cache struct {
	items map[string]CacheItem
	mutex sync.RWMutex
}

func NewCache() *Cache {
	return &Cache{
		items: make(map[string]CacheItem),
	}
}

func (c *Cache) Set(key string, value string, duration time.Duration) {
	c.mutex.Lock()
	defer c.mutex.Unlock()

	expiration := int64(0)
	if duration > 0 {
		expiration = time.Now().Add(duration).UnixNano()
	}

	c.items[key] = CacheItem{
		Value:      value,
		Expiration: expiration,
	}
}

func (c *Cache) Get(key string) (string, bool) {
	c.mutex.RLock()
	defer c.mutex.RUnlock()

	item, found := c.items[key]
	if !found {
		return "", false
	}

	if item.Expiration > 0 && time.Now().UnixNano() > item.Expiration {
		return "", false
	}

	return item.Value, true
}

func (c *Cache) Del(key string) {
	c.mutex.Lock()
	defer c.mutex.Unlock()

	delete(c.items, key)
}

func (c *Cache) Cleanup() {
	c.mutex.Lock()
	defer c.mutex.Unlock()

	now := time.Now().UnixNano()
	for key, item := range c.items {
		if item.Expiration > 0 && now > item.Expiration {
			delete(c.items, key)
		}
	}
}

func main() {
	// Example usage
	cache := NewCache()

	// Set values
	cache.Set("key1", "value1", 5*time.Second)
	cache.Set("key2", "value2", 0) // Never expires

	// Get values
	if val, found := cache.Get("key1"); found {
		println("key1:", val)
	} else {
		println("key1 not found or expired")
	}

	// Wait for key1 to expire
	time.Sleep(6 * time.Second)
	cache.Cleanup()

	if val, found := cache.Get("key1"); found {
		println("key1:", val)
	} else {
		println("key1 not found or expired")
	}

	// key2 should still be there
	if val, found := cache.Get("key2"); found {
		println("key2:", val)
	} else {
		println("key2 not found or expired")
	}

	// Delete key2
	cache.Del("key2")
	if val, found := cache.Get("key2"); found {
		println("key2:", val)
	} else {
		println("key2 not found or expired")
	}
}
