	// Check if the price feeder is active
	priceFeeder, found := server.GetPriceFeeder(ctx, msg.Provider)
	if !found || !priceFeeder.IsActive {
		return nil, types.ErrPriceFeederNotActive
	}

	// Store the price data
	priceData := types.PriceData{
		Provider:  msg.Provider,
		Asset:     msg.Asset,
		Source:    msg.Source,
		Price:     msg.Price,
		Timestamp: uint64(ctx.BlockTime().Unix()),
	}
	server.SetPriceData(ctx, priceData)

	return &types.MsgFeedPriceResponse{}, nil
}

// GetPrice retrieves the price data for a given asset, source, and timestamp.
