	m, e := f.tradeAPI.GetTickerPrice([]model.TradingPair{f.pair})
	if e != nil {
		return 0, e
	}

	p, ok := m[f.pair]
	if !ok {
		return 0, fmt.Errorf("could not get price for trading pair: %s", f.pair.String())
	}

	centerPrice := (p.BidPrice.AsFloat() + p.AskPrice.AsFloat()) / 2
	return centerPrice, nil
}

// PriceAggregator interface for aggregating prices from multiple exchange feeds
