	GetAveragePrice() (float64, error)
}

// priceAggregatorImpl is an implementation of the PriceAggregator interface
type priceAggregatorImpl struct {
	feeds []exchangeFeed
}

// GetAveragePrice calculates the average price across all feeds
func (pa *priceAggregatorImpl) GetAveragePrice() (float64, error) {
	if len(pa.feeds) == 0 {
		return 0, errors.New("no feeds available to aggregate")
	}

	var total float64
	for _, feed := range pa.feeds {
		price, err := feed.GetPrice()
		if err != nil {
			return 0, err
		}
		total += price
	}

	average := total / float64(len(pa.feeds))
	return average, nil
}

