// BlackholeServer simulates a blackhole proxy server.
type BlackholeServer struct {
	response *blackhole.HTTPResponse
}

// NewBlackholeServer creates a new BlackholeServer with a predefined HTTP response.
func NewBlackholeServer() *BlackholeServer {
	return &BlackholeServer{
		response: &blackhole.HTTPResponse{
			Status:   "200 OK",
			Header:   map[string]string{"Content-Type": "text/plain"},
			Response: []byte("Request absorbed by blackhole"),
		},
	}
}

// Serve processes the incoming data by absorbing it and writing an HTTP response back.
func (s *BlackholeServer) Serve(link transport.Link) error {
	// Absorb incoming data
	_, err := link.Reader.ReadMultiBuffer()
	if err != nil {
		return err
	}

	// Write the predefined HTTP response back
	writer := buf.NewWriter(link.Writer)
	httpResponse := fmt.Sprintf("HTTP/1.1 %s\r\n", s.response.Status)
	for key, value := range s.response.Header {
		httpResponse += fmt.Sprintf("%s: %s\r\n", key, value)
	}
	httpResponse += "\r\n" + string(s.response.Response)
	return writer.WriteString(httpResponse)
}

func TestBlackholeServer(t *testing.T) {
	server := NewBlackholeServer()

	reader, writer := pipe.New(pipe.WithoutSizeLimit())
	link := transport.Link{
		Reader: reader,
		Writer: writer,
	}

	// Simulate incoming data
	go func() {
		writer.WriteMultiBuffer(buf.NewMultiBufferValue(buf.NewBuffer([]byte("Incoming data"))))
		writer.Close()
	}()

	// Serve and process the data
	err := server.Serve(link)
	common.Must(err)

	// Read the response
	mb, err := reader.ReadMultiBuffer()
	common.Must(err)

	// Verify the response
	expectedResponse := "HTTP/1.1 200 OK\r\nContent-Type: text/plain\r\n\r\nRequest absorbed by blackhole"
	if mb.String() != expectedResponse {
		t.Errorf("unexpected response: got %v, want %v", mb.String(), expectedResponse)
	}
}
