package interac

import (
	"bufio"
	"context"
	"net"
	"os"
	"path/filepath"
	"strings"
)

// unixSocketFile returns the path to the Unix Domain Socket file.
func unixSocketFile() string {
	exeName := filepath.Base(os.Args[0])
	return filepath.Join(os.TempDir(), "."+exeName+".unix_socket_for_client_cmd")
}

// Request represents a single IPC request with a channel for the response.
type Request struct {
	Content  string
	Response chan<- string
}

// ChanFromClient sets up a Unix Domain Socket server and returns a channel for incoming requests.
func ChanFromClient(ctx context.Context) (ch <-chan Request, err error) {
	uf := unixSocketFile()
	_ = os.Remove(uf)

	unixAddr, _ := net.ResolveUnixAddr("unix", uf)
	unixListener, err := net.ListenUnix("unix", unixAddr)
	if err != nil {
		return nil, err
	}

	ret := make(chan Request, 10)

	go func() {
		<-ctx.Done()
		unixListener.Close()
	}()

	go func() {
		for {
			unixConn, err := unixListener.AcceptUnix()
			if err != nil {
				return
			}
			go handleConnection(ctx, unixConn, ret)
		}
	}()

	return ret, nil
}

// ChanFromServer connects to the Unix Domain Socket server and returns a channel to send requests.
func ChanFromServer(ctx context.Context) (ch chan<- Request, err error) {
	ret := make(chan Request)

	unixAddr, err := net.ResolveUnixAddr("unix", unixSocketFile())
	if err != nil {
		return nil, err
	}

	conn, err := net.DialUnix("unix", nil, unixAddr)
	if err != nil {
		return nil, err
	}

	go func() {
		<-ctx.Done()
		conn.Close()
	}()

	go func() {
		for req := range ret {
			request := addBlankLine(req.Content)
			_, err = conn.Write([]byte(request))
			if err != nil {
				close(req.Response)
				return
			}

			reader := bufio.NewReader(conn)
			allMsg, err := readAll(reader)
			if err != nil {
				close(req.Response)
				return
			}

			req.Response <- allMsg
		}
	}()

	return ret, nil
}

// handleConnection handles a single client connection.
func handleConnection(ctx context.Context, unixConn *net.UnixConn, ret chan<- Request) {
	defer unixConn.Close()

	reader := bufio.NewReader(unixConn)

	for {
		allMsg, err := readAll(reader)
		if err != nil {
			break
		}

		response := make(chan string, 1)
		ret <- Request{
			Content:  allMsg,
			Response: response,
		}
		res := <-response

		res = addBlankLine(res)
		_, err = unixConn.Write([]byte(res))
		if err != nil {
			break
		}
	}
}

// addBlankLine ensures that the request ends with a blank line.
func addBlankLine(request string) string {
	return strings.TrimRight(request, "\n") + "\n\n"
}

// readAll reads from the buffer until a blank line is encountered.
func readAll(reader *bufio.Reader) (string, error) {
	var allMsg strings.Builder
	for {
		msg, err := reader.ReadString('\n')
		if err != nil {
			return "", err
		}
		if msg == "\n" {
			break
		}
		allMsg.WriteString(msg)
	}
	return allMsg.String(), nil
}
