		fmt.Printf("Error initializing watcher directories: %s\n", err)
		return
	}

	// Start watching in a separate goroutine.
	go watcher.Watch()

	// Listen for events and errors for a certain duration.
	timeout := time.After(10 * time.Second)
	for {
		select {
		case event := <-watcher.Events:
			fmt.Printf("Event: %s\n", event)
		case err := <-watcher.Errs:
			fmt.Printf("Error: %s\n", err)
		case <-timeout:
			fmt.Println("Finished watching.")
			return
		}
	}
}
