package main

import (
	"bufio"
	"fmt"
	"io"
	"os"
	"path/filepath"
	"strings"
	"sync"
	"time"

	"github.com/sadaghiani/concurrent-file-processing/pkg/config"
	"github.com/sadaghiani/concurrent-file-processing/pkg/logger"
	"github.com/sadaghiani/concurrent-file-processing/internal/utils"
)

// reverseString reverses the characters in a string.
func reverseString(s string) string {
	runes := []rune(s)
	for i, j := 0, len(runes)-1; i < j; i, j = i+1, j-1 {
		runes[i], runes[j] = runes[j], runes[i]
	}
	return string(runes)
}

// processFile reads the contents of the input file, applies a transformation to each line,
// and writes the result to the output file.
func processFile(inputPath, outputPath string) error {
	logger.Log.Infof("Processing file: %s", inputPath)

	inputFile, err := os.Open(inputPath)
	if err != nil {
		return err
	}
	defer inputFile.Close()

	outputFile, err := os.Create(outputPath)
	if err != nil {
		return err
	}
	defer outputFile.Close()

	scanner := bufio.NewScanner(inputFile)
	writer := bufio.NewWriter(outputFile)

	for scanner.Scan() {
		transformedLine := reverseString(scanner.Text())
		if _, err := writer.WriteString(transformedLine + "\n"); err != nil {
			return err
		}
	}

	if err := scanner.Err(); err != nil {
		return err
	}

	if err := writer.Flush(); err != nil {
		return err
	}

	logger.Log.Infof("Finished processing file: %s", inputPath)
	return nil
}

func main() {
	config.NewConfig(utils.CreateMustBindEnvs(), utils.CreateMustBindFlags())
	logger.NewLogger(config.Config.GetInt(utils.MustBindEnvToString(utils.APP_LOG_LEVEL)), time.RFC3339)

	inputDir := "input_files"
	outputDir := "output_files"
	maxWorkers := 5

	files, err := os.ReadDir(inputDir)
	if err != nil {
		logger.Log.Fatal(err)
	}

	var wg sync.WaitGroup
	semaphore := make(chan struct{}, maxWorkers)

	for _, file := range files {
		wg.Add(1)
		semaphore <- struct{}{}

		go func(file os.DirEntry) {
			defer wg.Done()
			inputPath := filepath.Join(inputDir, file.Name())
			outputPath := filepath.Join(outputDir, file.Name())

			if err := processFile(inputPath, outputPath); err != nil {
				logger.Log.Error(err)
			}

			<-semaphore
		}(file)
	}

	wg.Wait()
	logger.Log.Info("All files have been processed.")
}

// Test cases to verify the solution correctness.
func main() {
	// Create test input files with known content.
	testInputDir := "./test_input"
	testOutputDir := "./test_output"
	os.Mkdir(testInputDir, 0755)
	os.Mkdir(testOutputDir, 0755)
	defer os.RemoveAll(testInputDir)
	defer os.RemoveAll(testOutputDir)

	testFiles := []string{"test1.txt", "test2.txt"}
	for _, fileName := range testFiles {
		filePath := filepath.Join(testInputDir, fileName)
		file, err := os.Create(filePath)
		if err != nil {
			logger.Log.Fatal(err)
		}
		_, err = file.WriteString(strings.Join([]string{"hello", "world"}, "\n"))
		if err != nil {
			logger.Log.Fatal(err)
		}
		file.Close()
	}

	// Run the main function to process the test files.
	main()

	// Verify the output files have the expected content.
	for _, fileName := range testFiles {
		inputPath := filepath.Join(testInputDir, fileName)
		outputPath := filepath.Join(testOutputDir, fileName)
		expectedContent, err := os.ReadFile(inputPath)
		if err != nil {
			logger.Log.Fatal(err)
		}
		expectedLines := strings.Split(string(expectedContent), "\n")
		for i, line := range expectedLines {
			expectedLines[i] = reverseString(line)
		}
		expectedOutput := strings.Join(expectedLines, "\n")

		actualContent, err := os.ReadFile(outputPath)
		if err != nil {
			logger.Log.Fatal(err)
		}

		if string(actualContent) != expectedOutput {
			logger.Log.Fatalf("Output file %s does not match expected content.", fileName)
		}
	}

	logger.Log.Info("All test cases passed.")
}
