func About(w http.ResponseWriter, r *http.Request) {
	fmt.Fprint(w, "This service provides basic arithmetic operations such as addition and division.")
}

func Add(w http.ResponseWriter, r *http.Request) {
	values := r.URL.Query()
	x, err1 := strconv.Atoi(values.Get("x"))
	y, err2 := strconv.Atoi(values.Get("y"))

	if err1 != nil || err2 != nil {
		http.Error(w, "Invalid query parameters. Please ensure that 'x' and 'y' are integers.", http.StatusBadRequest)
		return
	}

	result := addValue(x, y)
	fmt.Fprintf(w, "The sum of %d and %d is %d", x, y, result)
}

func Divide(w http.ResponseWriter, r *http.Request) {
	values := r.URL.Query()
	x, err1 := strconv.ParseFloat(values.Get("x"), 32)
	y, err2 := strconv.ParseFloat(values.Get("y"), 32)

	if err1 != nil || err2 != nil {
		http.Error(w, "Invalid query parameters. Please ensure that 'x' and 'y' are numbers.", http.StatusBadRequest)
		return
	}

	result, err := divideValues(float32(x), float32(y))
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	fmt.Fprintf(w, "The result of dividing %f by %f is %f", x, y, result)
}

func divideValues(x, y float32) (float32, error) {
	if y == 0 {
		err := errors.New("Cannot divide by zero")
		return 0, err
	}
	return x / y, nil
}

func addValue(x, y int) int {
	return x + y
}
