package main

import (
	"reflect"
	"testing"
)

// subsets generates all possible subsets of the given distinct integer array.
func subsets(nums []int) (ans [][]int) {
	set := []int{}
	var dfs func(int)
	dfs = func(cur int) {
		if cur == len(nums) {
			ans = append(ans, append([]int(nil), set...))
			return
		}
		// Include the current element
		set = append(set, nums[cur])
		dfs(cur + 1)
		// Exclude the current element
		set = set[:len(set)-1]
		dfs(cur + 1)
	}
	dfs(0)
	return
}

// TestSubsets tests the subsets function.
func TestSubsets(t *testing.T) {
	var subsetsTests = []struct {
		in       []int
		expected [][]int
	}{
		{[]int{1, 2, 3}, [][]int{{}, {1}, {2}, {1, 2}, {3}, {1, 3}, {2, 3}, {1, 2, 3}}},
		{[]int{0}, [][]int{{}, {0}}},
	}
	for _, tt := range subsetsTests {
		actual := subsets(tt.in)
		if !reflect.DeepEqual(actual, tt.expected) {
			t.Errorf("subsets(%v) = %v; expected %v", tt.in, actual, tt.expected)
		}
	}
}

func main() {
	// Example usage:
	nums := []int{1, 2, 3}
	subsets := subsets(nums)
	for _, subset := range subsets {
		fmt.Println(subset)
	}
}
