package main

import (
	"fmt"
	"math"
	"time"
)

const (
	Degree = math.Pi / 180
)

// SolarTransit calculates the Julian date for the local true solar transit.
func SolarTransit(d, solarAnomaly, eclipticLongitude float64) float64 {
	equationOfTime := 0.0053*math.Sin(solarAnomaly*Degree) -
		0.0069*math.Sin(2*eclipticLongitude*Degree)
	return d + equationOfTime
}

// CalculateSolarMeanAnomaly calculates the solar mean anomaly for a given Julian date.
func CalculateSolarMeanAnomaly(julianDate float64) float64 {
	return (357.5291 + 0.98560028*(julianDate-2451545)) * Degree
}

// CalculateEquationOfCenter calculates the equation of the center for a given solar mean anomaly.
func CalculateEquationOfCenter(solarMeanAnomaly float64) float64 {
	return (1.9148*math.Sin(solarMeanAnomaly) +
		0.0200*math.Sin(2*solarMeanAnomaly) +
		0.0003*math.Sin(3*solarMeanAnomaly)) * Degree
}

// CalculateEclipticLongitude calculates the ecliptic longitude for a given solar mean anomaly and equation of the center.
func CalculateEclipticLongitude(solarMeanAnomaly, equationOfCenter float64) float64 {
	return solarMeanAnomaly + equationOfCenter + 102.9372*Degree + math.Pi
}

// CalculateSunriseTime calculates the sunrise time for a given Julian date, latitude, and longitude.
func CalculateSunriseTime(julianDate, latitude, longitude float64) float64 {
	solarMeanAnomaly := CalculateSolarMeanAnomaly(julianDate)
	equationOfCenter := CalculateEquationOfCenter(solarMeanAnomaly)
	eclipticLongitude := CalculateEclipticLongitude(solarMeanAnomaly, equationOfCenter)

	solarTransit := SolarTransit(julianDate, solarMeanAnomaly, eclipticLongitude)

	// Calculate the hour angle
	hourAngle := math.Acos(math.Sin(-0.83*Degree) /
		(math.Cos(latitude*Degree) * math.Cos(eclipticLongitude)) -
		math.Tan(latitude*Degree)*math.Tan(eclipticLongitude))

	// Calculate the sunrise time
	sunriseTime := solarTransit - (hourAngle / (2 * math.Pi * 24)) - (longitude / 360)

	return sunriseTime
}

// JulianDateFromTime converts a time.Time to Julian date.
func JulianDateFromTime(t time.Time) float64 {
	year := float64(t.Year())
	month := float64(t.Month())
	day := float64(t.Day())

	if month <= 2 {
		year--
		month += 12
	}

	A := math.Floor(year / 100)
	B := 2 - A + math.Floor(A/4)

	julianDate := math.Floor(365.25*(year+4716)) + math.Floor(30.6001*(month+1)) + day + B - 1524.5
	return julianDate
}

func main() {
	// Example usage:
	// Calculate the sunrise time for New York City on April 1, 2023.
	// Latitude: 40.7128 N, Longitude: -74.0060 W
	location := time.Date(2023, 4, 1, 0, 0, 0, 0, time.UTC)
	latitude := 40.7128
	longitude := -74.0060

	julianDate := JulianDateFromTime(location)
	sunriseTime := CalculateSunriseTime(julianDate, latitude, -longitude)

	fmt.Printf("Sunrise time for New York City on April 1, 2023 is: %.4f hours from midnight\n", sunriseTime)
}

