	token   Token
	httpCli *http.Client
}

const (
	getHomeDirListAPI = "https://cloud.189.cn/api/open/file/listFiles.action?"
)

// GetHomeDirList retrieves a single page of directory and file listings.
func (d *Dao) GetHomeDirList(ctx context.Context, pn, ps int, order string, folderId ...string) (dirs []*Dir, err error) {
	if d.token.WebLoginToken == "" {
		err = errors.New("no user is currently logged in")
		return
	}
	if folderId == nil || folderId[0] == "" || folderId[0] == "~" {
		folderId = []string{"-11"} // Default home directory ID
	}
	params := url.Values{}
	params.Set("orderBy", order)
	params.Set("folderId", folderId[0])
	params.Set("pageNum", strconv.Itoa(pn))
	params.Set("pageSize", strconv.Itoa(ps))
	req, err := http.NewRequest("GET", getHomeDirListAPI+params.Encode(), nil)
	if err != nil {
		return
	}
	req.Header.Set("Cookie", fmt.Sprintf("COOKIE_LOGIN_USER=%s", d.token.WebLoginToken))
	req.Header.Set("accept", "application/json;charset=UTF-8")
	resp, err := d.httpCli.Do(req)
	if err != nil {
		return
	}
	defer resp.Body.Close()
	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		return
	}
	var res struct {
		ResCode    int    `json:"res_code"`
		ResMsg     string `json:"res_message"`
		FileListAO *struct {
			FileList   []*Dir `json:"fileList"`
			FolderList []*Dir `json:"folderList"`
		} `json:"fileListAO"`
	}
	if err = json.NewDecoder(bytes.NewReader(body)).Decode(&res); err != nil {
		return
	}
	if res.ResCode != 0 {
		err = errors.New(res.ResMsg)
		return
	}
	for _, dir := range res.FileListAO.FolderList {
		dir.IsFolder = true
		dir.IsHome = true
		dirs = append(dirs, dir)
	}
	for _, dir := range res.FileListAO.FileList {
		dir.IsHome = true
		dirs = append(dirs, dir)
	}
	return
}

// GetHomeDirAll retrieves all directories and files in the user's home directory.
func (d *Dao) GetHomeDirAll(ctx context.Context, fileID ...string) (dirs []*Dir, err error) {
	for pn := 1; ; pn++ {
		var dirsPage []*Dir
		if dirsPage, err = d.GetHomeDirList(ctx, pn, 100, "filename", fileID...); err != nil {
			return
		}
		dirs = append(dirs, dirsPage...)
		if len(dirsPage) < 100 {
			break
		}
	}
	return
}

