type Task struct {
	Name       string
	Hours      []int
	Mins       []int
	Retry      bool
	Handler    func(*database.Database) error
	RunOnStart bool
}

// scheduled checks if the task is scheduled to run at the given hour and minute.
func (t *Task) scheduled(hour, min int) bool {
	for _, h := range t.Hours {
		if h == hour {
			for _, m := range t.Mins {
				if m == min {
					return true
				}
			}
		}
	}
	return false
}

// run executes the task's handler and manages its lifecycle.
func (t *Task) run(now time.Time) {
	db := database.GetDatabase()
	defer db.Close()

	job := &Job{
		Id: fmt.Sprintf(
			"%s-%d", t.Name, now.Unix()-int64(now.Second())),
		Name:      t.Name,
		State:     "Running",
		Retry:     t.Retry,
		Node:      node.Self.Id,
		Timestamp: time.Now(),
	}

	reserved, err := job.Reserve(db)
	if err != nil {
		logrus.WithFields(logrus.Fields{
			"task":  t.Name,
			"error": err,
		}).Error("task: Task reserve failed")
		return
	}

	if !reserved {
		return
	}

	err = t.Handler(db)
	if err != nil {
		logrus.WithFields(logrus.Fields{
			"task":  t.Name,
			"error": err,
		}).Error("task: Task failed")
		job.Failed(db)
		return
	}

	job.Finished(db)
}

// runScheduler is the main loop that checks for and runs scheduled tasks.
func runScheduler() {
	now := time.Now()
	curHour := now.Hour()
	curMin := now.Minute()

	for _, task := range registry {
		if task.RunOnStart {
			go task.run(now)
		}
	}

	for {
		time.Sleep(1 * time.Second)

		now = time.Now()
		hour := now.Hour()
		min := now.Minute()

		if curHour == hour && curMin == min {
			continue
		}
		curHour = hour
		curMin = min

		for _, task := range registry {
			if task.scheduled(hour, min) {
				go func(task *Task, now time.Time) {
					task.run(now)
				}(task, now)
			}
		}
	}
}

// register adds a new task to the registry.
func register(task *Task) {
	registry = append(registry, task)
}

// Init starts the task scheduler.
