// clientWithDefaultHeaders wraps an http.Client and adds default headers to all requests.
type clientWithDefaultHeaders struct {
	*http.Client
	Header http.Header
}

// newClientWithDefaultHeaders creates a new clientWithDefaultHeaders with the provided default headers.
func newClientWithDefaultHeaders(defaultHeaders http.Header) *clientWithDefaultHeaders {
	return &clientWithDefaultHeaders{
		Client: &http.Client{
			Transport: &transportWithDefaultHeaders{
				Header:    defaultHeaders,
				Transport: http.DefaultTransport,
			},
		},
		Header: defaultHeaders,
	}
}

// transportWithDefaultHeaders wraps an http.RoundTripper and adds default headers to all requests.
type transportWithDefaultHeaders struct {
	Header    http.Header
	Transport http.RoundTripper
}

// RoundTrip executes a single HTTP transaction, adding the default headers to the request.
func (t *transportWithDefaultHeaders) RoundTrip(r *http.Request) (*http.Response, error) {
	for name, values := range t.Header {
		for _, value := range values {
			r.Header.Add(name, value)
		}
	}
	return t.Transport.RoundTrip(r)
}

// Test cases to verify the solution
