	"io"
	"os"
	"path"
	"runtime"
	"strings"
	"time"
)

// Log levels
const (
	LOG_EMERG = iota
	LOG_ALERT
	LOG_CRIT
	LOG_ERR
	LOG_WARNING
	LOG_NOTICE
	LOG_INFO
	LOG_DEBUG
)

// LogService interface for logging
type LogService interface {
	Error(...interface{})
	Info(...interface{})
}

// Logger is the default implementation of LogService
type Logger struct {
	w io.Writer
}

// NewLogger creates a new Logger instance
func NewLogger(w ...io.Writer) *Logger {
	if len(w) == 0 {
		return &Logger{w: os.Stdout}
	}
	return &Logger{w: w[0]}
}

// Info logs an informational message
func (l *Logger) Info(v ...interface{}) {
	l.write(LOG_INFO, v...)
}

// Error logs an error message
func (l *Logger) Error(v ...interface{}) {
	l.write(LOG_ERR, v...)
}

// write formats and writes the log message
func (l *Logger) write(level int, v ...interface{}) {
	prefix := [...]string{"EMERG", "ALERT", "CRIT", "ERR", "WARNING", "NOTICE", "INFO", "DEBUG"}[level]
	now := time.Now().Format("2006-01-02 15:04:05")
	_, file, line, _ := runtime.Caller(2)
	_, filename := path.Split(file)
	message := fmt.Sprint(v...)
	content := fmt.Sprintf("[%s] [%s] [%s:%d] %s\n", now, prefix, filename, line, message)
	if level <= LOG_WARNING && l.w == os.Stdout {
		l.w = os.Stderr
	}
	l.w.Write([]byte(content))
}

var logger LogService

// GetLogger returns the logger instance
func GetLogger() LogService {
	return logger
}

func init() {
	logger = NewLogger()
}

// Test cases to verify the solution
