package main

import (
	"errors"
	"sync"
)

type Flag struct {
	Namespace   string     `json:"namespace,omitempty"`
	Name        string     `json:"name,omitempty"`
	Description string     `json:"description,omitempty"`
	Rollout     []*Rollout `json:"rollout,omitempty"`
}

type Rollout struct {
	Percentage int  `json:"percentage,omitempty"`
	Value      bool `json:"value"`
}

type FlagStore struct {
	flags map[string]Flag
	mu    sync.RWMutex
}

func NewFlagStore() *FlagStore {
	return &FlagStore{
		flags: make(map[string]Flag),
	}
}

func (fs *FlagStore) CreateFlag(flag Flag) error {
	fs.mu.Lock()
	defer fs.mu.Unlock()

	key := flag.Namespace + ":" + flag.Name
	if _, exists := fs.flags[key]; exists {
		return errors.New("flag already exists")
	}

	fs.flags[key] = flag
	return nil
}

func (fs *FlagStore) GetFlag(namespace, name string) (Flag, error) {
	fs.mu.RLock()
	defer fs.mu.RUnlock()

	key := namespace + ":" + name
	flag, exists := fs.flags[key]
	if !exists {
		return Flag{}, errors.New("flag not found")
	}

	return flag, nil
}

func (fs *FlagStore) EvaluateFlag(namespace, name string, userPercentage int) (bool, error) {
	flag, err := fs.GetFlag(namespace, name)
	if err != nil {
		return false, err
	}

	for _, rollout := range flag.Rollout {
		if userPercentage <= rollout.Percentage {
			return rollout.Value, nil
		}
	}

	return false, errors.New("user percentage not covered by any rollout")
}

func main() {
	// Example usage
	store := NewFlagStore()

	// Create a new flag
	err := store.CreateFlag(Flag{
		Namespace:   "com.example",
		Name:        "new-feature",
		Description: "A new feature flag",
		Rollout: []*Rollout{
			{Percentage: 50, Value: true},
			{Percentage: 100, Value: false},
		},
	})
	if err != nil {
		panic(err)
	}

	// Retrieve the flag
	flag, err := store.GetFlag("com.example", "new-feature")
	if err != nil {
		panic(err)
	}
	println("Retrieved flag:", flag.Name)

	// Evaluate the flag for a user percentage
	isEnabled, err := store.EvaluateFlag("com.example", "new-feature", 25)
	if err != nil {
		panic(err)
	}
	println("Is feature enabled for 25% users?", isEnabled)
}
