// CheckValidatorLatest checks if the given slot is the latest for the specified validator address.
func (db *Database) CheckValidatorLatest(address string, slot int) bool {
	validator, exists := db.validators[address]
	if !exists || validator.Slot < slot {
		return true
	}
	return false
}

// SaveValidator saves or updates the validator record with the given details.
func (db *Database) SaveValidator(address string, slot int, node string, voter string, withdrawer string, balance int) error {
	if db.CheckValidatorLatest(address, slot) {
		db.validators[address] = Validator{
			Address:    address,
			Slot:       slot,
			Node:       node,
			Voter:      voter,
			Withdrawer: withdrawer,
			Balance:    balance,
		}
		return nil
	}
	return errors.New("slot is not the latest")
}

