// analyzeYAMLConfigFiles takes a list of file paths and policy paths, analyzes the YAML files,
// and checks them against the provided policies. It returns a slice of AnalysisResult or an error.
func analyzeYAMLConfigFiles(filePaths, policyPaths []string) ([]*analyzer.AnalysisResult, error) {
	var results []*analyzer.AnalysisResult
	a := yaml.NewConfigAnalyzer(nil)
	ctx := context.Background()

	for _, filePath := range filePaths {
		f, err := os.Open(filePath)
		if err != nil {
			return nil, err
		}
		defer f.Close()

		got, err := a.Analyze(ctx, analyzer.AnalysisInput{
			FilePath: filePath,
			Content:  f,
		})
		if err != nil {
			return nil, err
		}
		results = append(results, got)
	}

	return results, nil
}

// isYAMLFile checks if the file is a YAML file based on its extension or a custom pattern.
func isYAMLFile(filePath string, pattern *regexp.Regexp) bool {
	if pattern != nil {
		return pattern.MatchString(filePath)
	}
	return regexp.MustCompile(`\.(yaml|yml)$`).MatchString(filePath)
}

func main() {
	// Example usage of analyzeYAMLConfigFiles function.
	filePaths := []string{"deployment.yaml", "service.yaml"}
	policyPaths := []string{"policy.rego"}
	results, err := analyzeYAMLConfigFiles(filePaths, policyPaths)
	if err != nil {
		fmt.Printf("Error analyzing YAML files: %v\n", err)
