// Client represents a client that checks the cloning status of repositories.
type Client struct {
	// MockedClonedRepos is a set of repository names that are considered cloned.
	MockedClonedRepos map[string]struct{}
}

// GraphQL simulates sending a GraphQL query to check the cloning status of repositories.
// For this exercise, it returns a predefined response based on MockedClonedRepos.
func (c *Client) GraphQL(query string, variables map[string]interface{}) ([]string, error) {
	clonedRepos := make([]string, 0)
	for repo := range c.MockedClonedRepos {
		clonedRepos = append(clonedRepos, repo)
	}
	return clonedRepos, nil
}

// WaitForReposToBeCloned waits (up to 30 seconds) for all repositories in the list to be cloned.
func (c *Client) WaitForReposToBeCloned(repos ...string) error {
	return retry(30*time.Second, func() error {
		clonedRepos, err := c.GraphQL("", map[string]interface{}{"first": len(repos)})
		if err != nil {
			return errors.New("request GraphQL")
		}

		repoSet := make(map[string]struct{}, len(repos))
		for _, repo := range repos {
			repoSet[repo] = struct{}{}
		}
		for _, clonedRepo := range clonedRepos {
			delete(repoSet, clonedRepo)
		}
		if len(repoSet) > 0 {
			return errContinueRetry
		}

		return nil
	})
}

var errContinueRetry = errors.New("continue retry")

// retry retries the given function until the timeout is reached.
func retry(timeout time.Duration, fn func() error) error {
	ctx, cancel := context.WithTimeout(context.Background(), timeout)
	defer cancel()

	for {
		select {
		case <-ctx.Done():
			if ctx.Err() == context.DeadlineExceeded {
				return errors.New("retry timed out")
			}
			return ctx.Err()
		default:
			err := fn()
			if err != errContinueRetry {
				return err
			}
		}

		time.Sleep(100 * time.Millisecond)
	}
}

