// Book represents a book in the collection.
type Book struct {
	ID             string `json:"id,omitempty" bson:"_id,omitempty"`
	Title          string `json:"title,omitempty" bson:"title,omitempty"`
	Author         string `json:"author,omitempty" bson:"author,omitempty"`
	PublicationYear int    `json:"publicationYear,omitempty" bson:"publicationYear,omitempty"`
}

// Other types (Options, Server, etc.) and functions (LoadOptions, connectClients, etc.) are assumed to be the same as in the given code snippet.

// Initialize the server with routes for the book collection.
func initialize(ctx context.Context, options *Options) *Server {
	mongoClient, smtpClient := connectClients(ctx, options)
	logger := initLogger(options.Logger.FileName, options.Logger.LogLevel)
	router := mux.NewRouter().StrictSlash(true)

	// Initialize the book collection.
	bookCollection := mongoClient.Database(options.Mongo.DatabaseName).Collection("books")

	// Define the handlers for the book collection.
	router.HandleFunc("/api/v1/books", func(w http.ResponseWriter, r *http.Request) {
		var books []Book
		cursor, err := bookCollection.Find(ctx, bson.M{})
		if err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return
		}
		defer cursor.Close(ctx)
		for cursor.Next(ctx) {
			var book Book
			if err := cursor.Decode(&book); err != nil {
				http.Error(w, err.Error(), http.StatusInternalServerError)
				return
			}
			books = append(books, book)
		}
		json.NewEncoder(w).Encode(books)
	}).Methods("GET")

	router.HandleFunc("/api/v1/books", func(w http.ResponseWriter, r *http.Request) {
		var book Book
		if err := json.NewDecoder(r.Body).Decode(&book); err != nil {
			http.Error(w, err.Error(), http.StatusBadRequest)
			return
		}
		result, err := bookCollection.InsertOne(ctx, book)
		if err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return
		}
		json.NewEncoder(w).Encode(result)
	}).Methods("POST")

	router.HandleFunc("/api/v1/books/{id}", func(w http.ResponseWriter, r *http.Request) {
		id := mux.Vars(r)["id"]
		var book Book
		if err := bookCollection.FindOne(ctx, bson.M{"_id": id}).Decode(&book); err != nil {
			http.Error(w, err.Error(), http.StatusNotFound)
			return
		}
		json.NewEncoder(w).Encode(book)
	}).Methods("GET")

	router.HandleFunc("/api/v1/books/{id}", func(w http.ResponseWriter, r *http.Request) {
		id := mux.Vars(r)["id"]
		var book Book
		if err := json.NewDecoder(r.Body).Decode(&book); err != nil {
			http.Error(w, err.Error(), http.StatusBadRequest)
			return
		}
		result, err := bookCollection.UpdateOne(ctx, bson.M{"_id": id}, bson.M{"$set": book})
		if err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return
		}
		json.NewEncoder(w).Encode(result)
	}).Methods("PUT")

	router.HandleFunc("/api/v1/books/{id}", func(w http.ResponseWriter, r *http.Request) {
		id := mux.Vars(r)["id"]
		result, err := bookCollection.DeleteOne(ctx, bson.M{"_id": id})
		if err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return
		}
		json.NewEncoder(w).Encode(result)
	}).Methods("DELETE")

	return &Server{
		Router:      router,
		Options:     options,
		MongoClient: mongoClient,
		Logger:      logger,
		SmtpClient:  smtpClient,
	}
}

func main() {
	ctx := context.Background()
	options := LoadOptions()
	server := New(ctx, options)
	server.Start(ctx)
}
