package main

import (
	"encoding/json"
	"errors"
	"fmt"
	"net/http"
	"strings"
	"time"

	"github.com/golang-jwt/jwt/v4"
)

// User represents a user model in the application.
type User struct {
	AccessID string
}

// AppConfig holds the application configuration.
type AppConfig struct {
	Secret          string
	AccessTTLHour   int
}

// Global variable to simulate fetching configuration.
var appConfig = AppConfig{
	Secret:        "my_secret_key",
	AccessTTLHour: 24,
}

// Constants for JWT claims.
const (
	KeyUserID       = "id"
	KeyTokenExpired = "exp"
)

// GenerateToken creates a JWT for the given user with an expiration time.
func GenerateToken(user *User) (string, error) {
	token := jwt.New(jwt.SigningMethodHS256)
	claims := token.Claims.(jwt.MapClaims)
	claims[KeyUserID] = user.AccessID
	claims[KeyTokenExpired] = time.Now().Add(time.Hour * time.Duration(appConfig.AccessTTLHour)).Unix()
	signedToken, err := token.SignedString([]byte(appConfig.Secret))
	if err != nil {
		return "", err
	}
	return signedToken, nil
}

// Authenticate is a middleware that validates the JWT in the Authorization header of the request.
func Authenticate(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		extractToken := func() string {
			bearerToken := r.Header.Get("Authorization")
			strArr := strings.Split(bearerToken, " ")
			if len(strArr) == 2 {
				return strArr[1]
			}
			return ""
		}
		if r.Header["Authorization"] != nil {
			tokenString := extractToken()
			token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
				if _, ok := token.Method.(*jwt.SigningMethodHMAC); !ok {
					return nil, errors.New("invalid authorization token")
				}
				return []byte(appConfig.Secret), nil
			})
			if err != nil {
				w.WriteHeader(http.StatusUnauthorized)
				json.NewEncoder(w).Encode(err)
				return
			}
			if token.Valid {
				next.ServeHTTP(w, r)
			} else {
				w.WriteHeader(http.StatusUnauthorized)
				json.NewEncoder(w).Encode(errors.New("invalid authorization token"))
			}
		} else {
			w.WriteHeader(http.StatusUnauthorized)
			json.NewEncoder(w).Encode(errors.New("an authorization header is required"))
		}
	})
}

// Test cases to verify the solution correctness.
func main() {
	// Test case 1: Generate a token for a user.
	user := User{AccessID: "12345"}
	token, err := GenerateToken(&user)
	if err != nil {
		fmt.Println("Error generating token:", err)
	} else {
		fmt.Println("Generated token:", token)
	}

	// Test case 2: Middleware usage example.
	http.Handle("/", Authenticate(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		fmt.Fprintln(w, "Hello, authenticated user!")
	})))

	// Start the server (for testing purposes, you can send requests to localhost:8080).
	fmt.Println("Starting server on :8080")
	http.ListenAndServe(":8080", nil)
}
