package wordbreak2

import (
	"strings"
)

// wordBreak returns all possible sentences where each word is a valid word from wordDict.
func wordBreak(s string, wordDict []string) []string {
	wordDictSet := make(map[string]bool)
	for _, word := range wordDict {
		wordDictSet[word] = true
	}

	var sentences []string
	var backtrack func(int, []string)
	backtrack = func(index int, path []string) {
		if index == len(s) {
			sentences = append(sentences, strings.Join(path, " "))
			return
		}
		for end := index + 1; end <= len(s); end++ {
			word := s[index:end]
			if wordDictSet[word] {
				backtrack(end, append(path, word))
			}
		}
	}

	backtrack(0, []string{})
	return sentences
}

