// Optimized golang implementation of the Sieve of Eratosthenes using bit vector
// Author: Your Name

package main

import (
	"flag"
	"fmt"
	"math"
	"time"
)

// BitVector represents a slice of uint64 to use as a bit vector for the sieve
type BitVector []uint64

// NewBitVector creates a new BitVector with enough bits to cover the range up to max
func NewBitVector(max int) BitVector {
	return make(BitVector, (max+63)/64)
}

// Set marks the bit at index i as 1 (non-prime)
func (bv BitVector) Set(i int) {
	bv[i/64] |= 1 << (i % 64)
}

// IsSet checks if the bit at index i is set (non-prime)
func (bv BitVector) IsSet(i int) bool {
	return bv[i/64]&(1<<(i%64)) != 0
}

// SieveOptimized uses a bit vector to find all prime numbers up to max
func SieveOptimized(max int) []int {
	bitVector := NewBitVector(max)
	sqrtMax := int(math.Sqrt(float64(max)))

	for p := 2; p <= sqrtMax; p++ {
		if !bitVector.IsSet(p) {
			for i := p * p; i <= max; i += p {
				bitVector.Set(i)
			}
		}
	}

	var primes []int
	for p := 2; p <= max; p++ {
		if !bitVector.IsSet(p) {
			primes = append(primes, p)
		}
	}
	return primes
}

func main() {
	var startTime time.Time

	maximum := flag.Int("max", 1000000, "Maximum number in range to search for primes")
	dumpPrimes := flag.Bool("dump-prime", false, "Dump the list of prime numbers located")
	timeExecution := flag.Bool("timing", false, "Dump the execution time")
	flag.Parse()

	if *maximum < 2 {
		fmt.Printf("Maximum must be a number larger than 1\n")
		flag.PrintDefaults()
		return
	}

	if *timeExecution {
		startTime = time.Now()
	}

	results := SieveOptimized(*maximum)

	if *timeExecution {
		fmt.Printf("Took %s to find all primes up to %d\n", time.Since(startTime), *maximum)
	}
	fmt.Printf("Found %d prime numbers up to %d\n", len(results), *maximum)

	if *dumpPrimes {
		fmt.Printf("Prime numbers up to %d:\n", *maximum)
		for i, p := range results {
			fmt.Printf("\t[%d]: %d\n", i, p)
		}
	}
}
