// Status represents the status of an event.
type Status int

// Define constants for different event statuses.
const (
	StatusOngoing Status = iota
	StatusDone
	StatusNeutral
)

// Event represents an event with a status, description, and text color.
type Event struct {
	Status      Status
	Description string
	TextColor   color.Color
}

// New creates a new Event with the given status and description.
func New(status Status, description string) Event {
	var textColor color.Color
	switch status {
	case StatusDone:
		textColor = color.Green
	case StatusOngoing:
		textColor = color.Yellow
	case StatusNeutral:
		textColor = color.Gray
	default:
		textColor = color.Gray
	}
	return Event{
		Status:      status,
		Description: description,
		TextColor:   textColor,
	}
}

// Text returns the event description with the appropriate color rendering.
func (e Event) Text() string {
	if e.Status == StatusOngoing {
		return e.TextColor.Render(e.Description + "...")
	}
	return e.TextColor.Render(e.Description)
}

// Bus represents an event bus that can send and receive events.
type Bus struct {
	events chan Event
}

// NewBus creates a new event bus.
func NewBus() *Bus {
	return &Bus{
		events: make(chan Event),
	}
}

// Send sends an event to the event bus.
func (b *Bus) Send(event Event) {
	b.events <- event
}

// Events returns a channel from which events can be received.
func (b *Bus) Events() <-chan Event {
	return b.events
}

// Shutdown shuts down the event bus and closes the event channel.
func (b *Bus) Shutdown() {
	close(b.events)
}

