// NewLogger creates a new zap.SugaredLogger instance
func NewLogger(env, level, path string) *zap.SugaredLogger {
	var logger *zap.Logger

	if env == "production" {
		logger = productionLogger(level, path)
	} else {
		logger = developmentLogger(level, path)
	}

	defer logger.Sync()
	return logger.Sugar()
}

// set production logger defaults
func productionLogger(level, path string) *zap.Logger {
	atomicLevel := zap.NewAtomicLevel()
	atomicLevel.UnmarshalText([]byte(level))

	cfg := zap.Config{
		Encoding:         "json",
		Development:      false,
		Level:            atomicLevel,
		OutputPaths:      []string{path},
		ErrorOutputPaths: []string{path},
		EncoderConfig: zapcore.EncoderConfig{
			MessageKey:   "message",
			LevelKey:     "level",
			EncodeLevel:  zapcore.CapitalLevelEncoder,
			TimeKey:      "time",
			EncodeTime:   zapcore.ISO8601TimeEncoder,
			CallerKey:    "caller",
			EncodeCaller: zapcore.ShortCallerEncoder,
		},
	}
	l, _ := cfg.Build()
	return l
}

// set development logger defaults
func developmentLogger(level, path string) *zap.Logger {
	atomicLevel := zap.NewAtomicLevel()
	atomicLevel.UnmarshalText([]byte(level))

	cfg := zap.Config{
		Encoding:         "console",
		Development:      true,
		Level:            atomicLevel,
		OutputPaths:      []string{path},
		ErrorOutputPaths: []string{path},
		EncoderConfig: zapcore.EncoderConfig{
			MessageKey:   "message",
			LevelKey:     "level",
			EncodeLevel:  zapcore.CapitalColorLevelEncoder,
			TimeKey:      "time",
			EncodeTime:   zapcore.ISO8601TimeEncoder,
			CallerKey:    "caller",
			EncodeCaller: zapcore.ShortCallerEncoder,
		},
	}
	l, _ := cfg.Build()
	return l
}

