type Account struct {
	PrivKey secp256k1.PrivKey
	Address string
	Number  uint64
	Nonce   uint64
}

type Context struct {
	API        string
	GRPCClient grpc.ClientConnInterface
}

func NewAccount(ctx Context, privKey string, addr string) *Account {
	privKeyBytes, _ := hex.DecodeString(privKey)
	key := secp256k1.PrivKey{Key: privKeyBytes}

	number, nonce := getAccountNumberAndNonce(ctx, addr)
	account := &Account{
		PrivKey: key,
		Address: addr,
		Number:  number,
		Nonce:   nonce,
	}
	Accounts = append(Accounts, account)
	return account
}

func (acc *Account) WithNumber(number uint64) *Account {
	acc.Number = number
	return acc
}

func (acc *Account) WithNonce(nonce uint64) *Account {
	acc.Nonce = nonce
	return acc
}

func QueryAccount(ctx Context, address string) (*authtypes.QueryAccountResponse, error) {
	authClient := authtypes.NewQueryClient(ctx.GRPCClient)
	authRes, err := authClient.Account(
		context.Background(),
		&authtypes.QueryAccountRequest{Address: address},
	)
	return authRes, err
}

type Response struct {
	Account AccountResponse `json:"account"`
}
type AccountResponse struct {
	Type            string `json:"@type"`
	Address         string `json:"address"`
	PubKey          PubKey `json:"pub_key"`
	AccountNumber   string `json:"account_number"`
	AccountSequence string `json:"sequence"`
}
type PubKey struct {
	Type string `json:"@type"`
	Key  string `json:"key"`
}

func getAccountNumberAndNonce(ctx Context, addr string) (uint64, uint64) {
	req := fmt.Sprintf("%v/%v", ctx.API, addr)
	rsp, err := http.Get(req)
	if err != nil {
		fmt.Println(err)
		return 0, 0
	}
	defer rsp.Body.Close()
	responseData, err := ioutil.ReadAll(rsp.Body)
	if err != nil {
		log.Fatal(err)
	}

	var response Response
	json.Unmarshal(responseData, &response)

	account := response
	number, _ := strconv.ParseUint(account.Account.AccountNumber, 10, 64)
	sequence, _ := strconv.ParseUint(account.Account.AccountSequence, 10, 64)

	return number, sequence
}

func main() {
	// Example usage:
	ctx := Context{
		API:        Url,
		GRPCClient: nil, // Assume a valid gRPC client connection is provided here
	}

	// Create a new account
	privKey := "your_private_key_in_hex_format"
	addr := "cosmos1..."
	account := NewAccount(ctx, privKey, addr)

	// Query account details
	accountDetails, err := QueryAccount(ctx, account.Address)
	if err != nil {
		log.Fatalf("Failed to query account: %v", err)
	}
	fmt.Printf("Account details: %+v\n", accountDetails)

	// Update account number and nonce
	account.WithNumber(123).WithNonce(456)
	fmt.Printf("Updated account: %+v\n", account)
}
