package main

import (
	"bufio"
	"bytes"
	"encoding/json"
	"fmt"
	"os"
)

type Person struct {
	Name string
	Age  byte
	pin  int // this will not be included in encoding and decoding JSON, only uppercase fields will be there
}

func SavePersonToFile(person Person, filename string) error {
	bs, err := json.Marshal(person)
	if err != nil {
		return fmt.Errorf("error while encoding Person object: %v", err)
	}
	f, err := os.Create(filename)
	if err != nil {
		return fmt.Errorf("error while creating file: %v", err)
	}
	defer f.Close()
	bw := bufio.NewWriter(f)
	_, err = bw.Write(bs)
	if err != nil {
		return fmt.Errorf("error while writing to file: %v", err)
	}
	return bw.Flush()
}

func ReadPersonFromFile(filename string) (Person, error) {
	var person Person
	f, err := os.Open(filename)
	if err != nil {
		return person, fmt.Errorf("error while opening file: %v", err)
	}
	defer f.Close()
	br := bufio.NewReader(f)
	bs, err := br.ReadBytes('\n')
	if err != nil {
		return person, fmt.Errorf("error while reading from file: %v", err)
	}
	err = json.Unmarshal(bs, &person)
	if err != nil {
		return person, fmt.Errorf("error while decoding JSON: %v", err)
	}
	return person, nil
}

func PrintJSONString(person Person) {
	bs, err := json.Marshal(person)
	if err != nil {
		fmt.Println("Error while encoding Person object")
		return
	}
	jsonString := bytes.NewBuffer(bs).String()
	fmt.Println(jsonString)
}

func DecodeUnknownJSON(jsonString string) {
	var obj interface{}
	if err := json.Unmarshal([]byte(jsonString), &obj); err != nil {
		fmt.Println("Error while decoding unknown JSON:", err)
		return
	}
	if m, ok := obj.(map[string]interface{}); ok {
		fmt.Printf("{\n")
		for k, v := range m {
			fmt.Printf("\t%v: %v,\n", k, v)
		}
		fmt.Printf("}\n")
	} else {
		fmt.Println("map[string]interface{} type not found!")
	}
}

