// Hey returns Bob's response to a remark.
func Hey(remark string) string {
	remarkStripped := strings.TrimSpace(remark)
	remarkRunes := []rune(remarkStripped)
	if len(remarkRunes) == 0 {
		return "Fine. Be that way!"
	}
	yellingp := remarkStripped == strings.ToUpper(remarkStripped) &&
		strings.ContainsAny(remarkStripped, upperAlphabet)
	questionp := remarkRunes[len(remarkRunes)-1] == '?'
	switch {
	case yellingp && questionp:
		return "Calm down, I know what I'm doing!"
	case yellingp:
		return "Whoa, chill out!"
	case questionp:
		return "Sure."
	}
	return "Whatever."
}

// Test cases to verify the solution
func main() {
	// Test case 1: Yelling a question
	println(Hey("IS THIS A QUESTION?")) // Expected: "Calm down, I know what I'm doing!"

	// Test case 2: Yelling
	println(Hey("THIS IS YELLING!")) // Expected: "Whoa, chill out!"

	// Test case 3: Asking a question
	println(Hey("Is this a question?")) // Expected: "Sure."

	// Test case 4: Saying nothing
	println(Hey("   ")) // Expected: "Fine. Be that way!"

	// Test case 5: Anything else
	println(Hey("This is a statement.")) // Expected: "Whatever."

	// Test case 6: Yelling without alphabetic characters
	println(Hey("12345!")) // Expected: "Whatever."

	// Test case 7: Trailing whitespace with a question
	println(Hey("Is this a question?   ")) // Expected: "Sure."
