// RunBySS simulates the stream splitter processing.
func (d *Data) RunBySS() error {
	// Simulate processing the data.
	// For example, concatenate RawData and SSConfData.
	d.ResultData = append(d.RawData, d.SSConfData...)
	// Simulate a condition where processing could fail.
	if len(d.RawData) == 0 {
		return errors.New("no raw data provided")
	}
	return nil
}

// Define the ProcessController with Beego's Controller embedded.
type ProcessController struct {
	beego.Controller
}

// Semaphore is a channel that acts as a counting semaphore.
var Semaphore = make(chan struct{}, 1)

// Get renders the form for submitting data.
func (c *ProcessController) Get() {
	c.TplName = "home.tpl"
	c.Render()
}

// Post processes the submitted data using the stream splitter.
func (c *ProcessController) Post() {
	inputs := c.Input()

	data := &Data{
		RawData:    []byte(inputs["inputtext"][0]),
		SSConfData: []byte(inputs["applicationconf"][0]),
	}

	// Enter the critical section by acquiring the semaphore.
	Semaphore <- struct{}{}
	err := data.RunBySS()
	<-Semaphore // Release the semaphore.

	if err != nil {
		c.Data["error"] = err.Error()
	} else {
		c.Data["output"] = string(data.ResultData)
	}

	c.TplName = "home.tpl"
	c.Render()
}

