		"Ford":    {"Henry", "Ford"},
		"Mouse":   {"Mickey", "Mouse"},
		"Jackson": {"Michael", "Jackson"},
	}
	fmt.Println("Sort the user directory by key:")
	sortUserDirectoryByKey(userDirectory)

	playerScores := map[string]Player{
		"anna": {"Anna", 42},
		"bob":  {"Bob", 12},
	}
	fmt.Println("\nIncrement player score:")
	incrementPlayerScore(playerScores, "anna")
	fmt.Println("Anna's score:", playerScores["anna"].Score)

	fmt.Println("\nDemonstrate map reference type:")
	deleteUserFromDirectory(userDirectory, "Mouse")
	fmt.Println("User directory after deletion:", userDirectory)

	fmt.Println("\nDouble player score:")
	doublePlayerScore(playerScores, "bob")
	fmt.Println("Bob's score:", playerScores["bob"].Score)
}

func sortUserDirectoryByKey(userDirectory map[string]User) {
	var keys []string
	for k := range userDirectory {
		keys = append(keys, k)
	}
	sort.Strings(keys)
	for _, k := range keys {
		u := userDirectory[k]
		fmt.Printf("Key: %s, Name: %s %s\n", k, u.Name, u.Surname)
	}
}

func incrementPlayerScore(playerScores map[string]Player, key string) {
	player := playerScores[key]
	player.Score++
	playerScores[key] = player
}

func deleteUserFromDirectory(userDirectory map[string]User, key string) {
	delete(userDirectory, key)
}

func doublePlayerScore(playerScores map[string]Player, key string) {
	player := playerScores[key]
	player.Score *= 2
	playerScores[key] = player
}
