package main

import (
	"fmt"
	"sync"
)

// QueryType represents the type of attribute being queried.
type QueryType int

const (
	Attack QueryType = iota
	Defense
)

// Query represents a request to get the value of a creature's attribute.
type Query struct {
	CreatureName string
	WhatToQuery  QueryType
	Value        int
}

// Subscription is an interface for modifiers that can subscribe to game events.
type Subscription interface {
	Handle(*Query)
	Close() error
}

// Game represents the central event system for queries.
type Game struct {
	mu          sync.Mutex
	subscribers []Subscription
}

// Subscribe adds a new subscriber to the game.
func (g *Game) Subscribe(s Subscription) {
	g.mu.Lock()
	defer g.mu.Unlock()
	g.subscribers = append(g.subscribers, s)
}

// Unsubscribe removes a subscriber from the game.
func (g *Game) Unsubscribe(s Subscription) {
	g.mu.Lock()
	defer g.mu.Unlock()
	for i, subscriber := range g.subscribers {
		if subscriber == s {
			g.subscribers = append(g.subscribers[:i], g.subscribers[i+1:]...)
			break
		}
	}
}

// Fire sends a query to all subscribers.
func (g *Game) Fire(q *Query) {
	g.mu.Lock()
	defer g.mu.Unlock()
	for _, subscriber := range g.subscribers {
		subscriber.Handle(q)
	}
}

// Creature represents a game creature with attack and defense attributes.
type Creature struct {
	game            *Game
	Name            string
	attack, defense int
}

// NewCreature creates a new creature with the given attributes.
func NewCreature(game *Game, name string, attack, defense int) *Creature {
	return &Creature{game: game, Name: name, attack: attack, defense: defense}
}

// Attack returns the creature's attack value after applying modifiers.
func (c *Creature) Attack() int {
	q := Query{c.Name, Attack, c.attack}
	c.game.Fire(&q)
	return q.Value
}

// Defense returns the creature's defense value after applying modifiers.
func (c *Creature) Defense() int {
	q := Query{c.Name, Defense, c.defense}
	c.game.Fire(&q)
	return q.Value
}

// String returns a string representation of the creature.
func (c *Creature) String() string {
	return fmt.Sprintf("%s (%d/%d)", c.Name, c.Attack(), c.Defense())
}

// CreatureModifier is a base struct for creature modifiers.
type CreatureModifier struct {
	game     *Game
	creature *Creature
}

// Handle is a no-op for the base modifier.
func (c *CreatureModifier) Handle(*Query) {
	// nothing here!
}

// DoubleAttackModifier doubles a creature's attack value.
type DoubleAttackModifier struct {
	CreatureModifier
}

// NewDoubleAttackModifier creates a new DoubleAttackModifier.
func NewDoubleAttackModifier(g *Game, c *Creature) *DoubleAttackModifier {
	d := &DoubleAttackModifier{CreatureModifier{g, c}}
	g.Subscribe(d)
	return d
}

// Handle applies the double attack modifier to the query.
func (d *DoubleAttackModifier) Handle(q *Query) {
	if q.CreatureName == d.creature.Name && q.WhatToQuery == Attack {
		q.Value *= 2
	}
}

// Close unsubscribes the modifier from the game.
func (d *DoubleAttackModifier) Close() error {
	d.game.Unsubscribe(d)
	return nil
}

// IncreaseDefenseModifier increases a creature's defense value by a specified amount.
type IncreaseDefenseModifier struct {
	CreatureModifier
	increase int
}

// NewIncreaseDefenseModifier creates a new IncreaseDefenseModifier.
func NewIncreaseDefenseModifier(g *Game, c *Creature, increase int) *IncreaseDefenseModifier {
	m := &IncreaseDefenseModifier{CreatureModifier{g, c}, increase}
	g.Subscribe(m)
	return m
}

// Handle applies the defense increase modifier to the query.
func (m *IncreaseDefenseModifier) Handle(q *Query) {
	if q.CreatureName == m.creature.Name && q.WhatToQuery == Defense {
		q.Value += m.increase
	}
}

// Close unsubscribes the modifier from the game.
func (m *IncreaseDefenseModifier) Close() error {
	m.game.Unsubscribe(m)
	return nil
}

func main() {
	game := &Game{}
	goblin := NewCreature(game, "Goblin", 2, 2)
	fmt.Println(goblin)

	dam := NewDoubleAttackModifier(game, goblin)
	fmt.Println(goblin)

	defm := NewIncreaseDefenseModifier(game, goblin, 1)
	fmt.Println(goblin)

	dam.Close()
	fmt.Println(goblin)

	defm.Close()
	fmt.Println(goblin)
}
