	"time"
)

// CheckDockerAccess checks for unauthorized access to Docker daemons on the given IP and ports.
// It returns a slice of accessible URLs and a boolean indicating if any unauthorized access was found.
func CheckDockerAccess(ip string, ports []string, timeOut time.Duration) ([]string, bool) {
	accessibleURLs := make([]string, 0)
	if len(ports) == 0 {
		ports = []string{"2375"}
	}

	if timeOut <= 0 {
		timeOut = time.Second * 1
	}

	for _, port := range ports {
		url := fmt.Sprintf("http://%s:%s/", ip, port)
		client := http.Client{
			Timeout: timeOut,
		}
		resp, err := client.Get(url)
		if err == nil && resp.StatusCode == http.StatusOK {
			accessibleURLs = append(accessibleURLs, url)
		}
		if resp != nil {
			resp.Body.Close()
		}
	}

	return accessibleURLs, len(accessibleURLs) > 0
}

func main() {
	// Test cases
	ip := "192.168.1.10"
	ports := []string{"2375", "2376"}
	timeout := time.Second * 2

	accessibleURLs, unauthorizedAccess := CheckDockerAccess(ip, ports, timeout)
	if unauthorizedAccess {
		fmt.Println("Unauthorized Docker access found on the following URLs:")
		for _, url := range accessibleURLs {
			fmt.Println(url)
		}
	} else {
		fmt.Println("No unauthorized Docker access found.")
	}
}
