// GetObject retrieves an object from the datastore and unmarshals it into the provided dest struct.
// It returns the keys that were accessed and any error encountered.
func GetObject(ctx context.Context, ds datastore.Datastore, key string, dest interface{}) ([]string, error) {
	data, keys, err := ds.Get(ctx, []string{key})
	if err != nil {
		return nil, err
	}

	value, ok := data[key]
	if !ok {
		return keys, errors.New("key not found in datastore")
	}

	err = json.Unmarshal([]byte(value), dest)
	if err != nil {
		return keys, err
	}

	return keys, nil
}

// UpdateObject marshals the src struct into a JSON string and updates the datastore at the given key.
// It returns any error encountered.
func UpdateObject(ctx context.Context, ds datastore.Datastore, key string, src interface{}) error {
	data, err := json.Marshal(src)
	if err != nil {
		return err
	}

	return ds.Set(ctx, map[string]string{key: string(data)})
}

func main() {
	// Mock datastore setup
	closed := make(chan struct{})
	defer close(closed)
	ds := dsmock.NewMockDatastore(closed, map[string]string{
		"testmodel/1": `{"id":1,"name":"Test Model","tags":["go","programming"]}`,
	})

	// Define a struct that matches the expected data
	type TestModel struct {
		ID   int      `json:"id"`
		Name string   `json:"name"`
		Tags []string `json:"tags"`
	}

	// Retrieve and unmarshal the object
	var model TestModel
	keys, err := GetObject(context.Background(), ds, "testmodel/1", &model)
	if err != nil {
		fmt.Printf("Error retrieving object: %v\n", err)
		return
	}
	fmt.Printf("Retrieved object with keys: %v\n", keys)
	fmt.Printf("Model: %+v\n", model)

	// Update the object
	model.Tags = append(model.Tags, "datastore")
	err = UpdateObject(context.Background(), ds, "testmodel/1", model)
	if err != nil {
		fmt.Printf("Error updating object: %v\n", err)
		return
	}
	fmt.Println("Object updated successfully.")
}
