package main

import (
	"image"
	"image/color"
	"image/png"
	"io"
	"os"
)

// ImgData holds the image data.
type ImgData struct {
	Img image.Image
}

// Png populates image data using the given reader.
// The Reader r is expected to be opened and closed by the caller.
// A successful import replaces the image in ImgData with a new image.
func Png(r io.Reader, d *ImgData) (err error) {
	d.Img, err = png.Decode(r)
	return err
}

// ToGrayscale converts the image in ImgData to grayscale.
func (d *ImgData) ToGrayscale() {
	bounds := d.Img.Bounds()
	grayImg := image.NewGray(bounds)

	for y := bounds.Min.Y; y < bounds.Max.Y; y++ {
		for x := bounds.Min.X; x < bounds.Max.X; x++ {
			originalColor := d.Img.At(x, y)
			r, g, b, _ := originalColor.RGBA()
			grayValue := uint8((r + g + b) / 3 >> 8) // Average RGB and shift to 8-bit
			grayColor := color.Gray{Y: grayValue}
			grayImg.Set(x, y, grayColor)
		}
	}

	d.Img = grayImg
}

// SaveImage saves the image in ImgData to the specified file.
func (d *ImgData) SaveImage(filename string) error {
	file, err := os.Create(filename)
	if err != nil {
		return err
	}
	defer file.Close()

	return png.Encode(file, d.Img)
}

func main() {
	// Example usage:
	inputFilename := "input.png"
	outputFilename := "output.png"

	// Open the input file
	file, err := os.Open(inputFilename)
	if err != nil {
		panic(err)
	}
	defer file.Close()

	// Decode the PNG image
	imgData := &ImgData{}
	if err := Png(file, imgData); err != nil {
		panic(err)
	}

	// Convert to grayscale
	imgData.ToGrayscale()

	// Save the grayscale image
	if err := imgData.SaveImage(outputFilename); err != nil {
		panic(err)
	}
}
