package wss

import (
	"bytes"
	"io"
	"net/http"
	"net/url"
	"strings"
)

// Requester is an interface that defines methods to get headers, body, and parameters from an HTTP request.
type Requester interface {
	GetHeaders() map[string]string
	GetHeaderByName(name string) string
	GetBody() []byte
	GetParameters() map[string]string
	GetParameterByName(name string) string
}

// Request is a struct that implements the Requester interface and wraps an http.Request.
type Request struct {
	originRequest *http.Request
	body          io.ReadCloser
	headers       map[string]string
	parameters    map[string]string
}

// setHeaders parses the headers from the original request and stores them.
func (r *Request) setHeaders() {
	httpHeader := r.originRequest.Header
	r.headers = make(map[string]string)
	for name, values := range httpHeader {
		r.headers[name] = strings.Join(values, ",")
	}
}

// setRequestBody reads the request body and stores it, allowing for reuse if specified.
func (r *Request) setRequestBody(reused bool) {
	if reused {
		bytesBody, _ := io.ReadAll(r.originRequest.Body)
		r.originRequest.Body.Close() // Close the original body
		reader := io.NopCloser(bytes.NewBuffer(bytesBody))
		r.body = reader
		r.originRequest.Body = reader // Replace the original body with the reusable reader
	} else {
		r.body = r.originRequest.Body
	}
}

// setParameters parses the query parameters from the original request URL and stores them.
func (r *Request) setParameters() {
	queryValues := r.originRequest.URL.Query()
	r.parameters = make(map[string]string)
	for key, values := range queryValues {
		r.parameters[key] = strings.Join(values, ",")
	}
}

// GetHeaders returns the headers of the request.
func (r *Request) GetHeaders() map[string]string {
	return r.headers
}

// GetHeaderByName returns the value of a specific header by name.
func (r *Request) GetHeaderByName(name string) string {
	return r.headers[name]
}

// GetBody returns the body of the request as a byte slice.
func (r *Request) GetBody() []byte {
	bytesBody, _ := io.ReadAll(r.body)
	return bytesBody
}

// GetParameters returns a map of all query parameters key-value pairs.
func (r *Request) GetParameters() map[string]string {
	return r.parameters
}

// GetParameterByName returns the value of a specific query parameter by name.
func (r *Request) GetParameterByName(name string) string {
	return r.parameters[name]
}

// NewRequest creates a new Request object from an http.Request and initializes headers, body, and parameters.
func NewRequest(httpReq *http.Request, reused bool) *Request {
	req := &Request{originRequest: httpReq}
	req.setHeaders()
	req.setRequestBody(reused)
	req.setParameters()
	return req
}

// Test cases to verify the solution correctness
func main() {
	// Mock an http.Request
	httpReq, _ := http.NewRequest("GET", "http://example.com?foo=bar&baz=qux", strings.NewReader("request body"))
	httpReq.Header.Add("Content-Type", "application/json")
	httpReq.Header.Add("User-Agent", "Go-http-client/1.1")

	// Create a new Request object
	req := NewRequest(httpReq, true)

	// Test GetHeaders
	headers := req.GetHeaders()
	if headers["Content-Type"] != "application/json" {
		panic("GetHeaders does not return correct header values")
	}

	// Test GetHeaderByName
	contentType := req.GetHeaderByName("Content-Type")
	if contentType != "application/json" {
		panic("GetHeaderByName does not return correct header value")
	}

	// Test GetBody
	body := req.GetBody()
	if string(body) != "request body" {
		panic("GetBody does not return correct body content")
	}

	// Test GetParameters
	parameters := req.GetParameters()
	if parameters["foo"] != "bar" || parameters["baz"] != "qux" {
		panic("GetParameters does not return correct parameters")
	}

	// Test GetParameterByName
	fooValue := req.GetParameterByName("foo")
	if fooValue != "bar" {
		panic("GetParameterByName does not return correct parameter value")
	}

	// Output: No panic means all tests passed
}
