// LightsailStaticIpAttachmentManager manages the attachment of static IPs to Lightsail instances.
type LightsailStaticIpAttachmentManager struct {
	// In-memory map to simulate the attachment of static IPs to instances.
	// Key: static IP name, Value: instance name.
	attachments map[string]string
}

// AttachStaticIp attaches a static IP to a Lightsail instance.
func (manager *LightsailStaticIpAttachmentManager) AttachStaticIp(instanceName string, staticIpName string) error {
	if err := manager.validateInstanceName(instanceName); err != nil {
		return err
	}
	if err := manager.validateStaticIpName(staticIpName); err != nil {
		return err
	}
	if _, exists := manager.attachments[staticIpName]; exists {
		return fmt.Errorf("static IP '%s' is already attached to an instance", staticIpName)
	}
	manager.attachments[staticIpName] = instanceName
	return nil
}

// DetachStaticIp detaches a static IP from the instance it's attached to.
func (manager *LightsailStaticIpAttachmentManager) DetachStaticIp(staticIpName string) error {
	if err := manager.validateStaticIpName(staticIpName); err != nil {
		return err
	}
	if _, exists := manager.attachments[staticIpName]; !exists {
		return fmt.Errorf("static IP '%s' is not attached to any instance", staticIpName)
	}
	delete(manager.attachments, staticIpName)
	return nil
}

// validateInstanceName validates the instance name.
func (manager *LightsailStaticIpAttachmentManager) validateInstanceName(instanceName string) error {
	if instanceName == "" {
		return errors.New("instance name cannot be empty")
	}
