package main

import (
	"fmt"
	"errors"
)

const (
	// FlashArray is a constant for the name of the product
	FlashArray = "FlashArray"
	// FlashBlade is a constant for the name of the product
	FlashBlade = "FlashBlade"
)

// Inventory represents the stock of products in the tech store.
type Inventory struct {
	stock map[string]int
}

// NewInventory initializes the inventory with the given quantities.
func NewInventory(flashArrayQty, flashBladeQty int) *Inventory {
	return &Inventory{
		stock: map[string]int{
			FlashArray: flashArrayQty,
			FlashBlade: flashBladeQty,
		},
	}
}

// AddStock adds the specified quantity to the product's stock.
func (inv *Inventory) AddStock(product string, qty int) error {
	if qty < 0 {
		return errors.New("quantity to add must be non-negative")
	}
	if _, exists := inv.stock[product]; !exists {
		return fmt.Errorf("product %s does not exist in inventory", product)
	}
	inv.stock[product] += qty
	return nil
}

// DeductStock deducts the specified quantity from the product's stock.
func (inv *Inventory) DeductStock(product string, qty int) error {
	if qty < 0 {
		return errors.New("quantity to deduct must be non-negative")
	}
	if _, exists := inv.stock[product]; !exists {
		return fmt.Errorf("product %s does not exist in inventory", product)
	}
	if inv.stock[product] < qty {
		return errors.New("insufficient stock to complete the sale")
	}
	inv.stock[product] -= qty
	return nil
}

// DisplayStock prints the current stock for each product.
func (inv *Inventory) DisplayStock() {
	fmt.Println("Current Inventory Stock:")
	for product, qty := range inv.stock {
		fmt.Printf("%s: %d\n", product, qty)
	}
}

func main() {
	// Initialize inventory with 10 FlashArray and 5 FlashBlade products.
	inventory := NewInventory(10, 5)

	// Display initial stock.
	inventory.DisplayStock()

	// Add stock.
	err := inventory.AddStock(FlashArray, 5)
	if err != nil {
		fmt.Println("Error adding stock:", err)
	}

	// Deduct stock.
	err = inventory.DeductStock(FlashBlade, 3)
	if err != nil {
		fmt.Println("Error deducting stock:", err)
	}

	// Attempt to deduct more stock than available.
	err = inventory.DeductStock(FlashArray, 20)
	if err != nil {
		fmt.Println("Error deducting stock:", err)
	}

	// Display final stock.
	inventory.DisplayStock()
}
