	Age  int    `json:"age"`
}

// Define the struct for the Tools with the receiver methods
type Tools struct {
	MaxJSONSize        int64
	AllowedFileTypes   []string
	AllowUnknownFields bool
}

// Define the struct for the JSON response
type JSONResponse struct {
	Error   bool        `json:"error"`
	Message string      `json:"message"`
	Data    interface{} `json:"data,omitempty"`
}

// Define the method to read and validate JSON from an uploaded file
func (app *Tools) ReadJSONFromFile(w http.ResponseWriter, r *http.Request) error {
	file, header, err := r.FormFile("file")
	if err != nil {
		return err
	}
	defer file.Close()

	// Check file size
	if header.Size > app.MaxJSONSize {
		return errors.New("file size exceeds the maximum limit")
	}

	// Check file type
	contentType := header.Header.Get("Content-Type")
	if !contains(app.AllowedFileTypes, contentType) {
		return fmt.Errorf("file type '%s' is not allowed", contentType)
	}

	// Read file content
	fileBytes, err := ioutil.ReadAll(file)
	if err != nil {
		return err
	}

	// Unmarshal JSON
	var payload Payload
	if app.AllowUnknownFields {
		err = json.Unmarshal(fileBytes, &payload)
	} else {
		dec := json.NewDecoder(strings.NewReader(string(fileBytes)))
		dec.DisallowUnknownFields()
		err = dec.Decode(&payload)
	}

	if err != nil {
		return err
	}

	// Respond with the payload as a success message
	return app.WriteJSON(w, http.StatusOK, JSONResponse{
		Error:   false,
		Message: "File processed successfully",
		Data:    payload,
	})
}

// Define the method to write JSON response
func (app *Tools) WriteJSON(w http.ResponseWriter, status int, data JSONResponse) error {
	out, err := json.Marshal(data)
	if err != nil {
		return err
	}

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	_, err = w.Write(out)
	return err
}

// Define the method to write an error JSON response
func (app *Tools) ErrorJSON(w http.ResponseWriter, err error, status ...int) {
	statusCode := http.StatusBadRequest
	if len(status) > 0 {
		statusCode = status[0]
	}

	payload := JSONResponse{
		Error:   true,
		Message: err.Error(),
	}

	_ = app.WriteJSON(w, statusCode, payload)
}

// Helper function to check if a string is in a slice
func contains(slice []string, str string) bool {
	for _, v := range slice {
		if v == str {
			return true
		}
	}
	return false
}

// Define the handler for the upload endpoint
func uploadHandler(app *Tools) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		err := app.ReadJSONFromFile(w, r)
		if err != nil {
			app.ErrorJSON(w, err)
			return
		}
	}
}

func main() {
	// Initialize the Tools struct with some values
	app := Tools{
		MaxJSONSize:        1024 * 1024, // 1 MB
		AllowedFileTypes:   []string{"application/json"},
		AllowUnknownFields: false,
	}

	// Create a new router
	r := mux.NewRouter()

	// Define the route for the upload endpoint
	r.HandleFunc("/upload", uploadHandler(&app)).Methods("POST")

	// Start the server
	http.ListenAndServe(":8080", r)
}

// Test cases can be performed by sending POST requests to http://localhost:8080/upload with a form-data containing a file field.
