// InMemorySocietyRepository is a mock implementation of SocietyRepository using in-memory storage.
type InMemorySocietyRepository struct {
	societies map[int]*Society
	mu        sync.RWMutex
	nextID    int
}

// NewInMemorySocietyRepository creates a new instance of InMemorySocietyRepository.
func NewInMemorySocietyRepository() *InMemorySocietyRepository {
	return &InMemorySocietyRepository{
		societies: make(map[int]*Society),
		nextID:    1,
	}
}

// FindAll returns all societies in the repository.
func (r *InMemorySocietyRepository) FindAll() ([]*Society, error) {
	r.mu.RLock()
	defer r.mu.RUnlock()
	all := make([]*Society, 0, len(r.societies))
	for _, soc := range r.societies {
		all = append(all, soc)
	}
	return all, nil
}

// FindByID finds a society by its ID.
func (r *InMemorySocietyRepository) FindByID(id int) (*Society, error) {
	r.mu.RLock()
	defer r.mu.RUnlock()
	if soc, exists := r.societies[id]; exists {
		return soc, nil
	}
	return nil, errors.New("society not found")
}

// Create adds a new society to the repository.
func (r *InMemorySocietyRepository) Create(soc *Society) (int, error) {
	r.mu.Lock()
	defer r.mu.Unlock()
	soc.ID = r.nextID
	r.societies[soc.ID] = soc
	r.nextID++
	return soc.ID, nil
}

// UpdateByID updates an existing society.
func (r *InMemorySocietyRepository) UpdateByID(soc *Society) error {
	r.mu.Lock()
	defer r.mu.Unlock()
	if _, exists := r.societies[soc.ID]; exists {
		r.societies[soc.ID] = soc
		return nil
	}
	return errors.New("society not found")
}

// DeleteByID removes a society from the repository by its ID.
func (r *InMemorySocietyRepository) DeleteByID(id int) error {
	r.mu.Lock()
	defer r.mu.Unlock()
	if _, exists := r.societies[id]; exists {
		delete(r.societies, id)
		return nil
	}
	return errors.New("society not found")
}

