func V1UpdateTask(ctx context.Context, postgres PostgresDB) gin.HandlerFunc {
	return func(c *gin.Context) {
		username, password, ok := c.Request.BasicAuth()
		if !ok {
			c.JSON(http.StatusUnauthorized, HTTPError{
				Type:  "Unauthorized",
				Error: "Basic authentication required",
			})
			return
		}

		var u updateTaskURI
		if err := c.ShouldBindUri(&u); err != nil {
			c.JSON(http.StatusBadRequest, HTTPError{
				Type:    "InvalidParameter",
				Comment: "taskId must be a positive integer",
				Error:   err.Error(),
			})
			return
		}

		var b updateTaskBody
		if err := c.ShouldBindJSON(&b); err != nil {
			c.JSON(http.StatusBadRequest, HTTPError{
				Type:  "InvalidRequestBody",
				Error: err.Error(),
			})
			return
		}

		if utf8.RuneCountInString(b.Title) > maxLengthTaskTitle {
			c.JSON(http.StatusBadRequest, HTTPError{
				Type:    "ParameterTooLong",
				Comment: fmt.Sprintf("Title must not exceed %d characters", maxLengthTaskTitle),
