				return
			}
			c.JSON(http.StatusInternalServerError, HTTPError{
				Type:    "InternalServerError",
				Comment: "Failed to update task",
				Error:   err.Error(),
			})
			return
		}

		c.Status(http.StatusNoContent)
	}
