package main

import (
	"encoding/json"
	"errors"
	"fmt"
	"net/http"
	"sync"

	"github.com/google/uuid"
)

// User represents a user in the cinema system.
type User struct {
	ID    string `json:"id"`
	Name  string `json:"name"`
	Email string `json:"email"`
	Role  string `json:"role"`
}

// UsersResource is a collection of users.
type UsersResource struct {
	Data []User `json:"data"`
}

// UserResource represents a single user.
type UserResource struct {
	Data User `json:"data"`
}

// UserManager manages a list of users.
type UserManager struct {
	sync.RWMutex
	users map[string]User
}

// NewUserManager creates a new UserManager.
func NewUserManager() *UserManager {
	return &UserManager{
		users: make(map[string]User),
	}
}

// ListUsers returns all users.
func (m *UserManager) ListUsers() UsersResource {
	m.RLock()
	defer m.RUnlock()

	users := make([]User, 0, len(m.users))
	for _, user := range m.users {
		users = append(users, user)
	}
	return UsersResource{Data: users}
}

// CreateUser adds a new user to the manager.
func (m *UserManager) CreateUser(user User) (User, error) {
	m.Lock()
	defer m.Unlock()

	for _, u := range m.users {
		if u.Email == user.Email {
			return User{}, errors.New("user with the given email already exists")
		}
	}

	user.ID = uuid.New().String()
	m.users[user.ID] = user
	return user, nil
}

// UpdateUser updates an existing user.
func (m *UserManager) UpdateUser(id string, user User) (User, error) {
	m.Lock()
	defer m.Unlock()

	if _, exists := m.users[id]; !exists {
		return User{}, errors.New("user not found")
	}

	user.ID = id
	m.users[id] = user
	return user, nil
}

// DeleteUser removes a user from the manager.
func (m *UserManager) DeleteUser(id string) error {
	m.Lock()
	defer m.Unlock()

	if _, exists := m.users[id]; !exists {
		return errors.New("user not found")
	}

	delete(m.users, id)
	return nil
}

// Example usage of UserManager
func main() {
	userManager := NewUserManager()

	// Create a new user
	newUser, err := userManager.CreateUser(User{Name: "John Doe", Email: "john.doe@example.com", Role: "customer"})
	if err != nil {
		fmt.Println("Error creating user:", err)
		return
	}
	fmt.Println("Created user:", newUser)

	// Update the user
	updatedUser, err := userManager.UpdateUser(newUser.ID, User{Name: "John Doe Jr.", Email: "john.doe@example.com", Role: "customer"})
	if err != nil {
		fmt.Println("Error updating user:", err)
		return
	}
	fmt.Println("Updated user:", updatedUser)

	// List all users
	usersResource := userManager.ListUsers()
	usersJSON, _ := json.Marshal(usersResource)
	fmt.Println("List of users:", string(usersJSON))

	// Delete the user
	err = userManager.DeleteUser(newUser.ID)
	if err != nil {
		fmt.Println("Error deleting user:", err)
		return
	}
	fmt.Println("Deleted user:", newUser.ID)

	// List all users after deletion
	usersResource = userManager.ListUsers()
	usersJSON, _ = json.Marshal(usersResource)
	fmt.Println("List of users after deletion:", string(usersJSON))
}
