	"strings"

	"go.uber.org/fx"
)

// Route interface as provided in the snippet.
type Route interface {
	http.Handler
	Pattern() string
}

// StaticRoute serves a fixed message at a specific pattern.
type StaticRoute struct{}

func (sr *StaticRoute) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	fmt.Fprint(w, "Hello, Static World!")
}

func (sr *StaticRoute) Pattern() string {
	return "/static"
}

// DynamicRoute serves a message with a path parameter.
type DynamicRoute struct{}

func (dr *DynamicRoute) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	name := strings.TrimPrefix(r.URL.Path, "/dynamic/")
	fmt.Fprintf(w, "Hello, %s!", name)
}

func (dr *DynamicRoute) Pattern() string {
	return "/dynamic/"
}

// AsRoute and NewServeMux functions as provided in the snippet.
func AsRoute(f any) any {
	return fx.Annotate(
		f,
		fx.As(new(Route)),
		fx.ResultTags(`group:"routes"`),
	)
}

func NewServeMux(routes []Route) *http.ServeMux {
	mux := http.NewServeMux()
	for _, route := range routes {
		mux.Handle(route.Pattern(), route)
	}
	return mux
}

// Module provides the routes to the fx application.
var Module = fx.Options(
	fx.Provide(
		AsRoute(func() Route { return &StaticRoute{} }),
		AsRoute(func() Route { return &DynamicRoute{} }),
	),
	fx.Invoke(NewServeMux),
)

func main() {
	app := fx.New(
		Module,
		fx.Invoke(func(mux *http.ServeMux) {
			http.ListenAndServe(":8080", mux)
		}),
	)
	app.Run()
}

