)

// ResponseStatus is an enumeration of possible response statuses.
type ResponseStatus string

const (
	// Success indicates a successful response.
	Success ResponseStatus = "Success"
	// Error indicates an error in processing the request.
	Error ResponseStatus = "Error"
	// NotFound indicates that the requested resource was not found.
	NotFound ResponseStatus = "NotFound"
)

// ResultWrapper contains the result message of a request.
type ResultWrapper struct {
	Message string `json:"message"`
}

// ResponseEnvelope encapsulates a server response.
type ResponseEnvelope struct {
	RequestId string                 `json:"requestId,omitempty"`
	Status    ResponseStatus         `json:"status,omitempty"`
	Data      *ResultWrapper         `json:"data,omitempty"`
	More      *map[string]interface{} `json:"more,omitempty"`
}

// CreateResponse creates a new ResponseEnvelope with the given parameters.
func CreateResponse(requestId string, status ResponseStatus, message string, moreInfo map[string]interface{}) ResponseEnvelope {
	var more *map[string]interface{}
	if moreInfo != nil {
		more = &moreInfo
	}
	return ResponseEnvelope{
		RequestId: requestId,
		Status:    status,
		Data:      &ResultWrapper{Message: message},
		More:      more,
