// MemoryRoomService struct implementing RoomService with in-memory storage
type MemoryRoomService struct {
	rooms []Room
}

// AddRoom adds a new room to the system
func (m *MemoryRoomService) AddRoom(room Room) error {
	for _, r := range m.rooms {
		if r.Id == room.Id {
			return errors.New("room already exists")
		}
	}
	m.rooms = append(m.rooms, room)
	return nil
}

// GetRoomById retrieves a room by its ID
func (m *MemoryRoomService) GetRoomById(id int) (Room, error) {
	for _, r := range m.rooms {
		if r.Id == id {
			return r, nil
		}
	}
	return Room{}, errors.New("room not found")
}

// ListRoomsByCategory lists all rooms in a given category
func (m *MemoryRoomService) ListRoomsByCategory(categoryId int) ([]Room, error) {
	var roomsInCategory []Room
	for _, r := range m.rooms {
		if r.CategoryId == categoryId {
			roomsInCategory = append(roomsInCategory, r)
		}
	}
	if len(roomsInCategory) == 0 {
		return nil, errors.New("no rooms found for the given category")
	}
	return roomsInCategory, nil
}

