package main

import (
	"bufio"
	"fmt"
	"log"
	"os"
	"strconv"
	"strings"
)

// loadDataFromFile reads a file and returns a slice of strings, each representing a line in the file.
func loadDataFromFile(name string) []string {
	file, err := os.Open(name)
	if err != nil {
		log.Fatalln(err)
	}
	defer file.Close()

	scanner := bufio.NewScanner(file)
	scanner.Split(bufio.ScanLines)

	var data []string

	for scanner.Scan() {
		data = append(data, scanner.Text())
	}
	return data
}

// part1 calculates the product of the final horizontal position and depth
// after following the list of commands without considering the aim.
func part1(list []string) int {
	horizontal, depth := 0, 0
	for _, line := range list {
		directions := strings.Split(line, " ")
		val, _ := strconv.Atoi(directions[1])
		switch directions[0] {
		case "forward":
			horizontal += val
		case "down":
			depth += val
		case "up":
			depth -= val
		}
	}
	return horizontal * depth
}

// part2 calculates the product of the final horizontal position and depth
// after following the list of commands considering the aim.
func part2(list []string) int {
	horizontal, depth, aim := 0, 0, 0
	for _, line := range list {
		directions := strings.Split(line, " ")
		val, _ := strconv.Atoi(directions[1])
		switch directions[0] {
		case "forward":
			horizontal += val
			depth += aim * val
		case "down":
			aim += val
		case "up":
			aim -= val
		}
	}
	return horizontal * depth
}

func main() {
	// Replace "input.txt" with the path to the input file containing the commands.
	data := loadDataFromFile("input.txt")

	fmt.Println("Part 1 -- Product of final horizontal position and depth:", part1(data))
	fmt.Println("Part 2 -- Product of final horizontal position and depth considering aim:", part2(data))
}

// Test cases to verify the solution correctness.
func main() {
	testData := []string{
		"forward 5",
		"down 5",
		"forward 8",
		"up 3",
		"down 8",
		"forward 2",
	}

	expectedPart1 := 150
	actualPart1 := part1(testData)
	if actualPart1 != expectedPart1 {
		log.Fatalf("part1 failed: expected %d, got %d", expectedPart1, actualPart1)
	} else {
		fmt.Println("part1 passed")
	}

	expectedPart2 := 900
	actualPart2 := part2(testData)
	if actualPart2 != expectedPart2 {
		log.Fatalf("part2 failed: expected %d, got %d", expectedPart2, actualPart2)
	} else {
		fmt.Println("part2 passed")
	}
}
