		panic("simulated panic")
	}
	return nil
}

// PanicRecoveryWorkflow is a workflow that handles activity panics gracefully.
func PanicRecoveryWorkflow(ctx workflow.Context, shouldPanic bool) error {
	options := workflow.ActivityOptions{
		StartToCloseTimeout: time.Second * 5,
	}

	ctx = workflow.WithActivityOptions(ctx, options)

	var a *Activities // Temporal handles calling the registered activity object's methods

	err := workflow.ExecuteActivity(ctx, a.RiskyActivity, shouldPanic).Get(ctx, nil)
	if err != nil {
		// Check if the error is a panic error and return a specific error message.
		var panicErr *workflow.PanicError
		if errors.As(err, &panicErr) {
			return errors.New("Activity panicked")
		}
		// If it's not a panic error, return the original error.
		return err
	}

	// If the activity completed without panicking, return nil.
	return nil
}

