package pgstorage

import (
	"errors"
	"fmt"
	"strings"
)

// filterToWhere converts a filter object into a SQL WHERE clause string.
func filterToWhere(filter interface{}) (string, error) {
	switch f := filter.(type) {
	case map[string]interface{}:
		if len(f) != 1 {
			return "", errors.New("invalid filter: map should contain only one key-value pair")
		}
		for col, val := range f {
			cond, ok := val.([]interface{})
			if !ok || len(cond) != 2 {
				return "", errors.New("invalid condition: should be a two-element array")
			}
			op, ok := cond[0].(string)
			if !ok {
				return "", errors.New("invalid operator: should be a string")
			}
			return fmt.Sprintf("%s%s'%v'", col, op, cond[1]), nil
		}
	case string:
		if f != "AND" && f != "OR" {
			return "", errors.New("invalid logical operator: should be 'AND' or 'OR'")
		}
		return f, nil
	case []interface{}:
		var parts []string
		for _, part := range f {
			partStr, err := filterToWhere(part)
			if err != nil {
				return "", err
			}
			parts = append(parts, partStr)
		}
		return fmt.Sprintf("(%s)", strings.Join(parts, " ")), nil
	default:
		return "", errors.New("invalid filter type")
	}
	return "", nil
}

// Example usage and test cases
func main() {
	testCases := []struct {
		filter interface{}
		result string
		err    bool
	}{
		{
			filter: map[string]interface{}{"id": []interface{}{"=", 1}},
			result: "id='1'",
			err:    false,
		},
		{
			filter: "AND",
			err:    true,
		},
		{
			filter: []interface{}{
				map[string]interface{}{"id": []interface{}{"=", 1}},
				"OR",
				map[string]interface{}{"id": []interface{}{"=", 2}},
			},
			result: "(id='1' OR id='2')",
			err:    false,
		},
		{
			filter: map[string]interface{}{},
			err:    true,
		},
	}

	for _, tc := range testCases {
		result, err := filterToWhere(tc.filter)
		if (err != nil) != tc.err {
			fmt.Printf("Test failed: expected error: %v, got: %v\n", tc.err, err)
		} else if result != tc.result {
			fmt.Printf("Test failed: expected result: %s, got: %s\n", tc.result, result)
		} else {
			fmt.Println("Test passed")
		}
	}
}
