package main

import (
	"errors"
	"fmt"
)

// NamedRange represents a named range within a workbook.
type NamedRange struct {
	Name      string
	Reference string
	Comment   string
}

// WorkbookNamedRangeManager defines the interface for managing named ranges.
type WorkbookNamedRangeManager interface {
	AddNamedRange(namedRange NamedRange) error
	GetNamedRange(name string) (*NamedRange, error)
	UpdateNamedRange(name string, reference string, comment string) error
	DeleteNamedRange(name string) error
}

// InMemoryWorkbookNamedRangeManager is an in-memory implementation of WorkbookNamedRangeManager.
type InMemoryWorkbookNamedRangeManager struct {
	namedRanges map[string]NamedRange
}

// NewInMemoryWorkbookNamedRangeManager creates a new instance of InMemoryWorkbookNamedRangeManager.
func NewInMemoryWorkbookNamedRangeManager() *InMemoryWorkbookNamedRangeManager {
	return &InMemoryWorkbookNamedRangeManager{
		namedRanges: make(map[string]NamedRange),
	}
}

// AddNamedRange adds a new named range to the workbook.
func (m *InMemoryWorkbookNamedRangeManager) AddNamedRange(namedRange NamedRange) error {
	if _, exists := m.namedRanges[namedRange.Name]; exists {
		return errors.New("named range already exists")
	}
	m.namedRanges[namedRange.Name] = namedRange
	return nil
}

// GetNamedRange retrieves the details of a named range by its name.
func (m *InMemoryWorkbookNamedRangeManager) GetNamedRange(name string) (*NamedRange, error) {
	if namedRange, exists := m.namedRanges[name]; exists {
		return &namedRange, nil
	}
	return nil, errors.New("named range not found")
}

// UpdateNamedRange updates the reference and comment of an existing named range.
func (m *InMemoryWorkbookNamedRangeManager) UpdateNamedRange(name string, reference string, comment string) error {
	if namedRange, exists := m.namedRanges[name]; exists {
		namedRange.Reference = reference
		namedRange.Comment = comment
		m.namedRanges[name] = namedRange
		return nil
	}
	return errors.New("named range not found")
}

// DeleteNamedRange deletes a named range from the workbook.
func (m *InMemoryWorkbookNamedRangeManager) DeleteNamedRange(name string) error {
	if _, exists := m.namedRanges[name]; exists {
		delete(m.namedRanges, name)
		return nil
	}
	return errors.New("named range not found")
}

func main() {
	manager := NewInMemoryWorkbookNamedRangeManager()

	// Test cases
	err := manager.AddNamedRange(NamedRange{Name: "TotalSales", Reference: "Sheet1!A1:B2", Comment: "Total sales for Q1"})
	if err != nil {
		fmt.Println("Error:", err)
	}

	namedRange, err := manager.GetNamedRange("TotalSales")
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Printf("Named Range: %+v\n", *namedRange)
	}

	err = manager.UpdateNamedRange("TotalSales", "Sheet1!A1:B5", "Updated total sales for Q1")
	if err != nil {
		fmt.Println("Error:", err)
	}

	err = manager.DeleteNamedRange("TotalSales")
	if err != nil {
		fmt.Println("Error:", err)
	}

	_, err = manager.GetNamedRange("TotalSales")
	if err != nil {
		fmt.Println("Error:", err) // Expected error since named range has been deleted
	}
}
