	"github.com/cyucelen/marker"
	"github.com/fatih/color"
	"github.com/urfave/cli"
)

const version = "1.0.0"
const dateLayout = "2006-01-02 15:04:05"
const sleepTime = 1000

var blueFg = color.New(color.FgBlue)

// Convert a date string to a Unix timestamp in milliseconds.
func convertDateToUnixTimestamp(d string) (int64, error) {
	t, err := time.Parse(dateLayout, d)
	if err != nil {
		return 0, err
	}
	return t.UnixNano() / int64(time.Millisecond), nil
}

// Pretty print a JSON object.
func prettyPrintJSON(j interface{}) {
	jsonBytes, err := json.MarshalIndent(j, "", "    ")
	if err != nil {
		log.Fatal(err)
	}
	fmt.Println(string(jsonBytes))
}

// LogQueryTool command structure.
type LogQueryTool struct {
	logName   string
	apiKey    string
	startDate string
	endDate   string
	query     string
	client    http.Client
}

// LogsResponse represents the response from the log management service.
type LogsResponse struct {
	Logs []LogResponse `json:"logs"`
}

// GetLogByName finds a log by name within the response.
func (lr *LogsResponse) GetLogByName(name string) (LogResponse, error) {
	for _, log := range lr.Logs {
		if log.Name == name {
			return log, nil
		}
	}
	return LogResponse{}, fmt.Errorf("log not found with name %v", name)
}

// LogResponse represents a single log entry in the response.
type LogResponse struct {
	Name string `json:"name"`
	ID   string `json:"id"`
}

// PostQueryRequest represents the request body for posting a query.
type PostQueryRequest struct {
	Logs []string `json:"logs"`
	Leql Leql     `json:"leql"`
}

// Leql represents the query structure.
type Leql struct {
	During    During `json:"during"`
	Statement string `json:"statement"`
}

// During represents the time range for the query.
type During struct {
	From int64 `json:"from"`
	To   int64 `json:"to"`
}

// PostQueryResponse represents the response from posting a query.
type PostQueryResponse struct {
	Links []Link `json:"links"`
}

// Link represents a hyperlink from the response.
type Link struct {
	Href string `json:"href"`
}

// Event represents a single event from the query results.
type Event struct {
	Message string `json:"message"`
}

// FetchLogs retrieves the list of logs from the log management service.
func (lqt *LogQueryTool) FetchLogs() (*LogsResponse, error) {
	var logsResponse = new(LogsResponse)
	req, err := http.NewRequest("GET", "https://example.com/management/logs", nil)
	if err != nil {
		return logsResponse, err
	}
	req.Header.Add("x-api-key", lqt.apiKey)
	resp, err := lqt.client.Do(req)
	if err != nil {
		return logsResponse, err
	}
	defer resp.Body.Close()
	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		return logsResponse, err
	}
	err = json.Unmarshal(body, &logsResponse)
	return logsResponse, err
}

// PostQuery posts a query to the log management service.
func (lqt *LogQueryTool) PostQuery(logID string) (*PostQueryResponse, error) {
	postQueryResponse := new(PostQueryResponse)
	from, err := convertDateToUnixTimestamp(lqt.startDate)
	if err != nil {
		return postQueryResponse, err
	}
	to, err := convertDateToUnixTimestamp(lqt.endDate)
	if err != nil {
		return postQueryResponse, err
	}
	postQueryRequest := &PostQueryRequest{
		Logs: []string{logID},
		Leql: Leql{
			During: During{
				From: from,
				To:   to,
			},
			Statement: lqt.query,
		},
	}
	requestBody, err := json.Marshal(postQueryRequest)
	if err != nil {
		return postQueryResponse, err
	}
	req, err := http.NewRequest("POST", "https://example.com/query/logs/", bytes.NewBuffer(requestBody))
	if err != nil {
		return postQueryResponse, err
	}
	req.Header.Add("x-api-key", lqt.apiKey)
	req.Header.Set("Content-type", "application/json")
	resp, err := lqt.client.Do(req)
	if err != nil {
		return postQueryResponse, err
	}
	defer resp.Body.Close()
	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		return postQueryResponse, err
	}
	err = json.Unmarshal(body, &postQueryResponse)
	return postQueryResponse, err
}

// GetLogMessages retrieves the log messages from the log management service.
func (lqt *LogQueryTool) GetLogMessages(url string) ([]Event, error) {
	req, err := http.NewRequest("GET", url, nil)
	if err != nil {
		return nil, err
	}
	req.Header.Add("x-api-key", lqt.apiKey)
	resp, err := lqt.client.Do(req)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()
	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		return nil, err
	}
	var events []Event
	err = json.Unmarshal(body, &events)
	return events, err
}

// HighlightQuery highlights the query string within the log message.
func HighlightQuery(message, query string) string {
	return marker.Mark(message, marker.MatchAll(query), blueFg)
}

// Main function for the CLI tool.
func main() {
	lqt := LogQueryTool{}
	app := cli.NewApp()
	app.Name = "LogQueryTool"
	app.Usage = "Fetch and query logs from a log management service"
	app.Version = version
	app.Flags = []cli.Flag{
		cli.StringFlag{
			Name:        "log, l",
			Usage:       "Name of log in log management service",
			Destination: &lqt.logName,
			Required:    true,
		},
		cli.StringFlag{
			Name:        "api-key",
			Usage:       "API key for the log management service",
			Destination: &lqt.apiKey,
			Required:    true,
		},
		cli.StringFlag{
			Name:        "start-date",
			Usage:       "Start date for the log query (format: YYYY-MM-DD HH:MM:SS)",
			Destination: &lqt.startDate,
			Required:    true,
		},
		cli.StringFlag{
			Name:        "end-date",
			Usage:       "End date for the log query (format: YYYY-MM-DD HH:MM:SS)",
			Destination: &lqt.endDate,
			Required:    true,
		},
		cli.StringFlag{
			Name:        "query",
			Usage:       "Query string to search within the logs",
			Destination: &lqt.query,
			Required:    true,
		},
	}
	app.Action = func(c *cli.Context) error {
		logsResponse, err := lqt.FetchLogs()
		if err != nil {
			return err
		}
		logResponse, err := logsResponse.GetLogByName(lqt.logName)
		if err != nil {
			return err
		}
		postQueryResponse, err := lqt.PostQuery(logResponse.ID)
		if err != nil {
			return err
		}
		for _, link := range postQueryResponse.Links {
			events, err := lqt.GetLogMessages(link.Href)
			if err != nil {
				return err
			}
			for _, event := range events {
				fmt.Println(HighlightQuery(event.Message, lqt.query))
			}
		}
		return nil
	}
	err := app.Run(os.Args)
	if err != nil {
		log.Fatal(err)
	}
}
