package bson

import (
	"bufio"
	"errors"
)

// Bool represents BSON Boolean type.
type Bool bool

// ReadFrom reads a single byte from the provided bufio.Reader and sets the Bool value accordingly.
// It returns an error if the byte read is not 0x00 or 0x01.
func (b *Bool) ReadFrom(r *bufio.Reader) error {
	v, err := r.ReadByte()
	if err != nil {
		return err
	}

	switch v {
	case 0x00:
		*b = false
	case 0x01:
		*b = true
	default:
		return errors.New("invalid byte for BSON Bool")
	}

	return nil
}

// WriteTo writes the Bool value to the provided bufio.Writer as a single byte.
// It returns an error if writing fails.
func (b Bool) WriteTo(w *bufio.Writer) error {
	var v byte
	if b {
		v = 0x01
	} else {
		v = 0x00
	}

	if err := w.WriteByte(v); err != nil {
		return err
	}

	return nil
}

// MarshalBinary returns the BSON binary representation of the Bool value as a byte slice.
func (b Bool) MarshalBinary() ([]byte, error) {
	if b {
		return []byte{0x01}, nil
	}
	return []byte{0x00}, nil
}

// Test cases to verify the solution correctness.
func main() {
	// Test ReadFrom
	reader := bufio.NewReader(bytes.NewReader([]byte{0x01}))
	var b Bool
	err := b.ReadFrom(reader)
	if err != nil || !b {
		panic("ReadFrom failed")
	}

	// Test WriteTo
	buffer := bytes.NewBuffer(nil)
	writer := bufio.NewWriter(buffer)
	err = b.WriteTo(writer)
	writer.Flush()
	if err != nil || buffer.Bytes()[0] != 0x01 {
		panic("WriteTo failed")
	}

	// Test MarshalBinary
	data, err := b.MarshalBinary()
	if err != nil || data[0] != 0x01 {
		panic("MarshalBinary failed")
	}
}
