func DeleteClosedBlock(hash [32]byte) error {
	return db.Update(func(tx *bolt.Tx) error {
		b := tx.Bucket([]byte("closedblocks"))
		if b == nil {
			return errors.New("closedblocks bucket does not exist")
		}
		return b.Delete(hash[:])
	})
}

func DeleteOpenTx(transaction protocol.Transaction) {
	delete(txMemPool, transaction.Hash())
}

func DeleteClosedTx(transaction protocol.Transaction) error {
	var bucket string
	switch transaction.(type) {
	case *protocol.FundsTx:
		bucket = "closedfunds"
	case *protocol.AccTx:
		bucket = "closedaccs"
	case *protocol.ConfigTx:
		bucket = "closedconfigs"
	default:
		return errors.New("unknown transaction type")
	}

	hash := transaction.Hash()
	return db.Update(func(tx *bolt.Tx) error {
		b := tx.Bucket([]byte(bucket))
		if b == nil {
			return fmt.Errorf("%s bucket does not exist", bucket)
		}
		return b.Delete(hash[:])
	})
}

