	return fmt.Sprintf("/subscriptions/%s/resourceGroups/%s/providers/Microsoft.Network/frontDoorWebApplicationFirewallPolicies/%s", id.SubscriptionId, id.ResourceGroup, id.FrontDoorWebApplicationFirewallPolicyName)
}

// ParseFrontDoorWebApplicationFirewallPoliciesID parses a given WAF policy resource ID into its components.
func ParseFrontDoorWebApplicationFirewallPoliciesID(input string) (*FrontDoorWebApplicationFirewallPoliciesId, error) {
	// Define the regular expression pattern for matching the resource ID.
	pattern := `(?i)/subscriptions/(?P<subscriptionId>[^/]+)/resourceGroups/(?P<resourceGroup>[^/]+)/providers/Microsoft\.Network/frontDoorWebApplicationFirewallPolicies/(?P<policyName>[^/]+)$`
	re := regexp.MustCompile(pattern)

	if !re.MatchString(input) {
		return nil, fmt.Errorf("invalid Front Door WAF policy resource ID format")
	}

	matches := re.FindStringSubmatch(input)
	result := make(map[string]string)
	for i, name := range re.SubexpNames() {
		if i != 0 && name != "" {
			result[name] = matches[i]
		}
	}

	return &FrontDoorWebApplicationFirewallPoliciesId{
		SubscriptionId: result["subscriptionId"],
		ResourceGroup:  result["resourceGroup"],
		FrontDoorWebApplicationFirewallPolicyName: result["policyName"],
	}, nil
