package main

import (
	"fmt"
)

const (
	accBufSize = 1024 // Size of the preallocated buffer
	accBufMax  = 2048 // Maximum size for a single allocation
)

type BufferAllocator struct {
	buf   []byte
	index int
}

func NewBufferAllocator() *BufferAllocator {
	return &BufferAllocator{
		buf:   make([]byte, accBufSize),
		index: 0,
	}
}

func (ba *BufferAllocator) AllocateBuffer(length int) []byte {
	if length > accBufMax {
		// If requested length exceeds the maximum allowed size, allocate a new buffer
		return make([]byte, length)
	}

	if ba.index+length <= accBufSize {
		// If there is enough space in the preallocated buffer, allocate from it
		buf := ba.buf[ba.index : ba.index+length]
		ba.index += length
		return buf
	}

	// Not enough space in the preallocated buffer, allocate a new buffer
	ba.buf = make([]byte, accBufSize)
	ba.index = length
	return ba.buf[:length]
}

func (ba *BufferAllocator) Reset() {
	// Reset the index to reuse the preallocated buffer space
	ba.index = 0
}

func main() {
	// Test cases
	allocator := NewBufferAllocator()

	// Allocate a small buffer
	buf1 := allocator.AllocateBuffer(100)
	fmt.Println("Buffer 1 length:", len(buf1))

	// Allocate a buffer that fits in the remaining preallocated space
	buf2 := allocator.AllocateBuffer(900)
	fmt.Println("Buffer 2 length:", len(buf2))

	// Allocate a buffer that exceeds the remaining preallocated space
	buf3 := allocator.AllocateBuffer(100)
	fmt.Println("Buffer 3 length:", len(buf3))

	// Allocate a buffer that exceeds the maximum allowed size
	buf4 := allocator.AllocateBuffer(3000)
	fmt.Println("Buffer 4 length:", len(buf4))

	// Reset the allocator and allocate again
	allocator.Reset()
	buf5 := allocator.AllocateBuffer(500)
	fmt.Println("Buffer 5 length:", len(buf5))
}
