// PathExists checks if a given path exists on the local file system.
func PathExists(path string) (bool, error) {
	_, err := os.Stat(path)
	if err == nil {
		return true, nil
	}
	if errors.Is(os.ErrNotExist, err) {
		return false, nil
	}
	return false, err
}

// ExtractCoverFromVideo extracts the first frame of a video file and saves it as an image.
func ExtractCoverFromVideo(pathVideo, pathImg string) error {
	binPath := "./third_party/ffmpeg"
	if runtime.GOOS == "windows" {
		binPath += "windows/"
	} else if runtime.GOOS == "darwin" {
		binPath += "darwin/"
	} else {
		binPath += "linux/"
	}

	frameExtractionTime := "0"
	image_mode := "image2"
	vtime := "0.001"

	cmd := exec.Command(binPath+"ffmpeg",
		"-i", pathVideo,
		"-y",
		"-f", image_mode,
		"-ss", frameExtractionTime,
		"-t", vtime,
		"-y", pathImg)

	err := cmd.Start()
	if err != nil {
		return err
	}
	err = cmd.Wait()
	if err != nil {
		return err
	}
	return nil
}

// SaveFileToLocal saves an uploaded file to a specified directory with a unique name.
func SaveFileToLocal(savePath string, data *multipart.FileHeader) (string, error) {
	if exists, _ := PathExists(savePath); !exists {
		err := os.Mkdir(savePath, os.ModePerm)
		if err != nil {
			return "", err
		}
	}

	src, err := data.Open()
	if err != nil {
		return "", err
	}
	defer src.Close()
	timeLog := time.Now().Unix()
	fileName := GetFileNameWithoutExt(data.Filename)
	fileName += strconv.FormatInt(timeLog, 10) + path.Ext(data.Filename)
	out, err := os.Create(savePath + "/" + fileName)
	if err != nil {
		return "", err
	}
	defer out.Close()

	_, err = io.Copy(out, src)
	return fileName, err
}

