// Task interface that all tasks must implement.
type Task interface {
	Execute() error
}

// TaskRunner struct that will run tasks with retry logic.
type TaskRunner struct {
	retryLimit int
}

func NewTaskRunner(retryLimit int) *TaskRunner {
	return &TaskRunner{
		retryLimit: retryLimit,
	}
}

func (r *TaskRunner) Run(task Task) error {
	for retries := 0; retries <= r.retryLimit; retries++ {
		err := task.Execute()
		if err == nil {
			return nil
		}
		if _, ok := err.(*NonRetryableError); ok {
			return err
		}
		if retries < r.retryLimit {
			fmt.Printf("Retryable error occurred: %s. Retrying... (%d/%d)\n", err, retries+1, r.retryLimit)
			time.Sleep(1 * time.Second) // Wait for 1 second before retrying (simulating backoff strategy).
		}
	}
	return errors.New("task failed after reaching the retry limit")
