package main

import (
	"errors"
	"fmt"
	"strings"
)

type paragraph struct {
	text string
}

type question struct {
	quesNo int
	words  []string
}

type answer struct {
	text string
}

type Problem struct {
	paragraph paragraph
	questions []question
	answers   []answer
}

func NewProblem(paragraphText string, questionData []question, answerData []answer) Problem {
	return Problem{
		paragraph: paragraph{text: paragraphText},
		questions: questionData,
		answers:   answerData,
	}
}

func (p *Problem) Solve() ([]string, error) {
	solution := make([]string, len(p.questions))
	for _, ans := range p.answers {
		matchingQuestions, err := p.findMatchingQuestions(ans)
		if err != nil {
			return nil, err
		}
		for _, q := range matchingQuestions {
			solution[q.quesNo] = ans.text
		}
	}
	return solution, nil
}

func (p *Problem) findMatchingQuestions(ans answer) ([]question, error) {
	var matchingQuestions []question
	maxMatchingWordCount := 0

	for _, q := range p.questions {
		matchingWordCount := 0
		for _, word := range q.words {
			if strings.Contains(p.paragraph.text, word) && strings.Contains(ans.text, word) {
				matchingWordCount++
			}
		}
		if matchingWordCount > maxMatchingWordCount {
			maxMatchingWordCount = matchingWordCount
			matchingQuestions = []question{q}
		} else if matchingWordCount == maxMatchingWordCount && matchingWordCount != 0 {
			matchingQuestions = append(matchingQuestions, q)
		}
	}

	if len(matchingQuestions) == 0 {
		return nil, errors.New("no matching question found")
	}

	return matchingQuestions, nil
}

func main() {
