		{quesNo: 2, words: []string{"swift", "plane"}},
		{quesNo: 3, words: []string{"sky"}},
	}
	answerData := []answer{
		{text: "The fox is very quick."},
		{text: "Dogs can be lazy."},
		{text: "Planes fly in the sky."},
	}

