package main

import (
	"fmt"
	"time"
)

func createStage(addValue int) (chan int, chan int) {
	input := make(chan int)
	output := make(chan int)
	go func() {
		for num := range input {
			output <- num + addValue
		}
		close(output)
	}()
	return input, output
}

func extendPipeline(lastOutput chan int, addValue int) chan int {
	_, newOutput := createStage(addValue)
	go func() {
		for num := range lastOutput {
			newOutput <- num
		}
		close(newOutput)
	}()
	return newOutput
}

func sendData(input chan int, start int, end int) {
	for i := start; i < end; i++ {
		input <- i
	}
	close(input)
}

func receiveData(output chan int) {
	for num := range output {
		fmt.Println("Received:", num)
	}
}

func main() {
	fmt.Println("Dynamic Data Processing Pipeline")

	// Create initial pipeline with two stages
	input1, output1 := createStage(1)
	input2, output2 := createStage(2)

	// Link the stages
	go func() {
		for num := range output1 {
			input2 <- num
		}
		close(input2)
	}()

	// Send data through the initial pipeline
	go sendData(input1, 0, 5)

	// Extend the pipeline with one more stage
	finalOutput := extendPipeline(output2, 3)

	// Send another range of integers through the extended pipeline
	go sendData(input1, 5, 10)

	// Receive data from the last stage of the pipeline
	receiveData(finalOutput)

	// Use a channel or a waitgroup to properly wait for the go routine completion
	time.Sleep(1 * time.Second)
}
