		privValidator,
		proxy.NewLocalClientCreator(app),
		node.DefaultGenesisDocProviderFunc(config),
		node.DefaultDBProvider,
		logger)
	if err != nil {
		log.Errorf("Error on new node creation: %s", err.Error())
		return nil
	}
	return ret
}

