// GetTeacherInitials parses a Russian full name and returns the last name,
// first name initial, and middle name initial.
// It handles various formats of input and omits initials if not provided.
func GetTeacherInitials(fullName string) (lastName string, firstNameInitial string, middleNameInitial string) {
	// Remove extra spaces and split the name parts
	parts := strings.Fields(strings.ReplaceAll(fullName, ".", " . "))
	for i, part := range parts {
		if part == "." {
			continue
		}
		if i == 0 {
			lastName = part
		} else if firstNameInitial == "" {
			firstNameInitial = strings.TrimSuffix(part, ".")
		} else if middleNameInitial == "" {
			middleNameInitial = strings.TrimSuffix(part, ".")
		}
	}
	return
}

