package main

import (
	"encoding/json"
	"errors"
	"fmt"
)

type Item struct {
	ID       string `json:"id"`
	Name     string `json:"name"`
	Quantity int    `json:"quantity"`
}

type Inventory struct {
	Items map[string]Item
}

func NewInventory() *Inventory {
	return &Inventory{
		Items: make(map[string]Item),
	}
}

func (inv *Inventory) AddItem(item Item) {
	if existingItem, exists := inv.Items[item.ID]; exists {
		existingItem.Quantity += item.Quantity
		inv.Items[item.ID] = existingItem
	} else {
		inv.Items[item.ID] = item
	}
}

func (inv *Inventory) GetItem(id string) (Item, error) {
	if item, exists := inv.Items[id]; exists {
		return item, nil
	}
	return Item{}, errors.New("item not found")
}

func (inv *Inventory) ListItems() []Item {
	items := make([]Item, 0, len(inv.Items))
	for _, item := range inv.Items {
		items = append(items, item)
	}
	return items
}

type Metadata struct {
	Code    string `json:"code"`
	Message string `json:"message"`
}

type StandardResponse struct {
	Meta Metadata    `json:"meta"`
	Data interface{} `json:"data,omitempty"`
}

func main() {
	// Create a new inventory
	inventory := NewInventory()

	// Add some items
	inventory.AddItem(Item{ID: "1", Name: "Laptop", Quantity: 10})
	inventory.AddItem(Item{ID: "2", Name: "Smartphone", Quantity: 15})
	inventory.AddItem(Item{ID: "1", Name: "Laptop", Quantity: 5}) // This should update the quantity of the Laptop

	// Retrieve an item
	item, err := inventory.GetItem("1")
	if err != nil {
		fmt.Println(err)
	} else {
		response := StandardResponse{
			Meta: Metadata{Code: "200", Message: "Item retrieved successfully"},
			Data: item,
		}
		jsonResponse, _ := json.Marshal(response)
		fmt.Println(string(jsonResponse))
	}

	// List all items
	items := inventory.ListItems()
	listResponse := StandardResponse{
		Meta: Metadata{Code: "200", Message: "List of all items"},
		Data: items,
	}
	jsonListResponse, _ := json.Marshal(listResponse)
	fmt.Println(string(jsonListResponse))
}
