package main

import (
	"fmt"
)

// findMaxSubArraySum finds the sum of the contiguous subarray with the largest sum.
func findMaxSubArraySum(nums []int) int {
	// Helper function to calculate the maximum subarray sum recursively.
	var maxSubArrayHelper func(int) int
	maxSum := 0

	maxSubArrayHelper = func(index int) int {
		if index == 0 {
			maxSum = nums[0]
			return nums[0]
		}

		// Calculate the maximum subarray sum for the slice up to the current index.
		sum := maxSubArrayHelper(index - 1)
		currentMax := max(sum+nums[index], nums[index])

		// Update the overall maximum sum if necessary.
		maxSum = max(maxSum, currentMax)
		return currentMax
	}

	if len(nums) == 0 {
		return 0
	}

	// Start the recursive calculation from the last index.
	maxSubArrayHelper(len(nums) - 1)
	return maxSum
}

// max returns the larger of two integers.
func max(a, b int) int {
	if a > b {
		return a
	}
	return b
}

func main() {
	// Test cases to verify the solution correctness.
	testCases := [][]int{
		{-2, 1, -3, 4, -1, 2, 1, -5, 4},
		{1},
		{-1, -2, -3},
		{},
		{5, 4, -1, 7, 8},
	}

	for _, nums := range testCases {
		fmt.Printf("Input: %v, Output: %d\n", nums, findMaxSubArraySum(nums))
	}
}
