	addMultiplePhoneNumbers(&multiPhones, "jones", []string{"555-5678", "555-8765"})
	fmt.Println("Jones's phone numbers:", getMultiplePhoneNumbers(multiPhones, "jones"))

	addToBasket(&basket, 1, 12345, 3)
	addToBasket(&basket, 1, 67890, 1)
