// Address represents an Ethereum address.
type Address string

// IsHexAddress checks if the string is a valid Ethereum address.
func IsHexAddress(s string) bool {
	if s == "0x0" {
		return true
	}
	if !strings.HasPrefix(s, "0x") {
		return false
	}
	addressLength := 2 + 40
	if len(s) != addressLength {
		return false
	}
	return isHex(s[2:])
}

// ParseAddress parses a string into an Address type, validating its format.
func ParseAddress(address string) (Address, error) {
	if !IsHexAddress(address) {
		return "", errors.New("invalid address: " + address)
	}
	return Address(strings.ToLower(address)), nil
}

// isHexCharacter returns true if c is a valid hexadecimal character.
func isHexCharacter(c byte) bool {
	return ('0' <= c && c <= '9') || ('a' <= c && c <= 'f') || ('A' <= c && c <= 'F')
}

// isHex validates whether a string is a valid hexadecimal.
func isHex(str string) bool {
	if len(str)%2 != 0 {
		return false
	}
	for _, c := range []byte(str) {
		if !isHexCharacter(c) {
			return false
		}
	}
	return true
}

// User represents a user account.
type User struct {
	Username      string   `json:"username"`
	ProfileImgURL string   `json:"profile_img_url"`
	Address       Address  `json:"address"`
	Config        string   `json:"config"`
	DiscordID     string   `json:"discord_id"`
	Traits        []Trait  `json:"traits"`
}

// Trait represents a characteristic of a user.
type Trait struct {
	TraitType   string      `json:"trait_type"`
	Value       interface{} `json:"value"`
	DisplayType string      `json:"display_type,omitempty"`
	MaxValue    interface{} `json:"max_value,omitempty"`
	TraitCount  int64       `json:"trait_count"`
	Order       interface{} `json:"order,omitempty"`
}

// AddTrait adds a new trait to the user's account.
func (u *User) AddTrait(trait Trait) {
	u.Traits = append(u.Traits, trait)
}

// UpdateTrait updates an existing trait in the user's account.
func (u *User) UpdateTrait(traitType string, newValue interface{}) error {
	for i, trait := range u.Traits {
		if trait.TraitType == traitType {
			u.Traits[i].Value = newValue
			return nil
		}
	}
	return errors.New("trait not found")
}

// RemoveTrait removes a trait from the user's account.
func (u *User) RemoveTrait(traitType string) error {
	for i, trait := range u.Traits {
		if trait.TraitType == traitType {
			u.Traits = append(u.Traits[:i], u.Traits[i+1:]...)
			return nil
		}
	}
	return errors.New("trait not found")
}

