package main

import (
	"encoding/json"
	"net/http"
	"time"

	"github.com/go-chi/chi/v5"
	"github.com/go-chi/chi/v5/middleware"
	"github.com/sirupsen/logrus"

	"github.com/skycoin/skywire-utilities/pkg/buildinfo"
	"github.com/skycoin/skywire-utilities/pkg/httputil"
	"github.com/skycoin/skywire-utilities/pkg/logging"
)

// API represents the log server API with its associated router and logger.
type API struct {
	http.Handler
	logger    *logging.Logger
	startedAt time.Time
}

// NewAPI creates a new instance of the log server API.
func NewAPI(log *logging.Logger, tpLogPath, localPath, customPath string, printLog bool) *API {
	api := &API{
		logger:    log,
		startedAt: time.Now(),
	}

	r := chi.NewRouter()

	r.Use(middleware.RequestID)
	r.Use(middleware.RealIP)
	if printLog {
		r.Use(middleware.Logger)
		r.Use(middleware.Recoverer)
	}
	r.Use(httputil.SetLoggerMiddleware(log))

	r.Get("/health", api.health)

	fsTP := http.FileServer(http.Dir(tpLogPath))
	r.Handle("/tp/*", http.StripPrefix("/tp/", fsTP))

	fsLocal := http.FileServer(http.Dir(localPath))
	r.Handle("/local/survey.log", http.StripPrefix("/local/", fsLocal))
	r.Handle("/local/reward.log", http.StripPrefix("/local/", fsLocal))

	fsCustom := http.FileServer(http.Dir(customPath))
	r.Handle("/custom/*", http.StripPrefix("/custom/", fsCustom))

	api.Handler = r
	return api
}

// health is the handler for the health check endpoint.
func (api *API) health(w http.ResponseWriter, r *http.Request) {
	info := buildinfo.Get()
	api.writeJSON(w, r, http.StatusOK, httputil.HealthCheckResponse{
		BuildInfo: info,
		StartedAt: api.startedAt,
	})
}

// writeJSON writes the given object as a JSON response.
func (api *API) writeJSON(w http.ResponseWriter, r *http.Request, code int, object interface{}) {
	jsonObject, err := json.Marshal(object)
	if err != nil {
		api.log(r).WithError(err).Errorf("failed to encode json response")
		w.WriteHeader(http.StatusInternalServerError)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(code)
	_, err = w.Write(jsonObject)
	if err != nil {
		api.log(r).WithError(err).Errorf("failed to write json response")
	}
}

// log returns a logger with request-specific fields.
func (api *API) log(r *http.Request) logrus.FieldLogger {
	return httputil.GetLogger(r)
}

func main() {
	// Initialize the logger (for simplicity, using a basic logger here)
	logger := logging.MustGetLogger("logserver")

	// Define paths for different types of logs
	tpLogPath := "/var/log/transport"
	localPath := "/var/log/local"
	customPath := "/var/log/custom"

	// Create the API with the specified log paths and printLog set to true
	api := NewAPI(logger, tpLogPath, localPath, customPath, true)

	// Start the server
	http.ListenAndServe(":8080", api)
}
