type SpeakerQuotaType struct {
	ID           string    `json:"id"`
	Name         string    `json:"name"`
	Time         time.Time `json:"time"`
	CurrentCount int       `json:"currentCount"`
	Total        int       `json:"total"`
}

// NewSpeakerQuota creates a new SpeakerQuotaType with the given id, name, and total slots.
func NewSpeakerQuota(id, name string, total int) *SpeakerQuotaType {
	return &SpeakerQuotaType{
		ID:           id,
		Name:         name,
		Time:         time.Now(),
		CurrentCount: 0,
		Total:        total,
	}
}

// UseSlot increments the CurrentCount by 1 and updates the Time if the quota has not been exceeded.
func UseSlot(speakerQuota *SpeakerQuotaType) error {
	if speakerQuota.CurrentCount >= speakerQuota.Total {
		return errors.New("speaker quota exceeded")
	}
	speakerQuota.CurrentCount++
	speakerQuota.Time = time.Now()
	return nil
}

// RemainingSlots returns the number of remaining slots for the speaker.
func RemainingSlots(speakerQuota *SpeakerQuotaType) int {
	return speakerQuota.Total - speakerQuota.CurrentCount
}

func main() {
	// Test cases
	speakerQuota := NewSpeakerQuota("123", "John Doe", 3)
	fmt.Printf("New speaker quota created: %+v\n", speakerQuota)

	err := UseSlot(speakerQuota)
	if err != nil {
		fmt.Println("Error:", err)
	}
	fmt.Printf("Speaker quota after using a slot: %+v\n", speakerQuota)

	remaining := RemainingSlots(speakerQuota)
	fmt.Printf("Remaining slots: %d\n", remaining)

	// Use all slots
	for i := 0; i < 2; i++ {
		err = UseSlot(speakerQuota)
		if err != nil {
			fmt.Println("Error:", err)
		}
	}
	fmt.Printf("Speaker quota after using all slots: %+v\n", speakerQuota)

	// Try to exceed quota
	err = UseSlot(speakerQuota)
	if err != nil {
		fmt.Println("Error:", err)
	}
}
