// WeightLabel represents a label with a corresponding weight (value).
type WeightLabel struct {
    weight float64
    label  string
}

// WeightLabelList is a slice of WeightLabel used for statistical analysis.
type WeightLabelList []WeightLabel

// MaxWeight returns the maximum weight in the WeightLabelList.
func (wlList *WeightLabelList) MaxWeight() float64 {
    max := (*wlList)[0].weight
    for _, wl := range *wlList {
        if max < wl.weight {
            max = wl.weight
        }
    }
    return max
}

// MinWeight returns the minimum weight in the WeightLabelList.
func (wlList *WeightLabelList) MinWeight() float64 {
    min := (*wlList)[0].weight
    for _, wl := range *wlList {
        if min > wl.weight {
            min = wl.weight
        }
    }
    return min
}

// StatResult holds the statistical analysis results for a dataset.
type StatResult struct {
    discreteStat   map[string]map[string]map[string]float64
    labels         map[string]bool
    features       map[string]bool
    continuousStat map[string]WeightLabelList
}

// Init initializes the maps within StatResult.
func (sr *StatResult) Init() {
    sr.discreteStat = make(map[string]map[string]map[string]float64)
    sr.labels = make(map[string]bool)
    sr.features = make(map[string]bool)
    sr.continuousStat = make(map[string]WeightLabelList)
}

// StatData reads and processes the data from a TSV file to generate statistics.
func StatData(path string) *StatResult {
    file, err := os.Open(path)
    if err != nil {
        log.Printf("Error opening file: %v", err)
        return nil
    }
    defer file.Close()

    stat := StatResult{}
    stat.Init()
    scanner := bufio.NewScanner(file)
    var head []string
    lineNum := 0
    for scanner.Scan() {
        lineNum++
        line := scanner.Text()
        tokens := strings.Split(line, "\t")
        if lineNum == 1 {
            head = tokens
            continue
        }

        label := tokens[0]
        if len(label) == 0 {
            continue
        }
        stat.labels[label] = true
        if len(tokens) != len(head) {
            log.Printf("Mismatch in number of tokens: %v vs %v", len(tokens), len(head))
            continue
        }

        for i, token := range tokens {
            if i == 0 {
                continue
            }
            key := head[i]
            stat.features[key] = true
            if strings.HasPrefix(key, "[") {
                // Discrete feature
                if _, ok := stat.discreteStat[key]; !ok {
                    stat.discreteStat[key] = make(map[string]map[string]float64)
                }
                if _, ok := stat.discreteStat[key][token]; !ok {
                    stat.discreteStat[key][token] = make(map[string]float64)
                }
                stat.discreteStat[key][token][label]++
            } else {
                // Continuous feature
                value, _ := strconv.ParseFloat(token, 64)
                stat.continuousStat[key] = append(stat.continuousStat[key], WeightLabel{weight: value, label: label})
            }
        }
    }
    if err := scanner.Err(); err != nil {
        log.Printf("Error reading file: %v", err)
        return nil
    }
    return &stat
}

// StatAllData processes all datasets within the data directory.
func StatAllData() map[string]*StatResult {
    results := make(map[string]*StatResult)
    files, err := ioutil.ReadDir("./data/")
    if err != nil {
        log.Printf("Error reading data directory: %v", err)
        return results
    }
    for _, f := range files {
        if f.IsDir() {
            stat := StatData(fmt.Sprintf("./data/%s/data.tsv", f.Name()))
            results[f.Name()] = stat
        }
    }
    return results
}

// globalStat holds the statistical results for all datasets.
var globalStat map[string]*StatResult

// Implement the HTTP handlers for the endpoints here, following the API specification.

func main() {
    globalStat = StatAllData()
    // Set up the HTTP server and handlers.
    // ...
}
