type Company struct {
	gorm.Model
	Name     string
	Employees []Employee
}

type Employee struct {
	gorm.Model
	Name      string
	CompanyID uint
}

func initializeDatabase() *gorm.DB {
	dsn := "root:123456@tcp(127.0.0.1:3306)/db1?charset=utf8mb4&parseTime=True&loc=Local"
	db, err := gorm.Open(mysql.Open(dsn), &gorm.Config{})
	if err != nil {
		fmt.Println("Error connecting to database:", err)
		panic(err)
	}

	// Auto migrate the Company and Employee structs
	db.AutoMigrate(&Company{}, &Employee{})

	// Seed the database with one company and two employees
	company := Company{Name: "Tech Corp"}
	db.Create(&company)
	employees := []Employee{
		{Name: "Alice", CompanyID: company.ID},
		{Name: "Bob", CompanyID: company.ID},
	}
	for _, employee := range employees {
		db.Create(&employee)
	}

	return db
}

func listEmployees(db *gorm.DB, companyID uint) {
	var employees []Employee
	if err := db.Where("company_id = ?", companyID).Find(&employees).Error; err != nil {
		fmt.Println("Error retrieving employees:", err)
		return
	}

	fmt.Println("Employees belonging to Company ID", companyID)
	for _, employee := range employees {
		fmt.Printf("ID: %d, Name: %s\n", employee.ID, employee.Name)
	}
}

func main() {
	db := initializeDatabase()
	// Assuming the company ID is 1, this should list the employees for that company
	listEmployees(db, 1)
}
