	defer db.Close()

	// Prepare a statement for execution
	stmt, err := db.Prepare("SELECT id, name FROM users WHERE id = ?")
	if err != nil {
		panic(err)
	}
	defer stmt.Close()

	// Wrap the statement with sqlx features
	sqlxStmt := &Stmt{Stmt: stmt, Mapper: reflectx.NewMapperFunc("db", reflectx.CamelToSnake)}

	// Execute a Select operation
	var users []User // User is a struct representing a user record
	err = sqlxStmt.Select(&users, 1)
	if err != nil {
		panic(err)
	}

	// Execute a Get operation
	var user User
	err = sqlxStmt.Get(&user, 1)
	if err != nil {
		if errors.Is(err, sql.ErrNoRows) {
			// Handle no rows found
		} else {
			panic(err)
		}
	}

	// Execute a MustExec operation
	result := sqlxStmt.MustExec(1)
	affected, err := result.RowsAffected()
	if err != nil {
		panic(err)
	}
	println("Rows affected:", affected)

	// Execute a QueryRowx operation
	row := sqlxStmt.QueryRowx(1)
	err = row.Scan(&user)
	if err != nil {
		panic(err)
	}

	// Execute a Queryx operation
	rows, err := sqlxStmt.Queryx(1)
	if err != nil {
		panic(err)
	}
	defer rows.Close()
	for rows.Next() {
		err = rows.Scan(&user)
		if err != nil {
			panic(err)
		}
		println("User found:", user.Name)
	}
}
