	}
	p.groups[groupName] = &Group{
		Name:  groupName,
		Users: users,
		Roles: roles,
		Items: items,
	}
	return nil
}

func (p *Perm) GetGroup(groupName string) (*Group, error) {
	group, exists := p.groups[groupName]
	if !exists {
		return nil, fmt.Errorf("group %s does not exist", groupName)
	}
	return group, nil
}

func (p *Perm) UpdateItems(groupName string, items []string) error {
	group, exists := p.groups[groupName]
	if !exists {
		return fmt.Errorf("group %s does not exist", groupName)
	}
	for _, item := range items {
		if item == "" {
			return errors.New("items cannot contain empty strings")
		}
	}
	group.Items = items
	return nil
}

