package main

import (
	"sync"
	"time"
)

// CommandMetrics holds the metrics for command executions.
type CommandMetrics struct {
	mu                 sync.RWMutex
	commandsTotal      int64
	commandsSeconds    time.Duration
	errorsTotal        int64
	execSeconds        map[string]time.Duration
	projectorsSeconds  time.Duration
}

// NewCommandMetrics creates a new CommandMetrics instance.
func NewCommandMetrics() *CommandMetrics {
	return &CommandMetrics{
		execSeconds: make(map[string]time.Duration),
	}
}

// LogCommandExecution logs the execution of a command.
func (m *CommandMetrics) LogCommandExecution(commandName string, execTime time.Duration, isError bool) {
	m.mu.Lock()
	defer m.mu.Unlock()

	m.commandsTotal++
	m.commandsSeconds += execTime
	if isError {
		m.errorsTotal++
	}
	m.execSeconds[commandName] += execTime
}

// LogProjectorExecution logs the time taken by projectors to process commands.
func (m *CommandMetrics) LogProjectorExecution(execTime time.Duration) {
	m.mu.Lock()
	defer m.mu.Unlock()

	m.projectorsSeconds += execTime
}

// GetTotalCommands returns the total number of executed commands.
func (m *CommandMetrics) GetTotalCommands() int64 {
	m.mu.RLock()
	defer m.mu.RUnlock()

	return m.commandsTotal
}

// GetTotalCommandsSeconds returns the total execution time of all commands.
func (m *CommandMetrics) GetTotalCommandsSeconds() time.Duration {
	m.mu.RLock()
	defer m.mu.RUnlock()

	return m.commandsSeconds
}

// GetTotalErrors returns the total number of errors encountered.
func (m *CommandMetrics) GetTotalErrors() int64 {
	m.mu.RLock()
	defer m.mu.RUnlock()

	return m.errorsTotal
}

// GetExecSeconds returns the total execution time of a specific command.
func (m *CommandMetrics) GetExecSeconds(commandName string) time.Duration {
	m.mu.RLock()
	defer m.mu.RUnlock()

	return m.execSeconds[commandName]
}

// GetProjectorsSeconds returns the total time taken by projectors to process commands.
func (m *CommandMetrics) GetProjectorsSeconds() time.Duration {
	m.mu.RLock()
	defer m.mu.RUnlock()

	return m.projectorsSeconds
}

func main() {
	// Example usage of the CommandMetrics
	metrics := NewCommandMetrics()

	// Simulate logging command executions
	metrics.LogCommandExecution("command1", 50*time.Millisecond, false)
	metrics.LogCommandExecution("command2", 30*time.Millisecond, true)
	metrics.LogCommandExecution("command1", 20*time.Millisecond, false)
	metrics.LogProjectorExecution(10 * time.Millisecond)

	// Retrieve metrics
	totalCommands := metrics.GetTotalCommands()
	totalCommandsSeconds := metrics.GetTotalCommandsSeconds()
	totalErrors := metrics.GetTotalErrors()
	command1ExecSeconds := metrics.GetExecSeconds("command1")
	projectorsSeconds := metrics.GetProjectorsSeconds()

	// Output the metrics
	println("Total Commands:", totalCommands)
	println("Total Commands Seconds:", totalCommandsSeconds.Milliseconds(), "ms")
	println("Total Errors:", totalErrors)
	println("Command1 Exec Seconds:", command1ExecSeconds.Milliseconds(), "ms")
	println("Projectors Seconds:", projectorsSeconds.Milliseconds(), "ms")
}
