var serviceConfig = struct {
	TargetURL string
	APIKey    string
}{
	TargetURL: "https://api.bing.microsoft.com/v7.0/images/search",
	APIKey:    "your-api-key", // Replace with your Bing Search API key
}

// GetThumbnail retrieves the thumbnail URL for a given search term.
func (c *Client) GetThumbnail(input string) string {
	resp := c.bing(input)
	if len(resp.Value) > 0 {
		return resp.Value[0].ThumbnailURL
	}
	return ""
}

// GetImage retrieves the full-size image URL for a given list of search terms.
func (c *Client) GetImage(input []string) string {
	resp := c.bing(strings.Join(input, "+"))
	if len(resp.Value) > 0 {
		return resp.Value[0].ContentURL
	}
	return ""
}

// bing performs the actual API request to Bing Image Search API.
func (c *Client) bing(input string) *response {
	client := &http.Client{}
	req, err := http.NewRequest("GET", serviceConfig.TargetURL, nil)
	if err != nil {
		log.Fatal(err)
	}

	q := req.URL.Query()
	q.Set("q", input)
	q.Set("count", "1")
	req.URL.RawQuery = q.Encode()

	req.Header.Set("Ocp-Apim-Subscription-Key", serviceConfig.APIKey)

	resp, err := client.Do(req)
	if err != nil {
		log.Fatal(err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		log.Fatalf("Request failed with status code: %d", resp.StatusCode)
	}

	r := &response{}
	err = json.NewDecoder(resp.Body).Decode(r)
	if err != nil {
		log.Fatal(err)
	}
	return r
}

// response represents the JSON response structure from Bing Image Search API.
