import (
	"fmt"
	"github.com/golang-jwt/jwt/v4"
	"os"
	"time"
)

var SecretKey = os.Getenv("APP_KEY")

func GenerateJwt(userID string) (string, error) {
	// Define the claims for the JWT token, including the issuer and expiration time.
	claims := jwt.NewWithClaims(jwt.SigningMethodHS256, jwt.RegisteredClaims{
		Subject:   userID,
		ExpiresAt: jwt.NewNumericDate(time.Now().Add(time.Hour * 24)), // 1 day
	})

	// Sign the token with the secret key.
	return claims.SignedString([]byte(SecretKey))
}

func ParseJWT(jwtToken string) (string, error) {
	// Parse the token with the claims to validate it.
	token, err := jwt.ParseWithClaims(jwtToken, &jwt.RegisteredClaims{}, func(token *jwt.Token) (interface{}, error) {
		return []byte(SecretKey), nil
	})

	// Check if there was an error in parsing or if the token is invalid.
	if err != nil || !token.Valid {
		return "", err
	}

	// Extract the claims and return the user ID.
	claims := token.Claims.(*jwt.RegisteredClaims)
	return claims.Subject, nil
}

func main() {
	// Set the APP_KEY environment variable for testing purposes.
	os.Setenv("APP_KEY", "mysecretkey")

	// Generate a JWT for a user with ID "12345".
	jwtToken, err := GenerateJwt("12345")
	if err != nil {
		fmt.Println("Error generating JWT:", err)
		return
	}
	fmt.Println("Generated JWT:", jwtToken)

	// Parse the JWT to validate it and retrieve the user ID.
	userID, err := ParseJWT(jwtToken)
	if err != nil {
		fmt.Println("Error parsing JWT:", err)
		return
	}
	fmt.Println("User ID from JWT:", userID)

	// Output:
	// Generated JWT: <token>
	// User ID from JWT: 12345
}
