package main

import (
	"fmt"
)

// max returns the larger of two integers.
func max(a, b int) int {
	if a > b {
		return a
	}
	return b
}

// longestPalindrome finds the longest palindromic substring in a given string s.
func longestPalindrome(s string) string {
	n := len(s)
	if n == 0 {
		return ""
	}

	// dp[i][j] will be true if the string from index i to j is a palindrome.
	dp := make([][]bool, n)
	for i := range dp {
		dp[i] = make([]bool, n)
	}

	// All substrings of length 1 are palindromes.
	for i := 0; i < n; i++ {
		dp[i][i] = true
	}

	start := 0
	maxLength := 1

	// Check for substring of length 2.
	for i := 0; i < n-1; i++ {
		if s[i] == s[i+1] {
			dp[i][i+1] = true
			start = i
			maxLength = 2
		}
	}

	// Check for lengths greater than 2.
	for length := 3; length <= n; length++ {
		for i := 0; i < n-length+1; i++ {
			j := i + length - 1
			if s[i] == s[j] && dp[i+1][j-1] {
				dp[i][j] = true
				start = i
				maxLength = length
			}
		}
	}

	return s[start : start+maxLength]
}

func main() {
	// Test cases to verify the solution correctness.
	testCases := []struct {
		input    string
		expected string
	}{
		{"babad", "bab"},
		{"cbbd", "bb"},
		{"a", "a"},
		{"ac", "a"},
		{"", ""},
		{"forgeeksskeegfor", "geeksskeeg"},
	}

	for _, tc := range testCases {
		output := longestPalindrome(tc.input)
		fmt.Printf("longestPalindrome(%v) = %v (expected: %v)\n", tc.input, output, tc.expected)
	}
}
