package main

import (
	"fmt"
)

// Graph represents an undirected graph using an adjacency list.
type Graph struct {
	adjList map[int][]int
}

// NewGraph creates a new instance of a Graph.
func NewGraph() *Graph {
	return &Graph{adjList: make(map[int][]int)}
}

// AddEdge adds an edge between vertices v and w.
func (g *Graph) AddEdge(v, w int) {
	g.adjList[v] = append(g.adjList[v], w)
	g.adjList[w] = append(g.adjList[w], v)
}

// Adj returns a slice of integers representing the vertices adjacent to vertex v.
func (g *Graph) Adj(v int) []int {
	return g.adjList[v]
}

// Iterator is used to iterate over the adjacency list of a vertex.
type Iterator struct {
	list []int
	nextIndex int
}

// NewIterator creates a new iterator for the given graph and vertex.
func NewIterator(g *Graph, v int) *Iterator {
	return &Iterator{
		list: g.Adj(v),
		nextIndex: 0,
	}
}

// begin returns the first adjacent vertex.
func (it *Iterator) begin() int {
	if len(it.list) == 0 {
		return -1
	}
	return it.list[0]
}

// end checks if the iterator has finished iterating over the adjacency list.
func (it *Iterator) end() bool {
	return it.nextIndex >= len(it.list)
}

// next returns the next adjacent vertex.
func (it *Iterator) next() int {
	it.nextIndex++
	if it.end() {
		return -1
	}
	return it.list[it.nextIndex]
}

// Stack is a simple stack implementation for integers.
type Stack struct {
	elements []int
}

// Push adds an element to the top of the stack.
func (s *Stack) Push(v int) {
	s.elements = append(s.elements, v)
}

// Pop removes and returns the top element of the stack.
func (s *Stack) Pop() int {
	if len(s.elements) == 0 {
		return -1
	}
	v := s.elements[len(s.elements)-1]
	s.elements = s.elements[:len(s.elements)-1]
	return v
}

// IsEmpty checks if the stack is empty.
func (s *Stack) IsEmpty() bool {
	return len(s.elements) == 0
}

// Path represents a path in a graph from a source vertex.
type Path struct {
	src     int
	visited []bool
	from    []int
	g       *Graph
}

// NewPath creates a new Path instance for the given graph and source vertex.
func NewPath(graph *Graph, src int) *Path {
	vNumber := len(graph.adjList)
	p := &Path{
		src:     src,
		visited: make([]bool, vNumber),
		from:    make([]int, vNumber),
		g:       graph,
	}
	for i := range p.from {
		p.from[i] = -1
	}
	return p
}

// CalcPath calculates the path from the source vertex using DFS.
func (p *Path) CalcPath() {
	p.dfs(p.src)
}

// HasPath checks if there is a path to the destination vertex.
func (p *Path) HasPath(des int) bool {
	return p.visited[des]
}

// GetPath returns the path to the destination vertex as a slice of integers.
func (p *Path) GetPath(des int) []int {
	if !p.HasPath(des) {
		return nil
	}

	stack := &Stack{}
	cur := des
	for cur != -1 {
		stack.Push(cur)
		cur = p.from[cur]
	}

	path := []int{}
	for !stack.IsEmpty() {
		path = append(path, stack.Pop())
	}
	return path
}

// ShowPath prints the path to the destination vertex.
func (p *Path) ShowPath(des int) {
	path := p.GetPath(des)
	for _, v := range path {
		fmt.Printf("%d ", v)
	}
	fmt.Println()
}

// dfs is the recursive helper function for performing DFS.
func (p *Path) dfs(v int) {
	p.visited[v] = true
	iter := NewIterator(p.g, v)
	for w := iter.begin(); !iter.end(); w = iter.next() {
		if !p.visited[w] {
			p.from[w] = v
			p.dfs(w)
		}
	}
}

func main() {
	// Create a new graph instance.
	graph := NewGraph()

	// Add edges to the graph.
	graph.AddEdge(0, 1)
	graph.AddEdge(0, 2)
	graph.AddEdge(0, 3)
	graph.AddEdge(1, 4)
	graph.AddEdge(2, 5)
	graph.AddEdge(3, 6)
	graph.AddEdge(4, 5)
	graph.AddEdge(5, 6)

	// Create a path instance to find paths from vertex 0.
	path := NewPath(graph, 0)
	path.CalcPath()

	// Display the path from vertex 0 to 6.
	fmt.Print("Path from 0 to 6: ")
	path.ShowPath(6)

	// Display the path from vertex 0 to 4.
	fmt.Print("Path from 0 to 4: ")
	path.ShowPath(4)
}
