package main

import (
	"fmt"
	"errors"
)

type Filter struct {
	Field    string
	Operator string
	Value    string
}

type Filters struct {
	List []Filter `json:"filters"`
}

func NewFilters() Filters {
	return Filters{
		List: []Filter{},
	}
}

func (f *Filters) AddFilter(field, operator, value string) {
	f.List = append(f.List, Filter{Field: field, Operator: operator, Value: value})
}

func (f *Filters) RemoveFilter(index int) error {
	if index < 0 || index >= len(f.List) {
		return errors.New("index out of range")
	}
	f.List = append(f.List[:index], f.List[index+1:]...)
	return nil
}

func (f *Filters) GetFilter(index int) (Filter, error) {
	if index < 0 || index >= len(f.List) {
		return Filter{}, errors.New("index out of range")
	}
	return f.List[index], nil
}

func (f *Filters) Clean() {
	f.List = f.List[:0]
}

func (f *Filters) Size() int {
	return len(f.List)
}

func (f *Filters) HasFilters() bool {
	return len(f.List) > 0
}

func (f *Filters) Serialize() string {
	result := ""
	for i, v := range f.List {
		result += fmt.Sprintf("Filter #%d: %s %s %s\n", i, v.Field, v.Operator, v.Value)
	}
	return result
}

// Test cases to verify the solution correctness
func main() {
	filters := NewFilters()
	filters.AddFilter("price", ">", "20")
	filters.AddFilter("name", "=", "example")

	fmt.Println("Serialized Filters:")
	fmt.Println(filters.Serialize())

	fmt.Println("Number of Filters:", filters.Size())

	removedErr := filters.RemoveFilter(1)
	if removedErr != nil {
		fmt.Println("Error removing filter:", removedErr)
	}

	fmt.Println("Serialized Filters after removal:")
	fmt.Println(filters.Serialize())

	filter, getErr := filters.GetFilter(0)
	if getErr != nil {
		fmt.Println("Error getting filter:", getErr)
	} else {
		fmt.Printf("Retrieved Filter: %s %s %s\n", filter.Field, filter.Operator, filter.Value)
	}

	fmt.Println("Has Filters:", filters.HasFilters())

	filters.Clean()
	fmt.Println("Has Filters after cleaning:", filters.HasFilters())
}
