package main

import (
	"fmt"
	"strconv"
	"sync"
	"time"
)

// Msg represents a concurrent cache system for storing string values with int64 keys.
type Msg struct {
	rmutex sync.RWMutex
	mutex  sync.Mutex
	count  map[int64]string
}

// InitMsg initializes or updates the cache with the given key-value pair.
// It is safe for concurrent use by multiple goroutines.
func (m *Msg) InitMsg(key int64, value string) {
	m.mutex.Lock()
	defer m.mutex.Unlock()
	m.count[key] = value
}

// Get retrieves the value for the given key from the cache.
// If the key does not exist, it initializes the key with its string representation.
// It is safe for concurrent use by multiple goroutines.
func (m *Msg) Get(key int64, c chan bool) (str string) {
	defer func() { <-c }()
	m.rmutex.RLock()
	if _, ok := m.count[key]; !ok {
		m.rmutex.RUnlock()
		m.InitMsg(key, strconv.Itoa(int(key)))
	} else {
		m.rmutex.RUnlock()
	}
	m.rmutex.RLock()
	defer m.rmutex.RUnlock()
	if str, ok := m.count[key]; ok {
		return str
	}
	return
}

func main() {
	msg := &Msg{count: make(map[int64]string)}
	var i int64
	c := make(chan bool, 2000)
	t1 := time.Now().UnixNano()

	// Initialize the cache with some values.
	for i = 0; i <= 1024000; i++ {
		msg.InitMsg(i, strconv.Itoa(int(i)))
	}

	// Concurrently retrieve values from the cache.
	for i = 0; i <= 2048000; i++ {
		c <- true
		go func(key int64) {
			_ = msg.Get(key, c)
		}(i)
	}

	// Wait for all goroutines to finish.
	for len(c) > 0 {
		time.Sleep(10 * time.Millisecond)
	}

	t2 := time.Now().UnixNano()
	fmt.Println("Time taken (nanoseconds):", t2-t1)
}
