package main

import (
	"encoding/json"
	"errors"
	"fmt"
	"net/http"
	"regexp"
	"strconv"

	"backend/entity"
	"github.com/gorilla/mux"
)

// Assuming the following package is imported and contains the necessary user entity model
// import "backend/entity"

// UserCreateDTO is used when creating a new user
type UserCreateDTO struct {
	Name     string `json:"name" binding:"required"`
	Email    string `json:"email" binding:"required,email"`
	Password string `json:"password,omitempty" binding:"required,min=6"`
}

// UserUpdateDTO is used when updating a user's information
type UserUpdateDTO struct {
	ID          uint64 `json:"id"`
	Name        string `json:"name"`
	Email       string `json:"email"`
	PhoneNumber uint64 `json:"phone_number"`
	Password    string `json:"password,omitempty"`
}

// UserDetailResponse is the response payload for user data
type UserDetailResponse struct {
	ID    uint64 `json:"id"`
	Name  string `json:"name"`
	Email string `json:"email"`
}

// UserResponseBody is the response payload for listing users
type UserResponseBody struct {
	ID    uint64 `json:"id"`
	Name  string `json:"name"`
	Email string `json:"email"`
}

// Mock database for storing users
var users = make(map[uint64]*entity.User)
var nextUserID uint64 = 1

// createUserHandler handles the creation of a new user
func createUserHandler(w http.ResponseWriter, r *http.Request) {
	var userDTO UserCreateDTO
	if err := json.NewDecoder(r.Body).Decode(&userDTO); err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	if len(userDTO.Password) < 6 {
		http.Error(w, "Password must be at least 6 characters long", http.StatusBadRequest)
		return
	}

	if !isEmailValid(userDTO.Email) {
		http.Error(w, "Invalid email format", http.StatusBadRequest)
		return
	}

	for _, user := range users {
		if user.Email == userDTO.Email {
			http.Error(w, "Email already in use", http.StatusBadRequest)
			return
		}
	}

	user := &entity.User{
		ID:       nextUserID,
		Name:     userDTO.Name,
		Email:    userDTO.Email,
		Password: userDTO.Password,
	}
	users[nextUserID] = user
	nextUserID++

	w.WriteHeader(http.StatusCreated)
	json.NewEncoder(w).Encode(user)
}

// updateUserHandler handles the update of an existing user
func updateUserHandler(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	userID, err := strconv.ParseUint(vars["id"], 10, 64)
	if err != nil {
		http.Error(w, "Invalid user ID", http.StatusBadRequest)
		return
	}

	var userDTO UserUpdateDTO
	if err := json.NewDecoder(r.Body).Decode(&userDTO); err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	user, exists := users[userID]
	if !exists {
		http.Error(w, "User not found", http.StatusNotFound)
		return
	}

	if userDTO.Email != "" && !isEmailValid(userDTO.Email) {
		http.Error(w, "Invalid email format", http.StatusBadRequest)
		return
	}

	if userDTO.Password != "" && len(userDTO.Password) < 6 {
		http.Error(w, "Password must be at least 6 characters long", http.StatusBadRequest)
		return
	}

	if userDTO.Name != "" {
		user.Name = userDTO.Name
	}
	if userDTO.Email != "" {
		user.Email = userDTO.Email
	}
	if userDTO.PhoneNumber != 0 {
		user.PhoneNumber = userDTO.PhoneNumber
	}
	if userDTO.Password != "" {
		user.Password = userDTO.Password
	}

	json.NewEncoder(w).Encode(user)
}

// getUserHandler retrieves a single user by their ID
func getUserHandler(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	userID, err := strconv.ParseUint(vars["id"], 10, 64)
	if err != nil {
		http.Error(w, "Invalid user ID", http.StatusBadRequest)
		return
	}

	user, exists := users[userID]
	if !exists {
		http.Error(w, "User not found", http.StatusNotFound)
		return
	}

	response := UserDetailResponse{
		ID:    user.ID,
		Name:  user.Name,
		Email: user.Email,
	}

	json.NewEncoder(w).Encode(response)
}

// listUsersHandler lists all users with optional filtering
func listUsersHandler(w http.ResponseWriter, r *http.Request) {
	var response []UserResponseBody

	for _, user := range users {
		response = append(response, UserResponseBody{
			ID:    user.ID,
			Name:  user.Name,
			Email: user.Email,
		})
	}

	json.NewEncoder(w).Encode(response)
}

// isEmailValid checks if the email provided is valid
func isEmailValid(email string) bool {
	emailRegex := regexp.MustCompile(`^[a-z0-9._%+\-]+@[a-z0-9.\-]+\.[a-z]{2,4}$`)
	return emailRegex.MatchString(email)
}

func main() {
	r := mux.NewRouter()
	r.HandleFunc("/users", createUserHandler).Methods("POST")
	r.HandleFunc("/users/{id}", updateUserHandler).Methods("PUT")
	r.HandleFunc("/users/{id}", getUserHandler).Methods("GET")
	r.HandleFunc("/users", listUsersHandler).Methods("GET")

	http.ListenAndServe(":8080", r)
}
