package main

import (
	"fmt"
)

func main() {
	// Test the fiboGenerator function
	fiboGen := fiboGenerator()
	for i := 0; i < 10; i++ {
		fmt.Printf("%d ", fiboGen())
	}
	fmt.Println()

	// Test the fiboChannel function with the first 10 Fibonacci numbers
	fiboChan := fiboChannel(10)
	for num := range fiboChan {
		fmt.Printf("%d ", num)
	}
	fmt.Println()
}

// fiboGenerator returns a function that generates the next Fibonacci number each time it is called.
func fiboGenerator() func() int {
	a, b := 0, 1
	return func() int {
		a, b = b, a+b
		return a
	}
}

// fiboChannel takes an integer n and returns a channel that will produce the first n Fibonacci numbers.
func fiboChannel(n int) chan int {
	out := make(chan int)
	go func() {
		fiboGen := fiboGenerator()
		for i := 0; i < n; i++ {
			out <- fiboGen()
		}
		close(out)
	}()
	return out
}
