)

// CompanyDTO represents DTO structure for a Company
type CompanyDTO struct {
	ID          string `json:"id,omitempty"`
	Name        string `json:"name"`
	Description string `json:"description"`
	URL         string `json:"url"`
}

// CompanyManager manages a list of companies
type CompanyManager struct {
	companies map[string]CompanyDTO
	mu        sync.RWMutex
}

// NewCompanyManager creates a new instance of CompanyManager
func NewCompanyManager() *CompanyManager {
	return &CompanyManager{
		companies: make(map[string]CompanyDTO),
	}
}

// AddCompany adds a new company to the manager
func (m *CompanyManager) AddCompany(name, description, url string) CompanyDTO {
	m.mu.Lock()
	defer m.mu.Unlock()

	id := uuid.New().String()
	company := CompanyDTO{
		ID:          id,
		Name:        name,
		Description: description,
		URL:         url,
	}
	m.companies[id] = company
	return company
}

// GetCompany retrieves a company by its ID
func (m *CompanyManager) GetCompany(id string) (CompanyDTO, error) {
	m.mu.RLock()
	defer m.mu.RUnlock()

	company, exists := m.companies[id]
	if !exists {
		return CompanyDTO{}, errors.New("company not found")
	}
	return company, nil
}

// UpdateCompany updates the details of an existing company
func (m *CompanyManager) UpdateCompany(id, name, description, url string) (CompanyDTO, error) {
	m.mu.Lock()
	defer m.mu.Unlock()

	company, exists := m.companies[id]
	if !exists {
		return CompanyDTO{}, errors.New("company not found")
	}

	company.Name = name
	company.Description = description
	company.URL = url
	m.companies[id] = company
	return company, nil
}

// DeleteCompany removes a company from the manager
func (m *CompanyManager) DeleteCompany(id string) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	_, exists := m.companies[id]
	if !exists {
		return errors.New("company not found")
	}

	delete(m.companies, id)
	return nil
}

// ListCompanies lists all companies
func (m *CompanyManager) ListCompanies() []CompanyDTO {
	m.mu.RLock()
	defer m.mu.RUnlock()

	companies := make([]CompanyDTO, 0, len(m.companies))
	for _, company := range m.companies {
		companies = append(companies, company)
	}
	return companies
}

func main() {
	manager := NewCompanyManager()

	// Test cases
	company1 := manager.AddCompany("TechCorp", "Innovative tech company", "http://techcorp.example.com")
	fmt.Println("Added Company:", company1)

	company2, err := manager.GetCompany(company1.ID)
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Println("Retrieved Company:", company2)
	}

	updatedCompany, err := manager.UpdateCompany(company1.ID, "TechCorp International", "Global tech company", "http://techcorp.example.com/intl")
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Println("Updated Company:", updatedCompany)
	}

	err = manager.DeleteCompany(company1.ID)
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Println("Deleted Company with ID:", company1.ID)
	}

	allCompanies := manager.ListCompanies()
	fmt.Println("All Companies:", allCompanies)
}
