// AddExport adds a new export to the WebAssembly module with the given name, descriptor type, and value index.
func AddExport(mod *structure.Module, name string, descType structure.DescType, valIndex uint32) error {
	// Validate the descriptor type
	if descType < structure.DescTypeFunc || descType > structure.DescTypeGlobal {
		return structure.InvalidDesType
	}

	// Validate the value index based on the descriptor type
	switch descType {
	case structure.DescTypeFunc:
		if valIndex >= uint32(len(mod.Functions)) {
			return errors.New("function index out of bounds")
		}
	case structure.DescTypeTable:
		if valIndex >= uint32(len(mod.Tables)) {
			return errors.New("table index out of bounds")
		}
	case structure.DescTypeMemory:
		if valIndex >= uint32(len(mod.Memories)) {
			return errors.New("memory index out of bounds")
		}
	case structure.DescTypeGlobal:
		if valIndex >= uint32(len(mod.Globals)) {
			return errors.New("global index out of bounds")
		}
	}

	// Create a new export descriptor
	exportDesc := &structure.ExportDesc{
		Type: descType,
		Val:  valIndex,
	}

	// Create a new export and add it to the module's exports
	export := &structure.Export{
		Name: name,
		Desc: exportDesc,
	}
	mod.Exports = append(mod.Exports, export)

	return nil
}

