// Document represents a document with an ID, name, and tags.
type Document struct {
	ID     uuid.UUID
	Name   string
	Tags   []string
	Unique bool
}

// Shelf represents a collection of documents.
type Shelf struct {
	Name      string
	Documents map[uuid.UUID]Document
}

// NewShelf creates a new shelf with the given name.
func NewShelf(name string) *Shelf {
	return &Shelf{
		Name:      name,
		Documents: make(map[uuid.UUID]Document),
	}
}

// AddDocument adds a new document to the shelf.
func (s *Shelf) AddDocument(doc Document) {
	s.Documents[doc.ID] = doc
}

// ReplaceDocument replaces an existing document on the shelf with a new one.
func (s *Shelf) ReplaceDocument(newDoc Document) {
	if _, exists := s.Documents[newDoc.ID]; exists {
		s.Documents[newDoc.ID] = newDoc
	}
}

// RemoveDocument removes a document from the shelf.
func (s *Shelf) RemoveDocument(docID uuid.UUID) (deleteError string) {
	if _, exists := s.Documents[docID]; exists {
		delete(s.Documents, docID)
	} else {
		deleteError = "Document not found"
	}
	return
}

// RenameDocument renames a document on the shelf.
func (s *Shelf) RenameDocument(docID uuid.UUID, newName string) {
	if doc, exists := s.Documents[docID]; exists {
		doc.Name = newName
		s.Documents[docID] = doc
	}
}

// MakeDocumentUnique marks a document as unique and assigns it a unique name.
func (s *Shelf) MakeDocumentUnique(docID uuid.UUID, uniqueName string) {
	if doc, exists := s.Documents[docID]; exists {
		doc.Unique = true
		doc.Name = uniqueName
		s.Documents[docID] = doc
	}
}

// MakeDocumentNonUnique marks a document as non-unique.
func (s *Shelf) MakeDocumentNonUnique(docID uuid.UUID) {
	if doc, exists := s.Documents[docID]; exists {
		doc.Unique = false
		s.Documents[docID] = doc
	}
}

// TagDocument adds tags to a document.
func (s *Shelf) TagDocument(docID uuid.UUID, tags []string) {
	if doc, exists := s.Documents[docID]; exists {
		doc.Tags = append(doc.Tags, tags...)
		s.Documents[docID] = doc
	}
}

// UntagDocument removes tags from a document.
func (s *Shelf) UntagDocument(docID uuid.UUID, tagsToRemove []string) {
	if doc, exists := s.Documents[docID]; exists {
		newTags := []string{}
		for _, tag := range doc.Tags {
			if !contains(tagsToRemove, tag) {
				newTags = append(newTags, tag)
			}
		}
		doc.Tags = newTags
		s.Documents[docID] = doc
	}
}

// contains checks if a slice contains a string.
func contains(slice []string, str string) bool {
	for _, item := range slice {
		if item == str {
			return true
		}
	}
	return false
}

