	"net/http"
	"time"

	"github.com/DimmyJing/valise/attr"
	"github.com/DimmyJing/valise/log"
	"go.opentelemetry.io/otel/attribute"
	"go.opentelemetry.io/otel/trace"
)

// Logger is an interface that represents the ability to log messages.
type Logger interface {
	Log(ctx context.Context, level, severity string, msg attribute.KeyValue, attrs ...attribute.KeyValue) error
}

// Middleware is a function that wraps an http.Handler to perform additional actions.
type Middleware func(http.Handler) http.Handler

// LoggingMiddleware returns a middleware that logs HTTP requests using the provided logger.
func LoggingMiddleware(logger Logger, tracer trace.Tracer) Middleware {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			start := time.Now()
			ctx, span := tracer.Start(r.Context(), "http.request")
			defer span.End()

			next.ServeHTTP(w, r.WithContext(ctx))

			duration := time.Since(start)
			err := logger.Log(ctx, "INFO", "INFO", attribute.StringValue("HTTP request processed"),
				attribute.String("http.method", r.Method),
				attribute.String("http.url", r.URL.String()),
				attribute.Int64("http.duration_ms", duration.Milliseconds()),
			)
			if err != nil {
				fmt.Printf("failed to log request: %v\n", err)
			}
		})
	}
}

// ExampleLogger is a simple implementation of the Logger interface for demonstration purposes.
type ExampleLogger struct{}

func (l *ExampleLogger) Log(ctx context.Context, level, severity string, msg attribute.KeyValue, attrs ...attribute.KeyValue) error {
	fmt.Printf("Level: %s, Severity: %s, Message: %s, Attributes: %v\n", level, severity, msg.Value.AsString(), attrs)
	return nil
}

func main() {
	// Create an example logger and a tracer.
	logger := &ExampleLogger{}
	tracer := trace.NewNoopTracerProvider().Tracer("example-tracer")

	// Create a simple HTTP handler that responds with "Hello, World!".
	handler := http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Write([]byte("Hello, World!"))
	})

	// Wrap the handler with the logging middleware.
	loggedHandler := LoggingMiddleware(logger, tracer)(handler)

	// Start the HTTP server.
	http.ListenAndServe(":8080", loggedHandler)
}

// Test cases can be written using the net/http/httptest package to verify the middleware's functionality.
