	store   map[string][]byte
	options *Options
}

// NewKeyValueStore creates a new key-value store with the given options.
func NewKeyValueStore(opts *Options) *KeyValueStore {
	return &KeyValueStore{
		store:   make(map[string][]byte),
		options: opts,
	}
}

// Set stores the given key-value pair in the key-value store.
func (kvs *KeyValueStore) Set(key string, value []byte) error {
	if int64(len(value)) > kvs.options.ValueThreshold {
		return errors.New("value size exceeds the threshold")
	}
	kvs.store[key] = value
	return nil
}

// Get retrieves the value associated with the given key.
func (kvs *KeyValueStore) Get(key string) ([]byte, error) {
	value, exists := kvs.store[key]
	if !exists {
		return nil, errors.New("key not found")
	}
	return value, nil
}

