// Greeting holds the structure of the JSON response.
type Greeting struct {
	Message string `json:"message"`
	Time    string `json:"time"`
}

// indexHandler responds to requests with a JSON greeting.
func indexHandler(w http.ResponseWriter, r *http.Request) {
	if r.URL.Path != "/greet" {
		http.NotFound(w, r)
		return
	}

	currentTime := time.Now().UTC().Format(time.RFC3339)
	greeting := Greeting{
		Message: "Hello, World!",
		Time:    currentTime,
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(greeting)
}

// logRequest is a middleware that logs the HTTP method, URL path, and response status code.
func logRequest(handler http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		statusRecorder := &statusResponseWriter{w, http.StatusOK}
		handler.ServeHTTP(statusRecorder, r)
		log.Printf("%s %s %d", r.Method, r.URL.Path, statusRecorder.status)
	})
}

// statusResponseWriter wraps http.ResponseWriter to capture the status code.
type statusResponseWriter struct {
	http.ResponseWriter
	status int
}

// WriteHeader captures the status code and calls the underlying WriteHeader method.
func (srw *statusResponseWriter) WriteHeader(code int) {
	srw.status = code
	srw.ResponseWriter.WriteHeader(code)
}

func main() {
	http.Handle("/greet", logRequest(http.HandlerFunc(indexHandler)))

	port := os.Getenv("PORT")
	if port == "" {
		port = "8080"
		log.Printf("Defaulting to port %s", port)
	}

	log.Printf("Listening on port %s", port)
	if err := http.ListenAndServe(":"+port, nil); err != nil {
		log.Fatal(err)
	}
}
