package main

import (
	"encoding/json"
	"fmt"
	"os"
	"sync"
)

type numbers struct {
	A int `json:"a"`
	B int `json:"b"`
}

// Calc reads a JSON file named "numbers.json", calculates the sum of each pair
// using the specified number of goroutines, and returns the total sum and any error encountered.
func Calc(goroutines int) (*int, error) {
	nums, err := getNumbers()
	if err != nil {
		return nil, err
	}

	var wg sync.WaitGroup
	var sums = make(chan int, goroutines)

	batchSize := len(nums) / goroutines
	for i := 0; i < goroutines; i++ {
		start := i * batchSize
		end := (i + 1) * batchSize
		if i == goroutines-1 {
			end = len(nums)
		}

		wg.Add(1)
		go worker(&wg, nums[start:end], sums)
	}

	go func() {
		wg.Wait()
		close(sums)
	}()

	total := getTotal(sums)
	return &total, nil
}

func worker(wg *sync.WaitGroup, nums []numbers, sums chan int) {
	defer wg.Done()

	var sum int
	for _, v := range nums {
		sum += v.A + v.B
	}
	sums <- sum
}

func getTotal(sums chan int) (total int) {
	for sum := range sums {
		total += sum
	}
	return
}

func getNumbers() (nums []numbers, err error) {
	f, err := os.Open("numbers.json")
	if err != nil {
		return
	}
	defer f.Close()

	err = json.NewDecoder(f).Decode(&nums)
	if err != nil {
		return
	}
	return
}

// Test cases to verify the solution correctness.
func main() {
	// Assuming numbers.json contains:
	// [{"a": 1, "b": 2}, {"a": 3, "b": 4}, {"a": 5, "b": 6}, {"a": 7, "b": 8}]
	total, err := Calc(2) // Using 2 goroutines
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Println("Total sum:", *total) // Expected output: Total sum: 36
	}
}
