package main

import (
	"flag"
	"fmt"
	"io"
	"log"
	"sync"
	"time"

	"github.com/tarm/serial"
)

type Count struct {
	sync.RWMutex
	Up   int64
	Down int64
}

var count = &Count{}

func (c *Count) IncUp(n int) {
	c.Lock()
	c.Up += int64(n)
	c.Unlock()
}

func (c *Count) IncDown(n int) {
	c.Lock()
	c.Down += int64(n)
	c.Unlock()
}

func (c *Count) Print() {
	c.RLock()
	fmt.Printf("\rUp: %d, Down: %d\n", c.Up, c.Down)
	c.RUnlock()
}

func relayAndCount(dst io.Writer, src io.Reader, countFn func(int)) {
	buf := make([]byte, 1024)
	for {
		n, err := src.Read(buf)
		if err != nil {
			if err != io.EOF {
				log.Printf("Read error: %v", err)
			}
			break
		}
		if n > 0 {
			if _, err := dst.Write(buf[:n]); err != nil {
				log.Printf("Write error: %v", err)
				break
			}
			countFn(n)
		}
	}
}

func main() {
	baudRate := flag.Int("baud", 115200, "Baud rate")
	flag.Parse()
	if flag.NArg() != 2 {
		log.Fatalf("Two serial port device names are required as arguments.")
	}
	s1, err := serial.OpenPort(&serial.Config{
		Name: flag.Arg(0),
		Baud: *baudRate,
	})
	if err != nil {
		log.Fatal(err)
	}
	defer s1.Close()
	s2, err := serial.OpenPort(&serial.Config{
		Name: flag.Arg(1),
		Baud: *baudRate,
	})
	if err != nil {
		log.Fatal(err)
	}
	defer s2.Close()

	go relayAndCount(s1, s2, count.IncUp)
	go relayAndCount(s2, s1, count.IncDown)

	tick := time.NewTicker(3 * time.Second)
	defer tick.Stop()

	for range tick.C {
		count.Print()
	}
}

