func StartCapture(isConnected bool, filter string) (string, error) {
	if !isConnected {
		return "", errorf(codes.Unavailable, ErrNotConnected.Error())
	}
	if !isResolverHealthy() {
		return "", errorf(codes.Unavailable, ErrResolverUnhealthy.Error())
	}
	if !isUserAuthorized() {
		return "", errorf(codes.PermissionDenied, ErrNotAuthorized.Error())
	}
	if concurrentCaptures >= 3 {
		return "", errorf(codes.ResourceExhausted, errTooManyCaptures.Error())
	}
	if filter == "" {
		return "", errorf(codes.InvalidArgument, errEmptyField.Error())
	}

	concurrentCaptures++
	return "Capture started successfully", nil
}

