// Movie represents a movie with a title, duration, and synopsis.
type Movie struct {
	Title    string
	Duration int
	Synopsis string
}

// MovieCommand is used to create a new movie.
type MovieCommand struct {
	Movie Movie
}

// CreateMovie creates a new Movie object from the given MovieCommand.
// It returns an error if any of the required fields are missing or invalid.
func CreateMovie(cmd MovieCommand) (Movie, error) {
	if cmd.Movie.Title == "" {
		return Movie{}, errors.New("title cannot be empty")
	}
	if cmd.Movie.Duration <= 0 {
		return Movie{}, errors.New("duration must be positive")
	}
	if cmd.Movie.Synopsis == "" {
		return Movie{}, errors.New("synopsis cannot be empty")
	}
	return cmd.Movie, nil
}

// Unit tests for CreateMovie function.
func TestCreateMovie(t *testing.T) {
	t.Run("Valid movie creation", func(t *testing.T) {
		cmd := MovieCommand{
			Movie: Movie{
				Title:    "The Grand Adventure",
				Duration: 120,
				Synopsis: "An epic journey of discovery.",
			},
		}
		movie, err := CreateMovie(cmd)
		assert.NoError(t, err)
		assert.Equal(t, cmd.Movie, movie)
	})

	t.Run("Invalid movie creation with empty title", func(t *testing.T) {
		cmd := MovieCommand{
			Movie: Movie{
				Duration: 120,
				Synopsis: "An epic journey of discovery.",
			},
		}
		_, err := CreateMovie(cmd)
		assert.Error(t, err)
		assert.Equal(t, "title cannot be empty", err.Error())
	})

	t.Run("Invalid movie creation with non-positive duration", func(t *testing.T) {
		cmd := MovieCommand{
			Movie: Movie{
				Title:    "The Grand Adventure",
				Duration: 0,
				Synopsis: "An epic journey of discovery.",
			},
		}
