			Movie: Movie{
				Title:    "The Grand Adventure",
				Duration: 120,
			},
		}
		_, err := CreateMovie(cmd)
		assert.Error(t, err)
		assert.Equal(t, "synopsis cannot be empty", err.Error())
	})
