func NewParty(name, owner string) *Party {
	party := &Party{
		Id:    bson.NewObjectId(),
		Name:  name,
		Owner: owner,
		Track: []Track{},
	}
	parties[party.Id] = party
	return party
}

func AddTrack(partyID bson.ObjectId, title, artist string, duration int) error {
	party, exists := parties[partyID]
	if !exists {
		return errors.New("party not found")
	}
	party.Track = append(party.Track, Track{Title: title, Artist: artist, Duration: duration})
	return nil
}

func GetPlaylist(partyID bson.ObjectId) ([]Track, error) {
	party, exists := parties[partyID]
	if !exists {
		return nil, errors.New("party not found")
	}
	return party.Track, nil
}

