package main

import (
	"fmt"
	"regexp"
	"strings"
)

var txPattern = regexp.MustCompile(
	`\+` + // Plus sign
		`(\d+\.?\d*|\d*\.?\d+)` + // Amount
		`([A-Za-z]{2,6})` + // Currency code
		`(?:@((?:[a-zA-Z0-9]+_?)+))?` + // Optional username
		`()` + // Sentinel group
		`(?:[\s)\]}:;.,!?"']|\z)`, // Following character
)

const (
	maxAmountLength   = 100
	maxUsernameLength = 16
	maxTxsPerMessage  = 3000
)

type ChatTxCandidate struct {
	Amount       string
	CurrencyCode string
	Username     *string
	Full         string
	Position     []int
}

func FindChatTxCandidates(xs string) []ChatTxCandidate {
	buf := xs
	bufOffset := 0
	var matches []ChatTxCandidate
	for i := 0; i < maxTxsPerMessage; i++ {
		rawIndices := txPattern.FindStringSubmatchIndex(buf)
		if rawIndices == nil {
			break
		}
		group := func(n int) (s string, startIndex, endIndex int) {
			startIndex, endIndex = rawIndices[2*n], rawIndices[2*n+1]
			if startIndex >= 0 {
				return buf[startIndex:endIndex], startIndex, endIndex
			}
			return "", startIndex, endIndex
		}
		amount, amountStart, _ := group(1)
		_, _, nextIndex := group(4)
		if amount != "0" {
			currencyCode, _, ccEnd := group(2)
			currencyCode = strings.ToUpper(currencyCode)
			var atSign string
			endIndex := ccEnd
			username, _, usernameEndIndex := group(3)
			if len(username) > 0 {
				atSign = "@"
				endIndex = usernameEndIndex
			}
			full := fmt.Sprintf("+%s%s%s%s", amount, currencyCode, atSign, username)
			if len(amount) <= maxAmountLength && len(username) <= maxUsernameLength {
				var txUsername *string
				if username == "" {
					txUsername = nil
				} else {
					txUsername = &username
				}
				matches = append(matches, ChatTxCandidate{
					Full:         full,
					Amount:       amount,
					CurrencyCode: currencyCode,
					Username:     txUsername,
					Position:     []int{amountStart - 1 + bufOffset, endIndex + bufOffset},
				})
			}
		}
		if nextIndex == -1 || nextIndex > len(buf) {
			return nil
		}
		buf = buf[nextIndex:]
		bufOffset += nextIndex
	}
	return matches
}

func main() {
	// Test cases
	messages := []string{
		"Hey, can you send me +10USD for lunch?",
		"Sure, I'll send +10USD@alice and +5.5XLM@bob right away.",
		"Reminder: +0USD is not a valid transaction.",
		"Invalid cases: +100000000000000000000USD and +10USD@verylongusernamethatisinvalid",
		"Edge cases: +10USD+20EUR@john, +10USD, +10USD@john.",
	}

	for _, msg := range messages {
		fmt.Printf("Message: %s\n", msg)
		fmt.Println("Transactions found:")
		for _, tx := range FindChatTxCandidates(msg) {
			fmt.Printf("  %+v\n", tx)
		}
		fmt.Println()
	}
}
