package memory

import (
	"errors"
	"sync"

	"github.com/jasosa/PresetsManagement/pkg/preset"
)

var (
	ErrPresetNotFound = errors.New("preset not found")
)

type DataStore interface {
	SavePreset(preset.Info) error
	LoadPreset(name string) (preset.Info, error)
	GetPresetNames() []string
}

type memoryDataStore struct {
	presets map[string]preset.Info
	mu      sync.RWMutex
}

func NewDataStore() DataStore {
	return &memoryDataStore{
		presets: make(map[string]preset.Info),
	}
}

func (m *memoryDataStore) SavePreset(presetInfo preset.Info) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	if _, exists := m.presets[presetInfo.Name]; exists {
		return errors.New("preset already exists")
	}

	m.presets[presetInfo.Name] = presetInfo
	return nil
}

func (m *memoryDataStore) LoadPreset(name string) (preset.Info, error) {
	m.mu.RLock()
	defer m.mu.RUnlock()

	presetInfo, ok := m.presets[name]
	if !ok {
		return preset.Info{}, ErrPresetNotFound
	}

	return presetInfo, nil
}

func (m *memoryDataStore) GetPresetNames() []string {
	m.mu.RLock()
	defer m.mu.RUnlock()

	names := make([]string, 0, len(m.presets))
	for name := range m.presets {
		names = append(names, name)
	}
	return names
}

// Test cases to verify the solution correctness
func TestSavePreset(t *testing.T) {
	// Arrange
	ds := NewDataStore()

	// Act
	err := ds.SavePreset(preset.Info{Name: "Preset 1"})

	// Assert
	if err != nil {
		t.Errorf("Failed to save preset: %v", err)
	}
}

func TestLoadPreset(t *testing.T) {
	// Arrange
	ds := NewDataStore()
	presetName := "Preset A"
	presetInfo := preset.Info{Name: presetName}
	ds.SavePreset(presetInfo)

	// Act
	loadedPreset, err := ds.LoadPreset(presetName)

	// Assert
	if err != nil {
		t.Errorf("Expected preset was not found")
	}

	if loadedPreset.Name != presetName {
		t.Errorf("Expected preset name was %s but got %s", presetName, loadedPreset.Name)
	}
}

func TestLoadNotSavedPresetGivesError(t *testing.T) {
	// Arrange
	ds := NewDataStore()

	// Act
	_, err := ds.LoadPreset("Nonexistent preset")

	// Assert
	if err != ErrPresetNotFound {
		t.Errorf("Expected error was %v but got %v", ErrPresetNotFound, err)
	}
}

func TestGetAllPresetNames(t *testing.T) {
	// Arrange
	ds := NewDataStore()
