	"math"
	"os"
	"strconv"
)

// CalcFloat represents a simple floating-point calculator.
type CalcFloat struct {
	X        float64
	Y        float64
	Operator string
}

// Calc performs the arithmetic operation based on the operator.
func (c *CalcFloat) Calc() float64 {
	switch c.Operator {
	case "+":
		return c.X + c.Y
	case "-":
		return c.X - c.Y
	case "*":
		return c.X * c.Y
	case "/":
		if c.Y == 0 {
			fmt.Println("Error: Division by zero.")
			os.Exit(1)
		}
		return c.X / c.Y
	default:
		fmt.Println("Error: Invalid operator.")
		os.Exit(1)
	}
	return 0
}

// RoundTo rounds a floating-point number to a specified number of decimal places.
func RoundTo(val float64, places int) float64 {
	shift := math.Pow(10, float64(places))
	return math.Round(val*shift) / shift
}

func main() {
	var (
		x          float64
		y          float64
		op         string
		floatRound int
		p          bool // Print equation e.g., 2 + 3 = 5
	)

	fmt.Println("Task 1 - Calculator")

	flag.Float64Var(&x, "x", 0, "Float64 X")
	flag.Float64Var(&y, "y", 0, "Float64 Y")
	flag.StringVar(&op, "o", "", "Math Operator: +, -, *, or /.")
	flag.IntVar(&floatRound, "d", 2, "Rounding it to x decimal places")
	flag.BoolVar(&p, "p", false, "Print equation")
	flag.Parse()

	if op != "+" && op != "-" && op != "*" && op != "/" {
		fmt.Println("Error: Invalid operator. You can use only +, -, * or /")
		os.Exit(1)
	}

	f := CalcFloat{X: x, Y: y, Operator: op}
	result := f.Calc()
	roundedResult := RoundTo(result, floatRound)

	if p {
		fmt.Printf("Equation: %.f %s %.f = %.f\n", x, op, y, roundedResult)
	} else {
		fmt.Printf("Result: %.f\n", roundedResult)
	}
}

// Test cases:
// go run calculator.go -x 234.998989 -y 56.789 -o / -d 8 -p
// go run calculator.go -x 234.998989 -y 56.789 -o / -d 2 -p
