```go
package main

import (
	"errors"
	"fmt"
	"sort"
	"sync"
	"time"
)

// CacheDriverer interface
type CacheDriverer interface {
	Open(dsn string) (Cacher, error)
	OpenConnection(connection interface{}, settings ...string) (Cacher, error)
}

// Cacher interface
type Cacher interface {
	Get(key string) ([]byte, error)
	Set(key string, value []byte, expiration ...time.Duration) error
	Delete(key string) error
	Incr(key string, num ...int) (int, error)
	Decr(key string, num ...int) (int, error)
	Close() error
}

// MemoryCacheDriver is a driver for an in-memory cache.
type MemoryCacheDriver struct{}

// MemoryCache is an in-memory cache implementation of Cacher.
type MemoryCache struct {
	mu       sync.Mutex
	storage  map[string]cacheItem
	lifetime time.Duration
}

type cacheItem struct {
	value      []byte
	expiration time.Time
}

// Open creates a new MemoryCache instance.
func (d *MemoryCacheDriver) Open(dsn string) (Cacher, error) {
	return &MemoryCache{
		storage: make(map[string]cacheItem),
	}, nil
}

// OpenConnection is not used for MemoryCache.
func (d *MemoryCacheDriver) OpenConnection(connection interface{}, settings ...string) (Cacher, error) {
	return nil, errors.New("MemoryCache does not support OpenConnection")
}

// Get retrieves a value from the cache.
func (c *MemoryCache) Get(key string) ([]byte, error) {
	c.mu.Lock()
	defer c.mu.Unlock()

	item, exists := c.storage[key]
	if !exists || item.expiration.Before(time.Now()) {
		return nil, errors.New("key not found or expired")
	}
	return item.value, nil
}

// Set adds a value to the cache with an optional expiration time.
func (c *MemoryCache) Set(key string, value []byte, expiration ...time.Duration) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	exp := time.Now().Add(c.lifetime)
	if len(expiration) > 0 {
		exp = time.Now().Add(expiration[0])
	}
	c.storage[key] = cacheItem{
		value:      value,
		expiration: exp,
	}
	return nil
}

// Delete removes a value from the cache.
func (c *MemoryCache) Delete(key string) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	delete(c.storage, key)
	return nil
}

// Incr increments a numeric value in the cache.
func (c *MemoryCache) Incr(key string, num ...int) (int, error) {
	c.mu.Lock()
	defer c.mu.Unlock()

	item, exists := c.storage[key]
	if !exists || item.expiration.Before(time.Now()) {
		return 0, errors.New("key not found or expired")
	}

	val, err := strconv.Atoi(string(item.value))
	if err != nil {
		return 0, err
	}

	increment := 1
	if len(num) > 0 {
		increment = num[0]
	}
	val += increment

	c.storage[key] = cacheItem{
		value:      []byte(strconv.Itoa(val)),
		expiration: item.expiration,
	}
	return val, nil
}

// Decr decrements a numeric value in the cache.
func (c *MemoryCache) Decr(key string, num ...int) (int, error) {
	c.mu.Lock()
	defer c.mu.Unlock()

	item, exists := c.storage[key]
	if !exists || item.expiration.Before(time.Now()) {
		return 0, errors.New("key not found or expired")
	}

	val, err := strconv.Atoi(string(item.value))
	if err != nil {
		return 0, err
	}

	decrement := 1
	if len(num) > 0 {
		decrement = num[0]
	}
	val -= decrement

	c.storage[key] = cacheItem{
		value:      []byte(strconv.Itoa(val)),
		expiration: item.expiration,
	}
	return val, nil
}

// Close performs any necessary cleanup for the cache.
func (c *MemoryCache) Close() error {
	return nil
}

// Register makes a cache driver available by the provided name.
var drivers = make(map[string]CacheDriverer)

func Register(name string, driver CacheDriverer) {
	if driver == nil {
		panic("Register driver is nil")
	}
	if _, dup := drivers[name]; dup {
		panic("Register called twice for driver " + name)
	}
	drivers[name] = driver
}

// Drivers returns a list of available driver names.
func Drivers() []string {
	var list []string
	for name := range drivers {
		list = append(list, name)
	}
	sort.Strings(list)
	return list
}

// Open opens a cache by DSN.
func Open(dsn string) (Cacher, error) {
	driverName := "memory" // In a real implementation, parse the DSN to get the driver name.
	di, ok := drivers[driverName]
	if !ok {
		return nil, fmt.Errorf("unknown driver %q", driverName)
	}
	return di.Open(dsn)
}

func main() {
	// Register the memory cache driver.
	Register("memory", &MemoryCacheDriver{})

	// Open a new memory cache.
	cache, err := Open("memory://")
	if err != nil {
		panic(err)
	}

	// Test cases
	key := "testKey"
	value := []byte("testValue")

	// Set a value without expiration.
	err = cache.Set(key, value)
	if err != nil {
		panic(err)
	}

	// Get the value.
	retrievedValue, err := cache.Get(key)
	if err != nil {
		panic(err)
	}
	fmt.Printf("Retrieved value: %s\n", retrievedValue)

	// Increment the value.
	_, err = cache.Incr(key)
	if err == nil {
		panic("Expected error when incrementing non-numeric value")
	}

	// Set a numeric value.
	err = cache.Set(key, []byte("1"))
	if err != nil {
		panic(err)
	}

	// Increment the numeric value.
	newValue, err := cache.Incr(key)
	if err != nil {
		panic(err)
	}
	fmt.Printf("Incremented value: %d\n", newValue)

	// Decrement the numeric value.
	newValue, err = cache.Decr(key)
	if err != nil {
		panic(err)
	}
	fmt.Printf("Decremented value: %d\n", newValue)

	// Set a value with expiration.
	err = cache.Set(key, value, 1*time.Second)
	if err != nil {
		panic(err)
	}

	// Wait for the value to expire.
	time.Sleep(2 * time.Second)

	// Try to get the expired value.
	_, err = cache.Get(key)
	if err == nil {
		panic("Expected error when getting expired value")
	}

	fmt.Println("All test cases passed.")
}
