type Person struct {
	Name string
	Age  int
	Id   string
	bak  []byte
}

func (p *Person) SetName(name string) {
	p.Name = name
}

func (p *Person) Set(name string, age int, id string, bak []byte) {
	p.Name = name
	p.Age = age
	p.Id = id
	p.bak = bak
}

func (p *Person) Get(id string) (string, int, []byte) {
	if p.Id == id {
		return p.Name, p.Age, p.bak
	}
	return "", 0, nil
}

func main() {
	p := new(Person)

	pTyp := reflect.TypeOf(p)
	pVal := reflect.ValueOf(p)

	for i := 0; i < pTyp.NumMethod(); i++ {
		method := pTyp.Method(i)
		fmt.Println("method:", method.Name, method.Type)

		mtyp := method.Type
		fmt.Println("\tparams in num:", mtyp.NumIn())
		for j := 0; j < mtyp.NumIn(); j++ {
			in := mtyp.In(j)
			fmt.Println("\t\ttype in:", in)
		}

		fmt.Println("\tparams out num:", mtyp.NumOut())
		for j := 0; j < mtyp.NumOut(); j++ {
			out := mtyp.Out(j)
			fmt.Println("\t\ttype out:", out)
		}
	}

	// Dynamically invoke SetName
	name := "John Doe"
	args := []reflect.Value{reflect.ValueOf(name)}
	pVal.MethodByName("SetName").Call(args)
	fmt.Println("SetName called with:", name)

	// Dynamically invoke Set
	setArgs := []reflect.Value{
		reflect.ValueOf("Jane Doe"),
		reflect.ValueOf(30),
		reflect.ValueOf("12345"),
		reflect.ValueOf([]byte{1, 2, 3, 4, 5}),
	}
	pVal.MethodByName("Set").Call(setArgs)
	fmt.Println("Set called with:", setArgs)

	// Dynamically invoke Get
	getArgs := []reflect.Value{reflect.ValueOf("12345")}
	results := pVal.MethodByName("Get").Call(getArgs)
	fmt.Println("Get called with ID '12345':", results)
}

// Test cases to verify the solution correctness
func test() {
	p := &Person{Name: "Alice", Age: 25, Id: "abc123", bak: []byte{10, 20, 30}}
	name, age, bak := p.Get("abc123")
	if name != "Alice" || age != 25 || !reflect.DeepEqual(bak, []byte{10, 20, 30}) {
		fmt.Println("Test failed: Get method did not return expected values.")
	} else {
		fmt.Println("Test passed: Get method returned expected values.")
	}

	p.SetName("Bob")
	if p.Name != "Bob" {
		fmt.Println("Test failed: SetName method did not set the name correctly.")
	} else {
		fmt.Println("Test passed: SetName method set the name correctly.")
	}

	p.Set("Charlie", 40, "def456", []byte{40, 50, 60})
	if p.Name != "Charlie" || p.Age != 40 || p.Id != "def456" || !reflect.DeepEqual(p.bak, []byte{40, 50, 60}) {
		fmt.Println("Test failed: Set method did not set the fields correctly.")
	} else {
		fmt.Println("Test passed: Set method set the fields correctly.")
	}
}

func main() {
	main()
	test()
}
