	for _, s := range c.Services {
		if s.ID == service.ID {
			return errors.New("service already exists")
		}
	}
	c.Services = append(c.Services, service)
	return nil
}

// RemoveService removes a service from the list by its identifier.
func (c *CloudSupportedServicesList) RemoveService(serviceID string) error {
	for i, s := range c.Services {
		if s.ID == serviceID {
			c.Services = append(c.Services[:i], c.Services[i+1:]...)
			return nil
		}
	}
	return errors.New("service not found")
}

// ListServices returns a list of all currently supported cloud services.
func (c *CloudSupportedServicesList) ListServices() []CloudSupportedService {
	return c.Services
}

