	resourceMap.Unlock()
	return resource
}

// updateResource updates an existing Resource and returns it.
func updateResource(id, data string) (*Resource, error) {
	resourceMap.RLock()
	resource, exists := resourceMap.internalMap[id]
	resourceMap.RUnlock()
	if !exists {
