// ClusterIDManager provides a thread-safe way to manage a cluster's unique identifier.
// The identifier can be set once and retrieved as needed. It also provides a human-readable
// representation of the identifier and a reset function for testing purposes.
type ClusterIDManager struct {
	mu        sync.Mutex
	clusterID uuid.UUID
}

// NewClusterIDManager creates a new instance of ClusterIDManager with an unset identifier.
func NewClusterIDManager() *ClusterIDManager {
	return &ClusterIDManager{}
}

// String returns the cluster ID in a human-readable format, or "?" if it is unset.
func (m *ClusterIDManager) String() string {
	m.mu.Lock()
	defer m.mu.Unlock()

	if m.clusterID == uuid.Nil {
		return "?"
	}
	return m.clusterID.String()
}

// Get returns the current cluster ID; uuid.Nil if it is unset.
func (m *ClusterIDManager) Get() uuid.UUID {
	m.mu.Lock()
	defer m.mu.Unlock()

	return m.clusterID
}

// Set sets the current cluster ID. If it is already set, the value must match.
// It logs an informational message when the ID is set and a fatal error if an attempt
// is made to set a different ID.
func (m *ClusterIDManager) Set(ctx context.Context, val uuid.UUID) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	if m.clusterID == uuid.Nil {
		m.clusterID = val
		fmt.Printf("ClusterID set to %s\n", val)
		return nil
	} else if m.clusterID != val {
		return fmt.Errorf("different ClusterIDs set: %s, then %s", m.clusterID, val)
	}
	return nil
}

// Reset changes the ClusterID regardless of the old value. Should only be used in testing code.
func (m *ClusterIDManager) Reset(val uuid.UUID) {
	m.mu.Lock()
	defer m.mu.Unlock()

	m.clusterID = val
}

// Example usage and test cases
func main() {
