	err := manager.Set(ctx, newID)
	if err != nil {
		fmt.Println("Error setting ClusterID:", err)
	}
	fmt.Println("ClusterID after Set:", manager.String())

	// Test case 3: Set ClusterID again with the same value
	err = manager.Set(ctx, newID)
	if err != nil {
		fmt.Println("Error setting ClusterID:", err)
	}

	// Test case 4: Set ClusterID with a different value
	anotherID, _ := uuid.NewUUID()
	err = manager.Set(ctx, anotherID)
	if err != nil {
		fmt.Println("Error setting ClusterID:", err)
	}

