Design a GraphQL subscription service that allows clients to subscribe to real-time updates of currently playing music tracks. The service should provide a stream of information about the currently playing track, including the artist, title, and album. The updates should only be sent to the client when the currently playing track changes.

The service should be resilient to errors, and in case of an error while streaming the data, the error should be logged and the streaming should continue without interruption.

Write a Go program that implements the `SubscriptionResolver` struct with a `CurrentlyPlaying` method that subscribes to a music stream and filters out consecutive duplicates. The `CurrentlyPlaying` method should return a channel that emits updates of the currently playing music track whenever the track changes.

The `music.Streamer` interface is defined as follows:

```go
package music

type Streamer interface {
    StreamCurrent(ctx context.Context, dst chan<- CurrentlyPlayingResult) error
}

type CurrentlyPlayingResult struct {
    Current *CurrentlyPlaying
    Error   error
}

func (r CurrentlyPlayingResult) HasError() bool {
    return r.Error != nil
}

type CurrentlyPlaying struct {
    Artist string
    Title  string
    Album  string
}
```

The `IsEqualsCurrentlyPlaying` function is a helper function that compares two `CurrentlyPlaying` instances and returns `true` if they are equal, and `false` otherwise.

output:
```go
package main

import (
	"context"
	"errors"
	"fmt"
	"time"

	"github.com/99designs/gqlgen/graphql"
	"go.stevenxie.me/api/v2/music"
)

// Import the necessary packages
import (
	"log"
)

// Define the IsEqualsCurrentlyPlaying function
func IsEqualsCurrentlyPlaying(a, b *music.CurrentlyPlaying) bool {
	if a == b {
		return true
	}
	if a == nil || b == nil {
		return false
	}
	return a.Artist == b.Artist && a.Title == b.Title && a.Album == b.Album
}

// Implement the SubscriptionResolver struct
type SubscriptionResolver struct {
	stream music.Streamer
}

// Implement the CurrentlyPlaying method
func (res SubscriptionResolver) CurrentlyPlaying(ctx context.Context) (<-chan *music.CurrentlyPlaying, error) {
	src := make(chan music.CurrentlyPlayingResult, 1)
	dst := make(chan *music.CurrentlyPlaying, 1)

	go func() {
		var prev *music.CurrentlyPlaying
		for res := range src {
			if res.HasError() {
				graphql.AddError(ctx, res.Error)
				continue
			}
			curr := res.Current
			if !IsEqualsCurrentlyPlaying(prev, curr) {
				dst <- curr
			}
			prev = curr
		}
		close(dst)
	}()

	if err := res.stream.StreamCurrent(ctx, src); err != nil {
		return nil, err
	}
	return dst, nil
}

// Mock implementation of the music.Streamer interface for testing
type mockStreamer struct{}

func (ms mockStreamer) StreamCurrent(ctx context.Context, dst chan<- music.CurrentlyPlayingResult) error {
	ticker := time.NewTicker(500 * time.Millisecond)
	defer ticker.Stop()

	for i := 0; i < 5; i++ {
		select {
		case <-ctx.Done():
			return ctx.Err()
		case <-ticker.C:
			dst <- music.CurrentlyPlayingResult{
				Current: &music.CurrentlyPlaying{
					Artist: fmt.Sprintf("Artist %d", i),
					Title:  fmt.Sprintf("Title %d", i),
					Album:  fmt.Sprintf("Album %d", i),
				},
			}
		}
	}
	close(dst)
	return nil
}

func main() {
	ctx := context.Background()
	resolver := SubscriptionResolver{stream: mockStreamer{}}

	// Start the subscription
	stream, err := resolver.CurrentlyPlaying(ctx)
	if err != nil {
		log.Fatalf("Failed to start subscription: %v", err)
	}

	// Listen for updates
	for update := range stream {
		if update != nil {
			fmt.Printf("Now playing: %s - %s [%s]\n", update.Artist, update.Title, update.Album)
		}
	}
}
