	team.lineup = lineup
	return nil
}

func (l *League) UpdatePositions(teamShort string, positions [9]*Player) error {
	team, exists := l.teams[teamShort]
	if !exists {
		return fmt.Errorf("team with abbreviation %s does not exist", teamShort)
	}
	team.positions = positions
	return nil
}

func (l *League) RecordGameResult(winningTeamShort, losingTeamShort string) error {
	winner, exists := l.teams[winningTeamShort]
	if !exists {
		return fmt.Errorf("winning team with abbreviation %s does not exist", winningTeamShort)
	}
	loser, exists := l.teams[losingTeamShort]
	if !exists {
		return fmt.Errorf("losing team with abbreviation %s does not exist", losingTeamShort)
	}
	winner.wins++
	loser.losses++
	return nil
}

func (l *League) GetStandings() []Team {
	standings := make([]Team, 0, len(l.teams))
	for _, team := range l.teams {
		standings = append(standings, *team)
	}
	sort.Slice(standings, func(i, j int) bool {
		if standings[i].wins == standings[j].wins {
			return standings[i].losses < standings[j].losses
		}
		return standings[i].wins > standings[j].wins
	})
	return standings
}

func main() {
	// Create a new league
	league := NewLeague()

	// Add teams to the league
	league.AddTeam("New York", "Yankees", "NYY")
	league.AddTeam("Boston", "Red Sox", "BOS")

	// Add players to the teams
	league.AddPlayerToTeam("NYY", &Player{name: "Player A", BT: 80, OBT: 90})
	league.AddPlayerToTeam("BOS", &Player{name: "Player B", BT: 85, OBT: 95})

	// Record a game result
	league.RecordGameResult("NYY", "BOS")

	// Get the current standings
	standings := league.GetStandings()
	for _, team := range standings {
		fmt.Printf("%s - Wins: %d, Losses: %d\n", team.short, team.wins, team.losses)
	}
}
