// SetTokenOutPath sets the global file handle to the provided *os.File object.
func SetTokenOutPath(path *os.File) {
	token_path = path
}

// OutputToken writes the provided message string to the file represented by the global file handle.
// It returns an error if the file handle is not set or if an error occurs during file writing.
func OutputToken(message string) error {
	if token_path == nil {
		return errors.New("output path has not been set")
	}
	_, err := token_path.WriteString(message)
	if err != nil {
		return err
	}
	return nil
}

