	// Test case 1: Attempt to write token without setting the output path
	err := OutputToken("token123")
	if err == nil || err.Error() != "output path has not been set" {
		panic("Test case 1 failed: expected an error when output path is not set")
	}

	// Test case 2: Set output path and write token
	file, err := os.Create("token_output.txt")
	if err != nil {
		panic("Test case 2 failed: unable to create output file")
	}
	defer file.Close()
	SetTokenOutPath(file)
	err = OutputToken("token123")
	if err != nil {
		panic("Test case 2 failed: " + err.Error())
	}

	// Test case 3: Verify the content of the file
	file.Seek(0, 0) // Reset the file pointer to the beginning of the file
