// FhirStoreTimeouts defines the possible timeouts for create, read, update, and delete operations.
type FhirStoreTimeouts struct {
	Create string
	Read   string
	Update string
	Delete string
}

// ValidateFhirStoreTimeouts checks if the provided timeouts are within acceptable ranges and formats.
func ValidateFhirStoreTimeouts(timeouts FhirStoreTimeouts) error {
	for operation, timeout := range map[string]string{
		"create": timeouts.Create,
		"read":   timeouts.Read,
		"update": timeouts.Update,
		"delete": timeouts.Delete,
	} {
		if err := validateTimeout(operation, timeout); err != nil {
			return err
		}
	}
	return nil
}

// validateTimeout checks if a single timeout is within the acceptable range and format.
func validateTimeout(operation, timeout string) error {
	if timeout == "" {
		return fmt.Errorf("timeout for %s operation is required, but empty was provided", operation)
	}

	duration, err := time.ParseDuration(timeout)
	if err != nil {
		return fmt.Errorf("invalid timeout format for %s operation: %v", operation, err)
	}

	minDuration, _ := time.ParseDuration("5s")
	maxDuration, _ := time.ParseDuration("5m")

	if duration < minDuration || duration > maxDuration {
		return fmt.Errorf("timeout for %s operation must be between 5s and 5m, but %s was provided", operation, timeout)
	}

	return nil
}

// Test cases to verify the solution correctness.
func main() {
	validTimeouts := FhirStoreTimeouts{
		Create: "30s",
		Read:   "10s",
		Update: "1m",
		Delete: "45s",
	}

	invalidTimeouts := FhirStoreTimeouts{
		Create: "3s",   // less than 5s
		Read:   "10m",  // more than 5m
		Update: "60",   // missing unit
		Delete: "1hour", // invalid unit
	}

	fmt.Println("Validating validTimeouts:", ValidateFhirStoreTimeouts(validTimeouts))
	fmt.Println("Validating invalidTimeouts:", ValidateFhirStoreTimeouts(invalidTimeouts))
}
