package main

import (
	"fmt"
)

type Request struct {
	handlerType string
	data        string
}

// NewRequest creates a new Request.
func newRequest(handlerType string, data string) *Request {
	return &Request{
		handlerType: handlerType,
		data:        data,
	}
}

type Response struct {
	message string
}

type Handler interface {
	HandleRequest(*Request) *Response
}

type DataHandler struct{}

func (h *DataHandler) HandleRequest(req *Request) *Response {
	if req.handlerType == "data" {
		return &Response{message: "Data processed: " + req.data}
	}
	return nil
}

type AuthHandler struct{}

func (h *AuthHandler) HandleRequest(req *Request) *Response {
	if req.handlerType == "auth" {
		return &Response{message: "Authentication successful: " + req.data}
	}
	return nil
}

type LoggingHandler struct{}

func (h *LoggingHandler) HandleRequest(req *Request) *Response {
	if req.handlerType == "log" {
		return &Response{message: "Log entry: " + req.data}
	}
	return nil
}

type Chain struct {
	handlers []Handler
}

func (c *Chain) ProcessRequest(req *Request) *Response {
	for _, handler := range c.handlers {
		response := handler.HandleRequest(req)
		if response != nil {
			return response
		}
	}
	return &Response{message: "Request not processed"}
}

func main() {
	chain := Chain{
		handlers: []Handler{&DataHandler{}, &AuthHandler{}, &LoggingHandler{}},
	}

	testCases := []*Request{
		newRequest("data", "some data"),
		newRequest("auth", "user credentials"),
		newRequest("log", "log this message"),
		newRequest("unknown", "should not be processed"),
	}

	for _, testCase := range testCases {
		response := chain.ProcessRequest(testCase)
		fmt.Println(response.message)
	}
}
