	"github.com/labstack/echo/v4"
	"github.com/labstack/echo/v4/middleware"
	"gorm.io/driver/sqlite"
	"gorm.io/gorm"
	"github.com/oklog/ulid/v2"
	"math/rand"
	"time"
	"io"
)

// Address represents a user's address in the e-commerce platform.
type Address struct {
	ULID        string `gorm:"primary_key"`
	UserID      string `json:"user_id" gorm:"not null"`
	FullName    string `json:"full_name" gorm:"not null"`
	Street      string `json:"street" gorm:"not null"`
	City        string `json:"city" gorm:"not null"`
	State       string `json:"state" gorm:"not null"`
	ZipCode     string `json:"zip_code" gorm:"not null"`
	Country     string `json:"country" gorm:"not null"`
	PhoneNumber string `json:"phone_number" gorm:"not null"`
}

// Validation validates the Address fields.
func (a *Address) Validation() error {
	if a.UserID == "" || a.FullName == "" || a.Street == "" || a.City == "" || a.State == "" || a.ZipCode == "" || a.Country == "" || a.PhoneNumber == "" {
		return echo.NewHTTPError(http.StatusBadRequest, "All fields must be filled")
	}
	// Validate phone number format (simple example, adjust regex as needed)
	matched, err := regexp.MatchString(`^\+[1-9]\d{1,14}$`, a.PhoneNumber)
	if err != nil {
		return echo.NewHTTPError(http.StatusInternalServerError, "Error validating phone number")
	}
	if !matched {
		return echo.NewHTTPError(http.StatusBadRequest, "Invalid phone number format")
	}
	return nil
}

// NewULID generates a new ULID.
func NewULID() string {
	t := time.Now().UTC()
	entropy := ulid.Monotonic(rand.New(rand.NewSource(t.UnixNano())), 0)
	return ulid.MustNew(ulid.Timestamp(t), entropy).String()
}

// ConnectGORM initializes and returns a GORM database connection.
func ConnectGORM() *gorm.DB {
	db, err := gorm.Open(sqlite.Open("addresses.db"), &gorm.Config{})
	if err != nil {
		panic("failed to connect database")
	}
	// Migrate the schema
	db.AutoMigrate(&Address{})
	return db
}

// Handlers
func GetAllAddresses(c echo.Context) error {
	var addresses []Address
	db := ConnectGORM()
	db.Find(&addresses)
	return c.JSON(http.StatusOK, addresses)
}

func GetAddress(c echo.Context) error {
	addressUlid := c.Param("id")
	var address Address
	db := ConnectGORM()
	if err := db.First(&address, "ulid = ?", addressUlid).Error; err != nil {
		return echo.NewHTTPError(http.StatusNotFound, "Address not found")
	}
	return c.JSON(http.StatusOK, address)
}

func CreateAddress(c echo.Context) error {
	address := new(Address)
	if err := c.Bind(address); err != nil {
		return echo.NewHTTPError(http.StatusBadRequest, "Invalid input")
	}
	address.ULID = NewULID()
	if err := address.Validation(); err != nil {
		return err
	}
	db := ConnectGORM()
	if err := db.Create(&address).Error; err != nil {
		return echo.NewHTTPError(http.StatusInternalServerError, "Failed to create address")
	}
	return c.JSON(http.StatusCreated, address)
}

func UpdateAddress(c echo.Context) error {
	addressUlid := c.Param("id")
	var address Address
	db := ConnectGORM()
	if err := db.First(&address, "ulid = ?", addressUlid).Error; err != nil {
		return echo.NewHTTPError(http.StatusNotFound, "Address not found")
	}
	if err := c.Bind(&address); err != nil {
		return echo.NewHTTPError(http.StatusBadRequest, "Invalid input")
	}
	if err := address.Validation(); err != nil {
		return err
	}
	if err := db.Save(&address).Error; err != nil {
		return echo.NewHTTPError(http.StatusInternalServerError, "Failed to update address")
	}
	return c.JSON(http.StatusOK, address)
}

func DeleteAddress(c echo.Context) error {
	addressUlid := c.Param("id")
	db := ConnectGORM()
	if err := db.Delete(&Address{}, "ulid = ?", addressUlid).Error; err != nil {
		return echo.NewHTTPError(http.StatusNotFound, "Address not found")
	}
	return c.JSON(http.StatusOK, "Address deleted successfully")
}

func main() {
	e := echo.New()
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	e.GET("/address", GetAllAddresses)
	e.GET("/address/:id", GetAddress)
	e.POST("/address", CreateAddress)
	e.PUT("/address/:id", UpdateAddress)
	e.DELETE("/address/:id", DeleteAddress)

	e.Logger.Fatal(e.Start(":8080"))
}
