// isStringValid checks if the input string meets the specified criteria.
func isStringValid(s string) bool {
	str := strings.ToLower(s)

	// Remove trailing newline character if present.
	str = strings.TrimSuffix(str, "\n")
	str = strings.TrimSuffix(str, "\r") // For Windows CRLF

	// Check if the string starts with 'i', contains 'a', and ends with 'n'.
	return strings.HasPrefix(str, "i") && strings.Contains(str, "a") && strings.HasSuffix(str, "n")
}

