// PointerField returns the pointer field from the PSI table.
func PointerField(psi []byte) uint8 {
	return psi[0]
}

// TableID returns the table ID from the PSI table.
func TableID(psi []byte) uint8 {
	return tableID(psi[1+PointerField(psi):])
}

// SectionSyntaxIndicator returns true if the section syntax indicator is set.
func SectionSyntaxIndicator(psi []byte) bool {
	return sectionSyntaxIndicator(psi[1+PointerField(psi):])
}

// PrivateIndicator returns true if the private indicator is set.
func PrivateIndicator(psi []byte) bool {
	return psi[2+PointerField(psi)]&0x40 != 0
}

// SectionLength returns the section length from the PSI table.
func SectionLength(psi []byte) uint16 {
	return sectionLength(psi[1+PointerField(psi):])
}

// tableID returns the table ID from the header of a section.
func tableID(psi []byte) uint8 {
	return uint8(psi[0])
}

// sectionSyntaxIndicator returns true if the section syntax indicator is set.
func sectionSyntaxIndicator(psi []byte) bool {
	return psi[1]&0x80 != 0
}

// sectionLength returns the length of a single PSI section.
func sectionLength(psi []byte) uint16 {
	return uint16(psi[1]&0x0F)<<8 | uint16(psi[2])
}

// Test cases to verify the solution correctness.
func main() {
	// Example PSI table byte slice.
	psi := []byte{0x00, 0xB0, 0x0D, 0x00, 0x01, 0xC1, 0x00, 0x00, 0x00, 0x01, 0xF0, 0x00, 0x2E, 0x70, 0x1F}

	fmt.Printf("Pointer Field: %d\n", PointerField(psi))
	fmt.Printf("Table ID: %d\n", TableID(psi))
	fmt.Printf("Section Syntax Indicator: %t\n", SectionSyntaxIndicator(psi))
	fmt.Printf("Private Indicator: %t\n", PrivateIndicator(psi))
	fmt.Printf("Section Length: %d\n", SectionLength(psi))
