package main

import (
	"net/http"
	"sync"

	"github.com/labstack/echo"
)

type Service struct {
	ID     string `json:"id"`
	Status string `json:"status"`
}

var (
	services   = make(map[string]Service)
	servicesMu sync.RWMutex
)

func RegisterService(c echo.Context) error {
	servicesMu.Lock()
	defer servicesMu.Unlock()

	service := new(Service)
	if err := c.Bind(service); err != nil {
		return err
	}

	if service.ID == "" || (service.Status != "healthy" && service.Status != "unhealthy") {
		return echo.NewHTTPError(http.StatusBadRequest, "Invalid service data")
	}

	if _, exists := services[service.ID]; exists {
		return echo.NewHTTPError(http.StatusConflict, "Service already registered")
	}

	services[service.ID] = *service
	return c.JSON(http.StatusCreated, service)
}

func UpdateServiceStatus(c echo.Context) error {
	servicesMu.Lock()
	defer servicesMu.Unlock()

	id := c.Param("id")
	service, exists := services[id]
	if !exists {
		return echo.NewHTTPError(http.StatusNotFound, "Service not found")
	}

	if err := c.Bind(&service); err != nil {
		return err
	}

	if service.Status != "healthy" && service.Status != "unhealthy" {
		return echo.NewHTTPError(http.StatusBadRequest, "Invalid service status")
	}

	services[id] = service
	return c.JSON(http.StatusOK, service)
}

func GetAllServicesStatus(c echo.Context) error {
	servicesMu.RLock()
	defer servicesMu.RUnlock()

	allServices := make([]Service, 0, len(services))
	for _, service := range services {
		allServices = append(allServices, service)
	}
	return c.JSON(http.StatusOK, allServices)
}

func main() {
	e := echo.New()

	e.POST("/services", RegisterService)
	e.PUT("/services/:id", UpdateServiceStatus)
	e.GET("/services", GetAllServicesStatus)

	e.Logger.Fatal(e.Start(":8080"))
}

// Test cases to verify the solution correctness
// Note: These are pseudo test cases and would require a testing framework like `net/http/httptest` to be properly executed.

