// application holds the application-wide dependencies for the web application.
type application struct {
	// Add fields for dependencies such as logger, template cache, etc.
}

// recoverPanic is a middleware that recovers from any panics and writes a generic server error message.
func (app *application) recoverPanic(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		defer func() {
			if err := recover(); err != nil {
				w.WriteHeader(http.StatusInternalServerError)
				fmt.Fprint(w, "A server error occurred")
			}
		}()
		next.ServeHTTP(w, r)
	})
}

// logRequest is a middleware that logs the HTTP request method and URL.
func (app *application) logRequest(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		fmt.Printf("%s - %s\n", r.Method, r.URL)
		next.ServeHTTP(w, r)
	})
}

// secureHeaders is a middleware that adds security-related headers to the response.
func secureHeaders(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("X-XSS-Protection", "1; mode=block")
		w.Header().Set("X-Frame-Options", "deny")
		next.ServeHTTP(w, r)
	})
}

// authenticate is a middleware that checks if the user is authenticated.
func (app *application) authenticate(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Add authentication logic here.
		next.ServeHTTP(w, r)
	})
}

// requireAuthentication is a middleware that redirects unauthenticated users to the login page.
func (app *application) requireAuthentication(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Add logic to check if the user is authenticated.
		// If not, redirect to the login page.
		next.ServeHTTP(w, r)
	})
}

// Here you would define the handler methods like app.home, app.createSnippet, etc.

func (app *application) routes() http.Handler {
	// Setup middleware chain
	standardMiddleware := alice.New(app.recoverPanic, app.logRequest, secureHeaders)
	dynamicMiddleware := alice.New(app.authenticate)

	// Create a new servemux and apply handler mappings.
	mux := mux.NewRouter()
	mux.Handle("/", dynamicMiddleware.ThenFunc(app.home)).Methods("GET")
	mux.Handle("/snippet/create", dynamicMiddleware.Append(app.requireAuthentication).ThenFunc(app.createSnippet)).Methods("POST")
	mux.Handle("/snippet/create", dynamicMiddleware.Append(app.requireAuthentication).ThenFunc(app.createSnippetForm)).Methods("GET")
	mux.Handle("/snippet/{id}", dynamicMiddleware.ThenFunc(app.showSnippet)).Methods("GET")
	mux.Handle("/user/login", dynamicMiddleware.ThenFunc(app.loginUserForm)).Methods("GET")
	mux.Handle("/user/login", dynamicMiddleware.ThenFunc(app.loginUser)).Methods("POST")
	mux.Handle("/user/signup", dynamicMiddleware.ThenFunc(app.signupUserForm)).Methods("GET")
	mux.Handle("/user/signup", dynamicMiddleware.ThenFunc(app.signupUser)).Methods("POST")
	mux.Handle("/user/logout", dynamicMiddleware.ThenFunc(app.logoutUser)).Methods("POST")

	// Serve static assets.
	fileServer := http.FileServer(http.Dir("./ui/static/"))
	mux.PathPrefix("/static/").Handler(http.StripPrefix("/static", fileServer))

	return csrf.Protect([]byte("32-byte-long-auth-key"))(standardMiddleware.Then(mux))
}

func main() {
