		DSN string `json:"dsn"` // Data Source Name
	} `json:"mysql"`
	Redis struct {
		Addr     string `json:"addr"`
		Password string `json:"password"`
		DB       int    `json:"db"`
	} `json:"redis"`
}

var (
	DB    *gorm.DB
	Cache *redis.Client
)

func Init(configPath string) error {
	configData, err := ioutil.ReadFile(configPath)
	if err != nil {
		return errors.New(fmt.Sprintf("failed to read config file: %s", err.Error()))
	}

	var config Config
	err = json.Unmarshal(configData, &config)
	if err != nil {
		return errors.New(fmt.Sprintf("failed to parse config file: %s", err.Error()))
	}

	DB, err = gorm.Open(mysql.Open(config.Mysql.DSN), &gorm.Config{})
	if err != nil {
		return errors.New(fmt.Sprintf("failed to initialize db: %s", err.Error()))
	}

	Cache = redis.NewClient(&redis.Options{
		Addr:     config.Redis.Addr,
		Password: config.Redis.Password,
		DB:       config.Redis.DB,
	})

	_, err = Cache.Ping(context.Background()).Result()
	if err != nil {
		return errors.New(fmt.Sprintf("failed to initialize cache: %s", err.Error()))
	}

	return nil
}

func main() {
	err := Init("config.json")
	if err != nil {
