func TestMemberRoutes(t *testing.T) {
	r := mux.NewRouter()
	RegisterMemberRoutes(r)

	// Test cases
	tests := []struct {
		method         string
		url            string
		expectedStatus int
	}{
		{"GET", "/member/123", http.StatusOK},
		{"GET", "/member/group/456", http.StatusOK},
		{"POST", "/member", http.StatusOK},
		{"DELETE", "/member", http.StatusOK},
	}

	for _, test := range tests {
