// Bot represents a Discord bot that manages role-based access control for a Minecraft server.
type Bot struct {
	client *dg.Session
	store  *db.Store
	config *c.DiscordConfig
	sync   SyncHandler
	locked bool
}

// StartBot initializes and starts the Discord bot with the given configuration and database store.
func StartBot(config *c.DiscordConfig, store *db.Store) *Bot {
	client, _ := dg.New("Bot " + config.Token)
	client.Identify.Intents = dg.MakeIntent(dg.IntentsGuildMessages + dg.IntentsGuildMembers)

	bot := &Bot{
		client: client,
		store:  store,
		config: config,
		locked: false,
		sync:   GetSyncHandler(),
	}

	client.AddHandler(bot.OnMessage)
	client.AddHandler(bot.OnGuildMemberUpdate)
	client.AddHandlerOnce(bot.OnReady)

	log.Println("Starting the Discord bot...")

	if err := client.Open(); err != nil {
		log.Fatalln("Failed to connect to Discord\n" + err.Error())
	}
	return bot
}

// IsAdmin checks if a Discord member is an administrator based on their roles.
func (bot *Bot) IsAdmin(member *dg.Member) bool {
	for _, roleID := range member.Roles {
		for _, adminID := range bot.config.AdminRoles {
			if adminID == roleID {
				return true
			}
		}
	}
	return false
}

// CheckRoles checks if a Discord member is whitelisted and/or an administrator based on their roles.
func (bot *Bot) CheckRoles(roles []string) (isWhitelisted, isAdmin bool) {
	for _, role := range roles {
		if bot.AdminCheck([]string{role}) {
			return true, true
		}
		for _, whitelisted := range bot.config.Whitelist {
			if whitelisted == role {
				isWhitelisted = true
			}
		}
	}
	return isWhitelisted, isAdmin
}

// Sync synchronizes a Discord member's roles with the Minecraft server permissions.
func (bot *Bot) Sync(memberID string) {
	log.Printf("Syncing roles for \"%s\"\n", memberID)
	member, err := bot.client.GuildMember(bot.config.Guild, memberID)

	if err != nil {
		if strings.Contains(err.Error(), "Unknown Member") {
			bot.sync.SyncRoles(memberID, &[]string{})
		} else {
			log.Fatalf("Failed to fetch member \"%s\", please investigate \n%s", memberID, err)
		}
	} else {
		bot.sync.SyncRoles(memberID, &member.Roles)
	}
}

// AdminCheck determines if a role is an administrator role.
func (bot *Bot) AdminCheck(role []string) bool {
	for _, r := range role {
		for _, adminRole := range bot.config.AdminRoles {
			if adminRole == r {
				return true
			}
		}
	}
	return false
}

// Test cases to verify the correctness of the Bot methods.
func main() {
	// Mock configuration and database store
	config := &c.DiscordConfig{
		Token:       "YOUR_BOT_TOKEN",
		Guild:       "YOUR_GUILD_ID",
		AdminRoles:  []string{"ADMIN_ROLE_ID"},
		Whitelist:   []string{"WHITELISTED_ROLE_ID"},
	}
	store := &db.Store{} // Assume store is properly initialized

	// Initialize the bot
	bot := StartBot(config, store)

	// Test IsAdmin method
	member := &dg.Member{Roles: []string{"ADMIN_ROLE_ID"}}
	isAdmin := bot.IsAdmin(member)
	log.Printf("IsAdmin: %v\n", isAdmin) // Expected: true

	// Test CheckRoles method
	isWhitelisted, isAdmin := bot.CheckRoles([]string{"WHITELISTED_ROLE_ID", "ADMIN_ROLE_ID"})
	log.Printf("CheckRoles: Whitelisted: %v, Admin: %v\n", isWhitelisted, isAdmin) // Expected: true, true

	// Test AdminCheck method
	isAdminRole := bot.AdminCheck([]string{"ADMIN_ROLE_ID"})
	log.Printf("AdminCheck: %v\n", isAdminRole) // Expected: true

	// Note: Sync method requires a real Discord session and guild member, so it's not included in the test cases.
}
