package main

import (
	"image/color"
	"log"
	"machine"
	"time"

	"tinygo.org/x/bluetooth"
	"tinygo.org/x/drivers/ssd1306"
	"tinygo.org/x/tinyfont"
	"tinygo.org/x/tinyfont/gophers"
)

var (
	serviceUUID = bluetooth.NewUUID([16]byte{0xa0, 0xb4, 0x00, 0x01, 0x92, 0x6d, 0x4d, 0x61, 0x98, 0xdf, 0x8c, 0x5c, 0x62, 0xee, 0x53, 0xb3})
	charUUID    = bluetooth.NewUUID([16]byte{0xa0, 0xb4, 0x00, 0x02, 0x92, 0x6d, 0x4d, 0x61, 0x98, 0xdf, 0x8c, 0x5c, 0x62, 0xee, 0x53, 0xb3})
)

func main() {
	err := run()
	if err != nil {
		log.Fatal(err)
	}
}

func run() error {
	// Initialize BLE adapter
	adapter := bluetooth.DefaultAdapter
	err := adapter.Enable()
	if err != nil {
		return err
	}

	// Configure BLE advertisement
	adv := adapter.DefaultAdvertisement()
	err = adv.Configure(bluetooth.AdvertisementOptions{
		LocalName: "tinygo ble peripheral",
	})
	if err != nil {
		return err
	}

	// Start advertising
	err = adv.Start()
	if err != nil {
		return err
	}

	// Create a channel to receive BLE write events
	ch := make(chan byte, 10)

	// Add custom BLE service and characteristic
	err = adapter.AddService(&bluetooth.Service{
		UUID: serviceUUID,
		Characteristics: []bluetooth.CharacteristicConfig{
			{
				UUID: charUUID,
				Flags: bluetooth.CharacteristicReadPermission | bluetooth.CharacteristicWritePermission |
					bluetooth.CharacteristicWriteWithoutResponsePermission,
				WriteEvent: func(client bluetooth.Connection, offset int, value []byte) {
					if offset != 0 || len(value) != 1 {
						return
					}
					ch <- value[0]
				},
			},
		},
	})
	if err != nil {
		return err
	}

	// Initialize the I2C bus and the display
	machine.I2C0.Configure(machine.I2CConfig{
		Frequency: machine.TWI_FREQ_400KHZ,
		SCL:       machine.SCL0_PIN,
		SDA:       machine.SDA0_PIN,
	})
	display := ssd1306.NewI2C(machine.I2C0)
	display.Configure(ssd1306.Config{
		Address: ssd1306.Address_128_32,
		Width:   128,
		Height:  32,
	})
	display.ClearDisplay()

	// Configure the onboard LED
	machine.LED_GREEN.Configure(machine.PinConfig{Mode: machine.PinOutput})

	// Define the font and the string to scroll
	font := &gophers.Regular32pt
	str := "ABEFGIJMNVWXYZ" + "ABEFG"
	i := 0

	// Main loop
	for {
		select {
		case val := <-ch:
			// Change LED state based on the received value
			if (val % 2) == 0 {
				machine.LED_GREEN.Low()
			} else {
				machine.LED_GREEN.High()
			}
		default:
			// Scroll the text on the display
			display.ClearBuffer()
			tinyfont.WriteLine(&display, font, 5, 30, str[i:i+5], color.RGBA{0xFF, 0xFF, 0xFF, 0xFF})
			i = (i + 1) % (len(str) - 5)
			display.Display()
			time.Sleep(200 * time.Millisecond)
		}
	}

	return nil
}
