package main

import (
	"encoding/base58"
	"errors"
	"fmt"
)

type ChainID string

type ChainRecord struct {
	ChainID ChainID `swagger:"desc(ChainID (base58-encoded))"`
	Active  bool    `swagger:"desc(Whether or not the chain is active)"`
}

type BlockchainRegistry struct {
	records map[ChainID]*ChainRecord
}

func NewBlockchainRegistry() *BlockchainRegistry {
	return &BlockchainRegistry{
		records: make(map[ChainID]*ChainRecord),
	}
}

func (br *BlockchainRegistry) AddChainRecord(chainID ChainID, active bool) error {
	if _, exists := br.records[chainID]; exists {
		return errors.New("chain record already exists")
	}
	br.records[chainID] = &ChainRecord{ChainID: chainID, Active: active}
	return nil
}

func (br *BlockchainRegistry) GetChainRecord(chainID ChainID) (*ChainRecord, error) {
	record, exists := br.records[chainID]
	if !exists {
		return nil, errors.New("chain record not found")
	}
	return record, nil
}

func (br *BlockchainRegistry) UpdateChainStatus(chainID ChainID, active bool) error {
	record, exists := br.records[chainID]
	if !exists {
		return errors.New("chain record not found")
	}
	record.Active = active
	return nil
}

func (br *BlockchainRegistry) DeleteChainRecord(chainID ChainID) error {
	if _, exists := br.records[chainID]; !exists {
		return errors.New("chain record not found")
	}
	delete(br.records, chainID)
	return nil
}

func main() {
	registry := NewBlockchainRegistry()

	// Test cases
	chainID := ChainID(base58.Encode([]byte("test-chain-id")))
	err := registry.AddChainRecord(chainID, true)
	if err != nil {
		fmt.Println("Error adding chain record:", err)
	}

	record, err := registry.GetChainRecord(chainID)
	if err != nil {
		fmt.Println("Error retrieving chain record:", err)
	} else {
		fmt.Printf("Retrieved chain record: %+v\n", record)
	}

	err = registry.UpdateChainStatus(chainID, false)
	if err != nil {
		fmt.Println("Error updating chain status:", err)
	}

	err = registry.DeleteChainRecord(chainID)
	if err != nil {
		fmt.Println("Error deleting chain record:", err)
	}

	_, err = registry.GetChainRecord(chainID)
	if err != nil {
		fmt.Println("Chain record successfully deleted:", err)
	}
}
