	StoreFaultInStorage(faultName string, faultIdx int) error
	InitAlertInfos(faultIdx int) error
	IncrementFaultSn(faultIdx int) error
	SetFaultStartEpoch(faultIdx int, epoch int64) error
	Snapshot() StateSnapshot
	Restore(snapshot StateSnapshot) error
}

// Implement the in-memory state

type InMemState struct {
	hbIdx       int
	measIdx     int
	faultIdx    int
	schedulers  map[string]Scheduler
	faults      map[int]string
	alertInfos  map[int]bool
	faultSn     map[int]int
	faultEpochs map[int]int64
	mu          sync.Mutex
}

func NewInMemState() *InMemState {
	return &InMemState{
		schedulers:  make(map[string]Scheduler),
		faults:      make(map[int]string),
		alertInfos:  make(map[int]bool),
		faultSn:     make(map[int]int),
		faultEpochs: make(map[int]int64),
	}
}

func (s *InMemState) NextHeartbeatIndex() (int, error) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.hbIdx++
	return s.hbIdx, nil
}

func (s *InMemState) NextMeasurementIndex() (int, error) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.measIdx++
	return s.measIdx, nil
}

func (s *InMemState) UpdateScheduler(name string, interval time.Duration, now time.Time) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.schedulers[name] = Scheduler{Interval: interval, Next: now.Add(interval)}
	return nil
}

func (s *InMemState) NextFaultIndex() (int, error) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.faultIdx++
	return s.faultIdx, nil
}

func (s *InMemState) StoreFaultInStorage(faultName string, faultIdx int) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if _, exists := s.faults[faultIdx]; exists {
		return errors.New("fault index already exists")
	}
	s.faults[faultIdx] = faultName
	return nil
}

func (s *InMemState) InitAlertInfos(faultIdx int) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if _, exists := s.alertInfos[faultIdx]; exists {
		return errors.New("alert info already initialized for fault index")
	}
	s.alertInfos[faultIdx] = true
	return nil
}

func (s *InMemState) IncrementFaultSn(faultIdx int) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.faultSn[faultIdx]++
	return nil
}

func (s *InMemState) SetFaultStartEpoch(faultIdx int, epoch int64) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.faultEpochs[faultIdx] = epoch
	return nil
}

func (s *InMemState) Snapshot() StateSnapshot {
	s.mu.Lock()
	defer s.mu.Unlock()
	return StateSnapshot{
		HbIdx:       s.hbIdx,
		MeasIdx:     s.measIdx,
		FaultIdx:    s.faultIdx,
		Schedulers:  s.schedulers,
		Faults:      s.faults,
		AlertInfos:  s.alertInfos,
		FaultSn:     s.faultSn,
		FaultEpochs: s.faultEpochs,
	}
}

func (s *InMemState) Restore(snapshot StateSnapshot) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.hbIdx = snapshot.HbIdx
	s.measIdx = snapshot.MeasIdx
	s.faultIdx = snapshot.FaultIdx
	s.schedulers = snapshot.Schedulers
	s.faults = snapshot.Faults
	s.alertInfos = snapshot.AlertInfos
	s.faultSn = snapshot.FaultSn
	s.faultEpochs = snapshot.FaultEpochs
	return nil
}

// Serialization and deserialization helpers

func SerializeState(snapshot StateSnapshot) ([]byte, error) {
	var buf bytes.Buffer
	enc := gob.NewEncoder(&buf)
	if err := enc.Encode(snapshot); err != nil {
		return nil, err
	}
	return buf.Bytes(), nil
}

func DeserializeState(data []byte) (StateSnapshot, error) {
	var snapshot StateSnapshot
	buf := bytes.NewBuffer(data)
	dec := gob.NewDecoder(buf)
	if err := dec.Decode(&snapshot); err != nil {
		return StateSnapshot{}, err
	}
	return snapshot, nil
}

// Test cases to verify the solution correctness

func main() {
	// Initialize a new in-memory state
	state := NewInMemState()

	// Simulate state changes
	state.NextHeartbeatIndex()
	state.NextMeasurementIndex()
	state.UpdateScheduler("task1", 5*time.Minute, time.Now())
	faultIdx, _ := state.NextFaultIndex()
	state.StoreFaultInStorage("NetworkIssue", faultIdx)
	state.InitAlertInfos(faultIdx)
	state.IncrementFaultSn(faultIdx)
	state.SetFaultStartEpoch(faultIdx, 1234567890)

	// Take a snapshot of the current state
	snapshot := state.Snapshot()

	// Serialize the snapshot
	serializedSnapshot, err := SerializeState(snapshot)
	if err != nil {
		panic(err)
	}

	// Deserialize the snapshot
	deserializedSnapshot, err := DeserializeState(serializedSnapshot)
	if err != nil {
		panic(err)
	}

	// Restore the state from the deserialized snapshot
	newState := NewInMemState()
	err = newState.Restore(deserializedSnapshot)
	if err != nil {
		panic(err)
	}

	// Verify that the restored state matches the original state
	if newState.Snapshot() != snapshot {
		panic("restored state does not match the original state")
	}

	// Output success message
	println("State restored successfully and matches the original state.")
}
