	ETime time.Time
	Raw   json.RawMessage
}

type Cpc100Info struct {
	List []*Cpc100Egg
}

type Cpc100Egg struct {
	Name     string
	STime    time.Time
	ETime    time.Time
	Key      string
	Unlocked bool
	Data     interface{}
}

type ServiceConfig struct {
	Cpc100 struct {
		Vid string
	}
}

type DAO interface {
	GetWebViewDataByVid(ctx context.Context, vid string) ([]*WebDataItem, error)
	Cpc100UnlockInfo(ctx context.Context, mid int64) (map[string]int, error)
	Cpc100Unlock(ctx context.Context, mid int64, key string) error
	DelCacheGetWebViewDataByVid(ctx context.Context, vid string) error
	CpcGetPV(ctx context.Context) (int64, error)
	CpcGetTopicView(ctx context.Context) (int64, error)
}

// Service is the main structure for the promotional event service.
type Service struct {
	dao DAO
	c   ServiceConfig
}

// MD5 is a mock function to simulate generating a hash for the item key.
func MD5(text string) string {
	h := fnv.New32a()
	h.Write([]byte(text))
	return fmt.Sprint(h.Sum32())
}

// Info retrieves information about all available eggs.
func (s *Service) Info(ctx context.Context, mid int64) (res *Cpc100Info, err error) {
	items, err := s.dao.GetWebViewDataByVid(ctx, s.c.Cpc100.Vid)
	if err != nil {
		return nil, err
	}
	info := make(map[string]int)
	if mid > 0 {
		info, _ = s.dao.Cpc100UnlockInfo(ctx, mid)
	}
	res = new(Cpc100Info)
	now := time.Now()
	for _, item := range items {
		one := &Cpc100Egg{
			Name:  item.Name,
			STime: item.STime,
			ETime: item.ETime,
			Key:   MD5(fmt.Sprint(item.ID, "20210614")),
		}
		json.Unmarshal(item.Raw, &one.Data)
		if now.Before(item.STime) {
			continue
		}
		one.Unlocked = info[one.Key] == 1
		res.List = append(res.List, one)
	}
	return
}

// Unlock allows a user to unlock an egg if the current time is within the egg's active time window.
func (s *Service) Unlock(ctx context.Context, mid int64, key string) (err error) {
	items, err := s.dao.GetWebViewDataByVid(ctx, s.c.Cpc100.Vid)
	if err != nil {
		return
	}
	for _, item := range items {
		itemKey := MD5(fmt.Sprint(item.ID, "20210614"))
		if itemKey != key {
			continue
		}
		if time.Now().After(item.STime) {
			return s.dao.Cpc100Unlock(ctx, mid, key)
		} else {
			return fmt.Errorf("the item is not yet available for unlocking")
		}
	}
	return fmt.Errorf("invalid key provided")
}

// Reset clears the cache that stores the web view data for the event.
func (s *Service) Reset(ctx context.Context) (err error) {
	return s.dao.DelCacheGetWebViewDataByVid(ctx, s.c.Cpc100.Vid)
}

// PageView retrieves the page view count for the event.
func (s *Service) PageView(ctx context.Context) (int64, error) {
	return s.dao.CpcGetPV(ctx)
}

// TotalView calculates the total view count for the event.
func (s *Service) TotalView(ctx context.Context) (total int64, err error) {
	pv, err := s.dao.CpcGetPV(ctx)
	if err != nil {
		return
	}
	tv, err := s.dao.CpcGetTopicView(ctx)
	if err != nil {
		return
	}
	total = pv + tv
	return
}

