// Task represents a function that simulates work by sleeping for a random duration.
func Task(id int, wg *sync.WaitGroup) {
	defer wg.Done() // Signal that the goroutine is done after the function execution.

	// Simulate work by sleeping for a random duration between 1 to 3 seconds.
	sleepDuration := time.Duration(rand.Intn(3)+1) * time.Second
	fmt.Printf("Task %d started\n", id)
	time.Sleep(sleepDuration)
	fmt.Printf("Task %d completed after sleeping for %v\n", id, sleepDuration)
}

func main() {
	// Seed the random number generator.
	rand.Seed(time.Now().UnixNano())

	// Create a wait group to manage synchronization.
	var wg sync.WaitGroup

	// Define the number of tasks.
	numTasks := 5
	wg.Add(numTasks) // Set the number of goroutines to wait for.

	// Start each task in a new goroutine.
	for i := 1; i <= numTasks; i++ {
		go Task(i, &wg)
	}

	// Wait for all tasks to complete.
	wg.Wait()
	fmt.Println("All tasks completed.")
}

