// ParseGitURL parses the Git URL and returns the repository name and path.
func ParseGitURL(gitURL string) (repoName, repoPath string, err error) {
	if gitURL == "" {
		return "", "", errors.New("git URL is empty")
	}

	u, err := url.Parse(gitURL)
	if err != nil {
		return "", "", fmt.Errorf("invalid git URL: %v", err)
	}

	segments := strings.Split(u.Path, "/")
	if len(segments) < 2 {
		return "", "", errors.New("invalid git URL path")
	}

	repoName = strings.TrimSuffix(segments[len(segments)-1], ".git")
	repoPath = "/usr/local/datakit/gitrepos/" + repoName

	return repoName, repoPath, nil
}

// IsUserNamePasswordAuth checks if the Git URL contains username and password credentials.
func IsUserNamePasswordAuth(gitURL string) (bool, error) {
	if gitURL == "" {
		return false, errors.New("git URL is empty")
	}

	u, err := url.Parse(gitURL)
	if err != nil {
		return false, fmt.Errorf("invalid git URL: %v", err)
	}

	return u.User != nil, nil
}

// GetUserNamePasswordFromGitURL extracts the username and password from the Git URL.
func GetUserNamePasswordFromGitURL(gitURL string) (username, password string, err error) {
	if gitURL == "" {
		return "", "", errors.New("git URL is empty")
	}

	u, err := url.Parse(gitURL)
	if err != nil {
		return "", "", fmt.Errorf("invalid git URL: %v", err)
	}

	if u.User != nil {
		username = u.User.Username()
		password, _ = u.User.Password()
	}

	return username, password, nil
}

// GetAuthMethod returns the appropriate authentication method based on the provided credentials.
func GetAuthMethod(gitUserName, gitPassword string) (transport.AuthMethod, error) {
	if gitUserName == "" || gitPassword == "" {
		return nil, errors.New("username or password is empty")
	}

	return &http.BasicAuth{
		Username: gitUserName,
		Password: gitPassword,
	}, nil
}

