// IncrementCounter increments the counter by 1 and updates the last update time.
func (s *CounterService) IncrementCounter() {
	s.counter++
	s.lastUpdate = time.Now()
}

// GetCounter returns the current value of the counter and the last update time.
func (s *CounterService) GetCounter() (int, time.Time) {
	return s.counter, s.lastUpdate
}

// apiExample represents the JSON-RPC 2.0 response for the counter service.
type apiExample struct {
	Counter   int       `json:"counter"`
	UpdatedAt time.Time `json:"updated_at"`
}

// protoExample converts the internal counter service representation to the API representation.
func protoExample(s *CounterService) apiExample {
	counter, updatedAt := s.GetCounter()
	return apiExample{
		Counter:   counter,
		UpdatedAt: updatedAt,
	}
}

// handleIncrementCounter processes the incrementCounter JSON-RPC 2.0 request.
func handleIncrementCounter(s *CounterService, w http.ResponseWriter, r *http.Request) {
	s.IncrementCounter()
	response := protoExample(s)
	json.NewEncoder(w).Encode(response)
}

// handleGetCounter processes the getCounter JSON-RPC 2.0 request.
func handleGetCounter(s *CounterService, w http.ResponseWriter, r *http.Request) {
	response := protoExample(s)
	json.NewEncoder(w).Encode(response)
}

