package main

import (
	"encoding/json"
	"fmt"
	"reflect"
)

// TypeChange represents a change in type for a given key in a JSON object.
type TypeChange struct {
	Key       string
	Before    string
	After     string
}

// TypeChangeDetector detects type changes between two JSON objects.
func TypeChangeDetector(before, after map[string]interface{}) []TypeChange {
	var changes []TypeChange
	for key, beforeValue := range before {
		if afterValue, ok := after[key]; ok {
			beforeType := reflect.TypeOf(beforeValue).String()
			afterType := reflect.TypeOf(afterValue).String()
			if beforeType != afterType {
				changes = append(changes, TypeChange{
					Key:    key,
					Before: beforeType,
					After:  afterType,
				})
			}
		}
	}
	return changes
}

// TypeChangeRenderer renders a list of TypeChanges in a human-readable format.
func TypeChangeRenderer(changes []TypeChange) string {
	var output string
	for _, change := range changes {
		output += fmt.Sprintf("Key '%s' type changed from %s to %s\n", change.Key, change.Before, change.After)
	}
	return output
}

func main() {
	// Example JSON objects for comparison
	jsonStr1 := `{"name": "Alice", "age": 30, "is_student": false}`
	jsonStr2 := `{"name": "Alice", "age": "thirty", "is_student": "no"}`

	var obj1, obj2 map[string]interface{}
	json.Unmarshal([]byte(jsonStr1), &obj1)
	json.Unmarshal([]byte(jsonStr2), &obj2)

	// Detect type changes
	changes := TypeChangeDetector(obj1, obj2)

	// Render the type changes
	output := TypeChangeRenderer(changes)
	fmt.Println(output)
}

// Test cases to verify the solution correctness.
func main() {
	testCases := []struct {
		beforeJSON string
		afterJSON  string
		expected   []TypeChange
	}{
		{
			beforeJSON: `{"name": "Alice", "age": 30, "is_student": false}`,
			afterJSON:  `{"name": "Alice", "age": "thirty", "is_student": "no"}`,
			expected: []TypeChange{
				{"age", "float64", "string"},
				{"is_student", "bool", "string"},
			},
		},
		{
			beforeJSON: `{"height": 1.75, "hobbies": ["reading", "swimming"]}`,
			afterJSON:  `{"height": "1.75 meters", "hobbies": {"first": "reading", "second": "swimming"}}`,
			expected: []TypeChange{
				{"height", "float64", "string"},
				{"hobbies", "slice", "map"},
			},
		},
	}

	for _, tc := range testCases {
		var beforeObj, afterObj map[string]interface{}
		json.Unmarshal([]byte(tc.beforeJSON), &beforeObj)
		json.Unmarshal([]byte(tc.afterJSON), &afterObj)

		actual := TypeChangeDetector(beforeObj, afterObj)
		if !reflect.DeepEqual(actual, tc.expected) {
			fmt.Printf("FAIL: Expected %+v, got %+v\n", tc.expected, actual)
		} else {
			fmt.Printf("PASS: Detected type changes correctly\n")
		}
	}
}
