package main

import (
	"errors"
	"fmt"
	"strconv"
	"sync"
	"time"
)

const (
	maxPrefix    = 2<<3 - 1
	maxNode      = 2<<7 - 1
	maxSeq       = 2<<19 - 1
	maxTimestamp = 2<<31 - 1
	epoch        = int64(1575129600) // Custom epoch in seconds
)

type IDGenerator struct {
	prefix uint
	nodeID uint
	last   int64
	seq    uint64
	step   uint64
	lock   sync.Mutex
}

func NewIDGenerator(prefix, node uint) *IDGenerator {
	if prefix > maxPrefix {
		panic(fmt.Errorf("prefix is invalid, must not exceed %d", maxPrefix))
	}
	if node > maxNode {
		panic(fmt.Errorf("node is invalid, must not exceed %d", maxNode))
	}
	time.Sleep(time.Second)
	return &IDGenerator{
		prefix: prefix,
		nodeID: node,
		last:   time.Now().Unix(),
		step:   1,
	}
}

func (g *IDGenerator) WithStep(step uint64) *IDGenerator {
	if step == 0 || step > maxSeq {
		panic(fmt.Errorf("step must be in the range [1-%d]", maxSeq))
	}
	g.step = step
	return g
}

func (g *IDGenerator) NextID() uint64 {
	g.lock.Lock()
	defer g.lock.Unlock()

	current := time.Now().Unix()
	if current < g.last {
		refused := g.last - current
		panic(fmt.Errorf("clock skew detected, refusing to generate ID for %d seconds", refused))
	}
	if current > g.last {
		g.seq = 0
		g.last = current
	}
	g.seq += g.step
	if g.seq > maxSeq {
		return g.NextID()
	}
	timestamp := current - epoch
	id := uint64(g.prefix)<<60 | uint64(timestamp)<<28 | uint64(g.nodeID)<<20 | uint64(g.seq)
	return id
}

func (g *IDGenerator) State() string {
	return fmt.Sprintf("prefix=%d,node=%d,last=%d,seq=%d,step=%d", g.prefix, g.nodeID, g.last, g.seq, g.step)
}

const dateFormat = "060102150405"

func FormatID(id uint64) string {
	seq := id & maxSeq
	node := (id >> 20) & maxNode
	timestamp := (id >> 28) & maxTimestamp
	prefix := (id >> 60) & maxPrefix
	return fmt.Sprintf("%d%s%03d%07d", prefix, time.Unix((int64(timestamp)+epoch), 0).Format(dateFormat), node, seq)
}

func ParseID(id string) (uint64, error) {
	l := len(id)
	if l < 22 {
		return 0, errors.New("invalid ID format")
	}
	seq, err := strconv.ParseInt(id[l-7:], 10, 64)
	if err != nil || seq > maxSeq {
		return 0, errors.New("invalid ID format")
	}
	node, err := strconv.ParseInt(id[l-10:l-7], 10, 64)
	if err != nil || node > maxNode {
		return 0, errors.New("invalid ID format")
	}
	t, err := time.ParseInLocation(dateFormat, id[l-22:l-10], time.Local)
	if err != nil {
		return 0, errors.New("invalid ID format")
	}
	time := t.Unix()
	biz, err := strconv.ParseInt(id[:l-22], 10, 64)
	if err != nil || biz > maxPrefix {
		return 0, errors.New("invalid ID format")
	}
	timestamp := time - epoch
	return uint64(biz)<<60 | uint64(timestamp)<<28 | uint64(node)<<20 | uint64(seq), nil
}

func main() {
	// Test cases
	generator := NewIDGenerator(1, 1).WithStep(1)
	id1 := generator.NextID()
	id2 := generator.NextID()

	fmt.Println("Generated ID 1:", id1)
	fmt.Println("Generated ID 2:", id2)
	fmt.Println("State:", generator.State())

	formattedID := FormatID(id1)
	fmt.Println("Formatted ID:", formattedID)

	parsedID, err := ParseID(formattedID)
	if err != nil {
		fmt.Println("Error parsing ID:", err)
	} else {
		fmt.Println("Parsed ID:", parsedID)
	}

	// Check if parsed ID matches the original ID
	if parsedID != id1 {
		fmt.Println("Error: Parsed ID does not match the original ID")
	} else {
		fmt.Println("Success: Parsed ID matches the original ID")
	}
}
