package main

import (
	"fmt"
)

// duplicateZeros duplicates each occurrence of zero, shifting the remaining elements to the right.
// The input array is modified in place.
func duplicateZeros(arr []int) {
	l := len(arr)
	for i := 0; i < l; i++ {
		if arr[i] == 0 {
			for j := l - 1; j > i; j-- {
				arr[j] = arr[j-1]
			}
			i++ // Skip the next zero we just created to avoid duplicating it again.
		}
	}
}

func main() {
	// Test cases to verify the solution correctness.
	testCases := [][]int{
		{1, 0, 2, 3, 0, 4, 5, 0},
		{1, 2, 3},
		{0, 0, 0, 0, 0, 0, 0},
		{1, 2, 0, 3, 0, 4, 5},
	}

	for _, testCase := range testCases {
		fmt.Printf("Original array: %v\n", testCase)
		duplicateZeros(testCase)
		fmt.Printf("Modified array: %v\n", testCase)
	}
}
