)

// FilterLevel represents the severity level of a log message.
type FilterLevel uint

// Constants for the different logging levels.
const (
	LEV_INFO FilterLevel = iota
	LEV_WARNING
	LEV_ERROR
	LEV_FATAL
	LEV_INTERPRET
	LEV_RAW
	LEV_DEBUG
)

// DNP3Logger is a custom logger for the DNP3 communication package.
type DNP3Logger struct {
	infoLogger  *log.Logger
	errorLogger *log.Logger
}

// Init initializes the logger with default writers for info and error logs.
func (l *DNP3Logger) Init() {
	l.InitDefault(os.Stdout, os.Stderr)
}

// InitDefault initializes the logger with custom writers for info and error logs.
func (l *DNP3Logger) InitDefault(infoWriter, errorWriter io.Writer) {
	l.infoLogger = log.New(infoWriter, "INFO: ", log.Ldate|log.Ltime|log.Lshortfile)
	l.errorLogger = log.New(errorWriter, "ERROR: ", log.Ldate|log.Ltime|log.Lshortfile)
}

// Logged logs a message with the specified severity level.
func (l *DNP3Logger) Logged(calldepth int, filterlevel FilterLevel, messageLog string) {
	switch filterlevel {
	case LEV_INFO, LEV_INTERPRET, LEV_RAW, LEV_DEBUG:
		l.infoLogger.Output(calldepth, messageLog)
	case LEV_WARNING, LEV_ERROR:
		l.errorLogger.Output(calldepth, messageLog)
	case LEV_FATAL:
		l.errorLogger.Output(calldepth, messageLog)
		os.Exit(1) // Exit if it is fatal
	}
}

// Loggedf logs a formatted message with the specified severity level.
func (l *DNP3Logger) Loggedf(calldepth int, filterlevel FilterLevel, messageLog string, v ...interface{}) {
	l.Logged(calldepth, filterlevel, fmt.Sprintf(messageLog, v...))
}

// Example usage of the DNP3Logger.
func main() {
	logger := DNP3Logger{}
	logger.Init() // Initialize with default writers

	// Log an info message
	logger.Logged(2, LEV_INFO, "This is an informational message.")

	// Log a warning message
	logger.Logged(2, LEV_WARNING, "This is a warning message.")

	// Log an error message
	logger.Logged(2, LEV_ERROR, "This is an error message.")

	// Log a fatal message (this will exit the program)
	// logger.Logged(2, LEV_FATAL, "This is a fatal error message.")

	// Log a formatted debug message
	logger.Loggedf(2, LEV_DEBUG, "Debugging %s with ID %d", "session", 42)
}
