// UserClaims extends standard jwt.Claims with custom user information.
type UserClaims struct {
	jwt.StandardClaims
	UserID string `json:"user_id"`
	Email  string `json:"email"`
}

// GenerateUserToken generates a JWT for a user with the given ID and email.
func GenerateUserToken(userID, email string, key []byte) (string, error) {
	// Set token claims
	claims := UserClaims{
		StandardClaims: jwt.StandardClaims{
			ExpiresAt: time.Now().Add(24 * time.Hour).Unix(),
			IssuedAt:  time.Now().Unix(),
		},
		UserID: userID,
		Email:  email,
	}

	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)

	// Sign the token with the secret key
	tokenString, err := token.SignedString(key)
	if err != nil {
		return "", err
	}

	return tokenString, nil
}

func main() {
	// Example usage of GenerateUserToken
	secretKey := []byte("my_secret_key")
	userID := "12345"
	email := "user@example.com"

	token, err := GenerateUserToken(userID, email, secretKey)
	if err != nil {
		fmt.Println("Error generating token:", err)
		return
	}

	fmt.Println("Generated JWT:", token)
	// Output: Generated JWT: <token_string>
}
