	if len(user.Name) < 2 || len(user.Name) > 200 {
		return ErrInvalidName
	}
	if len(user.Email) < 3 || len(user.Email) > 200 {
		return ErrInvalidEmailLength
	}
	if !isValidEmail(user.Email) {
		return ErrInvalidEmail
	}
	if !isValidPhone(user.Phone) {
		return ErrInvalidPhone
	}
	if len(user.Password) < 6 || len(user.Password) > 200 {
		return ErrInvalidPassword
	}
	if user.CarBrandModel <= 0 {
		return ErrInvalidCarBrandModel
	}
	currentYear := time.Now().Year()
	if user.CarYear < 1900 || user.CarYear > currentYear {
		return ErrInvalidCarYear
	}
	return nil
}

// isValidEmail checks if the email is valid.
func isValidEmail(email string) bool {
	emailRegex := regexp.MustCompile(`^[a-z0-9._%+\-]+@[a-z0-9.\-]+\.[a-z]{2,4}$`)
	return emailRegex.MatchString(email)
}

// isValidPhone checks if the phone number is valid.
func isValidPhone(phone string) bool {
	phoneRegex := regexp.MustCompile(`^\+?[1-9]\d{1,14}$`)
