func main() {
	// Test cases
	results := []struct {
		numerator   int
		denominator int
	}{
		{20, 10},
		{10, 0},
		{15, 3},
		{-10, 2},
	}

	for _, test := range results {
		result, err := SafeDivide(test.numerator, test.denominator)
		if err != nil {
			fmt.Printf("Error: %s\n", err)
		} else {
			fmt.Printf("The result of dividing %d by %d is %d\n", test.numerator, test.denominator, result)
		}
	}
}

// SafeDivide performs a division operation and recovers from a division by zero panic.
func SafeDivide(num1, num2 int) (int, error) {
	defer func() {
		if r := recover(); r != nil {
			fmt.Println("Recovered in SafeDivide:", r)
		}
	}()
	if num2 == 0 {
		panic("Can't divide by zero")
	}
	return num1 / num2, nil
}

// recoverDivide is a helper function that recovers from a panic and returns an error.
func recoverDivide() error {
	if r := recover(); r != nil {
		if err, ok := r.(string); ok {
			return errors.New(err)
		}
		return errors.New("unknown error occurred")
	}
	return nil
}
