	"github.com/litmuschaos/litmus/chaoscenter/graphql/server/pkg/database/mongodb"
	"go.mongodb.org/mongo-driver/bson"
	"go.mongodb.org/mongo-driver/mongo"
	"go.mongodb.org/mongo-driver/mongo/options"
)

// Assuming mongodb package has a function to get the collection
var experimentRunCollection *mongo.Collection = mongodb.GetCollection("chaos_experiment_runs")

// CreateExperimentRun inserts a new ChaosExperimentRun into the database
func CreateExperimentRun(run ChaosExperimentRun) error {
	_, err := experimentRunCollection.InsertOne(context.Background(), run)
	return err
}

// UpdateExperimentRun updates the fields of an existing ChaosExperimentRun
func UpdateExperimentRun(experimentRunID string, updateFields map[string]interface{}) error {
	filter := bson.M{"experiment_run_id": experimentRunID}
	update := bson.M{"$set": updateFields}
	result, err := experimentRunCollection.UpdateOne(context.Background(), filter, update)
	if err != nil {
		return err
	}
	if result.MatchedCount == 0 {
		return errors.New("no experiment run found with the given ID")
	}
	return nil
}

// GetExperimentRunByID retrieves a ChaosExperimentRun by its ID
func GetExperimentRunByID(experimentRunID string) (*ChaosExperimentRun, error) {
	var run ChaosExperimentRun
	filter := bson.M{"experiment_run_id": experimentRunID}
	err := experimentRunCollection.FindOne(context.Background(), filter).Decode(&run)
	if err != nil {
		return nil, err
	}
	return &run, nil
}

// ListExperimentRunsByProjectID retrieves all ChaosExperimentRuns for a given project
func ListExperimentRunsByProjectID(projectID string) ([]ChaosExperimentRun, error) {
	var runs []ChaosExperimentRun
	filter := bson.M{"project_id": projectID}
	cursor, err := experimentRunCollection.Find(context.Background(), filter)
	if err != nil {
		return nil, err
	}
	defer cursor.Close(context.Background())
	for cursor.Next(context.Background()) {
		var run ChaosExperimentRun
		if err := cursor.Decode(&run); err != nil {
			return nil, err
		}
		runs = append(runs, run)
	}
	if err := cursor.Err(); err != nil {
		return nil, err
	}
	return runs, nil
}

func main() {
	// Example usage of the functions
	run := ChaosExperimentRun{
		ProjectID:       "project123",
		InfraID:         "infra456",
		ExperimentRunID: "run789",
		ExperimentID:    "exp101",
		Phase:           "Running",
		ExecutionData:   "Execution details here",
		RevisionID:      "rev111",
		Completed:       false,
	}

	// Create a new experiment run
	err := CreateExperimentRun(run)
	if err != nil {
		log.Fatalf("Failed to create experiment run: %v", err)
	}

	// Update an experiment run
	updateFields := map[string]interface{}{
		"phase":     "Completed",
		"completed": true,
	}
	err = UpdateExperimentRun("run789", updateFields)
	if err != nil {
		log.Fatalf("Failed to update experiment run: %v", err)
	}

	// Retrieve an experiment run by ID
	retrievedRun, err := GetExperimentRunByID("run789")
	if err != nil {
		log.Fatalf("Failed to retrieve experiment run: %v", err)
	}
	fmt.Printf("Retrieved run: %+v\n", retrievedRun)

	// List all experiment runs for a project
	runs, err := ListExperimentRunsByProjectID("project123")
	if err != nil {
		log.Fatalf("Failed to list experiment runs: %v", err)
	}
	fmt.Printf("Runs for project 'project123': %+v\n", runs)
}
