	// Mock a restful.Response object for testing purposes.
	responseRecorder := httptest.NewRecorder()
	response := restful.NewResponse(responseRecorder)

	// Test BadRequest function.
	BadRequest(response)
	if responseRecorder.Code != http.StatusBadRequest {
		log.Fatalf("Expected status code 400, got %d", responseRecorder.Code)
	}
	var errorResponse Error
	if err := json.Unmarshal(responseRecorder.Body.Bytes(), &errorResponse); err != nil {
		log.Fatalf("Error unmarshalling response: %s", err)
	}
	if errorResponse.Message != "Invalid request" {
		log.Fatalf("Expected error message 'Invalid request', got '%s'", errorResponse.Message)
	}

	// Reset the responseRecorder for the next test.
	responseRecorder = httptest.NewRecorder()
	response = restful.NewResponse(responseRecorder)

	// Test Internal function.
