	}
	if err := json.Unmarshal(responseRecorder.Body.Bytes(), &errorResponse); err != nil {
		log.Fatalf("Error unmarshalling response: %s", err)
	}
	if errorResponse.Message != "Internal error" {
		log.Fatalf("Expected error message 'Internal error', got '%s'", errorResponse.Message)
	}
}
