	backends map[string]BackendEntry
}

// NewLoadbalancerBackendManager creates a new LoadbalancerBackendManager.
func NewLoadbalancerBackendManager() *LoadbalancerBackendManager {
	return &LoadbalancerBackendManager{
		backends: make(map[string]BackendEntry),
	}
}

// ListBackends returns a list of all backend entries.
func (m *LoadbalancerBackendManager) ListBackends() []BackendEntry {
	backends := make([]BackendEntry, 0, len(m.backends))
	for _, backend := range m.backends {
		backends = append(backends, backend)
	}
	return backends
}

// GetBackendByID returns a single backend entry with the given ID.
func (m *LoadbalancerBackendManager) GetBackendByID(id string) (BackendEntry, error) {
	if backend, ok := m.backends[id]; ok {
		return backend, nil
	}
	return BackendEntry{}, errors.New("backend not found")
}

// CreateBackend adds a new backend entry to the manager.
func (m *LoadbalancerBackendManager) CreateBackend(backend BackendEntry) {
	m.backends[backend.ID] = backend
}

// UpdateBackend updates an existing backend entry with the given ID.
func (m *LoadbalancerBackendManager) UpdateBackend(id string, updatedBackend BackendEntry) error {
	if _, ok := m.backends[id]; ok {
		m.backends[id] = updatedBackend
		return nil
	}
	return errors.New("backend not found")
}

// DeleteBackend removes a backend entry with the given ID.
func (m *LoadbalancerBackendManager) DeleteBackend(id string) error {
	if _, ok := m.backends[id]; ok {
		delete(m.backends, id)
		return nil
	}
	return errors.New("backend not found")
}

