package tree

import (
	"github.com/leeyzero/leetcode/algorithm/base"
)

// TreeNode represents a node in a binary tree.
type TreeNode struct {
	Val   int
	Left  *TreeNode
	Right *TreeNode
}

// preorderTraversal performs a preorder traversal of a binary tree.
func preorderTraversal(root *TreeNode) []int {
	var result []int
	var preorder func(node *TreeNode)
	preorder = func(node *TreeNode) {
		if node == nil {
			return
		}
		result = append(result, node.Val)
		preorder(node.Left)
		preorder(node.Right)
	}
	preorder(root)
	return result
}

// Test cases to verify the solution
func TestPreorderTraversal(t *testing.T) {
	in := []int{1, 2, 3, -1, -1, 4, 5}
	root, err := base.UnmarshalTreeNodeByLevelorder(in)
	if err != nil {
		t.Fatalf("UnmarshalTreeNodeByLevelorder(%v) fail.err:%v", in, err)
	}
	if got, want := preorderTraversal(root), []int{1, 2, 3, 4, 5}; !reflect.DeepEqual(got, want) {
		t.Errorf("preorderTraversal(%v).got:%v want:%v", in, got, want)
	}
}
