	h.Handle("/{endpointId}/extensions", http.HandlerFunc(h.handlePostExtensions)).Methods(http.MethodPost)
	return h
}

type postExtensionRequest struct {
	Type int    `valid:"required"`
	URL  string `valid:"required,url"`
}

func (handler *ExtensionHandler) handlePostExtensions(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	id, err := strconv.Atoi(vars["endpointId"])
	if err != nil {
		httpError(w, err, http.StatusBadRequest, handler.Logger)
		return
	}
	endpointID := EndpointID(id)

	endpoint, err := handler.EndpointService.Endpoint(endpointID)
	if err == ErrEndpointNotFound {
		httpError(w, err, http.StatusNotFound, handler.Logger)
		return
	} else if err != nil {
		httpError(w, err, http.StatusInternalServerError, handler.Logger)
		return
	}

	var req postExtensionRequest
	if err = json.NewDecoder(r.Body).Decode(&req); err != nil {
		httpError(w, ErrInvalidJSON, http.StatusBadRequest, handler.Logger)
		return
	}

	_, err = govalidator.ValidateStruct(req)
	if err != nil {
		httpError(w, ErrInvalidRequestFormat, http.StatusBadRequest, handler.Logger)
		return
	}

	extensionType := EndpointExtensionType(req.Type)

	for _, extension := range endpoint.Extensions {
		if extension.Type == extensionType {
			httpError(w, ErrEndpointExtensionAlreadyAssociated, http.StatusConflict, handler.Logger)
			return
		}
	}

	extension := EndpointExtension{
		Type: extensionType,
		URL:  req.URL,
	}

	endpoint.Extensions = append(endpoint.Extensions, extension)

	err = handler.EndpointService.UpdateEndpoint(endpoint.ID, *endpoint)
	if err != nil {
		httpError(w, err, http.StatusInternalServerError, handler.Logger)
		return
	}

	encodeJSON(w, extension, handler.Logger)
}

func httpError(w http.ResponseWriter, err error, code int, logger *log.Logger) {
	http.Error(w, err.Error(), code)
	if logger != nil {
		logger.Printf("HTTP %d: %v", code, err)
	}
}

func encodeJSON(w http.ResponseWriter, v interface{}, logger *log.Logger) {
	w.Header().Set("Content-Type", "application/json")
	if err := json.NewEncoder(w).Encode(v); err != nil {
		httpError(w, err, http.StatusInternalServerError, logger)
	}
}

// Test cases to verify the solution correctness
func main() {
	// Initialize the handler
	handler := NewExtensionHandler()

	// Mock the endpoint service with a simple in-memory implementation
	mockEndpointService = &MockEndpointService{
		endpoints: map[EndpointID]*Endpoint{
