	// Check the response code and body
	if status := rr.Code; status != http.StatusOK {
		log.Fatalf("handler returned wrong status code: got %v want %v", status, http.StatusOK)
	}

	// ... additional checks on the response body ...
}

// MockEndpointService is a simple in-memory implementation of EndpointService for testing
