package main

import (
	"fmt"
	"sort"
	"strconv"
)

// RepeatString returns a new string consisting of the input string `s` repeated `cnt` times.
// If `cnt` is less than or equal to 0, an empty string is returned.
func RepeatString(s string, cnt int) string {
	if cnt <= 0 {
		return ""
	}
	result := make([]byte, len(s)*cnt)
	copy(result, s)
	for i := 1; i < cnt; i++ {
		copy(result[i*len(s):], s)
	}
	return string(result)
}

// isDigit checks if a byte is a digit.
func isDigit(b byte) bool {
	return b >= '0' && b <= '9'
}

// NaturalSort sorts a slice of strings in natural order.
func NaturalSort(strings []string) {
	sort.Slice(strings, func(i, j int) bool {
		return naturalLess(strings[i], strings[j])
	})
}

// naturalLess compares two strings in a human manner so that "rId2" sorts less than "rId10".
func naturalLess(lhs, rhs string) bool {
	i, j := 0, 0
	for i < len(lhs) && j < len(rhs) {
		lDigit, rDigit := isDigit(lhs[i]), isDigit(rhs[j])
		switch {
		case lDigit && !rDigit:
			return true
		case !lDigit && rDigit:
			return false
		case !lDigit && !rDigit:
			if lhs[i] != rhs[i] {
				return lhs[i] < rhs[i]
			}
			i++
			j++
		default:
			lEnd, rEnd := i+1, j+1
			for lEnd < len(lhs) && isDigit(lhs[lEnd]) {
				lEnd++
			}
			for rEnd < len(rhs) && isDigit(rhs[rEnd]) {
				rEnd++
			}
			lNum, _ := strconv.ParseUint(lhs[i:lEnd], 10, 64)
			rNum, _ := strconv.ParseUint(rhs[j:rEnd], 10, 64)
			if lNum != rNum {
				return lNum < rNum
			}
			i = lEnd
			j = rEnd
		}
	}
	return len(lhs) < len(rhs)
}

func main() {
	// Test cases for RepeatString
	fmt.Println(RepeatString("ab", 3)) // Expected: "ababab"
	fmt.Println(RepeatString("x", 0))  // Expected: ""

	// Test cases for NaturalSort
	s := []string{"rId2", "rId10", "rId1"}
	NaturalSort(s)
	fmt.Println(s) // Expected: ["rId1", "rId2", "rId10"]
}
