// Person represents an individual with a name, age, and sex.
type Person struct {
	Name string
	Age  int
	Sex  uint // 1 for male, 2 for female
}

// FilterInput is used to specify the filtering criteria for a list of people.
type FilterInput struct {
	MinAge    int      `json:"minAge"`
	MaxAge    int      `json:"maxAge"`
	SearchSex uint     `json:"sexSearch"`
	Reason    []string `json:"reason"`
}

// FilterPeople filters a slice of Person based on the given FilterInput criteria.
func FilterPeople(people []Person, filter FilterInput) []Person {
	var filteredPeople []Person
	for _, person := range people {
		if person.Age >= filter.MinAge && person.Age <= filter.MaxAge && person.Sex == filter.SearchSex {
			for _, reason := range filter.Reason {
				if reason == person.Name { // Assuming the reason contains the person's name for simplicity
					filteredPeople = append(filteredPeople, person)
					break
				}
			}
		}
	}
	return filteredPeople
}

func main() {
	people := []Person{
		{"Alice", 25, 2},
		{"Bob", 30, 1},
		{"Charlie", 22, 1},
		{"Diana", 35, 2},
	}

	filter := FilterInput{
		MinAge:    24,
		MaxAge:    32,
		SearchSex: 2,
		Reason:    []string{"Alice", "Diana"},
	}

	filteredPeople := FilterPeople(people, filter)
	for _, person := range filteredPeople {
