package main

import (
	"bufio"
	"bytes"
	"fmt"
	"io"
	"strings"

	"github.com/clipperhouse/uax29/iterators"
	"github.com/clipperhouse/uax29/iterators/transformer"
	"github.com/clipperhouse/uax29/words"
)

// CustomScanner is a scanner that can filter and transform words.
type CustomScanner struct {
	scanner    *iterators.Scanner
	filterFunc func([]byte) bool
	transforms []transformer.TransformFunc
}

// NewCustomScanner creates a new CustomScanner with the given reader and split function.
func NewCustomScanner(r io.Reader, split bufio.SplitFunc) *CustomScanner {
	return &CustomScanner{
		scanner: iterators.NewScanner(r, split),
	}
}

// Filter sets a filter function for the scanner.
func (cs *CustomScanner) Filter(f func([]byte) bool) {
	cs.filterFunc = f
}

// Transform sets a chain of transformation functions for the scanner.
func (cs *CustomScanner) Transform(transforms ...transformer.TransformFunc) {
	cs.transforms = transforms
}

// Scan advances the scanner to the next word that satisfies the filter.
func (cs *CustomScanner) Scan() bool {
	for cs.scanner.Scan() {
		word := cs.scanner.Bytes()
		for _, transform := range cs.transforms {
			word = transform(word)
		}
		if cs.filterFunc == nil || cs.filterFunc(word) {
			return true
		}
	}
	return false
}

// Bytes returns the most recent word generated by a call to Scan.
func (cs *CustomScanner) Bytes() []byte {
	return cs.scanner.Bytes()
}

// Err returns the first non-EOF error that was encountered by the Scanner.
func (cs *CustomScanner) Err() error {
	return cs.scanner.Err()
}

// startsWithH is a filter function that checks if a word starts with the letter 'H' or 'h'.
func startsWithH(word []byte) bool {
	return bytes.HasPrefix(word, []byte("H")) || bytes.HasPrefix(word, []byte("h"))
}

func main() {
	text := "Hello, 世界, how are you? Nice dog aha! 👍🐶"
	r := strings.NewReader(text)
	sc := NewCustomScanner(r, words.SplitFunc)
	sc.Filter(startsWithH)
	sc.Transform(transformer.Lower, transformer.Diacritics)

	var wordsFilteredTransformed []string
	for sc.Scan() {
		wordsFilteredTransformed = append(wordsFilteredTransformed, string(sc.Bytes()))
	}

	if err := sc.Err(); err != nil {
		fmt.Println("Error scanning:", err)
		return
	}

	fmt.Println("Filtered and transformed words:", wordsFilteredTransformed)
}

// Test cases and other functions would typically be in a separate _test.go file.
