func GeneratePresignedURL(client *minio.Client, bucketName, objectName string, expires time.Duration, method string) (string, error) {
	// Ensure the method is a valid HTTP method for presigned URLs
	validMethods := map[string]bool{"GET": true, "PUT": true, "HEAD": true, "POST": true, "DELETE": true}
	if _, ok := validMethods[method]; !ok {
		return "", fmt.Errorf("invalid method: %s", method)
	}

	// Retrieve the bucket location
	bucketLocation, err := client.GetBucketLocation(bucketName)
	if err != nil {
		return "", err
	}

	// Generate the target URL
	targetURL, err := makeTargetURL(client, bucketName, objectName, bucketLocation, client.IsVirtualHostStyle(), nil)
	if err != nil {
		return "", err
	}

	// Generate the presigned URL
	reqParams := make(url.Values)
	presignedURL, err := client.PresignedHTTPRequest(method, bucketName, objectName, expires, reqParams)
	if err != nil {
		return "", err
	}

	// Return the presigned URL
	return presignedURL.String(), nil
}

