package main

import (
	"database/sql"
	"log"
	"net/http"
	"time"

	"github.com/gin-gonic/contrib/static"
	"github.com/gin-gonic/gin"
	cors "github.com/itsjamie/gin-cors"
	_ "github.com/mattn/go-sqlite3"
)

var (
	router *gin.Engine
	db     *sql.DB
)

type CalculationRequest struct {
	Number1 float64 `json:"number1"`
	Number2 float64 `json:"number2"`
}

type CalculationResponse struct {
	Result float64 `json:"result"`
}

func main() {
	initDB("calculator.db")
	defer db.Close()

	router = gin.Default()

	router.Use(cors.Middleware(cors.Config{
		Origins:         "*",
		Methods:         "GET, PUT, POST, DELETE",
		RequestHeaders:  "Content-Type",
		ExposedHeaders:  "",
		MaxAge:          50 * time.Second,
		ValidateHeaders: false,
	}))

	api := router.Group("/api")
	initializeRoutes(api)

	router.Use(static.Serve("/", static.LocalFile("./frontend/client/build", true)))

	router.Run() // listen and serve on 0.0.0.0:8080
}

func initDB(filepath string) {
	var err error
	db, err = sql.Open("sqlite3", filepath)
	if err != nil {
		log.Fatal(err)
	}

	createTableSQL := `CREATE TABLE IF NOT EXISTS calculations (
		"id" INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,
		"operation" TEXT,
		"number1" REAL,
		"number2" REAL,
		"result" REAL,
		"timestamp" TEXT
	);`

	_, err = db.Exec(createTableSQL)
	if err != nil {
		log.Fatal(err)
	}
}

func initializeRoutes(api *gin.RouterGroup) {
	api.POST("/add", performAddition)
	api.POST("/subtract", performSubtraction)
	api.POST("/multiply", performMultiplication)
	api.POST("/divide", performDivision)
}

func performAddition(c *gin.Context) {
	var req CalculationRequest
	if err := c.BindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	result := req.Number1 + req.Number2
	saveCalculation("addition", req.Number1, req.Number2, result)
	c.JSON(http.StatusOK, CalculationResponse{Result: result})
}

func performSubtraction(c *gin.Context) {
	var req CalculationRequest
	if err := c.BindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	result := req.Number1 - req.Number2
	saveCalculation("subtraction", req.Number1, req.Number2, result)
	c.JSON(http.StatusOK, CalculationResponse{Result: result})
}

func performMultiplication(c *gin.Context) {
	var req CalculationRequest
	if err := c.BindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	result := req.Number1 * req.Number2
	saveCalculation("multiplication", req.Number1, req.Number2, result)
	c.JSON(http.StatusOK, CalculationResponse{Result: result})
}

func performDivision(c *gin.Context) {
	var req CalculationRequest
	if err := c.BindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if req.Number2 == 0 {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Division by zero is not allowed"})
		return
	}

	result := req.Number1 / req.Number2
	saveCalculation("division", req.Number1, req.Number2, result)
	c.JSON(http.StatusOK, CalculationResponse{Result: result})
}

func saveCalculation(operation string, number1, number2, result float64) {
	timestamp := time.Now().Format(time.RFC3339)
	_, err := db.Exec("INSERT INTO calculations (operation, number1, number2, result, timestamp) VALUES (?, ?, ?, ?, ?)",
		operation, number1, number2, result, timestamp)
	if err != nil {
		log.Printf("Failed to log calculation: %v", err)
	}
}

// Test cases to verify the solution correctness
func testCases() {
	// Initialize the database and router for testing
	initDB(":memory:")
	defer db.Close()
	router = gin.Default()
	api := router.Group("/api")
	initializeRoutes(api)

	// Define test cases
	tests := []struct {
		endpoint string
		payload  CalculationRequest
		expected CalculationResponse
	}{
		{"/api/add", CalculationRequest{Number1: 10, Number2: 5}, CalculationResponse{Result: 15}},
		{"/api/subtract", CalculationRequest{Number1: 10, Number2: 5}, CalculationResponse{Result: 5}},
		{"/api/multiply", CalculationRequest{Number1: 10, Number2: 5}, CalculationResponse{Result: 50}},
		{"/api/divide", CalculationRequest{Number1: 10, Number2: 5}, CalculationResponse{Result: 2}},
	}

	// Run test cases
	for _, test := range tests {
		w := performRequest(router, "POST", test.endpoint, test.payload)
		var response CalculationResponse
		err := json.Unmarshal(w.Body.Bytes(), &response)
		if err != nil {
			log.Fatalf("Failed to unmarshal response: %v", err)
		}
		if response.Result != test.expected.Result {
			log.Fatalf("Test failed for %s. Expected %v, got %v", test.endpoint, test.expected.Result, response.Result)
		}
	}
}

// Helper function to perform HTTP requests for testing
func performRequest(r http.Handler, method, path string, body interface{}) *httptest.ResponseRecorder {
	jsonBody, _ := json.Marshal(body)
	req, _ := http.NewRequest(method, path, bytes.NewBuffer(jsonBody))
	req.Header.Set("Content-Type", "application/json")
	w := httptest.NewRecorder()
	r.ServeHTTP(w, req)
	return w
}
