package main

import (
	"fmt"
)

type handShape int32

const (
	rock handShape = iota
	paper
	scissors
)

// winningShape determines the winning hand shape between two given hand shapes.
// It returns a pointer to the winning hand shape, or nil if there is a tie.
func winningShape(shape1, shape2 *handShape) *handShape {
	if *shape1 == *shape2 {
		return nil // Tie
	}
	switch *shape1 {
	case rock:
		if *shape2 == scissors {
			return shape1
		}
	case paper:
		if *shape2 == rock {
			return shape1
		}
	case scissors:
		if *shape2 == paper {
			return shape1
		}
	}
	return shape2
}

// letterToHandShapePart1 translates a letter to a handShape according to Part1 logic.
func letterToHandShapePart1(letter string) handShape {
	switch letter {
	case "A", "X":
		return rock
	case "B", "Y":
		return paper
	case "C", "Z":
		return scissors
	default:
		panic(fmt.Sprintf("Unhandled letter %s", letter))
	}
}

// letterToHandShapePart2 translates a letter to a handShape according to Part2 logic.
func letterToHandShapePart2(letter string, opponentHandShape handShape) (outShape handShape) {
	switch letter {
	case "A", "B", "C":
		outShape = letterToHandShapePart1(letter)
	case "X":
		for _, shape := range []handShape{rock, paper, scissors} {
			if winningShape(&opponentHandShape, &shape) == &opponentHandShape {
				outShape = shape
			}
		}
	case "Y":
		outShape = opponentHandShape
	case "Z":
		for _, shape := range []handShape{rock, paper, scissors} {
			if winningShape(&opponentHandShape, &shape) == &shape {
				outShape = shape
			}
		}
	default:
		panic(fmt.Sprintf("Unhandled letter %s", letter))
	}
	return outShape
}

// RPSRound represents a single round of rock-paper-scissors between the opponent and strategy.
type RPSRound struct {
	opponentShape handShape
	strategyShape handShape
}

// playRPSGame simulates a series of RPS rounds and prints the results.
func playRPSGame(strategy []string, opponentShapes []handShape, part2 bool) {
	for i, letter := range strategy {
		var strategyShape handShape
		if part2 {
			strategyShape = letterToHandShapePart2(letter, opponentShapes[i])
		} else {
			strategyShape = letterToHandShapePart1(letter)
		}
		round := RPSRound{opponentShape: opponentShapes[i], strategyShape: strategyShape}
		winner := winningShape(&round.opponentShape, &round.strategyShape)
		switch {
		case winner == nil:
			fmt.Printf("Round %d: Tie\n", i+1)
		case *winner == round.strategyShape:
			fmt.Printf("Round %d: AI wins\n", i+1)
		case *winner == round.opponentShape:
			fmt.Printf("Round %d: Opponent wins\n", i+1)
		}
	}
}

func main() {
	strategy := []string{"A", "X", "Y", "Z", "B"}
	opponentShapes := []handShape{scissors, rock, paper, scissors, rock}
	playRPSGame(strategy, opponentShapes, false) // Part 1
	fmt.Println("Switching to Part 2 logic")
	playRPSGame(strategy, opponentShapes, true) // Part 2
}
