package main

import (
	"bytes"
	"fmt"
	"sync"
)

// buffers is a pool of *bytes.Buffer objects that can be reused to reduce memory allocations.
var buffers = sync.Pool{
	New: func() interface{} {
		return new(bytes.Buffer)
	},
}

// GetBuffer retrieves a *bytes.Buffer from the pool or allocates a new one if the pool is empty.
func GetBuffer() *bytes.Buffer {
	return buffers.Get().(*bytes.Buffer)
}

// PutBuffer resets the contents of the given *bytes.Buffer and returns it to the pool for reuse.
func PutBuffer(buf *bytes.Buffer) {
	buf.Reset()
	buffers.Put(buf)
}

func main() {
	// Retrieve a buffer from the pool.
	buf := GetBuffer()

	// Write a string to the buffer.
	buf.WriteString("hello")

	// Print the contents of the buffer.
	fmt.Println(buf.String())

	// Return the buffer to the pool.
	PutBuffer(buf)

	// Attempt to print the contents of the buffer again to show that it has been reset.
	// The expected output should be an empty string.
	fmt.Println(buf.String())

	// Example of concurrent usage of the buffer pool.
	var wg sync.WaitGroup
	for i := 0; i < 10; i++ {
		wg.Add(1)
		go func(id int) {
			defer wg.Done()
			buffer := GetBuffer()
			defer PutBuffer(buffer)
			buffer.WriteString(fmt.Sprintf("goroutine %d\n", id))
			fmt.Print(buffer.String())
		}(i)
	}
	wg.Wait()
}
