package main

import (
	"fmt"
	"github.com/fasthttp/router"
	"github.com/valyala/fasthttp"
)

// API represents an API endpoint with a method, a path, and a test URL.
type API struct {
	Method string
	Brace  string
	Test   string
}

// ServeFunc is a function type that takes an API and returns the path of the request.
type ServeFunc func(api *API) string

// fasthttpRouterLoad initializes the router with the provided APIs and returns a ServeFunc.
func fasthttpRouterLoad(as []*API) ServeFunc {
	r := router.New()
	for _, api := range as {
		r.Handle(api.Method, api.Brace, func(ctx *fasthttp.RequestCtx) {
			ctx.Write(ctx.URI().Path())
		})
	}

	return func(api *API) string {
		resp := fasthttp.AcquireResponse()
		req := fasthttp.AcquireRequest()
		req.Header.SetMethod(api.Method)
		req.SetRequestURI(api.Test)

		ctx := &fasthttp.RequestCtx{Request: *req, Response: *resp}
		r.Handler(ctx)
		body := ctx.Response.Body()

		fasthttp.ReleaseRequest(req)
		fasthttp.ReleaseResponse(resp)

		return string(body)
	}
}

func main() {
	// Define test cases
	apis := []*API{
		{Method: "GET", Brace: "/user/{id}", Test: "http://localhost/user/123"},
		{Method: "POST", Brace: "/post/{category}", Test: "http://localhost/post/news"},
	}

	// Initialize the router
	serve := fasthttpRouterLoad(apis)

	// Test the ServeFunc with the defined APIs
	for _, api := range apis {
		path := serve(api)
		fmt.Printf("Request to %s returned path: %s\n", api.Test, path)
	}
}
