package virtualtx

import (
	"github.com/AsimovNetwork/asimov/common"
	"github.com/AsimovNetwork/asimov/protos"
	"math/big"
	"testing"
)

// Import the necessary packages
import (
	"errors"
	"sync"
)

// Define the types of virtual transfer
const (
	VTransferTypeCreation = iota
	VTransferTypeMint
)

// VirtualTransactionItem holds the details of a transaction for a specific asset.
type VirtualTransactionItem struct {
	Erc20         bool
	Mint          bool
	Create        bool
	Erc20Change   map[string]int64
	Erc721Change  map[string]map[int64]bool
}

// VirtualTransaction holds the details of all transactions.
type VirtualTransaction struct {
	mu    sync.Mutex
	items map[string]*VirtualTransactionItem
}

// NewVirtualTransaction creates a new VirtualTransaction instance.
func NewVirtualTransaction() *VirtualTransaction {
	return &VirtualTransaction{
		items: make(map[string]*VirtualTransactionItem),
	}
}

// AppendVTransfer appends a virtual transfer to the transaction.
func (vtx *VirtualTransaction) AppendVTransfer(sender, receiver common.Address, amount *big.Int, asset *protos.Asset) {
	vtx.mu.Lock()
	defer vtx.mu.Unlock()

	key := string(asset.Bytes())
	item, exists := vtx.items[key]
	if !exists {
		item = &VirtualTransactionItem{
			Erc20:       asset.IsErc20(),
			Erc20Change: make(map[string]int64),
			Erc721Change: make(map[string]map[int64]bool),
		}
		vtx.items[key] = item
	}

	if item.Erc20 {
		// Handle ERC20 asset transfer
		item.Erc20Change[string(sender.Bytes())] -= amount.Int64()
		item.Erc20Change[string(receiver.Bytes())] += amount.Int64()
	} else {
		// Handle ERC721 asset transfer
		if item.Erc721Change[string(sender.Bytes())] == nil {
			item.Erc721Change[string(sender.Bytes())] = make(map[int64]bool)
		}
		if item.Erc721Change[string(receiver.Bytes())] == nil {
			item.Erc721Change[string(receiver.Bytes())] = make(map[int64]bool)
		}
		item.Erc721Change[string(sender.Bytes())][amount.Int64()] = false
		item.Erc721Change[string(receiver.Bytes())][amount.Int64()] = true
	}
}

// AppendVCreation appends a virtual creation to the transaction.
func (vtx *VirtualTransaction) AppendVCreation(receiver common.Address, amount *big.Int, asset *protos.Asset, transferType int) {
	vtx.mu.Lock()
	defer vtx.mu.Unlock()

	key := string(asset.Bytes())
	item, exists := vtx.items[key]
	if !exists {
		item = &VirtualTransactionItem{
			Erc20:       asset.IsErc20(),
			Erc20Change: make(map[string]int64),
			Erc721Change: make(map[string]map[int64]bool),
		}
		vtx.items[key] = item
	}

	switch transferType {
	case VTransferTypeCreation:
		item.Create = true
	case VTransferTypeMint:
		item.Mint = true
	default:
		panic(errors.New("invalid transfer type"))
	}

	if item.Erc20 {
		// Handle ERC20 asset creation/minting
		item.Erc20Change[string(receiver.Bytes())] += amount.Int64()
	} else {
		// Handle ERC721 asset creation/minting
		if item.Erc721Change[string(receiver.Bytes())] == nil {
			item.Erc721Change[string(receiver.Bytes())] = make(map[int64]bool)
		}
		item.Erc721Change[string(receiver.Bytes())][amount.Int64()] = true
	}
}

// GetIncoming returns the net incoming amount of the specified asset for the given address.
func (vtx *VirtualTransaction) GetIncoming(address common.Address, asset *protos.Asset, blockHeight int64) *big.Int {
	vtx.mu.Lock()
	defer vtx.mu.Unlock()

	key := string(asset.Bytes())
	item, exists := vtx.items[key]
	if !exists {
		return big.NewInt(0)
	}

	if item.Erc20 {
		return big.NewInt(item.Erc20Change[string(address.Bytes())])
	}

	// For ERC721, we simply count the number of true entries for the address.
	count := int64(0)
	for _, has := range item.Erc721Change[string(address.Bytes())] {
		if has {
			count++
		}
	}
	return big.NewInt(count)
}

// getItem returns the transaction item associated with the given asset.
func (vtx *VirtualTransaction) getItem(asset *protos.Asset) *VirtualTransactionItem {
	vtx.mu.Lock()
	defer vtx.mu.Unlock()

	return vtx.items[string(asset.Bytes())]
}

// Test cases to verify the correctness of the solution
func TestVirtualTransaction(t *testing.T) {
	// Test cases would be similar to the ones provided in the given code snippet.
	// They would test the functionality of AppendVTransfer, AppendVCreation, GetIncoming, and getItem.
}
