package main

import (
	"fmt"
	"strconv"
	"strings"
)

func main() {
	fmt.Println("Simple Go Calculator")

	for {
		fmt.Print("Enter an expression (e.g., 3.5 * 2), or type 'exit' to quit: ")

		var input string
		fmt.Scanln(&input)

		if input == "exit" {
			break
		}

		result, err := evaluateExpression(input)
		if err != nil {
			fmt.Println("Error:", err)
		} else {
			fmt.Printf("Result: %.2f\n", result)
		}
	}
}

// evaluateExpression takes an input string and returns the result of the arithmetic expression.
// It returns an error if the input is not a valid expression.
func evaluateExpression(input string) (float64, error) {
	tokens := parseExpression(input)
	if len(tokens) != 3 {
		return 0, fmt.Errorf("invalid input. Please use the format 'number operator number'")
	}

	num1, err := strconv.ParseFloat(tokens[0], 64)
	if err != nil {
		return 0, fmt.Errorf("invalid first number: %v", err)
	}

	num2, err := strconv.ParseFloat(tokens[2], 64)
	if err != nil {
		return 0, fmt.Errorf("invalid second number: %v", err)
	}

	operator := tokens[1]

	switch operator {
	case "+":
		return num1 + num2, nil
	case "-":
		return num1 - num2, nil
	case "*":
		return num1 * num2, nil
	case "/":
		if num2 == 0 {
			return 0, fmt.Errorf("division by zero is not allowed")
		}
		return num1 / num2, nil
	default:
		return 0, fmt.Errorf("invalid operator. Please use +, -, *, or /")
	}
}

// parseExpression takes an input string and returns a slice of strings containing the tokens.
func parseExpression(input string) []string {
	return strings.Fields(input)
}

// Test cases to verify the solution correctness.
func main() {
	testExpressions := []string{
		"3.5 * 2",
		"10 + 5",
		"20 - 3.2",
		"8 / 0",
		"invalid input",
		"4.5 ^ 2",
		"exit",
	}

	for _, expr := range testExpressions {
		result, err := evaluateExpression(expr)
		if err != nil {
			fmt.Printf("Expression: %s, Error: %s\n", expr, err)
		} else {
			fmt.Printf("Expression: %s, Result: %.2f\n", expr, result)
		}
	}
}
