// SourceConfig represents the configuration for the source.
type SourceConfig struct {
	Name      string
	Directory string
}

// NewLogger creates a new logger instance.
func NewLogger(prefix string, name string) *log.Logger {
	return log.New(os.Stdout, fmt.Sprintf("%s%s", prefix, name), log.LstdFlags)
}

// NewFileSystemImageSourceWithConfig initializes a new FileSystemImageSource with the given configuration.
func NewFileSystemImageSourceWithConfig(config *SourceConfig) *FileSystemImageSource {
	source := &FileSystemImageSource{
		Config: config,
		Logger: NewLogger("source.fs.", config.Name),
	}

	baseDirectory, err := os.Open(source.Config.Directory)
	if os.IsNotExist(err) {
		source.Logger.Printf("%s does not exist. Creating.\n", source.Config.Directory)
		_ = os.MkdirAll(source.Config.Directory, 0700)
		baseDirectory, err = os.Open(source.Config.Directory)
	}

	if err != nil {
		source.Logger.Fatal(err)
	}

	fileInfo, err := baseDirectory.Stat()
	if err != nil || !fileInfo.IsDir() {
		source.Logger.Fatal("Directory ", source.Config.Directory, " is not a directory", err)
	}

	return source
}

// GetImage retrieves an image based on the provided ImageSourceOptions.
func (s *FileSystemImageSource) GetImage(request *ImageSourceOptions) (*Image, error) {
	fileName := s.fileNameForRequest(request)

	file, err := os.Open(fileName)
	if err != nil {
		s.Logger.Printf("Failed to open file: %v\n", err)
		return nil, err
	}
	defer file.Close()

	data, err := ioutil.ReadAll(file)
	if err != nil {
		s.Logger.Printf("Failed to read image: %v\n", err)
		return nil, err
	}

	return &Image{Data: data}, nil
}

// fileNameForRequest generates the file name based on the request options.
func (s *FileSystemImageSource) fileNameForRequest(request *ImageSourceOptions) string {
	return filepath.Join(s.Config.Directory, strings.Replace(strings.TrimLeft(request.Path, string(filepath.Separator)), string(filepath.Separator), "_", -1))
}

// RegisterSource registers the filesystem source type.
func RegisterSource(sourceType ImageSourceType, factoryFunc func(*SourceConfig) *FileSystemImageSource) {
	// Assume this function registers the source type with a factory function.
}

func init() {
	RegisterSource(ImageSourceTypeFilesystem, NewFileSystemImageSourceWithConfig)
}

// Example usage of the FileSystemImageSource.
func main() {
	config := &SourceConfig{
		Name:      "local",
		Directory: "./images",
	}
	source := NewFileSystemImageSourceWithConfig(config)

	http.HandleFunc("/image", func(w http.ResponseWriter, r *http.Request) {
		imagePath := r.URL.Query().Get("path")
		if imagePath == "" {
			http.Error(w, "Image path is required", http.StatusBadRequest)
			return
		}

		image, err := source.GetImage(&ImageSourceOptions{Path: imagePath})
		if err != nil {
			if errors.Is(err, os.ErrNotExist) {
				http.Error(w, "Image not found", http.StatusNotFound)
			} else {
				http.Error(w, "Internal server error", http.StatusInternalServerError)
			}
			return
		}

		w.Header().Set("Content-Type", "image/jpeg") // Assuming JPEG images for simplicity.
		w.Write(image.Data)
	})

	log.Fatal(http.ListenAndServe(":8080", nil))
}
