	Title       string `json:"title"`
	Description string `json:"description"`
	Url         string `json:"url"`
	Source      struct {
		Name string `json:"name"`
	} `json:"source"`
}

// FilterArticlesBySource filters a slice of NewsArticle by the given source name.
func FilterArticlesBySource(articles []NewsArticle, sourceName string) []NewsArticle {
	var filteredArticles []NewsArticle
	for _, article := range articles {
