func main() {
	config := &ssh.ClientConfig{
		ClientVersion: "Go SSH Client v1337",
		User:          "jpillora",
		Auth:          []ssh.AuthMethod{ssh.Password("<PASSWORD>")},
		HostKeyCallback: ssh.InsecureIgnoreHostKey(), // Note: In production, use a proper HostKeyCallback for security.
	}

	client, err := ssh.Dial("tcp", "localhost:2200", config)
	if err != nil {
		log.Fatalf("Failed to dial: %s", err)
	}

	log.Printf("connected")

	go openChannel(client, "foo")
	go openChannel(client, "bar")
	go openChannel(client, "bazz")

	// Wait for all go routines to finish
	client.Wait()

	log.Printf("disconnected")
}

func openChannel(client *ssh.Client, chanType string) {
	// Open channel
	channel, requests, err := client.OpenChannel(chanType, formatMessage("%s extra data", chanType))
	if err != nil {
		log.Fatalf("Failed to open %s channel: %s", chanType, err)
	}

	// Requests must be serviced
	go ssh.DiscardRequests(requests)

	// Send data forever...
	n := 1
	for {
		message := formatMessage("#%d send data channel %s", n, chanType)
		_, err := channel.Write(message)
		if err != nil {
			log.Printf("Error sending message on %s channel: %s", chanType, err)
			break
		}
		n++
		time.Sleep(3 * time.Second)
	}

	// Close the channel
	channel.Close()
}

func formatMessage(format string, args ...interface{}) []byte {
	return []byte(fmt.Sprintf(format, args...))
}
