	"text/template"
)

// RuleConfig holds the template strings for a rule.
type RuleConfig struct {
	MatchProfileTmpl         string
	OidcProfileTmpl          string
	AuthorizationProfileTmpl string
	MutatorProfileTmpl       string
}

// Rule represents a set of templates for matching, authenticating, authorizing, and mutating.
type Rule struct {
	Config                    *RuleConfig
	MatchProfileName          *template.Template
	AuthenticationProfileName *template.Template
	AuthorizationProfileName  *template.Template
	MutatorProfileName        *template.Template
}

// FromConfig initializes a Rule from a RuleConfig and an index for naming the templates.
func (rule *Rule) FromConfig(ruleConfig *RuleConfig, index int) []error {
	var errs []error
	var err error

	rule.Config = ruleConfig

	rule.MatchProfileName, err = template.New(fmt.Sprintf("RuleConfig.%d.MatchProfileTmpl", index)).Parse(ruleConfig.MatchProfileTmpl)
	if err != nil {
		errs = append(errs, err)
	}

	rule.AuthenticationProfileName, err = template.New(fmt.Sprintf("RuleConfig.%d.OidcProfileTmpl", index)).Parse(ruleConfig.OidcProfileTmpl)
	if err != nil {
		errs = append(errs, err)
	}

	rule.AuthorizationProfileName, err = template.New(fmt.Sprintf("RuleConfig.%d.AuthorizationProfileTmpl", index)).Parse(ruleConfig.AuthorizationProfileTmpl)
	if err != nil {
		errs = append(errs, err)
	}

	rule.MutatorProfileName, err = template.New(fmt.Sprintf("RuleConfig.%d.MutatorProfileTmpl", index)).Parse(ruleConfig.MutatorProfileTmpl)
	if err != nil {
		errs = append(errs, err)
	}

	return errs
}

// IsValid checks if the rule is valid by ensuring all necessary templates are non-nil.
func (rule *Rule) IsValid() bool {
	return rule.MatchProfileName != nil &&
		rule.AuthenticationProfileName != nil &&
		rule.AuthorizationProfileName != nil
}

func main() {
	// Example usage:
	ruleConfig := &RuleConfig{
		MatchProfileTmpl:         "match-{{.RequestPath}}",
		OidcProfileTmpl:          "oidc-{{.User}}",
		AuthorizationProfileTmpl: "authz-{{.Resource}}",
		MutatorProfileTmpl:       "mutate-{{.ResponseCode}}",
	}

	rule := &Rule{}
	errors := rule.FromConfig(ruleConfig, 1)

	if len(errors) > 0 {
		for _, err := range errors {
			fmt.Println("Error parsing template:", err)
		}
	} else if rule.IsValid() {
		fmt.Println("Rule is valid and ready to use.")
	} else {
		fmt.Println("Rule is not valid.")
	}
}
