package main

import (
	"fmt"
)

func main() {
	// Test cases to verify the solution correctness
	s := []string{"M", "N", "O", "P", "Q", "R"}
	in := []string{"A", "B", "C"}

	// Insert at the front
	res := insertSlice(s, in, 0)
	fmt.Println(res) // [A B C M N O P Q R]

	// Insert in the middle
	res = insertSlice(s, in, 3)
	fmt.Println(res) // [M N O A B C P Q R]

	// Insert at the end
	res = insertSlice(s, in, 6)
	fmt.Println(res) // [M N O P Q R A B C]

	// Insert with negative index (prepend)
	res = insertSlice(s, in, -1)
	fmt.Println(res) // [A B C M N O P Q R]

	// Insert with index greater than the length of the slice (append)
	res = insertSlice(s, in, 10)
	fmt.Println(res) // [M N O P Q R A B C]
}

// insertSlice inserts a slice of strings into another slice of strings at a specified index.
// If the index is out of bounds, the insertion slice is appended or prepended accordingly.
func insertSlice(slice, insertion []string, index int) []string {
	if index < 0 {
		return append(insertion, slice...)
	}
	if index > len(slice) {
		return append(slice, insertion...)
	}

	result := make([]string, len(slice)+len(insertion))
	at := copy(result, slice[:index])
	at += copy(result[at:], insertion)
	copy(result[at:], slice[index:])
	return result
}
