type ServiceConfig struct {
	PortName      string
	ContainerPort int
	ServicePort   int
}

func GetServiceConfig(portName string) (ServiceConfig, error) {
	switch portName {
	case HTTPPortName:
		return ServiceConfig{HTTPPortName, HTTPContainerPort, HTTPServicePort}, nil
	case GRPCPortName:
		return ServiceConfig{GRPCPortName, GRPCContainerPort, GRPCServicePort}, nil
	default:
		return ServiceConfig{}, errors.New("unknown port name")
	}
}

func UpdateServicePort(portName string, newPort int) error {
	if newPort < 1024 || newPort > 65535 {
		return errors.New("invalid port range")
	}

	switch portName {
	case HTTPPortName:
		HTTPServicePort = newPort
	case GRPCPortName:
		GRPCServicePort = newPort
	default:
		return errors.New("unknown port name")
	}

	return nil
}

func main() {
	// Retrieve the default HTTP configuration
	httpConfig, err := GetServiceConfig(HTTPPortName)
	if err != nil {
		fmt.Println(err)
		return
	}
	fmt.Printf("Default HTTP Config: %+v\n", httpConfig)

	// Update the HTTP service port
	err = UpdateServicePort(HTTPPortName, 8080)
	if err != nil {
		fmt.Println(err)
		return
	}

	// Retrieve the updated HTTP configuration
	updatedHTTPConfig, err := GetServiceConfig(HTTPPortName)
