// versionFormat is a regular expression that matches the version string in the build tag.
var versionFormat = regexp.MustCompile(`\d+\.\d+\.\d+`)

// GetClusterVersionInfo extracts the version info for each member of the cluster.
func GetClusterVersionInfo(members []serf.Member) (map[string]*version.Version, map[string]error) {
	versions := make(map[string]*version.Version)
	errors := make(map[string]error)

	for _, member := range members {
		str := versionFormat.FindString(member.Tags["build"])
		if str == "" {
			errors[member.Name] = fmt.Errorf("version information not found for member %s", member.Name)
			continue
		}
		v, err := version.NewVersion(str)
		if err != nil {
			errors[member.Name] = err
			continue
		}
		versions[member.Name] = v
	}

	return versions, errors
}

func main() {
	// Test cases
	members := []serf.Member{
		{
			Name: "node1",
			Tags: map[string]string{"build": "Consul 1.9.5"},
		},
		{
			Name: "node2",
			Tags: map[string]string{"build": "Consul 1.8.0"},
		},
		{
			Name: "node3",
			Tags: map[string]string{"build": "InvalidVersion"},
		},
	}

	versions, errors := GetClusterVersionInfo(members)

	for nodeName, version := range versions {
		fmt.Printf("Node %s is running version %s\n", nodeName, version)
	}

	for nodeName, err := range errors {
		fmt.Printf("Error for node %s: %s\n", nodeName, err)
	}
