}

type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].priority < pq[j].priority
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
	pq[i].index = i
	pq[j].index = j
}

func (pq *PriorityQueue) Push(x interface{}) {
	n := len(*pq)
	item := x.(*Item)
	item.index = n
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	old[n-1] = nil
	item.index = -1
	*pq = old[0 : n-1]
	return item
}

func (pq *PriorityQueue) update(item *Item, value interface{}, priority int64) {
	item.value = value
	item.priority = priority
	heap.Fix(pq, item.index)
}

func New() *PriorityQueue {
	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	return &pq
}

func (pq *PriorityQueue) Insert(value interface{}, priority int64) error {
	for _, item := range *pq {
		if item.value == value {
			return ErrorItemDuplicated
		}
	}
	heap.Push(pq, &Item{
		value:    value,
		priority: priority,
	})
	return nil
}

func (pq *PriorityQueue) PopItem() (interface{}, error) {
	if pq.Len() == 0 {
		return nil, ErrorEmptyQueue
	}
	item := heap.Pop(pq).(*Item)
	return item.value, nil
}

func (pq *PriorityQueue) Top() (interface{}, error) {
	if pq.Len() == 0 {
		return nil, ErrorEmptyQueue
	}
	return (*pq)[0].value, nil
}

func (pq *PriorityQueue) UpdatePriority(value interface{}, newPriority int64) error {
	for _, item := range *pq {
		if item.value == value {
			pq.update(item, value, newPriority)
			return nil
		}
	}
	return ErrorItemNotFound
}

func (pq *PriorityQueue) Remove(value interface{}) error {
	for i, item := range *pq {
		if item.value == value {
			heap.Remove(pq, i)
			return nil
		}
	}
	return ErrorItemNotFound
}

