// SyncConsoleLinks ensures that the ConsoleLink resources in the Kubernetes cluster match the desired state for the given Jaeger instance.
func SyncConsoleLinks(ctx context.Context, rClient client.Client, jaeger v1.Jaeger, desired []osconsolev1.ConsoleLink) error {
	tracer := otel.GetTracerProvider().Tracer(v1.ReconciliationTracer)
	ctx, span := tracer.Start(ctx, "SyncConsoleLinks")
	defer span.End()

	if viper.GetString(v1.ConfigOperatorScope) != v1.OperatorScopeCluster {
		logInfo(span, "console link skipped, operator isn't cluster-wide")
		return nil
	}

	opts := []client.ListOption{
		client.MatchingLabels(map[string]string{
			"app.kubernetes.io/instance":   jaeger.Name,
			"app.kubernetes.io/namespace":  jaeger.Namespace,
			"app.kubernetes.io/managed-by": "jaeger-operator",
		}),
	}
	list := &osconsolev1.ConsoleLinkList{}
	if err := rClient.List(ctx, list, opts...); err != nil {
		return handleError(err, span)
	}

	inv := inventory.ForConsoleLinks(list.Items, desired)
	for _, d := range inv.Create {
		logInfo(span, fmt.Sprintf("creating console link: %s in namespace: %s", d.Name, d.Namespace))
		if err := rClient.Create(ctx, &d); err != nil {
			return handleError(err, span)
		}
	}

	for _, d := range inv.Update {
		logInfo(span, fmt.Sprintf("updating console link: %s in namespace: %s", d.Name, d.Namespace))
		if err := rClient.Update(ctx, &d); err != nil {
			return handleError(err, span)
		}
