	for _, d := range inv.Delete {
		logInfo(span, fmt.Sprintf("deleting console link: %s in namespace: %s", d.Name, d.Namespace))
		if err := rClient.Delete(ctx, &d); err != nil {
			return handleError(err, span)
		}
	}

	return nil
}

