// InsertIssue inserts a new issue into the database and associates it with a user.
func InsertIssue(engine *xorm.Engine, issue *Issue) (int64, error) {
	return engine.Insert(issue)
}

// ToggleIssueVisibility toggles the visibility of an issue by updating its Show field.
func ToggleIssueVisibility(engine *xorm.Engine, issueId int64) (int64, error) {
	issue := new(Issue)
	has, err := engine.ID(issueId).Get(issue)
	if err != nil {
		return 0, err
	}
	if !has {
		return 0, errors.New("issue not found")
	}
	issue.Show = !issue.Show
	return engine.ID(issueId).Cols("show").Update(issue)
}

// SetIssueUserId sets an issue's UserId by the Id of a user's issue.
func SetIssueUserId(engine *xorm.Engine, issueId, userId int64) (int64, error) {
	issue := &Issue{UserId: userId}
	return engine.ID(issueId).Cols("user_id").Update(issue)
}

