}

// EnsureFieldsInUpdate ensures that certain fields are always included in updates.
func EnsureFieldsInUpdate(engine *xorm.Engine, user *User, mustCols ...string) (int64, error) {
	return engine.ID(user.Id).MustCols(mustCols...).Update(user)
}

