package main

import (
	"context"
	"fmt"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"

	"github.com/spf13/viper"
	"go.uber.org/zap"
	"go.uber.org/zap/zapcore"
)

var logger *zap.Logger

func initLogger(level zapcore.Level) {
	cfg := zap.NewProductionConfig()
	cfg.Level = zap.NewAtomicLevelAt(level)
	var err error
	logger, err = cfg.Build()
	if err != nil {
		panic(err)
	}
	defer logger.Sync() // flushes buffer, if any
}

func initViper() {
	viper.AutomaticEnv()
	viper.SetDefault("HTTP_HOST", "localhost")
	viper.SetDefault("HTTP_PORT", 8080)
	viper.SetDefault("HTTP_READ_TIMEOUT", 5)
	viper.SetDefault("HTTP_WRITE_TIMEOUT", 10)
	viper.SetDefault("HTTP_IDLE_TIMEOUT", 15)
	viper.SetDefault("LOG_LEVEL", -1)
}

func initHTTPServer(ctx context.Context, handler http.Handler) func() {
	host := viper.GetString("HTTP_HOST")
	port := viper.GetInt("HTTP_PORT")
	addr := fmt.Sprintf("%s:%d", host, port)

	server := &http.Server{
		Addr:         addr,
		Handler:      handler,
		ReadTimeout:  time.Duration(viper.GetInt("HTTP_READ_TIMEOUT")) * time.Second,
		WriteTimeout: time.Duration(viper.GetInt("HTTP_WRITE_TIMEOUT")) * time.Second,
		IdleTimeout:  time.Duration(viper.GetInt("HTTP_IDLE_TIMEOUT")) * time.Second,
	}

	go func() {
		logger.Info("HTTP server is running", zap.String("address", addr))
		if err := server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			logger.Fatal("HTTP server ListenAndServe error", zap.Error(err))
		}
	}()

	return func() {
		ctxShutdown, cancel := context.WithTimeout(ctx, 30*time.Second)
		defer cancel()

		server.SetKeepAlivesEnabled(false)
		if err := server.Shutdown(ctxShutdown); err != nil {
			logger.Fatal("HTTP server Shutdown error", zap.Error(err))
		}
		logger.Info("HTTP server has been shut down")
	}
}

func run(ctx context.Context) error {
	initViper()
	logLevel := zapcore.Level(viper.GetInt("LOG_LEVEL"))
	initLogger(logLevel)

	handler := http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Write([]byte("Hello, World!"))
	})

	cleanFunc := initHTTPServer(ctx, handler)

	sc := make(chan os.Signal, 1)
	signal.Notify(sc, syscall.SIGHUP, syscall.SIGINT, syscall.SIGTERM, syscall.SIGQUIT)

	select {
	case sig := <-sc:
		logger.Info("Received signal", zap.String("signal", sig.String()))
		cleanFunc()
	case <-ctx.Done():
		logger.Info("Context done", zap.Error(ctx.Err()))
		cleanFunc()
	}

	logger.Info("Server exiting")
	return nil
}

func main() {
	if err := run(context.Background()); err != nil {
		logger.Fatal("Server run error", zap.Error(err))
	}
}
