package main

import (
	"errors"
	"os"
	"strings"

	"github.com/dnephin/dobi/tasks/task"
	"gotest.tools/v3/assert"
	"gotest.tools/v3/env"
	"testing"
)

type EnvConfig struct {
	Variables []string
}

func RunEnvTask(taskName string, config *EnvConfig) (bool, error) {
	if config == nil {
		return false, errors.New("config cannot be nil")
	}

	originalEnv := make(map[string]string)
	modified := false

	for _, variable := range config.Variables {
		parts := strings.SplitN(variable, "=", 2)
		if len(parts) != 2 {
			return false, errors.New("invalid variable format")
		}
		key, value := parts[0], parts[1]

		originalValue, exists := os.LookupEnv(key)
		if !exists || originalValue != value {
			modified = true
		}
		originalEnv[key] = originalValue
		os.Setenv(key, value)
	}

	// Simulate task execution
	task.Execute(task.NewName(taskName, ""))

	// Restore original environment
	for key, value := range originalEnv {
		if value == "" {
			os.Unsetenv(key)
		} else {
			os.Setenv(key, value)
		}
	}

	return modified, nil
}

func toSlice(m map[string]string) []string {
	p := []string{}
	for k, v := range m {
		p = append(p, k+"="+v)
	}
	return p
}

func TestRunEnvTask(t *testing.T) {
	var testcases = []struct {
		doc      string
		expected bool
		vars     map[string]string
	}{
		{
			doc: "set from variables",
			vars: map[string]string{
				"VAR_ONE": "override",
				"VAR_TWO": "new",
			},
			expected: true,
		},
		{
			doc: "no modifications",
			vars: map[string]string{
				"VAR_ONE": "preset",
			},
			expected: false,
		},
	}

	for _, tc := range testcases {
		t.Run(tc.doc, func(t *testing.T) {
			defer env.PatchAll(t, map[string]string{
				"VAR_ONE": "preset",
			})()

			modified, err := RunEnvTask("foo", &EnvConfig{
				Variables: toSlice(tc.vars),
			})
			assert.NilError(t, err)
			assert.Equal(t, modified, tc.expected)

			for k, v := range tc.vars {
				assert.Equal(t, os.Getenv(k), v)
			}
		})
	}
}
