package main

import (
	"fmt"
	"time"
)

// TokenResponse is a generic OAuth2 token response
type TokenResponse struct {
	Token        string    `json:"token,omitempty"`
	AccessToken  string    `json:"access_token,omitempty"`
	RefreshToken string    `json:"refresh_token,omitempty"`
	ExpiresIn    int       `json:"expires_in,omitempty"`
	IssuedAt     time.Time `json:"issued_at,omitempty"`
}

// IsTokenExpired checks if the token has expired based on the current time and ExpiresIn duration.
// It returns a boolean indicating if the token is expired and the duration since expiration.
func IsTokenExpired(tokenResponse TokenResponse) (bool, time.Duration) {
	expirationTime := tokenResponse.IssuedAt.Add(time.Duration(tokenResponse.ExpiresIn) * time.Second)
	if time.Now().After(expirationTime) {
		return true, time.Now().Sub(expirationTime)
	}
	return false, 0
}

// RefreshToken simulates the process of refreshing an expired token.
// It returns a new TokenResponse with updated fields.
func RefreshToken(oldTokenResponse TokenResponse) TokenResponse {
	newTokenResponse := TokenResponse{
		Token:        oldTokenResponse.Token,
		AccessToken:  "new_access_token", // In a real scenario, this should be generated securely
		RefreshToken: oldTokenResponse.RefreshToken,
		ExpiresIn:    3600, // Fixed expiration time of 1 hour
		IssuedAt:     time.Now(),
	}
	return newTokenResponse
}

func main() {
	// Example test case
	tokenResponse := TokenResponse{
		Token:        "initial_token",
		AccessToken:  "initial_access_token",
		RefreshToken: "initial_refresh_token",
		ExpiresIn:    10, // Expires in 10 seconds for testing
		IssuedAt:     time.Now(),
	}

	// Wait for the token to expire
	time.Sleep(11 * time.Second)

	expired, sinceExpiration := IsTokenExpired(tokenResponse)
	if expired {
		fmt.Printf("Token expired %v ago\n", sinceExpiration)
		// Refresh the token
		newTokenResponse := RefreshToken(tokenResponse)
		fmt.Printf("New Access Token: %s\n", newTokenResponse.AccessToken)
	} else {
		fmt.Println("Token is still valid")
	}
}
