package randomnames

import (
	"math/rand"
	"testing"
	"time"
	"unicode"
)

// RandomName generates a random name with a length between 5 to 10 characters.
// The name may include any Unicode character.
func RandomName() string {
	rand.Seed(time.Now().UnixNano())
	length := rand.Intn(6) + 5 // Random length between 5 and 10
	runes := make([]rune, length)
	for i := range runes {
		runes[i] = rune(rand.Intn(0x10FFFF)) // Any valid Unicode code point
		if !unicode.IsPrint(runes[i]) {
			i-- // Ensure the character is printable
		}
	}
	return string(runes)
}

// SafeRandomName generates a random name with a length between 8 to 16 characters.
// The name only includes alphanumeric characters.
func SafeRandomName() string {
	const lettersAndNumbers = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
	rand.Seed(time.Now().UnixNano())
	length := rand.Intn(9) + 8 // Random length between 8 and 16
	runes := make([]rune, length)
	for i := range runes {
		runes[i] = rune(lettersAndNumbers[rand.Intn(len(lettersAndNumbers))])
	}
	return string(runes)
}

func BenchmarkRandomName(b *testing.B) {
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		_ = RandomName()
	}
}

func BenchmarkSafeRandomName(b *testing.B) {
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		_ = SafeRandomName()
	}
}

// Test cases to verify the solution correctness
func TestRandomName(t *testing.T) {
	name := RandomName()
	if len(name) < 5 || len(name) > 10 {
		t.Errorf("RandomName() generated a name of invalid length: got %v want between 5 and 10", len(name))
	}
}

func TestSafeRandomName(t *testing.T) {
	name := SafeRandomName()
	if len(name) < 8 || len(name) > 16 {
		t.Errorf("SafeRandomName() generated a name of invalid length: got %v want between 8 and 16", len(name))
	}
	for _, r := range name {
		if !unicode.IsLetter(r) && !unicode.IsNumber(r) {
			t.Errorf("SafeRandomName() generated a name with non-alphanumeric character: got %v", name)
			break
		}
	}
}
