package main

import (
	"bytes"
	"fmt"
	"os"
	"strconv"
	"strings"
	"time"
)

// FileInfo interface defines the methods to access file properties.
type FileInfo interface {
	Name() string
	Size() int64
	ModTime() time.Time
	Mode() os.FileMode
	Owner() string
	Group() string
	UID() int
	GID() int
}

// listFormatter is a slice of FileInfo interfaces.
type listFormatter []FileInfo

// Short returns a string that lists the collection of files by name only, one per line.
func (formatter listFormatter) Short() []byte {
	var buf bytes.Buffer
	for _, file := range formatter {
		fmt.Fprintf(&buf, "%s\r\n", file.Name())
	}
	return buf.Bytes()
}

// Detailed returns a string that lists the collection of files with extra detail, one per line.
func (formatter listFormatter) Detailed() []byte {
	var buf bytes.Buffer
	for _, file := range formatter {
		fmt.Fprint(&buf, file.Mode().String())
		fmt.Fprintf(&buf, " 1 %s %s ", file.Owner(), file.Group())
		fmt.Fprint(&buf, lpad(strconv.FormatInt(file.Size(), 10), 12))
		fmt.Fprint(&buf, file.ModTime().Format(" Jan _2 15:04 "))
		fmt.Fprintf(&buf, "%s\r\n", file.Name())
	}
	return buf.Bytes()
}

// RFC3659 returns a string that lists the collection of files according to RFC3659, one per line.
func (formatter listFormatter) RFC3659() []byte {
	buf := &bytes.Buffer{}
	for _, file := range formatter {
		kind := "file"
		sizeField := "size"
		if file.Mode().IsDir() {
			switch file.Name() {
			case ".":
				kind = "cdir"
			case "..":
				kind = "pdir"
			default:
				kind = "dir"
			}
			sizeField = "sizd"
		}
		fmt.Fprintf(buf, "type=%s;", kind)
		fmt.Fprintf(buf, "%s=%d;", sizeField, file.Size())
		fmt.Fprintf(buf, "modify=%s;", file.ModTime().Format("20060102150405"))
		fmt.Fprintf(buf, "UNIX.mode=%04o;", file.Mode().Perm())
		if file.UID() != -1 {
			fmt.Fprintf(buf, "UNIX.uid=%d;", file.UID())
		}
		if file.GID() != -1 {
			fmt.Fprintf(buf, "UNIX.gid=%d;", file.GID())
		}
		fmt.Fprintf(buf, " %s\r\n", file.Name())
	}
	return buf.Bytes()
}

// lpad left-pads the input string with spaces to a specified length.
func lpad(input string, length int) (result string) {
	if len(input) < length {
		result = strings.Repeat(" ", length-len(input)) + input
	} else if len(input) == length {
		result = input
	} else {
		result = input[0:length]
	}
	return
}

// Example implementation of FileInfo interface for testing purposes.
type mockFileInfo struct {
	name    string
	size    int64
	modTime time.Time
	mode    os.FileMode
	owner   string
	group   string
	uid     int
	gid     int
}

func (m mockFileInfo) Name() string       { return m.name }
func (m mockFileInfo) Size() int64        { return m.size }
func (m mockFileInfo) ModTime() time.Time { return m.modTime }
func (m mockFileInfo) Mode() os.FileMode  { return m.mode }
func (m mockFileInfo) Owner() string      { return m.owner }
func (m mockFileInfo) Group() string      { return m.group }
func (m mockFileInfo) UID() int           { return m.uid }
func (m mockFileInfo) GID() int           { return m.gid }

// Test cases to verify the solution correctness.
func main() {
	files := listFormatter{
		mockFileInfo{"file1.txt", 1234, time.Now(), 0644, "user", "group", 1000, 1000},
		mockFileInfo{"file2.txt", 5678, time.Now(), 0644, "user", "group", 1000, 1000},
	}

	fmt.Println("Short format:")
	fmt.Println(string(files.Short()))

	fmt.Println("Detailed format:")
	fmt.Println(string(files.Detailed()))

	fmt.Println("RFC3659 format:")
	fmt.Println(string(files.RFC3659()))
