	// Header
	o.WriteString("TYPE_OF_GENERIC_FILE=MOSES_NESTED_PROFILE\r\n")
	o.WriteString("VERSION=1.0\r\n")
	o.WriteString("USAGE=PLASMA\r\n")

	// Common data
	o.WriteString("COMMON_DATA\r\n")
	o.WriteString("NEST_NAME=" + b.NestName + "\r\n")
	o.WriteString("RAW_LENGTH=" + strconv.FormatFloat(b.RawLength, 'f', -1, 64) + "\r\n")
	o.WriteString("END_OF_COMMON_DATA\r\n")

	// Calculate used and remaining lengths
	var used float64
	for _, p := range b.Parts {
		used += Spacing(p.Left[0], b.FullType)
		used += p.Length
		used += Spacing(p.Right[0], b.FullType)
	}
	rest := b.RawLength - used

	// Profile data
	for i, p := range b.Parts {
		o.WriteString("PROFILE_DATA\r\n")
		o.WriteString("TLENGTH=" + strconv.FormatFloat(p.Length, 'f', -1, 64) + "\r\n")
		o.WriteString("IDENT_STRING=" + b.Project + "-" + b.Section + "-" + p.PosNo + "\r\n")
		o.WriteString("NO_OF_ICUTS=" + strconv.Itoa(len(p.Icuts)) + "\r\n")
		o.WriteString("NO_OF_PARTS=" + strconv.Itoa(i+1) + "\r\n")
		o.WriteString("END_OF_PROFILE_DATA\r\n")
	}

	// Output used and remaining lengths
	o.WriteString("USED_LENGTH=" + strconv.FormatFloat(used, 'f', -1, 64) + "\r\n")
	o.WriteString("REST_LENGTH=" + strconv.FormatFloat(rest, 'f', -1, 64) + "\r\n")

	return o.String()
}

