// Feedback represents the structure of the feedback data.
type Feedback struct {
	Rid             int
	AppointyID      int
	OrderId         int
	UserId          int
	FeedbackRating  int
	Comment         string
	FeedbackDate    int
	AdminReply      int
	Promote_Facebook int
	AppointmentID   int
}

// FetchFeedbackData retrieves feedback data from the database and encodes it into gob format.
func FetchFeedbackData(ctx context.Context, db *sql.DB, query string) ([]byte, error) {
	rows, err := db.QueryContext(ctx, query)
	if err != nil {
		return nil, fmt.Errorf("failed to execute query: %w", err)
	}
	defer rows.Close()

	var feedbacks []Feedback
	for rows.Next() {
		var f Feedback
		if err := rows.Scan(&f.Rid, &f.AppointyID, &f.OrderId, &f.UserId, &f.FeedbackRating, &f.Comment, &f.FeedbackDate, &f.AdminReply, &f.Promote_Facebook, &f.AppointmentID); err != nil {
			return nil, fmt.Errorf("failed to scan row: %w", err)
		}
		feedbacks = append(feedbacks, f)
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("rows iteration error: %w", err)
	}

	var buf bytes.Buffer
	if err := gob.NewEncoder(&buf).Encode(feedbacks); err != nil {
		return nil, fmt.Errorf("gob encoding failed: %w", err)
	}

	return buf.Bytes(), nil
}

func main() {
