package parser

import (
	"errors"
	"io"
	"strings"
)

// readToken reads the next token from the input stream.
// A token is defined as a sequence of non-space characters.
// It returns the token and any error encountered.
func readToken(r *strings.Reader) (string, error) {
	var sb strings.Builder
	var ch rune
	var err error

	for {
		ch, _, err = r.ReadRune()
		if err != nil {
			if err == io.EOF && sb.Len() > 0 {
				return sb.String(), nil
			}
			return "", errors.New("no more tokens")
		}
		if ch == ' ' {
			if sb.Len() > 0 {
				return sb.String(), nil
			}
			continue // skip spaces before a token
		}
		sb.WriteRune(ch)
	}
}

// Test cases to verify the solution correctness.
func TestTokenizer(t *testing.T) {
	tests := []struct {
		input    string
		expected []string
	}{
		{"1 2", []string{"1", "2"}},
		{"   leading spaces", []string{"leading", "spaces"}},
		{"trailing spaces   ", []string{"trailing", "spaces"}},
		{"  multiple   spaces  ", []string{"multiple", "spaces"}},
		{"", nil},
		{" ", nil},
	}

	for _, test := range tests {
		rs := strings.NewReader(test.input)
		for _, expToken := range test.expected {
			token, err := readToken(rs)
			if err != nil || token != expToken {
				t.Fatalf("Expected token '%s', got '%s' or error '%v'", expToken, token, err)
			}
		}
		_, err := readToken(rs)
		if err == nil {
			t.Fatal("Expected error for no more tokens, got nil")
		}
	}
}
