package main

import (
	"bufio"
	"fmt"
	"os"
	"strings"
)

// priorities assigns a unique priority to each letter of the alphabet.
var priorities = func() map[rune]int {
	priorities := make(map[rune]int, 52)
	prio := 0

	for i := 'a'; i <= 'z'; i++ {
		prio += 1
		priorities[i] = prio
	}

	for i := 'A'; i <= 'Z'; i++ {
		prio += 1
		priorities[i] = prio
	}
	return priorities
}()

// contains checks if a slice of runes contains a specific rune.
func contains(slice []rune, val rune) bool {
	for _, item := range slice {
		if item == val {
			return true
		}
	}
	return false
}

// processCompartmentSums processes the strings and calculates the sums of priorities.
func processCompartmentSums(filename string) (int, int, error) {
	file, err := os.Open(filename)
	if err != nil {
		return 0, 0, err
	}
	defer file.Close()
	scanner := bufio.NewScanner(file)

	var everyPrioSum, badgePrioSum int
	var group []string

	for scanner.Scan() {
		line := scanner.Text()
		length := len(line)
		group = append(group, line)

		first := []rune(line[:length/2])
		second := []rune(line[length/2:])

		for _, char := range first {
			if contains(second, char) {
				everyPrioSum += priorities[char]
				break
			}
		}

		if len(group) == 3 {
			chars1 := []rune(group[0])
			chars2 := []rune(group[1])
			chars3 := []rune(group[2])

			for _, char := range chars1 {
				if contains(chars2, char) && contains(chars3, char) {
					badgePrioSum += priorities[char]
					break
				}
			}
			group = nil
		}
	}

	return everyPrioSum, badgePrioSum, scanner.Err()
}

func main() {
	everyPrioSum, badgePrioSum, err := processCompartmentSums("input/aocday3.txt")
	if err != nil {
		fmt.Println("Error reading file:", err)
		return
	}

	fmt.Printf("The sum of the priorities of items found in each compartment is %d\n", everyPrioSum)
	fmt.Printf("The sum of the priorities of badges is %d\n", badgePrioSum)
}
