// User represents a user in the system.
type User struct {
	Username string `json:"username"`
	Email    string `json:"email"`
	Password string `json:"password"`
}

// userStore holds the in-memory user data.
var userStore = struct {
	sync.RWMutex
	users map[string]User
}{users: make(map[string]User)}

// createUser creates a new user in the system.
func createUser(c *gin.Context) {
	var newUser User
	if err := c.BindJSON(&newUser); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid user data"})
		return
	}

	userStore.Lock()
	defer userStore.Unlock()

	if _, exists := userStore.users[newUser.Username]; exists {
		c.JSON(http.StatusConflict, gin.H{"error": "Username already exists"})
		return
	}

	userStore.users[newUser.Username] = newUser
	c.JSON(http.StatusCreated, newUser)
}

// getUser retrieves a user's details by their username.
func getUser(c *gin.Context) {
	username := c.Param("username")

	userStore.RLock()
	defer userStore.RUnlock()

	user, exists := userStore.users[username]
	if !exists {
		c.JSON(http.StatusNotFound, gin.H{"error": "User not found"})
		return
	}

	c.JSON(http.StatusOK, user)
}

// updateUser updates a user's email and password by their username.
func updateUser(c *gin.Context) {
	username := c.Param("username")
	var updateData User
	if err := c.BindJSON(&updateData); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid update data"})
		return
	}

	userStore.Lock()
	defer userStore.Unlock()

	user, exists := userStore.users[username]
	if !exists {
		c.JSON(http.StatusNotFound, gin.H{"error": "User not found"})
		return
	}

	user.Email = updateData.Email
	user.Password = updateData.Password
	userStore.users[username] = user
	c.JSON(http.StatusOK, user)
}

// deleteUser deletes a user by their username.
func deleteUser(c *gin.Context) {
	username := c.Param("username")

	userStore.Lock()
	defer userStore.Unlock()

	if _, exists := userStore.users[username]; !exists {
		c.JSON(http.StatusNotFound, gin.H{"error": "User not found"})
		return
	}

	delete(userStore.users, username)
	c.JSON(http.StatusOK, gin.H{"message": "User deleted"})
}

