package main

import (
	"fmt"
	"math"
)

type Number interface {
	int64 | float64
}

func Power[T Number](x, y T) (float64, error) {
	switch x.(type) {
	case int64:
		switch y.(type) {
		case int64:
			return float64(integerPower(x.(int64), y.(int64))), nil
		case float64:
			return math.Pow(float64(x.(int64)), y.(float64)), nil
		}
	case float64:
		switch y.(type) {
		case int64:
			return math.Pow(x.(float64), float64(y.(int64))), nil
		case float64:
			return math.Pow(x.(float64), y.(float64)), nil
		}
	}
	return 0, fmt.Errorf("unsupported types for Power function")
}

func integerPower(x, y int64) int64 {
	p := int64(1)
	for y > 0 {
		if y&1 != 0 {
			p *= x
		}
		y >>= 1
		x *= x
	}
	return p
}

func main() {
