	testCases := []struct {
		x      Number
		y      Number
		result float64
		err    string
	}{
		{2, 3, 8, ""},
		{2.5, 2, 6.25, ""},
		{2, 3.5, 11.313708498984761, ""},
		{2.5, 2.5, 9.882117688026185, ""},
		{"a", 2, 0, "unsupported types for Power function"},
	}

	for _, tc := range testCases {
		result, err := Power(tc.x, tc.y)
		if err != nil {
			fmt.Printf("Power(%v, %v) = Error: %s\n", tc.x, tc.y, err)
		} else {
			fmt.Printf("Power(%v, %v) = %v\n", tc.x, tc.y, result)
		}
	}
}
