// Factorial returns the factorial of its argument, calculated via repeated
// multiplication using arbitrary precision arithmetic.
func Factorial(n *big.Int) *big.Int {
	one := big.NewInt(1)
	ret := big.NewInt(1)
	for ; n.Sign() > 0; n.Sub(n, one) {
		ret.Mul(ret, n)
	}
	return ret
}

