		big.NewInt(1),  // 1!
		big.NewInt(5),  // 5!
		big.NewInt(10), // 10!
		new(big.Int).SetInt64(20), // 20!
	}

	for _, n := range testCases {
		result := Factorial(n)
		fmt.Printf("%v! = %v\n", n, result)
	}
