	api := slack.New(token)

	return SlackClient{
		api,
	}
}

// SlackChannel represents a Slack channel
type SlackChannel struct {
	Name string
	ID   string
}

// LeaveChannel makes the user leave the channel with the given ID
func (sc SlackClient) LeaveChannel(channelID string) error {
	_, err := sc.api.LeaveChannel(channelID)
	return err
}

// FetchUserChannels returns a list of public channels that the user is a member of
func (sc SlackClient) FetchUserChannels(userID string) ([]SlackChannel, error) {
	channelNames := make([]SlackChannel, 0)
	cursor := ""

	for {
		params := &slack.GetConversationsForUserParameters{
			UserID: userID,
			Cursor: cursor,
		}

		channels, nextCursor, err := sc.api.GetConversationsForUser(params)
		if err != nil {
			return nil, err
		}

		for _, channel := range channels {
			channelNames = append(channelNames, SlackChannel{
				Name: channel.Name,
				ID:   channel.ID,
			})
		}

		if nextCursor == "" {
			break
		}
		cursor = nextCursor
	}

	return channelNames, nil
}

