package main

import (
	"fmt"
	"math"
	"strconv"
	"strings"
)

// Define the constants for ingredient names.
const (
	INGR_FUEL = "FUEL"
	INGR_ORE  = "ORE"
)

// Ingredient represents a chemical ingredient.
type Ingredient struct {
	name string
	eq   *Equation
}

// EqPart represents a part of an equation, either input or output.
type EqPart struct {
	ingredient *Ingredient
	cnt        int64
}

// Equation represents a chemical equation with inputs and an output.
type Equation struct {
	input  []*EqPart
	output *EqPart
}

// Blueprints holds the mapping of ingredients and the list of equations.
type Blueprints struct {
	ingrMap map[string]*Ingredient
	eqs     []*Equation
	fuelEq  *Equation
}

// newIngredient creates a new Ingredient.
func newIngredient(name string) *Ingredient {
	return &Ingredient{
		name: name,
	}
}

// newEquation creates a new Equation.
func newEquation() *Equation {
	return &Equation{
		input: make([]*EqPart, 0),
	}
}

// GetOrCreateIngredient retrieves or creates an Ingredient.
func (blueprints *Blueprints) GetOrCreateIngredient(name string) *Ingredient {
	if ingr, ok := blueprints.ingrMap[name]; ok {
		return ingr
	}

	ingr := newIngredient(name)
	blueprints.ingrMap[name] = ingr
	return ingr
}

// AddEquationFromString parses a string into an Equation and adds it to Blueprints.
func (blueprints *Blueprints) AddEquationFromString(str string) {
	strs := strings.Split(str, " => ")
	inputStrs := strings.Split(strs[0], ", ")

	eq := newEquation()
	for _, inputStr := range inputStrs {
		eqPart := blueprints.parseEqPart(inputStr)
		eq.input = append(eq.input, eqPart)
	}

	eq.output = blueprints.parseEqPart(strs[1])

	blueprints.eqs = append(blueprints.eqs, eq)
	outgr := eq.output.ingredient
	if outgr.name == INGR_FUEL {
		blueprints.fuelEq = eq
	}

	if outgr.eq != nil {
		panic(fmt.Sprintf("%s already has an eq %v", outgr.name, eq))
	}

	outgr.eq = eq
}

// parseEqPart parses a string into an EqPart.
func (blueprints *Blueprints) parseEqPart(str string) *EqPart {
	strs := strings.Split(str, " ")
	cnt, err := strconv.Atoi(strs[0])
	if err != nil {
		panic(err)
	}
	name := strs[1]

	ingr := blueprints.GetOrCreateIngredient(name)
	eqPart := EqPart{
		ingredient: ingr,
		cnt:        int64(cnt),
	}
	return &eqPart
}

// ParseBlueprint parses a multiline string into Blueprints.
func ParseBlueprint(str string) *Blueprints {
	blueprints := &Blueprints{
		ingrMap: make(map[string]*Ingredient),
		eqs:     make([]*Equation, 0),
	}

	str = strings.Replace(str, "\r", "", -1)
	lines := strings.Split(str, "\n")

	for _, line := range lines {
		blueprints.AddEquationFromString(line)
	}

	return blueprints
}

// CalculateOreRequired calculates the minimum amount of ORE required to produce a given amount of FUEL.
func CalculateOreRequired(blueprints *Blueprints, fuelAmount int64) int64 {
	needs := map[string]int64{INGR_FUEL: fuelAmount}
	excess := make(map[string]int64)

	var getOre func(ingredient string, amount int64) int64
	getOre = func(ingredient string, amount int64) int64 {
		if ingredient == INGR_ORE {
			return amount
		}

		// Use excess ingredients if available.
		if excess[ingredient] >= amount {
			excess[ingredient] -= amount
			return 0
		}

		amount -= excess[ingredient]
		excess[ingredient] = 0

		eq := blueprints.ingrMap[ingredient].eq
		times := int64(math.Ceil(float64(amount) / float64(eq.output.cnt)))
		oreNeeded := int64(0)

		for _, input := range eq.input {
			oreNeeded += getOre(input.ingredient.name, input.cnt*times)
		}

		excess[ingredient] += times*eq.output.cnt - amount
		return oreNeeded
	}

	return getOre(INGR_FUEL, fuelAmount)
}

func main() {
	// Example test case
	blueprintStr := `10 ORE => 10 A
1 ORE => 1 B
7 A, 1 B => 1 C
7 A, 1 C => 1 D
7 A, 1 D => 1 E
7 A, 1 E => 1 FUEL`

	blueprints := ParseBlueprint(blueprintStr)
	oreRequired := CalculateOreRequired(blueprints, 1)
	fmt.Printf("ORE required to produce 1 FUEL: %d\n", oreRequired)
}
