	service ITransactionService
}

// NewTransactionController creates a new instance of TransactionController
func NewTransactionController(service ITransactionService) *TransactionController {
	return &TransactionController{
		service: service,
	}
}

// Post handles the creation of a new transaction
func (t *TransactionController) Post(c *gin.Context) {
	transaction := &Transaction{}
	if err := c.BindJSON(&transaction); err != nil {
		c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": "Invalid JSON payload"})
		return
	}

	// Validate the transaction type
	if transaction.Type != "credit" && transaction.Type != "debit" {
		c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": "Invalid transaction type"})
		return
	}

	// Call the service to create the transaction
	createdTransaction, err := t.service.Create(transaction)
	if err != nil {
		c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusCreated, createdTransaction)
}

// Mock implementation of ITransactionService for testing
type MockTransactionService struct {
	mock.Mock
}

func (m *MockTransactionService) Create(transaction *Transaction) (*Transaction, error) {
	args := m.Called(transaction)
	return args.Get(0).(*Transaction), args.Error(1)
}

// Test cases for the Post method
func TestTransactionController_Post(t *testing.T) {
