			ID:        "1",
			AccountID: "123",
			Amount:    100.0,
			Type:      "credit",
		}

		mockService.On("Create", transaction).Return(transaction, nil)

		w := performRequest(router, "POST", "/transactions", transaction)

		assert.Equal(t, http.StatusCreated, w.Code)
		mockService.AssertExpectations(t)
	})

	t.Run("Invalid Transaction Type", func(t *testing.T) {
		mockService := new(MockTransactionService)
		controller := NewTransactionController(mockService)
		router := gin.Default()
		router.POST("/transactions", controller.Post)

		transaction := &Transaction{
