type RegisterCommand struct {
	ID        uuid.UUID `validate:"required"`
	FirstName string    `validate:"required"`
	LastName  string    `validate:"required"`
	Email     string    `validate:"required,email"`
	Password  []byte    `validate:"required"`
}

type RegisterCommandResponse struct {
	Success bool
	Message string
}

func RegisterCommandHandler(command RegisterCommand) RegisterCommandResponse {
	// Validate the input fields
	if command.FirstName == "" || command.LastName == "" || command.Email == "" || len(command.Password) == 0 {
		return RegisterCommandResponse{Success: false, Message: "All fields are required"}
	}

	// Validate the email format
	emailRegex := regexp.MustCompile(`^[a-z0-9._%+\-]+@[a-z0-9.\-]+\.[a-z]{2,4}$`)
	if !emailRegex.MatchString(command.Email) {
		return RegisterCommandResponse{Success: false, Message: "Invalid email format"}
	}

	// Hash the password
	hashedPassword, err := bcrypt.GenerateFromPassword(command.Password, bcrypt.DefaultCost)
	if err != nil {
		return RegisterCommandResponse{Success: false, Message: "Failed to hash password"}
	}
	command.Password = hashedPassword

	// Generate a unique identifier
	command.ID = uuid.New()

	// Here you would normally save the command to a database, etc.

	return RegisterCommandResponse{Success: true, Message: "Registration successful"}
}

func main() {
	// Test cases
	testCases := []RegisterCommand{
		{FirstName: "John", LastName: "Doe", Email: "john.doe@example.com", Password: []byte("password123")},
