package main

import (
	"errors"
	"fmt"
	"log"
	"os"
	"sync"
	"time"
)

var (
	ErrSubmitTimeout  = errors.New("exceeded maximum capacity and submit timeout")
	ErrWorkerReleased = errors.New("worker has been released")
)

type Pool struct {
	name          string
	capacity      int
	submitTimeout time.Duration
	active        chan struct{}
	tasks         chan func()
	wg            sync.WaitGroup
	quit          chan struct{}
	log           Logger
}

type Logger interface {
	Printf(format string, args ...interface{})
}

const (
	defaultCapacity      = 100
	maxCapacity          = 10000
	defaultSubmitTimeout = time.Millisecond * 500
)

func New(name string, opts ...Option) *Pool {
	p := &Pool{
		name:  name,
		tasks: make(chan func()),
		quit:  make(chan struct{}),
	}

	for _, opt := range opts {
		opt(p)
	}

	capacity := p.capacity
	if capacity <= 0 {
		capacity = defaultCapacity
	}
	if capacity > maxCapacity {
		capacity = maxCapacity
	}
	p.capacity = capacity
	p.active = make(chan struct{}, capacity)

	timeout := p.submitTimeout
	if timeout == 0 {
		timeout = defaultSubmitTimeout
	}
	p.submitTimeout = timeout

	if p.log == nil {
		p.log = log.New(os.Stderr, fmt.Sprintf("[worker-%s]: ", p.name), log.LstdFlags|log.Lmsgprefix|log.Lmicroseconds)
	}

	go p.run()
	return p
}

func (p *Pool) doTask(t func()) {
	p.wg.Add(1)
	go func() {
		defer func() {
			if err := recover(); err != nil {
				stack := make([]byte, 1024)
				length := runtime.Stack(stack, false)
				p.log.Printf("recover panic[%v] and exit - %s\n", err, stack[:length])
			}
			p.wg.Done()
			<-p.active
		}()
		t()
	}()
}

func (p *Pool) run() {
	for {
		select {
		case <-p.quit:
			p.log.Printf("exit")
			return
		case t := <-p.tasks:
			p.doTask(t)
		}
	}
}

func (p *Pool) Submit(t func()) error {
	select {
	case <-p.quit:
		return ErrWorkerReleased
	case p.active <- struct{}{}:
		p.tasks <- t
		return nil
	case <-time.After(p.submitTimeout):
		p.log.Printf("submit worker task timeout")
		return ErrSubmitTimeout
	}
}

func (p *Pool) Release() {
	close(p.quit)
	p.wg.Wait()
	p.log.Printf("release")
}

type Option func(*Pool)

func WithCapacity(capacity int) Option {
	return func(p *Pool) {
		p.capacity = capacity
	}
}

func WithSubmitTimeout(timeout time.Duration) Option {
	return func(p *Pool) {
		p.submitTimeout = timeout
	}
}

func WithLogger(logger Logger) Option {
	return func(p *Pool) {
		p.log = logger
	}
}

// Example usage of the Pool
func main() {
	// Create a new pool with a custom capacity and submit timeout
	pool := New("example", WithCapacity(10), WithSubmitTimeout(1*time.Second))

	// Define a simple task
	task := func() {
		fmt.Println("Task is running")
		time.Sleep(2 * time.Second) // Simulate a task taking some time
		fmt.Println("Task is done")
	}

	// Submit a task to the pool
	err := pool.Submit(task)
	if err != nil {
		log.Printf("Error submitting task: %v", err)
	}

	// Release the pool and wait for all tasks to complete
	pool.Release()
}
