// Endpoint represents a network tunnel endpoint with an ID, prefix, and key.
type Endpoint struct {
	ID     string
	Prefix string
	Key    int
}

// EndpointStore holds a map of endpoint IDs to their corresponding Endpoint objects.
type EndpointStore struct {
	sync.RWMutex
	endpoints map[string]Endpoint
}

// NewEndpointStore initializes and returns a new instance of EndpointStore.
func NewEndpointStore() *EndpointStore {
	return &EndpointStore{
		endpoints: make(map[string]Endpoint),
	}
}

// AddEndpoint adds a new tunnel endpoint to the store.
func (s *EndpointStore) AddEndpoint(endpointID, prefix string, key int) error {
	s.Lock()
	defer s.Unlock()

	if _, exists := s.endpoints[endpointID]; exists {
		return fmt.Errorf("endpoint with ID %s already exists", endpointID)
	}

	s.endpoints[endpointID] = Endpoint{
		ID:     endpointID,
		Prefix: prefix,
		Key:    key,
	}

	return nil
}

// GetEndpoint retrieves an endpoint's prefix and key by its ID.
func (s *EndpointStore) GetEndpoint(endpointID string) (string, int, bool) {
	s.RLock()
	defer s.RUnlock()

	endpoint, found := s.endpoints[endpointID]
	if !found {
		return "", 0, false
	}

	return endpoint.Prefix, endpoint.Key, true
}

// DeleteEndpoint removes an endpoint from the store by its ID.
func (s *EndpointStore) DeleteEndpoint(endpointID string) {
	s.Lock()
	defer s.Unlock()

	delete(s.endpoints, endpointID)
}

func main() {
	store := NewEndpointStore()

	// Test cases
	err := store.AddEndpoint("endpoint1", "10.0.0.1", 1234)
	if err != nil {
		fmt.Println("Error adding endpoint:", err)
	}

	prefix, key, found := store.GetEndpoint("endpoint1")
	if found {
		fmt.Printf("Retrieved endpoint: prefix=%s, key=%d\n", prefix, key)
	} else {
		fmt.Println("Endpoint not found")
	}

	store.DeleteEndpoint("endpoint1")
	_, _, found = store.GetEndpoint("endpoint1")
	if !found {
		fmt.Println("Endpoint successfully deleted")
	}
}
