)

const rfc3339Milli = "2006-01-02T15:04:05.999Z07:00"

type DB struct {
	db *bolt.DB
}

func NewDB(path string) (*DB, error) {
	db, err := bolt.Open(path, 0600, &bolt.Options{Timeout: 1 * time.Second})
	if err != nil {
		return nil, err
	}
	return &DB{db: db}, nil
}

func (d *DB) Open() error {
	return d.db.Update(func(tx *bolt.Tx) error {
		_, err := tx.CreateBucketIfNotExists([]byte(`tokens`))
		return err
	})
}

func (d *DB) Close() error {
	return d.db.Close()
}

func (d *DB) SaveToken(user, token, expires string) error {
	if err := d.Open(); err != nil {
		return err
	}
	defer d.Close()

	return d.db.Update(func(tx *bolt.Tx) error {
		b := tx.Bucket([]byte(`tokens`))
		u, err := b.CreateBucketIfNotExists([]byte(user))
		if err != nil {
			return err
		}
		mapdata := map[string]string{
			"expires": expires,
			"token":   token,
		}
		data, _ := json.Marshal(&mapdata)
		return u.Put([]byte(expires), data)
	})
}

func (d *DB) GetActiveToken(user string) (string, error) {
	if err := d.Open(); err != nil {
		return ``, err
	}
	defer d.Close()

	var token string
	if err := d.db.View(func(tx *bolt.Tx) error {
		// build cursor seek position
		var k, v []byte
		min := []byte(time.Now().UTC().Format(rfc3339Milli))

		// open bucket for that user
		b := tx.Bucket([]byte(`tokens`)).Bucket([]byte(user))
		if b == nil {
			return bolt.ErrBucketNotFound
		}

		// seek an entry
		c := b.Cursor()
		for k, v = c.First(); k != nil; k, v = c.Next() {
			data := make(map[string]string)
			json.Unmarshal(v, &data)
			if expires, err := time.Parse(rfc3339Milli, data["expires"]); err == nil && expires.After(time.Now().UTC()) {
				token = data["token"]
				break
			}
		}
		return nil
	}); err != nil {
		return "", err
	}
	if token != "" {
		return token, nil
	}
	return "", errors.New("no active token found")
}

func main() {
	// Initialize the database
	db, err := NewDB("my.db")
	if err != nil {
		panic(err)
	}
	defer db.Close()

	// Test cases
	user := "user123"
	token := "token123"
	expires := time.Now().Add(24 * time.Hour).Format(rfc3339Milli) // 24 hours from now

	// Save a token
	err = db.SaveToken(user, token, expires)
	if err != nil {
		fmt.Println("Error saving token:", err)
	} else {
		fmt.Println("Token saved successfully.")
	}

	// Retrieve the active token
	activeToken, err := db.GetActiveToken(user)
	if err != nil {
		fmt.Println("Error retrieving active token:", err)
	} else {
		fmt.Println("Active token:", activeToken)
	}

	// Attempt to retrieve the active token after expiration
	time.Sleep(24 * time.Hour) // Simulate time passing
	expiredToken, err := db.GetActiveToken(user)
	if err != nil {
		fmt.Println("Error retrieving active token after expiration:", err)
	} else {
		fmt.Println("Expired token:", expiredToken)
	}
}
