)

// CountSundaysOnFirstOfMonth counts the number of Sundays that fell on the first of the month
// between the given start and end times.
func CountSundaysOnFirstOfMonth(startTime, endTime time.Time) int {
	acc := 0
	for timeCursor := startTime; timeCursor.Before(endTime); timeCursor = timeCursor.AddDate(0, 0, 1) {
		if timeCursor.Weekday() == time.Sunday && timeCursor.Day() == 1 {
			acc++
		}
	}
	return acc
}

func main() {
	startTime := time.Date(1901, time.January, 1, 0, 0, 0, 0, time.UTC)
	endTime := time.Date(2000, time.December, 31, 23, 59, 59, 0, time.UTC)
	count := CountSundaysOnFirstOfMonth(startTime, endTime)
	fmt.Println(count)
}

// Test cases to verify the solution correctness
func main() {
	// Test case 1: The entire twentieth century
	startTime := time.Date(1901, time.January, 1, 0, 0, 0, 0, time.UTC)
	endTime := time.Date(2000, time.December, 31, 23, 59, 59, 0, time.UTC)
	fmt.Printf("Count from 1901 to 2000: %d\n", CountSundaysOnFirstOfMonth(startTime, endTime))

	// Test case 2: A single year
	startTime = time.Date(2000, time.January, 1, 0, 0, 0, 0, time.UTC)
	endTime = time.Date(2000, time.December, 31, 23, 59, 59, 0, time.UTC)
	fmt.Printf("Count for the year 2000: %d\n", CountSundaysOnFirstOfMonth(startTime, endTime))

	// Test case 3: A month with a Sunday on the first
	startTime = time.Date(2000, time.April, 1, 0, 0, 0, 0, time.UTC)
	endTime = time.Date(2000, time.April, 30, 23, 59, 59, 0, time.UTC)
	fmt.Printf("Count for April 2000: %d\n", CountSundaysOnFirstOfMonth(startTime, endTime))

	// Test case 4: A month without a Sunday on the first
	startTime = time.Date(2000, time.May, 1, 0, 0, 0, 0, time.UTC)
	endTime = time.Date(2000, time.May, 31, 23, 59, 59, 0, time.UTC)
	fmt.Printf("Count for May 2000: %d\n", CountSundaysOnFirstOfMonth(startTime, endTime))
}
