package main

import (
	"encoding/json"
	"fmt"
	"reflect"
	"time"
)

// Define the time buckets for transaction processing times.
var timeBuckets = []time.Duration{
	50 * time.Millisecond,
	100 * time.Millisecond,
	200 * time.Millisecond,
	// ... more buckets as needed
}

type transactionProcessingTimeDistribution struct {
	Buckets []int
}

func (t *transactionProcessingTimeDistribution) AddTransaction(duration time.Duration) {
	for i, bucket := range timeBuckets {
		if duration < bucket {
			t.Buckets[i]++
			return
		}
	}
	// If the duration is longer than any bucket, add it to the last bucket.
	t.Buckets[len(t.Buckets)-1]++
}

func (t *transactionProcessingTimeDistribution) MarshalJSON() ([]byte, error) {
	return json.Marshal(t.Buckets)
}

type AssembleBlockStats struct {
	TransactionCount    int
	TotalProcessingTime time.Duration
	// ... other relevant statistics
}

func (a *AssembleBlockStats) String() string {
	val := reflect.ValueOf(*a)
	var stats []string
	for i := 0; i < val.NumField(); i++ {
		field := val.Type().Field(i)
		value := val.Field(i).Interface()
		if val.Field(i).Kind() == reflect.Int && val.Field(i).Int() != 0 {
			stats = append(stats, fmt.Sprintf("%s: %d", field.Name, value))
		} else if val.Field(i).Kind() == reflect.Struct {
			// Handle nested structs if necessary.
		}
		// ... handle other non-zero fields
	}
	return fmt.Sprintf("{%s}", string.Join(stats, ", "))
}

func main() {
	// Initialize the distribution with a slice of zeros for each bucket.
	distribution := transactionProcessingTimeDistribution{
		Buckets: make([]int, len(timeBuckets)),
	}

	// Add some transactions.
	distribution.AddTransaction(45 * time.Millisecond)
	distribution.AddTransaction(75 * time.Millisecond)
	distribution.AddTransaction(150 * time.Millisecond)

	// Marshal the distribution to JSON.
	jsonBytes, err := distribution.MarshalJSON()
	if err != nil {
		fmt.Println("Error marshaling JSON:", err)
		return
	}
	fmt.Println("Transaction Processing Time Distribution:", string(jsonBytes))

	// Create block stats and print the summary string.
	blockStats := AssembleBlockStats{
		TransactionCount:    3,
		TotalProcessingTime: 270 * time.Millisecond,
		// ... other statistics
	}
	fmt.Println("Block Assembly Statistics:", blockStats.String())
}
