package cbor

import (
	"bytes"
	"errors"
	"github.com/fxamacker/cbor/v2"
	"math"
)

const invalidVersion = math.MaxUint16

var (
	// ErrInvalidVersion is the error returned when a versioned
	// serialized blob is either missing, or has an invalid version.
	ErrInvalidVersion = errors.New("cbor: missing or invalid version")

	decOptionsVersioned = cbor.DecOptions{
		DupMapKey: cbor.DupMapKeyEnforcedAPF,
	}

	decModeVersioned cbor.DecMode
)

// Versioned is a generic versioned serializable data structure.
type Versioned struct {
	V uint16 `cbor:"v"`
}

// GetVersion returns the version of a versioned serializable data
// structure, if any.
func GetVersion(data []byte) (uint16, error) {
	vblob := Versioned{
		V: invalidVersion,
	}
	if err := decModeVersioned.Unmarshal(data, &vblob); err != nil {
		return 0, err
	}
	if vblob.V == invalidVersion {
		return 0, ErrInvalidVersion
	}
	return vblob.V, nil
}

// NewVersioned creates a new Versioned structure with the specified version.
func NewVersioned(v uint16) Versioned {
	if v == invalidVersion {
		panic("cbor: invalid version specified")
	}
	return Versioned{V: v}
}

func init() {
	// Use the untrusted decode options, but ignore unknown fields.
	decOptionsVersioned.ExtraReturnErrors = cbor.ExtraDecErrorNone

	var err error
	if decModeVersioned, err = decOptionsVersioned.DecMode(); err != nil {
		panic(err)
	}
}

// Example usage and test cases
func main() {
	// Import the required package
	import (
		"fmt"
		"log"
	)

	// Test case 1: Create a new versioned struct and encode it
	version := uint16(1)
	vStruct := NewVersioned(version)
	encMode, _ := cbor.CanonicalEncOptions().EncMode()
	encoded, err := encMode.Marshal(vStruct)
	if err != nil {
		log.Fatalf("Failed to encode: %v", err)
	}
	fmt.Printf("Encoded data: %x\n", encoded)

	// Test case 2: Decode the version number from the encoded data
	decodedVersion, err := GetVersion(encoded)
	if err != nil {
		log.Fatalf("Failed to decode version: %v", err)
	}
	fmt.Printf("Decoded version: %d\n", decodedVersion)

	// Test case 3: Attempt to decode an invalid version
	invalidEncoded := []byte{0xff} // Invalid CBOR data
	_, err = GetVersion(invalidEncoded)
	if err == nil {
		log.Fatalf("Expected an error for invalid encoded data, but none occurred")
	}
	fmt.Println("Correctly identified invalid encoded data:", err)

	// Test case 4: Attempt to create a versioned struct with an invalid version
	defer func() {
		if r := recover(); r != nil {
			fmt.Println("Recovered from panic:", r)
		}
	}()
	_ = NewVersioned(invalidVersion) // This should panic
	fmt.Println("This should not be printed, as the above line should panic.")
}
