// Package rtmp provides functionality for parsing and generating RTMP messages.
package rtmp

import (
	"encoding/binary"
	"errors"
	"fmt"
	"github.com/bluenviron/mediamtx/internal/rtmp/rawmessage"
)

// Import the necessary packages
import (
	"bytes"
	"encoding/binary"
	"fmt"
)

// MessageFactory creates a Message instance based on the message type.
func MessageFactory(messageType Type) (Message, error) {
	switch messageType {
	case TypeSetChunkSize:
		return &SetChunkSizeMessage{}, nil
	case TypeAbortMessage:
		return &AbortMessage{}, nil
	case TypeAcknowledge:
		return &AcknowledgeMessage{}, nil
	case TypeSetWindowAckSize:
		return &SetWindowAckSizeMessage{}, nil
	case TypeSetPeerBandwidth:
		return &SetPeerBandwidthMessage{}, nil
	case TypeUserControl:
		return &UserControlMessage{}, nil
	// Add cases for other message types...
	default:
		return nil, fmt.Errorf("unsupported message type: %d", messageType)
	}
}

// CodecIdentifier returns a human-readable string for a given FourCC identifier.
func CodecIdentifier(codec FourCC) string {
	switch codec {
	case FourCCAV1:
		return "AV1"
	case FourCCVP9:
		return "VP9"
	case FourCCHEVC:
		return "HEVC"
	default:
		return "Unknown"
	}
}

// Example implementations of Message interface for different message types
type SetChunkSizeMessage struct {
	ChunkSize uint32
}

func (m *SetChunkSizeMessage) Unmarshal(rawMsg *rawmessage.Message) error {
	if len(rawMsg.Body) < 4 {
		return errors.New("invalid body length for SetChunkSizeMessage")
	}
	m.ChunkSize = binary.BigEndian.Uint32(rawMsg.Body)
	return nil
}

func (m *SetChunkSizeMessage) Marshal() (*rawmessage.Message, error) {
	body := make([]byte, 4)
	binary.BigEndian.PutUint32(body, m.ChunkSize)
	return &rawmessage.Message{
		Type: byte(TypeSetChunkSize),
		Body: body,
	}, nil
}

// Add implementations for other message types...

// Test cases to verify the solution correctness
func main() {
	// Test CodecIdentifier
	fmt.Println("CodecIdentifier(FourCCAV1):", CodecIdentifier(FourCCAV1)) // Output: AV1
	fmt.Println("CodecIdentifier(FourCCVP9):", CodecIdentifier(FourCCVP9)) // Output: VP9
	fmt.Println("CodecIdentifier(FourCCHEVC):", CodecIdentifier(FourCCHEVC)) // Output: HEVC
	fmt.Println("CodecIdentifier([4]byte{'x', 'y', 'z', '0'}):", CodecIdentifier([4]byte{'x', 'y', 'z', '0'})) // Output: Unknown

	// Test MessageFactory and Message interface
	rawMsg := &rawmessage.Message{
		Type: byte(TypeSetChunkSize),
		Body: []byte{0x00, 0x00, 0x40, 0x00}, // 16384 in big-endian
	}
	msg, err := MessageFactory(TypeSetChunkSize)
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		err := msg.Unmarshal(rawMsg)
		if err != nil {
			fmt.Println("Unmarshal Error:", err)
		} else {
			fmt.Printf("Unmarshaled Message: %+v\n", msg)
			marshaledMsg, err := msg.Marshal()
			if err != nil {
				fmt.Println("Marshal Error:", err)
			} else {
				fmt.Printf("Marshaled Message: %+v\n", marshaledMsg)
			}
		}
	}
}
