package main

import (
	"encoding/json"
	"fmt"
	"io/ioutil"
	"net/http"
	"sync"
)

// URLMapping holds the structure for the URL and its alias.
type URLMapping struct {
	Alias string `json:"alias"`
	URL   string `json:"url"`
}

// URLStore holds the URL mappings and a mutex for concurrent access.
type URLStore struct {
	sync.RWMutex
	mappings map[string]string
}

// NewURLStore initializes a new URLStore.
func NewURLStore() *URLStore {
	return &URLStore{
		mappings: make(map[string]string),
	}
}

// AddMapping adds a new URL mapping to the store.
func (s *URLStore) AddMapping(alias, url string) {
	s.Lock()
	defer s.Unlock()
	s.mappings[alias] = url
}

// GetURL retrieves the original URL for a given alias.
func (s *URLStore) GetURL(alias string) (string, bool) {
	s.RLock()
	defer s.RUnlock()
	url, exists := s.mappings[alias]
	return url, exists
}

// GetAllMappings returns all URL mappings.
func (s *URLStore) GetAllMappings() []URLMapping {
	s.RLock()
	defer s.RUnlock()
	mappings := make([]URLMapping, 0, len(s.mappings))
	for alias, url := range s.mappings {
		mappings = append(mappings, URLMapping{Alias: alias, URL: url})
	}
	return mappings
}

func main() {
	store := NewURLStore()
	http.HandleFunc("/shorten", func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
			return
		}

		var mapping URLMapping
		body, err := ioutil.ReadAll(r.Body)
		if err != nil {
			http.Error(w, "Failed to read request body", http.StatusBadRequest)
			return
		}
		defer r.Body.Close()

		if err := json.Unmarshal(body, &mapping); err != nil {
			http.Error(w, "Invalid JSON", http.StatusBadRequest)
			return
		}

		store.AddMapping(mapping.Alias, mapping.URL)
		response, _ := json.Marshal(mapping)
		w.Header().Set("Content-Type", "application/json")
		w.Write(response)
	})

	http.HandleFunc("/links", func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodGet {
			http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
			return
		}

		mappings := store.GetAllMappings()
		response, _ := json.Marshal(mappings)
		w.Header().Set("Content-Type", "application/json")
		w.Write(response)
	})

	http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		alias := r.URL.Path[1:]
		if url, exists := store.GetURL(alias); exists {
			http.Redirect(w, r, url, http.StatusFound)
			return
		}
		http.NotFound(w, r)
	})

	fmt.Println("Starting the server on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		panic(err)
	}
}
