package subscription

import (
	"context"
	"errors"
	"sync"
	"time"

	"github.com/google/uuid"
)

// Subscription represents a subscription to an event stream.
type Subscription struct {
	ID              uuid.UUID
	Sink            string
	SinkCredential  *Credential
	LastHeartbeat   time.Time
	CurrentOffset   int64
}

// Credential holds the credentials for secure event delivery.
type Credential struct {
	AccessKey    string
	SecretKey    string
}

// SubscriptionManager manages subscriptions.
type SubscriptionManager struct {
	subscriptions map[uuid.UUID]*Subscription
	mu            sync.RWMutex
}

// NewSubscriptionManager creates a new SubscriptionManager.
func NewSubscriptionManager() *SubscriptionManager {
	return &SubscriptionManager{
		subscriptions: make(map[uuid.UUID]*Subscription),
	}
}

// AddSubscription adds a new subscription.
func (m *SubscriptionManager) AddSubscription(ctx context.Context, sink string, credential *Credential) (uuid.UUID, error) {
	m.mu.Lock()
	defer m.mu.Unlock()

	id := uuid.New()
	subscription := &Subscription{
		ID:             id,
		Sink:           sink,
		SinkCredential: credential,
		LastHeartbeat:  time.Now(),
		CurrentOffset:  0,
	}
	m.subscriptions[id] = subscription
	return id, nil
}

// UpdateSubscription updates an existing subscription.
func (m *SubscriptionManager) UpdateSubscription(ctx context.Context, id uuid.UUID, sink string, credential *Credential) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	subscription, exists := m.subscriptions[id]
	if !exists {
		return errors.New("subscription not found")
	}

	subscription.Sink = sink
	subscription.SinkCredential = credential
	return nil
}

// DeleteSubscription deletes a subscription.
func (m *SubscriptionManager) DeleteSubscription(ctx context.Context, id uuid.UUID) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	_, exists := m.subscriptions[id]
	if !exists {
		return errors.New("subscription not found")
	}

	delete(m.subscriptions, id)
	return nil
}

// GetSubscription retrieves a subscription by ID.
func (m *SubscriptionManager) GetSubscription(ctx context.Context, id uuid.UUID) (*Subscription, error) {
	m.mu.RLock()
	defer m.mu.RUnlock()

	subscription, exists := m.subscriptions[id]
	if !exists {
		return nil, errors.New("subscription not found")
	}

	return subscription, nil
}

// ListSubscription lists all subscriptions.
func (m *SubscriptionManager) ListSubscription(ctx context.Context) []*Subscription {
	m.mu.RLock()
	defer m.mu.RUnlock()

	var subscriptions []*Subscription
	for _, sub := range m.subscriptions {
		subscriptions = append(subscriptions, sub)
	}
	return subscriptions
}

// Heartbeat records a heartbeat for a subscription.
func (m *SubscriptionManager) Heartbeat(ctx context.Context, id uuid.UUID) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	subscription, exists := m.subscriptions[id]
	if !exists {
		return errors.New("subscription not found")
	}

	subscription.LastHeartbeat = time.Now()
	return nil
}

// SaveOffset saves the offset for a subscription.
func (m *SubscriptionManager) SaveOffset(ctx context.Context, id uuid.UUID, offset int64) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	subscription, exists := m.subscriptions[id]
	if !exists {
		return errors.New("subscription not found")
	}

	subscription.CurrentOffset = offset
	return nil
}

// GetOffset retrieves the current offset for a subscription.
func (m *SubscriptionManager) GetOffset(ctx context.Context, id uuid.UUID) (int64, error) {
	m.mu.RLock()
	defer m.mu.RUnlock()

	subscription, exists := m.subscriptions[id]
	if !exists {
		return 0, errors.New("subscription not found")
	}

	return subscription.CurrentOffset, nil
}

