// Define the Context type
type Context struct{}

// Define the Keeper interface
type Keeper interface {
	HandleValidatorSignature(ctx Context, address []byte, power int64, signedLastBlock bool)
	HandleDoubleSign(ctx Context, address []byte, height int64, time time.Time, power int64)
	Logger(ctx Context) Logger
}

// Define the Logger interface
type Logger interface {
	Error(msg string)
}

// Define the RequestBeginBlock type
type RequestBeginBlock struct {
	LastCommitInfo       LastCommitInfo
	ByzantineValidators  []Evidence
}

// Define the LastCommitInfo type
type LastCommitInfo struct {
	Votes []VoteInfo
}

// Define the VoteInfo type
type VoteInfo struct {
	Validator Validator
	SignedLastBlock bool
}

// Define the Validator type
type Validator struct {
	Address []byte
	Power   int64
}

// Define the Evidence type
type Evidence struct {
	Type    tmtypes.EvidenceType
	Validator Validator
	Height  int64
	Time    time.Time
}

// BeginBlocker function
func BeginBlocker(ctx Context, req RequestBeginBlock, sk Keeper) {
	// Iterate over all the validators which *should* have signed this block
	for _, voteInfo := range req.LastCommitInfo.Votes {
		sk.HandleValidatorSignature(ctx, voteInfo.Validator.Address, voteInfo.Validator.Power, voteInfo.SignedLastBlock)
	}

	// Iterate through any newly discovered evidence of infraction
	for _, evidence := range req.ByzantineValidators {
		switch evidence.Type {
		case tmtypes.ABCIEvidenceTypeDuplicateVote:
			sk.HandleDoubleSign(ctx, evidence.Validator.Address, evidence.Height, evidence.Time, evidence.Validator.Power)
		default:
			sk.Logger(ctx).Error(fmt.Sprintf("ignored unknown evidence type: %s", evidence.Type))
		}
	}
}

// Test cases
func main() {
