				{Validator: Validator{Address: []byte("validator_2"), Power: 100}, SignedLastBlock: false},
			},
		},
		ByzantineValidators: []Evidence{
			{Type: tmtypes.ABCIEvidenceTypeDuplicateVote, Validator: Validator{Address: []byte("validator_3"), Power: 100}, Height: 10, Time: time.Now()},
		},
	}

	// Create a mock keeper
	mockKeeper := MockKeeper{}

