// Msg represents a message in the message queue system.
type Msg struct {
	Id      int
	Topic   string
	MsgType int
	Payload string
}

// MsgToBytes serializes the Msg struct into a slice of bytes.
func MsgToBytes(msg Msg) ([]byte, error) {
	var buf bytes.Buffer
	enc := gob.NewEncoder(&buf)
	err := enc.Encode(msg)
	if err != nil {
		return nil, err
	}
	return buf.Bytes(), nil
}

// BytesToMsg deserializes a slice of bytes back into a Msg struct.
func BytesToMsg(data []byte) (Msg, error) {
	var msg Msg
	buf := bytes.NewBuffer(data)
	dec := gob.NewDecoder(buf)
	err := dec.Decode(&msg)
	if err != nil {
		return Msg{}, err
	}
	return msg, nil
}

func main() {
	// Producer code
	conn, err := net.Dial("tcp", "127.0.0.1:12345")
	if err != nil {
		fmt.Println("connect failed, err:", err)
		return
	}
	defer conn.Close()

	msg := Msg{Id: 1102, Topic: "topic-test", MsgType: 2, Payload: "Hello World"}
	msgBytes, err := MsgToBytes(msg)
	if err != nil {
		fmt.Println("serialization failed, err:", err)
		return
	}

	n, err := conn.Write(msgBytes)
	if err != nil {
		fmt.Println("write failed, err:", err)
		return
	}

	fmt.Println("Bytes sent:", n)

	// Broker code (for demonstration purposes, this would be in a separate program)
	// Assuming `msgBytes` is the byte slice received from the producer over TCP
	receivedMsg, err := BytesToMsg(msgBytes)
	if err != nil {
		fmt.Println("deserialization failed, err:", err)
		return
	}

	fmt.Printf("Received message: %+v\n", receivedMsg)
}

