// reverseWordsInSentence takes a string sentence and returns a new string with each word reversed.
func reverseWordsInSentence(sentence string) string {
	if len(sentence) == 0 {
		return sentence
	}

	words := strings.Split(sentence, " ")
	var reversedWords []string
	for _, word := range words {
		reversedWord := []byte(word)
		for i := 0; i < len(reversedWord)/2; i++ {
			reversedWord[i], reversedWord[len(reversedWord)-i-1] = reversedWord[len(reversedWord)-i-1], reversedWord[i]
		}
		reversedWords = append(reversedWords, string(reversedWord))
	}

	return strings.Join(reversedWords, " ")
}

func main() {
	// Test cases to verify the solution correctness
	testCases := []struct {
		input    string
		expected string
	}{
		{"Hello World", "olleH dlroW"},
		{"The quick brown fox", "ehT kciuq nworb xof"},
