		{"", ""},
		{"Single", "elgniS"},
	}

	for _, testCase := range testCases {
		result := reverseWordsInSentence(testCase.input)
		fmt.Printf("reverseWordsInSentence(%q) = %q (expected: %q)\n", testCase.input, result, testCase.expected)
