// Mock database for storing releases, builds, and artifacts.
var (
	releasesDB = make(map[string]*Release)
	buildsDB   = make(map[string]*Build)
	artifactsDB = make(map[string]*Artifact)
	mu         sync.RWMutex
)

// Release represents a software release.
type Release struct {
	Id           string
	Status       Status
	BuildId      string
	ArtifactId   string
	Application  string
}

// Build represents a software build.
type Build struct {
	Id          string
	Application string
}

// Artifact represents a software artifact.
type Artifact struct {
	Id          string
	BuildId     string
}

// Status represents the status of a release.
type Status int

const (
	UNKNOWN Status = iota
	PENDING
	RUNNING
	SUCCESS
	FAILED
)

// ReleaseService provides operations for managing releases.
type ReleaseService struct{}

// UpsertRelease creates or updates a release.
func (s *ReleaseService) UpsertRelease(ctx context.Context, release *Release) (*Release, error) {
	mu.Lock()
	defer mu.Unlock()

	if release.Id == "" {
		// Create new release with a unique ID.
		release.Id = fmt.Sprintf("release-%d", len(releasesDB)+1)
		releasesDB[release.Id] = release
	} else {
		// Update existing release.
		if _, exists := releasesDB[release.Id]; !exists {
			return nil, status.Errorf(codes.NotFound, "release with ID '%s' not found", release.Id)
		}
		releasesDB[release.Id] = release
	}

	return release, nil
}

// GetRelease retrieves a release by its ID.
func (s *ReleaseService) GetRelease(ctx context.Context, id string) (*Release, error) {
	mu.RLock()
	defer mu.RUnlock()

	release, exists := releasesDB[id]
	if !exists {
		return nil, status.Errorf(codes.NotFound, "release with ID '%s' not found", id)
	}

	return release, nil
}

// ListReleases lists all releases for a given application.
func (s *ReleaseService) ListReleases(ctx context.Context, application string) ([]*Release, error) {
	mu.RLock()
	defer mu.RUnlock()

	var releases []*Release
	for _, release := range releasesDB {
		if release.Application == application {
			releases = append(releases, release)
		}
	}

	return releases, nil
}

func main() {
	// Create a new release service.
	service := &ReleaseService{}

	// Context for the operations.
	ctx := context.Background()

	// Test cases.
