	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Println("Created release:", release1)
	}

	release2, err := service.UpsertRelease(ctx, &Release{Id: release1.Id, Status: RUNNING, Application: "app1"})
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Println("Updated release:", release2)
	}

