	"encoding/hex"
	"fmt"
	"log"
	"os"
	"strings"
	"time"
)

type Block struct {
	ID        int
	Timestamp string
	Data      string
	PrevHash  string
}

func (b *Block) Hash() string {
	record := fmt.Sprintf("%d%s%s%s", b.ID, b.Timestamp, b.Data, b.PrevHash)
	h := sha256.New()
	h.Write([]byte(record))
	hashed := h.Sum(nil)
	return hex.EncodeToString(hashed)
}

type Blockchain struct {
	Chain []*Block
}

func NewBlockchain() *Blockchain {
	return &Blockchain{Chain: []*Block{NewGenesisBlock()}}
}

func NewGenesisBlock() *Block {
	return NewBlock(0, "Genesis Block", "")
}

func NewBlock(ID int, data, prevHash string) *Block {
	return &Block{
		ID:        ID,
		Timestamp: time.Now().Format(time.RFC3339),
		Data:      data,
		PrevHash:  prevHash,
	}
}

func (bc *Blockchain) AddBlock(data string) {
	prevBlock := bc.Chain[len(bc.Chain)-1]
	newBlock := NewBlock(prevBlock.ID+1, data, prevBlock.Hash())
	bc.Chain = append(bc.Chain, newBlock)
}

func main() {
	reader := bufio.NewReader(os.Stdin)
	bc := NewBlockchain()

	fmt.Print("Available commands: query, execute, state, help, exit\n")
	var running = true
	for running {
		fmt.Print("> ")
		input, _ := reader.ReadString('\n')
		input = strings.TrimSpace(input)
		args := strings.SplitN(input, " ", 2)
		command := args[0]

		switch command {
		case "help":
			fmt.Println(
				"Commands:\n" +
					"  query \"<sql select query>\" - sends a query to the blockchain database, prints the output.\n" +
					"  execute \"<sql statement>\" - executes an SQL transaction that changes the blockchain database.\n" +
					"  state - prints the current blockchain state.\n" +
					"  help - prints this help message.\n" +
					"  exit - exits the application.\n")

		case "state":
			fmt.Println("Block ID | Timestamp           | Previous Hash        | Block Hash")
			for _, block := range bc.Chain {
				fmt.Printf("%8d | %19s | %20s | %s\n", block.ID, block.Timestamp, block.PrevHash, block.Hash())
			}

		case "query":
			if len(args) != 2 {
				fmt.Println("Error: query command requires an argument.")
				break
			}
			query := args[1]
			fmt.Printf("Executing query: %s\n", query)
			// Here you would add logic to handle the query against the blockchain data.

		case "execute":
			if len(args) != 2 {
				fmt.Println("Error: execute command requires an argument.")
				break
			}
			statement := args[1]
			fmt.Printf("Executing statement: %s\n", statement)
			bc.AddBlock(statement)

		case "exit":
			running = false

		default:
			fmt.Println("Unknown command. Type 'help' for a list of commands.")
		}
	}
}
