func (asm *Asm) Byte(b byte) {
	asm.code = append(asm.code, b)
}

func (asm *Asm) Bytes(bs ...byte) {
	asm.code = append(asm.code, bs...)
}

func (asm *Asm) Int8(i int8) {
	asm.code = append(asm.code, byte(i))
}

func (asm *Asm) Int32(i int32) {
	asm.code = append(asm.code, byte(i), byte(i>>8), byte(i>>16), byte(i>>24))
}

func (asm *Asm) AddJump(addr uintptr) {
	asm.jumps = append(asm.jumps, addr)
}

func (asm *Asm) Code() []byte {
	return asm.code
}

// Implement the operations.
func (asm *Asm) Op1(op Op1, dst interface{}) {
	switch dst := dst.(type) {
	case Reg:
		asm.op1Reg(op, dst)
	case Mem:
		asm.op1Mem(op, dst)
	default:
		errorf("unsupported destination type %T, expecting Reg or Mem", dst)
	}
}

