// rowWiseTraversal traverses a 2D matrix row by row and returns the sum of all elements.
func rowWiseTraversal(matrix [][]int) int {
	sum := 0
	for _, row := range matrix {
		for _, value := range row {
			sum += value
		}
	}
	return sum
}

// columnWiseTraversal traverses a 2D matrix column by column and returns the sum of all elements.
func columnWiseTraversal(matrix [][]int) int {
	if len(matrix) == 0 {
		return 0
	}
	sum := 0
	for col := 0; col < len(matrix[0]); col++ {
		for row := 0; row < len(matrix); row++ {
			sum += matrix[row][col]
		}
	}
	return sum
}

// Benchmark tests for rowWiseTraversal and columnWiseTraversal functions.
func BenchmarkRowWiseTraversal(b *testing.B) {
	matrix := [][]int{
		{1, 2, 3},
		{4, 5, 6},
		{7, 8, 9},
	}
	var result int
	for i := 0; i < b.N; i++ {
		result = rowWiseTraversal(matrix)
	}
	_ = result // to avoid compiler optimization
}

func BenchmarkColumnWiseTraversal(b *testing.B) {
	matrix := [][]int{
		{1, 2, 3},
		{4, 5, 6},
		{7, 8, 9},
	}
	var result int
	for i := 0; i < b.N; i++ {
		result = columnWiseTraversal(matrix)
	}
	_ = result // to avoid compiler optimization
}

// Test cases to verify the correctness of the solution.
func TestRowWiseTraversal(t *testing.T) {
	matrix := [][]int{
		{1, 2, 3},
		{4, 5, 6},
		{7, 8, 9},
	}
	expectedSum := 45
	actualSum := rowWiseTraversal(matrix)
	if actualSum != expectedSum {
		t.Errorf("Expected sum of %d, but got %d", expectedSum, actualSum)
	}
}

func TestColumnWiseTraversal(t *testing.T) {
	matrix := [][]int{
		{1, 2, 3},
		{4, 5, 6},
		{7, 8, 9},
	}
	expectedSum := 45
	actualSum := columnWiseTraversal(matrix)
	if actualSum != expectedSum {
		t.Errorf("Expected sum of %d, but got %d", expectedSum, actualSum)
	}
}
