package main

import (
	"fmt"
	"sort"
)

func PurchasePlans(nums []int, target int) int {
	sort.Ints(nums)
	var l, r = 0, len(nums) - 1
	var res = 0
	for l < r {
		if nums[l]+nums[r] > target {
			r--
			continue
		}
		res += (r - l)
		l++
	}
	return res % 1000000007
}

func magicTower(nums []int) int {
	sum := 1
	for _, num := range nums {
		sum += num
	}
	if sum <= 0 {
		return -1
	}

	monsters := []int{}
	move := 0
	sum = 1
	isRemove := false
	for i := range nums {
		sum += nums[i]
		if nums[i] < 0 {
			if isRemove {
				monsters[0] = nums[i]
			} else {
				monsters = append(monsters, nums[i])
			}
		}

		if sum <= 0 {
			move++
			sort.Ints(monsters)
			sum -= monsters[0]
			monsters[0] = 0
			isRemove = true
		} else {
			isRemove = false
		}
	}
	return move
}

func main() {
	// Test cases for PurchasePlans
	fmt.Println(PurchasePlans([]int{2, 5, 3, 5}, 6)) // Expected output: 1
	fmt.Println(PurchasePlans([]int{2, 2, 1, 9}, 10)) // Expected output: 4

	// Test cases for magicTower
	fmt.Println(magicTower([]int{100, -250, 200, -100, -100})) // Expected output: 1
	fmt.Println(magicTower([]int{-200, -300, 400, 0}))         // Expected output: -1
}
