func NewWriterWithVersion(f io.Writer, version int) Writer {
	w := &rsfWriter{
		writer:  f,
		version: version,
	}
	if version == Version2 {
		// Write the IndexVersion2 header for version 2
		_, err := f.Write(IndexVersion2)
		if err != nil {
			panic(err) // Handle error appropriately in production code
		}
	}
	return w
