type Issue struct {
	ID          string    `json:"id"`
	Title       string    `json:"title"`
	Description string    `json:"description"`
	CreatedAt   time.Time `json:"createdAt"`
	Status      string    `json:"status"`
}

var (
	issues      = make(map[string]Issue)
	issuesMutex sync.RWMutex
)

func main() {
	fmt.Println("API for Citizen Connect app")
	fmt.Println("Server starting on port 4000")

	r := mux.NewRouter()
	r.HandleFunc("/issues", createIssue).Methods("POST")
	r.HandleFunc("/issues", getIssues).Methods("GET")
	r.HandleFunc("/issues/{id}", getIssueByID).Methods("GET")

	handler := cors.Default().Handler(r)

	log.Fatal(http.ListenAndServe(":4000", handler))
}

func createIssue(w http.ResponseWriter, r *http.Request) {
	var newIssue Issue
	if err := json.NewDecoder(r.Body).Decode(&newIssue); err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}
	newIssue.ID = fmt.Sprintf("%d", time.Now().UnixNano()) // Simple ID generation
	newIssue.CreatedAt = time.Now()
	newIssue.Status = "Open"

	issuesMutex.Lock()
	issues[newIssue.ID] = newIssue
	issuesMutex.Unlock()

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(newIssue)
}

func getIssues(w http.ResponseWriter, r *http.Request) {
	issuesMutex.RLock()
	defer issuesMutex.RUnlock()

	var issueList []Issue
	for _, issue := range issues {
		issueList = append(issueList, issue)
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(issueList)
}

func getIssueByID(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	id := vars["id"]

	issuesMutex.RLock()
	issue, ok := issues[id]
	issuesMutex.RUnlock()

	if !ok {
		http.Error(w, "Issue not found", http.StatusNotFound)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(issue)
}

// Test cases to verify the solution correctness
func mainTest() {
	// Test case 1: Create a new issue
	issue := Issue{
		Title:       "Pothole on Main Street",
		Description: "A large pothole has appeared on Main Street near the intersection with First Avenue.",
		Status:      "Open",
	}
	issues[issue.ID] = issue

	// Test case 2: Retrieve all issues
	allIssues := []Issue{}
	for _, issue := range issues {
		allIssues = append(allIssues, issue)
	}

	// Test case 3: Retrieve a single issue by ID
	singleIssue, exists := issues[issue.ID]
	if !exists {
		log.Fatal("Issue not found")
	}

	fmt.Printf("Test case 1: %+v\n", issue)
	fmt.Printf("Test case 2: %+v\n", allIssues)
	fmt.Printf("Test case 3: %+v\n", singleIssue)
