func NewECSTaskDefinitionManager(sess *session.Session) *ECSTaskDefinitionManager {
	return &ECSTaskDefinitionManager{
		svc: ecs.New(sess),
	}
}

func (manager *ECSTaskDefinitionManager) ListTaskDefinitions() ([]string, error) {
	var taskDefinitionARNs []string
	params := &ecs.ListTaskDefinitionsInput{
		MaxResults: aws.Int64(100),
	}

	for {
		output, err := manager.svc.ListTaskDefinitions(params)
		if err != nil {
			return nil, err
		}

		for _, taskDefinitionARN := range output.TaskDefinitionArns {
			taskDefinitionARNs = append(taskDefinitionARNs, *taskDefinitionARN)
		}

		if output.NextToken == nil {
			break
		}

		params.NextToken = output.NextToken
	}

	return taskDefinitionARNs, nil
}

func (manager *ECSTaskDefinitionManager) DeregisterTaskDefinition(arn string) error {
	_, err := manager.svc.DeregisterTaskDefinition(&ecs.DeregisterTaskDefinitionInput{
		TaskDefinition: aws.String(arn),
	})
	return err
}

