import (
	"bufio"
	"fmt"
	"io"
	"strconv"
	"sync"
)

func main() {
	sum, err := runPipeline()
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Println("Sum:", sum)
	}
}

// runPipeline sets up and runs the data pipeline, returning the sum of integers or an error.
func runPipeline() (int, error) {
	var (
		wg   sync.WaitGroup
		errs = make(chan error, 2)
		sum  int
	)

	pr, pw := io.Pipe()

	// Producer goroutine
	wg.Add(1)
	go func() {
		defer wg.Done()
		defer pw.Close()

		for i := 1; i <= 10; i++ {
			_, err := pw.Write([]byte(strconv.Itoa(i) + "\n"))
			if err != nil {
				errs <- err
				return
			}
		}
	}()

	// Consumer goroutine
	wg.Add(1)
	go func() {
		defer wg.Done()

		scanner := bufio.NewScanner(pr)
		for scanner.Scan() {
			value, err := strconv.Atoi(scanner.Text())
			if err != nil {
				errs <- err
				return
			}
			sum += value
		}

		if err := scanner.Err(); err != nil {
			errs <- err
		}
	}()

	// Wait for the producer and consumer to finish
	wg.Wait()

	close(errs)
	for e := range errs {
		return 0, e
	}

	return sum, nil
}
