package main

import (
	"encoding/csv"
	"fmt"
	"os"
	"strconv"
)

type Ident int

// shouldKeep determines whether an item should be kept based on the selection and inversion flags.
func shouldKeep(selected, invert bool) bool {
	if invert {
		return !selected
	}
	return selected
}

// filterIds filters identifiers based on a selection map and an inversion flag.
func filterIds(dst, src []Ident, selected map[Ident]struct{}, invert bool) []Ident {
	var filtered []Ident
	for _, id := range src {
		_, isSelected := selected[id]
		if shouldKeep(isSelected, invert) {
			filtered = append(filtered, id)
		}
	}
	return filtered
}

// Filter reads a matrix from the source path, filters it, and writes the result to the destination path.
func Filter(dstPath, srcPath string, rowIdsSelected, colIdsSelected []Ident, rowsInverted, colsInverted bool) error {
	srcFile, err := os.Open(srcPath)
	if err != nil {
		return err
	}
	defer srcFile.Close()

	reader := csv.NewReader(srcFile)
	srcMatrix, err := reader.ReadAll()
	if err != nil {
		return err
	}

	rowsSelected := make(map[Ident]struct{}, len(rowIdsSelected))
	colsSelected := make(map[Ident]struct{}, len(colIdsSelected))
	for _, id := range rowIdsSelected {
		rowsSelected[id] = struct{}{}
	}
	for _, id := range colIdsSelected {
		colsSelected[id] = struct{}{}
	}

	filteredRowIds := filterIds(rowIdsSelected, makeRange(0, len(srcMatrix)), rowsSelected, rowsInverted)
	filteredColIds := filterIds(colIdsSelected, makeRange(0, len(srcMatrix[0])), colsSelected, colsInverted)

	dstMatrix := make([][]string, len(filteredRowIds))
	for i, rowIdx := range filteredRowIds {
		dstMatrix[i] = make([]string, len(filteredColIds))
		for j, colIdx := range filteredColIds {
			dstMatrix[i][j] = srcMatrix[rowIdx][colIdx]
		}
	}

	dstFile, err := os.Create(dstPath)
	if err != nil {
		return err
	}
	defer dstFile.Close()

	writer := csv.NewWriter(dstFile)
	err = writer.WriteAll(dstMatrix)
	if err != nil {
		return err
	}

	return nil
}

// makeRange creates a slice of Ident values from start to end (exclusive).
func makeRange(start, end int) []Ident {
	var rangeSlice []Ident
	for i := start; i < end; i++ {
		rangeSlice = append(rangeSlice, Ident(i))
	}
	return rangeSlice
}

func main() {
	// Example usage of the Filter function
	dstPath := "filtered_matrix.csv"
	srcPath := "source_matrix.csv"
	rowIdsSelected := []Ident{1, 3} // Rows to include or exclude
	colIdsSelected := []Ident{0, 2} // Columns to include or exclude
	rowsInverted := false            // Include selected rows
	colsInverted := true             // Exclude selected columns

	err := Filter(dstPath, srcPath, rowIdsSelected, colIdsSelected, rowsInverted, colsInverted)
	if err != nil {
		fmt.Printf("Error filtering matrix: %s\n", err)
	} else {
		fmt.Println("Matrix filtered successfully.")
	}
}
