// StringInSlice tests whether the given string is contained in slice of strings.
func StringInSlice(a string, list []string) bool {
	for _, b := range list {
		if b == a {
			return true
		}
	}
	return false
}

// Index finds the given key in the slice. It returns the index and a bool indicating if the key was found.
func Index(key string, list []string) (int, bool) {
	for i, item := range list {
		if item == key {
			return i, true
		}
	}
	return -1, false
}

// UniqueStrings returns a slice of unique strings, preserving the order of first occurrence.
func UniqueStrings(list []string) []string {
	unique := make([]string, 0, len(list))
	seen := make(map[string]struct{})
	for _, item := range list {
		if _, ok := seen[item]; !ok {
			seen[item] = struct{}{}
			unique = append(unique, item)
		}
	}
	return unique
}

// Test cases to verify the correctness of the functions.
func main() {
	sampleList := []string{"apple", "banana", "apple", "orange", "banana", "kiwi"}

	// Test StringInSlice
	fmt.Println(StringInSlice("apple", sampleList)) // Expected: true
	fmt.Println(StringInSlice("grape", sampleList)) // Expected: false

	// Test Index
	if index, found := Index("orange", sampleList); found {
		fmt.Printf("Found 'orange' at index: %d\n", index) // Expected: Found 'orange' at index: 3
