	fmt.Printf("Running command: %s %s\n", command, strings.Join(args, " "))
	return nil
}

func openCmd(targetDir string) *cobra.Command {
	cmd := &cobra.Command{
		Use:   "open [COMMAND]",
		Short: "Open a directory or run a command with the directory.",
		Long: `Opens the specified directory with the system's default file explorer or runs a command with the directory as an argument. 
If '%s' is present in the command, it will be replaced with the directory path.`,
		Args: cobra.ArbitraryArgs,
		RunE: func(cmd *cobra.Command, args []string) error {
			if len(args) == 0 {
				return open.Run(targetDir)
			}

			runcmd := []string{}
			replaced := false
			for _, a := range args {
				if strings.Contains(a, "%s") {
					replaced = true
					runcmd = append(runcmd, strings.ReplaceAll(a, "%s", targetDir))
				} else {
					runcmd = append(runcmd, a)
				}
			}

			if !replaced {
				runcmd = append(runcmd, targetDir)
			}

			return RunCmd(runcmd[0], runcmd[1:]...)
		},
	}

	return cmd
}

func main() {
	if len(os.Args) < 2 {
		fmt.Println("Error: No directory specified.")
		os.Exit(1)
	}
	targetDir := os.Args[1]

	rootCmd := openCmd(targetDir)
	if err := rootCmd.Execute(); err != nil {
		fmt.Println(err)
		os.Exit(1)
	}
}
