package secureRandom

import (
	cryptoRand "crypto/rand"
	mathRand "math/rand"
	"encoding/binary"
	"reflect"
)

// Reader is the standard crypto/rand.Reader, re-exported for convenience.
var Reader = cryptoRand.Reader

// randomCharset contains the characters that can make up a secureRandom.String().
const randomCharset = "2345679abcdefghijkmnopqrstuvwxyzACDEFGHJKLMNPQRSTUVWXYZ"

type secureSource struct{}

func (s *secureSource) Int63() int64 {
	var b [8]byte
	_, err := cryptoRand.Read(b[:])
	if err != nil {
		panic(err)
	}
	// Mask off the sign bit to ensure we return a non-negative int64
	return int64(binary.BigEndian.Uint64(b[:]) & ^uint64(1<<63))
}

func (s *secureSource) Seed(seed int64) {
	// Not needed for crypto/rand, but must be implemented to satisfy the Source interface
}

func (s *secureSource) Uint64() uint64 {
	var b [8]byte
	_, err := cryptoRand.Read(b[:])
	if err != nil {
		panic(err)
	}
	return binary.BigEndian.Uint64(b[:])
}

var (
	// defaultSecureSource is a concurrency-safe, cryptographically secure math/rand.Source.
	defaultSecureSource = &secureSource{}

	// defaultSecureRand is a math/rand.Rand based on the secure source.
	defaultSecureRand = mathRand.New(defaultSecureSource)
)

// String returns a cryptographically secure random string of characters
// (taken from randomCharset) of the specified length.
func String(length int) string {
	bs := make([]byte, length)
	for i := range bs {
		bs[i] = randomCharset[defaultSecureRand.Intn(len(randomCharset))]
	}
	return string(bs)
}

// Int63 returns a cryptographically secure random int63.
func Int63() int64 {
	return defaultSecureSource.Int63()
}

// Uint64 returns a cryptographically secure random uint64.
func Uint64() uint64 {
	return defaultSecureSource.Uint64()
}

// Intn returns, as an int, a cryptographically secure non-negative
// random number in [0,n). It panics if n <= 0.
func Intn(n int) int {
	if n <= 0 {
		panic("argument to Intn is not positive")
	}
	return defaultSecureRand.Intn(n)
}

// Shuffle the order of elements in slice in a cryptographically secure manner.
func Shuffle(slice interface{}) {
	rv := reflect.ValueOf(slice)
	swap := reflect.Swapper(slice)
	length := rv.Len()
	if length < 2 {
		return
	}
	defaultSecureRand.Shuffle(length, swap)
}

// Test cases to verify the correctness of the solution
func main() {
	// Test String function
	randomStr := String(10)
	println("Random String:", randomStr)

	// Test Int63 function
	randomInt63 := Int63()
	println("Random Int63:", randomInt63)

	// Test Uint64 function
	randomUint64 := Uint64()
	println("Random Uint64:", randomUint64)

	// Test Intn function
	randomIntn := Intn(100)
	println("Random Intn:", randomIntn)

	// Test Shuffle function
	intSlice := []int{1, 2, 3, 4, 5}
	Shuffle(intSlice)
	println("Shuffled Slice:", intSlice)
}
