	"github.com/copernet/copernicus/peer"
	"github.com/stretchr/testify/assert"
)

// MockServer represents a mock P2P server.
type MockServer struct {
	peerCount int
	peers     map[string]*peer.Peer
	mtx       sync.Mutex
}

// NewMockServer creates a new instance of MockServer.
func NewMockServer() *MockServer {
	return &MockServer{
		peers: make(map[string]*peer.Peer),
	}
}

// AddPeer simulates adding a new peer to the server.
func (s *MockServer) AddPeer(p *peer.Peer) {
	s.mtx.Lock()
	defer s.mtx.Unlock()
	s.peers[p.Addr()] = p
	s.peerCount++
}

// RemovePeer simulates removing a peer from the server.
func (s *MockServer) RemovePeer(addr string) {
	s.mtx.Lock()
	defer s.mtx.Unlock()
	delete(s.peers, addr)
	s.peerCount--
}

// PeerCount returns the number of connected peers.
func (s *MockServer) PeerCount() int {
	s.mtx.Lock()
	defer s.mtx.Unlock()
	return s.peerCount
}

// HandleMessage processes incoming P2P messages.
func (s *MockServer) HandleMessage(msg wire.Message, p *peer.Peer) (wire.Message, error) {
	switch msg.Command() {
	case wire.CmdPing:
		// Respond with Pong message
		return wire.NewMsgPong(msg.(*wire.MsgPing).Nonce), nil
	case wire.CmdPong:
		// No response needed for Pong message
		return nil, nil
	case wire.CmdVersion:
		// Respond with VerAck message
		return wire.NewMsgVerAck(), nil
	case wire.CmdVerAck:
		// No response needed for VerAck message
		return nil, nil
	default:
		return nil, errors.New("unsupported message type")
	}
}

// GetNetworkInfo returns basic network information.
func (s *MockServer) GetNetworkInfo() map[string]interface{} {
	info := make(map[string]interface{})
	info["protocolVersion"] = wire.ProtocolVersion
	info["peerCount"] = s.PeerCount()
	return info
}

// Test cases to verify the solution correctness.
func TestMockServer(t *testing.T) {
	server := NewMockServer()

	// Test adding and removing peers
	server.AddPeer(peer.NewOutboundPeer(nil, "127.0.0.1:8333", false))
	server.AddPeer(peer.NewOutboundPeer(nil, "127.0.0.2:8333", false))
	assert.Equal(t, 2, server.PeerCount(), "Expected 2 peers to be connected")

	server.RemovePeer("127.0.0.1:8333")
	assert.Equal(t, 1, server.PeerCount(), "Expected 1 peer to be connected after removal")

	// Test handling messages
	ping := wire.NewMsgPing(123)
	pong, err := server.HandleMessage(ping, nil)
	assert.Nil(t, err, "Expected no error for MsgPing")
	assert.NotNil(t, pong, "Expected a MsgPong response")
	assert.Equal(t, wire.CmdPong, pong.Command(), "Expected a Pong message in response to Ping")

	verack, err := server.HandleMessage(wire.NewMsgVersion(nil, nil, 0, 0), nil)
	assert.Nil(t, err, "Expected no error for MsgVersion")
	assert.NotNil(t, verack, "Expected a MsgVerAck response")
	assert.Equal(t, wire.CmdVerAck, verack.Command(), "Expected a VerAck message in response to Version")

	_, err = server.HandleMessage(wire.NewMsgVerAck(), nil)
	assert.Nil(t, err, "Expected no error for MsgVerAck")

	// Test getting network info
	networkInfo := server.GetNetworkInfo()
	assert.Equal(t, wire.ProtocolVersion, networkInfo["protocolVersion"], "Expected correct protocol version")
	assert.Equal(t, 1, networkInfo["peerCount"], "Expected correct peer count")
}
