package main

import (
	"fmt"
	"math"
	"sort"
	"strings"
)

// text represents a block of text with multiple lines.
type text struct {
	lines []string
}

// searchMonth searches for the first occurrence of any month name within a string.
func searchMonth(s string, months []string) int {
	for i, month := range months {
		if strings.Contains(s, month) {
			return i
		}
	}
	return -1
}

// getNumber extracts the first numerical value found in a string.
func getNumber(line string) float64 {
	num := 0.0
	gotPoint := false
	digitsAfterPoint := 1.0
	for _, char := range line {
		if !gotPoint && char == '.' {
			gotPoint = true
		}
		if char >= '0' && char <= '9' {
			if gotPoint {
				num = num + float64(char-'0')/math.Pow(10, digitsAfterPoint)
				digitsAfterPoint++
			} else {
				num = num*10 + float64(char-'0')
			}
		}
	}
	return num
}

// reverse reverses the order of lines in the text.
func (t *text) reverse() {
	tLen := len(t.lines) - 1
	for i := 0; i <= tLen/2; i++ {
		t.lines[i], t.lines[tLen-i] = t.lines[tLen-i], t.lines[i]
	}
}

// isSorted determines if the lines in the text are sorted in ascending order.
func (t *text) isSorted() bool {
	return sort.StringsAreSorted(t.lines)
}

// removeDuplicates removes duplicate lines from the text.
func (t *text) removeDuplicates() {
	m := make(map[string]struct{})
	uniqueLines := []string{}
	for _, line := range t.lines {
		if _, found := m[line]; !found {
			uniqueLines = append(uniqueLines, line)
			m[line] = struct{}{}
		}
	}
	t.lines = uniqueLines
}

// removeTailSpaces removes trailing spaces from each line in the text.
func (t *text) removeTailSpaces() {
	for i, line := range t.lines {
		t.lines[i] = strings.TrimRight(line, " ")
	}
}

// getHelp displays a help message describing the available commands.
func getHelp() {
	fmt.Println(
		"-k — specify the column for sorting (words in a line can be used as columns, default delimiter is space)\n" +
			"-n — sort by numerical value\n" +
			"-r — sort in reverse order\n" +
			"-u — do not output duplicate lines\n" +
			"-M — sort by month name\n" +
			"-b — ignore trailing spaces\n" +
			"-c — check if the data is sorted")
}

// executeCommands parses and executes a series of commands on the text.
func (t *text) executeCommands(commands string) {
	for _, cmd := range commands {
		switch cmd {
		case 'r':
			t.reverse()
		case 'u':
			t.removeDuplicates()
		case 'b':
			t.removeTailSpaces()
		case 'c':
			fmt.Println("Is sorted:", t.isSorted())
		case 'h':
			getHelp()
		}
	}
}

func main() {
	// Example usage:
	txt := text{
		lines: []string{
			"April is the 4th month",
			"January is the 1st month",
			"February is the 2nd month",
			"March is the 3rd month",
			"January is the 1st month   ",
		},
	}

	// Execute a series of commands on the text.
	txt.executeCommands("rubc")

	// Print the modified text.
	for _, line := range txt.lines {
		fmt.Println(line)
	}
}
