}

// NotFound is the error returned when a key or value is not found.
var NotFound = errors.New("not found")

// Memtable represents an in-memory key-value store with map-like semantics.
type Memtable struct {
	sync.RWMutex
	keyMap map[string][]MapPair
}

// NewMemtable creates a new Memtable instance.
func NewMemtable() *Memtable {
	return &Memtable{
		keyMap: make(map[string][]MapPair),
	}
}

// Set associates the given value with the specified key.
func (m *Memtable) Set(key []byte, value MapPair) {
	m.Lock()
	defer m.Unlock()

	strKey := string(key)
	m.keyMap[strKey] = append(m.keyMap[strKey], value)
}

// Get retrieves all values associated with the specified key.
func (m *Memtable) Get(key []byte) ([]MapPair, error) {
	m.RLock()
	defer m.RUnlock()

	strKey := string(key)
	values, exists := m.keyMap[strKey]
	if !exists {
		return nil, NotFound
	}
	return values, nil
}

// Delete removes the specified value from the list of values associated with the given key.
func (m *Memtable) Delete(key []byte, value MapPair) error {
	m.Lock()
	defer m.Unlock()

	strKey := string(key)
	values, exists := m.keyMap[strKey]
	if !exists {
		return NotFound
	}

	for i, pair := range values {
		if bytes.Equal(pair.Key, value.Key) && bytes.Equal(pair.Value, value.Value) {
			m.keyMap[strKey] = append(values[:i], values[i+1:]...)
			return nil
		}
	}

	return NotFound
}

// CursorMap is the interface for iterating over key-value pairs.
type CursorMap interface {
	First() ([]byte, []MapPair, error)
	Next() ([]byte, []MapPair, error)
	Seek(key []byte) ([]byte, []MapPair, error)
}

// memtableCursorMap implements the CursorMap interface for Memtable.
type memtableCursorMap struct {
	data    []MapPair
	current int
	lock    func()
	unlock  func()
}

// Cursor returns a cursor for iterating over the key-value pairs.
func (m *Memtable) Cursor() CursorMap {
	m.RLock()
	defer m.RUnlock()

	var data []MapPair
	for _, pairs := range m.keyMap {
		data = append(data, pairs...)
	}

	return &memtableCursorMap{
		data:   data,
		lock:   m.RLock,
		unlock: m.RUnlock,
	}
}

// First moves the cursor to the first key-value pair and returns it.
func (c *memtableCursorMap) First() ([]byte, []MapPair, error) {
	c.lock()
	defer c.unlock()

	if len(c.data) == 0 {
		return nil, nil, NotFound
	}

	c.current = 0
	return c.data[c.current].Key, []MapPair{c.data[c.current]}, nil
}

// Next moves the cursor to the next key-value pair and returns it.
func (c *memtableCursorMap) Next() ([]byte, []MapPair, error) {
	c.lock()
	defer c.unlock()

	c.current++
	if c.current >= len(c.data) {
		return nil, nil, NotFound
	}

	return c.data[c.current].Key, []MapPair{c.data[c.current]}, nil
}

// Seek moves the cursor to the key-value pair with the specified key or the next larger key.
func (c *memtableCursorMap) Seek(key []byte) ([]byte, []MapPair, error) {
	c.lock()
	defer c.unlock()

	for i, pair := range c.data {
		if bytes.Compare(pair.Key, key) >= 0 {
			c.current = i
			return c.data[c.current].Key, []MapPair{c.data[c.current]}, nil
		}
	}

	return nil, nil, NotFound
}

// Test cases to verify the solution correctness.
func main() {
	memtable := NewMemtable()

	// Set some key-value pairs.
	memtable.Set([]byte("key1"), MapPair{Key: []byte("subkey1"), Value: []byte("value1")})
	memtable.Set([]byte("key1"), MapPair{Key: []byte("subkey2"), Value: []byte("value2")})
	memtable.Set([]byte("key2"), MapPair{Key: []byte("subkey1"), Value: []byte("value3")})

	// Get values for a key.
	values, err := memtable.Get([]byte("key1"))
	if err != nil {
		panic(err)
	}
	for _, pair := range values {
		println(string(pair.Key), string(pair.Value))
	}

	// Delete a value for a key.
	err = memtable.Delete([]byte("key1"), MapPair{Key: []byte("subkey1"), Value: []byte("value1")})
	if err != nil {
		panic(err)
	}

	// Iterate over key-value pairs using a cursor.
	cursor := memtable.Cursor()
	for key, pairs, err := cursor.First(); err == nil; key, pairs, err = cursor.Next() {
		for _, pair := range pairs {
			println(string(key), string(pair.Key), string(pair.Value))
		}
	}
}
