// generateUniqueRandomMatrix creates a matrix with unique random integers.
func generateUniqueRandomMatrix(rows, cols int) [][]int {
	matrix := make([][]int, rows)
	used := make(map[int]bool)
	for i := range matrix {
		matrix[i] = make([]int, cols)
		for j := range matrix[i] {
			var num int
			for {
				num = rand.Intn(rows * cols)
				if !used[num] {
					used[num] = true
					break
				}
			}
			matrix[i][j] = num
		}
	}
	return matrix
}

// findMaxSumRow finds the row with the highest cumulative sum.
func findMaxSumRow(matrix [][]int) (int, int) {
	maxSum := 0
	maxRow := -1
	for i, row := range matrix {
		rowSum := 0
		for _, num := range row {
			rowSum += num
		}
		if rowSum > maxSum {
			maxSum = rowSum
			maxRow = i
		}
	}
	return maxRow, maxSum
}

func main() {
	// Initialize the random number generator
	rand.Seed(time.Now().UnixNano())

	// Define the size of the matrix
	rows := 5
	cols := 10

	// Generate the matrix with unique random integers
	matrix := generateUniqueRandomMatrix(rows, cols)

	// Find the row with the highest cumulative sum
	maxRow, maxSum := findMaxSumRow(matrix)

	// Print the matrix and the row with the highest sum
	fmt.Println("Matrix:")
	for _, row := range matrix {
		fmt.Println(row)
	}
	fmt.Printf("Row with the maximum sum: %d (Sum: %d)\n", maxRow, maxSum)
}

// Test cases to verify the solution correctness
func main() {
	testMatrix := generateUniqueRandomMatrix(3, 3)
	fmt.Println("Test Matrix:")
