func main() {
	reader := bufio.NewReader(os.Stdin)
	n := readNum(reader)
	A := readNNums(reader, n)
	m := readNum(reader)
	B := readNNums(reader, m)
	res := solve(A, B)
	var buf bytes.Buffer
	buf.WriteString(fmt.Sprintf("%d\n", len(res)))
	if len(res) > 0 {
		for i := 0; i < len(res); i++ {
			buf.WriteString(fmt.Sprintf("%d ", res[i]))
		}
		buf.WriteByte('\n')
	}
	fmt.Print(buf.String())
}

// ... (The rest of the helper functions like readInt, readNum, readNNums, etc. are omitted for brevity)

func solve(A []int, B []int) []int {
	L := make([]int, len(B))
	P := make([][]int, len(A))
	PL := make([][]int, len(A))

	for i := range A {
		P[i] = make([]int, len(B))
		PL[i] = make([]int, len(B))
	}

	var ii, jj int
	var ans int

	for i := range A {
		var cur int
		maxJ := -1

		for j := range B {
			if A[i] == B[j] {
				if cur+1 > L[j] {
					L[j] = cur + 1
					P[i][j] = maxJ
					PL[i][j] = L[j]
				}
				if L[j] > ans {
					ans = L[j]
					ii = i
					jj = j
				}
			} else if A[i] > B[j] && cur < L[j] {
				cur = L[j]
				maxJ = j
			}
		}
	}

	var print func(row int, col int, ans int)
	res := make([]int, 0, ans)

	print = func(row int, col int, ans int) {
		if col < 0 || ans == 0 {
			return
		}
		if A[row] == B[col] && PL[row][col] == ans {
			print(row-1, P[row][col], ans-1)
			res = append(res, A[row])
			return
		}
		print(row-1, col, ans)
	}

	if ans == 0 {
		return nil
	}

	print(ii-1, P[ii][jj], ans-1)
	res = append(res, A[ii])

	return res
}

func max(a, b int) int {
	if a >= b {
		return a
	}
	return b
}

func min(a, b int) int {
	if a <= b {
		return a
	}
	return b
}
