package main

import (
	"errors"
	"sync"
)

const (
	// Dialog received 200 response
	DialogStateEstablished = iota
	// Dialog received ACK
	DialogStateConfirmed
	// Dialog received BYE
	DialogStateEnded
)

// DialogStateString maps state to string
func DialogStateString(state int) string {
	switch state {
	case DialogStateEstablished:
		return "established"
	case DialogStateConfirmed:
		return "confirmed"
	case DialogStateEnded:
		return "ended"
	default:
		return "unknown"
	}
}

// Dialog is a data structure representing a dialog
type Dialog struct {
	ID    string // ID created by FROM tag, TO tag, and Call-ID
	State int    // State of dialog. Check more for DialogState... constants
}

// StateString returns string version of state
func (d *Dialog) StateString() string {
	return DialogStateString(d.State)
}

// DialogManager manages multiple dialogs
type DialogManager struct {
	dialogs map[string]*Dialog
	mu      sync.RWMutex
}

// NewDialogManager creates a new DialogManager
func NewDialogManager() *DialogManager {
	return &DialogManager{
		dialogs: make(map[string]*Dialog),
	}
}

// CreateDialog creates a new dialog with the given ID
func (dm *DialogManager) CreateDialog(id string) {
	dm.mu.Lock()
	defer dm.mu.Unlock()
	dm.dialogs[id] = &Dialog{ID: id, State: DialogStateEstablished}
}

// UpdateDialogState updates the state of the dialog with the given ID
func (dm *DialogManager) UpdateDialogState(id string, state int) error {
	dm.mu.Lock()
	defer dm.mu.Unlock()
	dialog, exists := dm.dialogs[id]
	if !exists {
		return errors.New("dialog not found")
	}
	if state < DialogStateEstablished || state > DialogStateEnded {
		return errors.New("invalid state")
	}
	dialog.State = state
	return nil
}

// GetDialogStateString returns the string representation of the dialog's state
func (dm *DialogManager) GetDialogStateString(id string) (string, error) {
	dm.mu.RLock()
	defer dm.mu.RUnlock()
	dialog, exists := dm.dialogs[id]
	if !exists {
		return "", errors.New("dialog not found")
	}
	return dialog.StateString(), nil
}

// EndAllDialogs sets the state of all dialogs to DialogStateEnded
func (dm *DialogManager) EndAllDialogs() {
	dm.mu.Lock()
	defer dm.mu.Unlock()
	for _, dialog := range dm.dialogs {
		dialog.State = DialogStateEnded
	}
}

func main() {
	// Test cases
	dm := NewDialogManager()
	dm.CreateDialog("dialog1")
	dm.CreateDialog("dialog2")

	err := dm.UpdateDialogState("dialog1", DialogStateConfirmed)
	if err != nil {
		panic(err)
	}

	state, err := dm.GetDialogStateString("dialog1")
	if err != nil {
		panic(err)
	}
	println("Dialog1 state:", state)

	dm.EndAllDialogs()
	state, err = dm.GetDialogStateString("dialog2")
	if err != nil {
		panic(err)
	}
	println("Dialog2 state:", state)
}
