// Parser parses Kubernetes objects from given streams and files, ensuring they are namespace-free.
type Parser struct {
	Streams   []io.Reader
	FilePaths []string
}

// NewParser returns a new *Parser.
func NewParser(paths []string, streams ...io.Reader) *Parser {
	return &Parser{
		Streams:   streams,
		FilePaths: paths,
	}
}

// Parse returns an array of *unstructured.Unstructured parsed from the streams and files.
func (p *Parser) Parse() ([]*unstructured.Unstructured, error) {
	var result []*unstructured.Unstructured
	for _, s := range p.Streams {
		u, err := parseStream(s)
		if err != nil {
			return nil, errors.Wrap(err, "cannot parse stream")
		}
		result = append(result, u...)
	}
	for _, path := range p.FilePaths {
		f, err := os.Open(path)
		if err != nil {
			return nil, errors.Wrapf(err, "cannot open file in %s", path)
		}
		defer f.Close()
		u, err := parseStream(f)
		if err != nil {
			return nil, errors.Wrap(err, "cannot parse file stream")
		}
		result = append(result, u...)
	}
	return result, nil
}

func parseStream(in io.Reader) ([]*unstructured.Unstructured, error) {
	dec := yaml.NewYAMLOrJSONDecoder(in, 1024)
	var result []*unstructured.Unstructured
	for {
		u := &unstructured.Unstructured{}
		err := dec.Decode(u)
		if err != nil && err != io.EOF {
			return nil, errors.Wrap(err, "cannot decode yaml into unstructured")
		}
		if err == io.EOF {
			break
		}
		if u.GetAPIVersion() == "" || u.GetKind() == "" {
			continue
		}
		removeNamespace(u)
		result = append(result, u)
	}
	return result, nil
}

func removeNamespace(obj *unstructured.Unstructured) {
	obj.SetNamespace("")
}

