package main

import (
	"context"
	"fmt"
	"sync"
	"time"

	"github.com/pkg/errors"
)

// Node interface represents a task that can be executed.
type Node interface {
	Go(ctx context.Context) error
}

// Config struct defines the configuration for nodes.
type Config struct {
	Node     string
	Parallel []Config
	Sequence []Config
}

// Factory interface is used to create nodes.
type Factory interface {
	Create(name string) (Node, error)
}

// Flow struct represents the flow of tasks.
type Flow struct {
	entrypoint Node
}

// NewFlow creates a new flow based on the given configuration and factory.
func NewFlow(config *Config, factory Factory) (*Flow, error) {
	node, err := createNode(config, factory)
	if err != nil {
		return nil, err
	}
	return &Flow{entrypoint: node}, nil
}

// Go starts the execution of the flow.
func (f *Flow) Go(ctx context.Context) error {
	return f.entrypoint.Go(ctx)
}

// createNode creates nodes based on the configuration and factory.
func createNode(config *Config, factory Factory) (Node, error) {
	switch {
	case len(config.Node) != 0:
		return factory.Create(config.Node)
	case len(config.Parallel) != 0 || len(config.Sequence) != 0:
		configs := config.Parallel
		if len(configs) == 0 {
			configs = config.Sequence
		}

		nodes := make([]Node, 0, len(configs))
		for _, c := range configs {
			node, err := createNode(&c, factory)
			if err != nil {
				return nil, err
			}
			nodes = append(nodes, node)
		}

		if len(config.Parallel) != 0 {
			return &Parallel{nodes: nodes}, nil
		} else {
			return &Sequence{nodes: nodes}, nil
		}
	default:
		return nil, errors.New("empty node")
	}
}

// Parallel struct represents a node that executes its child nodes in parallel.
type Parallel struct {
	nodes []Node
}

// Go executes all child nodes in parallel.
func (p *Parallel) Go(ctx context.Context) error {
	var wg sync.WaitGroup
	errChan := make(chan error, len(p.nodes))

	for _, node := range p.nodes {
		wg.Add(1)
		go func(n Node) {
			defer wg.Done()
			if err := n.Go(ctx); err != nil {
				errChan <- err
			}
		}(node)
	}

	wg.Wait()
	close(errChan)

	for err := range errChan {
		if err != nil {
			return err
		}
	}

	return nil
}

// Sequence struct represents a node that executes its child nodes in sequence.
type Sequence struct {
	nodes []Node
}

// Go executes all child nodes in sequence.
func (s *Sequence) Go(ctx context.Context) error {
	for _, node := range s.nodes {
		if err := node.Go(ctx); err != nil {
			return err
		}
	}
	return nil
}

// Sample implementation of the Factory and Node interfaces.

// SimpleNode represents a simple task.
type SimpleNode struct {
	name string
}

// Go executes the simple task.
func (n *SimpleNode) Go(ctx context.Context) error {
