	time.Sleep(1 * time.Second) // Simulate work
	return nil
}

// SimpleFactory creates SimpleNode instances.
type SimpleFactory struct{}

// Create creates a SimpleNode with the given name.
func (f *SimpleFactory) Create(name string) (Node, error) {
	return &SimpleNode{name: name}, nil
}

