	OrderId      string `json:"order_id"`
	OrderStatus  string `json:"order_status"`
	CancelReason string `json:"cancel_reason,omitempty"`
	CancelFrom   string `json:"cancel_from,omitempty"`
	Signature    string `json:"signature"`
	DmId         string `json:"dm_id"`
	DmName       string `json:"dm_name"`
	DmMobile     string `json:"dm_mobile"`
	UpdateTime   string `json:"update_time"`
}

type OrderNotification2 struct {
	OrderNotification
	UpdateTime int `json:"update_time"`
}

type Client struct{}

func (c *Client) GetOrderNotification(req *http.Request) (notity *OrderNotification, err error) {
	if req == nil {
		return nil, errors.New("request parameter cannot be nil")
	}
	if err = req.ParseForm(); err != nil {
		return nil, err
	}

	notity = &OrderNotification{}
	body, err := ioutil.ReadAll(req.Body)
	if err != nil {
		return nil, err
	}

	if errNotity := json.Unmarshal(body, notity); errNotity != nil {
		notity2 := &OrderNotification2{}
		if errNotity2 := json.Unmarshal(body, notity2); errNotity2 != nil {
			return nil, errNotity2
		}
		notity.UpdateTime = strconv.Itoa(notity2.UpdateTime)
	}

	ok := VerifySign(*notity)
	if !ok {
		return nil, errors.New("signature verification failed")
	}

	return notity, nil
}

func (c *Client) AckNotification(w http.ResponseWriter) {
	AckNotification(w)
}

func AckNotification(w http.ResponseWriter) {
	w.WriteHeader(http.StatusOK)
	w.Write([]byte(`{"status":"ok"}`))
}

func VerifySign(notity OrderNotification) bool {
	keys := []string{notity.UpdateTime, notity.ClientId, notity.OrderId}
	sort.Strings(keys)
	var strParam string
	for _, key := range keys {
		strParam += key
	}
	strParam = MD5(strParam)
	return notity.Signature == strParam
}

func MD5(text string) string {
	hash := md5.Sum([]byte(text))
	return hex.EncodeToString(hash[:])
}

