// LogLevel represents the severity of the log messages.
type LogLevel byte

// Enumeration of log levels with unique byte values.
const (
	LogLevelDebug LogLevel = iota + 1
	LogLevelInfo
	LogLevelWarn
	LogLevelError
	LogLevelFatal
)

// String returns the string representation of the LogLevel.
func (l LogLevel) String() string {
	switch l {
	case LogLevelDebug:
		return "DEBUG"
	case LogLevelInfo:
		return "INFO"
	case LogLevelWarn:
		return "WARN"
	case LogLevelError:
		return "ERROR"
	case LogLevelFatal:
		return "FATAL"
	default:
		return "<unknown>"
	}
}

// MarshalJSON marshals the LogLevel into JSON.
func (l LogLevel) MarshalJSON() ([]byte, error) {
	return json.Marshal(l.String())
}

// UnmarshalJSON unmarshals JSON into a LogLevel.
func (l *LogLevel) UnmarshalJSON(data []byte) error {
	var s string
	if err := json.Unmarshal(data, &s); err != nil {
		return err
	}

	switch s {
	case "DEBUG":
		*l = LogLevelDebug
	case "INFO":
		*l = LogLevelInfo
	case "WARN":
		*l = LogLevelWarn
	case "ERROR":
		*l = LogLevelError
	case "FATAL":
		*l = LogLevelFatal
	default:
		return errors.New("invalid LogLevel")
	}
	return nil
}

// IsValid checks if the byte value is a valid LogLevel.
func (l LogLevel) IsValid() bool {
	switch l {
	case LogLevelDebug, LogLevelInfo, LogLevelWarn, LogLevelError, LogLevelFatal:
		return true
	default:
		return false
	}
}

// FormatLogMessage formats a log message with the given LogLevel and message.
func FormatLogMessage(level LogLevel, message string) string {
	return fmt.Sprintf("[%s] %s", level, message)
}

