	var level LogLevel
	err := json.Unmarshal(debugJSON, &level)
	if err != nil {
		fmt.Println("Error:", err)
	}
	fmt.Println(level.String()) // Output: DEBUG

	// Test IsValid method
	fmt.Println(LogLevel(0).IsValid()) // Output: false
	fmt.Println(LogLevelInfo.IsValid()) // Output: true

	// Test FormatLogMessage function
