package main

import (
	"fmt"
	"net/http"
	"time"
)

// Define the client structure with its configuration fields.
type client struct {
	timeout              time.Duration
	baseURL              string
	baseHeader           http.Header
	errorHandler         ErrorHandler
	beforeRequestHandler BeforeRequestHandler
	afterResponseHandler AfterResponseHandler
}

// Define the types for the handlers.
type ErrorHandler func(error)
type BeforeRequestHandler func(*http.Request)
type AfterResponseHandler func(*http.Response)

// Functional options to configure the client.
func WithTimeout(timeout time.Duration) Option {
	return func(c *client) {
		c.timeout = timeout
	}
}

func WithBaseURL(url string) Option {
	return func(c *client) {
		c.baseURL = url
	}
}

func WithBaseHeader(header http.Header) Option {
	return func(c *client) {
		c.baseHeader = header
	}
}

func WithErrorHandler(handler ErrorHandler) Option {
	return func(c *client) {
		c.errorHandler = handler
	}
}

func WithBeforeRequestHandler(handler BeforeRequestHandler) Option {
	return func(c *client) {
		c.beforeRequestHandler = handler
	}
}

func WithAfterResponseHandler(handler AfterResponseHandler) Option {
	return func(c *client) {
		c.afterResponseHandler = handler
	}
}

// NewClient creates a new client with the given options.
func NewClient(opts ...Option) *client {
	c := &client{}
	for _, opt := range opts {
		opt(c)
	}
	return c
}

// Get makes a GET request to the specified endpoint using the client's configuration.
func (c *client) Get(endpoint string) (*http.Response, error) {
	fullURL := c.baseURL + endpoint
	req, err := http.NewRequest("GET", fullURL, nil)
	if err != nil {
		if c.errorHandler != nil {
			c.errorHandler(err)
		}
		return nil, err
	}

	req.Header = c.baseHeader

	if c.beforeRequestHandler != nil {
		c.beforeRequestHandler(req)
	}

	client := &http.Client{
		Timeout: c.timeout,
	}
	resp, err := client.Do(req)
	if err != nil {
		if c.errorHandler != nil {
			c.errorHandler(err)
		}
		return nil, err
	}

	if c.afterResponseHandler != nil {
		c.afterResponseHandler(resp)
	}

	return resp, nil
}

// Option defines the signature for client options.
type Option func(*client)

// Example usage and test cases.
func main() {
	// Create a new client with a base URL and a timeout.
	c := NewClient(
		WithBaseURL("https://api.example.com"),
		WithTimeout(5*time.Second),
		WithBaseHeader(http.Header{"Content-Type": []string{"application/json"}}),
		WithErrorHandler(func(err error) {
			fmt.Printf("An error occurred: %v\n", err)
		}),
		WithBeforeRequestHandler(func(req *http.Request) {
			fmt.Println("Before request:", req.URL)
		}),
		WithAfterResponseHandler(func(resp *http.Response) {
			fmt.Println("After response:", resp.Status)
		}),
	)

	// Make a GET request to the "/data" endpoint.
	response, err := c.Get("/data")
	if err != nil {
		fmt.Println("Failed to make the GET request:", err)
		return
	}
	defer response.Body.Close()

	// Output the response status code.
	fmt.Println("Response status code:", response.StatusCode)
}
