package jwtbench

import (
	"crypto/rand"
	"crypto/rsa"
	"fmt"
	"testing"

	"github.com/dgrijalva/jwt-go"
)

var result error
var boolResult bool

type testTuple struct {
	rsaPublicKey *rsa.PublicKey
	token        []byte
}

func BenchmarkSigning(b *testing.B) {
	// Generate test matrix
	matrix, err := generateTestMatrix(b.N)
	if err != nil {
		b.Fatal(err)
	}

	// Reset the benchmark timer to exclude setup time
	b.ResetTimer()

	for i := 0; i < b.N; i++ {
		token := jwt.NewWithClaims(jwt.SigningMethodRS256, jwt.MapClaims{
			"aud": "very_fake_audience_claim",
		})
		tokenString, err := token.SignedString(matrix[i].rsaPublicKey)
		if err != nil {
			b.Fatal(err)
		}
		result = err
		_ = tokenString // Use the token string to avoid compiler optimization
	}

	// Avoid compiler optimizations
	result = err
}

func BenchmarkVerifying(b *testing.B) {
	// Generate test matrix
	matrix, err := generateTestMatrix(b.N)
	if err != nil {
		b.Fatal(err)
	}

	// Generate signatures using matrix
	signedTokens := make([]string, b.N)
	for i := 0; i < b.N; i++ {
		token := jwt.NewWithClaims(jwt.SigningMethodRS256, jwt.MapClaims{
			"aud": "very_fake_audience_claim",
		})
		signedTokens[i], err = token.SignedString(matrix[i].rsaPublicKey)
		if err != nil {
			b.Fatal(err)
		}
	}

	// Reset the benchmark timer to exclude setup time
	b.ResetTimer()

	var ok bool
	for i := 0; i < b.N; i++ {
		_, err := jwt.Parse(signedTokens[i], func(token *jwt.Token) (interface{}, error) {
			return matrix[i].rsaPublicKey, nil
		})
		if err != nil {
			b.Fatal(fmt.Errorf("Failed to verify signature: %v", err))
		}
		ok = true
	}

	// Avoid compiler optimizations
	boolResult = ok
}

func generateTestMatrix(n int) ([]testTuple, error) {
	tests := make([]testTuple, n)
	for i := 0; i < n; i++ {
		key, err := rsa.GenerateKey(rand.Reader, 2048)
		if err != nil {
			return nil, err
		}

		jwt, err := createOIDCToken(key, "very_fake_audience_claim")
		if err != nil {
			return nil, err
		}

		tests[i] = testTuple{rsaPublicKey: &key.PublicKey, token: jwt}
	}

	return tests, nil
}

func createOIDCToken(key *rsa.PrivateKey, audience string) ([]byte, error) {
	token := jwt.NewWithClaims(jwt.SigningMethodRS256, jwt.MapClaims{
		"aud": audience,
	})
	return token.SignedString(key)
}
