import (
	"net/http"
	"sync"
)

// Request represents a simple HTTP request with only the method specified.
type Request struct {
	Method string
}

// QueueHttpRequestGenerator is a struct that generates HTTP requests from a queue.
type QueueHttpRequestGenerator struct {
	Requests chan *Request
	done     chan struct{}
	wg       sync.WaitGroup
}

// NewQueueHttpRequestGenerator creates a new instance of QueueHttpRequestGenerator.
func NewQueueHttpRequestGenerator() *QueueHttpRequestGenerator {
	return &QueueHttpRequestGenerator{
		Requests: make(chan *Request, 10),
		done:     make(chan struct{}),
	}
}

// AddRequest adds a new request to the queue.
func (g *QueueHttpRequestGenerator) AddRequest(req *Request) {
	g.wg.Add(1)
	g.Requests <- req
}

// GenRequest retrieves the next request from the queue.
// If the queue is empty and Finish has been called, it returns nil.
func (g *QueueHttpRequestGenerator) GenRequest() *http.Request {
	select {
	case req := <-g.Requests:
		g.wg.Done()
		return &http.Request{Method: req.Method}
	case <-g.done:
		return nil
	}
}

// Finish signals that no more requests will be added to the queue.
func (g *QueueHttpRequestGenerator) Finish() {
	g.wg.Wait()
	close(g.done)
}

// TestQueueHttpRequestGenerator_GenRequest demonstrates the functionality of the QueueHttpRequestGenerator.
func TestQueueHttpRequestGenerator_GenRequest() {
	generator := NewQueueHttpRequestGenerator()

	go func() {
		defer generator.Finish()
		for i := 1; i <= 10; i++ {
			generator.AddRequest(&Request{
				Method: "GET",
			})
		}
	}()

	for {
		request := generator.GenRequest()
		if request == nil {
			break
		}
		println(request.Method)
	}
	println("no more")
}

// This is a simple test case that can be run to verify the solution.
func main() {
	TestQueueHttpRequestGenerator_GenRequest()
}
