package matchers

import (
	"fmt"
	"reflect"
	"testing"
)

// Matcher is a function type that checks if the actual value satisfies a certain condition.
type Matcher func(actual interface{}) (bool, string)

// Assert checks if the actual value satisfies the condition provided by the matcher.
// If the condition is not met, it logs an error message using the testing object.
func Assert(t *testing.T, actual interface{}, matcher Matcher, msg ...string) {
	pass, errMsg := matcher(actual)
	if !pass {
		if len(msg) > 0 {
			t.Errorf("%s\n%s", msg[0], errMsg)
		} else {
			t.Error(errMsg)
		}
	}
}

// IsTrue is a matcher that checks if the actual value is true.
func IsTrue(actual interface{}) (bool, string) {
	if actual == true {
		return true, ""
	}
	return false, fmt.Sprintf("Expected true, but got %v", actual)
}

// IsFalse is a matcher that checks if the actual value is false.
func IsFalse(actual interface{}) (bool, string) {
	if actual == false {
		return true, ""
	}
	return false, fmt.Sprintf("Expected false, but got %v", actual)
}

// IsNil is a matcher that checks if the actual value is nil.
func IsNil(actual interface{}) (bool, string) {
	if actual == nil || reflect.ValueOf(actual).IsNil() {
		return true, ""
	}
	return false, fmt.Sprintf("Expected nil, but got %v", actual)
}

// Equals is a matcher that checks if the actual value is equal to the expected value.
func Equals(expected interface{}) Matcher {
	return func(actual interface{}) (bool, string) {
		if reflect.DeepEqual(expected, actual) {
			return true, ""
		}
		return false, fmt.Sprintf("Expected %v, but got %v", expected, actual)
	}
}

// Not takes a matcher and returns a new matcher with the opposite condition.
func Not(matcher Matcher) Matcher {
	return func(actual interface{}) (bool, string) {
		pass, errMsg := matcher(actual)
		if pass {
			return false, "not " + errMsg
		}
		return true, ""
	}
}

// Example test case using the matchers
func TestMatchers(t *testing.T) {
	Assert(t, true, IsTrue, "True should be true")
	Assert(t, false, IsFalse, "False should be false")
	Assert(t, nil, IsNil, "Nil should be nil")
	Assert(t, 42, Equals(42), "Values should be equal")
	Assert(t, 42, Not(Equals(24)), "Values should not be equal")
}
