	"golang.org/x/tools/go/analysis"
	"golang.org/x/tools/go/analysis/passes/inspect"
	"golang.org/x/tools/go/analysis/singlechecker"
	"golang.org/x/tools/go/ast/inspector"
)

// IfShortenerAnalyzer is the analysis.Analyzer for the IfShortener tool.
var IfShortenerAnalyzer = &analysis.Analyzer{
	Name:     "ifshortener",
	Doc:      "suggests using short variable declaration in if statements",
	Run:      run,
	Requires: []*analysis.Analyzer{inspect.Analyzer},
}

func run(pass *analysis.Pass) (interface{}, error) {
	inspect := pass.ResultOf[inspect.Analyzer].(*inspector.Inspector)

	nodeFilter := []ast.Node{
		(*ast.IfStmt)(nil),
	}

	inspect.Preorder(nodeFilter, func(n ast.Node) {
		ifStmt := n.(*ast.IfStmt)
		if ifStmt.Init == nil && ifStmt.Cond != nil {
			switch cond := ifStmt.Cond.(type) {
			case *ast.BinaryExpr:
				if ident, ok := cond.X.(*ast.Ident); ok {
					obj := pass.TypesInfo.Uses[ident]
					if obj != nil && obj.Pos() < ifStmt.Pos() && obj.Parent() == pass.TypesInfo.Scopes[ifStmt].Outer() {
						pass.Reportf(ifStmt.Pos(), "consider using short variable declaration in if statement")
					}
				}
			}
		}
	})

	return nil, nil
}

func main() {
	singlechecker.Main(IfShortenerAnalyzer)
}

// Test cases to verify the solution correctness.
func testIfShortener(source string) {
	fset := token.NewFileSet()
	file, err := parser.ParseFile(fset, "src.go", source, parser.ParseComments)
	if err != nil {
		fmt.Printf("Failed to parse source: %v\n", err)
		return
	}

	var buf bytes.Buffer
	err = format.Node(&buf, fset, file)
	if err != nil {
		fmt.Printf("Failed to format source: %v\n", err)
		return
	}

	pass := &analysis.Pass{
		Fset:     fset,
		Files:    []*ast.File{file},
		Report:   func(diag analysis.Diagnostic) { fmt.Println(diag.Message) },
		TypesInfo: &types.Info{
			Defs: make(map[*ast.Ident]types.Object),
			Uses: make(map[*ast.Ident]types.Object),
		},
	}

	_, err = run(pass)
	if err != nil {
		fmt.Printf("Error running analysis: %v\n", err)
	}
}

func main() {
	// Test case 1: Should suggest short variable declaration
	testIfShortener(`
package main

func someFunction() int {
	return 42
}

func main() {
	x := someFunction()
	if x > 0 {
		fmt.Println("x is positive")
	}
}
`)

	// Test case 2: Should not suggest short variable declaration (already short)
	testIfShortener(`
package main

