package main

import (
	"context"
	"fmt"
	"github.com/miekg/dns"
	"net"
	"strings"
	"sync"
	"time"
)

// NewBootstrap initializes a custom DNS resolver with a specified upstream DNS server.
func NewBootstrap(s string) *net.Resolver {
	if len(s) == 0 {
		return nil
	}
	// Add port if missing.
	_, _, err := net.SplitHostPort(s)
	if err != nil {
		s = net.JoinHostPort(strings.Trim(s, "[]"), "53")
	}

	bs := newBootstrap(s)

	return &net.Resolver{
		PreferGo:     true,
		StrictErrors: false,
		Dial:         bs.dial,
	}
}

// bootstrap contains the upstream DNS server address and a cache for DNS responses.
type bootstrap struct {
	upstream string
	cache    *cache
}

// newBootstrap creates a new bootstrap instance with the given upstream DNS server.
func newBootstrap(upstream string) *bootstrap {
	return &bootstrap{
		upstream: upstream,
		cache:    newCache(0),
	}
}

// dial creates a custom network connection for DNS queries.
func (b *bootstrap) dial(_ context.Context, _, _ string) (net.Conn, error) {
	c1, c2 := net.Pipe()
	go func() {
		_ = b.handlePipe(c2)
		_ = c2.Close()
	}()
	return c1, nil
}

// handlePipe handles the DNS query and response logic over a net.Conn.
func (b *bootstrap) handlePipe(c net.Conn) error {
	q, _, err := dnsutils.ReadMsgFromTCP(c)
	if err != nil {
		return err
	}

	var resp *dns.Msg
	if len(q.Question) == 1 {
		k := q.Question[0]
		m := b.cache.lookup(k)
		if m != nil {
			resp = m.Copy()
			resp.Id = q.Id
		}
	}

	if resp == nil {
		d := net.Dialer{}
		ctx, cancel := context.WithTimeout(context.Background(), time.Second*2)
		defer cancel()
		upstreamConn, err := d.DialContext(ctx, "udp", b.upstream)
		if err != nil {
			return err
		}
		defer upstreamConn.Close()
		_ = upstreamConn.SetDeadline(time.Now().Add(time.Second * 3))
		if _, err := dnsutils.WriteMsgToUDP(upstreamConn, q); err != nil {
			return err
		}
		m, _, err := dnsutils.ReadMsgFromUDP(upstreamConn, 1500)
		if err != nil {
			return err
		}
		resp = m
	}

	if resp.Rcode == dns.RcodeSuccess && hasIP(resp) {
		if len(resp.Question) == 1 {
			k := resp.Question[0]
			ttl := time.Duration(dnsutils.GetMinimalTTL(resp)) * time.Second
			b.cache.store(k, resp, ttl)
		}
	}

	_, err = dnsutils.WriteMsgToTCP(c, resp)
	return err
}

// hasIP checks if the DNS response contains A or AAAA records.
func hasIP(m *dns.Msg) bool {
	for _, rr := range m.Answer {
		switch rr.Header().Rrtype {
		case dns.TypeA, dns.TypeAAAA:
			return true
		}
	}
	return false
}

// cache is a simple DNS response cache with a FIFO eviction policy.
type cache struct {
	l int

	m sync.Mutex
	c map[key]*elem
}

// elem represents a cached DNS response with an expiration time.
type elem struct {
	m              *dns.Msg
	expirationTime time.Time
}

// key is a DNS question used as a cache key.
type key = dns.Question

// newCache creates a new cache with the specified size.
func newCache(size int) *cache {
	const defaultSize = 8
	if size <= 0 {
		size = defaultSize
	}
	return &cache{
		l: size,
		c: make(map[key]*elem),
	}
}

// lookup returns a cached DNS response if it exists and is not expired.
func (c *cache) lookup(k key) *dns.Msg {
	now := time.Now()
	c.m.Lock()
	defer c.m.Unlock()
	e, ok := c.c[k]
	if !ok {
		return nil
	}
	if e.expirationTime.Before(now) {
		delete(c.c, k)
		return nil
	}
	return e.m
}

// store adds a DNS response to the cache with the specified TTL.
func (c *cache) store(k key, m *dns.Msg, ttl time.Duration) {
	if ttl <= 0 {
		return
	}
	expirationTime := time.Now().Add(ttl)

	c.m.Lock()
	defer c.m.Unlock()

	if len(c.c)+1 > c.l {
		for k := range c.c {
			if len(c.c)+1 <= c.l {
				break
			}
			delete(c.c, k)
		}
	}

	c.c[k] = &elem{
		m:              m,
		expirationTime: expirationTime,
	}
}

// Test cases to verify the solution correctness.
func main() {
	// Initialize the custom DNS resolver with Google's public DNS server.
	resolver := NewBootstrap("8.8.8.8")

	// Perform a DNS query for the domain "example.com".
	ip, err := resolver.LookupHost(context.Background(), "example.com")
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Println("IP addresses for example.com:", ip)
	}

	// Perform another DNS query for the same domain to test caching.
	ip, err = resolver.LookupHost(context.Background(), "example.com")
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Println("Cached IP addresses for example.com:", ip)
	}
}
