	"github.com/aws/aws-sdk-go-v2/aws"
	"github.com/aws/aws-sdk-go-v2/aws/external"
	"github.com/aws/aws-sdk-go-v2/service/s3/s3manager"
	cid "github.com/ipfs/go-cid"
	multihash "github.com/multiformats/go-multihash"
	"github.com/pkg/errors"
	"github.com/rs/zerolog"
	"github.com/rs/zerolog/log"
)

type S3UploaderSettings struct {
	Bucket string
	Prefix string
	Region string
}

type Uploader interface {
	Upload(ctx context.Context, r io.Reader) (link string, err error)
	Close() error
}

type uploader struct {
	bucket        string
	prefix        string
	uploadManager *s3manager.Uploader
	cidBuilder    cid.Builder
}

func New(client *http.Client, settings S3UploaderSettings) (Uploader, error) {
	cfg, err := external.LoadDefaultAWSConfig()
	if err != nil {
		return nil, errors.Wrap(err, "failed to load aws config")
	}
	cfg.Region = settings.Region
	cfg.HTTPClient = client

	uploadManager := s3manager.NewUploader(cfg)
	return &uploader{
		bucket:        settings.Bucket,
		prefix:        settings.Prefix,
		uploadManager: uploadManager,
		cidBuilder:    cid.V1Builder{MhType: multihash.SHA2_256},
	}, nil
}

func (u *uploader) Close() error {
	// Implement any necessary cleanup operations
	return nil
}

func (u *uploader) Upload(ctx context.Context, r io.Reader) (link string, err error) {
	content, err := ioutil.ReadAll(r)
	if err != nil {
		return "", err
	}

	c, err := u.cidBuilder.Sum(content)
	if err != nil {
		return "", err
	}

	key := path.Join(u.prefix, c.String())
	logger := log.With().Str("bucket", u.bucket).Str("key", key).Logger()
	ectx, cancel := context.WithCancel(logger.WithContext(ctx))
	defer cancel()

	go func() {
		select {
		case <-ectx.Done():
			if ectx.Err() == context.Canceled {
				logger.Info().Msg("Upload canceled")
			} else if ectx.Err() == context.DeadlineExceeded {
				logger.Info().Msg("Upload deadline exceeded")
			}
		case <-time.After(20 * time.Second):
			logger.Info().Msg("Uploading S3 object")
		}
	}()

	upParams := &s3manager.UploadInput{
		Bucket: aws.String(u.bucket),
		Key:    aws.String(key),
		Body:   bytes.NewReader(content),
	}

	_, err = u.uploadManager.UploadWithContext(ctx, upParams)
	if err != nil {
		return "", err
	}

	return fmt.Sprintf("s3://%s/%s", u.bucket, key), nil
}

func main() {
	// Example usage of the uploader
	client := &http.Client{}
	settings := S3UploaderSettings{
		Bucket: "my-s3-bucket",
		Prefix: "uploads",
		Region: "us-west-2",
	}

	uploader, err := New(client, settings)
	if err != nil {
		log.Fatal().Err(err).Msg("Failed to create uploader")
	}
	defer uploader.Close()

	fileContent := bytes.NewReader([]byte("file content to upload"))
	ctx := context.Background()
	link, err := uploader.Upload(ctx, fileContent)
	if err != nil {
		log.Fatal().Err(err).Msg("Failed to upload file")
	}

	fmt.Println("Uploaded file link:", link)
}
