package main

import (
	"bytes"
	"encoding/binary"
	"fmt"
	"io"
	"os"
)

const tapBlockMaxLength = 65535

type TAPfileBlockWriter struct {
	buf bytes.Buffer
	wtr io.Writer
}

func NewTAPfileBlockWriter(w io.Writer) *TAPfileBlockWriter {
	return &TAPfileBlockWriter{wtr: w}
}

func (b *TAPfileBlockWriter) Write(p []byte) (int, error) {
	if (len(p) + b.buf.Len()) > int(tapBlockMaxLength-1) {
		return 0, fmt.Errorf("write error: TAP file block is going to become longer than max length of %d", tapBlockMaxLength-1)
	}
	return b.buf.Write(p)
}

func (b *TAPfileBlockWriter) CompleteBlock() error {
	defer b.buf.Reset()
	blockSize := uint16(b.buf.Len() + 1)
	if err := binary.Write(b.wtr, binary.LittleEndian, blockSize); err != nil {
		return err
	}
	if _, err := b.wtr.Write(b.buf.Bytes()); err != nil {
		return err
	}
	checksum := xorChecksum(b.buf.Bytes())
	if err := binary.Write(b.wtr, binary.LittleEndian, checksum); err != nil {
		return err
	}
	return nil
}

func xorChecksum(data []byte) uint8 {
	var cs uint8
	for _, b := range data {
		cs ^= b
	}
	return cs
}

func main() {
	// Example usage:
	file, err := os.Create("example.tap")
	if err != nil {
		panic(err)
	}
	defer file.Close()

	writer := NewTAPfileBlockWriter(file)
	data := []byte("Hello, TAP file format!")
	if _, err := writer.Write(data); err != nil {
		panic(err)
	}
	if err := writer.CompleteBlock(); err != nil {
		panic(err)
	}

	// Additional test cases can be added here to verify the correctness of the solution.
}
