// Context represents a connection object into the token service
type Context struct {
	URL          string
	ClientID     string
	ClientSecret string
	Logger       *logging.Logger
}

// ImmediateETL triggers an Immediate ETL cycle for the specified connection.
// If datasource and cycle are not provided, it triggers extraction for all datasources in the configuration.
func (ctx Context) ImmediateETL(conn, osp, ds, cycle string) error {
	body := fmt.Sprintf("{\"connection\":\"%s\", \"osp\":\"%s\", \"datasource\":\"%s\", \"cycle\":\"%s\"}", conn, osp, ds, cycle)
	response, err := http.Request{
		URL: ctx.URL,
		Authentication: http.Authentication{
			Scheme:   "basic",
			Username: ctx.ClientID,
			Password: ctx.ClientSecret,
		},
		ContentType: "application/json",
		Body:        []byte(body),
	}.Post()

	if err != nil {
		return fmt.Errorf("while interacting with Producer service: %s", err.Error())
	}

	var ret struct {
		Status  string `json:"status"`
		Message string `json:"message"`
	}

	if err := json.Unmarshal(response.Body, &ret); err != nil {
		return fmt.Errorf("while unmarshalling message: %s", err.Error())
	}

	if ret.Status != "ok" {
		return fmt.Errorf(ret.Message)
	}

	return nil
}

// GetSchedules retrieves a list of ETL schedules for the specified organization.
// Optional filters for specific applications and data sources can be applied.
func (ctx Context) GetSchedules(organization string, app, datasource *string) ([]types.Schedule, error) {
	ctx.Logger.Infof("Getting schedules for organization %q, app %v, datasource %v", organization, app, datasource)

	query := make(map[string]string)
	if app != nil {
		query["app"] = *app
	}
	if datasource != nil {
		query["datasource"] = *datasource
	}

	response, err := http.Request{
		URL: fmt.Sprintf("%s/organizations/%s/schedule", ctx.URL, organization),
		Authentication: http.Authentication{
			Scheme:   "basic",
			Username: ctx.ClientID,
			Password: ctx.ClientSecret,
		},
		Query:       query,
		ContentType: "application/json",
	}.Get()

	if err != nil {
		return nil, fmt.Errorf("failed to send request to producer for getting schedules: %s", err.Error())
	}

	var res api.Response
	if err := json.Unmarshal(response.Body, &res); err != nil {
		return nil, fmt.Errorf("failed to unmarshal json into response: %s", err.Error())
	}

	schedules, ok := res.Details.([]types.Schedule)
	if !ok {
		return nil, fmt.Errorf("details(%T) from response is not type of []Schedule", res.Details)
	}

	ctx.Logger.Infof("Fetched %d schedules", len(schedules))
	return schedules, nil
}

// Test cases to verify the solution correctness
func main() {
	// Initialize the context with configuration and logger
	ctx := Context{
		URL:          "https://producer.example.com",
		ClientID:     "client-id",
		ClientSecret: "client-secret",
		Logger:       logging.NewLogger(),
	}

	// Test ImmediateETL
	err := ctx.ImmediateETL("conn-id", "osp-id", "datasource-id", "cycle-id")
	if err != nil {
		ctx.Logger.Errorf("Error triggering ImmediateETL: %s", err)
	} else {
		ctx.Logger.Info("ImmediateETL triggered successfully")
	}

	// Test GetSchedules
	schedules, err := ctx.GetSchedules("organization-id", nil, nil)
	if err != nil {
		ctx.Logger.Errorf("Error retrieving schedules: %s", err)
	} else {
		ctx.Logger.Infof("Retrieved %d schedules", len(schedules))
	}
}
