package main

import (
	"context"
	"encoding/binary"
	"fmt"
	"time"

	"github.com/allegro/bigcache/v3"
	"github.com/cespare/xxhash/v2"
)

type ResponseManager struct {
	manager *bigcache.BigCache
}

func NewResponseManager() *ResponseManager {
	responseManager, _ := bigcache.New(context.Background(), bigcache.DefaultConfig(5*time.Minute))

	return &ResponseManager{
		manager: responseManager,
	}
}

func (responseManager *ResponseManager) GetHashKey(reqId uint32, user string) []byte {
	hasher := xxhash.New()
	hasher.Write([]byte(user))
	hash := hasher.Sum64()
	hash ^= uint64(reqId)

	hashKey := make([]byte, 12)
	binary.LittleEndian.PutUint64(hashKey[:8], hash)
	binary.LittleEndian.PutUint32(hashKey[8:], reqId)
	return hashKey
}

func (responseManager *ResponseManager) GetCachedResponse(hashKey []byte) ([]byte, error) {
	cachedResponse, err := responseManager.manager.Get(string(hashKey))
	if err != nil {
		return nil, err
	}

	return cachedResponse, nil
}

func (responseManager *ResponseManager) SetCachedResponse(hashKey []byte, response []byte) error {
	err := responseManager.manager.Set(string(hashKey), response)
	if err != nil {
		return err
	}

	return nil
}

func main() {
	// Initialize the ResponseManager
	rm := NewResponseManager()

	// Generate a hash key for a request
	reqId := uint32(12345)
	user := "user123"
	hashKey := rm.GetHashKey(reqId, user)

	// Set a response in the cache
	response := []byte("This is a cached response")
	err := rm.SetCachedResponse(hashKey, response)
	if err != nil {
		fmt.Println("Error setting cached response:", err)
		return
	}

	// Retrieve the cached response
	cachedResponse, err := rm.GetCachedResponse(hashKey)
	if err != nil {
		fmt.Println("Error getting cached response:", err)
		return
	}

	fmt.Println("Cached Response:", string(cachedResponse))
}
