	if symlinksMode == SymlinksSecure {
		return errors.New("symlinks: secure mode is not supported on this platform")
	}

	var err error
	if isDir {
		err = os.Mkdir(path, 0755)
	} else {
		_, err = os.Create(path)
	}
	return err
}

