// Read reads the next XML element that matches the XPath expression.
func (s *XMLStreamReader) Read() (*Node, error) {
	for {
		token, err := s.decoder.Token()
		if err != nil {
			if err == io.EOF {
				return nil, io.EOF
			}
			return nil, err
		}

		switch se := token.(type) {
		case xml.StartElement:
			if matchesXPath(se.Name.Local, s.filter) {
				var node Node
				err := s.decoder.DecodeElement(&node, &se)
				if err != nil {
					return nil, err
				}
				return &node, nil
			}
		}
	}
}

