package main

import (
	"fmt"
	"regexp"
	"strings"
	"unicode"
)

// toTitleCase capitalizes the first letter of a word.
func toTitleCase(word string) string {
	if word == "" {
		return ""
	}
	return strings.ToUpper(string(word[0])) + word[1:]
}

// PascalCase converts a string from snake_case, kebab-case, or camelCase to PascalCase.
func PascalCase(identifier string) (string, error) {
	if identifier == "" {
		return "", nil
	}

	// Regular expression to find camelCase occurrences.
	camelRe, err := regexp.Compile(`([a-z])([A-Z])`)
	if err != nil {
		return "", fmt.Errorf("failed to compile camelCase regex: %v", err)
	}

	// Replace camelCase with space-separated words.
	unCamel := camelRe.ReplaceAllStringFunc(identifier, func(match string) string {
		return string(match[0]) + " " + string(unicode.ToUpper(rune(match[1])))
	})

	// Regular expression to find snake_case and kebab-case occurrences.
	wordRe, err := regexp.Compile(`[-_\s]+`)
	if err != nil {
		return "", fmt.Errorf("failed to compile snake_case and kebab-case regex: %v", err)
	}

	// Split the string into words and capitalize the first letter of each word.
	words := wordRe.Split(unCamel, -1)
	for i, word := range words {
		words[i] = toTitleCase(word)
	}

	// Join the words to form a PascalCase string.
	pascal := strings.Join(words, "")

	return pascal, nil
}

func main() {
	// Test cases to verify the solution correctness.
	testCases := []string{
		"",
		"hello",
		"hello_world",
		"hello-world",
		"helloWorld",
		"getHTTPResponseCode",
		"this_is_a_long_snake_case_string",
		"this-is-a-long-kebab-case-string",
		"thisIsALongCamelCaseString",
	}

	for _, testCase := range testCases {
		pascal, err := PascalCase(testCase)
		if err != nil {
			fmt.Printf("Error: %v\n", err)
		} else {
			fmt.Printf("PascalCase(%q) = %q\n", testCase, pascal)
		}
	}
}
