// SetFBType encodes the type and bit width into a single byte.
func SetFBType(fbt uint8, btw uint8) uint8 {
	return (fbt << 3) | (btw & 0x07)
}

// GetFBType decodes and returns the type from the encoded byte.
func GetFBType(fbType uint8) uint8 {
	return fbType >> 3
}

// GetBitWidth decodes and returns the bit width from the encoded byte.
func GetBitWidth(fbType uint8) uint8 {
	return fbType & 0x07
}

// IsInline returns true if the value is stored inline, false otherwise.
func IsInline(fbType uint8) bool {
	return (fbType & 0x80) != 0
}

// Test cases to verify the correctness of the solution
func TestFlexBufferEncoding(t *testing.T) {
	tests := []struct {
		fbt      uint8
		btw      uint8
		expected uint8
	}{
		{fbt: 3, btw: 3, expected: 0x18},
		{fbt: 1, btw: 0, expected: 0x08},
		{fbt: 15, btw: 7, expected: 0x7F},
	}

	for _, test := range tests {
		fbType := SetFBType(test.fbt, test.btw)
		if fbType != test.expected {
			t.Errorf("SetFBType(%d, %d) = %d; want %d", test.fbt, test.btw, fbType, test.expected)
		}

		if GetBitWidth(fbType) != test.btw {
			t.Errorf("GetBitWidth(%d) = %d; want %d", fbType, GetBitWidth(fbType), test.btw)
		}

		if GetFBType(fbType) != test.fbt {
			t.Errorf("GetFBType(%d) = %d; want %d", fbType, GetFBType(fbType), test.fbt)
		}
	}
}

func TestIsInline(t *testing.T) {
	tests := []struct {
		fbType   uint8
		expected bool
	}{
		{fbType: 0x18, expected: false},
		{fbType: 0x88, expected: true},
	}

	for _, test := range tests {
		if IsInline(test.fbType) != test.expected {
			t.Errorf("IsInline(%d) = %t; want %t", test.fbType, IsInline(test.fbType), test.expected)
		}
	}
}
