// KeyValueStore represents a simple key-value store.
type KeyValueStore struct {
	store map[string]string
}

// NewKeyValueStore creates a new instance of KeyValueStore.
func NewKeyValueStore() *KeyValueStore {
	return &KeyValueStore{
		store: make(map[string]string),
	}
}

// AddKeyValue adds or updates a key-value pair in the store.
func (kvs *KeyValueStore) AddKeyValue(key, value string) {
	kvs.store[key] = value
}

// GetValue retrieves the value for a given key from the store.
func (kvs *KeyValueStore) GetValue(key string) (string, error) {
	value, ok := kvs.store[key]
	if !ok {
		return "", errors.New("key does not exist")
	}
	return value, nil
}

// DeleteKey removes a key-value pair from the store.
func (kvs *KeyValueStore) DeleteKey(key string) error {
	_, ok := kvs.store[key]
	if !ok {
		return errors.New("key does not exist")
	}
	delete(kvs.store, key)
	return nil
}

func main() {
	fmt.Println("--- Key-Value Store ---")
	defer fmt.Println("--- End Key-Value Store ---")

	kvs := NewKeyValueStore()

	// Add key-value pairs
	kvs.AddKeyValue("name", "hazim")
	kvs.AddKeyValue("age", "seventeen")

	// Retrieve and print a value
	value, err := kvs.GetValue("name")
	if err != nil {
		fmt.Println("Error:", err)
	} else {
