func (r *ServicesLabelsReconciler) Reconcile(ctx context.Context, req ctrl.Request) (ctrl.Result, error) {
	// Log that we are reconciling the Service
	r.Log.Info(fmt.Sprintf("Reconciling Service %s/%s", req.Namespace, req.Name))

	// Fetch the Service instance
	service := &corev1.Service{}
	err := r.Client.Get(ctx, req.NamespacedName, service)
	if err != nil {
		return ctrl.Result{}, client.IgnoreNotFound(err)
	}

	// Check if the 'managed-by' label is set to 'capsule'
	if service.Labels["managed-by"] != "capsule" {
		// Update the labels
		if service.Labels == nil {
			service.Labels = make(map[string]string)
		}
		service.Labels["managed-by"] = "capsule"

		// Log that we are updating the Service
		r.Log.Info(fmt.Sprintf("Updating Service %s/%s with 'managed-by: capsule' label", req.Namespace, req.Name))

		// Update the Service
		if err := r.Client.Update(ctx, service); err != nil {
			return ctrl.Result{}, err
		}
	}

	// Return with no error
	return ctrl.Result{}, nil
}

