	b64Signature := b64EncodedURL[1:strings.Index(b64EncodedURL[1:], "/")+1] // Extract the signature
	b64EncodedPart := b64EncodedURL[strings.Index(b64EncodedURL[1:], "/")+2:] // Extract the encoded URL part

	decodedURL, err = B64DecodeURL(hmacKey, b64Signature, b64EncodedPart)
	if err != nil {
		fmt.Println("Error decoding base64 URL:", err)
	} else {
		fmt.Println("Decoded Base64 URL:", decodedURL)
	}

	// Test Automatic Decoding
	autoDecodedURL, success := DecodeURL(hmacKey, hexSignature, hexEncodedPart)
	if !success {
		fmt.Println("Error automatically decoding URL")
	} else {
		fmt.Println("Automatically Decoded URL:", autoDecodedURL)
	}
}
