package osutils

import (
	"io"
	"os"
	"path/filepath"
)

// FileOrPathExists checks if a file or directory exists at the given path.
func FileOrPathExists(path string) bool {
	_, err := os.Stat(path)
	return !os.IsNotExist(err)
}

// CopyFile copies a file from the source path to the destination path.
func CopyFile(src, dest string) error {
	sourceFileStat, err := os.Stat(src)
	if err != nil {
		return err
	}

	if !sourceFileStat.Mode().IsRegular() {
		return errors.New("source file is not a regular file")
	}

	source, err := os.Open(src)
	if err != nil {
		return err
	}
	defer source.Close()

	destination, err := os.Create(dest)
	if err != nil {
		return err
	}
	defer destination.Close()

	_, err = io.Copy(destination, source)
	return err
}

// CreateDirectoryIfNotExists creates a directory at the given path with the specified permissions if it does not already exist.
func CreateDirectoryIfNotExists(path string, perm os.FileMode) error {
	if !FileOrPathExists(path) {
		return os.MkdirAll(path, perm)
	}
	return nil
}

// CreateFileIfNotExists creates a new file at the given path if it does not already exist.
func CreateFileIfNotExists(fileName string) error {
	if !FileOrPathExists(fileName) {
		file, err := os.Create(fileName)
		if err != nil {
			return err
		}
		file.Close()
	}
	return nil
}
