package main

import (
	"fmt"
)

func reverseStr(s string, k int) string {
	str := []byte(s)
	var begin int
	for begin < len(str) {
		left := begin
		right := begin + k - 1
		if right >= len(str) {
			right = len(str) - 1
		}
		for left < right && left < len(str) {
			str[left], str[right] = str[right], str[left]
			left++
			right--
		}
		begin = begin + 2*k
	}
	return string(str)
}

func main() {
	// Test cases to verify the solution correctness
	fmt.Println(reverseStr("abcdefg", 2)) // Expected output: "bacdfeg"
	fmt.Println(reverseStr("abcd", 2))    // Expected output: "bacd"
	fmt.Println(reverseStr("a", 2))       // Expected output: "a"
	fmt.Println(reverseStr("abcdefg", 1)) // Expected output: "abcdefg"
	fmt.Println(reverseStr("abcdefg", 8)) // Expected output: "gfedcba"
