func (c circle) perimeter() float64 {
	return 2 * math.Pi * c.radius
}

// Implement the area method for rectangle
func (r rectangle) area() float64 {
	return r.length * r.width
}

// Implement the perimeter method for rectangle
func (r rectangle) perimeter() float64 {
	return 2 * (r.length + r.width)
}

// Define a function to display the area and perimeter of a geometry
func displayInfo(g geometry) {
	fmt.Printf("Area: %.2f\n", g.area())
	fmt.Printf("Perimeter: %.2f\n", g.perimeter())
}

// Main function to demonstrate the functionality
func main() {
	c := circle{radius: 5}
	r := rectangle{length: 3, width: 4}

	displayInfo(c)
	displayInfo(r)
}

