// SetMaxOpenFiles sets the maximum number of open files for the current process.
func SetMaxOpenFiles(maxOpenFiles uint64) error {
	var rLimit syscall.Rlimit
	err := syscall.Getrlimit(syscall.RLIMIT_NOFILE, &rLimit)
	if err != nil {
		return err
	}

	if maxOpenFiles > rLimit.Max {
		return errors.New("specified limit exceeds system-imposed maximum")
	}

	rLimit.Cur = maxOpenFiles
	err = syscall.Setrlimit(syscall.RLIMIT_NOFILE, &rLimit)
	if err != nil {
		return err
	}

	return nil
}

// GetMaxOpenFiles returns the current maximum number of open files for the process.
func GetMaxOpenFiles() (uint64, error) {
	var rLimit syscall.Rlimit
	err := syscall.Getrlimit(syscall.RLIMIT_NOFILE, &rLimit)
	if err != nil {
		return 0, err
	}

	return rLimit.Cur, nil
}

// Test cases to verify the solution correctness.
func main() {
	// Set the maximum number of open files to 1024.
	err := SetMaxOpenFiles(1024)
	if err != nil {
		panic(err)
	}

	// Get the current maximum number of open files.
	maxOpenFiles, err := GetMaxOpenFiles()
	if err != nil {
		panic(err)
	}

	// Print the current limit.
	println("Current max open files:", maxOpenFiles)
}
