// Cache interface defines the methods for a cache implementation.
type Cache interface {
	Set(key string, value interface{})
	Get(key string) (interface{}, bool)
}

// SimpleCache is a basic in-memory cache that implements the Cache interface.
type SimpleCache struct {
	mu    sync.RWMutex
	store map[string]interface{}
}

// NewSimpleCache creates a new instance of SimpleCache.
func NewSimpleCache() *SimpleCache {
	return &SimpleCache{
		store: make(map[string]interface{}),
	}
}

// Set stores a value associated with a key in the cache.
func (c *SimpleCache) Set(key string, value interface{}) {
	c.mu.Lock()
	defer c.mu.Unlock()
	c.store[key] = value
}

// Get retrieves the value for a given key from the cache.
func (c *SimpleCache) Get(key string) (interface{}, bool) {
	c.mu.RLock()
	defer c.mu.RUnlock()
	value, ok := c.store[key]
	return value, ok
}

// BenchmarkSimpleCacheSet benchmarks the Set method of SimpleCache.
func BenchmarkSimpleCacheSet(b *testing.B) {
	cache := NewSimpleCache()
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		cache.Set("key", "value")
	}
}

// BenchmarkSimpleCacheGet benchmarks the Get method of SimpleCache.
func BenchmarkSimpleCacheGet(b *testing.B) {
	cache := NewSimpleCache()
	cache.Set("key", "value")
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		_, _ = cache.Get("key")
	}
}

// TestSimpleCache tests the Set and Get methods of SimpleCache.
func TestSimpleCache(t *testing.T) {
	cache := NewSimpleCache()
