// isPalindrome checks if a given string is a palindrome, considering only alphanumeric characters and ignoring cases.
func isPalindrome(s string) bool {
	var cleanString strings.Builder
	for _, r := range s {
		if unicode.IsLetter(r) || unicode.IsNumber(r) {
			cleanString.WriteRune(unicode.ToLower(r))
		}
	}

	cleaned := cleanString.String()
	length := len(cleaned)
	for i := 0; i < length/2; i++ {
		if cleaned[i] != cleaned[length-1-i] {
			return false
		}
	}
	return true
}

