// disk_plan_to_key is a mock function to convert DiskPlanID to a string key.
func disk_plan_to_key(planID int) string {
	// For the purpose of this exercise, we'll just return a string representation of the planID.
	return fmt.Sprintf("Plan%d", planID)
}

// FormatDiskDetails formats the details of a Disk using the provided column definitions.
func FormatDiskDetails(disk Disk) (string, error) {
	var defaultColumnDefs = []struct {
		Name     string
		Template string
	}{
		{Name: "Zone", Template: "{{.Zone}}"},
		{Name: "ID", Template: "{{.ID}}"},
		{Name: "Name", Template: "{{.Name}}"},
		{Name: "Tags", Template: "{{.Tags}}"},
		{
			Name:     "Server",
			Template: `{{ if .ServerID }}{{ .ServerID }}({{ .ServerName }}){{ end }}`,
		},
		{
			Name:     "Plan",
			Template: "{{ disk_plan_to_key .DiskPlanID }}",
		},
		{Name: "Size", Template: "{{.Size}}"},
		{Name: "Connection", Template: "{{.Connection}}"},
		{
			Name:     "Storage",
			Template: "{{ .StorageName }}",
		},
		{Name: "Description", Template: "{{.Description}}"},
	}

	var result bytes.Buffer
	for _, colDef := range defaultColumnDefs {
		tmpl, err := template.New(colDef.Name).Funcs(template.FuncMap{
			"disk_plan_to_key": disk_plan_to_key,
		}).Parse(colDef.Template)
		if err != nil {
			return "", err
		}

		err = tmpl.Execute(&result, disk)
		if err != nil {
			return "", err
		}
		result.WriteString("\t")
	}

	return result.String(), nil
}

