// MessageDecoder defines an interface for decoding messages.
type MessageDecoder interface {
	Decode(topic string, b []byte) ([]byte, error)
}

// MsgpackDecoder is an implementation of MessageDecoder that decodes MessagePack encoded messages.
type MsgpackDecoder struct{}

// Decode decodes a MessagePack encoded message into a JSON encoded message.
func (m MsgpackDecoder) Decode(topic string, b []byte) ([]byte, error) {
	if topic == "" {
		return b, nil
	}

	var out map[string]interface{}
	err := msgpack.Unmarshal(b, &out)
	if err != nil {
		return nil, err
	}

	repr, err := json.Marshal(out)
	if err != nil {
		return nil, err
	}

	return repr, nil
}

func main() {
