type TreeMapReader struct {
	scanner *bufio.Scanner
}

func NewTreeMapReader(f *os.File) *TreeMapReader {
	tr := new(TreeMapReader)
	tr.scanner = bufio.NewScanner(f)

	return tr
}

func (tr *TreeMapReader) ReadMap() [][]int {
	grid := [][]int{}

	for {
		tr.scanner.Scan()
		line := tr.scanner.Text()

		if line == "" {
			break
		}

		tokens := strings.Split(line, "")
		row := make([]int, len(tokens))
		for i, c := range tokens {
			val, err := strconv.Atoi(c)
			if err != nil {
				panic(err)
			}

			row[i] = val
		}

		grid = append(grid, row)
	}

	return grid
}

func TotalTreeHeight(grid [][]int) int {
	totalHeight := 0
	for _, row := range grid {
		for _, height := range row {
			totalHeight += height
		}
	}
	return totalHeight
}

func main() {
	// Open the file containing the forest map
	file, err := os.Open("forest_map.txt")
	if err != nil {
		panic(err)
	}
	defer file.Close()

	// Create a new TreeMapReader and read the map
	treeMapReader := NewTreeMapReader(file)
	forestMap := treeMapReader.ReadMap()

	// Calculate the total height of all trees
	totalHeight := TotalTreeHeight(forestMap)
	fmt.Printf("Total height of all trees: %d\n", totalHeight)
}

