	startDate := "2023-01-01"
	endDate := "2023-12-31"

	err := godotenv.Load(os.Getenv("ENV_PATH"))
	if err != nil {
		log.Fatal("Error loading .env file")
	}

	apis := au.NewClientAPIs(os.Getenv("AHA_ACCOUNT"), os.Getenv("AHA_API_KEY"))

	featureSet := au.NewFeatureSet()
	featureSet.ClientAPIs = apis

	err = featureSet.LoadFeaturesForReleases(context.Background(), releases)
	if err != nil {
		log.Fatal(err)
	}

	filteredFeatures := filterFeaturesByDateRange(featureSet, startDate, endDate)

	if len(filteredFeatures.FeatureMap) > 0 {
		fmtutil.PrintJSON(filteredFeatures)
		bytes, err := json.MarshalIndent(filteredFeatures, "", "  ")
		if err != nil {
			log.Fatal(err)
		}

		err = ioutil.WriteFile(outputFile, bytes, 0644)
		if err != nil {
			log.Fatal(err)
		}
		log.Printf("Wrote [%v]\n", outputFile)
	} else {
		log.Println("No features found within the specified date range.")
	}
	fmt.Println("DONE")
}

func filterFeaturesByDateRange(featureSet *au.FeatureSet, startDate, endDate string) *au.FeatureSet {
	start, err := time.Parse("2006-01-02", startDate)
	if err != nil {
		log.Fatal(err)
	}
	end, err := time.Parse("2006-01-02", endDate)
	if err != nil {
		log.Fatal(err)
	}

	filteredSet := au.NewFeatureSet()
	for _, feature := range featureSet.Features {
		releaseDate, err := time.Parse(time.RFC3339, feature.ReleaseDate)
		if err != nil {
			log.Printf("Error parsing release date for feature %s: %v", feature.ID, err)
			continue
		}
		if releaseDate.After(start) && releaseDate.Before(end) {
			filteredSet.Features = append(filteredSet.Features, feature)
			filteredSet.FeatureMap[feature.ID] = feature
		}
	}
	return filteredSet
}
