package idx

import (
	"errors"
	"sync"
	"time"
)

const (
	epoch            int64 = 1577836800000 // Custom epoch: January 1, 2020 (midnight UTC)
	timestampBits    uint8 = 41
	machineIdBits    uint8 = 10
	sequenceBits     uint8 = 12
	timestampMax     int64 = 1<<timestampBits - 1
	machineIdMax     int64 = 1<<machineIdBits - 1
	sequenceMask     int64 = 1<<sequenceBits - 1
	timestampShift   uint8 = sequenceBits + machineIdBits
	machineIdShift   uint8 = sequenceBits
)

type JsSnowFlake struct {
	machineId int64
	sequence  int64
	lastTime  int64
	lock      sync.Mutex
}

func NewJsSnowFlake(machineId int64) (*JsSnowFlake, error) {
	if machineId < 0 || machineId > machineIdMax {
		return nil, errors.New("machine ID out of range")
	}
	return &JsSnowFlake{
		machineId: machineId,
		sequence:  0,
		lastTime:  -1,
	}, nil
}

func (js *JsSnowFlake) GetId() int64 {
	js.lock.Lock()
	defer js.lock.Unlock()

	currentTime := time.Now().UnixMilli() - epoch
	if currentTime < js.lastTime {
		// Handle clock going backwards
		currentTime = js.lastTime
	}

	if currentTime == js.lastTime {
		js.sequence = (js.sequence + 1) & sequenceMask
		if js.sequence == 0 {
			// Wait for the next millisecond
			for currentTime <= js.lastTime {
				currentTime = time.Now().UnixMilli() - epoch
			}
		}
	} else {
		js.sequence = 0
	}

	js.lastTime = currentTime

	id := (currentTime << timestampShift) | (js.machineId << machineIdShift) | js.sequence
	return id
