	Number      int64
	Timestamp   int64
	Transactions []Transaction
}

// Transaction represents a simple transaction from one address to another with an amount.
type Transaction struct {
	ID     string
	From   string
	To     string
	Amount float64
	Status string
}

// Blockchain represents a series of blocks.
type Blockchain struct {
	Blocks       []Block
	Transactions []Transaction
	mu           sync.Mutex
}

// NewBlockchain creates a new Blockchain with a genesis block.
func NewBlockchain() *Blockchain {
	genesisBlock := Block{
		Number:      0,
		Timestamp:   time.Now().Unix(),
		Transactions: []Transaction{},
	}
	return &Blockchain{
		Blocks:       []Block{genesisBlock},
		Transactions: []Transaction{},
	}
}

// AddBlock adds a new block to the blockchain.
func (bc *Blockchain) AddBlock(transactions []Transaction) {
	bc.mu.Lock()
	defer bc.mu.Unlock()

	newBlock := Block{
		Number:      int64(len(bc.Blocks)),
		Timestamp:   time.Now().Unix(),
		Transactions: transactions,
	}
	bc.Blocks = append(bc.Blocks, newBlock)
}

// AddTransaction adds a new transaction to the blockchain and returns its ID.
func (bc *Blockchain) AddTransaction(from, to string, amount float64) string {
	bc.mu.Lock()
	defer bc.mu.Unlock()

	transaction := Transaction{
		ID:     fmt.Sprintf("tx-%d", len(bc.Transactions)+1),
		From:   from,
		To:     to,
		Amount: amount,
		Status: "PENDING",
	}
	bc.Transactions = append(bc.Transactions, transaction)
	return transaction.ID
}

// GetBlock retrieves a block by its number.
func (bc *Blockchain) GetBlock(number int64) *Block {
	if number < 0 || number >= int64(len(bc.Blocks)) {
		return nil
	}
	return &bc.Blocks[number]
}

// GetLatestBlock retrieves the latest block in the blockchain.
func (bc *Blockchain) GetLatestBlock() *Block {
	return &bc.Blocks[len(bc.Blocks)-1]
}

// GetTransactionStatus retrieves the status of a transaction by its ID.
func (bc *Blockchain) GetTransactionStatus(id string) string {
	for _, tx := range bc.Transactions {
		if tx.ID == id {
			return tx.Status
		}
	}
	return "NOT FOUND"
}

