}

// RemoveUser removes an existing user with the given username.
func (m *UserManager) RemoveUser(username string) error {
	if _, exists := m.users[username]; !exists {
		return ErrUserNotFound
	}
	delete(m.users, username)
	return nil
}

// AddDevice adds a new device to the user with the given device name.
func (m *UserManager) AddDevice(username, deviceName string) error {
	user, exists := m.users[username]
	if !exists {
		return ErrUserNotFound
	}
	if _, exists := user.Devices[deviceName]; exists {
		return ErrDuplicatedDeviceName
	}
	if len(user.Devices) >= 5 { // Assuming the max device count is 5.
		return ErrMaxDeviceCountReached
	}
	user.Devices[deviceName] = &Device{
		Name: deviceName,
		Tags: make(map[string]struct{}),
	}
	return nil
}

// RemoveDevice removes a device from the user.
func (m *UserManager) RemoveDevice(username, deviceName string) error {
	user, exists := m.users[username]
	if !exists {
		return ErrUserNotFound
	}
	if _, exists := user.Devices[deviceName]; !exists {
		return ErrDeviceNotFound
	}
	delete(user.Devices, deviceName)
	return nil
}

// TagDevice tags a device with a given tag name.
func (m *UserManager) TagDevice(username, deviceName, tagName string) error {
	user, exists := m.users[username]
	if !exists {
		return ErrUserNotFound
	}
	device, exists := user.Devices[deviceName]
	if !exists {
		return ErrDeviceNotFound
	}
	if _, exists := device.Tags[tagName]; exists {
		return ErrDuplicateTagName
	}
	if len(device.Tags) >= 10 { // Assuming the max tag count is 10.
		return ErrMaxTagReached
	}
	device.Tags[tagName] = struct{}{}
	return nil
}

