package kvstore

import (
	"sync"
	"time"
)

// KeyValueStore is a thread-safe in-memory key-value store with expirable keys.
type KeyValueStore struct {
	store map[string]*storeValue
	mu    sync.RWMutex
}

type storeValue struct {
	value      interface{}
	expiration *time.Time
}

// NewKeyValueStore creates a new instance of KeyValueStore.
func NewKeyValueStore() *KeyValueStore {
	return &KeyValueStore{
		store: make(map[string]*storeValue),
	}
}

// Set stores the key with the given value and expiration duration.
func (kvs *KeyValueStore) Set(key string, value interface{}, duration time.Duration) {
	kvs.mu.Lock()
	defer kvs.mu.Unlock()

	var expiration *time.Time
	if duration > 0 {
		exp := time.Now().Add(duration)
		expiration = &exp
	}

	kvs.store[key] = &storeValue{
		value:      value,
		expiration: expiration,
	}

	// If the key has an expiration, start a goroutine to remove it after the duration.
	if expiration != nil {
		go func() {
			time.Sleep(duration)
			kvs.Delete(key)
		}()
	}
}

// Get retrieves the value associated with the key.
func (kvs *KeyValueStore) Get(key string) (interface{}, bool) {
	kvs.mu.RLock()
	defer kvs.mu.RUnlock()

	storeVal, exists := kvs.store[key]
	if !exists {
		return nil, false
	}

	// Check if the key has expired.
	if storeVal.expiration != nil && storeVal.expiration.Before(time.Now()) {
		return nil, false
	}

	return storeVal.value, true
}

// Delete removes the key from the store.
func (kvs *KeyValueStore) Delete(key string) {
	kvs.mu.Lock()
	defer kvs.mu.Unlock()

	delete(kvs.store, key)
}

// Clear removes all keys from the store.
func (kvs *KeyValueStore) Clear() {
	kvs.mu.Lock()
	defer kvs.mu.Unlock()

	kvs.store = make(map[string]*storeValue)
}

// Test cases to verify the solution correctness.
func main() {
	kv := NewKeyValueStore()

	// Test Set and Get
	kv.Set("key1", "value1", 0)
	val, exists := kv.Get("key1")
	fmt.Println(val, exists) // Output: value1 true

	// Test expiration
	kv.Set("key2", "value2", 1*time.Second)
	time.Sleep(2 * time.Second)
	_, exists = kv.Get("key2")
	fmt.Println(exists) // Output: false

	// Test Delete
	kv.Set("key3", "value3", 0)
	kv.Delete("key3")
	_, exists = kv.Get("key3")
	fmt.Println(exists) // Output: false

	// Test Clear
	kv.Set("key4", "value4", 0)
	kv.Clear()
	_, exists = kv.Get("key4")
	fmt.Println(exists) // Output: false
}
