}

// Global settings variable
var global = Settings{
	UserInfo: struct{ PwdEncDiff int }{PwdEncDiff: bcrypt.DefaultCost},
}

// SetPassword hashes a plaintext password using bcrypt.
// Parameters:
//     password: The plaintext password to hash.
// Returns:
//     string: The hashed password.
//     error: Any error that occurred during hashing.
func SetPassword(password string) (string, error) {
	pwdBytes, err := bcrypt.GenerateFromPassword([]byte(password), global.UserInfo.PwdEncDiff)
	return string(pwdBytes), err
}

// CheckPassword verifies a plaintext password against a hashed password.
// Parameters:
//     storedPwd: The hashed password stored in the database.
//     enteredPwd: The plaintext password entered by the user.
// Returns:
//     bool: True if the passwords match, false otherwise.
func CheckPassword(storedPwd, enteredPwd string) bool {
	err := bcrypt.CompareHashAndPassword([]byte(storedPwd), []byte(enteredPwd))
	return err == nil
}

// Test cases to verify the solution correctness.
func main() {
	// Setting a new password
	hashedPassword, err := SetPassword("mySecureP@ssw0rd")
	if err != nil {
		fmt.Println("Error hashing password:", err)
		return
	}
	fmt.Println("Hashed Password:", hashedPassword)

	// Checking the password
	isCorrect := CheckPassword(hashedPassword, "mySecureP@ssw0rd")
	fmt.Println("Is the entered password correct?", isCorrect)

	// Checking with an incorrect password
	isCorrect = CheckPassword(hashedPassword, "wrongPassword")
	fmt.Println("Is the entered password correct with wrong password?", isCorrect)
}
