func main() {
	const TOLERANCE = 1e-06
	var x1, y1, m, q float64

	fmt.Print("Enter the coordinates of a point (x1, y1): ")
	fmt.Scan(&x1, &y1)
	fmt.Print("Enter the coefficients 'm' (slope) and 'q' (y-intercept) of a line: ")
	fmt.Scan(&m, &q)

	// Calculate the y-coordinate of the line at x1
	yLine := m*x1 + q

	// Determine the position of the point relative to the line
	position := determinePosition(y1, yLine, TOLERANCE)

	// Output the result
	fmt.Printf("The point is %s the line.\n", position)
}

// determinePosition returns the position of the point relative to the line.
func determinePosition(yPoint, yLine, tolerance float64) string {
	diff := math.Abs(yPoint - yLine)
	if diff < tolerance {
		return "on"
	} else if yPoint > yLine {
		return "above"
	} else {
		return "below"
	}
}

// Test cases to verify the correctness of the solution
func main() {
	testCases := []struct {
		x1, y1, m, q float64
		expected     string
	}{
		{x1: 1, y1: 2, m: 1, q: 1, expected: "on"},
		{x1: 0, y1: 0, m: 0, q: 0, expected: "on"},
		{x1: 2, y1: 5, m: 1, q: 2, expected: "above"},
		{x1: -1, y1: -3, m: 1, q: 0, expected: "below"},
	}

	for _, tc := range testCases {
		result := determinePosition(tc.y1, tc.m*tc.x1+tc.q, 1e-06)
		if result == tc.expected {
			fmt.Printf("Test passed for (%v, %v) with line y = %vx + %v\n", tc.x1, tc.y1, tc.m, tc.q)
		} else {
			fmt.Printf("Test failed for (%v, %v) with line y = %vx + %v. Expected %v, got %v\n", tc.x1, tc.y1, tc.m, tc.q, tc.expected, result)
		}
	}
}
