package main

import (
	"encoding/json"
	"fmt"
	"github.com/valyala/fasthttp"
	"log"
)

type ErrorMessage struct {
	Message string `json:"message"`
}

func SendSuccessStatus(ctx *fasthttp.RequestCtx) {
	ctx.SetStatusCode(fasthttp.StatusOK)
}

func SendInternalServerError(ctx *fasthttp.RequestCtx) {
	ctx.SetStatusCode(fasthttp.StatusInternalServerError)
}

func SendError(errCode int, errorMsg string, ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(errCode)

	var errorMessage = ErrorMessage{errorMsg}

	JSONEncodedData, err := json.Marshal(errorMessage)
	if err != nil {
		SendInternalServerError(ctx)
	}

	ctx.SetBody(JSONEncodedData)
}

func SendResponse(status int, data interface{}, ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(status)

	JSONEncodedData, err := json.Marshal(data)
	if err != nil {
		SendInternalServerError(ctx)
	}

	ctx.SetBody(JSONEncodedData)
}

func StatusHandler(ctx *fasthttp.RequestCtx) {
	SendSuccessStatus(ctx)
}

func ErrorHandler(ctx *fasthttp.RequestCtx) {
	SendError(fasthttp.StatusInternalServerError, "Internal Server Error", ctx)
}

func CustomErrorHandler(ctx *fasthttp.RequestCtx) {
	var errorMessage ErrorMessage
	err := json.Unmarshal(ctx.PostBody(), &errorMessage)
	if err != nil {
		SendInternalServerError(ctx)
		return
	}
	SendError(fasthttp.StatusBadRequest, errorMessage.Message, ctx)
}

func DataHandler(ctx *fasthttp.RequestCtx) {
	var data interface{}
	err := json.Unmarshal(ctx.PostBody(), &data)
	if err != nil {
		SendInternalServerError(ctx)
		return
	}
	SendResponse(fasthttp.StatusOK, data, ctx)
}

func main() {
	router := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/status":
			StatusHandler(ctx)
		case "/error":
			ErrorHandler(ctx)
		case "/custom-error":
			CustomErrorHandler(ctx)
		case "/data":
			DataHandler(ctx)
		default:
			ctx.Error("Unsupported path", fasthttp.StatusNotFound)
		}
	}

	if err := fasthttp.ListenAndServe(":8080", router); err != nil {
		log.Fatalf("Error in ListenAndServe: %s", err)
	}
}

// Test cases can be written using any Go testing framework, such as the built-in `testing` package.
// Here is an example of how you might write a test case for the `/status` endpoint:

func TestStatusHandler(t *testing.T) {
	expectedStatus := fasthttp.StatusOK

	// Mock request and response context
	ctx := &fasthttp.RequestCtx{}
	StatusHandler(ctx)

	if ctx.Response.StatusCode() != expectedStatus {
		t.Errorf("Expected status code %d, got %d", expectedStatus, ctx.Response.StatusCode())
	}
}

// Similar test cases should be written for the other handlers to ensure they respond with the correct status codes and payloads.
