	log.Fatal(http.ListenAndServe("127.0.0.1:2000", nil))
}

func timedProcessHandler(w http.ResponseWriter, r *http.Request) {
	fmt.Println("Timed process handler invoked")
	defer fmt.Println("Timed process handler ended")

	ctxt := r.Context()

	select {
	case <-ctxt.Done():
		err := ctxt.Err()
		log.Println("Context canceled: ", err.Error())
		http.Error(w, "Process canceled by client", http.StatusRequestTimeout)

	case <-time.After(time.Second * 10):
		fmt.Println("Process completed")
		fmt.Fprintln(w, "Process completed")
	}
}

