	"strings"
)

type ConfigParser struct {
	settings     map[string]string
	trueIfBlank bool
}

func NewConfigParser(settings map[string]string, trueIfBlank bool) *ConfigParser {
	return &ConfigParser{
		settings:     settings,
		trueIfBlank: trueIfBlank,
	}
}

func (cp *ConfigParser) GetBool(key string, defaultValue bool) bool {
	value, exists := cp.settings[strings.ToLower(key)]
	if !exists {
		return defaultValue
	}
	return stringBool(value, "true", "false", cp.trueIfBlank) == "true"
}

func (cp *ConfigParser) GetString(key string, defaultValue string) string {
	value, exists := cp.settings[strings.ToLower(key)]
	if !exists {
		return defaultValue
	}
	return valueOrValueString(value, defaultValue)
}

func (cp *ConfigParser) GetInt(key string, defaultValue int) int {
	value, exists := cp.settings[strings.ToLower(key)]
	if !exists {
		return defaultValue
	}
	if intValue, err := strconv.Atoi(value); err == nil {
		return intValue
	}
	return defaultValue
}

func (cp *ConfigParser) GetUInt(key string, defaultValue uint) uint {
	value, exists := cp.settings[strings.ToLower(key)]
	if !exists {
		return defaultValue
	}
	if uintValue, err := strconv.ParseUint(value, 10, 64); err == nil {
		return uint(uintValue)
	}
	return defaultValue
}

// Helper functions from the given code snippet
func stringBool(a string, valueIfA string, valueIfNotA string, trueIfBlank bool) string {
	a = strings.ToLower(a)
	switch a {
	case "true", "yes", "y":
		return valueIfA
	case "":
		if trueIfBlank {
			return valueIfA
		}
		return valueIfNotA
	}
	return valueIfNotA
}

func valueOrValueString(a string, b string) string {
	if a == "" {
		return b
	}
	return a
}

// Test cases to verify the solution correctness
func main() {
	settings := map[string]string{
		"debug":       "true",
		"maxretries":  "3",
		"servername":  "",
		"workercount": "5",
	}

	parser := NewConfigParser(settings, true)

	fmt.Println("Debug:", parser.GetBool("debug", false)) // Expected: true
	fmt.Println("MaxRetries:", parser.GetInt("maxretries", 1)) // Expected: 3
	fmt.Println("ServerName:", parser.GetString("servername", "localhost")) // Expected: "localhost"
	fmt.Println("WorkerCount:", parser.GetUInt("workercount", 10)) // Expected: 5
	fmt.Println("MissingKey:", parser.GetBool("missingkey", false)) // Expected: false
