// ContextError is a custom error type that includes a message, a code, and a context map.
type ContextError struct {
	Message string
	Code    int
	Context map[string]string
}

// NewContextError creates a new ContextError with the provided message, code, and context map.
func NewContextError(message string, code int, context map[string]string) error {
	return &ContextError{Message: message, Code: code, Context: context}
}

// Error returns the error message.
func (e *ContextError) Error() string {
	return e.Message
}

// Code returns the error code.
func (e *ContextError) Code() int {
	return e.Code
}

// Context returns the context map.
func (e *ContextError) Context() map[string]string {
	return e.Context
}

// WithContext adds a new key-value pair to the context map of the error.
func (e *ContextError) WithContext(key, value string) {
	if e.Context == nil {
		e.Context = make(map[string]string)
	}
	e.Context[key] = value
}

func main() {
	// Create a ContextError with initial context.
	err := NewContextError("Page not found", 404, map[string]string{"URL": "/non-existent-page"})
	if err != nil {
		contextErr, ok := err.(*ContextError)
		if !ok {
			fmt.Println("Error is not of type ContextError")
			return
		}

		// Add additional context to the error.
		contextErr.WithContext("Method", "GET")
		contextErr.WithContext("User", "anonymous")

		// Print out the error message, code, and context.
		fmt.Printf("Error: %s\n", contextErr.Error())
		fmt.Printf("Code: %d\n", contextErr.Code())
		fmt.Printf("Context: %+v\n", contextErr.Context())
	}
}

// Test cases to verify the solution correctness.
func main() {
