package main

import (
	"errors"
	"fmt"
	"sort"
)

// Define custom errors for the reference management system
var (
	ErrPeerIDRequired   = errors.New("peer ID is required")
	ErrPeernameRequired = errors.New("peername is required")
	ErrNameRequired     = errors.New("name is required")
	ErrPathRequired     = errors.New("either path or FSIPath is required")
	ErrNotFound         = errors.New("reference not found")
)

// DatasetRef represents a reference to a dataset
type DatasetRef struct {
	ProfileID string
	Peername  string
	Name      string
	Path      string
	FSIPath   string
}

// Match checks if two DatasetRefs match based on non-empty fields
func (ref DatasetRef) Match(other DatasetRef) bool {
	return (ref.ProfileID == other.ProfileID || other.ProfileID == "") &&
		(ref.Peername == other.Peername || other.Peername == "") &&
		(ref.Name == other.Name || other.Name == "") &&
		(ref.Path == other.Path || other.Path == "") &&
		(ref.FSIPath == other.FSIPath || other.FSIPath == "")
}

// MemRefstore is an in-memory implementation of the reference management system
type MemRefstore []DatasetRef

// PutRef adds a reference to the system. Only complete references may be added
func (r *MemRefstore) PutRef(put DatasetRef) error {
	// Validation
	if put.ProfileID == "" {
		return ErrPeerIDRequired
	} else if put.Peername == "" {
		return ErrPeernameRequired
	} else if put.Name == "" {
		return ErrNameRequired
	} else if put.Path == "" && put.FSIPath == "" {
		return ErrPathRequired
	}

	// Update or append
	for i, ref := range *r {
		if ref.Match(put) {
			(*r)[i] = put
			return nil
		}
	}
	*r = append(*r, put)
	sort.Slice(*r, func(i, j int) bool {
		return (*r)[i].Peername+(*r)[i].Name < (*r)[j].Peername+(*r)[j].Name
	})
	return nil
}

// GetRef retrieves a reference from the system
func (r MemRefstore) GetRef(get DatasetRef) (DatasetRef, error) {
	for _, ref := range r {
		if ref.Match(get) {
			return ref, nil
		}
	}
	return DatasetRef{}, ErrNotFound
}

// DeleteRef removes a reference from the system
func (r *MemRefstore) DeleteRef(del DatasetRef) error {
	for i, ref := range *r {
		if ref.Match(del) {
			*r = append((*r)[:i], (*r)[i+1:]...)
			return nil
		}
	}
	return ErrNotFound
}

// References lists a subset of references from the system
func (r MemRefstore) References(offset, limit int) ([]DatasetRef, error) {
	if offset < 0 || limit <= 0 {
		return nil, errors.New("invalid offset or limit")
	}
	end := offset + limit
	if end > len(r) {
		end = len(r)
	}
	if offset > end {
		return []DatasetRef{}, nil
	}
	return r[offset:end], nil
}

// RefCount returns the total number of references in the system
func (r MemRefstore) RefCount() (int, error) {
	return len(r), nil
}

// Test cases to verify the solution correctness
func main() {
	store := MemRefstore{}

	// Test PutRef
	err := store.PutRef(DatasetRef{ProfileID: "123", Peername: "alice", Name: "dataset1", Path: "/path/to/dataset1"})
	if err != nil {
