package main

import (
	"context"
	"fmt"
	"net/http"
	"time"
)

// Config holds the configuration for the Prometheus scraper.
type Config struct {
	PrometheusEndpoint string
	ScrapeInterval     time.Duration
}

// PrometheusScraper is responsible for scraping metrics from a Prometheus endpoint.
type PrometheusScraper struct {
	config   Config
	stopChan chan struct{}
}

// NewPrometheusScraper creates a new PrometheusScraper with the given configuration.
func NewPrometheusScraper(config Config) *PrometheusScraper {
	return &PrometheusScraper{
		config:   config,
		stopChan: make(chan struct{}),
	}
}

// Start begins scraping metrics from the Prometheus endpoint at the specified interval.
func (ps *PrometheusScraper) Start() {
	go func() {
		ticker := time.NewTicker(ps.config.ScrapeInterval)
		defer ticker.Stop()

		for {
			select {
			case <-ticker.C:
				ps.scrape()
			case <-ps.stopChan:
				fmt.Println("Stopping Prometheus scraper.")
				return
			}
		}
	}()
}

// Stop signals the PrometheusScraper to stop scraping.
func (ps *PrometheusScraper) Stop() {
	close(ps.stopChan)
}

// scrape fetches metrics from the Prometheus endpoint and prints them to the console.
func (ps *PrometheusScraper) scrape() {
	resp, err := http.Get(ps.config.PrometheusEndpoint)
	if err != nil {
		fmt.Printf("Error scraping Prometheus endpoint: %v\n", err)
		return
	}
	defer resp.Body.Close()

	// In a real-world scenario, you would parse the Prometheus metrics here.
	// For simplicity, we're just printing the status code.
	fmt.Printf("Scraped Prometheus endpoint with status code: %d\n", resp.StatusCode)
}

func main() {
	// Example configuration for the Prometheus scraper.
	config := Config{
		PrometheusEndpoint: "http://localhost:9090/metrics",
		ScrapeInterval:     5 * time.Second,
	}

	scraper := NewPrometheusScraper(config)
	scraper.Start()

	// Run the scraper for 15 seconds before stopping.
	time.Sleep(15 * time.Second)
	scraper.Stop()
}
