package main

import (
	"fmt"
	"net"
	"net/url"
	"strings"
)

const propertiesSuffix = ".properties"

type Conf struct {
	MetaAddr string
	AppID    string
	Cluster  string
}

func getLocalIP() string {
	addrs, err := net.InterfaceAddrs()
	if err != nil {
		return ""
	}
	for _, a := range addrs {
		if ip4 := toIP4(a); ip4 != nil {
			return ip4.String()
		}
	}
	return ""
}

func toIP4(addr net.Addr) net.IP {
	if ipnet, ok := addr.(*net.IPNet); ok && !ipnet.IP.IsLoopback() {
		if ip4 := ipnet.IP.To4(); ip4 != nil {
			return ip4
		}
	}
	return nil
}

func httpurl(ipOrAddr string) string {
	if strings.HasPrefix(ipOrAddr, "http://") || strings.HasPrefix(ipOrAddr, "https://") {
		return ipOrAddr
	}
	return fmt.Sprintf("http://%s", ipOrAddr)
}

func normalizeNamespace(namespace string) string {
	return strings.TrimSuffix(namespace, propertiesSuffix)
}

func notificationURL(conf *Conf, notifications string) string {
	return fmt.Sprintf("%s/notifications/v2?appId=%s&cluster=%s&notifications=%s",
		httpurl(conf.MetaAddr),
		url.QueryEscape(conf.AppID),
		url.QueryEscape(conf.Cluster),
		url.QueryEscape(notifications))
}

func configURL(conf *Conf, namespace, releaseKey string) string {
	return fmt.Sprintf("%s/configs/%s/%s/%s?releaseKey=%s&ip=%s",
		httpurl(conf.MetaAddr),
		url.QueryEscape(conf.AppID),
		url.QueryEscape(conf.Cluster),
		url.QueryEscape(normalizeNamespace(namespace)),
		url.QueryEscape(releaseKey),
		getLocalIP())
}

func strIn(slice []string, target string) bool {
	for _, v := range slice {
		if v == target {
			return true
		}
	}
	return false
}

func main() {
	// Example usage:
	conf := &Conf{
		MetaAddr: "https://config-service.example.com",
		AppID:    "myApp",
		Cluster:  "default",
	}

	// Construct notification URL
	notifications := `[{"namespaceName":"application","notificationId":100}]`
	fmt.Println("Notification URL:", notificationURL(conf, notifications))

	// Construct configuration fetch URL
	namespace := "application.properties"
	releaseKey := "20191225-1345"
	fmt.Println("Configuration Fetch URL:", configURL(conf, namespace, releaseKey))

	// Check if a string is in a slice
	slice := []string{"apple", "banana", "cherry"}
	target := "banana"
	fmt.Printf("Is '%s' in the slice? %v\n", target, strIn(slice, target))
}
