package main

import "fmt"

func merge(left, right []int) ([]int, []int) {
	if left[0] <= right[0] && left[1] >= right[1] {
		return left, nil
	} else if right[0] <= left[0] && right[1] >= left[1] {
		return right, nil
	} else if left[0] <= right[0] && left[1] >= right[0] && left[1] <= right[1] {
		return []int{left[0], right[1]}, nil
	} else if right[0] <= left[0] && right[1] >= left[0] && right[1] <= left[1] {
		return []int{right[0], left[1]}, nil
	} else if left[1] < right[0] {
		return left, right
	} else {
		return right, left
	}
}

func appendLeft(result [][]int, left [][]int) [][]int {
	return append(result, left...)
}

func insertInterval(intervals [][]int, newInterval []int) [][]int {
	result := make([][]int, 0, len(intervals)+1)
	for i := 0; i < len(intervals); i++ {
		a, b := merge(intervals[i], newInterval)

		if b == nil {
			newInterval = a
		} else {
			result = append(result, a)
			newInterval = b
			if intervals[i][0] == newInterval[0] {
				return appendLeft(result, intervals[i:])
			}
		}
	}
	return append(result, newInterval)
}

func main() {
	// Test cases
	testCases := []struct {
		intervals   [][]int
		newInterval []int
		expected    [][]int
	}{
		{intervals: [][]int{{1, 3}, {6, 9}}, newInterval: []int{2, 5}, expected: [][]int{{1, 5}, {6, 9}}},
		{intervals: [][]int{{1, 2}, {3, 5}, {6, 7}, {8, 10}, {12, 16}}, newInterval: []int{4, 8}, expected: [][]int{{1, 2}, {3, 10}, {12, 16}}},
		{intervals: [][]int{}, newInterval: []int{5, 7}, expected: [][]int{{5, 7}}},
		{intervals: [][]int{{1, 5}}, newInterval: []int{2, 3}, expected: [][]int{{1, 5}}},
		{intervals: [][]int{{1, 5}}, newInterval: []int{6, 8}, expected: [][]int{{1, 5}, {6, 8}}},
	}

	for _, tc := range testCases {
		result := insertInterval(tc.intervals, tc.newInterval)
		fmt.Printf("Intervals: %v, New Interval: %v, Result: %v, Expected: %v\n", tc.intervals, tc.newInterval, result, tc.expected)
	}
}
