	db, err := gorm.Open(sqlite.Open("users.db"), &gorm.Config{})
	if err != nil {
		log.Fatalf("failed to connect database: %v", err)
	}
	db.AutoMigrate(&Users{})
	return db
}

func CreateUser(db *gorm.DB, user Users) error {
	result := db.Create(&user)
	return result.Error
}

func GetUserByID(db *gorm.DB, id string) (Users, error) {
	var user Users
	result := db.First(&user, "id = ?", id)
	return user, result.Error
}

func UpdateUser(db *gorm.DB, id string, newData Users) error {
	var user Users
	result := db.First(&user, "id = ?", id)
	if result.Error != nil {
		return result.Error
	}
	result = db.Model(&user).Updates(newData)
	return result.Error
}

func DeleteUser(db *gorm.DB, id string) error {
	var user Users
	result := db.Delete(&user, "id = ?", id)
	return result.Error
}

func main() {
	db := InitializeDB()

	// Create a new user
	newUser := Users{ID: "1", Username: "johndoe", Password: "password123", Email: "john@example.com"}
