// IsLeapYear determines if the given year is a leap year.
func IsLeapYear(year int) bool {
	if year%4 == 0 {
		if year%100 == 0 {
			return year%400 == 0
		}
		return true
	}
	return false
}

// MonthToNumber converts the name of the month to its corresponding number.
func MonthToNumber(month string) int {
	months := map[string]int{
		"january":   1,
		"february":  2,
		"march":     3,
		"april":     4,
		"may":       5,
		"june":      6,
		"july":      7,
		"august":    8,
		"september": 9,
		"october":   10,
		"november":  11,
		"december":  12,
	}
	return months[strings.ToLower(month)]
}

// DaysInMonth returns the number of days in the given month for the specified year.
func DaysInMonth(month, year int) int {
	switch month {
	case 1, 3, 5, 7, 8, 10, 12:
		return 31
	case 4, 6, 9, 11:
		return 30
	case 2:
		if IsLeapYear(year) {
			return 29
		}
		return 28
	default:
		return 0 // Invalid month
	}
}

func main() {
	var day int
	var monthName string
	var year int

	fmt.Scanln(&day, &monthName, &year)

	month := MonthToNumber(monthName)
	days := DaysInMonth(month, year)

	fmt.Printf("The number of days in %s %d is %d.\n", monthName, year, days)
}

// Test cases to verify the solution correctness
func main() {
	fmt.Println(IsLeapYear(2020)) // true
	fmt.Println(IsLeapYear(1900)) // false
	fmt.Println(IsLeapYear(2000)) // true

	fmt.Println(MonthToNumber("February")) // 2
	fmt.Println(MonthToNumber("November")) // 11

	fmt.Println(DaysInMonth(2, 2020)) // 29
	fmt.Println(DaysInMonth(2, 2021)) // 28
	fmt.Println(DaysInMonth(11, 2021)) // 30
}
