// ExecuteCommand takes a command string, executes it, and returns the standard output,
// standard error, and an error if the execution fails.
func ExecuteCommand(command string) (stdoutStr string, stderrStr string, err error) {
	// Split the command into command name and arguments
	cmdArgs := strings.Fields(command)
	cmd := exec.Command(cmdArgs[0], cmdArgs[1:]...)

	// Create buffers to capture standard output and standard error
	var stdoutBuf, stderrBuf bytes.Buffer
	cmd.Stdout = &stdoutBuf
	cmd.Stderr = &stderrBuf

	// Execute the command
	err = cmd.Run()
	stdoutStr = stdoutBuf.String()
	stderrStr = stderrBuf.String()

	// If there is an error executing the command, wrap it with a meaningful message
	if err != nil {
		err = fmt.Errorf("failed to execute command '%s': %v", command, err)
	}

	return stdoutStr, stderrStr, err
}

func main() {
