	"github.com/dim4egster/qmallgo/codec"
	"github.com/dim4egster/qmallgo/codec/linearcodec"
	"github.com/dim4egster/qmallgo/utils/wrappers"
)

var Codec codec.Manager

func init() {
	gc := linearcodec.NewCustomMaxLength(math.MaxInt32)
	Codec = codec.NewManager(math.MaxInt32)

	// Initialize codec with space for transaction types
	gc.SkipRegistrations(10)

	errs := wrappers.Errs{}
	errs.Add(
		Codec.RegisterCodec(1, gc),
	)
	if errs.Errored() {
		panic(errs.Err)
	}
}

type Transaction struct {
	ID      string
	Type    int
	Version int
	Payload string
}

func RegisterTransactionType(typeID int, version int) error {
	gc := linearcodec.NewCustomMaxLength(math.MaxInt32)
	return Codec.RegisterCodec(version, gc)
}

func EncodeTransaction(tx Transaction) ([]byte, error) {
	return Codec.Marshal(tx.Version, &tx)
}

func DecodeTransaction(b []byte, version int) (*Transaction, error) {
	tx := &Transaction{}
	_, err := Codec.Unmarshal(b, version, tx)
	if err != nil {
		return nil, err
	}
	return tx, nil
}

func main() {
	// Register a new transaction type with version 1
	err := RegisterTransactionType(1, 1)
	if err != nil {
		panic(err)
	}

	// Create a new transaction
	tx := Transaction{
		ID:      "tx123",
		Type:    1,
		Version: 1,
		Payload: "Payload of the transaction",
	}

	// Encode the transaction
	encodedTx, err := EncodeTransaction(tx)
	if err != nil {
		panic(err)
	}
	fmt.Printf("Encoded Transaction: %x\n", encodedTx)

	// Decode the transaction
	decodedTx, err := DecodeTransaction(encodedTx, tx.Version)
	if err != nil {
		panic(err)
	}
	fmt.Printf("Decoded Transaction: %+v\n", decodedTx)
}
