	"sort"
)

// UniquePermutations returns all unique permutations of the given slice of integers.
// nums: Slice of integers that may contain duplicates.
// The function returns a slice of slices, with each inner slice representing a unique permutation.
func UniquePermutations(nums []int) (ans [][]int) {
	sort.Ints(nums) // Sort the slice to handle duplicates.
	n := len(nums)
	perm := make([]int, 0, n) // Temporary slice to store current permutation.
	vis := make([]bool, n)    // Visited array to keep track of used elements.

	var backtrack func(int)
	backtrack = func(idx int) {
		if idx == n {
			ans = append(ans, append([]int(nil), perm...)) // Append a copy of perm to ans.
			return
		}
		for i, v := range nums {
			if vis[i] || (i > 0 && !vis[i-1] && v == nums[i-1]) {
				continue // Skip duplicates.
			}
			perm = append(perm, v) // Choose the element.
			vis[i] = true          // Mark as visited.
			backtrack(idx + 1)     // Recurse with the next element.
			vis[i] = false         // Backtrack: unmark the element.
			perm = perm[:len(perm)-1] // Remove the element.
		}
	}
	backtrack(0) // Start the backtracking algorithm.
	return
}

func main() {
	// Test cases to verify the solution correctness.
	testCases := [][]int{
		{1, 2, 3},
		{1, 1, 2},
		{1, 1, 1},
	}

	for _, nums := range testCases {
		fmt.Printf("Unique permutations of %v: %v\n", nums, UniquePermutations(nums))
	}
}
