// GD represents a generic data field in an address.
type GD struct {
	Value string `json:"$t"`
}

// Address format.
type Address struct {
	Rel         string `json:"rel,omitempty"`
	Full        GD     `json:"gd$formattedAddress,omitempty"`
	POBox       GD     `json:"gd$pobox,omitempty"`
	Street      GD     `json:"gd$street,omitempty"`
	City        GD     `json:"gd$city,omitempty"`
	StateOrProv GD     `json:"gd$region,omitempty"`
	PostalCode  GD     `json:"gd$postcode,omitempty"`
	Country     GD     `json:"gd$country,omitempty"`
}

// FormatAddress formats the address into a single string.
func FormatAddress(addr Address) string {
	var parts []string
	if addr.Full.Value != "" {
		parts = append(parts, addr.Full.Value)
	} else {
		if addr.Street.Value != "" {
			parts = append(parts, addr.Street.Value)
		}
		if addr.City.Value != "" {
			parts = append(parts, addr.City.Value)
		}
		if addr.StateOrProv.Value != "" {
			parts = append(parts, addr.StateOrProv.Value)
		}
		if addr.PostalCode.Value != "" {
			parts = append(parts, addr.PostalCode.Value)
		}
		if addr.Country.Value != "" {
			parts = append(parts, addr.Country.Value)
		}
	}
	return fmt.Sprintf("%s", string.Join(parts, ", "))
}

// ParseAddresses parses a JSON string into a slice of Address objects.
func ParseAddresses(jsonData string) ([]Address, error) {
	var addresses []Address
	err := json.Unmarshal([]byte(jsonData), &addresses)
	if err != nil {
		return nil, err
	}
	return addresses, nil
}

func main() {
	jsonData := `[
		{
			"gd$formattedAddress": {"$t": "1600 Amphitheatre Parkway, Mountain View, CA 94043, USA"},
			"gd$street": {"$t": "1600 Amphitheatre Parkway"},
