// Read fetches data from a given URL or file path and returns the data as a byte slice.
// It returns an error if the URL is invalid, if there is an unexpected EOF, or if there is a file system error.
func Read(path string) ([]byte, error) {
	if path == "" {
		return nil, errors.New("path cannot be empty")
	}

	// Check if the path is a URL or a file path
	if isURL(path) {
		resp, err := http.Get(path)
		if err != nil {
			return nil, err
		}
		defer resp.Body.Close()

		return ioutil.ReadAll(resp.Body)
	}

	// If not a URL, assume it's a file path
	return ioutil.ReadFile(path)
}

// isURL checks if the given path is a URL.
func isURL(path string) bool {
	_, err := http.NewRequest(http.MethodGet, path, nil)
	return err == nil
}

