package main

import (
	"fmt"
)

type Any interface{}

type Queue[T Any] struct {
	queue []T
}

func NewQueue[T Any]() *Queue[T] {
	return &Queue[T]{
		queue: make([]T, 0),
	}
}

func (q *Queue[T]) EnQueue(v T) {
	q.queue = append(q.queue, v)
}

func (q *Queue[T]) DeQueue() T {
	if len(q.queue) == 0 {
		return *new(T)
	}
	v := q.queue[0]
	q.queue = q.queue[1:]
	return v
}

func (q *Queue[T]) Len() int {
	return len(q.queue)
}

func (q *Queue[T]) Peek() T {
	if len(q.queue) == 0 {
		return *new(T)
	}
	return q.queue[0]
}

func (q *Queue[T]) IsEmpty() bool {
	return len(q.queue) == 0
}

func main() {
	// Test cases
	intQueue := NewQueue[int]()
	intQueue.EnQueue(1)
	intQueue.EnQueue(2)
	fmt.Println("DeQueue:", intQueue.DeQueue()) // Output: DeQueue: 1
	fmt.Println("Peek:", intQueue.Peek())       // Output: Peek: 2
	fmt.Println("Len:", intQueue.Len())         // Output: Len: 1
	fmt.Println("IsEmpty:", intQueue.IsEmpty()) // Output: IsEmpty: false
	intQueue.DeQueue()
	fmt.Println("IsEmpty:", intQueue.IsEmpty()) // Output: IsEmpty: true

	stringQueue := NewQueue[string]()
	stringQueue.EnQueue("hello")
	stringQueue.EnQueue("world")
	fmt.Println("DeQueue:", stringQueue.DeQueue()) // Output: DeQueue: hello
	fmt.Println("Peek:", stringQueue.Peek())       // Output: Peek: world
	fmt.Println("Len:", stringQueue.Len())         // Output: Len: 1
	fmt.Println("IsEmpty:", stringQueue.IsEmpty()) // Output: IsEmpty: false
	stringQueue.DeQueue()
	fmt.Println("IsEmpty:", stringQueue.IsEmpty()) // Output: IsEmpty: true
}
