package main

import (
	"bufio"
	"fmt"
	"os"
	"strconv"
	"strings"
)

var wrtr = bufio.NewWriterSize(os.Stdout, 10000000)
var rdr = bufio.NewScanner(os.Stdin)

func gs() string { rdr.Scan(); return rdr.Text() }
func gi() int {
	i, e := strconv.Atoi(gs())
	if e != nil {
		panic(e)
	}
	return i
}
func gbs() []byte { return []byte(gs()) }

func nextBytePermutation(a []byte) bool {
	la := len(a)
	var i, j int
	for i = la - 2; i >= 0; i-- {
		if a[i] < a[i+1] {
			break
		}
	}
	if i < 0 {
		i, j = 0, la-1
		for i < j {
			a[i], a[j] = a[j], a[i]
			i++
			j--
		}
		return false
	}
	for j = la - 1; j >= 0; j-- {
		if a[i] < a[j] {
			break
		}
	}
	a[i], a[j] = a[j], a[i]
	i, j = i+1, la-1
	for i < j {
		a[i], a[j] = a[j], a[i]
		i++
		j--
	}
	return true
}

func main() {
	defer wrtr.Flush()
	rdr.Split(bufio.ScanWords)
	rdr.Buffer(make([]byte, 1024), 1000000000)

	T := gi()
	for tt := 1; tt <= T; tt++ {
		s := gbs()
		if !nextBytePermutation(s) {
			strings.Sort(s)
		}
		ans := string(s)
		fmt.Fprintf(wrtr, "Case #%v: %v\n", tt, ans)
	}
}
