// GetWebData makes an HTTP GET request to the specified URL with optional headers.
func GetWebData(url string, headers map[string]string) (string, error) {
	client := &http.Client{}
	req, err := http.NewRequest("GET", url, nil)
	if err != nil {
		return "", err
	}

	for key, value := range headers {
		req.Header.Add(key, value)
	}

	resp, err := client.Do(req)
	if err != nil {
		return "", err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return "", errors.New("non-200 HTTP status code received")
	}

	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		return "", err
	}

	return string(body), nil
}

// GetWebData2 makes an HTTP GET request to the specified URL with optional parameters, headers, and cookies.
func GetWebData2(urlStr string, params map[string]string, headers map[string]string, cookies []*http.Cookie) (int, string, error) {
	client := &http.Client{}
	reqURL, err := url.Parse(urlStr)
	if err != nil {
		return 0, "", err
	}

	q := reqURL.Query()
	for key, value := range params {
		q.Add(key, value)
	}
	reqURL.RawQuery = q.Encode()

	req, err := http.NewRequest("GET", reqURL.String(), nil)
	if err != nil {
		return 0, "", err
	}

	for key, value := range headers {
		req.Header.Add(key, value)
	}

	for _, cookie := range cookies {
		req.AddCookie(cookie)
	}

	resp, err := client.Do(req)
	if err != nil {
		return 0, "", err
	}
	defer resp.Body.Close()

	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		return resp.StatusCode, "", err
	}

	return resp.StatusCode, string(body), nil
}

// Test cases for GetWebData
func TestGetWebData(t *testing.T) {
	weburl := "http://www.example.com"
	resp, err := GetWebData(weburl, nil)
	if err != nil {
		t.Errorf("Test failed, error received: %s", err)
	}

	if len(resp) == 0 {
		t.Errorf("The result is empty, but we expect not empty")
	}
}

// Test cases for GetWebData2
