	weburl := "http://www.example.com"
	data := make(map[string]string)
	status, resp, err := GetWebData2(weburl, data, nil, nil)
	if status != 200 || err != nil {
		t.Errorf("Test failed. status:%d, err:%s", status, err)
	}

	if len(resp) == 0 {
