func countHomogenous(s string) (ans int) {
	const modulo = 1000000007
	var prev byte
	var start, i, l = 0, 0, len(s)

	for i = 0; i < l; i++ {
		if prev != s[i] {
			ans = (ans + ((1+i-start)*(i-start)/2) % modulo) % modulo
			start = i
			prev = s[i]
		}
	}

	ans = (ans + ((1+l-start)*(l-start)/2) % modulo) % modulo
	return ans
}

func main() {
	// Test cases
	fmt.Println(countHomogenous("a")) // 1
	fmt.Println(countHomogenous("aa")) // 3
	fmt.Println(countHomogenous("abc")) // 3
	fmt.Println(countHomogenous("aaa")) // 6
	fmt.Println(countHomogenous("zzzzz")) // 15
