package main

import (
	"context"
	"sync"
	"time"

	v1 "k8s.io/api/core/v1"
	policyv1beta1 "k8s.io/api/policy/v1beta1"
	kerrors "k8s.io/apimachinery/pkg/api/errors"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/fields"
	"k8s.io/apimachinery/pkg/util/wait"
	"k8s.io/client-go/kubernetes"
	"k8s.io/klog/v2"
)

const waitForPodTerminationCheckPeriod = 10 * time.Second

type NodeDrainer struct {
	client kubernetes.Interface
	node   *v1.Node
}

func NewNodeDrainer(client kubernetes.Interface, node *v1.Node) *NodeDrainer {
	return &NodeDrainer{
		client: client,
		node:   node,
	}
}

func (d *NodeDrainer) DrainNode(ctx context.Context) error {
	podsToEvict, err := d.getPodsForDeletion(ctx)
	if err != nil {
		klog.Error(err)
		return err
	}

	if err = d.evictPods(ctx, podsToEvict); err != nil {
		klog.Error(err)
		return err
	}

	klog.Infof("node %v successfully drained", d.node.GetName())
	return nil
}

func (d *NodeDrainer) getPodsForDeletion(ctx context.Context) (*v1.PodList, error) {
	podList, err := d.client.CoreV1().Pods(metav1.NamespaceAll).List(ctx, metav1.ListOptions{
		FieldSelector: fields.SelectorFromSet(fields.Set{
			"spec.nodeName": d.node.GetName(),
		}).String()})
	if err != nil {
		return nil, err
	}
	return podList, nil
}

func (d *NodeDrainer) evictPods(ctx context.Context, podList *v1.PodList) error {
	var wg sync.WaitGroup
	errors := make(chan error, len(podList.Items))
	defer close(errors)

	for i := range podList.Items {
		wg.Add(1)
		go d.evictPod(ctx, &podList.Items[i], &wg, errors)
	}

	wg.Wait()

	select {
	case err := <-errors:
		klog.Error(err)
		return err
	default:
		return nil
	}
}

func (d *NodeDrainer) evictPod(ctx context.Context, pod *v1.Pod, wg *sync.WaitGroup, errors chan error) {
	defer wg.Done()

	eviction := &policyv1beta1.Eviction{
		ObjectMeta: metav1.ObjectMeta{
			Name:      pod.Name,
			Namespace: pod.Namespace,
		},
		DeleteOptions: &metav1.DeleteOptions{},
	}

	if err := d.client.PolicyV1beta1().Evictions(pod.Namespace).Evict(ctx, eviction); err != nil {
		klog.Error(err)
		errors <- err
		return
	}

	if err := d.waitForDelete(ctx, pod); err != nil {
		klog.Error(err)
		errors <- err
		return
	}
}

func (d *NodeDrainer) waitForDelete(ctx context.Context, pod *v1.Pod) error {
	return wait.PollImmediateInfinite(waitForPodTerminationCheckPeriod, func() (bool, error) {
		retPod, err := d.client.CoreV1().Pods(pod.Namespace).Get(ctx, pod.Name, metav1.GetOptions{})
		if kerrors.IsNotFound(err) || (retPod != nil && retPod.ObjectMeta.UID != pod.ObjectMeta.UID) {
			return true, nil
		}
		if err != nil {
			klog.Error(err)
			return false, err
		}
		return false, nil
	})
}

