package main

import (
	"fmt"
	"github.com/gomodule/redigo/redis"
	"os"
	"time"
)

var (
	// RedisPool is a pool of Redis connections.
	RedisPool *redis.Pool
)

// Connect initializes the Redis connection pool.
func Connect(maxIdle int, idleTimeout time.Duration) {
	redisAddress := os.Getenv("REDIS_ADDR")
	if redisAddress == "" {
		redisAddress = "127.0.0.1:6379"
	}

	RedisPool = &redis.Pool{
		Dial: func() (redis.Conn, error) {
			return redis.Dial("tcp", redisAddress)
		},
		MaxIdle:     maxIdle,
		IdleTimeout: idleTimeout,
	}
}

// SetValue sets a key-value pair in Redis with an expiration time.
func SetValue(key string, value string, expiration time.Duration) error {
	conn := RedisPool.Get()
	defer conn.Close()

	_, err := conn.Do("SETEX", key, int(expiration.Seconds()), value)
	return err
}

// GetValue retrieves the value for a given key from Redis.
func GetValue(key string) (string, error) {
	conn := RedisPool.Get()
	defer conn.Close()

	value, err := redis.String(conn.Do("GET", key))
	if err == redis.ErrNil {
		return "", fmt.Errorf("key not found: %s", key)
	} else if err != nil {
		return "", err
	}

	return value, nil
}

func main() {
	// Initialize the Redis connection pool.
	Connect(3, 240*time.Second)

	// Test cases
	key := "testKey"
	value := "testValue"
	expiration := 10 * time.Second

	// Set a value in Redis.
	err := SetValue(key, value, expiration)
	if err != nil {
		fmt.Println("Error setting value:", err)
		return
	}
	fmt.Println("Value set successfully")

	// Get the value from Redis.
	retrievedValue, err := GetValue(key)
	if err != nil {
		fmt.Println("Error getting value:", err)
		return
	}
	fmt.Printf("Retrieved value: %s\n", retrievedValue)

	// Wait for the key to expire and try to get it again.
	time.Sleep(expiration + 1*time.Second)
	_, err = GetValue(key)
	if err != nil {
		fmt.Println("Expected error after expiration:", err)
	}
}
