// CloudFormationStacks manages AWS CloudFormation stacks.
type CloudFormationStacks struct{}

// cloudFormationStack represents a CloudFormation stack.
type cloudFormationStack struct {
	id   string
	name string
}

// ARN returns the Amazon Resource Name of the stack.
func (p cloudFormationStack) ARN() string {
	return p.id
}

// ResourceKey returns the name of the stack.
func (p cloudFormationStack) ResourceKey() string {
	return p.name
}

// delete removes the CloudFormation stack.
func (p cloudFormationStack) delete(svc *cf.CloudFormation) error {
	input := &cf.DeleteStackInput{StackName: aws.String(p.name)}
	if _, err := svc.DeleteStack(input); err != nil {
		return err
	}
	return nil
}

// ListAll lists all CloudFormation stacks in the given AWS account and region.
func (cfs *CloudFormationStacks) ListAll(sess *session.Session, acct, region string) ([]*cloudFormationStack, error) {
	svc := cf.New(sess, aws.NewConfig().WithRegion(region))
	var stacks []*cloudFormationStack

	err := svc.ListStacksPages(&cf.ListStacksInput{}, func(page *cf.ListStacksOutput, _ bool) bool {
		for _, stack := range page.StackSummaries {
			stacks = append(stacks, &cloudFormationStack{
				id:   aws.StringValue(stack.StackId),
				name: aws.StringValue(stack.StackName),
			})
		}
		return true
	})

	return stacks, errors.Wrapf(err, "couldn't describe cloud formation stacks for %q in %q", acct, region)
}

// MarkAndSweep marks stacks for deletion and deletes them.
func (cfs *CloudFormationStacks) MarkAndSweep(sess *session.Session, acct, region string) error {
	svc := cf.New(sess, &aws.Config{Region: aws.String(region)})
	stacks, err := cfs.ListAll(sess, acct, region)
	if err != nil {
		return err
	}

	var toDelete []*cloudFormationStack
	for _, stack := range stacks {
		// Custom logic to determine if a stack should be deleted.
		// For example, delete stacks that are not in use or based on naming conventions.
		// This example simply marks all stacks for deletion.
		toDelete = append(toDelete, stack)
		klog.Warningf("Marked for deletion: %s", stack.ARN())
	}

	for _, stack := range toDelete {
		if err := stack.delete(svc); err != nil {
			klog.Warningf("Deletion failed for %s: %v", stack.ARN(), err)
		} else {
			klog.Infof("Deleted stack: %s", stack.ARN())
		}
	}

	return nil
}

