package main

import (
	"fmt"
	"io/ioutil"
	"net/http"
	"strconv"
	"strings"
)

// Logs retrieves logs from the Cloudflare API for a given zone within a specified one-hour time frame.
func Logs(zoneID, email, apiKey, date string, hour int) (string, error) {
	client := &http.Client{}

	apiURL := "https://api.cloudflare.com/client/v4/zones/" + zoneID + "/logs/received?"
	var hour2 int
	var date2 string = date

	if hour == 23 {
		hour2 = 0
		days := strings.Split(date2, "-")
		day := days[2]
		intDay, err := strconv.Atoi(day)
		if err != nil {
			return "", err
		}
		intDay++
		strDay := strconv.Itoa(intDay)

		days2 := []string{days[0], days[1], strDay}
		date2 = strings.Join(days2, "-")
	} else {
		hour2 = hour + 1
	}

	strHour := fmt.Sprintf("%02d", hour)
	strHour2 := fmt.Sprintf("%02d", hour2)

	fields := "CacheCacheStatus,CacheResponseBytes,CacheResponseStatus,CacheTieredFill,ClientASN,ClientCountry,ClientDeviceType,ClientIP,ClientIPClass,ClientRequestBytes,ClientRequestHost,ClientRequestMethod,ClientRequestPath,ClientRequestProtocol,ClientRequestReferer,ClientRequestURI,ClientSSLProtocol,EdgeColoID,EdgePathingOp,EdgePathingSrc,EdgePathingStatus,EdgeRateLimitAction,EdgeRateLimitID,EdgeRequestHost,EdgeResponseStatus,EdgeServerIP,OriginIP,OriginResponseStatus,OriginResponseTime,ParentRayID,RayID,SecurityLevel,WAFAction,WAFFlags,WAFMatchedVar,WAFProfile,WAFRuleID,WAFRuleMessage"

	urlParts := []string{apiURL, "start=", date, "T", strHour, ":00:00Z", "&end=", date2, "T", strHour2, ":00:00Z", "&fields=", fields}
	url := strings.Join(urlParts, "")

	req, err := http.NewRequest("GET", url, nil)
	if err != nil {
		return "", err
	}

	req.Header.Add("X-Auth-Email", email)
	req.Header.Add("X-Auth-Key", apiKey)
	resp, err := client.Do(req)
	if err != nil {
		return "", err
	}
	defer resp.Body.Close()

	text, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		return "", err
	}

	return string(text), nil
}

func main() {
	zoneID := "ZONE_ID"
	email := "cf-mail"
	apiKey := "cf-key"
	date := "2023-04-01"
	hour := 23

	logs, err := Logs(zoneID, email, apiKey, date, hour)
	if err != nil {
		fmt.Printf("Error fetching logs: %v\n", err)
		return
	}

	fmt.Println(logs)
}
