Design a RESTful API server in Go that provides endpoints to manage user data. The server should have the following functionalities:

1. An endpoint to return a simple welcome message at the root path.
2. An endpoint to retrieve a user's details by their ID (UserA).
3. An endpoint to create a new user with a name and age (UserB).

The server should handle JSON data for both input and output. The user data should be stored in memory for the purpose of this exercise.

The `model` package contains two structs, `UserA` and `UserB`, with the following definitions:

```go
package model

type UserA struct {
	ID   string `json:"id"`
	Name string `json:"name"`
	Age  int    `json:"age"`
}

func GetUserA(id string) (*UserA, error) {
	// This function simulates fetching a user by ID from a data store.
	// For this exercise, return a dummy user if the ID matches "123", otherwise return an error.
	if id == "123" {
		return &UserA{ID: id, Name: "John Doe", Age: 30}, nil
	}
	return nil, fmt.Errorf("user not found")
}

type UserB struct {
	Name string `json:"name"`
	Age  int    `json:"age"`
}

func (u *UserB) Create() (*UserB, error) {
	// This function simulates creating a new user in a data store.
	// For this exercise, simply return the user passed in.
	return u, nil
}
```

Write the Go code for the server with the following endpoints:

- `GET /`: Should return a welcome message.
- `GET /usera/{id}`: Should return the details of UserA with the specified ID in JSON format.
- `POST /userb`: Should accept a JSON payload to create a new UserB and return the created user details in JSON format.

Include error handling for cases such as user not found or bad input data. Also, provide test cases to verify the correctness of the implemented endpoints.

output:
```go
package main

import (
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"strings"

	"emahiro/gotester/model"
)

func main() {
	http.HandleFunc("/", Index)
	http.HandleFunc("/usera/", GetUserA)
	http.HandleFunc("/userb", CreateUserB)

	log.Fatal(http.ListenAndServe(":8080", nil))
}

// Index returns a welcome message at the root path.
func Index(w http.ResponseWriter, r *http.Request) {
	w.WriteHeader(http.StatusOK)
	w.Write([]byte("Welcome to the User Management API"))
}

// GetUserA retrieves a user's details by their ID.
func GetUserA(w http.ResponseWriter, r *http.Request) {
	id := strings.TrimPrefix(r.URL.Path, "/usera/")
	if id == "" {
		http.Error(w, "User ID is required", http.StatusBadRequest)
		return
	}

	u, err := model.GetUserA(id)
	if err != nil {
		http.Error(w, err.Error(), http.StatusNotFound)
		return
	}

	b, err := json.Marshal(u)
	if err != nil {
		http.Error(w, "Failed to encode user data to JSON", http.StatusInternalServerError)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusOK)
	w.Write(b)
}

// CreateUserB creates a new user with a name and age.
func CreateUserB(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Invalid request method", http.StatusMethodNotAllowed)
		return
	}

	var u model.UserB
	if err := json.NewDecoder(r.Body).Decode(&u); err != nil {
		http.Error(w, "Invalid user data", http.StatusBadRequest)
		return
	}

	createdUser, err := u.Create()
	if err != nil {
		http.Error(w, "Failed to create user", http.StatusInternalServerError)
		return
	}

	b, err := json.Marshal(createdUser)
	if err != nil {
		http.Error(w, "Failed to encode user data to JSON", http.StatusInternalServerError)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusCreated)
	w.Write(b)
}
