// parseArgs parses command-line arguments and returns a map of flags to values.
func parseArgs(args []string) map[string]string {
	flags := make(map[string]string)
	var lastFlag string

	for _, arg := range args {
		if arg[0] == '-' {
			lastFlag = arg[1:]
		} else if lastFlag != "" {
			flags[lastFlag] = arg
			lastFlag = ""
		}
	}

	return flags
}

// printSortedMap prints the keys of the map in sorted order along with their values.
func printSortedMap(m map[string]string) {
	keys := make([]string, 0, len(m))
	for k := range m {
		keys = append(keys, k)
	}
	sort.Strings(keys)

	for _, k := range keys {
		fmt.Printf("%s: %s\n", k, m[k])
	}
}

func main() {
	args := os.Args[1:] // Ignore the program name
	flags := parseArgs(args)
	printSortedMap(flags)
}

