)

// maxLevelSum finds the level of a binary tree with the maximum sum of its nodes' values.
// If there are multiple levels with the same maximum sum, it returns the smallest level number.
func maxLevelSum(root *TreeNode) int {
	if root == nil {
		return 0
	}

	maxSum := root.Val
	maxLevel := 1
	currentLevel := 1
	queue := []*TreeNode{root}

	for len(queue) > 0 {
		levelSize := len(queue)
		levelSum := 0

		for i := 0; i < levelSize; i++ {
			node := queue[0]
			queue = queue[1:]
			levelSum += node.Val

			if node.Left != nil {
				queue = append(queue, node.Left)
			}
			if node.Right != nil {
				queue = append(queue, node.Right)
			}
		}

		if levelSum > maxSum {
			maxSum = levelSum
			maxLevel = currentLevel
		}

		currentLevel++
	}

	return maxLevel
}

func main() {
	// Test cases
	root := &TreeNode{Val: 1,
		Left: &TreeNode{Val: 7,
			Left:  &TreeNode{Val: 7},
			Right: &TreeNode{Val: -8}},
		Right: &TreeNode{Val: 0},
	}

	fmt.Println(maxLevelSum(root)) // Expected output: 2
}
