}

// GetTimeHandler handles the GET requests to the /api/time endpoint.
func GetTimeHandler(w http.ResponseWriter, r *http.Request) {
	// Parse the timezone from the query parameter.
	timezone := r.URL.Query().Get("timezone")

	// Set the content type to application/json.
	w.Header().Set("Content-Type", "application/json")

	// If timezone is empty or invalid, return an error.
	if timezone == "" {
		http.Error(w, `{"error": "Timezone parameter is required"}`, http.StatusBadRequest)
		return
	}

	loc, err := time.LoadLocation(timezone)
	if err != nil {
		http.Error(w, `{"error": "Invalid timezone"}`, http.StatusBadRequest)
		return
	}

	// Get the current time in the specified timezone.
	currentTime := time.Now().In(loc)

	// Create the response object.
	response := TimeResponse{
		Time: currentTime.Format(time.RFC3339),
	}

	// Encode the response as JSON and send it.
	json.NewEncoder(w).Encode(response)
}

func main() {
	http.HandleFunc("/api/time", GetTimeHandler)
	http.ListenAndServe(":8080", nil)
