package main

import (
	"fmt"
	"sync"
	"testing"

	"github.com/go-redis/redis"
)

// Singleton pattern for Redis client manager
var (
	once     sync.Once
	instance *redis.Client
)

// GetInstance returns a pointer to the Redis client, initializing it if necessary.
func GetInstance(url string) *redis.Client {
	once.Do(func() {
		if instance == nil {
			instance = redis.NewClient(&redis.Options{
				Addr: url,
				DB:   0,
			})
		}
	})
	return instance
}

// Test cases to verify the solution
func TestRedisClientSingleton(t *testing.T) {
	var wg sync.WaitGroup
	url := "localhost:6379"
	clientCount := 100
	instances := make([]*redis.Client, clientCount)

	// Initialize multiple instances concurrently
	for i := 0; i < clientCount; i++ {
		wg.Add(1)
		go func(index int) {
			defer wg.Done()
			instances[index] = GetInstance(url)
		}(i)
	}

	wg.Wait()

	// Check that all instances are the same
	for i := 1; i < clientCount; i++ {
		if instances[i] != instances[0] {
			t.Errorf("GetInstance returned different instances: got %v want %v", instances[i], instances[0])
		}
	}

	// Check that the client is only initialized once
	if instance == nil {
		t.Errorf("GetInstance did not initialize the Redis client")
	}
}

func main() {
	// Run the test case
	fmt.Println("Starting test...")
	TestRedisClientSingleton(&testing.T{})
	fmt.Println("Test finished.")
}
