package main

import (
	"bufio"
	"errors"
	"fmt"
	"log"
	"net"
	"strings"
	"time"

	"github.com/tuannkhoi/Distributed-Cache/cache"
)

const (
	CMDSet = "SET"
	CMDGet = "GET"
	CMDDel = "DEL"
	CMDHas = "HAS"
)

type Message struct {
	Command string
	Key     string
	Value   string
	TTL     time.Duration
}

func parseMessage(rawCmd []byte) (*Message, error) {
	parts := strings.Fields(string(rawCmd))
	if len(parts) < 2 {
		return nil, errors.New("invalid command format")
	}

	msg := &Message{
		Command: parts[0],
		Key:     parts[1],
	}

	switch msg.Command {
	case CMDSet:
		if len(parts) < 3 {
			return nil, errors.New("SET command requires a value")
		}
		msg.Value = parts[2]
		if len(parts) == 4 {
			ttl, err := time.ParseDuration(parts[3] + "s")
			if err != nil {
				return nil, fmt.Errorf("invalid TTL: %s", err)
			}
			msg.TTL = ttl
		}
	case CMDGet, CMDDel, CMDHas:
		// No additional processing needed for these commands
	default:
		return nil, fmt.Errorf("unknown command: %s", msg.Command)
	}

	return msg, nil
}

func main() {
	// Initialize the cache (using a simple in-memory cache for this example)
	c := cache.NewInMemoryCache()

	// Define server options
	opts := ServerOpts{
		ListenAddr: ":8080",
		IsLeader:   true,
	}

	// Create a new server with the given options and cache
	server := NewServer(opts, c)

	// Start the server
	if err := server.Start(); err != nil {
		log.Fatalf("server failed to start: %s", err)
	}
}

// Test cases to verify the solution correctness
func test() {
	// Assuming we have a function to connect to the server and send commands
	conn, err := net.Dial("tcp", "localhost:8080")
	if err != nil {
		log.Fatal(err)
	}
	defer conn.Close()

	// Test SET command
	sendCommand(conn, "SET mykey myvalue 60")
	// Test GET command
	sendCommand(conn, "GET mykey")
	// Test DEL command
	sendCommand(conn, "DEL mykey")
	// Test HAS command
	sendCommand(conn, "HAS mykey")
}

func sendCommand(conn net.Conn, cmd string) {
	fmt.Fprintf(conn, cmd+"\n")
	status, err := bufio.NewReader(conn).ReadString('\n')
	if err != nil {
		log.Printf("error sending command: %s", err)
	} else {
		log.Printf("command response: %s", status)
	}
}
