package main

import (
	"errors"
	"fmt"
)

type Snssai struct {
	Sst int    `json:"sst"`
	Sd  string `json:"sd,omitempty"`
}

type SubscribedSnssai struct {
	SubscribedSnssai *Snssai `json:"subscribedSnssai"`
	DefaultIndication bool   `json:"defaultIndication,omitempty"`
}

type SnssaiManager struct {
	subscriptions []SubscribedSnssai
}

func NewSnssaiManager() *SnssaiManager {
	return &SnssaiManager{}
}

func (m *SnssaiManager) Add(subscription SubscribedSnssai) error {
	for _, sub := range m.subscriptions {
		if sub.SubscribedSnssai.Sst == subscription.SubscribedSnssai.Sst && sub.SubscribedSnssai.Sd == subscription.SubscribedSnssai.Sd {
			return errors.New("subscription already exists")
		}
	}
	m.subscriptions = append(m.subscriptions, subscription)
	return nil
}

func (m *SnssaiManager) Remove(sst int, sd string) error {
	for i, sub := range m.subscriptions {
		if sub.SubscribedSnssai.Sst == sst && sub.SubscribedSnssai.Sd == sd {
			m.subscriptions = append(m.subscriptions[:i], m.subscriptions[i+1:]...)
			return nil
		}
	}
	return errors.New("subscription not found")
}

func (m *SnssaiManager) GetDefaultSubscriptions() []SubscribedSnssai {
	var defaults []SubscribedSnssai
	for _, sub := range m.subscriptions {
		if sub.DefaultIndication {
			defaults = append(defaults, sub)
		}
	}
	return defaults
}

func (m *SnssaiManager) UpdateDefaultIndication(sst int, sd string, defaultIndication bool) error {
	for i, sub := range m.subscriptions {
		if sub.SubscribedSnssai.Sst == sst && sub.SubscribedSnssai.Sd == sd {
			m.subscriptions[i].DefaultIndication = defaultIndication
			return nil
		}
	}
	return errors.New("subscription not found")
}

func main() {
	manager := NewSnssaiManager()

	// Test cases
	err := manager.Add(SubscribedSnssai{SubscribedSnssai: &Snssai{Sst: 1, Sd: "010203"}, DefaultIndication: true})
	if err != nil {
		fmt.Println(err)
	}

	err = manager.Add(SubscribedSnssai{SubscribedSnssai: &Snssai{Sst: 1, Sd: "010203"}, DefaultIndication: false})
	if err != nil {
		fmt.Println(err) // Should print "subscription already exists"
	}

	err = manager.Remove(1, "010204")
	if err != nil {
		fmt.Println(err) // Should print "subscription not found"
	}

	defaults := manager.GetDefaultSubscriptions()
	fmt.Println("Default Subscriptions:", defaults) // Should print the default subscription

	err = manager.UpdateDefaultIndication(1, "010203", false)
	if err != nil {
		fmt.Println(err)
	}

	defaults = manager.GetDefaultSubscriptions()
	fmt.Println("Default Subscriptions after update:", defaults) // Should print an empty list
}
