package main

import (
	"fmt"
	"net/http"

	"github.com/gin-gonic/gin"
	"github.com/spf13/viper"
)

// Item represents an inventory item
type Item struct {
	ID       string  `json:"id"`
	Name     string  `json:"name"`
	Quantity int     `json:"quantity"`
	Price    float64 `json:"price"`
}

// Inventory holds the list of items
var Inventory = []Item{}

// setConfig sets up application configuration
func setConfig(config string) {
	viper.SetConfigName(config)
	viper.AddConfigPath(".")
	err := viper.ReadInConfig()
	if err != nil {
		panic(fmt.Errorf("Configuration file not found: %s", err))
	}
	viper.SetEnvPrefix("INV")
	viper.AutomaticEnv()
}

// setErrorHandler sets up the error handler for 404 requests
func setErrorHandler(router *gin.Engine) {
	router.NoRoute(func(c *gin.Context) {
		c.JSON(http.StatusNotFound, gin.H{"message": "Resource not found"})
	})
}

// addItem adds a new item to the inventory
func addItem(c *gin.Context) {
	var newItem Item
	if err := c.BindJSON(&newItem); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}
	Inventory = append(Inventory, newItem)
	c.JSON(http.StatusCreated, newItem)
}

// getItems retrieves all items from the inventory
func getItems(c *gin.Context) {
	c.JSON(http.StatusOK, Inventory)
}

// updateItem updates an existing item in the inventory
func updateItem(c *gin.Context) {
	id := c.Param("id")
	var updatedItem Item
	if err := c.BindJSON(&updatedItem); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}
	for i, item := range Inventory {
		if item.ID == id {
			Inventory[i] = updatedItem
			c.JSON(http.StatusOK, updatedItem)
			return
		}
	}
	c.JSON(http.StatusNotFound, gin.H{"message": "Item not found"})
}

// getItem retrieves a single item by ID from the inventory
func getItem(c *gin.Context) {
	id := c.Param("id")
	for _, item := range Inventory {
		if item.ID == id {
			c.JSON(http.StatusOK, item)
			return
		}
	}
	c.JSON(http.StatusNotFound, gin.H{"message": "Item not found"})
}

func main() {
	setConfig("config")

	router := gin.Default()
	setErrorHandler(router)

	router.POST("/items", addItem)
	router.GET("/items", getItems)
	router.PUT("/items/:id", updateItem)
	router.GET("/items/:id", getItem)

	router.Run(":8080")
}
