// IsSignalSupported checks if the given signal name is supported by the current system.
func IsSignalSupported(signalName string) (bool, error) {
	// Look up the signal in the SignalMap
	sig, ok := signal.SignalMap[signalName]
	if !ok {
		return false, fmt.Errorf("signal %s is not recognized", signalName)
	}

	// Check if the signal exists in the system's signal map
	for _, v := range signal.SignalMap {
		if v == sig {
			return true, nil
		}
	}
	return false, nil
}

