// RandomStringGenerator is a struct that generates random strings of a fixed length from a given alphabet.
type RandomStringGenerator struct {
	length   int
	alphabet []rune
}

// NewRandomStringGenerator is a constructor for RandomStringGenerator.
func NewRandomStringGenerator(length int, alphabet []rune) *RandomStringGenerator {
	return &RandomStringGenerator{
		length:   length,
		alphabet: alphabet,
	}
}

// GenerateString generates a random string of the specified length from the given alphabet.
func (r *RandomStringGenerator) GenerateString() string {
	rand.Seed(time.Now().UnixNano())
	var buf bytes.Buffer
	for i := 0; i < r.length; i++ {
		buf.WriteRune(r.alphabet[rand.Intn(len(r.alphabet))])
	}
	return buf.String()
}

func main() {
	// Example usage:
	alphabet := []rune("abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ")
	generator := NewRandomStringGenerator(10, alphabet)

	// Generate 5 random strings and print them
	for i := 0; i < 5; i++ {
		fmt.Println(generator.GenerateString())
	}
}
