package inproc

import (
	"errors"
	"net"
	"sync"
)

// InProc represents an in-process transport that can be used to serve gRPC services without network sockets.
type InProc struct {
	stop    chan struct{}
	running bool
	mu      sync.RWMutex
}

// New creates a new InProc transport.
func New() *InProc {
	return &InProc{stop: make(chan struct{})}
}

// Serve starts the in-process server. It returns an error if the server is already running.
func (i *InProc) Serve(_ net.Listener) error {
	i.mu.RLock()
	running := i.running
	i.mu.RUnlock()
	if running {
		return errors.New("already running")
	}
	i.mu.Lock()
	i.running = true
	i.mu.Unlock()
	<-i.stop
	return nil
}

// Stop signals the in-process server to stop.
func (i *InProc) Stop() {
	i.mu.RLock()
	running := i.running
	i.mu.RUnlock()
	if running {
		i.stop <- struct{}{}
	}
}

// GracefulStop stops the in-process server gracefully.
func (i *InProc) GracefulStop() {
	i.Stop()
}

// Example usage of the InProc transport.
func main() {
	// Create a new InProc transport.
	inProcServer := New()

	// Start the server in a separate goroutine.
	go func() {
		if err := inProcServer.Serve(nil); err != nil {
			panic(err)
		}
	}()

	// Stop the server after some operations.
	inProcServer.Stop()

	// Optionally, you can use GracefulStop instead of Stop.
	// inProcServer.GracefulStop()
}
