// createPrototypeDeploymentFiles creates the necessary deployment files for a given branch.
// If skipDocker is true, Docker-related files will not be created.
func createPrototypeDeploymentFiles(branch string, skipDocker bool) error {
	// Create .github directory and workflow file
	githubDir := ".github/workflows"
	err := os.MkdirAll(githubDir, os.ModePerm)
	if err != nil {
		return err
	}
	githubWorkflowContent := fmt.Sprintf("name: CD for %s\non:\n  push:\n    branches:\n      - %s", branch, branch)
	err = ioutil.WriteFile(githubDir+"/cd-"+branch+".yaml", []byte(githubWorkflowContent), 0644)
	if err != nil {
		return err
	}

	// Create Kubernetes deployment template file
	kubernetesDeploymentContent := strings.Replace("apiVersion: apps/v1\nkind: Deployment\nmetadata:\n  name: {BRANCH}-deployment", "{BRANCH}", branch, -1)
	err = ioutil.WriteFile("kubernetes-deploy-"+branch+".tpl", []byte(kubernetesDeploymentContent), 0644)
	if err != nil {
		return err
	}

	// Create Docker-related files if not skipped
	if !skipDocker {
		dockerFileContent := "FROM alpine\nCMD [\"/start.sh\"]"
		err = ioutil.WriteFile("Dockerfile", []byte(dockerFileContent), 0644)
		if err != nil {
			return err
		}

		dockerIgnoreContent := "*.md\n*.txt"
		err = ioutil.WriteFile(".dockerignore", []byte(dockerIgnoreContent), 0644)
		if err != nil {
			return err
		}

		startShContent := "#!/bin/sh\necho \"Starting application...\""
		err = ioutil.WriteFile("start.sh", []byte(startShContent), 0755)
		if err != nil {
			return err
		}
	}

	return nil
}

// cleanUpPrototypeDeploymentFiles removes the generated deployment files for a given branch.
// If skipDocker is true, Docker-related files will not be removed.
func cleanUpPrototypeDeploymentFiles(branch string, skipDocker bool) {
	os.RemoveAll(".github")
	os.Remove("kubernetes-deploy-" + branch + ".tpl")
	if !skipDocker {
		cleanUpPrototypeDockerFiles()
	}
}

// cleanUpPrototypeDockerFiles removes the generated Docker-related files.
func cleanUpPrototypeDockerFiles() {
	os.Remove("Dockerfile")
	os.Remove(".dockerignore")
	os.Remove("start.sh")
}

