package main

import (
	"encoding/json"
	"errors"
	"fmt"
	"github.com/sideshow/apns2"
	"time"
)

// apnsMessage represents the structure of an incoming APNS message.
type apnsMessage struct {
	Token   string                     `json:"token"`
	Headers map[string]json.RawMessage `json:"headers,omitempty"`
	Payload json.RawMessage            `json:"payload,omitempty"`
}

// apnsNotification wraps an apns2.Notification object.
type apnsNotification struct {
	notification *apns2.Notification
}

// ConvertMessage takes a byte slice of JSON data and converts it into an apnsNotification.
func ConvertMessage(data []byte) (apnsNotification, error) {
	var msg apnsMessage
	var notif apnsNotification

	if err := json.Unmarshal(data, &msg); err != nil {
		return notif, err
	}
	if msg.Token == "" {
		return notif, errors.New("token required")
	}

	notif.notification = &apns2.Notification{
		DeviceToken: msg.Token,
		Payload:     msg.Payload,
	}

	if topic, ok := msg.Headers["apns-topic"]; ok {
		if err := json.Unmarshal(topic, &notif.notification.Topic); err != nil {
			return notif, err
		}
	} else {
		return notif, errors.New("APNS requires a topic")
	}

	if prio, ok := msg.Headers["apns-priority"]; ok {
		if err := json.Unmarshal(prio, &notif.notification.Priority); err != nil {
			return notif, err
		}
	}

	if collapse, ok := msg.Headers["apns-collapse-id"]; ok {
		if err := json.Unmarshal(collapse, &notif.notification.CollapseID); err != nil {
			return notif, err
		}
	}

	if exp, ok := msg.Headers["apns-expiration"]; ok {
		var epoch int64
		if err := json.Unmarshal(exp, &epoch); err != nil {
			return notif, err
		}
		notif.notification.Expiration = time.Unix(epoch, 0)
	}

	return notif, nil
}

// Validate checks if the provided data is a valid APNS message.
func Validate(data []byte) error {
	_, err := ConvertMessage(data)
	return err
}

// Example usage and test cases
func main() {
	// Valid APNS message
	validMessage := []byte(`{
		"token": "some_device_token",
		"headers": {
			"apns-topic": "\"com.example.app\"",
			"apns-priority": "10"
		},
		"payload": "{\"aps\":{\"alert\":\"Hello, world!\"}}"
	}`)

	// Invalid APNS message (missing token)
	invalidMessage := []byte(`{
		"headers": {
			"apns-topic": "\"com.example.app\""
		},
		"payload": "{\"aps\":{\"alert\":\"Hello, world!\"}}"
	}`)

	// Test valid message
	if err := Validate(validMessage); err != nil {
		fmt.Println("Valid message failed validation:", err)
	} else {
		fmt.Println("Valid message passed validation")
	}

	// Test invalid message
	if err := Validate(invalidMessage); err != nil {
		fmt.Println("Invalid message failed validation as expected:", err)
	} else {
		fmt.Println("Invalid message passed validation unexpectedly")
	}
}
