import (
	"fmt"
	"os"
	"time"

	"github.com/golang-jwt/jwt"
)

type SignedDetails struct {
	Username  string
	FirstName string
	LastName  string
	Uid       string
	Role      string
	jwt.StandardClaims
}

// GenerateToken creates a new JWT token for a user with the given details.
func GenerateToken(username, firstName, lastName, uid, role string) (signedToken string, err error) {
	SECRET_KEY := os.Getenv("SECRET_KEY")

	claims := &SignedDetails{
		Username:  username,
		FirstName: firstName,
		LastName:  lastName,
		Uid:       uid,
		Role:      role,
		StandardClaims: jwt.StandardClaims{
			ExpiresAt: time.Now().Add(time.Hour * 24).Unix(),
			Issuer:    "go-program",
			IssuedAt:  time.Now().Unix(),
		},
	}

	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
	signedToken, err = token.SignedString([]byte(SECRET_KEY))
	if err != nil {
		return "", err
	}
	return signedToken, nil
}

// ValidateToken checks if the provided JWT token is valid and returns the user details.
func ValidateToken(signedToken string) (claims *SignedDetails, msg string) {
	SECRET_KEY := os.Getenv("SECRET_KEY")
	token, err := jwt.ParseWithClaims(
		signedToken,
		&SignedDetails{},
		func(token *jwt.Token) (interface{}, error) {
			return []byte(SECRET_KEY), nil
		},
	)
	if err != nil {
		msg = "Invalid token"
		return
	}
	claims, ok := token.Claims.(*SignedDetails)
	if !ok {
		msg = "Invalid token"
		return
	}
	if claims.ExpiresAt < time.Now().Unix() {
		msg = "Token expired"
		return
	}
	return claims, ""
}

func main() {
	// Set up environment variable for SECRET_KEY
	os.Setenv("SECRET_KEY", "my_secret_key")

	// Test case for GenerateToken
	signedToken, err := GenerateToken("johndoe", "John", "Doe", "12345", "user")
	if err != nil {
		fmt.Println("Error generating token:", err)
		return
	}
	fmt.Println("Generated Token:", signedToken)

	// Test case for ValidateToken
	claims, msg := ValidateToken(signedToken)
	if msg != "" {
		fmt.Println("Error validating token:", msg)
		return
	}
	fmt.Printf("Token is valid. User details: %+v\n", claims)
}
