package main

import (
	"fmt"
)

// SysOperationRecord represents the details of an API operation.
type SysOperationRecord struct {
	Path       string
	Method     string
	UserID     string
	IP         string
	Status     string
}

// PageInfo holds the pagination details.
type PageInfo struct {
	Page     int
	PageSize int
}

// SysOperationRecordSearch includes the operation record and pagination info.
type SysOperationRecordSearch struct {
	SysOperationRecord
	PageInfo
}

// SearchOperationRecords simulates the search of operation records with filters and pagination.
func SearchOperationRecords(searchParams SysOperationRecordSearch, records []SysOperationRecord) ([]SysOperationRecord, bool) {
	filteredRecords := make([]SysOperationRecord, 0)
	for _, record := range records {
		if (searchParams.Path == "" || record.Path == searchParams.Path) &&
			(searchParams.Method == "" || record.Method == searchParams.Method) &&
			(searchParams.UserID == "" || record.UserID == searchParams.UserID) &&
			(searchParams.IP == "" || record.IP == searchParams.IP) &&
			(searchParams.Status == "" || record.Status == searchParams.Status) {
			filteredRecords = append(filteredRecords, record)
		}
	}

	start := (searchParams.Page - 1) * searchParams.PageSize
	end := start + searchParams.PageSize
	if start >= len(filteredRecords) {
		return []SysOperationRecord{}, false
	}
	if end > len(filteredRecords) {
		end = len(filteredRecords)
	}
	return filteredRecords[start:end], end < len(filteredRecords)
}

func main() {
	// Example usage:
	records := []SysOperationRecord{
		{Path: "/api/user", Method: "GET", UserID: "1", IP: "192.168.1.1", Status: "success"},
		{Path: "/api/user", Method: "POST", UserID: "2", IP: "192.168.1.2", Status: "success"},
		{Path: "/api/order", Method: "GET", UserID: "1", IP: "192.168.1.3", Status: "error"},
		// ... more records
	}

	searchParams := SysOperationRecordSearch{
		SysOperationRecord: SysOperationRecord{
			Path:   "/api/user",
			Method: "GET",
		},
		PageInfo: PageInfo{
			Page:     1,
			PageSize: 10,
		},
	}

