package main

import (
	"errors"
	"fmt"
	"sync"
	"time"
	"github.com/google/uuid"
)

type Transaction struct {
	ID        string  `json:"id"`
	Sender    string  `json:"sender"`
	Recipient string  `json:"recipient"`
	Amount    float64 `json:"amount"`
	Timestamp int64   `json:"timestamp"`
}

type CreateTransactionRequest struct {
	Transactions []Transaction `json:"transactions,omitempty"`
	mu           sync.Mutex
}

func NewTransaction(sender, recipient string, amount float64) (*Transaction, error) {
	if amount <= 0 {
		return nil, errors.New("amount must be positive")
	}
	if sender == "" || recipient == "" {
		return nil, errors.New("sender and recipient addresses must be provided")
	}

	return &Transaction{
		ID:        uuid.New().String(),
		Sender:    sender,
		Recipient: recipient,
		Amount:    amount,
		Timestamp: time.Now().Unix(),
	}, nil
}

func (ctr *CreateTransactionRequest) AddTransaction(tx *Transaction) {
	ctr.mu.Lock()
	defer ctr.mu.Unlock()
	ctr.Transactions = append(ctr.Transactions, *tx)
}

func (ctr *CreateTransactionRequest) GetTransactions() []Transaction {
	ctr.mu.Lock()
	defer ctr.mu.Unlock()
	return ctr.Transactions
}

func main() {
	// Initialize the transaction pool
	transactionPool := CreateTransactionRequest{}

	// Create a new transaction and add it to the pool
	tx1, err := NewTransaction("Alice", "Bob", 10.0)
	if err != nil {
		fmt.Println("Error creating transaction:", err)
		return
	}
	transactionPool.AddTransaction(tx1)

	// Create another transaction and add it to the pool
	tx2, err := NewTransaction("Charlie", "Dave", 20.0)
	if err != nil {
		fmt.Println("Error creating transaction:", err)
		return
	}
	transactionPool.AddTransaction(tx2)

	// Retrieve all transactions from the pool
	allTransactions := transactionPool.GetTransactions()
	fmt.Println("Transactions in the pool:")
	for _, tx := range allTransactions {
		fmt.Printf("ID: %s, Sender: %s, Recipient: %s, Amount: %.2f, Timestamp: %d\n",
			tx.ID, tx.Sender, tx.Recipient, tx.Amount, tx.Timestamp)
	}
}
