	"github.com/rs/zerolog/log"
)

// Import the necessary packages
import (
	"context"
	"fmt"
	"time"

	"github.com/rs/zerolog/log"
)

// Define constants and types
const (
	DefaultFlashDelay = 3 * time.Second
	FlashInfo         = iota
	FlashWarn
	FlashErr
)

type FlashLevel int

type LevelMessage struct {
	Level FlashLevel
	Text  string
}

type FlashChan chan LevelMessage

type FlashListener interface {
	FlashChanged(FlashLevel, string)
	FlashCleared()
}

type Flash struct {
	msg     LevelMessage
	cancel  context.CancelFunc
	delay   time.Duration
	msgChan FlashChan
}

// Implement the Flash struct methods
func NewFlash(dur time.Duration) *Flash {
	return &Flash{
		delay:   dur,
		msgChan: make(FlashChan, 3),
	}
}

func (f *Flash) Channel() FlashChan {
	return f.msgChan
}

func (f *Flash) Info(msg string) {
	f.SetMessage(FlashInfo, msg)
}

func (f *Flash) Infof(fmat string, args ...interface{}) {
	f.Info(fmt.Sprintf(fmat, args...))
}

func (f *Flash) Warn(msg string) {
	log.Warn().Msg(msg)
	f.SetMessage(FlashWarn, msg)
}

func (f *Flash) Warnf(fmat string, args ...interface{}) {
	f.Warn(fmt.Sprintf(fmat, args...))
}

func (f *Flash) Err(err error) {
	log.Error().Msg(err.Error())
	f.SetMessage(FlashErr, err.Error())
}

func (f *Flash) Errf(fmat string, args ...interface{}) {
	var err error
	for _, a := range args {
		if e, ok := a.(error); ok {
			err = e
		}
	}
	log.Error().Err(err).Msgf(fmat, args...)
	f.SetMessage(FlashErr, fmt.Sprintf(fmat, args...))
}

func (f *Flash) Clear() {
	f.fireCleared()
}

func (f *Flash) SetMessage(level FlashLevel, msg string) {
	if f.cancel != nil {
		f.cancel()
		f.cancel = nil
	}

	f.msg = LevelMessage{Level: level, Text: msg}
	f.fireFlashChanged()

	ctx, cancel := context.WithCancel(context.Background())
	f.cancel = cancel
	go f.refresh(ctx)
}

func (f *Flash) refresh(ctx context.Context) {
	select {
	case <-ctx.Done():
		return
	case <-time.After(f.delay):
		f.Clear()
	}
}

func (f *Flash) fireFlashChanged() {
	f.msgChan <- f.msg
}

func (f *Flash) fireCleared() {
	f.msgChan <- LevelMessage{}
}

// Test cases to verify the solution correctness
func main() {
	flash := NewFlash(DefaultFlashDelay)

	go func() {
		for msg := range flash.Channel() {
			if msg.Text == "" {
				fmt.Println("Flash message cleared.")
			} else {
				fmt.Printf("Flash message [%d]: %s\n", msg.Level, msg.Text)
			}
		}
	}()

	flash.Info("This is an info message.")
	time.Sleep(1 * time.Second)
	flash.Warn("This is a warning message.")
	time.Sleep(1 * time.Second)
	flash.Err(fmt.Errorf("This is an error message."))
	time.Sleep(1 * time.Second)
	flash.Clear()
	time.Sleep(5 * time.Second) // Wait for all messages to clear
}
