	fmt.Printf("Allocated %d blocks starting at %d: %t\n", 10, blockid, allocated)

	// Deallocate the previously allocated blocks
	root = root.Deallocate(blockid, 10)
	fmt.Println("Deallocated 10 blocks:", root)

	// Allocate 5 blocks
	blockid, allocated = root.Allocate(5)
	fmt.Printf("Allocated %d blocks starting at %d: %t\n", 5, blockid, allocated)

	// Allocate another 5 blocks
	blockid, allocated = root.Allocate(5)
	fmt.Printf("Allocated %d blocks starting at %d: %t\n", 5, blockid, allocated)

	// Deallocate the first 5 blocks
