// Deposit adds the amount to the account balance
func (ba *BankAccount) Deposit(amount float64) {
	ba.Balance += amount
	fmt.Printf("Deposited: $%.2f, New Balance: $%.2f\n", amount, ba.Balance)
}

// Withdraw subtracts the amount from the account balance if there are sufficient funds
func (ba *BankAccount) Withdraw(amount float64) error {
	if amount > ba.Balance {
		return errors.New("insufficient funds")
	}
	ba.Balance -= amount
	fmt.Printf("Withdrew: $%.2f, New Balance: $%.2f\n", amount, ba.Balance)
	return nil
}

// CheckBalance prints the current balance of the bank account
func (ba *BankAccount) CheckBalance() {
	fmt.Printf("Current Balance: $%.2f\n", ba.Balance)
}

