// GetNodeIDFromIP retrieves the instance ID of a VM based on its private DNS name.
func (cp *CloudProvider) GetNodeIDFromIP(privateDNSName string) (string, error) {
	input := &ec2.DescribeInstancesInput{
		Filters: []*ec2.Filter{
			{
				Name:   aws.String("private-dns-name"),
				Values: []*string{aws.String(privateDNSName)},
			},
		},
	}

	result, err := cp.EC2.DescribeInstances(input)
	if err != nil {
		return "", err
	}

	for _, reservation := range result.Reservations {
		for _, instance := range reservation.Instances {
			if instance.InstanceId != nil {
				return *instance.InstanceId, nil
			}
		}
	}

	return "", errors.New("instance not found")
}

// TestGetNodeIDFromIP tests the GetNodeIDFromIP function with a mock EC2 service.
func TestGetNodeIDFromIP(t *testing.T) {
	expected := "i-0123456789abcdef0"
	privateDNSName := "ip-10-0-0-1.ec2.internal"

	clients := CloudProvider{
		EC2: &fakeEC2{
			describeInstancesOutput: &ec2.DescribeInstancesOutput{
				Reservations: []*ec2.Reservation{
					{
						Instances: []*ec2.Instance{
							{
								InstanceId: aws.String(expected),
							},
						},
					},
				},
			},
		},
	}

	id, err := clients.GetNodeIDFromIP(privateDNSName)
	if err != nil {
		t.Fatalf("Unexpected error: %v", err)
