type DataDigitalOceanAppSpecIngressRule struct {
	Path   string
	Method string
	Action string
	Source string
}

func (rule *DataDigitalOceanAppSpecIngressRule) Validate() error {
	if rule.Path == "" || !strings.HasPrefix(rule.Path, "/") {
		return errors.New("invalid Path: must not be empty and must start with '/'")
	}

	validMethods := map[string]bool{"GET": true, "POST": true, "PUT": true, "DELETE": true}
	if _, ok := validMethods[rule.Method]; !ok {
		return errors.New("invalid Method: must be one of GET, POST, PUT, DELETE")
	}

	if rule.Action != "ALLOW" && rule.Action != "DENY" {
		return errors.New("invalid Action: must be either ALLOW or DENY")
	}

	if _, _, err := net.ParseCIDR(rule.Source); err != nil {
		return errors.New("invalid Source: must be a valid CIDR notation")
	}

	return nil
}

func main() {
	// Test cases to verify solution correctness
	testCases := []DataDigitalOceanAppSpecIngressRule{
		{Path: "/api", Method: "GET", Action: "ALLOW", Source: "192.168.1.0/24"},
		{Path: "api", Method: "GET", Action: "ALLOW", Source: "192.168.1.0/24"}, // Invalid Path
		{Path: "/api", Method: "FETCH", Action: "ALLOW", Source: "192.168.1.0/24"}, // Invalid Method
		{Path: "/api", Method: "GET", Action: "ACCEPT", Source: "192.168.1.0/24"}, // Invalid Action
		{Path: "/api", Method: "GET", Action: "ALLOW", Source: "192.168.1.0"}, // Invalid Source
	}

	for _, testCase := range testCases {
		err := testCase.Validate()
		if err != nil {
			fmt.Printf("Rule: %+v is invalid: %s\n", testCase, err)
		} else {
			fmt.Printf("Rule: %+v is valid\n", testCase)
		}
	}
}
