	"sort"
)

// InputSecurityGroup_InputWhitelistRuleCidr represents a CIDR block that can be whitelisted.
type InputSecurityGroup_InputWhitelistRuleCidr struct {
	Cidr string
}

// InputSecurityGroupManager manages a list of InputSecurityGroup_InputWhitelistRuleCidr instances.
type InputSecurityGroupManager struct {
	whitelist []InputSecurityGroup_InputWhitelistRuleCidr
}

// AddCIDR adds a new CIDR block to the whitelist.
func (m *InputSecurityGroupManager) AddCIDR(cidr string) error {
	for _, rule := range m.whitelist {
		if rule.Cidr == cidr {
			return errors.New("duplicate CIDR block")
		}
	}
	m.whitelist = append(m.whitelist, InputSecurityGroup_InputWhitelistRuleCidr{Cidr: cidr})
	sort.Slice(m.whitelist, func(i, j int) bool {
		return m.whitelist[i].Cidr < m.whitelist[j].Cidr
	})
	return nil
}

// RemoveCIDR removes a CIDR block from the whitelist.
func (m *InputSecurityGroupManager) RemoveCIDR(cidr string) error {
	for i, rule := range m.whitelist {
		if rule.Cidr == cidr {
			m.whitelist = append(m.whitelist[:i], m.whitelist[i+1:]...)
			return nil
		}
	}
	return errors.New("CIDR block does not exist")
}

// ListCIDRs returns a list of all CIDR blocks currently in the whitelist.
func (m *InputSecurityGroupManager) ListCIDRs() []string {
	cidrs := make([]string, len(m.whitelist))
	for i, rule := range m.whitelist {
		cidrs[i] = rule.Cidr
	}
	return cidrs
}

func main() {
	manager := InputSecurityGroupManager{}

	// Test cases
	err := manager.AddCIDR("192.168.1.0/24")
	if err != nil {
		fmt.Println(err)
	}
	err = manager.AddCIDR("192.168.2.0/24")
	if err != nil {
		fmt.Println(err)
	}
	err = manager.AddCIDR("192.168.1.0/24") // This should return a duplicate error
	if err != nil {
		fmt.Println(err)
	}
	err = manager.RemoveCIDR("192.168.3.0/24") // This should return a does not exist error
	if err != nil {
		fmt.Println(err)
	}
	err = manager.RemoveCIDR("192.168.2.0/24")
	if err != nil {
		fmt.Println(err)
	}

	fmt.Println("Current CIDR blocks in whitelist:", manager.ListCIDRs())
}
