package main

import (
	"encoding/json"
	"errors"
	"os"
	"path/filepath"
)

// Cache represents a simple file-based cache system.
type Cache struct {
	Entries map[string]interface{}
}

// NewCache creates a new Cache instance with initialized entries.
func NewCache() Cache {
	return Cache{
		Entries: make(map[string]interface{}),
	}
}

// ReadCache reads the cache from the specified file path.
func ReadCache(path string) (Cache, error) {
	cache := NewCache()
	bytes, err := os.ReadFile(path)
	if err != nil {
		if errors.Is(err, os.ErrNotExist) {
			return cache, nil // Return empty cache if file does not exist
		}
		return cache, err
	}
	err = json.Unmarshal(bytes, &cache.Entries)
	if err != nil {
		return cache, err
	}
	return cache, nil
}

// WriteCache writes the current state of the cache to the specified file path.
func WriteCache(path string, cache Cache) error {
	data, err := json.Marshal(cache.Entries)
	if err != nil {
		return err
	}
	return os.WriteFile(path, data, 0644)
}

// GetFileNameForFilePath extracts the file name from the given file path.
func GetFileNameForFilePath(path string) string {
	_, file := filepath.Split(path)
	return file
}

// Test cases to verify the correctness of the implemented functions.
func main() {
	cache := NewCache()
	cache.Entries["key1"] = "value1"
	cache.Entries["key2"] = 42

	cacheFilePath := "test_cache.json"

	// Test WriteCache
	err := WriteCache(cacheFilePath, cache)
	if err != nil {
		panic("failed to write cache: " + err.Error())
	}

	// Test ReadCache
	readCache, err := ReadCache(cacheFilePath)
	if err != nil {
		panic("failed to read cache: " + err.Error())
	}

	// Verify that the cache read from file is the same as the one written
	if len(readCache.Entries) != len(cache.Entries) {
		panic("cache entries mismatch")
	}
	for key, value := range cache.Entries {
		if readCache.Entries[key] != value {
			panic("cache entry values mismatch")
		}
	}

	// Test GetFileNameForFilePath
	fileName := GetFileNameForFilePath(cacheFilePath)
	if fileName != "test_cache.json" {
		panic("file name extraction failed")
	}

	// Clean up test cache file
	os.Remove(cacheFilePath)

	println("All tests passed!")
}
