package service

import (
	"io/ioutil"
	"os"
	"path/filepath"
)

type Service struct {
	Name    string
	Actions []string
}

type ActionsResponse struct {
	Actions []string
}

func NewFromPath(servicePath string) (*Service, error) {
	files, err := ioutil.ReadDir(servicePath)
	if err != nil {
		return nil, err
	}

	serviceName := filepath.Base(servicePath)
	service := &Service{Name: serviceName}

	for _, file := range files {
		if !file.IsDir() {
			service.Actions = append(service.Actions, file.Name())
		}
	}

	return service, nil
}

func GetServices(dataPath string) ([]Service, error) {
	dirs, err := ioutil.ReadDir(dataPath)
	if err != nil {
		return nil, err
	}

	var services []Service
	for _, dir := range dirs {
		if dir.IsDir() {
			servicePath := filepath.Join(dataPath, dir.Name())
			service, err := NewFromPath(servicePath)
			if err != nil {
				return nil, err
			}
			services = append(services, *service)
		}
	}

	return services, nil
}

func (s *Service) GetActions() ActionsResponse {
	return ActionsResponse{Actions: s.Actions}
}
