// UpdateMenuItem updates a menu item in the database based on the provided ID and form data.
func UpdateMenuItem(w http.ResponseWriter, r *http.Request) {
	// Validate admin session
	sessions, _ := store.Get(r, "admin")
	if _, ok := sessions.Values["UserID"]; !ok {
		http.Redirect(w, r, "/login", http.StatusSeeOther)
		return
	}

	// Parse form and URL parameters
	r.ParseForm()
	vars := mux.Vars(r)
	id, _ := strconv.Atoi(vars["id"])
	dish := r.Form.Get("dish")
	price := r.Form.Get("price")
	category := r.Form.Get("category")
	description := r.Form.Get("description")

	// Open database connection
	db, err := sql.Open("sqlite3", "./menu.db")
	if err != nil {
		http.Error(w, "Error opening database", http.StatusInternalServerError)
		return
	}
	defer db.Close()

	// Update price if provided
	if price != "" {
		if _, err := strconv.Atoi(price); err == nil {
			if err := updateField(db, "price", price, id); err != nil {
				http.Error(w, "Error updating price", http.StatusInternalServerError)
				return
			}
		}
	}

	// Update other fields if provided
	if description != "" {
		if err := updateField(db, "description", description, id); err != nil {
			http.Error(w, "Error updating description", http.StatusInternalServerError)
			return
		}
	}

	if dish != "" {
		if err := updateField(db, "dish", dish, id); err != nil {
			http.Error(w, "Error updating dish", http.StatusInternalServerError)
			return
		}
	}

	if category != "" {
		if err := updateField(db, "category", category, id); err != nil {
			http.Error(w, "Error updating category", http.StatusInternalServerError)
			return
		}
	}

	// Redirect to the editing page
	http.Redirect(w, r, "/editing", http.StatusSeeOther)
}

// updateField updates a specific field in the menu table for a given ID.
func updateField(db *sql.DB, field, value string, id int) error {
	stmt, err := db.Prepare(fmt.Sprintf("UPDATE menu SET %s=? WHERE id=?", field))
	if err != nil {
		return err
	}
	defer stmt.Close()

	_, err = stmt.Exec(value, id)
	return err
}
