package main

import (
	"crypto/sha256"
	"encoding/base64"
	"fmt"
	"net/http"
	"strings"
	"time"
)

// Robot represents a robot account with its details.
type Robot struct {
	Name      string
	Secret    string
	Salt      string
	ExpiresAt int64
	Disabled  bool
}

// RobotAuthenticator provides methods for authenticating robot accounts.
type RobotAuthenticator struct {
	Robots      []Robot
	RobotPrefix string
}

// NewRobotAuthenticator creates a new instance of RobotAuthenticator.
func NewRobotAuthenticator(robots []Robot, prefix string) *RobotAuthenticator {
	return &RobotAuthenticator{
		Robots:      robots,
		RobotPrefix: prefix,
	}
}

// Authenticate validates the robot's credentials and returns a security context if successful.
func (ra *RobotAuthenticator) Authenticate(req *http.Request) *Robot {
	name, secret, ok := req.BasicAuth()
	if !ok {
		fmt.Println("Basic Auth credentials not found")
		return nil
	}
	if !strings.HasPrefix(name, ra.RobotPrefix) {
		fmt.Println("Robot name does not have the correct prefix")
		return nil
	}

	for _, robot := range ra.Robots {
		if robot.Name == strings.TrimPrefix(name, ra.RobotPrefix) {
			if ra.encrypt(secret, robot.Salt) != robot.Secret {
				fmt.Printf("Failed to authenticate robot account: %s\n", name)
				return nil
			}
			if robot.Disabled {
				fmt.Printf("Robot account is disabled: %s\n", name)
				return nil
			}
			now := time.Now().Unix()
			if robot.ExpiresAt != -1 && robot.ExpiresAt <= now {
				fmt.Printf("Robot account is expired: %s\n", name)
				return nil
			}
			fmt.Printf("Robot authenticated successfully: %s\n", name)
			return &robot
		}
	}

	fmt.Println("Robot not found")
	return nil
}

// encrypt hashes the secret using SHA256 with a salt.
func (ra *RobotAuthenticator) encrypt(secret, salt string) string {
	hash := sha256.Sum256([]byte(secret + salt))
	return base64.StdEncoding.EncodeToString(hash[:])
}

// Example usage of the RobotAuthenticator.
func main() {
	robots := []Robot{
		{Name: "project1_robot", Secret: "hashed_secret_1", Salt: "salt1", ExpiresAt: -1, Disabled: false},
		{Name: "project2_robot", Secret: "hashed_secret_2", Salt: "salt2", ExpiresAt: time.Now().Add(24 * time.Hour).Unix(), Disabled: false},
	}

	authenticator := NewRobotAuthenticator(robots, "robot$")

	// Example HTTP request with Basic Auth credentials.
	req, _ := http.NewRequest("GET", "http://example.com", nil)
	req.SetBasicAuth("robot$project1_robot", "password1")

	// Authenticate the request.
	robot := authenticator.Authenticate(req)
	if robot != nil {
		fmt.Printf("Authenticated robot: %+v\n", *robot)
	}
}
