instruction:
Write a function `countSpecialPairs` that takes an array of integers `nums` and an integer `k`. The function should return the number of unique pairs `(i, j)` where `nums[i]` is equal to `nums[j]` and the product of their indices `(i * j)` is divisible by `k`. The pairs `(i, j)` and `(j, i)` are considered the same pair, and should only be counted once. The indices `i` and `j` are 0-based.

**Example**:
```go
nums := []int{1, 2, 3, 1, 1, 3}
k := 2
result := countSpecialPairs(nums, k)
// Output: 4
// Explanation: There are four pairs with equal values and indices product divisible by k:
// - Pair (0, 3) with nums[0] = nums[3] = 1 and (0*3) % 2 == 0
// - Pair (0, 4) with nums[0] = nums[4] = 1 and (0*4) % 2 == 0
// - Pair (3, 4) with nums[3] = nums[4] = 1 and (3*4) % 2 == 0
// - Pair (2, 5) with nums[2] = nums[5] = 3 and (2*5) % 2 == 0
```

**Constraints**:
- `1 <= nums.length <= 100`
- `1 <= nums[i] <= 100`
- `1 <= k <= 100`

output:
```go
package main

import (
	"fmt"
)

func countSpecialPairs(nums []int, k int) int {
	count := 0
	indicesMap := make(map[int][]int)

	for i, v := range nums {
		indicesMap[v] = append(indicesMap[v], i)
	}

	for _, indices := range indicesMap {
		for i := 0; i < len(indices); i++ {
			for j := i + 1; j < len(indices); j++ {
				if (indices[i]*indices[j])%k == 0 {
					count++
				}
			}
		}
	}

	return count
}

func main() {
	// Test cases
	fmt.Println(countSpecialPairs([]int{1, 2, 3, 1, 1, 3}, 2)) // Expected output: 4
	fmt.Println(countSpecialPairs([]int{1, 1, 1, 1}, 1))       // Expected output: 6
	fmt.Println(countSpecialPairs([]int{4, 4, 4, 4}, 3))       // Expected output: 0
	fmt.Println(countSpecialPairs([]int{1, 2, 1, 2, 1}, 3))    // Expected output: 0
}
