package storage

import (
	"fmt"
	"io"
	"path"

	"github.com/goamz/goamz/aws"
	"github.com/goamz/goamz/s3"
)

// AccessMethod is a type that defines the method of accessing the storage.
type AccessMethod string

// Params is a map that holds key-value pairs for initializing storage.
type Params map[string]string

const KST_S3 AccessMethod = "s3"

type stS3 struct {
	regionName string
	bucketName string
	pathPrefix string
	bucket     *s3.Bucket
}

func (st *stS3) init(params Params) error {
	if regionName, ok := params["awsregion"]; ok {
		st.regionName = regionName
	}
	if bucketName, ok := params["bucket"]; ok {
		st.bucketName = bucketName
	}
	if pathPrefix, ok := params["prefix"]; ok {
		st.pathPrefix = pathPrefix
	}

	region, ok := aws.Regions[st.regionName]
	if !ok {
		validSet := ""
		for k := range aws.Regions {
			validSet += " " + k
		}
		return fmt.Errorf("Invalid AWS region name: '%s'. Valid values:%s", st.regionName, validSet)
	}

	auth, err := aws.EnvAuth()
	if err != nil {
		return err
	}

	s := s3.New(auth, region)
	st.bucket = s.Bucket(st.bucketName)

	return nil
}

func (st *stS3) Get(repoPath string) ([]byte, error) {
	return st.bucket.Get(st.makeS3Path(repoPath))
}

func (st *stS3) Put(repoPath string, data []byte) error {
	options := s3.Options{}
	return st.bucket.Put(st.makeS3Path(repoPath), data, "application/octet-stream", s3.AuthenticatedRead, options)
}

func (st *stS3) GetReader(repoPath string) (io.ReadCloser, error) {
	return st.bucket.GetReader(st.makeS3Path(repoPath))
}

func (st *stS3) PutReader(repoPath string, rc io.ReadCloser, length int64) error {
	options := s3.Options{}
	return st.bucket.PutReader(st.makeS3Path(repoPath), rc, length, "application/octet-stream", s3.AuthenticatedRead, options)
}

func (st *stS3) Delete(repoPath string) error {
	return st.bucket.Del(st.makeS3Path(repoPath))
}

func (st *stS3) makeS3Path(repoPath string) string {
	if st.pathPrefix == "" {
		return repoPath
	}
	return path.Join(st.pathPrefix, repoPath)
}

// Example usage of the storage package.
func main() {
	params := Params{
		"awsregion": "us-east-1",
		"bucket":    "my-bucket",
		"prefix":    "my-app",
	}

	storage := &stS3{}
	err := storage.init(params)
	if err != nil {
		fmt.Println("Error initializing storage:", err)
		return
	}

	// Example of putting a file
	err = storage.Put("example.txt", []byte("Hello, S3!"))
	if err != nil {
		fmt.Println("Error putting file:", err)
		return
	}

	// Example of getting a file
	data, err := storage.Get("example.txt")
	if err != nil {
		fmt.Println("Error getting file:", err)
		return
	}
	fmt.Println("File contents:", string(data))

	// Example of deleting a file
	err = storage.Delete("example.txt")
	if err != nil {
		fmt.Println("Error deleting file:", err)
		return
	}
}
