package main

import (
	"fmt"
	"log"

	"github.com/Yefhem/rest-api-cleancode/models"
	"golang.org/x/crypto/bcrypt"
	"gorm.io/driver/sqlite"
	"gorm.io/gorm"
)

// User model definition
type User struct {
	ID       uint   `gorm:"primaryKey"`
	Email    string `gorm:"uniqueIndex"`
	Password string
	Products []Product
}

// Product model definition for demonstration purposes
type Product struct {
	ID     uint `gorm:"primaryKey"`
	UserID uint
	Name   string
	User   User
}

// UserRepository interface definition
type UserRepository interface {
	InsertUser(user User) User
	UpdateUser(user User) User
	VerifyCredential(email string, password string) interface{}
	IsDuplicateEmail(email string) (tx *gorm.DB)
	FindByEmail(email string) User
	ProfileUser(userID uint) User
}

// userConnection struct that implements UserRepository
type userConnection struct {
	connection *gorm.DB
}

// NewUserRepository creates a new UserRepository with the given DB connection
func NewUserRepository(db *gorm.DB) UserRepository {
	return &userConnection{
		connection: db,
	}
}

// HashPassword hashes the given password using bcrypt
func HashPassword(password string) string {
	hash, err := bcrypt.GenerateFromPassword([]byte(password), bcrypt.DefaultCost)
	if err != nil {
		log.Println(err)
		panic("Failed to hash a password")
	}
	return string(hash)
}

// InsertUser inserts a new user into the database with a hashed password
func (db *userConnection) InsertUser(user User) User {
	user.Password = HashPassword(user.Password)
	db.connection.Create(&user)
	return user
}

// UpdateUser updates an existing user's information in the database
func (db *userConnection) UpdateUser(user User) User {
	if user.Password != "" {
		user.Password = HashPassword(user.Password)
	} else {
		var tempUser User
		db.connection.Find(&tempUser, user.ID)
		user.Password = tempUser.Password
	}
	db.connection.Save(&user)
	return user
}

// IsDuplicateEmail checks if the given email already exists in the database
func (db *userConnection) IsDuplicateEmail(email string) (tx *gorm.DB) {
	var user User
	return db.connection.Where("email = ?", email).Take(&user)
}

// FindByEmail finds a user by email
func (db *userConnection) FindByEmail(email string) User {
	var user User
	db.connection.Where("email = ?", email).Take(&user)
	return user
}

// ProfileUser retrieves a user's profile by their ID, including associated products
func (db *userConnection) ProfileUser(userID uint) User {
	var user User
	db.connection.Preload("Products").Find(&user, userID)
	return user
}

// VerifyCredential verifies user credentials based on email and password
func (db *userConnection) VerifyCredential(email string, password string) interface{} {
	var user User
	res := db.connection.Where("email = ?", email).Take(&user)
	if res.Error == nil {
		err := bcrypt.CompareHashAndPassword([]byte(user.Password), []byte(password))
		if err == nil {
			return user
		}
	}
	return nil
}

// Test cases to verify the correctness of the implemented functions
func main() {
	db, err := gorm.Open(sqlite.Open("test.db"), &gorm.Config{})
	if err != nil {
		panic("failed to connect database")
	}

	// Migrate the schema
	db.AutoMigrate(&User{}, &Product{})

	userRepo := NewUserRepository(db)

	// Insert a new user
	newUser := User{Email: "test@example.com", Password: "password123"}
	userRepo.InsertUser(newUser)

	// Update user information
	updatedUser := User{ID: 1, Email: "test@example.com", Password: "newpassword123"}
	userRepo.UpdateUser(updatedUser)

	// Verify user credentials
	verifiedUser := userRepo.VerifyCredential("test@example.com", "newpassword123")
