	ctx, _ := context.WithTimeout(context.Background(), 10*time.Second)
	client, err := mongo.Connect(ctx, options.Client().ApplyURI(m.host))
	if err != nil {
		return err
	}
	collection := client.Database(m.database).Collection(m.name)
	var iface []interface{}
	for _, t := range docs {
		iface = append(iface, t)
	}
	_, err = collection.InsertMany(ctx, iface)
	return err
}

