func (e *ElasticsearchStorage) Store(docs []Doc) error {
	ctx := context.Background()
	client, err := elastic.NewClient(elastic.SetURL(e.host))
	if err != nil {
		return err
	}
	_, err = client.CreateIndex(e.name).BodyString(mapping).Do(ctx)
	if err != nil {
		return err
	}
	for _, item := range docs {
		_, err := client.Index().Index(e.name).BodyJson(item).Do(ctx)
		if err != nil {
			return err
		}
	}
	return nil
