package main

import (
	"fmt"
	"net"
)

// GetIp retrieves the first non-loopback IPv4 address and its corresponding MAC address.
func GetIp() (ip net.IP, mac net.HardwareAddr) {
	ifaces, err := net.Interfaces()
	if err != nil {
		return nil, nil
	}
	for _, iface := range ifaces {
		if iface.Flags&net.FlagUp == 0 {
			continue // interface down
		}
		if iface.Flags&net.FlagLoopback != 0 {
			continue // loopback interface
		}
		addrs, err := iface.Addrs()
		if err != nil {
			return nil, nil
		}
		for _, addr := range addrs {
			ip = getIpFromAddr(addr)
			if ip == nil {
				continue
			}

			mac = iface.HardwareAddr
			return ip, mac
		}
	}
	return nil, nil
}

// getIpFromAddr extracts the IPv4 address from a given net.Addr object.
func getIpFromAddr(addr net.Addr) net.IP {
	var ip net.IP
	switch v := addr.(type) {
	case *net.IPNet:
		ip = v.IP
	case *net.IPAddr:
		ip = v.IP
	}
	if ip == nil || ip.IsLoopback() {
		return nil
	}
	ip = ip.To4()
	if ip == nil {
		return nil // not an ipv4 address
	}

	return ip
}

func main() {
	ip, mac := GetIp()
	if ip != nil && mac != nil {
		fmt.Printf("IP: %s, MAC: %s\n", ip.String(), mac.String())
	} else {
		fmt.Println("No non-loopback IPv4 address and MAC address found.")
	}
}
