package main

import (
	"errors"
	"fmt"
)

var (
	ErrLocaleAlreadyExist   = errors.New("locale already exists")
	ErrUncertainArguments   = errors.New("arguments to i18n should not contain uncertain slices")
	ErrLocaleNotFound       = errors.New("locale not found")
	ErrTranslationKeyAbsent = errors.New("translation key does not exist")
)

type Locale struct {
	Name        string
	Translations map[string]string
}

type I18nManager struct {
	locales map[string]Locale
}

func NewI18nManager() *I18nManager {
	return &I18nManager{
		locales: make(map[string]Locale),
	}
}

func (i *I18nManager) RegisterLocale(name string, translations map[string]string) error {
	if _, exists := i.locales[name]; exists {
		return ErrLocaleAlreadyExist
	}
	if translations == nil {
		return ErrUncertainArguments
	}
	i.locales[name] = Locale{Name: name, Translations: translations}
	return nil
}

func (i *I18nManager) UpdateTranslation(localeName, key, translation string) error {
	locale, exists := i.locales[localeName]
	if !exists {
		return ErrLocaleNotFound
	}
	locale.Translations[key] = translation
	i.locales[localeName] = locale
	return nil
}

func (i *I18nManager) GetTranslation(localeName, key string) (string, error) {
	locale, exists := i.locales[localeName]
	if !exists {
		return "", ErrLocaleNotFound
	}
	translation, exists := locale.Translations[key]
	if !exists {
		return "", ErrTranslationKeyAbsent
	}
	return translation, nil
}

func (i *I18nManager) ListLocales() []string {
	localeNames := make([]string, 0, len(i.locales))
	for name := range i.locales {
		localeNames = append(localeNames, name)
	}
	return localeNames
}

func main() {
	manager := NewI18nManager()

	// Test case 1: Register a new locale
	err := manager.RegisterLocale("en-US", map[string]string{"hello": "Hello", "bye": "Goodbye"})
	if err != nil {
		fmt.Println(err)
	}

	// Test case 2: Attempt to register the same locale again
	err = manager.RegisterLocale("en-US", map[string]string{"hello": "Hello", "bye": "Goodbye"})
	if err != nil {
		fmt.Println(err) // Should print "locale already exists"
	}

	// Test case 3: Retrieve a translation
	translation, err := manager.GetTranslation("en-US", "hello")
	if err != nil {
		fmt.Println(err)
	} else {
		fmt.Println(translation) // Should print "Hello"
	}

	// Test case 4: Update a translation
	err = manager.UpdateTranslation("en-US", "bye", "Farewell")
	if err != nil {
		fmt.Println(err)
	}

	// Test case 5: Retrieve the updated translation
	translation, err = manager.GetTranslation("en-US", "bye")
	if err != nil {
		fmt.Println(err)
	} else {
		fmt.Println(translation) // Should print "Farewell"
	}

	// Test case 6: List all registered locales
	fmt.Println(manager.ListLocales()) // Should print "[en-US]"
}
