package main

import (
	"database/sql"
	"errors"
	"fmt"
	"log"

	"github.com/go-kratos/kratos/v2/log"
	"github.com/golang-migrate/migrate/v4"
	"github.com/golang-migrate/migrate/v4/database/mysql"
	_ "github.com/golang-migrate/migrate/v4/source/file"
)

// conf.Data struct holds the configuration for the database connection and migration path.
type Data struct {
	Database struct {
		Driver string
		Source string
	}
	Migrate struct {
		Path string
	}
}

// MigrateUp applies new migrations to update the database schema to the latest version.
func MigrateUp(c *Data, logger log.Logger) error {
	log := log.NewHelper(log.With(logger, "module", "migrate"))
	db, err := sql.Open(c.Database.Driver, c.Database.Source)
	if err != nil {
		log.Errorf("err = %v", err)
		return err
	}
	defer db.Close()

	driver, err := mysql.WithInstance(db, &mysql.Config{})
	if err != nil {
		log.Errorf("err = %v", err)
		return err
	}

	m, err := migrate.NewWithDatabaseInstance(
		fmt.Sprintf("file://%s", c.Migrate.Path),
		"mysql", driver)
	if err != nil {
		log.Errorf("err = %v", err)
		return err
	}
	defer m.Close()

	if err = m.Up(); err != nil && !errors.Is(err, migrate.ErrNoChange) {
		log.Errorf("err = %v", err)
		return err
	}

	log.Debugf("Database schema is up to date or successfully updated.")
	return nil
}

func main() {
	// Example configuration
	config := &Data{
		Database: struct {
			Driver string
			Source string
		}{
			Driver: "mysql",
			Source: "user:password@tcp(localhost:3306)/dbname",
		},
		Migrate: struct {
			Path string
		}{
			Path: "/path/to/migrations",
		},
	}

	// Example logger
	logger := log.NewStdLogger(log.Writer())

	// Perform the migration
	if err := MigrateUp(config, logger); err != nil {
		log.Errorf("Migration failed: %v", err)
	} else {
		log.Infof("Migration completed successfully.")
	}
}
