package main

import (
	"errors"
	"sync"
)

// Item represents a cache item with a primary key.
type Item struct {
	Key string
	// Other fields can be added here to represent the item's data.
}

// Cache represents a thread-safe in-memory cache.
type Cache struct {
	items          map[string]interface{}
	secondaryIndex map[string]string
	foreignIndex   map[string][]string
	mutex          sync.RWMutex
}

// NewCache creates a new instance of Cache.
func NewCache() *Cache {
	return &Cache{
		items:          make(map[string]interface{}),
		secondaryIndex: make(map[string]string),
		foreignIndex:   make(map[string][]string),
	}
}

// Get retrieves an item from the cache using its primary key.
func (c *Cache) Get(key string) (interface{}, error) {
	c.mutex.RLock()
	defer c.mutex.RUnlock()

	item, exists := c.items[key]
	if !exists {
		return nil, errors.New("item not found")
	}
	return item, nil
}

// GetItem retrieves a strongly-typed Item object from the cache using its primary key.
func (c *Cache) GetItem(key string) (*Item, error) {
	item, err := c.Get(key)
	if err != nil {
		return nil, err
	}

	typedItem, ok := item.(*Item)
	if !ok {
		return nil, errors.New("item is not of type *Item")
	}
	return typedItem, nil
}

// GetBySecondaryKey retrieves an item using its secondary key.
func (c *Cache) GetBySecondaryKey(secondaryKey string) (interface{}, error) {
	c.mutex.RLock()
	defer c.mutex.RUnlock()

	primary, exists := c.secondaryIndex[secondaryKey]
	if !exists {
		return nil, errors.New("item not found")
	}
	return c.Get(primary)
}

// GetItemBySecondaryKey retrieves a strongly-typed Item object using its secondary key.
func (c *Cache) GetItemBySecondaryKey(secondaryKey string) (*Item, error) {
	item, err := c.GetBySecondaryKey(secondaryKey)
	if err != nil {
		return nil, err
	}

	typedItem, ok := item.(*Item)
	if !ok {
		return nil, errors.New("item is not of type *Item")
	}
	return typedItem, nil
}

// GetForeignKeys retrieves a list of all foreign keys in the cache.
func (c *Cache) GetForeignKeys() []string {
	c.mutex.RLock()
	defer c.mutex.RUnlock()

	keys := make([]string, 0, len(c.foreignIndex))
	for key := range c.foreignIndex {
		keys = append(keys, key)
	}
	return keys
}

// GetItemsByForeignKey retrieves a list of Item objects associated with a foreign key.
func (c *Cache) GetItemsByForeignKey(foreignKey string) ([]*Item, error) {
	c.mutex.RLock()
	defer c.mutex.RUnlock()

	primaryKeys, exists := c.foreignIndex[foreignKey]
	if !exists {
		return nil, errors.New("foreign key not found")
	}

	items := make([]*Item, 0, len(primaryKeys))
	for _, key := range primaryKeys {
		item, err := c.GetItem(key)
		if err != nil {
			return nil, err
		}
		items = append(items, item)
	}
	return items, nil
}

// GetKeys retrieves a list of all primary keys in the cache.
func (c *Cache) GetKeys() []string {
	c.mutex.RLock()
	defer c.mutex.RUnlock()

	keys := make([]string, 0, len(c.items))
	for key := range c.items {
		keys = append(keys, key)
	}
	return keys
}

// HasItemChanged checks if an item has changed compared to the one stored in the cache.
func (c *Cache) HasItemChanged(key string, item interface{}) (bool, error) {
	cachedItem, err := c.Get(key)
	if err != nil {
		return false, err
	}
	return cachedItem != item, nil
}

// HasItemBySecondaryKeyChanged checks if an item with a secondary key has changed.
func (c *Cache) HasItemBySecondaryKeyChanged(secondaryKey string, item interface{}) (bool, error) {
	cachedItem, err := c.GetBySecondaryKey(secondaryKey)
	if err != nil {
		return false, err
	}
	return cachedItem != item, nil
}

// Set stores an item with its primary key.
func (c *Cache) Set(key string, item interface{}) error {
	c.mutex.Lock()
	defer c.mutex.Unlock()

	c.items[key] = item
	return nil
}

// SetWithSecondaryKey stores an item with both primary and secondary keys.
func (c *Cache) SetWithSecondaryKey(key string, secondaryKey string, item interface{}) error {
	if err := c.Set(key, item); err != nil {
		return err
	}

	c.mutex.Lock()
	defer c.mutex.Unlock()

	c.secondaryIndex[secondaryKey] = key
	return nil
}

// SetWithForeignKey stores an item with a foreign key.
func (c *Cache) SetWithForeignKey(key string, foreignKey string, item interface{}) error {
	if err := c.Set(key, item); err != nil {
		return err
	}

	c.mutex.Lock()
	defer c.mutex.Unlock()

	c.foreignIndex[foreignKey] = append(c.foreignIndex[foreignKey], key)
	return nil
}

// SetSecondaryKey associates a secondary key with an existing item.
func (c *Cache) SetSecondaryKey(key string, secondaryKey string) error {
	c.mutex.Lock()
	defer c.mutex.Unlock()

	if _, exists := c.items[key]; !exists {
		return errors.New("primary key not found")
	}

	c.secondaryIndex[secondaryKey] = key
	return nil
}

// SetForeignKey associates a foreign key with an existing item.
func (c *Cache) SetForeignKey(key string, foreignKey string) error {
	c.mutex.Lock()
	defer c.mutex.Unlock()

	if _, exists := c.items[key]; !exists {
		return errors.New("primary key not found")
	}

	c.foreignIndex[foreignKey] = append(c.foreignIndex[foreignKey], key)
	return nil
}

// Delete removes an item using its primary key.
func (c *Cache) Delete(key string) error {
	c.mutex.Lock()
	defer c.mutex.Unlock()

	delete(c.items, key)
	return nil
}

// DeleteBySecondaryKey removes an item using its secondary key.
func (c *Cache) DeleteBySecondaryKey(secondaryKey string) error {
	c.mutex.Lock()
	defer c.mutex.Unlock()

	primary, exists := c.secondaryIndex[secondaryKey]
	if !exists {
		return errors.New("secondary key not found")
	}

	delete(c.items, primary)
	delete(c.secondaryIndex, secondaryKey)
	return nil
}

// DeleteSecondaryKey removes the association of a secondary key with an item.
func (c *Cache) DeleteSecondaryKey(secondaryKey string) error {
	c.mutex.Lock()
	defer c.mutex.Unlock()

	delete(c.secondaryIndex, secondaryKey)
	return nil
}

// DeleteForeignKey removes the association of a foreign key with an item.
func (c *Cache) DeleteForeignKey(foreignKey string) error {
	c.mutex.Lock()
	defer c.mutex.Unlock()

	delete(c.foreignIndex, foreignKey)
	return nil
}

// DeleteItemsByForeignKey removes all items associated with a foreign key.
func (c *Cache) DeleteItemsByForeignKey(foreignKey string) error {
	c.mutex.Lock()
	defer c.mutex.Unlock()

	primaryKeys, exists := c.foreignIndex[foreignKey]
	if !exists {
		return errors.New("foreign key not found")
	}

	for _, key := range primaryKeys {
		delete(c.items, key)
	}
	delete(c.foreignIndex, foreignKey)
	return nil
}

// Flush clears all items from the cache.
func (c *Cache) Flush() {
	c.mutex.Lock()
	defer c.mutex.Unlock()

	c.items = make(map[string]interface{})
	c.secondaryIndex = make(map[string]string)
	c.foreignIndex = make(map[string][]string)
}

// Save saves the current state of the cache to a file.
func (c *Cache) Save(filename string) error {
	// Implementation for saving the cache state to a file goes here.
	return nil
}

// Load loads the cache state from a file.
func (c *Cache) Load(filename string) error {
	// Implementation for loading the cache state from a file goes here.
	return nil
}

// Test cases to verify the solution correctness.
func main() {
	cache := NewCache()

	// Test Set and Get
	err := cache.Set("key1", "value1")
	if err != nil {
		panic(err)
	}
	value, err := cache.Get("key1")
	if err != nil {
		panic(err)
	}
	if value != "value1" {
		panic("Set or Get not working correctly")
	}

	// Test SetWithSecondaryKey and GetBySecondaryKey
	err = cache.SetWithSecondaryKey("key2", "secondaryKey1", "value2")
	if err != nil {
		panic(err)
	}
	value, err = cache.GetBySecondaryKey("secondaryKey1")
	if err != nil {
		panic(err)
	}
	if value != "value2" {
		panic("SetWithSecondaryKey or GetBySecondaryKey not working correctly")
	}

	// Test SetWithForeignKey and GetItemsByForeignKey
	err = cache.SetWithForeignKey("key3", "foreignKey1", &Item{Key: "key3"})
	if err != nil {
		panic(err)
	}
	items, err := cache.GetItemsByForeignKey("foreignKey1")
	if err != nil {
		panic(err)
	}
	if len(items) != 1 || items[0].Key != "key3" {
		panic("SetWithForeignKey or GetItemsByForeignKey not working correctly")
	}

	// Test Delete and Get
	err = cache.Delete("key1")
