package main

import (
	crand "crypto/rand"
	"math/big"
	"strings"
)

const tokenAlphabet = "123456789abcdefghijkmnopqrstuvwxyzABCDEFGHJKLMNPQRSTUVWXYZ"

// GenerateToken creates a cryptographically secure, URL-safe token.
func GenerateToken(length int, hyphenate bool) (string, error) {
	var sb strings.Builder
	maxBigInt := big.NewInt(int64(len(tokenAlphabet)))

	for i := 0; i < length; i++ {
		randNum, err := crand.Int(crand.Reader, maxBigInt)
		if err != nil {
			return "", err
		}
		sb.WriteByte(tokenAlphabet[randNum.Int64()])
		if hyphenate && (i+1)%4 == 0 && i+1 < length {
			sb.WriteByte('-')
		}
	}

	return sb.String(), nil
}

// ValidateToken checks if the token is URL-safe and correctly encoded.
func ValidateToken(token string) (bool, error) {
	for _, char := range token {
		if !strings.ContainsRune(tokenAlphabet, char) && char != '-' {
			return false, nil
		}
	}
	return true, nil
}

func main() {
	// Example usage:
	token, err := GenerateToken(16, true)
	if err != nil {
		panic(err)
	}
	println("Generated Token:", token)

	valid, err := ValidateToken(token)
	if err != nil {
		panic(err)
	}
	println("Is Token Valid?", valid)
}
