package main

import (
	"fmt"
	"net/http"
	"testing"
)

// welcomeHandler responds with a welcome message for the root path.
func welcomeHandler(w http.ResponseWriter, r *http.Request) {
	if r.URL.Path != "/" {
		http.NotFound(w, r)
		return
	}
	fmt.Fprint(w, "Welcome to the Go HTTP Server!")
}

// TestServer tests the HTTP server response for the root and undefined paths.
func TestServer(t *testing.T) {
	// Define the server with the handler function.
	server := http.Server{
		Addr:    "localhost:8020",
		Handler: http.HandlerFunc(welcomeHandler),
	}

	// Start the server in a goroutine so it doesn't block.
	go func() {
		err := server.ListenAndServe()
		if err != nil && err != http.ErrServerClosed {
			panic(err)
		}
	}()
	defer server.Close()

	// Test cases for the server responses.
	tests := []struct {
		path       string
		wantStatus int
		wantBody   string
	}{
		{path: "/", wantStatus: http.StatusOK, wantBody: "Welcome to the Go HTTP Server!"},
		{path: "/undefined", wantStatus: http.StatusNotFound, wantBody: "404 page not found\n"},
	}

	// Run the test cases.
	for _, test := range tests {
		resp, err := http.Get("http://localhost:8020" + test.path)
		if err != nil {
			t.Fatalf("Could not make GET request: %v", err)
		}
		defer resp.Body.Close()

		// Check the status code.
		if resp.StatusCode != test.wantStatus {
			t.Errorf("handler returned wrong status code: got %v want %v",
				resp.StatusCode, test.wantStatus)
		}

		// Check the response body.
		buf := new(bytes.Buffer)
		buf.ReadFrom(resp.Body)
		gotBody := buf.String()
		if gotBody != test.wantBody {
			t.Errorf("handler returned unexpected body: got %v want %v",
				gotBody, test.wantBody)
		}
	}
}

func main() {
	// Define the server with the handler function.
	server := http.Server{
		Addr:    "localhost:8020",
		Handler: http.HandlerFunc(welcomeHandler),
	}

	// Start the server.
	fmt.Println("Server is running on http://localhost:8020")
	err := server.ListenAndServe()
	if err != nil {
		panic(err)
	}
}
