// IsInitPathValid checks if the given path matches the pattern of an initialization endpoint.
// The pattern is defined as `/init` followed by an optional slash and any number of additional characters.
// It returns true if the path matches the pattern, and false otherwise.
func IsInitPathValid(path string) (bool, error) {
	// Compile the regular expression pattern once to optimize performance
	pattern := regexp.MustCompile(`^/init(/.*)?$`)
	return pattern.MatchString(path), nil
}

func main() {
	// Test cases to verify the correctness of the IsInitPathValid function
	testCases := []struct {
		path     string
		expected bool
	}{
		{"/init", true},
		{"/init/", true},
		{"/init/abc", true},
		{"/init123", false},
		{"/initialize", false},
		{"/other", false},
	}

	// Iterate through test cases and check the result
	for _, testCase := range testCases {
		result, err := IsInitPathValid(testCase.path)
		if err != nil {
			fmt.Printf("Error while checking path '%s': %s\n", testCase.path, err)
			continue
		}
		if result == testCase.expected {
			fmt.Printf("Test passed for path '%s'\n", testCase.path)
		} else {
			fmt.Printf("Test failed for path '%s': expected %v, got %v\n", testCase.path, testCase.expected, result)
		}
	}
