package main

import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
)

func main() {
	apiDir, apiDirFound := os.LookupEnv("COGMENT_API_DIR")
	if !apiDirFound {
		fmt.Println("COGMENT_API_DIR environment variable must be set to the path to the api")
		os.Exit(1)
	}

	protocExec, protocFound := os.LookupEnv("PROTOC_EXEC")
	if !protocFound {
		fmt.Println("PROTOC_EXEC environment variable is not defined, using default value \"protoc\"")
		protocExec = "protoc"
	}

	packageDir := "grpcapi"

	fmt.Printf("Generating Go code from the Cogment API from %q using %q...\n", apiDir, protocExec)

	err := os.MkdirAll(packageDir, 0755)
	if err != nil {
		fmt.Printf("Error while creating package directory: %s\n", err)
		os.Exit(1)
	}

	protoFiles, err := filepath.Glob(filepath.Join(apiDir, "*.proto"))
	if err != nil {
		fmt.Printf("Error finding .proto files: %s\n", err)
		os.Exit(1)
	}

	protocArgs := []string{
		fmt.Sprintf("--proto_path=%s", apiDir),
		fmt.Sprintf("--go_out=%s", packageDir),
		fmt.Sprintf("--go-grpc_out=%s", packageDir),
		"--go_opt=paths=source_relative",
		"--go-grpc_opt=paths=source_relative",
	}

	if protobufIncludeDir, protobufIncludeDirFound := os.LookupEnv("PROTOBUF_INCLUDE_DIR"); protobufIncludeDirFound {
		protocArgs = append(protocArgs, fmt.Sprintf("--proto_path=%s", protobufIncludeDir))
	}

	for _, protoFile := range protoFiles {
		protoDir := filepath.Dir(protoFile)
		protocArgs = append(
			protocArgs,
			fmt.Sprintf("--go_opt=M%s=github.com/cogment/cogment/%s/%s", protoFile, packageDir, protoDir),
			fmt.Sprintf("--go-grpc_opt=M%s=github.com/cogment/cogment/%s/%s", protoFile, packageDir, protoDir),
		)
	}

	protocArgs = append(protocArgs, protoFiles...)

	protocCmd := exec.Command(protocExec, protocArgs...)
	protocCmd.Stdout = os.Stdout
	protocCmd.Stderr = os.Stderr

	err = protocCmd.Run()
	if err != nil {
		fmt.Printf("Error while running protoc: %s\n", err)
		os.Exit(1)
	}

	fmt.Println("Go code generation completed successfully.")
}

