// MakeName creates a node name that follows the convention
// for such names. It adds the operating system name and Go runtime version
// to the name.
func MakeName(name, version string) string {
	return fmt.Sprintf("%s/v%s/%s/%s", name, version, runtime.GOOS, runtime.Version())
}

// FileExist checks if a given file path exists on the file system.
func FileExist(filePath string) bool {
	_, err := os.Stat(filePath)
	return err == nil || !os.IsNotExist(err)
}

// AbsolutePath resolves the absolute path of a file given a data directory and a file name.
// If the file name is already an absolute path, it returns the file name as is.
func AbsolutePath(Datadir string, filename string) string {
	if filepath.IsAbs(filename) {
		return filename
	}
	return filepath.Join(Datadir, filename)
}

// Test cases to verify the correctness of the utility functions.
func TestMakeName(t *testing.T) {
	name := "node"
	version := "1.0.0"
	expected := fmt.Sprintf("node/v1.0.0/%s/%s", runtime.GOOS, runtime.Version())
	result := MakeName(name, version)
	if result != expected {
		t.Errorf("MakeName() = %v, want %v", result, expected)
	}
}

func TestFileExist(t *testing.T) {
	// Assuming the current file exists
	existingFile := "common.go"
	if !FileExist(existingFile) {
		t.Errorf("FileExist() = false, want true for existing file")
	}

	// Assuming this file does not exist
	nonExistingFile := "non_existing_file.go"
	if FileExist(nonExistingFile) {
		t.Errorf("FileExist() = true, want false for non-existing file")
	}
}

func TestAbsolutePath(t *testing.T) {
	datadir := "/tmp"
	filename := "data.txt"
	expected := "/tmp/data.txt"
	result := AbsolutePath(datadir, filename)
	if result != expected {
		t.Errorf("AbsolutePath() = %v, want %v", result, expected)
	}

	absoluteFilename := "/var/data.txt"
	result = AbsolutePath(datadir, absoluteFilename)
	if result != absoluteFilename {
		t.Errorf("AbsolutePath() = %v, want %v", result, absoluteFilename)
	}
}
