package main

import (
	"errors"
	"fmt"
)

// ScriptNum represents a numeric value in the script that can be pushed onto the stack.
type ScriptNum int

// DataStack represents a stack of data used by the virtual machine.
type DataStack struct {
	stack []interface{}
}

// DupN duplicates the top n items on the stack.
func (ds *DataStack) DupN(n int) error {
	if n <= 0 || n > len(ds.stack) {
		return errors.New("invalid number of items to duplicate")
	}
	topItems := make([]interface{}, n)
	copy(topItems, ds.stack[len(ds.stack)-n:])
	ds.stack = append(ds.stack, topItems...)
	return nil
}

// SwapN swaps the top n items with the next n items on the stack.
func (ds *DataStack) SwapN(n int) error {
	if n <= 0 || 2*n > len(ds.stack) {
		return errors.New("invalid number of items to swap")
	}
	topIndex := len(ds.stack) - n
	for i := 0; i < n; i++ {
		ds.stack[topIndex+i], ds.stack[topIndex-n+i] = ds.stack[topIndex-n+i], ds.stack[topIndex+i]
	}
	return nil
}

// PeekByteArray returns the item at index from the top of the stack without removing it.
func (ds *DataStack) PeekByteArray(index int) ([]byte, error) {
	if index < 0 || index >= len(ds.stack) {
		return nil, errors.New("index out of range")
	}
	item, ok := ds.stack[len(ds.stack)-1-index].([]byte)
	if !ok {
		return nil, errors.New("item at index is not a byte array")
	}
	return item, nil
}

// PushInt pushes an integer onto the stack.
func (ds *DataStack) PushInt(value ScriptNum) {
	ds.stack = append(ds.stack, value)
}

// DropN drops the top n items from the stack.
func (ds *DataStack) DropN(n int) error {
	if n <= 0 || n > len(ds.stack) {
		return errors.New("invalid number of items to drop")
	}
	ds.stack = ds.stack[:len(ds.stack)-n]
	return nil
}

// Engine represents the virtual machine that executes operations on the data stack.
type Engine struct {
	dstack DataStack
}

// opDup duplicates the top item on the stack.
func opDup(vm *Engine) error {
	return vm.dstack.DupN(1)
}

// op2Dup duplicates the top two items on the stack.
func op2Dup(vm *Engine) error {
	return vm.dstack.DupN(2)
}

// op3Dup duplicates the top three items on the stack.
func op3Dup(vm *Engine) error {
	return vm.dstack.DupN(3)
}

// opSwap swaps the top two items on the stack.
func opSwap(vm *Engine) error {
	return vm.dstack.SwapN(1)
}

// opSize pushes the size of the top item of the data stack onto the data stack.
func opSize(vm *Engine) error {
	so, err := vm.dstack.PeekByteArray(0)
	if err != nil {
		return err
	}
	vm.dstack.PushInt(ScriptNum(len(so)))
	return nil
}

// opDrop removes the top item from the data stack.
func opDrop(vm *Engine) error {
	return vm.dstack.DropN(1)
}

// Test cases to verify the solution correctness.
func main() {
	vm := Engine{dstack: DataStack{}}

	// Push some data onto the stack.
	vm.dstack.PushInt(10)
	vm.dstack.PushInt(20)
	vm.dstack.PushInt(30)

	// Perform operations.
	err := opDup(&vm)
	if err != nil {
		fmt.Println("Error:", err)
	}
	err = op2Dup(&vm)
	if err != nil {
		fmt.Println("Error:", err)
	}
	err = opSwap(&vm)
	if err != nil {
		fmt.Println("Error:", err)
	}
	err = opSize(&vm)
	if err != nil {
		fmt.Println("Error:", err)
	}
	err = opDrop(&vm)
	if err != nil {
		fmt.Println("Error:", err)
	}

	// Print the stack to verify the results.
	fmt.Println("Stack:", vm.dstack.stack)
}
