package main

import (
	"errors"
	"fmt"
	"time"
)

type Rate struct {
	PricePerUnit float64
	StartTime    time.Time
	EndTime      time.Time
}

type RatingPlan struct {
	ID    string
	Rates map[string]Rate
}

type Event struct {
	Duration     time.Duration
	Type         string
	RatingPlanID string
}

type RatingService struct {
	ratingPlans map[string]RatingPlan
}

func NewRatingService() *RatingService {
	return &RatingService{
		ratingPlans: make(map[string]RatingPlan),
	}
}

func (rs *RatingService) AddRatingPlan(plan RatingPlan) {
	rs.ratingPlans[plan.ID] = plan
}

func (rs *RatingService) AddRateToPlan(planID string, eventType string, rate Rate) error {
	plan, exists := rs.ratingPlans[planID]
	if !exists {
		return errors.New("rating plan does not exist")
	}
	if plan.Rates == nil {
		plan.Rates = make(map[string]Rate)
	}
	plan.Rates[eventType] = rate
	rs.ratingPlans[planID] = plan
	return nil
}

func (rs *RatingService) CalculateCost(event Event) (float64, error) {
	plan, exists := rs.ratingPlans[event.RatingPlanID]
	if !exists {
		return 0, errors.New("rating plan does not exist")
	}
	rate, exists := plan.Rates[event.Type]
	if !exists {
		return 0, errors.New("rate for event type does not exist")
	}
	if event.Duration < 0 {
		return 0, errors.New("event duration cannot be negative")
	}
	return float64(event.Duration) * rate.PricePerUnit, nil
}

func main() {
	ratingService := NewRatingService()

	// Define a rating plan
	ratingPlan := RatingPlan{
		ID:    "RP1",
		Rates: make(map[string]Rate),
	}
	ratingService.AddRatingPlan(ratingPlan)

	// Add rates to the rating plan
	startTime, _ := time.Parse(time.RFC3339, "2023-01-01T00:00:00Z")
	endTime, _ := time.Parse(time.RFC3339, "2023-12-31T23:59:59Z")
	rate := Rate{
		PricePerUnit: 0.05,
		StartTime:    startTime,
		EndTime:      endTime,
	}
	err := ratingService.AddRateToPlan("RP1", "voice", rate)
	if err != nil {
		fmt.Println("Error adding rate to plan:", err)
	}

	// Calculate the cost of an event
	event := Event{
		Duration:     10 * time.Minute,
		Type:         "voice",
		RatingPlanID: "RP1",
	}
	cost, err := ratingService.CalculateCost(event)
	if err != nil {
		fmt.Println("Error calculating cost:", err)
	} else {
		fmt.Printf("The cost of the event is: $%.2f\n", cost)
	}
}
