// Function to extract the names of available zones
func (r *NovaListAvailabilityZonesResponse) AvailableZones() []string {
	var availableZones []string
	for _, zone := range r.AvailabilityZoneInfo {
		if zone.ZoneState.Available {
			availableZones = append(availableZones, zone.ZoneName)
		}
	}
	return availableZones
}

