			}
		]
	}`

	// Unmarshal the JSON response into the struct
	var response NovaListAvailabilityZonesResponse
	err := json.Unmarshal([]byte(jsonResponse), &response)
	if err != nil {
		fmt.Println("Error unmarshaling JSON:", err)
