package main

import (
	"encoding/json"
	"fmt"
	"io/ioutil"
	"os"
	"strings"

	"github.com/spf13/cobra"
)

var (
	inputTextFile   string
	outputJsonFile  string
	printOutput     bool
)

func main() {
	var rootCmd = &cobra.Command{Use: "KVTJ"}
	rootCmd.AddCommand(keyValueToJsonCmd)
	rootCmd.Execute()
}

var keyValueToJsonCmd = &cobra.Command{
	Use:   "KVTJ [flags]",
	Short: "Converts Key-Value (text) to JSON.",
	Run: func(cmd *cobra.Command, args []string) {
		content, err := ioutil.ReadFile(inputTextFile)
		if err != nil {
			fmt.Println("Error reading input file:", err)
			os.Exit(1)
		}

		if len(content) == 0 {
			fmt.Println("Input file is empty.")
			os.Exit(1)
		}

		entries := strings.Split(string(content), "\n")
		m := make(map[string]string)
		for _, e := range entries {
			if e == "" || strings.HasPrefix(e, "#") || strings.HasPrefix(e, "//") || !strings.Contains(e, "=") {
				continue
			}

			parts := strings.SplitN(e, "=", 2)
			key := strings.TrimSpace(parts[0])
			value := strings.Trim(strings.TrimSpace(parts[1]), "\"'")

			m[key] = value
		}

		jsonString, err := json.MarshalIndent(m, "", "  ")
		if err != nil {
			fmt.Println("Error converting to JSON:", err)
			os.Exit(1)
		}

		if printOutput {
			fmt.Println(string(jsonString))
		} else {
			if outputJsonFile == "" {
				outputJsonFile = "output.json"
			}

			err = ioutil.WriteFile(outputJsonFile, jsonString, 0644)
			if err != nil {
				fmt.Println("Error writing output file:", err)
				os.Exit(1)
			}

			fmt.Println("Operation completed successfully. Check the", outputJsonFile, "file.")
		}
	},
}

func init() {
	keyValueToJsonCmd.Flags().StringVarP(&inputTextFile, "file", "f", "", "Input the text file name. Eg: keys.txt or .env")
	keyValueToJsonCmd.MarkFlagRequired("file")

	keyValueToJsonCmd.Flags().StringVarP(&outputJsonFile, "output", "o", "", "Output JSON file name (default is output.json)")
	keyValueToJsonCmd.Flags().BoolVarP(&printOutput, "print", "p", false, "Print the output to the console")
}

