package main

import (
	"fmt"
	"log"
	"math"
	"os"
	"strconv"
	"time"

	"github.com/joho/godotenv"
)

// LoadConfig reads the configuration from the given .env file and returns an IConfig interface.
func LoadConfig(path string) IConfig {
	// Load the .env file into a map
	envMap, err := godotenv.Read(path)
	if err != nil {
		log.Fatalf("Error loading .env file: %v", err)
	}

	// Parse and set the configuration values
	return &config{
		app: &app{
			host:            envMap["APP_HOST"],
			port:            parseEnvInt(envMap["APP_PORT"], "APP_PORT"),
			name:            envMap["APP_NAME"],
			version:         envMap["APP_VERSION"],
			readTimeout:     parseEnvDuration(envMap["APP_READ_TIMEOUT"], "APP_READ_TIMEOUT"),
			writeTimeout:    parseEnvDuration(envMap["APP_WRITE_TIMEOUT"], "APP_WRITE_TIMEOUT"),
			bodyLimit:       parseEnvInt(envMap["APP_BODY_LIMIT"], "APP_BODY_LIMIT"),
			usersGrpcUrl:    envMap["USERS_GRPC_URL"],
			authGrpcUrl:     envMap["AUTH_GRPC_URL"],
			productsGrpcUrl: envMap["PRODUCTS_GRPC_URL"],
		},
		db: &db{
			host:           envMap["DB_HOST"],
			port:           parseEnvInt(envMap["DB_PORT"], "DB_PORT"),
			protocol:       envMap["DB_PROTOCOL"],
			username:       envMap["DB_USERNAME"],
			password:       envMap["DB_PASSWORD"],
			database:       envMap["DB_DATABASE"],
			sslMode:        envMap["DB_SSL_MODE"],
			maxConnections: parseEnvInt(envMap["DB_MAX_CONNECTIONS"], "DB_MAX_CONNECTIONS"),
		},
		jwt: &jwt{
			secretKey:        envMap["JWT_SECRET_KEY"],
			apiKey:           envMap["JWT_API_KEY"],
			accessExpiresAt:  parseEnvInt(envMap["JWT_ACCESS_EXPIRES"], "JWT_ACCESS_EXPIRES"),
			refreshExpiresAt: parseEnvInt(envMap["JWT_REFRESH_EXPIRES"], "JWT_REFRESH_EXPIRES"),
		},
	}
}

// Helper function to parse integer values from the environment variables.
func parseEnvInt(value string, key string) int {
	parsedValue, err := strconv.Atoi(value)
	if err != nil {
		log.Fatalf("Error parsing %s: %v", key, err)
	}
	return parsedValue
}

// Helper function to parse duration values from the environment variables.
func parseEnvDuration(value string, key string) time.Duration {
	parsedValue, err := strconv.Atoi(value)
	if err != nil {
		log.Fatalf("Error parsing %s: %v", key, err)
	}
	return time.Duration(int64(parsedValue) * int64(math.Pow10(9)))
}

// Define the interfaces and structs for the configuration.

