type JSONHandler struct{}

func (h *JSONHandler) HandleSimpleRequest(jsonStr string) (string, error) {
	var obj map[string]interface{}
	if err := json.Unmarshal([]byte(jsonStr), &obj); err != nil {
		return "", err
	}
	payload, ok := obj["payload"].(string)
	if !ok {
		return "", fmt.Errorf("payload is not a string")
	}
	return payload, nil
}

func (h *JSONHandler) HandleComplexRequest(jsonStr string) (map[string]interface{}, error) {
	var obj map[string]interface{}
	if err := json.Unmarshal([]byte(jsonStr), &obj); err != nil {
		return nil, err
	}
	payload, ok := obj["payload"].(map[string]interface{})
	if !ok {
		return nil, fmt.Errorf("payload is not a map")
	}
	return payload, nil
}

func main() {
	handler := JSONHandler{}

	// Test simple request
	simpleReq := `{"type":"Post", "payload":"1"}`
	payloadStr, err := handler.HandleSimpleRequest(simpleReq)
