package inventory

import (
	"errors"
	"sync"
)

// Product represents the details of a product in the inventory.
type Product struct {
	ID       string
	Name     string
	Quantity int
	Price    float64
}

// Inventory manages a collection of products.
type Inventory struct {
	mu       sync.RWMutex
	products map[string]*Product
	pool     sync.Pool
}

// NewInventory creates a new instance of Inventory.
func NewInventory() *Inventory {
	return &Inventory{
		products: make(map[string]*Product),
		pool: sync.Pool{
			New: func() any {
				return new(Product)
			},
		},
	}
}

// AddProduct adds a new product to the inventory.
func (inv *Inventory) AddProduct(id, name string, quantity int, price float64) error {
	inv.mu.Lock()
	defer inv.mu.Unlock()

	if _, exists := inv.products[id]; exists {
		return errors.New("product already exists")
	}

	product := inv.pool.Get().(*Product)
	product.ID = id
	product.Name = name
	product.Quantity = quantity
	product.Price = price

	inv.products[id] = product
	return nil
}

// GetProduct retrieves a product's details by its ID.
func (inv *Inventory) GetProduct(id string) (*Product, error) {
	inv.mu.RLock()
	defer inv.mu.RUnlock()

	product, exists := inv.products[id]
	if !exists {
		return nil, errors.New("product not found")
	}

	return product, nil
}

// UpdateProduct updates the details of an existing product by its ID.
func (inv *Inventory) UpdateProduct(id, name string, quantity int, price float64) error {
	inv.mu.Lock()
	defer inv.mu.Unlock()

	product, exists := inv.products[id]
	if !exists {
		return errors.New("product not found")
	}

	product.Name = name
	product.Quantity = quantity
	product.Price = price

	return nil
}

// ResetProduct resets the product details to their default values.
func (inv *Inventory) ResetProduct(id string) error {
	inv.mu.Lock()
	defer inv.mu.Unlock()

	product, exists := inv.products[id]
	if !exists {
		return errors.New("product not found")
	}

	product.Name = ""
	product.Quantity = 0
	product.Price = 0.0

	inv.pool.Put(product)
	delete(inv.products, id)

	return nil
}

// Test cases to verify the solution correctness.
func main() {
	inv := NewInventory()

	// Test AddProduct
	err := inv.AddProduct("p1", "Product 1", 100, 10.99)
	if err != nil {
		panic(err)
	}

	// Test GetProduct
	product, err := inv.GetProduct("p1")
	if err != nil {
		panic(err)
	}
	if product.ID != "p1" || product.Name != "Product 1" || product.Quantity != 100 || product.Price != 10.99 {
		panic("GetProduct returned incorrect product details")
	}

	// Test UpdateProduct
	err = inv.UpdateProduct("p1", "Updated Product 1", 150, 9.99)
	if err != nil {
		panic(err)
	}
	product, err = inv.GetProduct("p1")
	if err != nil {
		panic(err)
	}
	if product.Name != "Updated Product 1" || product.Quantity != 150 || product.Price != 9.99 {
		panic("UpdateProduct did not update product details correctly")
	}

	// Test ResetProduct
	err = inv.ResetProduct("p1")
	if err != nil {
		panic(err)
	}
	_, err = inv.GetProduct("p1")
	if err == nil {
		panic("ResetProduct did not remove the product from inventory")
	}
}
