package main

import (
	"fmt"
)

// singleNumber finds the element that appears once in an array where every other element appears exactly three times.
func singleNumber(nums []int) int {
	// Initialize variables to hold the bits that have appeared once and twice.
	once, twice := 0, 0

	for _, num := range nums {
		// For the current number, update the bits that have appeared once and twice.
		once = (once ^ num) & ^twice
		twice = (twice ^ num) & ^once
	}

	// The bits that have appeared once represent the single number.
	return once
}

func main() {
	// Example test cases
	fmt.Println(singleNumber([]int{3, 4, 3, 3})) // Output: 4
	fmt.Println(singleNumber([]int{9, 1, 7, 9, 7, 9, 7})) // Output: 1
}

// Test cases to verify the solution correctness.
func TestSingleNumber(t *testing.T) {
	testCases := []struct {
		input []int
		want  int
	}{
		{[]int{3, 4, 3, 3}, 4},
		{[]int{9, 1, 7, 9, 7, 9, 7}, 1},
		{[]int{2, 2, 3, 2}, 3},
		{[]int{0, 1, 0, 1, 0, 1, 99}, 99},
	}

	for _, tc := range testCases {
		got := singleNumber(tc.input)
		if tc.want != got {
			t.Errorf("For input %v; expected %d, but got %d", tc.input, tc.want, got)
		}
	}
}
