// CustomFormatter is a custom logrus formatter
type CustomFormatter struct {
	NoColors bool
}

// Format formats the log entry according to the custom formatter rules
func (f *CustomFormatter) Format(entry *logrus.Entry) ([]byte, error) {
	timestamp := entry.Time.Format("2006-01-02 15:04:05")
	level := entry.Level.String()
	if !f.NoColors {
		switch entry.Level {
		case logrus.InfoLevel:
			level = "\x1b[34mINFO\x1b[0m"
		case logrus.WarnLevel:
			level = "\x1b[33mWARN\x1b[0m"
		case logrus.ErrorLevel:
			level = "\x1b[31mERROR\x1b[0m"
		}
	} else {
		level = strings.ToUpper(level)
	}
	return []byte(fmt.Sprintf("%s [%s] %s\n", timestamp, level, entry.Message)), nil
}

// SetupLogger initializes the logger with the custom formatter
func SetupLogger(noColors bool) {
	logrus.SetFormatter(&CustomFormatter{NoColors: noColors})
}

// LogInfo logs an info level message
func LogInfo(message string) {
	logrus.Info(message)
}

// LogWarning logs a warning level message
func LogWarning(message string) {
	logrus.Warn(message)
}

// LogError logs an error level message
func LogError(message string) {
	logrus.Error(message)
}

func main() {
	// Initialize the logger without colors
	SetupLogger(true)

	// Log messages at different levels
	LogInfo("This is an info message.")
	LogWarning("This is a warning message.")
	LogError("This is an error message.")

	// Reinitialize the logger with colors
	SetupLogger(false)

	// Log messages at different levels with color
	LogInfo("This is an info message with color.")
	LogWarning("This is a warning message with color.")
	LogError("This is an error message with color.")
}

