func calculadoraSimples() {
	var x, n, n0 int
	fmt.Println("Choose an operation: ")
	fmt.Println("1 -> Addition (+)")
	fmt.Println("2 -> Subtraction (-)")
	fmt.Println("3 -> Multiplication (*)")
	fmt.Println("4 -> Division (/)")
	fmt.Println("5 -> Exit")
	fmt.Scan(&x)

	switch x {
	case 1:
		n, n0 = readOperands()
		fmt.Println("The result is:", add(n, n0))
	case 2:
		n, n0 = readOperands()
		fmt.Println("The result is:", subtract(n, n0))
	case 3:
		n, n0 = readOperands()
		fmt.Println("The result is:", multiply(n, n0))
	case 4:
		n, n0 = readOperands()
		result, err := divide(n, n0)
		if err != nil {
			fmt.Println("Error:", err)
		} else {
			fmt.Println("The result is:", result)
		}
	case 5:
		fmt.Println("Exiting the calculator.")
