import (
	"bufio"
	"fmt"
	"os"
	"strings"
)

// isPalindrome checks if a given string is a palindrome.
func isPalindrome(s string) bool {
	// Normalize the string: remove spaces, punctuation, and make it lowercase.
	normalized := strings.ToLower(s)
	normalized = strings.ReplaceAll(normalized, " ", "")
	normalized = strings.ReplaceAll(normalized, ",", "")
	normalized = strings.ReplaceAll(normalized, ".", "")

	// Compare characters from the beginning and the end moving towards the center.
	for i, j := 0, len(normalized)-1; i < j; i, j = i+1, j-1 {
		if normalized[i] != normalized[j] {
			return false
		}
	}
	return true
}

// readInput reads strings from the standard input until an empty line is entered.
func readInput() {
	scanner := bufio.NewScanner(os.Stdin)
	fmt.Println("Enter strings to check for palindrome. An empty line to stop.")

	for {
		fmt.Printf("Type Something?: ")
		scanner.Scan()
		input := scanner.Text()

		// Stop if the input is an empty line.
		if input == "" {
			break
		}

		// Check if the input is a palindrome and print the result.
		if isPalindrome(input) {
			fmt.Printf("%q is a palindrome.\n", input)
		} else {
			fmt.Printf("%q is not a palindrome.\n", input)
		}
	}
}

func main() {
	readInput()
}
