package main

import (
	"flag"
	"fmt"
	"time"

	"github.com/robfig/cron/v3"
)

// Command interface that all commands should implement.
type Command interface {
	Execute()
}

// ExampleCommand struct that implements the Command interface.
type ExampleCommand struct{}

// Execute method for ExampleCommand.
func (ec *ExampleCommand) Execute() {
	fmt.Println("Executing Example Command")
}

// SpecJob struct that holds the cron specification, command, and description.
type SpecJob struct {
	Spec        string
	Command     Command
	Description string
}

// SpecCron map that associates job names with SpecJob.
var SpecCron = map[string]SpecJob{
	"example": {"@every 1s", new(ExampleCommand), "test example"},
}

// Scheduler that can register and execute jobs.
type Scheduler struct {
	cron *cron.Cron
}

// NewScheduler creates a new Scheduler instance.
func NewScheduler() *Scheduler {
	return &Scheduler{
		cron: cron.New(),
	}
}

// RegisterJob registers a job with the scheduler.
func (s *Scheduler) RegisterJob(name string, job SpecJob) error {
	_, err := s.cron.AddFunc(job.Spec, job.Command.Execute)
	if err != nil {
		return err
	}
	fmt.Printf("Registered job: %s - %s\n", name, job.Description)
	return nil
}

// Start begins the scheduler.
func (s *Scheduler) Start() {
	s.cron.Start()
}

// Stop stops the scheduler.
func (s *Scheduler) Stop() {
	s.cron.Stop()
}

func main() {
	var jobName string
	flag.StringVar(&jobName, "name", "", "job name to start")
	flag.Parse()

	if jobName == "" {
		fmt.Println("Please specify a job name using the -name flag.")
		return
	}

	job, exists := SpecCron[jobName]
	if !exists {
		fmt.Printf("Job %s not found.\n", jobName)
		return
	}

	scheduler := NewScheduler()
	if err := scheduler.RegisterJob(jobName, job); err != nil {
		fmt.Printf("Error registering job: %s\n", err)
		return
	}

	scheduler.Start()
	fmt.Println("Scheduler started. Press Ctrl+C to stop.")
	select {} // Block forever, or until an interrupt signal is received.
}

