	"github.com/pkg/errors"
	"github.com/stretchr/testify/assert"
	authUsecase "timetracker/internal/Auth/usecase"
)

// User is a placeholder for the user model.
type User struct {
	ID string
}

// authUsecaseMock is a mock implementation of the authUsecase interface for testing.
type authUsecaseMock struct{}

func (a *authUsecaseMock) Auth(token string) (User, error) {
	if token == "valid_token" {
		return User{ID: "123"}, nil
	}
	return User{}, errors.New("invalid token")
}

// Middleware is the authentication middleware.
type Middleware struct {
	authUC authUsecase.UsecaseI
}

func NewMiddleware(authUC authUsecase.UsecaseI) *Middleware {
	return &Middleware{authUC: authUC}
}

func (m *Middleware) Auth(next echo.HandlerFunc) echo.HandlerFunc {
	return func(c echo.Context) error {
		if c.Request().URL.Path == "/signup" || c.Request().URL.Path == "/signin" ||
			c.Request().URL.Path == "/auth" || c.Request().URL.Path == "/prometheus" ||
			c.Request().URL.Path == "/favicon.ico" {
			return next(c)
		}

		cookie, err := c.Cookie("session_token")
		if err == http.ErrNoCookie {
			return echo.NewHTTPError(http.StatusUnauthorized, "authentication required")
		} else if err != nil {
			return echo.NewHTTPError(http.StatusBadRequest, "invalid request")
		}

		user, err := m.authUC.Auth(cookie.Value)
		if err != nil {
			return echo.NewHTTPError(http.StatusUnauthorized, "invalid or expired session token")
		}

		c.Set("user_id", user.ID)
		c.Set("user", user)

		return next(c)
	}
}

// Test cases to verify the middleware's correctness.
func TestAuthMiddleware(t *testing.T) {
	e := echo.New()
	req := httptest.NewRequest(http.MethodGet, "/", nil)
	rec := httptest.NewRecorder()
	c := e.NewContext(req, rec)
	handler := func(c echo.Context) error {
		return c.String(http.StatusOK, "test")
	}

	authMiddleware := NewMiddleware(&authUsecaseMock{})

	// Test case: Request without a session token should fail.
	req = httptest.NewRequest(http.MethodGet, "/", nil)
	rec = httptest.NewRecorder()
	c = e.NewContext(req, rec)
	err := authMiddleware.Auth(handler)(c)
	assert.Equal(t, http.StatusUnauthorized, rec.Code)
	assert.NotNil(t, err)

	// Test case: Request with an invalid session token should fail.
	req = httptest.NewRequest(http.MethodGet, "/", nil)
	req.AddCookie(&http.Cookie{Name: "session_token", Value: "invalid_token"})
	rec = httptest.NewRecorder()
	c = e.NewContext(req, rec)
	err = authMiddleware.Auth(handler)(c)
	assert.Equal(t, http.StatusUnauthorized, rec.Code)
	assert.NotNil(t, err)

	// Test case: Request with a valid session token should succeed.
	req = httptest.NewRequest(http.MethodGet, "/", nil)
	req.AddCookie(&http.Cookie{Name: "session_token", Value: "valid_token"})
	rec = httptest.NewRecorder()
	c = e.NewContext(req, rec)
	err = authMiddleware.Auth(handler)(c)
	assert.Equal(t, http.StatusOK, rec.Code)
	assert.Nil(t, err)

	// Test case: Request to an authentication bypass path should succeed.
	req = httptest.NewRequest(http.MethodGet, "/signin", nil)
	rec = httptest.NewRecorder()
	c = e.NewContext(req, rec)
	err = authMiddleware.Auth(handler)(c)
	assert.Equal(t, http.StatusOK, rec.Code)
	assert.Nil(t, err)
}
