	"io/ioutil"
	"net/http"
	"os"
	"path/filepath"
	"time"
)

// SystemConfig represents the system configuration data.
type SystemConfig struct {
	// Add configuration fields here.
	Version string `json:"version"`
}

// SystemConfigProvider defines the interface for fetching system configuration.
type SystemConfigProvider interface {
	SystemConfig() (*SystemConfig, error)
}

// FilesystemCache is responsible for caching data on the filesystem.
type FilesystemCache struct {
	Dir      string
	Filename string
	TTL      time.Duration
}

// CacheData represents the structure of cached data.
type CacheData struct {
	Data      []byte
	Timestamp time.Time
}

// Serve checks the cache and either serves the cached data or fetches new data using the provided make function.
func (c *FilesystemCache) Serve(make func() ([]byte, error)) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		cachePath := filepath.Join(c.Dir, c.Filename)
		var data []byte
		var err error

		// Check if the cache file exists and is still valid.
		info, err := os.Stat(cachePath)
		if err == nil && time.Since(info.ModTime()) < c.TTL {
			// Cache is valid, read the data from the cache.
			data, err = ioutil.ReadFile(cachePath)
			if err != nil {
				http.Error(w, "Failed to read from cache", http.StatusInternalServerError)
				return
			}
		} else {
			// Cache is invalid or does not exist, fetch new data.
			data, err = make()
			if err != nil {
				http.Error(w, "Failed to fetch new data", http.StatusInternalServerError)
				return
			}

			// Write the new data to the cache.
			err = ioutil.WriteFile(cachePath, data, 0644)
			if err != nil {
				http.Error(w, "Failed to write to cache", http.StatusInternalServerError)
				return
			}
		}

		// Serve the data.
		w.Header().Set("Content-Type", "application/json")
		w.Write(data)
	})
}

// MockSystemConfigProvider is a mock implementation of SystemConfigProvider for testing purposes.
type MockSystemConfigProvider struct{}

// SystemConfig returns a mock system configuration.
func (m *MockSystemConfigProvider) SystemConfig() (*SystemConfig, error) {
	return &SystemConfig{Version: "1.0.0"}, nil
}

// SystemConfigHandler handles requests for the system configuration.
type SystemConfigHandler struct {
	SystemConfig    SystemConfigProvider
	FilesystemCache *FilesystemCache
}

// ServeHTTP implements the http.Handler interface for SystemConfigHandler.
func (h *SystemConfigHandler) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	make := func() ([]byte, error) {
		cfg, err := h.SystemConfig.SystemConfig()
		if err != nil {
			return nil, err
		}

		b, err := json.Marshal(cfg)
		if err != nil {
			return nil, err
		}

		return b, nil
	}

	h.FilesystemCache.Serve(make).ServeHTTP(w, r)
}

func main() {
	// Set up the cache directory.
	cacheDir := "./cache"
	if err := os.MkdirAll(cacheDir, 0755); err != nil {
		panic("Failed to create cache directory: " + err.Error())
	}

	// Create the FilesystemCache and SystemConfigHandler.
	filesystemCache := &FilesystemCache{
		Dir:      cacheDir,
		Filename: "system-config.json",
		TTL:      5 * time.Minute,
	}
	handler := &SystemConfigHandler{
		SystemConfig:    &MockSystemConfigProvider{},
		FilesystemCache: filesystemCache,
	}

	// Set up the HTTP server.
	http.Handle("/api/system-config.json", handler)
	http.ListenAndServe(":8080", nil)
}

