	err := wc.vim.Command(fmt.Sprintf("highlight %s ctermbg=darkgrey guibg=lightgrey", highlightGroup))
	if err != nil {
		return fmt.Errorf("failed to define highlight group: %w", err)
	}

	// Set the highlight for the entire line
	lineNumber := cursor[0]
	startCol := 0
	endCol := -1 // -1 signifies the end of the line
	err = wc.vim.Command(fmt.Sprintf("call matchaddpos('%s', [[%d, %d, %d]])", highlightGroup, lineNumber, startCol, endCol))
	if err != nil {
		return fmt.Errorf("failed to set highlight: %w", err)
	}

	return nil
}

