func (pc *PipelineCollection) AddPipeline(metadata PipelineMetadata) error {
	for _, p := range pc.pipelines {
		if p.Type == metadata.Type && p.Version == metadata.Version {
			return errors.New("pipeline with the same type and version already exists")
		}
	}
	pc.pipelines = append(pc.pipelines, metadata)
	return nil
}

