package main

import (
	"context"
	"fmt"

	"github.com/aws/aws-sdk-go-v2/aws"
	"github.com/aws/aws-sdk-go-v2/config"
	awselb "github.com/aws/aws-sdk-go-v2/service/elasticloadbalancing"
	awselbtypes "github.com/aws/aws-sdk-go-v2/service/elasticloadbalancing/types"
)

type ELBAttachment struct {
	ELBName    string
	InstanceID string
	Attached   bool
}

func Observe(ctx context.Context, elbClient *awselb.Client, attachment *ELBAttachment) error {
	output, err := elbClient.DescribeLoadBalancers(ctx, &awselb.DescribeLoadBalancersInput{
		LoadBalancerNames: []string{attachment.ELBName},
	})
	if err != nil {
		return fmt.Errorf("failed to describe load balancers: %w", err)
	}

	for _, lb := range output.LoadBalancerDescriptions {
		for _, instance := range lb.Instances {
			if aws.ToString(instance.InstanceId) == attachment.InstanceID {
				attachment.Attached = true
				return nil
			}
		}
	}

	attachment.Attached = false
	return nil
}

func Create(ctx context.Context, elbClient *awselb.Client, attachment *ELBAttachment) error {
	if attachment.Attached {
		fmt.Println("Instance is already attached to the ELB.")
		return nil
	}

	_, err := elbClient.RegisterInstancesWithLoadBalancer(ctx, &awselb.RegisterInstancesWithLoadBalancerInput{
		LoadBalancerName: aws.String(attachment.ELBName),
		Instances:        []awselbtypes.Instance{{InstanceId: aws.String(attachment.InstanceID)}},
	})
	if err != nil {
		return fmt.Errorf("failed to attach instance to ELB: %w", err)
	}

	attachment.Attached = true
	fmt.Println("Instance attached to the ELB successfully.")
	return nil
}

func Delete(ctx context.Context, elbClient *awselb.Client, attachment *ELBAttachment) error {
	if !attachment.Attached {
		fmt.Println("Instance is not attached to the ELB.")
		return nil
	}

	_, err := elbClient.DeregisterInstancesFromLoadBalancer(ctx, &awselb.DeregisterInstancesFromLoadBalancerInput{
		LoadBalancerName: aws.String(attachment.ELBName),
		Instances:        []awselbtypes.Instance{{InstanceId: aws.String(attachment.InstanceID)}},
	})
	if err != nil {
		return fmt.Errorf("failed to detach instance from ELB: %w", err)
	}

	attachment.Attached = false
	fmt.Println("Instance detached from the ELB successfully.")
	return nil
}

func main() {
	ctx := context.Background()
	cfg, err := config.LoadDefaultConfig(ctx)
	if err != nil {
		panic(fmt.Sprintf("unable to load SDK config, %v", err))
	}

	elbClient := awselb.NewFromConfig(cfg)

	// Example ELBAttachment resource
	attachment := &ELBAttachment{
		ELBName:    "my-elb",
		InstanceID: "i-1234567890abcdef0",
	}

	// Observe the attachment state
	if err := Observe(ctx, elbClient, attachment); err != nil {
		fmt.Printf("Observe error: %s\n", err)
	} else {
		fmt.Printf("Observe success: Attached = %v\n", attachment.Attached)
	}

	// Attach the instance to the ELB
	if err := Create(ctx, elbClient, attachment); err != nil {
		fmt.Printf("Create error: %s\n", err)
	}

	// Detach the instance from the ELB
	if err := Delete(ctx, elbClient, attachment); err != nil {
		fmt.Printf("Delete error: %s\n", err)
	}
}
