// Assuming a mock metrics service interface for the sake of example.
type metricsService interface {
	Presenter() string
}

// MockMetricsService is a mock implementation of a metrics service.
type MockMetricsService struct{}

// Presenter returns the type of the metrics presenter.
func (m *MockMetricsService) Presenter() string {
	return "prometheus"
}

var metricsNamespace = "execd"

var latestBlock prometheus.Gauge
var blocksProcessed prometheus.Gauge

func registerMetrics(ctx context.Context, monitor metricsService) error {
	if latestBlock != nil {
		// Already registered.
		return nil
	}
	if monitor == nil {
		// No monitor.
		return nil
	}
	if monitor.Presenter() == "prometheus" {
		return registerPrometheusMetrics(ctx)
	}
	return nil
}

func registerPrometheusMetrics(ctx context.Context) error {
	latestBlock = prometheus.NewGauge(prometheus.GaugeOpts{
		Namespace: metricsNamespace,
		Subsystem: "blocks",
		Name:      "latest_height",
		Help:      "Latest block height processed",
	})
	if err := prometheus.Register(latestBlock); err != nil {
		return errors.Wrap(err, "failed to register latest block height")
	}

	blocksProcessed = prometheus.NewGauge(prometheus.GaugeOpts{
		Namespace: metricsNamespace,
		Subsystem: "blocks",
		Name:      "processed_total",
		Help:      "Total number of blocks processed",
	})
	if err := prometheus.Register(blocksProcessed); err != nil {
		return errors.Wrap(err, "failed to register total blocks processed")
	}

	return nil
}

func monitorBlocksProcessed(blocks int, height uint32) {
	if blocksProcessed != nil {
		blocksProcessed.Add(float64(blocks))
	}
	if latestBlock != nil {
		latestBlock.Set(float64(height))
	}
}

func main() {
	ctx := context.Background()
	monitor := &MockMetricsService{}

	// Register metrics with Prometheus.
	if err := registerMetrics(ctx, monitor); err != nil {
		log.Fatalf("Failed to register metrics: %v", err)
	}

	// Expose the registered metrics at "/metrics" endpoint.
	http.Handle("/metrics", promhttp.Handler())
	log.Fatal(http.ListenAndServe(":2112", nil))
}

// Test cases (to be run in a proper testing environment with a testing framework):
