	monitor := &MockMetricsService{}

	err := registerMetrics(ctx, monitor)
	if err != nil {
		fmt.Println("Test failed: Error registering metrics:", err)
	} else {
		fmt.Println("Test passed: Metrics registered successfully.")
	}
}

func testMonitorBlocksProcessed() {
	// Simulate processing of 5 blocks, reaching a height of 100.
	monitorBlocksProcessed(5, 100)

	if blocksProcessed == nil || latestBlock == nil {
		fmt.Println("Test failed: Metrics not initialized.")
		return
	}

	if blocksProcessedValue := prometheus.NewDesc("execd_blocks_processed_total", "Total number of blocks processed", nil, nil); blocksProcessedValue == nil {
