import (
	"fmt"
	"strings"
	"testing"
	"unicode"
)

// makeGood removes all instances of adjacent characters where one is the uppercase version of the other.
func makeGood(s string) string {
	stack := []rune{}

	for _, char := range s {
		if len(stack) > 0 && unicode.ToLower(char) == unicode.ToLower(stack[len(stack)-1]) && char != stack[len(stack)-1] {
			stack = stack[:len(stack)-1] // Pop the last character
		} else {
			stack = append(stack, char) // Push the current character
		}
	}

	return string(stack)
}

func Test_makeGood(t *testing.T) {
	tests := []struct {
		name string
		s    string
		want string
	}{
		{
			name: "Test with alternating cases",
			s:    "leEeetcode",
			want: "leetcode",
		},
		{
			name: "Test with all removable pairs",
			s:    "abBAcC",
			want: "",
		},
		{
			name: "Test with single character",
			s:    "s",
			want: "s",
		},
		{
			name: "Test with two characters",
			s:    "Pp",
			want: "",
		},
		{
			name: "Test with no removable pairs",
			s:    "HelloWorld",
			want: "HelloWorld",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			if got := makeGood(tt.s); got != tt.want {
				t.Errorf("makeGood(%q) = %q, want %q", tt.s, got, tt.want)
			}
		})
	}
}

func main() {
	// Example usage:
	fmt.Println(makeGood("leEeetcode")) // Output: "leetcode"
	fmt.Println(makeGood("abBAcC"))     // Output: ""
	fmt.Println(makeGood("s"))          // Output: "s"
	fmt.Println(makeGood("Pp"))         // Output: ""
	fmt.Println(makeGood("HelloWorld")) // Output: "HelloWorld"
}
