// Bundle represents a collection of resources with metadata.
type Bundle struct {
	ID          string    `json:"_id"`
	Owner       string    `json:"owner"`
	Created     time.Time `json:"created"`
	Modified    time.Time `json:"modified"`
	Imported    time.Time `json:"imported,omitempty"`
	Name        string    `json:"name,omitempty"`
	Description string    `json:"description,omitempty"`
}

// NewBundle creates a new Bundle with the given ID and owner.
func NewBundle(id, owner string) (*Bundle, error) {
	if id == "" {
		return nil, errors.New("id required")
	}
	if owner == "" {
		return nil, errors.New("owner required")
	}
	// Additional validation for ID and owner can be added here.
	now := time.Now()
	return &Bundle{
		ID:       id,
		Owner:    owner,
		Created:  now,
		Modified: now,
	}, nil
}

// MarshalJSON serializes the Bundle into JSON format.
func (b *Bundle) MarshalJSON() ([]byte, error) {
	if err := b.Validate(); err != nil {
		return nil, err
	}
	type Alias Bundle
	return json.Marshal(&struct {
		Created  string `json:"created"`
		Modified string `json:"modified"`
		Imported string `json:"imported,omitempty"`
		*Alias
	}{
		Created:  b.Created.Format(time.RFC3339),
		Modified: b.Modified.Format(time.RFC3339),
		Imported: b.Imported.Format(time.RFC3339),
		Alias:    (*Alias)(b),
	})
}

// UnmarshalJSON deserializes the given JSON data into a Bundle.
func (b *Bundle) UnmarshalJSON(data []byte) error {
	type Alias Bundle
	aux := &struct {
		Created  string `json:"created"`
		Modified string `json:"modified"`
		Imported string `json:"imported,omitempty"`
		*Alias
	}{
		Alias: (*Alias)(b),
	}
	if err := json.Unmarshal(data, &aux); err != nil {
		return fmt.Errorf("failed to unmarshal Bundle: %w", err)
	}
	var err error
	b.Created, err = time.Parse(time.RFC3339, aux.Created)
	if err != nil {
		return err
	}
	b.Modified, err = time.Parse(time.RFC3339, aux.Modified)
	if err != nil {
		return err
	}
	if aux.Imported != "" {
		b.Imported, err = time.Parse(time.RFC3339, aux.Imported)
		if err != nil {
			return err
		}
	}
	return nil
}

// MergeImport attempts to merge the Bundle with an existing one.
func (b *Bundle) MergeImport(existing *Bundle) (bool, error) {
	if b.ID != existing.ID {
		return false, errors.New("IDs don't match")
	}
	if b.Owner != existing.Owner {
		return false, errors.New("Cannot change bundle ownership")
	}
	if !b.Created.Equal(existing.Created) {
		return false, errors.New("Created timestamps don't match")
	}
	if b.Modified.After(existing.Modified) {
		*existing = *b
		return true, nil
	}
	return false, nil
}

// Validate checks if the Bundle is valid.
func (b *Bundle) Validate() error {
	if b.ID == "" {
		return errors.New("id required")
	}
	if b.Owner == "" {
		return errors.New("owner required")
	}
	if b.Created.IsZero() {
		return errors.New("created time required")
	}
	if b.Modified.IsZero() {
		return errors.New("modified time required")
	}
	// Additional validation rules can be added here.
	return nil
}

func main() {
	// Example usage:
	b, err := NewBundle("bundle-123456", "user-abcdef")
	if err != nil {
		fmt.Println("Error creating bundle:", err)
		return
	}
	fmt.Println("Bundle created:", b)

	jsonData, err := b.MarshalJSON()
	if err != nil {
		fmt.Println("Error marshaling bundle:", err)
		return
	}
	fmt.Println("JSON representation:", string(jsonData))

	newBundle := &Bundle{}
	err = newBundle.UnmarshalJSON(jsonData)
	if err != nil {
		fmt.Println("Error unmarshaling JSON:", err)
		return
	}
	fmt.Println("Unmarshaled bundle:", newBundle)

	merged, err := newBundle.MergeImport(b)
	if err != nil {
		fmt.Println("Error merging bundles:", err)
		return
	}
	fmt.Printf("Bundles merged: %t\n", merged)

	err = newBundle.Validate()
	if err != nil {
		fmt.Println("Bundle validation failed:", err)
		return
	}
	fmt.Println("Bundle is valid.")
}
