	"sync"

	"github.com/golang/protobuf/ptypes/empty"
	"github.com/networkservicemesh/api/pkg/api/networkservice"
	"google.golang.org/grpc"
)

// connectClient is a client chain element that translates a single incoming server connection
// to an outgoing client connection.
type connectClient struct {
	connection *networkservice.Connection
	cancel     context.CancelFunc
	mu         sync.Mutex
}

// NewClient creates a new connectClient with the provided context cancellation function.
func NewClient(cancel context.CancelFunc) networkservice.NetworkServiceClient {
	return &connectClient{
		cancel: cancel,
	}
}

// Request handles an incoming request by forwarding it as an outgoing client connection.
func (c *connectClient) Request(ctx context.Context, request *networkservice.NetworkServiceRequest, opts ...grpc.CallOption) (*networkservice.Connection, error) {
	c.mu.Lock()
	defer c.mu.Unlock()

	clientRequest := &networkservice.NetworkServiceRequest{Connection: request.GetConnection().Clone()}
	clientRequest.GetConnection().Mechanism = nil

	if c.connection != nil {
		clientRequest.Connection = c.connection
	}

	conn, err := next.Client(ctx).Request(ctx, clientRequest)
	c.connection = conn

	return conn, err
}

// Close handles the closing of the client connection.
func (c *connectClient) Close(ctx context.Context, conn *networkservice.Connection, opts ...grpc.CallOption) (*empty.Empty, error) {
	c.mu.Lock()
	defer c.mu.Unlock()

	if c.connection == nil {
		return &empty.Empty{}, nil
	}

	_, err := next.Client(ctx).Close(ctx, c.connection)
	c.cancel()

	return &empty.Empty{}, err
}

// Example usage of the connectClient.
func main() {
	// Context with cancellation function.
	ctx, cancel := context.WithCancel(context.Background())

	// Create a new connectClient.
	client := NewClient(cancel)

	// Example request.
	request := &networkservice.NetworkServiceRequest{
		Connection: &networkservice.Connection{Id: "example-connection-id"},
	}

	// Handle the request.
	connection, err := client.Request(ctx, request)
	if err != nil {
		panic(err)
	}

	// Output the connection ID.
	println("Connection ID:", connection.Id)

	// Close the client.
	_, err = client.Close(ctx, connection)
	if err != nil {
		panic(err)
	}
}
