func NewPNCounter() *PNCounter {
	return &PNCounter{}
}

// Increment increases the counter by the specified positive value.
func (c *PNCounter) Increment(v int64) {
	c.value += v
	c.delta += v
	c.hasDelta = true
}

// Decrement decreases the counter by the specified positive value.
func (c *PNCounter) Decrement(v int64) {
	c.value -= v
	c.delta -= v
	c.hasDelta = true
}

// Value returns the current value of the counter.
func (c *PNCounter) Value() int64 {
	return c.value
}

// Delta returns the delta of the counter since the last reset.
func (c *PNCounter) Delta() *entity.CrdtDelta {
	return &entity.CrdtDelta{
		Delta: &entity.CrdtDelta_Pncounter{
			Pncounter: &entity.PNCounterDelta{
				Change: c.delta,
			},
		},
	}
}

// applyDelta applies the given delta to the counter.
func (c *PNCounter) applyDelta(delta *entity.CrdtDelta) error {
	if pncDelta, ok := delta.GetDelta().(*entity.CrdtDelta_Pncounter); ok {
		c.value += pncDelta.Pncounter.Change
		return nil
	}
	return errors.New("illegal delta applied to PNCounter")
}

// resetDelta resets the delta to zero.
func (c *PNCounter) resetDelta() {
	c.delta = 0
	c.hasDelta = false
}

// HasDelta returns true if there are any unapplied changes (deltas) in the counter.
func (c *PNCounter) HasDelta() bool {
	return c.hasDelta
}

