	"net/http"
	"net/http/httptest"
	"testing"
)

// GreetHandler handles the /greet endpoint.
func GreetHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	var payload struct {
		Name string `json:"name"`
	}

	body, err := ioutil.ReadAll(r.Body)
	if err != nil {
		http.Error(w, "Error reading request body", http.StatusInternalServerError)
		return
	}

	err = json.Unmarshal(body, &payload)
	if err != nil || payload.Name == "" {
		http.Error(w, `{"message":"Name field is missing or empty"}`, http.StatusBadRequest)
		return
	}

	response := struct {
		Message string `json:"message"`
	}{
		Message: fmt.Sprintf("Hello, %s!", payload.Name),
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(response)
}

func TestGreetHandler(t *testing.T) {
	ts := httptest.NewServer(http.HandlerFunc(GreetHandler))
	defer ts.Close()

	// Test with a valid name
	resp := testRequest(t, ts, "POST", "/greet", `{"name":"John"}`, nil)
	if resp.StatusCode != http.StatusOK {
		t.Errorf("Expected status OK, got %v", resp.Status)
	}

	// Test with an empty name
	resp = testRequest(t, ts, "POST", "/greet", `{"name":""}`, nil)
	if resp.StatusCode != http.StatusBadRequest {
		t.Errorf("Expected status Bad Request, got %v", resp.Status)
	}
	checkErr(t, resp, "Name field is missing or empty")

	// Test with no name field
	resp = testRequest(t, ts, "POST", "/greet", `{}`, nil)
	if resp.StatusCode != http.StatusBadRequest {
		t.Errorf("Expected status Bad Request, got %v", resp.Status)
	}
	checkErr(t, resp, "Name field is missing or empty")
}

func main() {
	http.HandleFunc("/greet", GreetHandler)
	http.ListenAndServe(":8080", nil)
}
