package main

import (
	"bufio"
	"errors"
	"flag"
	"fmt"
	"io/ioutil"
	"os"
	"strings"
)

// StorySection represents a section of the story with its content and options.
type StorySection struct {
	Content string
	Options map[string]string
}

// Story represents the entire story with all sections.
type Story map[string]StorySection

// parseStory parses the story from the given text and returns a Story.
func parseStory(text string) (Story, error) {
	story := make(Story)
	sections := strings.Split(text, "\n\n")
	for _, section := range sections {
		lines := strings.Split(section, "\n")
		if len(lines) == 0 {
			continue
		}
		header := lines[0]
		if !strings.HasPrefix(header, "[") || !strings.HasSuffix(header, "]") {
			return nil, errors.New("invalid section header")
		}
		sectionName := header[1 : len(header)-1]
		content := strings.Join(lines[1:], "\n")
		options := make(map[string]string)
		for _, line := range lines[1:] {
			if strings.HasPrefix(line, "- ") {
				parts := strings.SplitN(line[2:], " (", 2)
				if len(parts) != 2 || !strings.HasSuffix(parts[1], ")") {
					return nil, errors.New("invalid option format")
				}
				optionText := parts[0]
				nextSection := parts[1][:len(parts[1])-1]
				options[optionText] = nextSection
			}
		}
		story[sectionName] = StorySection{Content: content, Options: options}
	}
	return story, nil
}

// playStory starts the game and plays through the story.
func playStory(story Story, startSection string) {
	currentSection := startSection
	reader := bufio.NewReader(os.Stdin)
	for {
		section, exists := story[currentSection]
		if !exists {
			fmt.Println("The story is incomplete. No further path found.")
			return
		}
		fmt.Println(section.Content)
		if len(section.Options) == 0 {
			fmt.Println("The End.")
			return
		}
		for option, nextSection := range section.Options {
			fmt.Printf("- %s (%s)\n", option, nextSection)
		}
		fmt.Print("What do you do? ")
		choice, _ := reader.ReadString('\n')
		choice = strings.TrimSpace(choice)
		if nextSection, ok := section.Options[choice]; ok {
			currentSection = nextSection
		} else {
			fmt.Println("Invalid choice. Please try again.")
		}
	}
}

func main() {
	helpFlag := flag.Bool("h", false, "show help message")
	flag.Parse()

	if *helpFlag || flag.NArg() != 1 {
		fmt.Println("Usage: adventure [options] <story file>")
		flag.PrintDefaults()
		return
	}

	storyFile := flag.Arg(0)
	content, err := ioutil.ReadFile(storyFile)
	if err != nil {
		fmt.Printf("Error reading story file: %v\n", err)
		os.Exit(1)
	}

	story, err := parseStory(string(content))
	if err != nil {
		fmt.Printf("Error parsing story: %v\n", err)
		os.Exit(1)
	}

	playStory(story, "Start")
}
