package palindrome_partitioning_ii

import (
	"math"
	"testing"

	"github.com/stretchr/testify/assert"
)

func minCut(s string) int {
	n := len(s)
	if n <= 1 {
		return 0
	}

	// dp[i] will be the min cut for s[:i+1]
	dp := make([]int, n)
	for i := range dp {
		dp[i] = i // max cuts
	}

	// isPalindrome[i][j] will be true if s[i:j+1] is a palindrome
	isPalindrome := make([][]bool, n)
	for i := range isPalindrome {
		isPalindrome[i] = make([]bool, n)
		for j := range isPalindrome[i] {
			isPalindrome[i][j] = true // single character is a palindrome
		}
	}

	for end := 1; end < n; end++ {
		for start := 0; start < end; start++ {
			if s[start] == s[end] && (end-start <= 2 || isPalindrome[start+1][end-1]) {
				isPalindrome[start][end] = true
				if start == 0 {
					dp[end] = 0
				} else {
					dp[end] = int(math.Min(float64(dp[end]), float64(dp[start-1]+1)))
				}
			}
		}
	}

	return dp[n-1]
}

func TestMinCut(t *testing.T) {
	assert.Equal(t, 1, minCut("aab"))
	assert.Equal(t, 0, minCut("a"))
	assert.Equal(t, 1, minCut("ab"))
	assert.Equal(t, 0, minCut("aba"))
	assert.Equal(t, 2, minCut("abcbm"))
	assert.Equal(t, 3, minCut("abcde"))
}
