}

func (p *Product) AddTax() float64 {
	return p.Price * 1.2
}

func (p *Product) ApplyDiscount(amount float64) float64 {
	if amount < 0 || amount > p.Price {
		return p.Price
	}
	return p.Price - amount
}

func FilterProductsByCategory(category string) []Product {
	var filteredProducts []Product
	for _, product := range Products {
		if product.Category == category {
			filteredProducts = append(filteredProducts, product)
		}
	}
	return filteredProducts
}

func MostExpensiveProduct(category string) (Product, bool) {
	filteredProducts := FilterProductsByCategory(category)
	if len(filteredProducts) == 0 {
		return Product{}, false
	}

	mostExpensive := filteredProducts[0]
	for _, product := range filteredProducts {
		if product.Price > mostExpensive.Price {
			mostExpensive = product
		}
	}
	return mostExpensive, true
}

func main() {
	// Test cases
