package main

import (
	"fmt"
	"errors"
)

// calculate takes two integers and returns their sum, difference, product, and quotient.
// If the second integer is zero, it returns an error for the division.
func calculate(a int, b int) (int, int, int, float64, error) {
	sum := a + b
	diff := a - b
	prod := a * b
	var div float64
	var divErr error

	if b != 0 {
		div = float64(a) / float64(b)
	} else {
		divErr = errors.New("division by zero is not allowed")
	}

	return sum, diff, prod, div, divErr
}

func main() {
	// Test cases
	testCases := []struct {
		a, b int
	}{
		{15, 10},
		{20, 0}, // Division by zero case
		{9, 3},
	}

	for _, tc := range testCases {
		sum, diff, prod, div, divErr := calculate(tc.a, tc.b)
		fmt.Printf("Calculating with inputs (%d, %d):\n", tc.a, tc.b)
		fmt.Printf("Sum: %d\n", sum)
		fmt.Printf("Difference: %d\n", diff)
		fmt.Printf("Product: %d\n", prod)
		if divErr != nil {
			fmt.Printf("Division error: %s\n", divErr)
		} else {
			fmt.Printf("Division: %.2f\n", div)
		}
		fmt.Println()
	}
}
