	return Gallons(l / LitersPerGallon)
}

func (m Milliliters) ToLiters() Liters {
	return Liters(m / MillilitersPerLiter)
}

func (m Milliliters) ToGallons() Gallons {
	return Gallons(m / (MillilitersPerLiter * LitersPerGallon))
}

