package main

import (
	"bytes"
	"crypto/hmac"
	"crypto/sha256"
	"encoding/base64"
	"fmt"
	"io/ioutil"
	"net/http"
	"path"
	"time"
)

// CreateSignature generates a HMAC SHA-256 signature for an HTTP request.
// It uses the request method, path, current timestamp, and SHA-256 hash of the request body to create the signature.
func CreateSignature(pk string, secret string, req *http.Request) (string, error) {
	timestamp := time.Now().UTC().Format(http.TimeFormat)
	method := req.Method
	requestPath := "/" + path.Base(req.URL.Path)
	if req.URL.RawQuery != "" {
		requestPath = requestPath + "?" + req.URL.RawQuery
	}
	body, err := ioutil.ReadAll(req.Body)
	if err != nil {
		return "", err
	}
	req.Body = ioutil.NopCloser(bytes.NewBuffer(body))
	hasher := sha256.New()
	hasher.Write(body)
	contentHash := base64.StdEncoding.EncodeToString(hasher.Sum(nil))

	stringToSign := fmt.Sprintf("%s\n%s\n%s\n%s", method, requestPath, timestamp, contentHash)

	hasherSign := hmac.New(sha256.New, []byte(secret))
	hasherSign.Write([]byte(stringToSign))

	signature := base64.StdEncoding.EncodeToString(hasherSign.Sum(nil))

	return signature, nil
}

func main() {
	data := []byte("requestBody")
	request, _ := http.NewRequest("POST", "http://example.com/api/data", bytes.NewBuffer(data))
	signature, err := CreateSignature("appKey", "secret", request)
	if err != nil {
		fmt.Println("Error creating signature:", err)
		return
	}
	fmt.Println("Signature:", signature)
}

// Test cases to verify the solution correctness
