	if err != nil {
		fmt.Println("Error creating signature:", err)
	} else {
		fmt.Println("Signature for Test case 1:", signature)
	}

	// Test case 2: GET request with query parameters
	request, _ = http.NewRequest("GET", "http://example.com/api/data?param=value", nil)
	signature, err = CreateSignature("appKey", "secret", request)
	if err != nil {
		fmt.Println("Error creating signature:", err)
	} else {
		fmt.Println("Signature for Test case 2:", signature)
	}

	// Test case 3: PUT request with JSON body
	jsonData := []byte(`{"key":"value"}`)
	request, _ = http.NewRequest("PUT", "http://example.com/api/update", bytes.NewBuffer(jsonData))
	signature, err = CreateSignature("appKey", "secret", request)
