// TemplateParam is a placeholder for the parameters to be injected into the template.
type TemplateParam map[string]interface{}

// loadTemplate parses a YAML template and injects the provided parameters.
func loadTemplate(name, templateData string, p TemplateParam) ([]byte, error) {
	var writer bytes.Buffer
	t := template.New(name)
	t, err := t.Parse(templateData)
	if err != nil {
		return nil, errors.Wrapf(err, "failed to parse template %v", name)
	}
	err = t.Execute(&writer, p)
	return writer.Bytes(), err
}

// TemplateToService creates a Service object from a YAML template and parameters.
func TemplateToService(name, templateData string, p TemplateParam) (*corev1.Service, error) {
	var svc corev1.Service
	t, err := loadTemplate(name, templateData, p)
	if err != nil {
		return nil, errors.Wrap(err, "failed to load service template")
	}

	err = yaml.Unmarshal(t, &svc)
	if err != nil {
		return nil, errors.Wrap(err, "failed to unmarshal service template")
	}
	return &svc, nil
}

// TemplateToCSIDriver creates a CSIDriver object from a YAML template and parameters.
func TemplateToCSIDriver(name, templateData string, p TemplateParam) (*storagev1.CSIDriver, error) {
