	t, err := loadTemplate(name, templateData, p)
	if err != nil {
		return nil, errors.Wrap(err, "failed to load csi driver template")
	}

	err = yaml.Unmarshal(t, &csidriver)
	if err != nil {
		return nil, errors.Wrap(err, "failed to unmarshal csi driver template")
