package main

import (
	"fmt"
)

// fibonacci generates a slice containing the Fibonacci sequence up to the nth number.
// The sequence starts with 1 and 1, and each subsequent number is the sum of the two preceding ones.
func fibonacci(n int) []int {
	if n <= 0 {
		return []int{}
	}

	fibSequence := []int{1}
	if n == 1 {
		return fibSequence
	}

	currentValue := 1
	previousValue := 1
	fibSequence = append(fibSequence, currentValue)

	for i := 2; i < n; i++ {
		currentValue, previousValue = currentValue+previousValue, currentValue
		fibSequence = append(fibSequence, currentValue)
	}

	return fibSequence
}

func main() {
	// Test cases to verify the correctness of the solution
	testCases := []int{0, 1, 2, 5, 10}
	for _, n := range testCases {
		fmt.Printf("fibonacci(%d) = %v\n", n, fibonacci(n))
	}
}
