// Define the account types as constants.
const SAVING = "saving"
const CHECKING = "checking"

// AccountRequest represents a request to open a new bank account.
type AccountRequest struct {
	CustomerId  string  `json:"customer_id"`
	AccountType string  `json:"account_type"`
	Amount      float64 `json:"amount"`
}

// IsAccountTypeSaving checks if the account type is "saving".
func (a AccountRequest) IsAccountTypeSaving() bool {
	return strings.ToLower(a.AccountType) == SAVING
}

// IsAccountTypeChecking checks if the account type is "checking".
func (a AccountRequest) IsAccountTypeChecking() bool {
	return strings.ToLower(a.AccountType) == CHECKING
}

// AppError represents an application error with a message.
type AppError struct {
	Message string
}

// NewValidationError creates a new validation error with the given message.
func NewValidationError(message string) *AppError {
	return &AppError{Message: message}
}

// Validate checks if the account request is valid.
func (a AccountRequest) Validate() *AppError {
	if a.Amount < 5000 {
		return NewValidationError("To open a new account, you need to deposit at least $5000.00")
	}
	if !a.IsAccountTypeSaving() && !a.IsAccountTypeChecking() {
		return NewValidationError("Account Type should be saving or checking")
	}
	return nil
}

// Test the AccountRequest validation logic.
