	}

	// Test case: invalid account request (amount less than $5000.00)
	invalidRequestAmount := AccountRequest{
		CustomerId:  "12345",
		AccountType: "checking",
		Amount:      3000.00,
	}
	if err := invalidRequestAmount.Validate(); err != nil {
		fmt.Printf("Error: %s\n", err.Message)
	} else {
