package main

import (
	"fmt"
)

type (
	EntryIdentifier = string
	Permission      = string
)

const (
	Policy EntryIdentifier = "p"
	Group  EntryIdentifier = "g"
)

const (
	Allow Permission = "allow"
	Deny  Permission = "deny"
)

type RbacPolicy struct {
	Identifier EntryIdentifier
	Subject    string
	Resource   string
	Action     string
	Object     string
	Permission Permission
}

type RbacGroup struct {
	Identifier EntryIdentifier
	Group      string
	Role       string
}

type RbacMap struct {
	Policies map[string][]*RbacPolicy
	Groups   map[string][]*RbacGroup
}

func NewRbacMap() *RbacMap {
	return &RbacMap{
		Policies: make(map[string][]*RbacPolicy),
		Groups:   make(map[string][]*RbacGroup),
	}
}

func (r *RbacMap) AddPolicy(policy *RbacPolicy) {
	r.Policies[policy.Subject] = append(r.Policies[policy.Subject], policy)
}

func (r *RbacMap) AddGroup(group *RbacGroup) {
	r.Groups[group.Group] = append(r.Groups[group.Group], group)
}

func (r *RbacMap) CheckPermission(subject, resource, action string) bool {
	// Check direct policies for the subject
	for _, policy := range r.Policies[subject] {
		if policy.Resource == resource && policy.Action == action {
			return policy.Permission == Allow
		}
	}

	// Check group policies for the subject
	for _, groups := range r.Groups {
		for _, group := range groups {
			if group.Group == subject {
				for _, policy := range r.Policies[group.Role] {
					if policy.Resource == resource && policy.Action == action {
						return policy.Permission == Allow
					}
				}
			}
		}
	}

	return false
}

func main() {
	rbac := NewRbacMap()

	// Test cases
	rbac.AddPolicy(&RbacPolicy{Identifier: Policy, Subject: "user1", Resource: "file1", Action: "read", Permission: Allow})
	rbac.AddPolicy(&RbacPolicy{Identifier: Policy, Subject: "role_admin", Resource: "file2", Action: "write", Permission: Allow})
	rbac.AddGroup(&RbacGroup{Identifier: Group, Group: "user1", Role: "role_admin"})

	fmt.Println("User 'user1' can read 'file1':", rbac.CheckPermission("user1", "file1", "read")) // Expected: true
	fmt.Println("User 'user1' can write 'file2':", rbac.CheckPermission("user1", "file2", "write")) // Expected: true
	fmt.Println("User 'user1' can delete 'file1':", rbac.CheckPermission("user1", "file1", "delete")) // Expected: false
}
