// queryHook is a custom database hook that logs the query and its execution time.
type queryHook struct {
	beforeQuery func(context.Context, *bun.QueryEvent) context.Context
	afterQuery  func(context.Context, *bun.QueryEvent)
}

// BeforeQuery is called before a query is executed.
func (h *queryHook) BeforeQuery(ctx context.Context, evt *bun.QueryEvent) context.Context {
	if h.beforeQuery != nil {
		return h.beforeQuery(ctx, evt)
	}
	return ctx
}

// AfterQuery is called after a query has been executed.
func (h *queryHook) AfterQuery(ctx context.Context, evt *bun.QueryEvent) {
	if h.afterQuery != nil {
		h.afterQuery(ctx, evt)
	}
}

// logQueryHook creates a new queryHook that logs the query and its execution time.
func logQueryHook() *queryHook {
	return &queryHook{
		beforeQuery: func(ctx context.Context, event *bun.QueryEvent) context.Context {
			fmt.Printf("Executing query: %s\n", event.Query)
			return context.WithValue(ctx, "startTime", time.Now())
		},
		afterQuery: func(ctx context.Context, event *bun.QueryEvent) {
			startTime := ctx.Value("startTime").(time.Time)
			duration := time.Since(startTime)
			fmt.Printf("Query executed in: %v\n", duration)
		},
	}
