package main

import (
	"context"
	"fmt"
	"time"

	"github.com/go-ldap/ldap/v3"
)

// Define the groupRow struct to hold LDAP group information.
type groupRow struct {
	Dn             string
	Cn             string
	Description    string
	WhenCreated    *time.Time
	WhenChanged    *time.Time
	ObjectClass    []string
	Ou             string
	ObjectSid      string
	SamAccountName string
	Title          string
	MemberOf       []string
	Attributes     map[string][]string
}

// getGroup retrieves a single LDAP group by its distinguished name.
func getGroup(ctx context.Context, groupDN string, ldapConn *ldap.Conn) (*groupRow, error) {
	searchReq := ldap.NewSearchRequest(
		groupDN,
		ldap.ScopeBaseObject,
		ldap.NeverDerefAliases,
		0,
		0,
		false,
		"(objectClass=group)",
		[]string{"*"}, // Request all attributes
		nil,
	)

	result, err := ldapConn.Search(searchReq)
	if err != nil {
		return nil, err
	}

	if len(result.Entries) == 0 {
		return nil, fmt.Errorf("group not found")
	}

	entry := result.Entries[0]
	group := &groupRow{
		Dn:             entry.DN,
		Cn:             entry.GetAttributeValue("cn"),
		Description:    entry.GetAttributeValue("description"),
		ObjectClass:    entry.GetAttributeValues("objectClass"),
		Ou:             entry.GetAttributeValue("ou"),
		ObjectSid:      entry.GetAttributeValue("objectSid"),
		SamAccountName: entry.GetAttributeValue("sAMAccountName"),
		Title:          entry.GetAttributeValue("title"),
		MemberOf:       entry.GetAttributeValues("memberOf"),
		Attributes:     make(map[string][]string),
	}

	// Convert LDAP time strings to time.Time objects
	group.WhenCreated = convertLDAPTime(entry.GetAttributeValue("whenCreated"))
	group.WhenChanged = convertLDAPTime(entry.GetAttributeValue("whenChanged"))

	// Transform attributes into a map
	for _, attr := range entry.Attributes {
		group.Attributes[attr.Name] = attr.Values
	}

	return group, nil
}

// listGroups lists LDAP groups based on provided filters and pagination settings.
func listGroups(ctx context.Context, baseDN string, filter string, attributes []string, pageSize uint32, ldapConn *ldap.Conn) ([]groupRow, error) {
	var groups []groupRow
	searchReq := ldap.NewSearchRequest(
		baseDN,
		ldap.ScopeWholeSubtree,
		ldap.NeverDerefAliases,
		0,
		0,
		false,
		filter,
		attributes,
		nil,
	)

	// Implement pagination using the paging control
	pagingControl := ldap.NewControlPaging(pageSize)
	searchReq.Controls = append(searchReq.Controls, pagingControl)

	for {
		result, err := ldapConn.Search(searchReq)
		if err != nil {
			return nil, err
		}

		for _, entry := range result.Entries {
			group := groupRow{
				Dn:             entry.DN,
				Cn:             entry.GetAttributeValue("cn"),
				Description:    entry.GetAttributeValue("description"),
				ObjectClass:    entry.GetAttributeValues("objectClass"),
				Ou:             entry.GetAttributeValue("ou"),
				ObjectSid:      entry.GetAttributeValue("objectSid"),
				SamAccountName: entry.GetAttributeValue("sAMAccountName"),
				Title:          entry.GetAttributeValue("title"),
				MemberOf:       entry.GetAttributeValues("memberOf"),
				Attributes:     make(map[string][]string),
			}

			// Convert LDAP time strings to time.Time objects
			group.WhenCreated = convertLDAPTime(entry.GetAttributeValue("whenCreated"))
			group.WhenChanged = convertLDAPTime(entry.GetAttributeValue("whenChanged"))

			// Transform attributes into a map
			for _, attr := range entry.Attributes {
				group.Attributes[attr.Name] = attr.Values
			}

			groups = append(groups, group)
		}

		// Handle pagination
		pagingResult := ldap.FindControl(result.Controls, ldap.ControlTypePaging)
		if pagingResult == nil {
			break
		}

		pagingControl := pagingResult.(*ldap.ControlPaging)
		if len(pagingControl.Cookie) == 0 {
			break
		}

		// Set the next page cookie
		pagingControl.SetCookie(pagingControl.Cookie)
	}

	return groups, nil
}

// convertLDAPTime converts an LDAP time string to a time.Time object.
func convertLDAPTime(ldapTime string) *time.Time {
	if ldapTime == "" {
		return nil
	}
	t, err := time.Parse("20060102150405.0Z", ldapTime)
	if err != nil {
		return nil
	}
	return &t
}

// Example usage of getGroup and listGroups functions.
func main() {
	// Establish an LDAP connection (example: ldap://localhost:389)
	ldapConn, err := ldap.DialURL("ldap://localhost:389")
	if err != nil {
		panic(err)
	}
	defer ldapConn.Close()

	// Example usage of getGroup
	group, err := getGroup(context.Background(), "cn=example,dc=domain,dc=com", ldapConn)
	if err != nil {
		fmt.Println("Error getting group:", err)
	} else {
		fmt.Printf("Group: %+v\n", group)
	}

	// Example usage of listGroups
	groups, err := listGroups(context.Background(), "dc=domain,dc=com", "(objectClass=group)", []string{"*"}, 100, ldapConn)
	if err != nil {
		fmt.Println("Error listing groups:", err)
	} else {
		for _, g := range groups {
			fmt.Printf("Group: %+v\n", g)
		}
	}
}
