package main

import (
	"fmt"
	"math"
)

// Polygon represents a geometric polygon with vertices.
type Polygon struct {
	vertices [][]float64
}

// PolygonSetter defines the interface for setting vertices and calculating the perimeter.
type PolygonSetter interface {
	SetVertices(vertices [][]float64)
	Perimeter() float64
}

// SetVertices sets the vertices of the polygon.
func (p *Polygon) SetVertices(vertices [][]float64) {
	p.vertices = vertices
}

// Perimeter calculates the perimeter of the polygon.
func (p *Polygon) Perimeter() float64 {
	perimeter := 0.0
	for i := 0; i < len(p.vertices); i++ {
		j := (i + 1) % len(p.vertices)
		perimeter += distance(p.vertices[i], p.vertices[j])
	}
	return perimeter
}

// distance calculates the distance between two points.
func distance(p1, p2 []float64) float64 {
	return math.Sqrt(math.Pow(p2[0]-p1[0], 2) + math.Pow(p2[1]-p1[1], 2))
}

func main() {
	// Test cases
	testcases := []struct {
		vertices [][]float64
		expected float64
	}{
		{
			vertices: [][]float64{
				{0, 0},
				{4, 0},
				{4, 3},
				{0, 3},
			},
			expected: 14.0, // Perimeter of the rectangle
		},
		{
			vertices: [][]float64{
				{0, 0},
				{3, 0},
				{3, 4},
				{0, 4},
				{0, 0},
			},
			expected: 14.0, // Perimeter of the rectangle with repeated first/last point
		},
	}

	for i, tc := range testcases {
		polygon := &Polygon{}
		polygon.SetVertices(tc.vertices)
		perimeter := polygon.Perimeter()
		if math.Abs(perimeter-tc.expected) > 1e-9 {
			fmt.Printf("Test case %d failed: expected %.2f, got %.2f\n", i, tc.expected, perimeter)
		} else {
			fmt.Printf("Test case %d passed: expected %.2f, got %.2f\n", i, tc.expected, perimeter)
		}
	}
}
