package main

import (
	"errors"
	"fmt"
	"regexp"
	"strconv"
	"strings"
)

// ValidateNATSMessage checks if the provided message is a valid NATS protocol message.
func ValidateNATSMessage(message string) (bool, error) {
	// Check if the message ends with the proper line terminator.
	if !strings.HasSuffix(message, "\r\n") {
		return false, errors.New("message does not end with CRLF")
	}

	// Remove the line terminator for further processing.
	message = strings.TrimSuffix(message, "\r\n")

	// Split the message into parts.
	parts := strings.Fields(message)

	// Check if the message is empty or has no command.
	if len(parts) == 0 {
		return false, errors.New("message is empty or has no command")
	}

	// Validate based on the command.
	switch parts[0] {
	case "CONNECT":
		// CONNECT command should have a JSON payload as the only argument.
		if len(parts) != 2 {
			return false, errors.New("CONNECT command should have a single JSON argument")
		}
	case "PUB":
		// PUB command should have at least three parts: PUB subject size [reply-to].
		if len(parts) < 3 || len(parts) > 4 {
			return false, errors.New("PUB command has incorrect number of arguments")
		}
		// Check if the size is a valid number.
		size, err := strconv.Atoi(parts[len(parts)-2])
		if err != nil {
			return false, errors.New("PUB command has invalid size argument")
		}
		// Check if the payload size matches the declared size.
		payload := parts[len(parts)-1]
		if len(payload) != size {
			return false, errors.New("PUB command payload size does not match the declared size")
		}
	case "SUB":
		// SUB command should have two or three parts: SUB subject sid [queue-group].
		if len(parts) < 2 || len(parts) > 3 {
			return false, errors.New("SUB command has incorrect number of arguments")
		}
	case "UNSUB":
		// UNSUB command should have two or three parts: UNSUB sid [max_msgs].
		if len(parts) < 2 || len(parts) > 3 {
			return false, errors.New("UNSUB command has incorrect number of arguments")
		}
	case "PING", "PONG":
		// PING and PONG commands should not have any arguments.
		if len(parts) != 1 {
			return false, errors.New("PING/PONG command should not have any arguments")
		}
	default:
		return false, fmt.Errorf("unknown or unsupported command: %s", parts[0])
	}

	return true, nil
}

func main() {
	// Test cases to verify the solution correctness.
	testMessages := []string{
		"CONNECT {\"verbose\":true}\r\n",
		"PUB foo 5\r\nhello\r\n",
		"SUB foo 1\r\n",
		"UNSUB 1\r\n",
		"PING\r\n",
		"PONG\r\n",
		"PUB foo bar\r\n", // Invalid PUB command
		"SUB\r\n",         // Invalid SUB command
		"PING foo\r\n",    // Invalid PING command
	}

	for _, msg := range testMessages {
		valid, err := ValidateNATSMessage(msg)
		if valid {
			fmt.Printf("Valid: %s\n", msg)
		} else {
			fmt.Printf("Invalid: %s, Error: %v\n", msg, err)
		}
	}
}
