package main

import (
	"encoding/json"
	"fmt"
	"net/http"
	"strconv"
	"sync"
	"time"
)

type FibResult struct {
	Input    uint64 `json:"input"`
	Result   uint64 `json:"result"`
	Duration string `json:"duration"`
}

type FibResponse struct {
	Done bool       `json:"done"`
	Fib  *FibResult `json:"fib,omitempty"`
}

type AllResponse struct {
	Queries []FibResult `json:"queries"`
}

var cache = make(map[uint64]uint64)
var cacheMutex sync.RWMutex

func fib(n uint64) uint64 {
	if n <= 1 {
		return n
	}
	cacheMutex.RLock()
	if result, found := cache[n]; found {
		cacheMutex.RUnlock()
		return result
	}
	cacheMutex.RUnlock()

	cacheMutex.Lock()
	defer cacheMutex.Unlock()
	if result, found := cache[n]; found {
		return result
	}
	cache[n] = fib(n-1) + fib(n-2)
	return cache[n]
}

func calculateFibonacci(w http.ResponseWriter, r *http.Request) {
	start := time.Now()
	query := r.URL.Query().Get("number")
	if query == "" {
		http.Error(w, "Missing 'number' query parameter", http.StatusBadRequest)
		return
	}

	number, err := strconv.ParseUint(query, 10, 64)
	if err != nil {
		http.Error(w, "Invalid 'number' query parameter", http.StatusBadRequest)
		return
	}

	result := fib(number)
	duration := time.Since(start)

	fibResult := FibResult{
		Input:    number,
		Result:   result,
		Duration: fmt.Sprintf("%vms", duration.Milliseconds()),
	}

	response := FibResponse{
		Done: true,
		Fib:  &fibResult,
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(response)
}

func getAllCachedFibonacci(w http.ResponseWriter, r *http.Request) {
	cacheMutex.RLock()
	defer cacheMutex.RUnlock()

	var queries []FibResult
	for input, result := range cache {
		queries = append(queries, FibResult{Input: input, Result: result})
	}

	response := AllResponse{
		Queries: queries,
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(response)
}

func main() {
	http.HandleFunc("/fibonacci", calculateFibonacci)
	http.HandleFunc("/fibonacci/all", getAllCachedFibonacci)
	http.ListenAndServe(":8080", nil)
}

// Test cases to verify the solution correctness
// You can use curl or any HTTP client to test the endpoints:
// 1. Calculate Fibonacci for 10: curl "http://localhost:8080/fibonacci?number=10"
// 2. Get all cached Fibonacci calculations: curl "http://localhost:8080/fibonacci/all"
```

