package eco

import (
	"fmt"

	"github.com/QOSGroup/qbase/baseabci"
	"github.com/QOSGroup/qbase/context"
	btypes "github.com/QOSGroup/qbase/types"
	"github.com/QOSGroup/qos/module/eco/mapper"
	qtypes "github.com/QOSGroup/qos/types"
)

// BonusToDelegator distributes bonus to a delegator from a validator's economic fee pool.
func BonusToDelegator(ctx context.Context, delegatorAddr, validatorAddr btypes.Address, bonusAmount btypes.BigInt, onlyMinusFeePool bool) error {
	distriMapper := mapper.GetDistributionMapper(ctx)
	log := ctx.Logger()

	if !onlyMinusFeePool {
		err := IncrAccountQOS(ctx, delegatorAddr, bonusAmount)
		if err != nil {
			return err
		}
	}

	distriMapper.MinusValidatorEcoFeePool(validatorAddr, bonusAmount)
	log.Debug("bonus To Delegator", "validatorAddr", validatorAddr.String(), "delegatorAddr", delegatorAddr.String(), "amount", bonusAmount)

	return nil
}

// IncrAccountQOS increases the QOS balance of an account.
func IncrAccountQOS(ctx context.Context, addr btypes.Address, amount btypes.BigInt) error {
	accountMapper := baseabci.GetAccountMapper(ctx)

	acc := accountMapper.GetAccount(addr)
	if qosAcc, ok := acc.(*qtypes.QOSAccount); ok {
		err := qosAcc.SetQOS(qosAcc.GetQOS().NilToZero().Add(amount))
		if err != nil {
			return err
		}
		accountMapper.SetAccount(acc)
		return nil
	}

	return fmt.Errorf("addr: %s not a QOSAccount", addr)
}

// DecrAccountQOS decreases the QOS balance of an account.
func DecrAccountQOS(ctx context.Context, addr btypes.Address, amount btypes.BigInt) error {
	accountMapper := baseabci.GetAccountMapper(ctx)

	acc := accountMapper.GetAccount(addr)
	if qosAcc, ok := acc.(*qtypes.QOSAccount); ok {
		current := qosAcc.GetQOS().NilToZero()
		if current.LT(amount) {
			return fmt.Errorf("addr: %s has not enough QOS to decrease. Expected: %d, Actual: %d", addr, amount, current)
		}

		err := qosAcc.SetQOS(current.Sub(amount))
		if err != nil {
			return err
		}
		accountMapper.SetAccount(acc)
		return nil
	}

	return fmt.Errorf("addr: %s not a QOSAccount", addr)
}

// Test cases to verify the solution correctness.
func main() {
	// Mock context and addresses for testing purposes.
	ctx := context.NewContext()
	delegatorAddr := btypes.Address("delegator1")
	validatorAddr := btypes.Address("validator1")
	bonusAmount := btypes.BigInt(1000)

	// Test BonusToDelegator function.
	err := BonusToDelegator(ctx, delegatorAddr, validatorAddr, bonusAmount, false)
	if err != nil {
		fmt.Printf("Error distributing bonus: %s\n", err)
	} else {
		fmt.Println("Bonus distributed successfully.")
	}

	// Test IncrAccountQOS function.
	err = IncrAccountQOS(ctx, delegatorAddr, bonusAmount)
	if err != nil {
		fmt.Printf("Error increasing QOS balance: %s\n", err)
	} else {
		fmt.Println("QOS balance increased successfully.")
