package main

import (
	"fmt"
	"os"

	"github.com/go-pg/pg"
	"github.com/go-pg/pg/orm"
)

type Post struct {
	Id       int // Primary key
	Content  string
	AuthorID int // Foreign key referencing User.Id
	Author   *User `pg:"rel:has-one"` // Author
}

type User struct {
	Id   int // Primary key
	Name string
}

var Db *pg.DB

func ConnectDB() error {
	Db = pg.Connect(&pg.Options{
		User:     "postgres",
		Password: "123",
		Database: "demo",
		Addr:     "localhost:5432",
	})

	var n int
	_, err := Db.QueryOne(pg.Scan(&n), "SELECT 1")
	return err
}

func InitSchema() {
	var post Post
	var user User

	for _, model := range []interface{}{&user, &post} {
		Db.DropTable(model, &orm.DropTableOptions{
			IfExists: true,
			Cascade:  true,
		})

		err := Db.CreateTable(model, &orm.CreateTableOptions{
			Temp:          false,
			FKConstraints: true,
			IfNotExists:   true,
		})

		if err != nil {
			panic(err)
		}
	}
}

func SaveData() {
	user1 := User{
		Name: "Alice",
	}

	user2 := User{
		Name: "Bob",
	}

	user3 := User{
		Name: "Charlie",
	}

	err := Db.Insert(&user1, &user2, &user3)
	if err != nil {
		fmt.Println("Error inserting users:", err)
		return
	}

	post1 := Post{
		Content:  "Hello World",
		AuthorID: user1.Id,
	}

	post2 := Post{
		Content:  "Goodbye World",
		AuthorID: user2.Id,
	}

	post3 := Post{
		Content:  "Hello again",
		AuthorID: user3.Id,
	}

	err = Db.Insert(&post1, &post2, &post3)
	if err != nil {
		fmt.Println("Error inserting posts:", err)
		return
	}
}

func GetAllPostsWithAuthors() ([]Post, error) {
	var posts []Post
	err := Db.Model(&posts).Column("post.*", "Author").Select()
	if err != nil {
		return nil, err
	}
	return posts, nil
}

func main() {
	if err := ConnectDB(); err != nil {
		fmt.Println("Error connecting to the database:", err)
		os.Exit(1)
	}
	defer Db.Close()

	InitSchema()
	SaveData()

	posts, err := GetAllPostsWithAuthors()
	if err != nil {
		fmt.Println("Error retrieving posts:", err)
		os.Exit(1)
	}

	for _, post := range posts {
		fmt.Printf("Post: %s, Author: %s\n", post.Content, post.Author.Name)
	}
}
