package main

import "fmt"

type nodeTree struct {
	Data  int
	Left  *nodeTree
	Right *nodeTree
}

func newNode(data int) *nodeTree {
	return &nodeTree{
		Data:  data,
		Left:  nil,
		Right: nil,
	}
}

// preOrderTraversal prints the elements of the binary tree in pre-order without using recursion.
func preOrderTraversal(root *nodeTree) {
	if root == nil {
		return
	}

	stack := []*nodeTree{root}

	for len(stack) > 0 {
		current := stack[len(stack)-1]
		stack = stack[:len(stack)-1]

		fmt.Printf("%d ", current.Data)

		if current.Right != nil {
			stack = append(stack, current.Right)
		}
		if current.Left != nil {
			stack = append(stack, current.Left)
		}
	}
}

func main() {
	root := newNode(1)
	root.Left = newNode(2)
	root.Right = newNode(3)
	root.Left.Left = newNode(4)
	root.Left.Right = newNode(5)
	root.Right.Left = newNode(6)
	root.Right.Right = newNode(7)

	fmt.Println("Pre-order traversal without recursion:")
	preOrderTraversal(root)
}

