package main

import (
	"bytes"
	"compress/flate"
	"fmt"
	"io"
	"io/ioutil"
	"math/rand"
	"os"
	"time"
)

// Replace 'path/to/your/textfile.txt' with the actual path to the text file you want to compress and decompress.
const testDat = "path/to/your/textfile.txt"

type testState struct {
	remaining []byte
	state     []byte
}

func main() {
	// Seed the random number generator
	rand.Seed(time.Now().UnixNano())

	// Read and compress the data into a bytes.Buffer.
	f, err := os.Open(testDat)
	if err != nil {
		fmt.Println("Error opening file:", err)
		return
	}
	defer f.Close()

	var b bytes.Buffer
	w, err := flate.NewWriter(&b, flate.DefaultCompression)
	if err != nil {
		fmt.Println("Error creating flate writer:", err)
		return
	}
	if _, err := io.Copy(w, f); err != nil {
		fmt.Println("Error copying data to flate writer:", err)
		return
	}
	if err := w.Close(); err != nil {
		fmt.Println("Error closing flate writer:", err)
		return
	}

	// Decompress the data, saving decompressor state at random points.
	r := flate.NewReader(&b)
	defer r.Close()
	nRead := 0
	nextState := rand.Intn(128 * 1024)
	var states []testState
	for {
		sz := rand.Intn(4096)
		buf := make([]byte, sz)
		n, err := r.Read(buf)
		if err == io.EOF {
			break
		} else if err != nil {
			fmt.Println("Error reading from flate reader:", err)
			return
		}

		nRead += n
		if nRead >= nextState {
			remaining := make([]byte, b.Len())
			copy(remaining, b.Bytes())
			state, err := r.(flate.DecompressorState).State()
			if err != nil {
				fmt.Println("Error getting decompressor state:", err)
				return
			}
			states = append(states, testState{
				remaining: remaining,
				state:     state,
			})
			nextState += rand.Intn(128 * 1024)
		}
	}
	fmt.Printf("Saved %d decompressor states\n", len(states))

	// Verify that we can resume decompression from each of the saved states.
	for _, s := range states {
		fmt.Printf("Resuming decompression with %d bytes remaining\n", len(s.remaining))
		compressedR := bytes.NewReader(s.remaining)
		r := flate.NewReaderDict(compressedR, s.state)
		if _, err := io.Copy(ioutil.Discard, r); err != nil {
			fmt.Println("Error resuming decompression:", err)
			return
		}
		r.Close()
	}

	fmt.Println("Decompression verified successfully from all saved states.")
}
