package main

import (
	"errors"
	"sync"
	"time"

	"github.com/codahale/hdrhistogram"
)

const histWrapNum = 5 // Number of histograms to maintain in the window

// LatencyTracker tracks the latency of requests over a sliding window of time.
type LatencyTracker struct {
	histogram *slidingHistogram
	mu        sync.Mutex
}

// NewLatencyTracker creates a new LatencyTracker with the given parameters.
func NewLatencyTracker(duration time.Duration, maxVal int64, sigFigs int) *LatencyTracker {
	return &LatencyTracker{
		histogram: newSlidingHistogram(duration, maxVal, sigFigs),
	}
}

// RecordLatency records a single request latency.
func (lt *LatencyTracker) RecordLatency(latency int64) error {
	lt.mu.Lock()
	defer lt.mu.Unlock()

	return lt.histogram.RecordValue(latency)
}

// GetMergedHistogram returns a merged histogram of the latencies over the current sliding window.
func (lt *LatencyTracker) GetMergedHistogram() *hdrhistogram.Histogram {
	lt.mu.Lock()
	defer lt.mu.Unlock()

	return lt.histogram.Current()
}

// RotateHistogram rotates the histogram window, should be called periodically based on the sliding window duration.
func (lt *LatencyTracker) RotateHistogram() {
	lt.mu.Lock()
	defer lt.mu.Unlock()

	lt.histogram.tick()
}

// Test cases to verify the solution correctness.
func main() {
	// Create a new LatencyTracker with a 1-minute sliding window, max value of 10 seconds, and 2 significant figures.
	tracker := NewLatencyTracker(1*time.Minute, 10*1000, 2)

	// Record some latencies.
	err := tracker.RecordLatency(100) // 100 ms
	if err != nil {
		panic(err)
	}
	err = tracker.RecordLatency(200) // 200 ms
	if err != nil {
		panic(err)
	}

	// Get the merged histogram and print the count of recorded latencies.
	histogram := tracker.GetMergedHistogram()
	println("Count of latencies:", histogram.TotalCount())

	// Rotate the histogram and record a new latency.
	tracker.RotateHistogram()
	err = tracker.RecordLatency(300) // 300 ms
	if err != nil {
		panic(err)
	}

	// Get the new merged histogram and print the count of recorded latencies.
	newHistogram := tracker.GetMergedHistogram()
	println("Count of latencies after rotation:", newHistogram.TotalCount())
}
