type email struct{}

func (e *email) genRandomOTP(len int) string {
	const digits = "0123456789"
	var otp string
	for i := 0; i < len; i++ {
		num, err := rand.Int(rand.Reader, big.NewInt(10))
		if err != nil {
			panic(err) // For simplicity, panic on error. In production, handle the error properly.
		}
		otp += string(digits[num.Int64()])
	}
	fmt.Printf("Email: generating random otp %s\n", otp)
	return otp
}

func (e *email) saveOTPCache(otp string) {
	fmt.Printf("Email: saving otp: %s to cache\n", otp)
}

