// Mock function to sign the node status data.
func signNodeStatus(status NodeStatus) (string, error) {
	// In a real-world scenario, this function would use cryptographic methods to sign the data.
	// For this mock, we'll just return a fixed string.
	return "mock_signature", nil
}

// Mock function to send the node status to a remote server.
func sendNodeStatus(status NodeStatus) error {
	jsonData, err := json.Marshal(status)
	if err != nil {
		return err
	}

	req, err := http.NewRequest("POST", mockServerURL, bytes.NewBuffer(jsonData))
	if err != nil {
		return err
	}
	req.Header.Set("Content-Type", "application/json")

	client := &http.Client{}
	resp, err := client.Do(req)
	if err != nil {
		return err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return errors.New("server responded with non-OK status")
	}

	return nil
}

// Collects and reports node status at a fixed interval.
func reportNodeStatus(ctx context.Context) {
	ticker := time.NewTicker(statusReportInterval)
	defer ticker.Stop()

	for {
		select {
		case <-ctx.Done():
			log.Println("Stopping node status reporting.")
			return
		case <-ticker.C:
			status := NodeStatus{
				NodeID:             "node-123",
				Version:            "1.0.0",
				ActiveChannels:     10,
				InactiveChannels:   2,
