func (e *emptyChunk) layout() string {
	return ""
}

// Implement the fits method for emptyChunk
func (e *emptyChunk) fits(width int) bool {
	return width >= 0
}

// Define the textChunk type
type textChunk struct {
	str       string
	strLength int
	c         Chunk
}

// Implement the layout method for textChunk
func (t *textChunk) layout() string {
	if t.c != nil {
		return t.str + t.c.layout()
	}
	return t.str
}

// Implement the fits method for textChunk
func (t *textChunk) fits(width int) bool {
	if width < t.strLength {
		return false
	}
	if t.c != nil {
		return t.c.fits(width - t.strLength)
	}
	return true
}

// Define the lineChunk type
type lineChunk struct {
	indent uint
	c      Chunk
}

// Implement the layout method for lineChunk
func (l *lineChunk) layout() string {
	indentation := strings.Repeat(" ", int(l.indent))
	if l.c != nil {
		return "\n" + indentation + l.c.layout()
	}
	return "\n" + indentation
}

// Implement the fits method for lineChunk
func (l *lineChunk) fits(width int) bool {
	if int(l.indent) >= width {
		return false
	}
	if l.c != nil {
		return l.c.fits(width - int(l.indent))
	}
	return true
}

// Test cases to verify the solution correctness
