	}
}

func TestEmptyChunkFits(t *testing.T) {
	chunk := &emptyChunk{}
	fit := chunk.fits(1)
	if !fit {
		t.Errorf("emptyChunk should always fit if width is larger than or equal to 0")
	}
	notfit := chunk.fits(-1)
	if notfit {
		t.Errorf("emptyChunk should not fit if width is smaller than 0")
	}
}

