	"github.com/google/uuid"
)

// Account, Bet, Player, and Signature structs are as defined in the given code snippet.

// CreateBet creates a new Bet with the given details.
func CreateBet(description, terms string, amount int, moderatorAddress string, dateExpired time.Time) Bet {
	return Bet{
		ID:               uuid.New().String(),
		Status:           "open",
		Description:      description,
		Terms:            terms,
		Amount:           amount,
		ModeratorAddress: moderatorAddress,
		DateExpired:      dateExpired,
		DateCreated:      time.Now(),
		DateUpdated:      time.Now(),
	}
}

// PlaceBet allows an Account to place a bet by creating a Player entry.
func PlaceBet(betID, address string, inFavor bool, bets map[string]Bet) (*Player, error) {
	bet, exists := bets[betID]
	if !exists {
		return nil, errors.New("bet does not exist")
	}
	if bet.Status != "open" || bet.DateExpired.Before(time.Now()) {
		return nil, errors.New("bet is not open or has expired")
	}
	player := Player{
		BetID:   betID,
		Address: address,
		InFavor: inFavor,
	}
	return &player, nil
}

// SignBet allows an Account to sign a bet by creating a Signature entry.
func SignBet(betID, address string, nonce int, signature string, bets map[string]Bet, signatures map[string][]Signature) (*Signature, error) {
	bet, exists := bets[betID]
	if !exists {
		return nil, errors.New("bet does not exist")
	}
	if bet.Status != "open" {
		return nil, errors.New("bet is not open")
	}
	for _, sig := range signatures[betID] {
		if sig.Address == address {
			return nil, errors.New("account has already signed the bet")
		}
	}
	sig := Signature{
		BetID:      betID,
		Address:    address,
		Nonce:      nonce,
		Signature:  signature,
		DateSigned: time.Now(),
	}
	signatures[betID] = append(signatures[betID], sig)
	return &sig, nil
}

// CloseBet changes the status of the bet to "closed".
func CloseBet(betID string, bets map[string]Bet) error {
	bet, exists := bets[betID]
	if !exists {
		return errors.New("bet does not exist")
	}
	bet.Status = "closed"
	bet.DateUpdated = time.Now()
	bets[betID] = bet
	return nil
}

func main() {
	// Test cases
	bets := make(map[string]Bet)
	signatures := make(map[string][]Signature)

	// Create a new bet
	newBet := CreateBet("Bet on the game", "Team A wins", 100, "moderator1", time.Now().Add(24*time.Hour))
	betID := newBet.ID
	bets[betID] = newBet

	// Place a bet
	player, err := PlaceBet(betID, "player1", true, bets)
	if err != nil {
		fmt.Println("Error placing bet:", err)
	} else {
		fmt.Println("Player placed bet:", player)
	}

	// Sign the bet
	signature, err := SignBet(betID, "player1", 1, "signature1", bets, signatures)
	if err != nil {
		fmt.Println("Error signing bet:", err)
	} else {
		fmt.Println("Signature created:", signature)
	}

	// Close the bet
	err = CloseBet(betID, bets)
	if err != nil {
		fmt.Println("Error closing bet:", err)
	} else {
		fmt.Println("Bet closed successfully")
	}
}
