		db:      make(map[string][]byte),
		cache:   lru.NewCache[string, ExpiredValue](balanceCacheLimit),
		clock:   clock,
		closeCh: make(chan struct{}),
	}
	go ndb.expirer()
	return ndb
}

// setBalance sets the balance for a node with the given ID.
func (db *nodeDB) setBalance(id string, neg bool, b ExpiredValue) {
	key := db.key(id, neg)
	enc, err := rlp.EncodeToBytes(&b)
	if err != nil {
		panic(fmt.Sprintf("Failed to encode balance: %v", err))
	}
	db.db[key] = enc
	db.cache.Add(key, b)
}

// getBalance retrieves the balance for a node with the given ID.
func (db *nodeDB) getBalance(id string, neg bool) (ExpiredValue, bool) {
