	if b, ok := db.cache.Get(key); ok {
		return b, true
	}
	if enc, ok := db.db[key]; ok {
		var b ExpiredValue
		if err := rlp.DecodeBytes(enc, &b); err != nil {
			panic(fmt.Sprintf("Failed to decode balance: %v", err))
		}
		db.cache.Add(key, b)
		return b, true
	}
	return ExpiredValue{}, false
}

// key generates a unique key for the given node ID and balance type.
func (db *nodeDB) key(id string, neg bool) string {
	prefix := "pb:"
	if neg {
		prefix = "nb:"
	}
	return prefix + id
}

// expirer runs in a loop and expires balances that have passed their expiration time.
func (db *nodeDB) expirer() {
	for {
		select {
		case <-db.clock.After(dbCleanupCycle):
			db.expireNodes()
		case <-db.closeCh:
			return
		}
	}
}

// expireNodes iterates over all balances and expires them if necessary.
func (db *nodeDB) expireNodes() {
	now := db.clock.Now()
	for key, enc := range db.db {
		var b ExpiredValue
		if err := rlp.DecodeBytes(enc, &b); err != nil {
			panic(fmt.Sprintf("Failed to decode balance: %v", err))
		}
		if b.Expiration < now {
			delete(db.db, key)
			db.cache.Remove(key)
		}
	}
}

// close terminates the expirer goroutine.
func (db *nodeDB) close() {
	close(db.closeCh)
}

// Test cases to verify the solution correctness.
func main() {
	clock := mclock.System{}
	db := newNodeDB(clock)

	// Add a balance with a future expiration.
	expiration := mclock.AbsTime(time.Now().Add(1 * time.Hour).Unix())
	db.setBalance("node1", false, ExpiredValue{Balance: 100, Expiration: expiration})

	// Retrieve the balance.
	balance, exists := db.getBalance("node1", false)
	if !exists || balance.Balance != 100 {
		fmt.Println("Test failed: expected balance 100 for node1")
	} else {
		fmt.Println("Test passed: balance for node1 is correct")
	}

	// Wait for the balance to expire.
	time.Sleep(2 * time.Hour)
	db.expireNodes()

	// Try to retrieve the expired balance.
	_, exists = db.getBalance("node1", false)
	if exists {
		fmt.Println("Test failed: expected balance for node1 to be expired")
	} else {
		fmt.Println("Test passed: balance for node1 has expired")
	}

	// Clean up.
	db.close()
}
