package main

import (
	"fmt"
	"github.com/laconiz/eros/logis"
	"github.com/laconiz/eros/network"
	"github.com/laconiz/eros/network/cipher"
	"github.com/laconiz/eros/network/encoder"
	"github.com/laconiz/eros/network/queue"
	"github.com/laconiz/eros/network/session"
	"github.com/laconiz/eros/network/socket/reader"
	"net"
	"sync"
	"time"
)

// SessionOption defines the options for a session.
type SessionOption struct {
	Queue   queue.Option
	Timeout time.Duration
	Cipher  cipher.Cipher
	Encoder encoder.Encoder
	Reader  reader.Reader
	Invoker network.Invoker
}

// Session represents a network session with a client.
type Session struct {
	id       session.ID
	conn     net.Conn
	option   *SessionOption
	queue    *queue.Queue
	logger   logis.Logger
	reader   reader.Reader
	cipher   cipher.Cipher
	encoder  encoder.Encoder
	sync.Map
}

// NewSession creates a new session with the given connection and options.
func NewSession(conn net.Conn, option *SessionOption, logger logis.Logger) *Session {
	id := session.Increment()
	return &Session{
		id:      id,
		conn:    conn,
		option:  option,
		queue:   queue.New(option.Queue),
		logger:  logger.Field(network.FieldSession, id),
		cipher:  option.Cipher.New(),
		encoder: option.Encoder.New(),
		reader:  option.Reader.New(),
	}
}

// ID returns the session ID.
func (s *Session) ID() session.ID {
	return s.id
}

// Addr returns the remote address of the client.
func (s *Session) Addr() string {
	return s.conn.RemoteAddr().String()
}

// Close closes the session and releases resources.
func (s *Session) Close() {
	s.queue.Close()
}

// Send sends a message to the client.
func (s *Session) Send(msg interface{}) error {
	message, err := s.encoder.Marshal(msg)
	if err != nil {
		s.logger.Data(msg).Err(err).Error("marshal error")
		return err
	}
	return s.SendRaw(message.Stream)
}

// SendRaw sends a raw byte slice to the client.
func (s *Session) SendRaw(raw []byte) error {
	return s.queue.Add(raw)
}

// read handles incoming messages from the client.
func (s *Session) read() {
	logger := s.logger
	option := s.option
	for {
		deadline := time.Now().Add(option.Timeout)
		s.conn.SetReadDeadline(deadline)
		stream, err := s.reader.Read(s.conn)
		if err != nil {
			logger.Err(err).Info("read error")
			return
		}
		raw, err := s.cipher.Decode(stream)
		if err != nil {
			logger.Err(err).Warn("decode error")
			break
		}
		message, err := s.encoder.Unmarshal(raw)
		if err != nil {
			logger.Err(err).Warn("unmarshal error")
			break
		}
		logger.Data(string(raw)).Debug("recv message")
		s.invoke(&network.Event{
			Meta: message.Meta,
			Msg:  message.Msg,
			Ses:  s,
		})
	}
}

// write handles outgoing messages to the client.
func (s *Session) write() {
	logger := s.logger
	option := s.option
	for {
		deadline := time.Now().Add(option.Timeout)
		s.conn.SetWriteDeadline(deadline)
		events, closed := s.queue.Pick()
		for _, event := range events {
			raw := event.([]byte)
			stream, err := s.cipher.Encode(raw)
			if err != nil {
				logger.Data(raw).Err(err).Warn("encode error")
				return
			}
			if err := s.reader.Write(s.conn, stream); err != nil {
				logger.Data(stream).Err(err).Warn("write error")
				return
			}
			logger.Data(string(raw)).Debug("send message")
		}
		if closed {
			return
		}
	}
}

// run starts the session and handles its lifecycle.
func (s *Session) run(callback func(*Session)) {
	s.logger.Data(s.Addr()).Info("connected")
	go func() {
		s.write()
		s.conn.Close()
	}()
	s.invoke(network.NewConnectedEvent(s))
	s.read()
	s.queue.Close()
	s.logger.Info("disconnected")
	callback(s)
	s.invoke(network.NewDisconnectedEvent(s))
}

// invoke invokes the event handler for the session.
func (s *Session) invoke(event *network.Event) {
	defer func() {
		if err := recover(); err != nil {
			s.logger.Data(err).Error("invoke panic")
		}
	}()
	s.option.Invoker.Invoke(event)
}

// Example usage of the Session type.
func main() {
	// This is a placeholder for actual implementation details.
	// You would need to set up the server, listen for connections,
	// and create sessions with appropriate options and loggers.
	fmt.Println("This is an example usage of the Session type.")
}
