// Decrementer is an interface for a data structure that supports decrementing values.
type Decrementer interface {
	Decrby(key string, value int) (int, error)
}

// InMemoryStore represents an in-memory data store.
type InMemoryStore struct {
	sync.Mutex
	store map[string]int
}

// NewInMemoryStore creates a new instance of InMemoryStore.
func NewInMemoryStore() Decrementer {
	return &InMemoryStore{
		store: make(map[string]int),
	}
}

// Decrby decrements the value of a key by a given value in a thread-safe manner.
func (s *InMemoryStore) Decrby(key string, value int) (int, error) {
	s.Lock()
	defer s.Unlock()

	if currentValue, ok := s.store[key]; ok {
		if currentValue-value < 0 {
			return 0, errors.New("resulting value is less than zero")
		}
		s.store[key] = currentValue - value
	} else {
		s.store[key] = -value
	}
	return s.store[key], nil
}

func main() {
	// Test cases
	store := NewInMemoryStore()

	// Test case 1: Decrement a non-existing key
	newValue, err := store.Decrby("counter", 10)
	if err != nil {
		panic(err)
	}
	println("Test case 1 - New value:", newValue) // Should print -10

	// Test case 2: Decrement an existing key
	store.Decrby("counter", 5)
	newValue, err = store.Decrby("counter", 3)
	if err != nil {
		panic(err)
	}
	println("Test case 2 - New value:", newValue) // Should print -18

	// Test case 3: Decrement resulting in an error
	_, err = store.Decrby("counter", 20)
	if err != nil {
		println("Test case 3 - Error:", err.Error()) // Should print an error message
	}
}
