		for val := range channel {
			fmt.Printf("Processed value: %d\n", val)
		}
	}()
	go AllDanMu()

	// Run for a certain duration then close
	time.Sleep(10 * time.Minute)
	CloseClient()
}

func Register(channel chan int, total int) {
	limit := make(map[int]int)
	c = client.NewClient(roomId)
	c.SetCookie(getCookieFromFile())

	c.OnDanmaku(func(danmaku *message.Danmaku) {
		fmt.Printf("[Danmaku] %s[%d]: %s\n", danmaku.Sender.Uname, danmaku.Sender.Uid, danmaku.Content)
		if danmaku.Type != message.EmoticonDanmaku {
			val, err := strconv.Atoi(danmaku.Content)
			if err == nil && val > 0 && val <= total {
				lock.Lock()
				limit[danmaku.Sender.Uid]++
				if limit[danmaku.Sender.Uid] <= 3 {
					channel <- val
				}
				lock.Unlock()
			}
		}
	})

	if err := c.Start(); err != nil {
		fmt.Println("Error starting client:", err)
		panic(err)
	}
}

func CloseClient() {
	if c != nil {
		c.Stop()
	}
	c = nil
}

func AllDanMu() {
	c := client.NewClient(roomId)
	c.SetCookie(getCookieFromFile())

	c.OnDanmaku(func(danmaku *message.Danmaku) {
		if danmaku.Type != message.EmoticonDanmaku {
			writeToFile(time.Unix(danmaku.Timestamp/1000, 0).Format("2006-01-02 15:04:05"), danmaku.Sender.Uname, danmaku.Content, danmaku.Sender.Uid)
		}
	})

	c.OnSuperChat(func(superChat *message.SuperChat) {
		jsonStr, _ := json.Marshal(superChat)
