		writeToFile(time.Unix(int64(superChat.StartTime), 0).Format("2006-01-02 15:04:05")+"[SC]", superChat.UserInfo.Uname, superChat.Message, superChat.Uid)
	})

	if err := c.Start(); err != nil {
		panic(err)
	}

	for {
		time.Sleep(5 * time.Minute)
	}
}

func writeToFile(tm, uname, content string, uid int) {
	now := time.Now()
	filePath := fmt.Sprintf(danmuFilePath, now.Year(), now.Format("01"), now.Format("02"))
	file, err := os.OpenFile(filePath, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0644)
	if err != nil {
		fmt.Println("Error opening file:", err)
		return
	}
	defer file.Close()

	write := bufio.NewWriter(file)
	if _, err := write.WriteString(fmt.Sprintf("[%s] %s[%d]: %s\n", tm, uname, uid, content)); err != nil {
		fmt.Println("Error writing to file:", err)
		return
	}
	if err := write.Flush(); err != nil {
		fmt.Println("Error flushing to file:", err)
	}
}

func getCookieFromFile() string {
