}

// HandleCall handles incoming messages that require a response.
func (s *Subscription) HandleCall(serverProcess *gen.ServerProcess, from gen.ServerFrom, message etf.Term) (etf.Term, gen.ServerStatus) {
	s.mu.Lock()
	defer s.mu.Unlock()

	log.Debugf("Received message: %s from: %v\n", message, from)

	action, data, err := extractActionData(message)
	if err != nil {
		log.Errorf("Error extracting action data: %s", err)
		return etf.Atom("error"), gen.ServerStatusOK
	}

	switch action {
	case "publish":
		log.Debugf("Received publish message: %s\n", data)
		s.topic.PubSubTopic.Publish(context.Background(), data[0].([]byte))
		return etf.Atom("ok"), gen.ServerStatusOK
	case "list_peers":
		log.Debug("Received list_peers message.")
		result := s.topic.PubSubTopic.ListPeers()
		return result, gen.ServerStatusOK
	case "get_topics":
		log.Debug("Received get_topics message.")
		result := global.GetPubSubService().Sub.GetTopics()
		return result, gen.ServerStatusOK
	default:
		log.Debugf("Received unknown message: %s\n", data)
		return "error", gen.ServerStatusOK
	}
}

// HandleInfo handles info messages.
func (s *Subscription) HandleInfo(serverProcess *gen.ServerProcess, message etf.Term) gen.ServerStatus {
	log.Debugf("Received message: %s\n", message)
	return gen.ServerStatusOK
}

// subscribeTopic listens for messages on a topic and forwards them to the appropriate process.
func subscribeTopic(to *gen.ServerProcess, s *Subscription) {
	s.mu.Lock()
	defer s.mu.Unlock()

	var sid = s.topic.TopicID
	var ctx = s.ctx

	log.Infof("Starting to listen for messages on topic: %s", sid)

	sub, err := s.topic.PubSubTopic.Subscribe()
	if err != nil {
		log.Errorf("Error subscribing to topic: %s", sid)
	}

	log.Infof("Subscribed to topic: %s\n", sid)

	for {
		log.Debugf("Waiting for next message in topic: %s\n", sid)
		msg, err := sub.Next(ctx)
		if err != nil {
			log.Errorf("Error getting next message: %v", err)
			continue
		}
		log.Debugf("Received message: %s\n", msg.GetData())
		sendMessage(to, s.owner, msg.GetData())
	}
}

// sendMessage sends a message to a specified process.
func sendMessage(process *gen.ServerProcess, dst gen.ProcessID, data []byte) error {
	log.Debugf("Sending message to: %s", dst)

	err := process.Process.Send(dst, etf.Term(data))
	if err != nil {
		log.Error(err)
	}

	return nil
}

// createOwnerProcessId creates a process ID for the owner of the subscription.
func createOwnerProcessId(id string) gen.ProcessID {
	return gen.ProcessID{
		Name: id,
		Node: config.SpaceNodeName,
	}
}

// extractActionData extracts the action and data from an ETF term.
func extractActionData(term etf.Term) (etf.Atom, []etf.Term, error) {
	// If the term is just an Atom
	if atom, ok := term.(etf.Atom); ok {
		return atom, nil, nil
	}

	// If the term is a Tuple
	tuple, ok := term.(etf.Tuple)
	if !ok || len(tuple) == 0 {
		return "", nil, errors.New("term is not a tuple or is empty")
	}

	command, ok := tuple[0].(etf.Atom)
	if !ok {
		return "", nil, errors.New("first element is not an atom")
	}

	// Return the command and the rest of the tuple
	return command, tuple[1:], nil
}

// Mocked Subscription for the purpose of this example
type MockedSubscription struct{}

func (ms MockedSubscription) Next(ctx context.Context) (Message, error) {
	return Message{}, nil
}

type Message struct{}

func (m Message) GetData() []byte {
	return []byte("mocked data")
}

func main() {
	// Example usage of the Subscription struct
	ctx := context.Background()
	subscriptionBehavior := New(ctx, "exampleTopic")

	// Mocked server process for the purpose of this example
	serverProcess := &gen.ServerProcess{}

	// Initialize the subscription
	subscriptionBehavior.Init(serverProcess)

	// Handle a publish call
	publishMessage := etf.Tuple{etf.Atom("publish"), []byte("Hello, World!")}
	subscriptionBehavior.HandleCall(serverProcess, gen.ServerFrom{}, publishMessage)

	// Handle a list_peers call
	listPeersMessage := etf.Tuple{etf.Atom("list_peers")}
	subscriptionBehavior.HandleCall(serverProcess, gen.ServerFrom{}, listPeersMessage)

	// Handle a get_topics call
	getTopicsMessage := etf.Tuple{etf.Atom("get_topics")}
	subscriptionBehavior.HandleCall(serverProcess, gen.ServerFrom{}, getTopicsMessage)
}
