// DescribeDataSourceAsync asynchronously retrieves the details of a data source by its ID using channels.
func (client *MetastoreClient) DescribeDataSourceAsync(dataSourceID string) (<-chan *DataSource, <-chan error) {
	dataSourceChan := make(chan *DataSource, 1)
	errorChan := make(chan error, 1)

	go func() {
		defer close(dataSourceChan)
		defer close(errorChan)

		dataSource, err := client.DescribeDataSource(dataSourceID)
		if err != nil {
			errorChan <- err
			return
		}
		dataSourceChan <- dataSource
	}()

	return dataSourceChan, errorChan
}

