package main

import (
	"bytes"
	"errors"
	"fmt"
)

var (
	errNilWriter  = errors.New("nil writer")
	errOutOfRange = errors.New("out of range")
)

type errorList struct {
	errs []error
}

func (e *errorList) tryPush(err error) {
	if err != nil {
		if e.errs == nil {
			e.errs = make([]error, 0, 2)
		}
		e.errs = append(e.errs, err)
	}
}

func (e errorList) err() error {
	if len(e.errs) == 0 {
		return nil
	}
	b := new(bytes.Buffer)
	for _, err := range e.errs {
		b.WriteString(err.Error())
		b.WriteByte(';')
	}
	return errors.New(b.String())
}

type BufferedErrorWriter struct {
	buffer *bytes.Buffer
	errors errorList
}

func (bew *BufferedErrorWriter) Write(p []byte) (n int, err error) {
	if bew.buffer == nil {
		bew.errors.tryPush(errNilWriter)
		return 0, errNilWriter
	}
	if len(p) > 1024 {
		bew.errors.tryPush(errOutOfRange)
		return 0, errOutOfRange
	}
	n, err = bew.buffer.Write(p)
	bew.errors.tryPush(err)
	return n, err
}

func (bew *BufferedErrorWriter) Flush() error {
	return bew.errors.err()
}

func main() {
	bew := BufferedErrorWriter{buffer: new(bytes.Buffer)}

	// Test case 1: Normal write
	_, err := bew.Write([]byte("Hello, World!"))
	if err != nil {
		fmt.Println("Error:", err)
	}

	// Test case 2: Write with nil buffer
	bew.buffer = nil
	_, err = bew.Write([]byte("This should fail."))
	if err != nil {
		fmt.Println("Error:", err)
	}

	// Test case 3: Write with out of range data
	bew.buffer = new(bytes.Buffer)
	_, err = bew.Write(make([]byte, 1025))
	if err != nil {
		fmt.Println("Error:", err)
	}

	// Flush and get consolidated error
	err = bew.Flush()
	if err != nil {
		fmt.Println("Consolidated Error:", err)
	} else {
		fmt.Println("No errors occurred during write operations.")
	}
}
