The function should maintain the sorting order of the nodes and should handle cases where either or both of the input lists are `nil`.

output:
```go
package main

import (
	"fmt"
)

type ListNode struct {
	Val  int
	Next *ListNode
}

func CreateList(nums ...int) *ListNode {
	if len(nums) < 1 {
		return nil
	}
	head := &ListNode{Val: nums[0]}
	cur := head
	for i := 1; i < len(nums); i++ {
		cur.Next = &ListNode{Val: nums[i]}
		cur = cur.Next
	}
	return head
}

func ToString(head *ListNode) string {
	if head == nil {
		return "_"
	}
	cur := head
	str := fmt.Sprintf("%v", cur.Val)
	cur = cur.Next
	for cur != nil {
		str += fmt.Sprintf(", %v", cur.Val)
		cur = cur.Next
	}
	return str
}

func MergeSortedLists(l1 *ListNode, l2 *ListNode) *ListNode {
	dummy := &ListNode{}
	current := dummy

	for l1 != nil && l2 != nil {
		if l1.Val < l2.Val {
			current.Next = l1
			l1 = l1.Next
		} else {
			current.Next = l2
			l2 = l2.Next
		}
		current = current.Next
	}

	if l1 != nil {
		current.Next = l1
	} else {
		current.Next = l2
	}

	return dummy.Next
}

func main() {
	// Test cases
	testCases := []struct {
		list1     []int
		list2     []int
		mergedStr string
	}{
		{[]int{1, 2, 4}, []int{1, 3, 4}, "1, 1, 2, 3, 4, 4"},
		{[]int{}, []int{0}, "0"},
		{[]int{2, 3, 5}, []int{}, "2, 3, 5"},
		{[]int{1, 3, 5}, []int{2, 4, 6}, "1, 2, 3, 4, 5, 6"},
	}

	for _, tc := range testCases {
		l1 := CreateList(tc.list1...)
		l2 := CreateList(tc.list2...)
		mergedList := MergeSortedLists(l1, l2)
		mergedListStr := ToString(mergedList)
		fmt.Printf("Merged List: %s | Expected: %s\n", mergedListStr, tc.mergedStr)
	}
}
