type User struct {
	ID        *int64 `json:"id"`
	Name      string `json:"name"`
	SecretKey string `json:"secret_key"`
}

var (
	users      = make(map[int64]User)
	nextUserID int64 = 1
	mutex      sync.Mutex
)

func RegisterUser(name, secretKey string) User {
	mutex.Lock()
	defer mutex.Unlock()

	user := User{
		ID:        &nextUserID,
		Name:      name,
		SecretKey: secretKey,
	}
	users[nextUserID] = user
	nextUserID++
	return user
}

func AuthenticateUser(id int64, secretKey string) (bool, string) {
	user, exists := users[id]
	if !exists || user.SecretKey != secretKey {
		return false, ""
	}
	return true, user.Name
}

func GetUserByID(id int64) (User, error) {
	user, exists := users[id]
	if !exists {
		return User{}, errors.New("user not found")
	}
	return user, nil
}

func main() {
	// Test cases
	user1 := RegisterUser("Alice", "aliceSecret")
	user2 := RegisterUser("Bob", "bobSecret")

	fmt.Println("Registered Users:")
	fmt.Println(user1)
	fmt.Println(user2)

	authSuccess, name := AuthenticateUser(*user1.ID, "aliceSecret")
	fmt.Printf("Authentication successful: %v, Name: %s\n", authSuccess, name)

	authSuccess, name = AuthenticateUser(*user2.ID, "wrongSecret")
	fmt.Printf("Authentication successful: %v, Name: %s\n", authSuccess, name)

	retrievedUser, err := GetUserByID(*user1.ID)
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Println("Retrieved User:", retrievedUser)
	}

	_, err = GetUserByID(3)
	if err != nil {
		fmt.Println("Error:", err)
	}
}
