// Bucket interface as defined in the question.
type Bucket interface {
	Name() string
	Region() string
	ListBlobs(path string) ([]Blob, error)
	ListDirectories() ([]string, error)
	CopyBlobWithinBucket(src, dst string) error
	CopyBlobFromBucket(bucket Bucket, src, dst string) error
	UploadBlob(path, contents string) error
	HasBlob(path string) (bool, error)
}

// Blob interface as defined in the question.
type Blob interface {
	Path() string
}

// SimpleBlob is a simple implementation of the Blob interface.
type SimpleBlob struct {
	path string
}

// Path returns the path of the blob.
func (b *SimpleBlob) Path() string {
	return b.path
}

// SimpleBucket is a simple in-memory implementation of the Bucket interface.
type SimpleBucket struct {
	name     string
	region   string
	blobs    map[string]string
	blobLock sync.RWMutex
}

// NewSimpleBucket creates a new instance of SimpleBucket.
func NewSimpleBucket(name, region string) *SimpleBucket {
	return &SimpleBucket{
		name:   name,
		region: region,
		blobs:  make(map[string]string),
	}
}

// Name returns the name of the bucket.
func (b *SimpleBucket) Name() string {
	return b.name
}

// Region returns the region of the bucket.
func (b *SimpleBucket) Region() string {
	return b.region
}

// ListBlobs lists all blobs in the bucket that have the specified path prefix.
func (b *SimpleBucket) ListBlobs(path string) ([]Blob, error) {
	b.blobLock.RLock()
	defer b.blobLock.RUnlock()

	var blobs []Blob
	for blobPath := range b.blobs {
		if path == "" || blobPath == path || blobPath[:len(path)] == path {
			blobs = append(blobs, &SimpleBlob{path: blobPath})
		}
	}
	return blobs, nil
}

// ListDirectories is not implemented for SimpleBucket.
func (b *SimpleBucket) ListDirectories() ([]string, error) {
	return nil, errors.New("ListDirectories not implemented for SimpleBucket")
}

// CopyBlobWithinBucket copies a blob within the bucket.
func (b *SimpleBucket) CopyBlobWithinBucket(src, dst string) error {
	b.blobLock.Lock()
	defer b.blobLock.Unlock()

	if contents, ok := b.blobs[src]; ok {
		b.blobs[dst] = contents
		return nil
	}
	return errors.New("source blob does not exist")
}

// CopyBlobFromBucket copies a blob from another bucket.
func (b *SimpleBucket) CopyBlobFromBucket(bucket Bucket, src, dst string) error {
	b.blobLock.Lock()
	defer b.blobLock.Unlock()

	if hasBlob, _ := bucket.HasBlob(src); hasBlob {
		blobs, _ := bucket.ListBlobs(src)
		for _, blob := range blobs {
			if blob.Path() == src {
				b.blobs[dst] = b.blobs[blob.Path()]
				return nil
			}
		}
	}
	return errors.New("source blob does not exist in the specified bucket")
}

// UploadBlob uploads a blob to the bucket.
func (b *SimpleBucket) UploadBlob(path, contents string) error {
	b.blobLock.Lock()
	defer b.blobLock.Unlock()

	b.blobs[path] = contents
	return nil
}

// HasBlob checks if the bucket has a blob at the specified path.
func (b *SimpleBucket) HasBlob(path string) (bool, error) {
	b.blobLock.RLock()
	defer b.blobLock.RUnlock()

	_, exists := b.blobs[path]
	return exists, nil
}

