	Email string `json:"email"`
}

// userDB simulates a database of users with UUID as the key.
var userDB = map[uuid.UUID]User{
	uuid.MustParse("123e4567-e89b-12d3-a456-426614174000"): {Name: "John Doe", Email: "john.doe@example.com"},
	uuid.MustParse("123e4567-e89b-12d3-a456-426614174001"): {Name: "Jane Smith", Email: "jane.smith@example.com"},
}

// getUser is an HTTP handler that retrieves user information based on UUID.
func getUser(w http.ResponseWriter, r *http.Request) {
	UUID, err := getUUIDFromRequest(r)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	user, ok := userDB[UUID]
	if !ok {
		http.Error(w, "User not found", http.StatusNotFound)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(user)
}

// getUUIDFromRequest gets and parses the UUID from the request.
func getUUIDFromRequest(r *http.Request) (uuid.UUID, error) {
	uuidString := chi.URLParam(r, "uuid")
	UUID, err := uuid.Parse(uuidString)
	if err != nil {
		return uuid.Nil, fmt.Errorf("[%s] is not a valid UUID: [%w]", uuidString, err)
	}
	return UUID, nil
}

// Test cases to verify the correctness of the getUser handler.
func TestGetUser(t *testing.T) {
	r := chi.NewRouter()
	r.Get("/users/{uuid}", getUser)

	// Test case: valid UUID and user exists
	req := httptest.NewRequest("GET", "/users/123e4567-e89b-12d3-a456-426614174000", nil)
	w := httptest.NewRecorder()
	r.ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Errorf("Expected status code 200, got %d", w.Code)
	}

	expected := `{"name":"John Doe","email":"john.doe@example.com"}`
	if !strings.Contains(w.Body.String(), expected) {
		t.Errorf("Expected body to contain %s, got %s", expected, w.Body.String())
	}

	// Test case: valid UUID but user does not exist
	req = httptest.NewRequest("GET", "/users/123e4567-e89b-12d3-a456-426614174002", nil)
	w = httptest.NewRecorder()
	r.ServeHTTP(w, req)

	if w.Code != http.StatusNotFound {
		t.Errorf("Expected status code 404, got %d", w.Code)
	}

	// Test case: invalid UUID
	req = httptest.NewRequest("GET", "/users/invalid-uuid", nil)
	w = httptest.NewRecorder()
	r.ServeHTTP(w, req)

	if w.Code != http.StatusBadRequest {
		t.Errorf("Expected status code 400, got %d", w.Code)
	}
}

func main() {
	r := chi.NewRouter()
	r.Get("/users/{uuid}", getUser)

	http.ListenAndServe(":8080", r)
}
