// canReachLastIndex checks if it's possible to jump to the last index of the array.
func canReachLastIndex(nums []int) bool {
	lastIndex := len(nums) - 1
	for i := lastIndex - 1; i >= 0; i-- {
		if i+nums[i] >= lastIndex {
			lastIndex = i
		}
	}
	return lastIndex == 0
}

func main() {
	// Test cases to verify the solution
	fmt.Println(canReachLastIndex([]int{2, 3, 1, 1, 4})) // Output: true
	fmt.Println(canReachLastIndex([]int{3, 2, 1, 0, 4})) // Output: false
	fmt.Println(canReachLastIndex([]int{0}))              // Output: true
	fmt.Println(canReachLastIndex([]int{2, 5, 0, 0}))     // Output: true
}
