var rootCmd = &cobra.Command{
	Use:   "tasker",
	Short: "Tasker is a simple CLI to-do list manager.",
}

var addCmd = &cobra.Command{
	Use:   "add [description]",
	Short: "Adds a new task with the specified description.",
	Args:  cobra.MinimumNArgs(1),
	Run: func(cmd *cobra.Command, args []string) {
		description := args[0]
		task := Task{ID: taskID, Description: description, Completed: false}
		tasks = append(tasks, task)
		fmt.Printf("Added task #%d: %s\n", taskID, description)
		taskID++
	},
}

var listCmd = &cobra.Command{
	Use:   "list",
	Short: "Lists all tasks with their identifiers, descriptions, and statuses.",
	Run: func(cmd *cobra.Command, args []string) {
		for _, task := range tasks {
			status := "Incomplete"
			if task.Completed {
				status = "Completed"
			}
			fmt.Printf("%d: %s [%s]\n", task.ID, task.Description, status)
		}
	},
}

var completeCmd = &cobra.Command{
	Use:   "complete [id]",
	Short: "Marks a task as completed by its identifier.",
	Args:  cobra.MinimumNArgs(1),
	Run: func(cmd *cobra.Command, args []string) {
		id, err := strconv.Atoi(args[0])
		if err != nil {
			fmt.Println("Invalid task ID")
			return
		}
		for i, task := range tasks {
			if task.ID == id {
				tasks[i].Completed = true
				fmt.Printf("Task #%d marked as completed.\n", id)
				return
			}
		}
		fmt.Println("Task ID not found")
	},
}

func init() {
	rootCmd.AddCommand(addCmd)
	rootCmd.AddCommand(listCmd)
	rootCmd.AddCommand(completeCmd)
}

func Execute() {
	if err := rootCmd.Execute(); err != nil {
		fmt.Println(err)
		os.Exit(1)
	}
}

func main() {
	Execute()
}
