	BaseRouter
}

// Override PreHandle method.
func (cr *CustomRouter) PreHandle(req ziface.IRequest) {
	fmt.Println("PreHandle: Processing request before main handler.")
}

// Override Handle method.
func (cr *CustomRouter) Handle(req ziface.IRequest) {
	fmt.Println("Handle: Main request processing.")
}

// Override PostHandle method.
func (cr *CustomRouter) PostHandle(req ziface.IRequest) {
	fmt.Println("PostHandle: Processing request after main handler.")
}

// Server struct that can register a custom router.
