package main

import (
	"flag"
	"net/http"
	"net/http/httptest"
	"os"
	"testing"

	"github.com/gin-gonic/gin"
	"github.com/stretchr/testify/assert"
	"github.com/txn2/ack"
	"github.com/txn2/micro"
	"github.com/txn2/provision"
)

// getEnv gets an environment variable or sets a default if
// one does not exist.
func getEnv(key, fallback string) string {
	value := os.Getenv(key)
	if len(value) == 0 {
		return fallback
	}
	return value
}

func main() {
	// Parse configuration from environment variables or command-line flags
	provisionPath := flag.String("provisionPath", getEnv("PROVISION_PATH", "/provision"), "Provision path")
	provisionHost := flag.String("provisionHost", getEnv("PROVISION_HOST", "api-provision:8080"), "Provision host")
	provisionScheme := flag.String("provisionScheme", getEnv("PROVISION_SCHEME", "http"), "Provision scheme")
	flag.Parse()

	serverCfg, _ := micro.NewServerCfg("Op")
	server := micro.NewServer(serverCfg)

	// User token middleware
	server.Router.Use(provision.UserTokenHandler())

	// Health check endpoint
	server.Router.GET("/health", func(c *gin.Context) {
		c.String(http.StatusOK, "OK")
	})

	// Middleware to check user privileges
	checkSysopHandler := func(c *gin.Context) {
		ak := ack.Gin(c)

		userI, ok := c.Get("User")
		if !ok {
			ak.SetPayloadType("ErrorMessage")
			ak.SetPayload("missing user token")
			ak.GinErrorAbort(http.StatusUnauthorized, "E401", "UnauthorizedAccess")
			return
		}

		user := userI.(*provision.User)

		if user.Active && user.Sysop {
			return
		}

		ak.SetPayloadType("ErrorMessage")
		ak.SetPayload("insufficient privileges")
		ak.GinErrorAbort(http.StatusUnauthorized, "E401", "UnauthorizedAccess")
	}

	// Setup reverse proxy group with middleware
	prov := server.Router.Group(*provisionPath, checkSysopHandler)

	prov.Any("/*any",
		server.ReverseProxy(micro.PxyCfg{
			Scheme: *provisionScheme,
			Host:   *provisionHost,
			Strip:  *provisionPath,
		}),
	)

	// Run the server
	server.Run()
}

// Test cases to verify middleware and reverse proxy functionality
func TestMiddlewareAndReverseProxy(t *testing.T) {
	gin.SetMode(gin.TestMode)

	t.Run("HealthCheckEndpoint", func(t *testing.T) {
		router := gin.Default()
		router.GET("/health", func(c *gin.Context) {
			c.String(http.StatusOK, "OK")
		})

		w := httptest.NewRecorder()
		req, _ := http.NewRequest("GET", "/health", nil)
		router.ServeHTTP(w, req)

		assert.Equal(t, http.StatusOK, w.Code)
		assert.Equal(t, "OK", w.Body.String())
	})

	t.Run("UnauthorizedAccess", func(t *testing.T) {
		// Setup a test server with the middleware
		router := gin.Default()
		router.Use(provision.UserTokenHandler())
		router.GET("/provision/test", func(c *gin.Context) {
			c.String(http.StatusOK, "OK")
		})

		w := httptest.NewRecorder()
		req, _ := http.NewRequest("GET", "/provision/test", nil)
		router.ServeHTTP(w, req)

		assert.Equal(t, http.StatusUnauthorized, w.Code)
	})

	// Additional tests for reverse proxy functionality can be added here
}
