package main

import (
	"fmt"
	"sort"
)

// Brute-force approach to find two numbers that add up to the target.
func bruteForce(nums []int, target int) (int, int) {
	length := len(nums)
	for i := 0; i < length-1; i++ {
		for j := i + 1; j < length; j++ {
			if nums[i]+nums[j] == target {
				return i, j
			}
		}
	}
	return -1, -1
}

// Hash map approach to find two numbers that add up to the target.
func hashMap(nums []int, target int) (int, int) {
	arrMap := make(map[int]int)
	for j := 0; j < len(nums); j++ {
		complement := target - nums[j]
		if index, ok := arrMap[complement]; ok {
			return index, j
		}
		arrMap[nums[j]] = j
	}
	return -1, -1
}

// Binary search approach to find two numbers that add up to the target.
func binarySearch(nums []int, target int) (int, int) {
	sort.Ints(nums)
	for i := 0; i < len(nums); i++ {
		low, high := i+1, len(nums)-1
		for low <= high {
			mid := low + (high-low)/2
			if nums[mid] == target-nums[i] {
				return i, mid
			} else if nums[mid] > target-nums[i] {
				high = mid - 1
			} else {
				low = mid + 1
			}
		}
	}
	return -1, -1
}

// Two-pointer approach to find two numbers that add up to the target.
func twoPointer(nums []int, target int) (int, int) {
	sort.Ints(nums)
	low, high := 0, len(nums)-1
	for low < high {
		sum := nums[low] + nums[high]
		if sum == target {
			return low, high
		} else if sum < target {
			low++
		} else {
			high--
		}
	}
	return -1, -1
}

func main() {
	nums := []int{1, 2, 3, 5}
	target := 8

	// Test cases
	fmt.Println("Brute-force approach:", bruteForce(nums, target))
	fmt.Println("Hash map approach:", hashMap(nums, target))
	fmt.Println("Binary search approach:", binarySearch(nums, target))
	fmt.Println("Two-pointer approach:", twoPointer(nums, target))
}
