// PoiManager struct to manage a collection of POIs
type PoiManager struct {
	pois map[string]Poi
}

// NewPoiManager creates a new instance of PoiManager
func NewPoiManager() *PoiManager {
	return &PoiManager{
		pois: make(map[string]Poi),
	}
}

// AddPoi adds a new POI to the collection
func (pm *PoiManager) AddPoi(poi Poi) error {
	if _, exists := pm.pois[poi.PoiId]; exists {
		return errors.New("POI with the given ID already exists")
	}
	pm.pois[poi.PoiId] = poi
	return nil
}

// GetPoi retrieves a POI by its PoiId
func (pm *PoiManager) GetPoi(poiId string) (Poi, error) {
	poi, exists := pm.pois[poiId]
	if !exists {
		return Poi{}, errors.New("POI not found")
	}
	return poi, nil
}

// UpdatePoi updates the details of an existing POI
func (pm *PoiManager) UpdatePoi(poi Poi) error {
	if _, exists := pm.pois[poi.PoiId]; !exists {
		return errors.New("POI not found")
	}
	pm.pois[poi.PoiId] = poi
	return nil
}

// DeletePoi deletes a POI from the collection by its PoiId
func (pm *PoiManager) DeletePoi(poiId string) error {
	if _, exists := pm.pois[poiId]; !exists {
		return errors.New("POI not found")
	}
	delete(pm.pois, poiId)
	return nil
}

// ListPois lists all POIs in the collection
func (pm *PoiManager) ListPois() []Poi {
	pois := make([]Poi, 0, len(pm.pois))
	for _, poi := range pm.pois {
		pois = append(pois, poi)
	}
	return pois
