const name = "GETSERVERS"

func New(serverListFn func() []serverinfo.ServerDetail) *Command {
	return &Command{serverListFn}
}

type Command struct {
	serverListFn func() []serverinfo.ServerDetail
}

func (c *Command) Execute(conn redcon.Conn, args [][]byte) (interface{}, error) {
	if len(args) != 1 {
		return nil, fmt.Errorf("command %s does not accept any arguments", name)
	}
	serverList := c.serverListFn()
	return serverList, nil
}

func (c *Command) Name() string {
	return name
}

func (c *Command) Hint() interface{} {
	return []interface{}{
		redcon.SimpleString(name),
		0,
		[]interface{}{},
		0,
		0,
		0,
		[]interface{}{},
	}
}

// Main function to start the Redis server and handle the GETSERVERS command
func main() {
	addr := ":6379"
	server := redcon.NewServer(addr,
		func(conn redcon.Conn, cmd redcon.Command) {
			if string(cmd.Args[0]) != "GETSERVERS" {
				conn.WriteError("ERR unknown command '" + string(cmd.Args[0]) + "'")
				return
			}
			getServersCmd := command.New(serverinfo.GetServerList)
			result, err := getServersCmd.Execute(conn, cmd.Args[1:])
			if err != nil {
				conn.WriteError("ERR " + err.Error())
				return
			}
			conn.WriteArray(len(result.([]serverinfo.ServerDetail)))
			for _, server := range result.([]serverinfo.ServerDetail) {
				conn.WriteBulkString(server.Name + " " + server.Address)
			}
		},
		nil,
		nil,
	)

	log.Printf("started server at %s", addr)
	if err := server.ListenAndServe(); err != nil {
		log.Fatal(err)
	}
