package main

import (
	"fmt"
	"net"

	"github.com/google/gopacket"
	gplayers "github.com/google/gopacket/layers"
)

const (
	// HeaderLength is the IPv4 header length.
	HeaderLength = 20

	// MTU (maximum transmission unit) is the maximum number of bytes that are
	// allowed on the payload of a datagram (the network layer name for a packet).
	MTU = 1500 - HeaderLength
)

type Host struct {
	IPAddress net.IP
	NIC       chan gopacket.Packet
}

func NewHost(ipAddress string) *Host {
	return &Host{
		IPAddress: net.ParseIP(ipAddress),
		NIC:       make(chan gopacket.Packet, 1),
	}
}

func (h *Host) SendPacket(destination *Host, payload []byte) error {
	if len(payload) > MTU {
		return fmt.Errorf("payload size exceeds the MTU")
	}

	// Create the IP layer
	ipLayer := &gplayers.IPv4{
		SrcIP:    h.IPAddress,
		DstIP:    destination.IPAddress,
		Version:  4,
		IHL:      5,
		Length:   uint16(HeaderLength + len(payload)),
		Protocol: gplayers.IPProtocolTCP,
	}

	// Create the packet with the IP layer and payload
	buffer := gopacket.NewSerializeBuffer()
	options := gopacket.SerializeOptions{}
	gopacket.SerializeLayers(buffer, options, ipLayer, gopacket.Payload(payload))

	// Send the packet to the destination host's NIC
	destination.NIC <- gopacket.NewPacket(buffer.Bytes(), gplayers.LayerTypeIPv4, gopacket.Default)

	return nil
}

func (h *Host) ReceivePacket() {
	packet := <-h.NIC
	fmt.Printf("Host %s received packet: %s\n", h.IPAddress, packet.Dump())
}

func main() {
	hostA := NewHost("192.168.1.2")
	hostB := NewHost("192.168.1.3")

	go hostB.ReceivePacket()

	payload := []byte("Hello, World!")
	err := hostA.SendPacket(hostB, payload)
	if err != nil {
		fmt.Println("Error sending packet:", err)
		return
	}
}

