// Todo model represents a single Todo item.
type Todo struct {
	ID          string `json:"id"`
	Title       string `json:"title"`
	Description string `json:"description"`
	Completed   bool   `json:"completed"`
}

// TodoService interface defines the methods to manage Todo items.
type TodoService interface {
	GetAll() ([]Todo, error)
	Create(todo *Todo) (*Todo, error)
	GetByID(id string) (*Todo, error)
	Update(id string, todo *Todo) (*Todo, error)
	UpdatePartial(id string, todo *Todo) (*Todo, error)
	Delete(id string) error
}

// InMemoryTodoService implements TodoService with an in-memory storage.
type InMemoryTodoService struct {
	todos map[string]Todo
	mu    sync.RWMutex
}

// NewInMemoryTodoService creates a new instance of InMemoryTodoService.
func NewInMemoryTodoService() *InMemoryTodoService {
	return &InMemoryTodoService{
		todos: make(map[string]Todo),
	}
}

func (s *InMemoryTodoService) GetAll() ([]Todo, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	todos := make([]Todo, 0, len(s.todos))
	for _, todo := range s.todos {
		todos = append(todos, todo)
	}
	return todos, nil
}

func (s *InMemoryTodoService) Create(todo *Todo) (*Todo, error) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.todos[todo.ID] = *todo
	return todo, nil
}

func (s *InMemoryTodoService) GetByID(id string) (*Todo, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	todo, exists := s.todos[id]
	if !exists {
		return nil, errors.New("todo not found")
	}
	return &todo, nil
}

func (s *InMemoryTodoService) Update(id string, todo *Todo) (*Todo, error) {
	s.mu.Lock()
	defer s.mu.Unlock()
	_, exists := s.todos[id]
	if !exists {
		return nil, errors.New("todo not found")
	}
	s.todos[id] = *todo
	return todo, nil
}

func (s *InMemoryTodoService) UpdatePartial(id string, todo *Todo) (*Todo, error) {
	s.mu.Lock()
	defer s.mu.Unlock()
	currentTodo, exists := s.todos[id]
	if !exists {
		return nil, errors.New("todo not found")
	}
	if todo.Title != "" {
		currentTodo.Title = todo.Title
	}
	if todo.Description != "" {
		currentTodo.Description = todo.Description
	}
	if todo.Completed != currentTodo.Completed {
		currentTodo.Completed = todo.Completed
	}
	s.todos[id] = currentTodo
	return &currentTodo, nil
}

func (s *InMemoryTodoService) Delete(id string) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	_, exists := s.todos[id]
	if !exists {
		return errors.New("todo not found")
	}
	delete(s.todos, id)
	return nil
}

