	"go.mongodb.org/mongo-driver/mongo"
	"go.mongodb.org/mongo-driver/mongo/options"
)

// Assuming utils package is available with the required functions
import "github.com/yourproject/utils"

// DeviceBlockRequestJSON represents the JSON structure for device block requests.
type DeviceBlockRequestJSON struct {
	Nickname   string `json:"nickname" validate:"required,min=3,max=32,alphanum"`
	DeviceName string `json:"deviceName" validate:"required,min=3,max=32,alphanum"`
	Block      bool   `json:"block"`
}

// Device represents the structure of a device in the database.
type Device struct {
	Nickname   string `bson:"nickname"`
	DeviceName string `bson:"deviceName"`
	Blocked    bool   `bson:"blocked"`
}

// DeviceBlock handles the blocking and unblocking of devices.
func DeviceBlock(w http.ResponseWriter, req *http.Request) {
	if req.Method != "POST" {
		utils.HTTPError(w, "Method not allowed", http.StatusMethodNotAllowed, "HTTP001")
		return
	}

	var request DeviceBlockRequestJSON
	if err := json.NewDecoder(req.Body).Decode(&request); err != nil {
		utils.HTTPError(w, "Invalid request format", http.StatusBadRequest, "DB001")
		return
	}

	validate := validator.New()
	if err := validate.Struct(request); err != nil {
		utils.HTTPError(w, "Validation error: "+err.Error(), http.StatusBadRequest, "DB002")
		return
	}

	nickname := utils.Sanitize(request.Nickname)
	deviceName := utils.Sanitize(request.DeviceName)

	if err := utils.AdminOrItselfOnly(w, req, nickname); err != nil {
		return
	}

	client, err := mongo.Connect(req.Context(), options.Client().ApplyURI("mongodb://localhost:27017"))
	if err != nil {
		utils.HTTPError(w, "Database connection error", http.StatusInternalServerError, "DB003")
		return
	}
	defer client.Disconnect(req.Context())

	collection := client.Database("yourdatabase").Collection("devices")

	filter := bson.M{"nickname": nickname, "deviceName": deviceName, "blocked": !request.Block}
	update := bson.M{"$set": bson.M{"blocked": request.Block}}

	result, err := collection.UpdateOne(req.Context(), filter, update)
	if err != nil {
		utils.HTTPError(w, "Error updating device status", http.StatusInternalServerError, "DB004")
		return
	}

	if result.MatchedCount == 0 {
		utils.HTTPError(w, "No matching device found or device already in the desired state", http.StatusBadRequest, "DB005")
		return
	}

	status := "unblocked"
	if request.Block {
		status = "blocked"
	}
	utils.Log("Device " + deviceName + " successfully " + status)

	response := map[string]string{"status": "OK"}
	json.NewEncoder(w).Encode(response)
}

func main() {
	http.HandleFunc("/device/block", DeviceBlock)
	http.ListenAndServe(":8080", nil)
}

// Test cases to verify the solution correctness would be implemented as HTTP client requests
// to the "/device/block" endpoint, sending various POST requests with different JSON payloads
// and checking the HTTP response codes and JSON responses.
