package main

import (
	"bufio"
	"fmt"
	"os"
	"strconv"
	"strings"
)

type Stack[T any] []T

func (st *Stack[T]) IsEmpty() bool { return len(*st) == 0 }
func (st *Stack[T]) Push(v T)      { *st = append(*st, v) }
func (st *Stack[T]) Pop() T {
	if st.IsEmpty() {
		var zeroValue T
		return zeroValue
	}
	topIndex := len(*st) - 1
	top := (*st)[topIndex]
	*st = (*st)[:topIndex]
	return top
}
func (st *Stack[T]) Top() T {
	if st.IsEmpty() {
		var zeroValue T
		return zeroValue
	}
	return (*st)[len(*st)-1]
}

func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}

func trapRainWater(walls []int) int {
	st := &Stack[int]{}
	waterTrapped := 0

	for i, height := range walls {
		for !st.IsEmpty() && walls[st.Top()] < height {
			bottom := walls[st.Pop()]
			if st.IsEmpty() {
				break
			}
			distance := i - st.Top() - 1
			boundedHeight := min(walls[st.Top()], height) - bottom
			waterTrapped += distance * boundedHeight
		}
		st.Push(i)
	}

	return waterTrapped
}

func main() {
	scanner := bufio.NewScanner(os.Stdin)
	scanner.Scan() // Read and discard the first line (H W), only W is needed

	scanner.Scan()
	wallHeightsStr := strings.Fields(scanner.Text())
	wallHeights := make([]int, len(wallHeightsStr))
	for i, hStr := range wallHeightsStr {
		wallHeights[i], _ = strconv.Atoi(hStr)
	}

	fmt.Println(trapRainWater(wallHeights))
}

// Test cases to verify the solution correctness
func main() {
	testCases := [][]int{
		{0, 1, 0, 2, 1, 0, 1, 3, 2, 1, 2, 1}, // Expected output: 6
		{2, 0, 2},                             // Expected output: 2
		{3, 0, 0, 2, 0, 4},                    // Expected output: 10
		{0, 0, 0, 0, 0},                       // Expected output: 0
		{1, 2, 3, 4, 5},                       // Expected output: 0
	}

	for _, walls := range testCases {
		fmt.Printf("Trapped rainwater for walls %v: %d\n", walls, trapRainWater(walls))
	}
}
