// CreateCgroup creates a new cgroup managed by systemd with resource accounting.
func CreateCgroup(path string) error {
	c, err := systemdDbus.New()
	if err != nil {
		return err
	}
	defer c.Close()

	slice, name := filepath.Split(path)
	slice = strings.TrimSuffix(slice, "/")

	var lastError error
	for i := 0; i < 2; i++ {
		properties := []systemdDbus.Property{
			systemdDbus.PropDescription(fmt.Sprintf("cgroup %s", name)),
			systemdDbus.PropWants(slice),
		}
		pMap := map[string]bool{
			"DefaultDependencies": false,
			"MemoryAccounting":    true,
			"CPUAccounting":       true,
			"BlockIOAccounting":   true,
		}
		if i == 0 {
			pMap["Delegate"] = true
		}
		for k, v := range pMap {
			p := systemdDbus.Property{
				Name:  k,
				Value: dbus.MakeVariant(v),
			}
			properties = append(properties, p)
		}

		ch := make(chan string)
		_, err = c.StartTransientUnit(name, "replace", properties, ch)
		if err != nil {
			lastError = err
			continue
		}
		<-ch
		return nil
	}
	return lastError
}

// DestroyCgroup stops and removes a cgroup managed by systemd.
func DestroyCgroup(path string) error {
	c, err := systemdDbus.New()
	if err != nil {
		return err
	}
	defer c.Close()

	name := filepath.Base(path)

	ch := make(chan string)
	_, err = c.StopUnit(name, "replace", ch)
	if err != nil {
		return err
	}
	<-ch
	return nil
}

// Example usage of CreateCgroup and DestroyCgroup.
func main() {
	cgroupPath := "/sys/fs/cgroup/system.slice/my-cgroup"

	// Create a new cgroup
	if err := CreateCgroup(cgroupPath); err != nil {
		fmt.Printf("Error creating cgroup: %v\n", err)
	} else {
		fmt.Println("Cgroup created successfully.")
	}

	// Destroy the cgroup
	if err := DestroyCgroup(cgroupPath); err != nil {
		fmt.Printf("Error destroying cgroup: %v\n", err)
	} else {
		fmt.Println("Cgroup destroyed successfully.")
	}
}
