// InferTZNameFromFileName infers the time zone name from the given file path.
// It assumes the file path is within the zoneinfo database directory structure.
func InferTZNameFromFileName(filePath string) (string, error) {
	const zoneinfoPrefix = "/usr/share/zoneinfo/"
	if !strings.HasPrefix(filePath, zoneinfoPrefix) {
		return "", errors.New("file path does not start with zoneinfo prefix")
	}
	return strings.TrimPrefix(filePath, zoneinfoPrefix), nil
}

// SystemLocation returns the current system time zone location as a string.
func SystemLocation() string {
	loc := time.Now().Location()
	return loc.String()
}

// InferOneStepLinkForPath resolves one level of symbolic link for the given file path.
func InferOneStepLinkForPath(filePath string) (string, error) {
	linkInfo, err := os.Lstat(filePath)
	if err != nil {
		return "", err
	}
	if linkInfo.Mode()&os.ModeSymlink != 0 {
		return os.Readlink(filePath)
	}
	return filePath, nil
}

