package main

import (
	"io/ioutil"
	"log"
	"os"
	"sync"

	"gopkg.in/yaml.v2"
)

// Config represents the application configuration.
type Config struct {
	loaded          bool
	Repositories    []Repository
	PreferredRepoID string
	DarkMode        bool
}

// Repository represents a repository configuration.
type Repository struct {
	Name string
	ID   string
}

// prListener is a function type for preferred repository change listeners.
type prListener func(string)

var (
	instance     *Config
	once         sync.Once
	prListeners  []prListener
	configPath   = "config.yaml" // Assuming a fixed path for the config file.
	logger       = log.New(os.Stdout, "CONFIG: ", log.LstdFlags)
)

// Init initializes the configuration system.
func Init() (*Config, error) {
	var err error
	once.Do(func() {
		if Exists() {
			instance, err = Load()
			return
		}
		instance = &Config{}
		instance.loaded = true
	})
	return instance, err
}

// Load loads the configuration from a YAML file.
func Load() (*Config, error) {
	c := &Config{}
	data, err := ioutil.ReadFile(configPath)
	if err != nil {
		logger.Println("error reading config:", err)
		return c, err
	}
	err = yaml.Unmarshal(data, c)
	if err != nil {
		logger.Println("invalid config file format:", err)
		return c, err
	}
	c.loaded = true
	return c, nil
}

// Save saves the configuration to a YAML file.
func (c *Config) Save() error {
	data, err := yaml.Marshal(c)
	if err != nil {
		logger.Println("error marshalling configuration:", err)
		return err
	}
	err = ioutil.WriteFile(configPath, data, 0644)
	if err != nil {
		logger.Println("error writing config file:", err)
	}
	return err
}

// AddRepository adds a new repository to the configuration.
func (c *Config) AddRepository(name, id string, preferred bool) {
	c.Repositories = append(c.Repositories, Repository{ID: id, Name: name})
	if preferred {
		c.SetPreferredRepo(id)
	} else {
		c.Save()
	}
}

// ListRepositories lists all repositories in the configuration.
func (c *Config) ListRepositories() []Repository {
	return c.Repositories
}

// PreferredRepo returns the ID of the preferred repository.
func (c *Config) PreferredRepo() string {
	return c.PreferredRepoID
}

// SetPreferredRepo sets the preferred repository and notifies listeners.
func (c *Config) SetPreferredRepo(id string) {
	if c.PreferredRepoID == id {
		return
	}
	c.PreferredRepoID = id
	c.notifyPreferredChanged(id)
	c.Save()
}

// AddPreferredRepoListener adds a listener for preferred repository changes.
func AddPreferredRepoListener(l prListener) {
	prListeners = append(prListeners, l)
}

// notifyPreferredChanged notifies all listeners about the preferred repository change.
func (c *Config) notifyPreferredChanged(id string) {
	for _, l := range prListeners {
		l(id)
	}
}

// IsDarkMode returns whether dark mode is enabled.
func (c *Config) IsDarkMode() bool {
	return c.DarkMode
}

// SetDarkMode enables or disables dark mode.
func (c *Config) SetDarkMode(mode bool) {
	c.DarkMode = mode
	c.Save()
}

// Exists checks if the configuration file exists.
func Exists() bool {
	_, err := os.Stat(configPath)
	return err == nil || !os.IsNotExist(err)
}

// Test cases to verify the solution correctness.
func main() {
	// Initialize configuration
	config, err := Init()
	if err != nil {
		logger.Fatal("Failed to initialize config:", err)
	}

	// Add repositories
	config.AddRepository("Repo1", "id1", false)
	config.AddRepository("Repo2", "id2", true) // Set as preferred

	// List repositories
	repos := config.ListRepositories()
	for _, repo := range repos {
		logger.Printf("Repository: %s, ID: %s\n", repo.Name, repo.ID)
	}

	// Check preferred repository
	logger.Println("Preferred Repository ID:", config.PreferredRepo())

	// Enable dark mode
	config.SetDarkMode(true)
	logger.Println("Is Dark Mode enabled?", config.IsDarkMode())

	// Add a listener for preferred repository changes
	AddPreferredRepoListener(func(id string) {
		logger.Printf("Preferred repository changed to: %s\n", id)
	})

	// Change preferred repository and trigger listeners
	config.SetPreferredRepo("id1")
}
