	return fmt.Sprintf("%d BTC", b)
}

// ErrInsufficientFunds is returned when a withdrawal is attempted with insufficient balance.
var ErrInsufficientFunds = errors.New("cannot withdraw, insufficient funds")

// Wallet stores the number of Bitcoin someone owns.
type Wallet struct {
	total Bitcoin
}

// Deposit will add some Bitcoin to the wallet.
func (w *Wallet) Deposit(amount Bitcoin) {
	w.total += amount
}

// Withdraw subtracts some Bitcoin from the wallet, if possible.
func (w *Wallet) Withdraw(amount Bitcoin) error {
	if amount > w.total {
		return ErrInsufficientFunds
	}
	w.total -= amount
	return nil
}

// Balance returns the number of Bitcoin a wallet has.
func (w *Wallet) Balance() Bitcoin {
	return w.total
}
