package main

import (
	"context"
	"log"
	"sync"
)

// gen is the first stage of the pipeline that generates a stream of integers from a given slice.
func gen(nums ...int) <-chan int {
	out := make(chan int)
	go func() {
		for _, n := range nums {
			out <- n
		}
		close(out)
	}()
	return out
}

// sq is the second stage of the pipeline that receives integers and squares them.
func sq(ctx context.Context, in <-chan int) <-chan int {
	out := make(chan int)
	go func() {
		defer close(out)
		for n := range in {
			select {
			case <-ctx.Done():
				return
			case out <- n * n:
			}
		}
	}()
	return out
}

// merge is the final stage of the pipeline that merges multiple streams of squared integers into a single stream.
func merge(ctx context.Context, cs ...<-chan int) <-chan int {
	var wg sync.WaitGroup
	out := make(chan int)

	output := func(c <-chan int) {
		defer wg.Done()
		for n := range c {
			select {
			case out <- n:
			case <-ctx.Done():
				return
			}
		}
	}

	wg.Add(len(cs))
	for _, c := range cs {
		go output(c)
	}
	go func() {
		wg.Wait()
		close(out)
	}()
	return out
}

func main() {
	ctx, cancel := context.WithCancel(context.Background())

	in := gen(1, 2, 3, 4, 5)
	c1 := sq(ctx, in)
	c2 := sq(ctx, in)

	out := merge(ctx, c1, c2)

	// Print the first two squared integers from the merged stream.
	log.Printf("%d\n", <-out) // 1
	log.Printf("%d\n", <-out) // 4

	// Cancel the context to demonstrate pipeline cancellation.
	cancel()

	// Print the rest of the squared integers from the merged stream until the context is canceled.
	for n := range out {
		log.Printf("%d\n", n)
	}
}
