import (
	"io"
)

// MyStringReader is a simple implementation of io.Reader that reads from a string.
type MyStringReader struct {
	s   string
	pos int // current reading position
}

// Read reads up to len(p) bytes into p from the underlying string.
// It returns the number of bytes read and any error encountered.
func (r *MyStringReader) Read(p []byte) (n int, err error) {
	if r.pos >= len(r.s) { // no more data to return
		return 0, io.EOF
	}

	n = copy(p, r.s[r.pos:])
	r.pos += n
	if r.pos >= len(r.s) { // if we've reached the end of the string
		err = io.EOF
	}

	return
}

// NewReader returns a new MyStringReader reading from s.
func NewReader(s string) io.Reader {
	return &MyStringReader{s: s}
}

func main() {
	// Test cases to verify the solution correctness
	reader := NewReader("Hello, Gophers!")
	buf := make([]byte, 5)

	n, err := reader.Read(buf)
	if n != 5 || err != nil {
		panic("Test failed: Expected to read 5 bytes without error")
	}
	if string(buf) != "Hello" {
		panic("Test failed: Expected 'Hello'")
	}

	n, err = reader.Read(buf)
	if n != 5 || err != nil {
		panic("Test failed: Expected to read 5 bytes without error")
	}
	if string(buf) != ", Gop" {
		panic("Test failed: Expected ', Gop'")
	}

	n, err = reader.Read(buf)
	if n != 5 || err != io.EOF {
		panic("Test failed: Expected to read 5 bytes and get io.EOF error")
	}
	if string(buf[:n]) != "hers!" {
		panic("Test failed: Expected 'hers!'")
	}

	// Reading from an empty string
	emptyReader := NewReader("")
	n, err = emptyReader.Read(buf)
