// ExecuteRemoteCommand executes a command on a remote Windows machine using WinRM.
func ExecuteRemoteCommand(address string, port int, https bool, username string, password string, command string, usePowerShell bool) (stdOut string, stdErr string, exitCode int, err error) {
	endpoint := winrm.NewEndpoint(address, port, https, true, nil, nil, nil, 0)

	params := winrm.DefaultParameters
	enc, _ := winrm.NewEncryption("ntlm")
	params.TransportDecorator = func() winrm.Transporter { return enc }

	client, err := winrm.NewClientWithParameters(endpoint, username, password, params)
	if err != nil {
		return "", "", 0, err
	}

	if usePowerShell {
		psCommand := fmt.Sprintf(`$FormatEnumerationLimit=-1; %s | Out-String -Width 4096`, command)
		return client.RunPSWithContext(context.Background(), psCommand)
	} else {
		return client.RunCmdWithContext(context.Background(), command)
	}
}

