package main

import (
	"context"
	"crypto/tls"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"strings"
	"time"

	"github.com/segmentio/kafka-go"
	"github.com/segmentio/kafka-go/sasl/plain"
)

// FileRow represents a row of data read from a file.
type FileRow interface {
	FileName() string
	Data() interface{}
	GetError() error
	GetOnDone() *func()
}

// KafkaMessageInt represents a Kafka message interface.
type KafkaMessageInt interface {
	Message() *kafka.Message
	GetError() error
	GetOnDone() *func()
}

// GenericEventInt represents a generic event interface.
type GenericEventInt interface{}

// GenericEvent represents a generic event.
type GenericEvent struct {
	Err error
}

// NewKafkaStage creates a new Kafka stage with the specified value and error topics.
func NewKafkaStage(valueTopic, errorTopic string) *kafkaStage {
	batcher := NewMessageBatcher()
	return &kafkaStage{
		valueTopic:     valueTopic,
		errorTopic:     errorTopic,
		messageBatcher: batcher,
	}
}

// kafkaStage represents a stage in the Kafka message processing pipeline.
type kafkaStage struct {
	errorTopic     string
	valueTopic     string
	messageBatcher *messageBatcher
}

// CreateMessage processes FileRow objects and creates Kafka messages.
func (ks *kafkaStage) CreateMessage(ctx context.Context, fileRowCh chan FileRow) chan KafkaMessageInt {
	resultCh := make(chan KafkaMessageInt)

	go func() {
		defer close(resultCh)

		for fileRow := range fileRowCh {
			var kafkaMsg *kafkaMessage
			if err := fileRow.GetError(); err != nil {
				kafkaMsg = &kafkaMessage{
					msg: &kafka.Message{
						Topic: ks.errorTopic,
						Key:   []byte(fileRow.FileName()),
						Value: []byte(err.Error()),
					},
					err: err,
				}
			} else {
				data, _ := json.Marshal(fileRow.Data())
				kafkaMsg = &kafkaMessage{
					msg: &kafka.Message{
						Topic: ks.valueTopic,
						Key:   []byte(fileRow.FileName()),
						Value: data,
					},
				}
			}

			select {
			case <-ctx.Done():
				return
			case resultCh <- kafkaMsg:
			}

			if onDone := fileRow.GetOnDone(); onDone != nil {
				(*onDone)()
			}
		}
	}()

	return resultCh
}

// SendMessage batches Kafka messages and sends them to Kafka.
func (ks *kafkaStage) SendMessage(ctx context.Context, kafkaMessageCh chan KafkaMessageInt) chan GenericEventInt {
	resultCh := make(chan GenericEventInt)

	go func() {
		defer close(resultCh)

		for {
			select {
			case <-ctx.Done():
				return
			case kafkaMsg, ok := <-kafkaMessageCh:
				if !ok {
					if err := ks.messageBatcher.send(ctx); err != nil {
						panic(err)
					}
					return
				}

				if err := kafkaMsg.GetError(); err != nil {
					resultCh <- &GenericEvent{Err: err}
					continue
				}

				ks.messageBatcher.add(*kafkaMsg.Message())
				if ks.messageBatcher.size() >= 100 {
					if err := ks.messageBatcher.send(ctx); err != nil {
						panic(err)
					}
					ks.messageBatcher.flush()
				}

				if onDone := kafkaMsg.GetOnDone(); onDone != nil {
					(*onDone)()
				}
			}
		}
	}()

	return resultCh
}

// kafkaMessage represents a Kafka message.
type kafkaMessage struct {
	msg  *kafka.Message
	done *func()
	err  error
}

func (km *kafkaMessage) GetOnDone() *func() {
	return km.done
}

func (km *kafkaMessage) Message() *kafka.Message {
	return km.msg
}

func (km *kafkaMessage) GetError() error {
	return km.err
}

// kafkaClient creates a Kafka writer with SASL/PLAIN authentication and TLS configuration.
func kafkaClient() (*kafka.Writer, error) {
	username := os.Getenv("KAFKA_USERNAME")
	password := os.Getenv("KAFKA_PASSWORD")
	brokers := os.Getenv("KAFKA_BROKERS")

	if username == "" || password == "" || brokers == "" {
		return nil, errors.New("Kafka environment variables are not set")
	}

	dialer := &kafka.Dialer{
		Timeout:   10 * time.Second,
		DualStack: true,
		SASLMechanism: plain.Mechanism{
			Username: username,
			Password: password,
		},
		TLS: &tls.Config{
			InsecureSkipVerify: true,
		},
	}

	return kafka.NewWriter(kafka.WriterConfig{
		Brokers:   strings.Split(brokers, ","),
		BatchSize: 100,
		Balancer:  &kafka.Hash{},
		Dialer:    dialer,
	}), nil
}

// NewMessageBatcher creates a new message batcher.
func NewMessageBatcher() *messageBatcher {
	client, err := kafkaClient()
	if err != nil {
		panic(err)
	}

	return &messageBatcher{
		kafkaClient: client,
	}
}

// messageBatcher represents a batcher for Kafka messages.
type messageBatcher struct {
	kafkaClient *kafka.Writer
	messages    []kafka.Message
}

func (mb *messageBatcher) size() int {
	return len(mb.messages)
}

func (mb *messageBatcher) add(m kafka.Message) {
	mb.messages = append(mb.messages, m)
}

func (mb *messageBatcher) flush() {
	mb.messages = []kafka.Message{}
}

func (mb *messageBatcher) send(ctx context.Context) error {
	if len(mb.messages) == 0 {
		return nil
	}
	err := mb.kafkaClient.WriteMessages(ctx, mb.messages...)
	mb.flush()
	return err
}

// Example usage of the Kafka message processing pipeline.
func main() {
	// Set up the Kafka stage with the appropriate topics.
	valueTopic := "value-topic"
	errorTopic := "error-topic"
	kafkaStage := NewKafkaStage(valueTopic, errorTopic)

	// Create channels for FileRow and KafkaMessageInt.
	fileRowCh := make(chan FileRow)
	kafkaMessageCh := make(chan KafkaMessageInt)

	// Context to control the pipeline.
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	// Start the CreateMessage and SendMessage stages.
	go kafkaStage.CreateMessage(ctx, fileRowCh)
	go kafkaStage.SendMessage(ctx, kafkaMessageCh)

