package dynamomq

import (
	"errors"
	"fmt"
	"sync"
)

// Message represents a message in the queue with an ID and Version for optimistic concurrency control.
type Message struct {
	ID      string
	Version int
	Content string
}

// DynamoMQ represents a simple message queue with basic operations.
type DynamoMQ struct {
	messages []Message
	lock     sync.Mutex
}

// Enqueue adds a new message to the queue.
func (q *DynamoMQ) Enqueue(message Message) error {
	q.lock.Lock()
	defer q.lock.Unlock()

	if message.ID == "" {
		return IDNotProvidedError{}
	}

	for _, m := range q.messages {
		if m.ID == message.ID {
			return IDDuplicatedError{}
		}
	}

	q.messages = append(q.messages, message)
	return nil
}

// Dequeue removes and returns the message at the front of the queue.
func (q *DynamoMQ) Dequeue() (Message, error) {
	q.lock.Lock()
	defer q.lock.Unlock()

	if len(q.messages) == 0 {
		return Message{}, EmptyQueueError{}
	}

	message := q.messages[0]
	q.messages = q.messages[1:]
	return message, nil
}

// Peek returns the message at the front of the queue without removing it.
func (q *DynamoMQ) Peek() (Message, error) {
	q.lock.Lock()
	defer q.lock.Unlock()

	if len(q.messages) == 0 {
		return Message{}, EmptyQueueError{}
	}

	return q.messages[0], nil
}

// Test cases to verify the solution correctness.
func main() {
	queue := DynamoMQ{}

	// Test Enqueue
	err := queue.Enqueue(Message{ID: "1", Version: 1, Content: "First message"})
	if err != nil {
		fmt.Println("Enqueue failed:", err)
	}

	// Test Enqueue with empty ID
	err = queue.Enqueue(Message{Content: "No ID"})
	if err != nil {
		fmt.Println("Enqueue failed:", err) // Expected: ID was not provided.
	}

	// Test Enqueue with duplicated ID
