package main

import (
	"fmt"
)

// LessConstraint is an interface that types must satisfy to be sorted by the Sort function.
// It requires a Less method that defines the ordering between two elements.
type LessConstraint[T any] interface {
	Less(T) bool
}

// Sort is a generic function that sorts a slice of elements that satisfy the LessConstraint interface.
// It uses the insertion sort algorithm.
func Sort[T LessConstraint[T]](x []T) {
	n := len(x)
	for i := 1; i < n; i++ {
		for j := i; j > 0 && x[j].Less(x[j-1]); j-- {
			x[j], x[j-1] = x[j-1], x[j]
		}
	}
}

// MyInt is a struct that holds an integer value.
type MyInt struct {
	Value int
}

// Less compares two MyInt instances and returns true if the value of the receiver is less than the value of the argument.
func (a MyInt) Less(b MyInt) bool {
	return a.Value < b.Value
}

// F demonstrates the usage of the Sort function with a slice of MyInt instances.
func F() {
	sl1 := []MyInt{{4}, {3}, {8}, {7}}
	Sort(sl1)
	for _, v := range sl1 {
		fmt.Printf("%v ", v.Value)
	}
	fmt.Println()
}

func main() {
	F() // This should print the sorted values: 3 4 7 8
}
