	binding, exists := m.bindings[name]
	if !exists {
		return errors.New("KameletBinding does not exist")
	}

	binding.Spec.Replicas = &replicas
	binding.Status.Replicas = &replicas
	m.bindings[name] = binding
	return nil
}

