	"time"
)

// Event represents a notification event with a message and a timestamp.
type Event struct {
	Message   string
	Timestamp time.Time
}

// ICommunicate defines the methods required for a communication channel.
type ICommunicate interface {
	Setup()
	Connect() error
	PushEvent(Event) error
	IsEnabled() bool
	IsConnected() bool
	GetName() string
}

// IComm aggregates multiple ICommunicate instances.
type IComm []ICommunicate

// CommsStatus represents the status of a communication channel.
type CommsStatus struct {
	Enabled   bool
	Connected bool
}

// Setup sets up communication variables and initiates a connection to the communication channels.
func (c IComm) Setup() {
	for _, comm := range c {
		if comm.IsEnabled() && !comm.IsConnected() {
			err := comm.Connect()
			if err != nil {
				log.Printf("Communication error: %s failed to connect. Err: %s", comm.GetName(), err)
				continue
			}
			log.Printf("Communication: %v is enabled and online.", comm.GetName())
		}
	}
}

// PushEvent pushes triggered events to all enabled and connected communication channels.
func (c IComm) PushEvent(event Event) {
	for _, comm := range c {
		if comm.IsEnabled() && comm.IsConnected() {
			err := comm.PushEvent(event)
			if err != nil {
				log.Printf("Communication error: PushEvent() in %s with %v. Err %s", comm.GetName(), event, err)
			}
		}
	}
}

// GetStatus returns the status of the communication channels.
func (c IComm) GetStatus() map[string]CommsStatus {
	result := make(map[string]CommsStatus)
	for _, comm := range c {
		result[comm.GetName()] = CommsStatus{
			Enabled:   comm.IsEnabled(),
			Connected: comm.IsConnected(),
		}
	}
	return result
}

// GetEnabledCommunicationMediums prints out enabled and connected communication channels.
func (c IComm) GetEnabledCommunicationMediums() error {
	var count int
	for _, comm := range c {
		if comm.IsEnabled() && comm.IsConnected() {
			log.Printf("Communication: Medium %s is enabled.", comm.GetName())
			count++
		}
	}
	if count == 0 {
		return errors.New("no communication mediums are enabled")
	}
	return nil
}

