package models

import (
	"crypto/sha256"
	"encoding/hex"
	"errors"
	"fmt"
	"github.com/dgrijalva/jwt-go"
	"github.com/stretchr/testify/assert"
	"testing"
	"time"
)

type User struct {
	Name     string
	Email    string
	Password string
	Hash     string
	Token    string
}

var usersDB = make(map[string]User)

// DbInit initializes the database (mocked with a map for this example).
func DbInit() {
	usersDB = make(map[string]User)
}

// CreateUser registers a new user with a unique email and generates a unique hash.
func (u *User) CreateUser() error {
	if _, exists := usersDB[u.Email]; exists {
		return errors.New("user already exists")
	}

	hasher := sha256.New()
	hasher.Write([]byte(u.Password))
	u.Hash = hex.EncodeToString(hasher.Sum(nil))

	usersDB[u.Email] = *u
	return nil
}

// GenerateToken creates a JWT token for the user session.
func (u *User) GenerateToken() error {
	if u.Email == "" {
		return errors.New("email is required")
	}

	token := jwt.NewWithClaims(jwt.SigningMethodHS256, jwt.MapClaims{
		"name": u.Name,
		"exp":  time.Now().Add(time.Hour * 72).Unix(),
	})

	tokenString, err := token.SignedString([]byte("secret"))
	if err != nil {
		return err
	}

	u.Token = tokenString
	return nil
}

// VerifyToken checks if the provided token is valid.
func (u *User) VerifyToken(tokenString string) error {
	token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
		return []byte("secret"), nil
	})

	if err != nil {
		return err
	}

	if claims, ok := token.Claims.(jwt.MapClaims); ok && token.Valid {
		if claims["name"] != u.Name {
			return errors.New("invalid token")
		}
	} else {
		return errors.New("invalid token")
	}

	return nil
}

