func (ctp ChainedTelemetryProcessor) ProcessTelemetry(ctx context.Context, batch *TelemetryBatch) error {
	for _, processor := range ctp {
		if err := processor.ProcessTelemetry(ctx, batch); err != nil {
			return err
		}
	}
	return nil
