package main

import (
	"fmt"
	"strings"
	"sync"
)

// FreqMap records the frequency of each rune in a given text.
type FreqMap map[rune]int

// Frequency counts the frequency of each rune in a given text and returns this
// data as a FreqMap.
func Frequency(s string) FreqMap {
	m := FreqMap{}
	s = strings.ToLower(s) // Make the frequency analysis case-insensitive
	for _, r := range s {
		m[r]++
	}
	return m
}

// SequentialFrequency counts the frequency of each rune sequentially in string slices and returns this
// data as a FreqMap.
func SequentialFrequency(texts []string) FreqMap {
	result := make(FreqMap)
	for _, text := range texts {
		freq := Frequency(text)
		for k, v := range freq {
			result[k] += v
		}
	}
	return result
}

// ConcurrentFrequency counts frequency of each rune concurrently in string slices and returns this
// data as a FreqMap.
func ConcurrentFrequency(texts []string) FreqMap {
	result := make(FreqMap)
	freqs := make(chan FreqMap, len(texts)) // Buffered channel to avoid blocking goroutines
	var wg sync.WaitGroup

	for _, text := range texts {
		wg.Add(1)
		go func(text string) {
			defer wg.Done()
			freqs <- Frequency(text)
		}(text)
	}

	wg.Wait()
	close(freqs)

	for freq := range freqs {
		for k, v := range freq {
			result[k] += v
		}
	}
	return result
}

func main() {
	texts := []string{"Go is Awesome!", "Concurrency is powerful", "Groutines are cool!"}

	// Test SequentialFrequency
	seqFreq := SequentialFrequency(texts)
	fmt.Println("Sequential Frequency:", seqFreq)

	// Test ConcurrentFrequency
	concFreq := ConcurrentFrequency(texts)
	fmt.Println("Concurrent Frequency:", concFreq)

	// Verify that both methods produce the same result
	if len(seqFreq) != len(concFreq) {
		fmt.Println("The frequency maps do not match in size.")
		return
	}
	for k, v := range seqFreq {
		if concFreq[k] != v {
			fmt.Printf("The frequency of rune '%c' does not match: %d (sequential) vs %d (concurrent)\n", k, v, concFreq[k])
			return
		}
	}
	fmt.Println("Both methods produced the same frequency map.")
}
