// SecretMetadata represents metadata of a secret.
type SecretMetadata struct {
	Path    string `json:"path"`
	Project string `json:"project"`
}

// SecretAnnotation represents annotations of a secret.
type SecretAnnotation struct {
	Annotations map[string]string `json:"annotations"`
}

// SecretManager is an interface for managing secrets.
type SecretManager interface {
	CreateSecret(project, path string, secret Secret) error
	UpdateSecret(project, path string, secret Secret) error
	GetSecret(project, path string, version int) (SecretVersion, error)
	DeleteSecret(project, path string) error
	ListSecrets(project, path string) ([]SecretMetadata, error)
