}

// Server represents the HTTP server.
type Server struct {
	secretManager SecretManager
}

// NewServer creates a new Server with the given SecretManager.
func NewServer(secretManager SecretManager) *Server {
	return &Server{secretManager: secretManager}
}

// Start runs the server on the specified address.
func (s *Server) Start(address string) error {
	router := mux.NewRouter()

	router.HandleFunc("/secrets/{project}/{path}", s.handleCreateOrUpdateSecret).Methods(http.MethodPost, http.MethodPut)
	router.HandleFunc("/secrets/{project}/{path}", s.handleGetSecret).Methods(http.MethodGet)
	router.HandleFunc("/secrets/{project}/{path}", s.handleDeleteSecret).Methods(http.MethodDelete)
	router.HandleFunc("/secrets/{project}", s.handleListSecrets).Methods(http.MethodGet)
	router.HandleFunc("/metadata/{project}/{path}", s.handleGetMetadata).Methods(http.MethodGet)
	router.HandleFunc("/versions/{project}/{path}", s.handleGetVersions).Methods(http.MethodGet)
	router.HandleFunc("/rollback/{project}/{path}", s.handleRollback).Methods(http.MethodPost)
	router.HandleFunc("/init/{project}", s.handleInitProject).Methods(http.MethodPost)
	router.HandleFunc("/annotations/{project}", s.handleGetSecretAnnotation).Methods(http.MethodGet)

	return http.ListenAndServe(address, router)
}

func (s *Server) handleCreateOrUpdateSecret(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	project := vars["project"]
	path := vars["path"]

	var secret Secret
	body, err := ioutil.ReadAll(r.Body)
	if err != nil {
		http.Error(w, fmt.Sprintf("Error reading request body: %v", err), http.StatusBadRequest)
		return
	}
	defer r.Body.Close()

	if err := json.Unmarshal(body, &secret); err != nil {
		http.Error(w, fmt.Sprintf("Error unmarshalling request body: %v", err), http.StatusBadRequest)
		return
	}

	switch r.Method {
	case http.MethodPost:
		if err := s.secretManager.CreateSecret(project, path, secret); err != nil {
