package main

import (
	"fmt"
	"time"

	"github.com/zyedidia/generic/hashmap"
)

// Importing necessary packages
import (
	"github.com/google/uuid"
)

// Domain entities and response models
type ShorturlEntity struct {
	Origin    string
	Shortened string
	CreatedAt time.Time
	UpdatedAt time.Time
	DeletedAt *time.Time
}

func (s *ShorturlEntity) Data() *ShorturlData {
	return &ShorturlData{
		Origin:    s.Origin,
		Shortened: s.Shortened,
	}
}

func (s *ShorturlEntity) Metadata() *ShorturlMetadata {
	return &ShorturlMetadata{
		CreatedAt: s.CreatedAt,
		UpdatedAt: s.UpdatedAt,
		DeletedAt: s.DeletedAt,
	}
}

type ShorturlData struct {
	Origin    string
	Shortened string
}

func (d *ShorturlData) Result(address string) string {
	return address + "/" + d.Shortened
}

type ShorturlMetadata struct {
	CreatedAt time.Time
	UpdatedAt time.Time
	DeletedAt *time.Time
}

type ShorturlResponse struct {
	Origin    string
	Shortened string
	Result    string
	CreatedAt time.Time
	UpdatedAt time.Time
	DeletedAt *time.Time
}

type ShorturlBatchResponse struct {
	CorrelationID string
	Origin        string
	Shortened     string
	Result        string
}

type ShorturlUserResponse struct {
	Origin    string
	Shortened string
	Result    string
}

// Use cases (functions to transform domain entities into response models)
func toShorturlModel(value *ShorturlEntity, address string) *ShorturlResponse {
	return &ShorturlResponse{
		Origin:    value.Data().Origin,
		Shortened: value.Data().Shortened,
		Result:    value.Data().Result(address),
		CreatedAt: value.Metadata().CreatedAt,
		UpdatedAt: value.Metadata().UpdatedAt,
		DeletedAt: value.Metadata().DeletedAt,
	}
}

func toShorturlBatchModel(value *ShorturlEntity, correlationID string, address string) *ShorturlBatchResponse {
	return &ShorturlBatchResponse{
		CorrelationID: correlationID,
		Origin:        value.Data().Origin,
		Shortened:     value.Data().Shortened,
		Result:        value.Data().Result(address),
	}
}

func toUserShorturlModel(value *ShorturlEntity, address string) *ShorturlUserResponse {
	return &ShorturlUserResponse{
		Origin:    value.Data().Origin,
		Shortened: value.Data().Shortened,
		Result:    value.Data().Result(address),
	}
}

// Test cases to verify the correctness of the solution
func main() {
	address := "http://short.url"
	originalURL := "http://example.com"
	shortened := uuid.NewString()[:8]

	// Test case for single URL shortening
	shorturlEntity := ShorturlEntity{
		Origin:    originalURL,
		Shortened: shortened,
		CreatedAt: time.Now(),
		UpdatedAt: time.Now(),
	}

	response := toShorturlModel(&shorturlEntity, address)
	fmt.Printf("Single URL Shortening Response: %+v\n", response)

	// Test case for batch URL shortening
	batchMap := hashmap.New[ShorturlEntity, string]()
	batchMap.Put(shorturlEntity, "correlation-id-1")

	batchResponse := make([]*ShorturlBatchResponse, 0)
	batchMap.Each(func(k ShorturlEntity, v string) {
		model := toShorturlBatchModel(&k, v, address)
		batchResponse = append(batchResponse, model)
	})

	fmt.Printf("Batch URL Shortening Response: %+v\n", batchResponse)

	// Test case for retrieving URLs for a user
	userShorturlEntities := []*ShorturlEntity{&shorturlEntity}
	userResponses := make([]*ShorturlUserResponse, 0)
	for _, v := range userShorturlEntities {
		model := toUserShorturlModel(v, address)
		userResponses = append(userResponses, model)
	}

	fmt.Printf("User URL Retrieval Response: %+v\n", userResponses)
}
