func InitializeAppWithServiceAccount() *firebase.App {
	opt := option.WithCredentialsFile("serviceAccountKey.json")
	app, err := firebase.NewApp(context.Background(), nil, opt)
	if err != nil {
		log.Fatalf("error initializing app: %v\n", err)
	}
	return app
}

func GetUser(ctx context.Context, app *firebase.App, userID string) (User, error) {
	client, err := app.Firestore(ctx)
	if err != nil {
		return User{}, fmt.Errorf("error getting Firestore client: %v", err)
	}
	defer client.Close()

	doc, err := client.Collection("users").Doc(userID).Get(ctx)
	if err != nil {
		return User{}, fmt.Errorf("error getting user document: %v", err)
	}

	var user User
	if err := doc.DataTo(&user); err != nil {
		return User{}, fmt.Errorf("error parsing user document: %v", err)
	}

	return user, nil
}

func UpdateUserAge(ctx context.Context, app *firebase.App, userID string, newAge int) error {
	client, err := app.Firestore(ctx)
	if err != nil {
		return fmt.Errorf("error getting Firestore client: %v", err)
	}
	defer client.Close()

	_, err = client.Collection("users").Doc(userID).Update(ctx, []db.Update{{Path: "age", Value: newAge}})
	if err != nil {
		return fmt.Errorf("error updating user age: %v", err)
	}

	return nil
}

