package main

import (
	"fmt"
	"log"
	"strconv"
)

// solve takes a slice of strings representing lines from the game's score log
// and returns the highest score achieved by any player during their turn.
func solve(lines []string) int {
	highestScore := 0
	currentScore := 0

	for _, line := range lines {
		if line != "" {
			points, err := strconv.Atoi(line)
			if err != nil {
				// Ignore non-numeric or malformed entries
				continue
			}
			currentScore += points
		} else {
			// Reset score for the next player
			currentScore = 0
		}

		if currentScore > highestScore {
			highestScore = currentScore
		}
	}

	return highestScore
}

func main() {
	// Example test cases
	testCases := []struct {
		input    []string
		expected int
	}{
		{[]string{"5", "3", "-2", "", "7", "-1", "4", ""}, 10},
		{[]string{"1", "2", "3", "", "4", "5", "6", ""}, 15},
		{[]string{"-1", "-2", "-3", "", "2", "2", "2", ""}, 6},
		{[]string{"abc", "5", "def", "", "3", "ghi", "7", ""}, 10},
	}

	for _, tc := range testCases {
		actual := solve(tc.input)
		if actual != tc.expected {
			log.Fatalf("solve(%v) = %d; expected %d", tc.input, actual, tc.expected)
		}
		fmt.Printf("Test passed: %v -> %d\n", tc.input, actual)
	}
}
