	err = os.WriteFile(notePath, []byte("This is an example note."), defaultFilePerms)
	if err != nil {
		fmt.Println("Error writing note:", err)
		return
	}

	addCmd := git(notes, logFile, "add", notePath)
	if err := addCmd.Run(); err != nil {
		fmt.Println("Error adding note:", err)
		return
	}

	// Commit changes
	commitCmd := git(notes, logFile, "commit", "-m", "Add example note")
	if err := commitCmd.Run(); err != nil {
		fmt.Println("Error committing changes:", err)
		return
	}

	fmt.Println("Repository updated successfully.")
}

func git(notes note.List, logFile io.Writer, args ...string) *exec.Cmd {
	cmd := exec.Command(gitCmd, args...)
	cmd.Stdout = os.Stdout
	cmd.Stderr = logFile
	cmd.Dir = notes.HomeDir()
	return cmd
}

func openErrorLog(logName string) (*os.File, error) {
	if _, err := os.Stat(logName); err != nil {
		if os.IsNotExist(err) {
			return os.Create(logName)
		}
		return nil, err
	}

	// file exists
	return os.OpenFile(logName, os.O_WRONLY|os.O_APPEND, 0666)
}

