// RMQConsumeVrdMailerQueue consumes messages from the "vrdmailerqueue" queue and sends emails.
func (mail *Mail) RMQConsumeVrdMailerQueue(rabbitmqChCons *amqp.Channel) {
	var sendData SendData

	log.Println("Start consuming vrdmailerqueue..")
	msgs, err := rabbitmqChCons.Consume(
		"vrdmailerqueue", // queue
		"",               // consumer
		false,            // auto-ack
		false,            // exclusive
		false,            // no-local
		false,            // no-wait
		nil,              // args
	)
	if err != nil {
		log.Panicf("Failed to consume a message: %s", err)
	}

	go func() {
		for d := range msgs {
			err := json.Unmarshal(d.Body, &sendData)
			if err != nil {
				log.Printf("Failed to unmarshal json: %s", err)
				continue
			}

			if err = d.Ack(false); err != nil {
				log.Fatalf("RabbitMQ: failed to acknowledge message in queue: %s", d.Body)
			}

			// send email
			log.Printf("Sending email to: %s ..\n", sendData.MailTo)

			sendEmailUtil := utilsMail{
				Subject: sendData.Subject,
				Body:    sendData.Body,
				To:      sendData.MailTo,
				From:    os.Getenv("SMTP_EMAIL_FROM"),
			}

			if err := sendEmailUtil.SendMail(); err != nil {
				log.Printf("Failed to send email to: %s\n", sendEmailUtil.To)
			}
		}
	}()
}

