	Name        string
	Version     string
	Project     projectMetainfo
	Application applicationMetainfo
	Library     libraryMetainfo
}

func GenerateStructure(metadata Metadatainfo, projectName string) error {
	for _, entity := range metadata.Project.Structure {
		path := fmt.Sprintf(entity.Pattern, projectName)
		if entity.EntityType == ENTITY_TYPE_DIR {
			if err := os.MkdirAll(path, 0755); err != nil {
				return err
			}
		} else if entity.EntityType == ENTITY_TYPE_FILE {
			if _, err := os.Stat(path); os.IsNotExist(err) {
				var content []byte
				var err error
				if entity.Template != "" {
					content, err = ioutil.ReadFile(filepath.Join("templates", entity.Template))
					if err != nil {
						return err
					}
				}
				if err := ioutil.WriteFile(path, content, 0644); err != nil {
					return err
				}
			}
		}
	}
	return nil
}

