package main

import (
	"flag"
	"fmt"
	"io/ioutil"
	"log"
	"strings"
	"time"
)

// Config represents the configuration for the Prometheus blackbox exporter.
type Config struct {
	HTTPStatus      int
	HTTPSRedirect   int
	URLs            []string
	ScrapeInterval  time.Duration
	BlackboxConfig  string
	PrometheusConfig string
}

// parseURLs splits a comma-separated list of URLs into a slice.
func parseURLs(urls string) []string {
	return strings.Split(urls, ",")
}

// generateBlackboxConfig generates the blackbox exporter configuration.
func generateBlackboxConfig(cfg *Config) string {
	// Define blackbox exporter modules for HTTP and HTTPS monitoring
	return fmt.Sprintf(`modules:
  http_2xx:
    prober: http
    timeout: 5s
    http:
      valid_http_versions: [ "HTTP/1.1", "HTTP/2" ]
      valid_status_codes: [ %d ]  # Expected HTTP status code
      method: GET
  http_redirect:
    prober: http
    timeout: 5s
    http:
      valid_status_codes: [ %d ]  # Expected redirect status code
      fail_if_not_ssl: true
`, cfg.HTTPStatus, cfg.HTTPSRedirect)
}

// generatePrometheusConfig generates the Prometheus scrape configuration.
func generatePrometheusConfig(cfg *Config) string {
	scrapeConfig := `scrape_configs:
`
	for _, url := range cfg.URLs {
		scheme := "http"
		if strings.HasPrefix(url, "https://") {
			scheme = "https"
		}
		module := "http_2xx"
		if scheme == "http" {
			module = "http_redirect"
		}
		scrapeConfig += fmt.Sprintf(`  - job_name: '%s'
    metrics_path: /probe
    params:
      module: [ %s ]
    static_configs:
      - targets:
        - '%s'
    relabel_configs:
      - source_labels: [__address__]
        target_label: __param_target
      - source_labels: [__param_target]
        target_label: instance
      - target_label: __address__
        replacement: blackbox-exporter:9115  # Blackbox exporter.
      - source_labels: [__param_target]
        regex: '([^:]+)(?::\d+)?'
        target_label: site
        replacement: '$1'
`, url, module, url)
	}
	return scrapeConfig
}

func main() {
	var urls string
	flag.StringVar(&urls, "urls", "", "Comma-separated list of URLs to monitor")
	httpStatus := flag.Int("http_status", 200, "Expected HTTP status code for HTTP URLs")
	httpsRedirect := flag.Int("https_redirect", 301, "Expected HTTP redirect status code for HTTP URLs that should redirect to HTTPS")
	scrapeInterval := flag.Duration("scrape_interval", 30*time.Second, "Scrape interval for Prometheus")
	blackboxFile := flag.String("blackbox_config", "blackbox.yaml", "Output file for blackbox exporter configuration")
	prometheusFile := flag.String("prometheus_config", "prometheus.yaml", "Output file for Prometheus scrape configuration")

	flag.Parse()

	if urls == "" {
		log.Fatal("No URLs provided. Use the -urls flag to specify the URLs to monitor.")
	}

	cfg := Config{
		HTTPStatus:      *httpStatus,
		HTTPSRedirect:   *httpsRedirect,
		URLs:            parseURLs(urls),
		ScrapeInterval:  *scrapeInterval,
		BlackboxConfig:  *blackboxFile,
		PrometheusConfig: *prometheusFile,
	}

	blackboxConfig := generateBlackboxConfig(&cfg)
	if err := ioutil.WriteFile(cfg.BlackboxConfig, []byte(blackboxConfig), 0666); err != nil {
		log.Fatalf("Error writing blackbox exporter configuration: %v", err)
	}

	prometheusConfig := generatePrometheusConfig(&cfg)
	if err := ioutil.WriteFile(cfg.PrometheusConfig, []byte(prometheusConfig), 0666); err != nil {
		log.Fatalf("Error writing Prometheus scrape configuration: %v", err)
	}

	log.Println("Configuration files generated successfully.")
}

// Test cases to verify the solution correctness.
func main() {
	// Test case 1: Generate configuration for a single HTTP URL
	main()

	// Test case 2: Generate configuration for multiple URLs, including HTTPS
	main()
}
